export const part3: Record<string, string[]> = {
  "23:1": ["Successful indeed are the believers;","নিশ্চয়ই বিশ্বাসীরা সফলকাম।"],
  "23:2": ["who are reverent during their Contact Prayers (Salat).","যারা তাদের সংযোগ প্রার্থনা (সালাত)-এ ভক্তিপূর্ণ থাকে।"],
  "23:3": ["And they avoid vain talk.","এবং তারা অনর্থক কথা এড়িয়ে চলে।"],
  "23:4": ["And they give their obligatory charity (Zakat).","এবং তারা তাদের বাধ্যতামূলক দান (যাকাত) প্রদান করে।"],
  "23:5": ["And they maintain their chastity.","এবং তারা তাদের যৌন শুদ্ধতা বজায় রাখে।"],
  "23:6": ["Only with their spouses, or those who are rightfully theirs, do they have sexual relations; they are not to be blamed.","তাদের যৌন সম্পর্ক থাকে শুধু তাদের জীবনসংগীদের  সাথে, অথবা তাদের সাথে যারা তাদের জন্য বৈধ, ; সেক্ষেত্রে তারা দোষী হবে না।"],
  "23:7": ["Those who transgress these limits are the transgressors.","যারা এইসব সীমা অতিক্রম করে তারাই সীমালঙ্ঘনকারী।"],
  "23:8": ["When it comes to deposits entrusted to them, as well as any agreements they make, they are trustworthy.","যখন তাদেরকে কাছে কোন আমানত রাখা হয় অথবা কোন চুক্তি তারা করে, তারা আস্থাভাজন।"],
  "23:9": ["And they observe their Contact Prayers (Salat) regularly.","এবং তারা নিয়মিত তাদের সংযোগ প্রার্থনা (সালাত) পালন করে।"],
  "23:10": ["Such are the inheritors.","উত্তরাধিকারীরা এমনই।"],
  "23:11": ["They will inherit Paradise, wherein they abide forever.","তারা স্বর্গের উত্তরাধিকারী হবে, যেখানে তারা চিরকাল বসবাস করে।"],
  "23:12": ["We created the human being from a certain kind of mud.","আমরা মানুষকে সৃষ্টি করেছি এক বিশেষ ধরনের কাদামাটি থেকে ।"],
  "23:13": ["Subsequently, we reproduced him from a tiny drop, that is placed into a well protected repository.","পরবর্তীকালে, আমরা তাকে এক অতি ক্ষুদ্র ফোঁটা থেকে পুনঃসৃষ্টি করেছি, যা এক সুরক্ষিত আধারে রাখা হয়।"],
  "23:14": ["Then we developed the drop into a hanging (embryo), then developed the hanging (embryo) into a bite-size (fetus), then created the bite-size (fetus) into bones, then covered the bones with flesh. We thus produce a new creature. Most blessed is Allah, the best Creator.","এরপর আমরা ফোঁটাটিকে পরিণত করলাম ঝুলন্ত (ভ্রুনে), তারপর ঝুলন্ত (ভ্রুন) -কে পরিণত করলাম কামড়-সদৃশ (মানবাকৃতির ভ্রুনে), তারপর কামড়-সদৃশ (মানবাকৃতির ভ্রুন) থেকে সৃষ্টি করলাম হাড়, তারপর হাড়কে মাংস দিয়ে ঢেকে দিলাম। আমরা এভাবে এক নতুন সৃষ্টি তৈরি করি। পরম কল্যাণময় আল্লাহ, সর্বোত্তম সৃষ্টিকারী।"],
  "23:15": ["Then, later on, you die.","এরপর, পরবর্তীতে, তোমরা মারা যাও।"],
  "23:16": ["Then, on the Day of Resurrection, you will be resurrected.","তারপর, পুনরুত্থান দিবসে তোমরা পুনরুত্থিত হবে।"],
  "23:17": ["We created above you seven universes in layers, and we are never unaware of a single creature in them.","আমরা তোমাদের উপর স্তরে স্তরে সাতটি মহাবিশ্ব সৃষ্টি করেছি, এবং আমরা তাতে একটি সৃষ্টি সম্পর্কেও অনবগত নই।"],
  "23:18": ["We send down from the sky water, in exact measure, then we store it in the ground. Certainly, we can let it escape.","আমরা আকাশ থেকে পানি বর্ষণ করি, যথাযথ পরিমাণে, এরপর আমরা তা ভূমির ভেতরে জমা করি। নিশ্চয়ই, আমরা তা সরিয়ে দিতে পারি।"],
  "23:19": ["With it, we produce for you orchards of date palms, grapes, all kinds of fruits, and various foods.","এটি দিয়ে, আমরা তোমাদের জন্য উৎপন্ন করি খেজুর গাছ এবং আঙ্গুরের বাগান, সব রকমের ফল, এবং নানা ধরনের খাদ্য।"],
  "23:20": ["Also, a tree native to Sinai produces oil, as well as relish for the eaters.","আবার, সিনাই এর স্থানীয় একটি গাছ তেল উৎপন্ন করে, সেই সাথে আহারকারীদের জন্য রুচি।"],
  "23:21": ["And the livestock should provide you with a lesson. We let you drink (milk) from their bellies, you derive other benefits from them, and some of them you use for food.","এবং পালনযোগ্য পশুসম্বদ  থেকে তোমাদের  একটি শিক্ষা নেওয়া উচিত। তাদের পেট থেকে আমরা তোমাদেরকে (দুধ) পান করতে দেই, তাদের থেকে তোমরা অন্যান্য সুবিধাও নিয়ে থাকো, এবং তাদের কতককে তোমরা খাদ্য হিসেবে নাও।"],
  "23:22": ["On them, and on the ships, you ride.","তাদের উপর, এবং জাহাজগুলোতে, তোমরা আরোহণ করো।"],
  "23:23": ["We sent Noah to his people, saying, \"O my people, worship Allah. You have no other god beside Him. Would you not be righteous?\"","আমরা নূহকে তার লোকদের কাছে পাঠিয়েছিলাম, এই বলে যে, “হে আমার লোকেরা, আল্লাহর উপাসনা করো। তার পাশে তোমাদের অন্যকোন উপাস্য নেই। তোমরা কি সৎকর্মশীল হবে না?"],
  "23:24": ["The leaders who disbelieved among his people said, \"This is no more than a human like you, who wants to gain prominence among you. Had Allah willed, He could have sent down angels. We never heard of anything like this from our ancestors.","তার লোকদের মধ্যে যেসব নেতারা অবিশ্বাস করেছিল তারা বলল, “এ তো তোমাদের মত মানুষের চেয়ে বেশি কিছু না, যে তোমাদের মাঝে ক্ষ্যাতি অর্জন করতে চায়।যদি আল্লাহ চাইতেন, তিনি স্বর্গদূতদের পাঠাতে পারতেন। আমরা আমাদের পূর্বপুরুষদের কাছে কখনোই এরকম কিছু শুনিনি।"],
  "23:25": ["\"He is simply a man gone crazy. Just ignore him for awhile.\"","সে কেবল একজন মানুষ যে পাগল হয়ে গেছে।   তাকে শুধু কিছু সময়ের জন্য  উপেক্ষা করো।”"],
  "23:26": ["He said, \"My Lord, grant me victory, for they have disbelieved me.\"","সে বলল, “ আমার প্রভু, আমাকে বিজয় দান করুন, কারন তারা আমাকে অবিশ্বাস করেছে।”"],
  "23:27": ["We then inspired him: \"Make the watercraft under our watchful eyes, and in accordance with our inspiration. When our command comes, and the atmosphere boils up, put on it a pair of every kind (of your domesticated animals), and your family, except those condemned to be doomed. Do not speak to Me on behalf of those who transgressed; they will be drowned.","আমরা এরপর তাকে প্রত্যাদেশ করলাম: “আমাদের নজরদারির অধীনে, এবং আমাদের  প্রত্যাদেশ  অনুযায়ী জলযান তৈরী করো। যখন আমাদের আদেশ এসে যায়; এবং আবহাওয়া ভীষণ উত্তপ্ত হয়ে পড়ে, তখন এতে (তোমার গৃহপালিত পশুর) প্রত্যেকের একটি জোড়া, এবং তোমার পরিবারকে  উঠিয়ে নাও, তাদেরকে ছাড়া যারা ধ্বংস হবার জন্য সাব্যস্ত হয়েছে। যারা সীমালংঘন করেছে তাদের পক্ষ হয়ে আমার সাথে কথা বলো না; তারা নিমজ্জিত হবে।"],
  "23:28": ["\"Once you are settled, together with those who are with you, on the watercraft, you shall say, 'Praise Allah for saving us from the evil people.'","“যখন তুমি  জলযানে   স্থির হবে  তাদের সাথে একত্রে  যারা তোমার সাথে  আছে, তুমি বলবে, ‘প্রশংসা আল্লাহর আমাদেরকে মন্দ লোকদের কাছ থেকে রক্ষা করার জন্য।’"],
  "23:29": ["\"And say, 'My Lord, let me disembark onto a blessed location; You are the best deliverer.' \"","“এবং বল, ‘আমার প্রভু, আমাকে এক পবিত্র স্থানে  নোঙ্গর করতে দিন; আপনি সর্বোত্তম উদ্ধারকারী।”"],
  "23:30": ["These should provide sufficient proofs for you. We will certainly put you to the test.","এগুলো তোমাদের জন্য যথেষ্ট প্রমাণ হওয়া উচিত। আমরা নিশ্চয় তোমাদের পরীক্ষায় ফেলবো।"],
  "23:31": ["Subsequently, we established another generation after them.","পরবর্তীতে, আমরা তাদের পর আরেকটি প্রজন্মকে প্রতিষ্ঠা করেছিলাম।"],
  "23:32": ["We sent to them a messenger from among them, saying, \"You shall worship Allah. You have no other god beside Him. Would you not be righteous?\"","আমরা তাদের কাছে তাদের মধ্য থেকে একজন বার্তাবাহক পাঠিয়েছিলাম, এই বলে যে, “তোমরা আল্লাহর উপাসনা করবে। তাঁর পাশে তোমাদের অন্য কোন উপাস্য নেই। তোমরা কি সৎকর্মশীল হবে না?”"],
  "23:33": ["The leaders among his people who disbelieved and rejected the idea of the Hereafter—although we provided for them generously in this life—said, \"This is no more than a human being like you. He eats from what you eat, and drinks as you drink.","তার লোকদের মধ্যে যে নেতারা পরকালের ধারণাকে অবিশ্বাস ও প্রত্যাখ্যান করেছিল, -যদিও এই জীবনে আমরা তাদেরকে উদারভাবে দান করেছিলাম - বলল, “এ তো তোমাদের মত একজন মানুষের চেয়ে বেশি কিছু নয়। সে খায় যা থেকে  তোমরা খাও, এবং পান করে যেমন তোমরা পান  করো।”"],
  "23:34": ["\"If you obey a human being like you, then you are really losers.","“যদি তোমরা তোমাদেরই মতন একজন মানুষকে মান্য কর, তাহলে তোমরা আসলেই ক্ষতিগ্রস্ত হবে।"],
  "23:35": ["\"Does he promise you that, after you die and turn into dust and bones, you will come out again?","“সে কি তোমাদেরকে এই  প্রতিশ্রুতি দেয় যে, তোমরা মরে যেয়ে ধূলা এবং হাড়ে পরিণত হবার পর, তোমরা আবার আবির্ভূত হবে?"],
  "23:36": ["\"Impossible, impossible indeed is what is promised to you.","“অসম্ভব, সত্যিই অসম্ভব তোমাদেরকে যে  প্রতিশ্রুতি দেয়া হয়।"],
  "23:37": ["\"We only live this life—we live and die—and we will never be resurrected.","“আমরা শুধু এই জীবনেই বেঁচে থাকি - আমরা বেঁচে থাকি এবং মরে যাই-এবং আমরা কখনোই পুনরুত্থিত হবো না।"],
  "23:38": ["\"He is just a man who fabricated lies and attributed them to Allah. We will never believe him.\"","সে কেবলই একজন মানুষ যে মিথ্যা রচনা করেছে এবং সেগুলো আল্লাহর প্রতি আরোপ করেছে। আমরা কখনোই তাকে বিশ্বাস করবো না।"],
  "23:39": ["He said, \"My Lord, grant me victory, for they have disbelieved me.\"","সে বলল, “আমার প্রভু, আমাকে বিজয় দান করুন, কারণ তারা আমাকে অবিশ্বাস করেছে।”"],
  "23:40": ["He said, \"Soon they will be sorry.\"","তিনি বললেন, “শীঘ্রই তারা অনুতপ্ত হবে।”"],
  "23:41": ["The retribution struck them, equitably, and thus, we turned them into ruins. The wicked people perished.","শাস্তি তাদের আঘাত করল, ন্যায়সঙ্গত ভাবে এবং এভাবে, আমরা তাদেরকে ধ্বংসাবশেষে পরিণত করলাম। অন্যায়কারীরা ধ্বংস  হল।"],
  "23:42": ["Subsequently, we established other generations after them.","পরবর্তীতে, আমরা তাদের পর অন্যান্য প্রজন্মদের প্রতিষ্ঠা করেছিলাম।"],
  "23:43": ["No community can advance its predetermined fate, nor delay it.","কোন সম্প্রদায় এর পূর্বনির্ধারিত নিয়তি এগিয়ে নিতে পারে না, না পারে পেছাতে।"],
  "23:44": ["Then we sent our messengers in succession. Every time a messenger went to his community, they disbelieved him. Consequently, we annihilated them, one after the other, and made them history. The people who disbelieved have perished.","এরপর আমরা পর্যায়ক্রমে আমাদের বার্তাবাহক পাঠালাম। যতবারই কোন বার্তাবাহক তার সম্প্রদায়ের কাছে গিয়েছে, তারা তাকে অবিশ্বাস করেছে। পরিনামে, আমরা তাদের ধ্বংস করলাম, একটির পর আরেকটি, এবং তাদেরকে ইতিহাস বানালাম। অবিশ্বাস করা লোকেরা বিলুপ্ত হল।"],
  "23:45": ["Then we sent Moses and his brother Aaron with our revelations and a profound proof.","এরপর আমরা মুসা ও তার ভাই হারুনকে আমাদের প্রত্যাদেশাবলি এবং এক প্রগাঢ় প্রমাণ সহকারে পাঠিয়েছিলাম।"],
  "23:46": ["To Pharaoh and his elders, but they turned arrogant. They were oppressive people.","ফেরাউন এবং তার সভাসদের কাছে, কিন্তু তারা উদ্ধত হয়ে গেল। তারা অত্যাচারী লোক ছিল।"],
  "23:47": ["They said, \"Shall we believe for two men whose people are our slaves?\"","তারা বলল, “আমরা কি এমন দুজন মানুষের জন্য বিশ্বাস করবো যাদের লোকেরা আমাদের দাস?”"],
  "23:48": ["They rejected the two, and consequently, they were annihilated.","তারা সে দুজনকে প্রত্যাখ্যান করেছিল, এবং পরিনামে, এরা ধ্বংস হল।"],
  "23:49": ["We gave Moses the scripture, that they may be guided.","আমরা মুসাকে ঐশীগ্রন্থ দিয়েছিলাম, যাতে তারা পথপ্রাপ্ত হতে পারে।"],
  "23:50": ["We made the son of Mary and his mother a sign, and we gave them refuge on a mesa with food and drink.","আমরা মরিয়মের পুত্র এবং তার মাকে করলাম একটি নিদর্শন, এবং আমরা তাদেরকে খাদ্য ও পানীয় দিয়ে একটি সমতল পাহাড় চূড়ায় আশ্রয় প্রদান করেছিলাম।"],
  "23:51": ["O you messengers, eat from the good provisions, and work righteousness. I am fully aware of everything you do.","হে তোমরা বার্তাবাহকেরা, ভাল খাদ্যসামগ্রী থেকে খাও, এবং সৎকর্মশীল কাজ করো।"],
  "23:52": ["Such is your congregation—one congregation—and I am your Lord; you shall reverence Me.","এমনই তোমাদের ধর্মগোষ্ঠী- এক ধর্মগোষ্ঠী - এবং আমি তোমাদের প্রভু; তোমরা আমাকে ভক্তি করবে।"],
  "23:53": ["But they tore themselves into disputing factions; each party happy with what they have.","কিন্তু তারা নিজেদের বিবাদপূর্ণ উপদলে ছিন্ন করল। প্রত্যেক দল তাদের নিজেদেরটা নিয়ে খুশী।"],
  "23:54": ["Therefore, just leave them in their confusion, for awhile.","অতএব, তাদেরকে শুধু তাদের বিভ্রান্তিতে ছেড়ে দাও, কিছু সময়ের জন্য।"],
  "23:55": ["Do they think that, since we provided them with money and children,","তারা কি মনে করে যে, যেহেতু আমরা তাদেরকে অর্থ ও সন্তানাদি প্রদান করেছি,"],
  "23:56": ["we must be showering them with blessings? Indeed, they have no idea.","সেহেতু আমরা তাদের উপর অবশ্যই অনুগ্রহ বর্ষণও করতে থাকবো? বস্তুত, তাদের কোন ধারণা নেই।"],
  "23:57": ["Surely, those who are reverently conscious of their Lord,","নিশ্চিতই, যারা ভক্তির সাথে তাদের প্রভুর ব্যাপারে সচেতন,"],
  "23:58": ["And who believe in the revelations of their Lord,","এবং যারা তাদের প্রভুর প্রত্যাদেশে বিশ্বাস করে,"],
  "23:59": ["And who never set up any idols beside their Lord,","এবং যারা কখনোই তাদের প্রভুর পাশে কোন উপাস্য স্থাপন করে না,"],
  "23:60": ["As they give their charities, their hearts are fully reverent. For they recognize that they will be summoned before their Lord,","যখন তারা দান করে, তাদের হৃদয় তখন ভক্তিতে পূর্ণ থাকে। কারণ, তারা মানে যে তারা তাদের প্রভুর সামনে একত্রিত হবে,"],
  "23:61": ["They are eager to do righteous works; they compete in doing them.","তারা সৎ কাজ করতে আগ্রহী ; তারা সেগুলো করতে প্রতিযোগীতা করে।"],
  "23:62": ["We never burden any soul beyond its means, and we keep a record that utters the truth. No one will suffer injustice.","আমরা কখনও কোন আত্মার উপর তার  সাধ্যের অতিরিক্ত বোঝা চাপাই না, এবং আমরা একটি নথি রাখি যা সত্য বলে। কেউই অবিচার ভোগ করবে না।"],
  "23:63": ["Because their minds are oblivious to this, they commit works that do not conform with this; their works are evil.","তাদের অন্তর যেহেতু এর প্রতি বেখবর, তারা এমন কাজ করে এর সাথে যা মেলে না; তাদের কাজ মন্দ।"],
  "23:64": ["Then, when we requite their leaders with retribution, they complain.","এরপর, যখন আমরা তাদের নেতাদের শাস্তি দিয়ে প্রতিফল দেই , তারা অভিযোগ করে।"],
  "23:65": ["Do not complain now; you have given up all help from us.","এখন অভিযোগ করো না; তোমরা আমাদের সব সাহায্য পরিত্যাগ করেছ।"],
  "23:66": ["My proofs have been presented to you, but you turned back on your heels.","আমার প্রমাণাদি তোমাদের কাছে উপস্থাপন করা হচ্ছিল , কিন্তু তোমরা পিছু হটে গেলে।"],
  "23:67": ["You were too arrogant to accept them, and you defiantly disregarded them.","তোমরা এতো উদ্ধত ছিলে যে সেগুলো গ্রহণ করনি , এবং তোমরা স্পর্ধাসহকারে এগুলোকে উপেক্ষা করেছিলে।"],
  "23:68": ["Why do they not reflect upon this scripture? Do they not realize that they have received something never attained by their ancestors?","কেন তারা এই ঐশীগ্রন্থের বিষয়ে ভেবে দেখে না? তারা কি অনুধাবন করে না যে, তারা এমনকিছু পেয়েছে, যা কখনো তাদের পূর্বপুরুষেরা পায়নি?"],
  "23:69": ["Have they failed to recognize their messenger? Is this why they are disregarding him?","তারা কি তাদের বার্তাবাহকে চিনতে ব্যর্থ হয়েছে? এ কারণেই কি তারা তাকে উপেক্ষা করছে?"],
  "23:70": ["Have they decided that he is crazy? Indeed, he has brought the truth to them, but most of them hate the truth.","তারা কি সিদ্ধান্তে এসেছে যে সে পাগল? নিশ্চয়ই, সে তাদের কাছে সত্য এনেছে, কিন্তু তাদের বেশিরভাগই সত্যকে ঘৃণা করে।"],
  "23:71": ["Indeed, if the truth conformed to their wishes, there would be chaos in the heavens and the earth; everything in them would be corrupted. We have given them their proof, but they are disregarding their proof.","নিশ্চয়, সত্য যদি তাদের ইচ্ছামতো  হতো, তাহলে আকাশমন্ডলী ও পৃথিবীতে বিশৃঙ্খলা হতো; এদের মধ্যে সবকিছু কলুষিত হয়ে পড়তো। আমরা তাদেরকে তাদের প্রমাণ দিয়েছি, কিন্তু তারা তাদের প্রমাণ উপেক্ষা করছে।"],
  "23:72": ["Are you asking them for a wage? Your Lord's wage is far better. He is the best Provider.","তুমি কি তাদের কাছে কোন পারিশ্রমিক চাইছো? তোমরা প্রভুর দেয়া পারিশ্রমিক অনেক উত্তম। তিনি সর্বোত্তম জীবিকা প্রদানকারী।"],
  "23:73": ["Most assuredly, you are inviting them to a straight path.","নিশ্চিতভাবে, তুমি তাদেরকে এক সরল পথের দিকে আহবান করছ।"],
  "23:74": ["Those who disbelieve in the Hereafter will surely deviate from the right path.","যারা পরকালে অবিশ্বাস করে, অবশ্যই তারা সঠিক পথ থেকে বিচ্যুত হবে।"],
  "23:75": ["Even when we showered them with mercy, and relieved their problems, they plunged deeper into transgression, and continued to blunder.","এমনকি যখন আমরা তাদের উপর দয়া বর্ষণ করলাম, এবং তাদের সমস্যাগুলো দূর করে দিলাম, তখন সীমালঙ্ঘনে তারা আরো গভীরভাবে নিমজ্জিত হলো, এবং বিভ্রান্তিতে পড়েই রইল।"],
  "23:76": ["Even when we afflicted them with retribution, they never turned to their Lord imploring.","এমনকি যখন আমরা তাদেরকে শাস্তি ভোগ করালাম, তারা কখনো তাদের প্রভুর কাছে মিনতি করতে ফেরেনি।"],
  "23:77": ["Subsequently, when we requited them with the severe retribution they had incurred, they were shocked.","পরবর্তীতে, আমরা যখন তাদেরকে তাদের অর্জিত কঠিন শাস্তি দিয়ে প্রতিফল দিলাম, তারা প্রচণ্ড ধাক্কা খেলো।"],
  "23:78": ["He is the One who granted you the hearing, the eyesight, and the brains. Rarely are you appreciative.","তিনিই সেই সত্ত্বা যিনি তোমাদের দান করেছেন শ্রবনশক্তি, দৃষ্টিশক্তি, এবং মস্তিষ্ক। তোমরা খুব কমই কৃতজ্ঞ।"],
  "23:79": ["He is the One who established you on earth, and before Him you will be summoned.","তিনিই সেই সত্ত্বা যিনি তোমাদেরকে পৃথিবীতে প্রতিষ্ঠিত করেছেন, এবং তাঁর সামনেই তোমাদের তলব করা হবে।"],
  "23:80": ["He is the One who controls life and death, and He is the One who alternates the night and day. Do you not understand?","তিনিই সেই সত্ত্বা যিনি জীবন ও মৃত্যু নিয়ন্ত্রণ করেন, এবং তিনিই সেই সত্ত্বা যিনি রাত এবং দিনের পালা-বদল করান। তোমরা কি বোঝো না?"],
  "23:81": ["They said what their ancestors said.","তারা বলেছিল যা তাদের পূর্বপুরুষরা বলেছিল।"],
  "23:82": ["They said, \"After we die and become dust and bones, we get resurrected?","তারা বলেছিল, “আমরা মরে ধূলা ও হাড়ে পরিনত হবার পরও কি আমরা পুনরুত্থিত হবো?"],
  "23:83": ["\"Such promises were given to us and to our parents in the past. These are no more than tales from the past.\"","“অতীতেও এ ধরণের প্রতিশ্রুতি আমাদেরকে এবং আমাদের পিতামাতাদের দেয়া হয়েছিল। এগুলো অতীতের কল্পকাহিনীর চেয়ে বেশি কিছু নয়।”"],
  "23:84": ["Say, \"To whom belongs the earth and everyone on it, if you know?\"","বল, “পৃথিবী এবং এর উপরের সকলে কার অধীন, যদি তোমরা জেনে থাকো?”"],
  "23:85": ["They will say, \"To Allah.\" Say, \"Why then do you not take heed?\"","তারা বলবে, “আল্লাহর।” বল, “তাহলে কেন তোমরা মনোযোগী হও না?”"],
  "23:86": ["Say, \"Who is the Lord of the seven universes; the Lord of the great dominion?\"","বল, “ কে সাতটি মহাবিশ্বের প্রভু; মহা রাজত্যের প্রভু?"],
  "23:87": ["They will say, \"Allah.\" Say, \"Why then do you not turn righteous?\"","তারা বলবে, “আল্লাহ।” বল, “তাহলে কেন তোমরা সৎকর্মশীল হও না?”"],
  "23:88": ["Say, \"In whose hand is all sovereignty over all things, and He is the only one who can provide help, but needs no help, if you know?\"","বল, “কার হাতে রয়েছে সবকিছুর উপর সকল সার্বভৌমত্ত্ব, এবং একমাত্র তিনিই সাহায্য করতে পারেন, কিন্তু তাঁর কোনও সাহায্যের প্রয়োজন হয় না, যদি তোমরা জানো?”"],
  "23:89": ["They will say, \"Allah.\" Say, \"Where did you go wrong?\"","তারা বলবে, “আল্লাহ।” বল, “কোথায় তোমরা ভুল করেছ?”"],
  "23:90": ["We have given them the truth, while they are liars.","আমরা তাদেরকে সত্য দিয়েছি, অথচ তারা মিথ্যাবাদী।"],
  "23:91": ["Allah has never begotten a son. Nor was there ever any other god besides Him. Otherwise, each god would have declared independence with his creations, and they would have competed with each other for dominance. Allah be glorified; far above their claims.","আল্লাহ কখনোই কোন পুত্র জন্ম দেননি। না তাঁর পাশে কখনো অন্য কোন উপাস্য ছিল। অন্যথায়, প্রত্যেক উপাস্য তার সৃষ্টিকে নিয়ে স্বাধীনতা ঘোষণা করতো, এবং তারা  কর্তৃত্তের জন্য একে অন্যের সাথে প্রতিযোগিতা করতো। মহিমা আল্লাহর, তাদের দাবির অনেক উর্ধ্বে।"],
  "23:92": ["The Knower of all secrets and declarations; be He exalted, far above having a partner.","সকল গোপন ও প্রকাশ্য বিষয়ের জ্ঞাতা; তিনি সমুচ্চ, অংশীদার থাকা থেকে অনেক ঊর্ধ্বে।"],
  "23:93": ["Say, \"My Lord, whether You show me (the retribution) they have incurred,","বল, “আমার প্রভু,  তাদের অর্জিত (শাস্তি) আমাকে দেখান বা না দেখান,"],
  "23:94": ["\"My Lord, let me not be one of the transgressing people.\"","“আমার প্রভু, আমাকে সীমালংঘনকারী লোকদের একজন করবেন না।”"],
  "23:95": ["To show you (the retribution) we have reserved for them is something we can easily do.","তাদের জন্য আমাদের সংরক্ষিত (শাস্তি) এমনকিছু যা আমরা তোমাকে সহজেই দেখাতে  পারি।"],
  "23:96": ["Therefore, counter their evil works with goodness; we are fully aware of their claims.","সুতরাং, ভাল দিয়ে তাদের মন্দ কাজ প্রতিহত কর; আমরা তাদের দাবি সম্পর্কে পূর্ণ অবগত।"],
  "23:97": ["Say, \"My Lord, I seek refuge in You from the whispers of the devils.","বল, “আমার প্রভু, আমি আপনার কাছে শয়তানদের প্ররোচনা থেকে আশ্রয় চাই।"],
  "23:98": ["\"And I seek refuge in You, my Lord, lest they come near me.\"","“এবং আমি আপনার কাছে আশ্রয় চাই, আমার প্রভু, পাছে তারা আমার নিকটে চলে আসে।”"],
  "23:99": ["When death comes to one of them, he says, \"My Lord, send me back.","মৃত্যু যখন তাদের কারো কাছে আসে, সে বলে, “আমার প্রভু, আমাকে ফেরত পাঠান।"],
  "23:100": ["\"I will then work righteousness in everything I left.\" Not true. This is a false claim that he makes. A barrier will separate his soul from this world until resurrection.","“তাহলে আমি আমার ফেলে আসা সবকিছুতে সৎকাজ করবো।” সত্য নয়। এটি একটি মিথ্যা দাবি যা সে করে। একটি অন্তরায় এই দুনিয়া থেকে তার আত্মাকে আলাদা করে রাখবে পুনরুত্থান পর্যন্ত।"],
  "23:101": ["When the horn is blown, no relations among them will exist on that day, nor will they care about one another.","যখন শিঙায় ফুঁ দেয়া হবে, সেদিন তাদের মধ্যে কোন সম্পর্ক বিদ্যমান থাকবে না, না তারা একে অন্যের বিষয়ে পরোয়া করবে।"],
  "23:102": ["As for those whose weights are heavy, they will be the winners.","তাদের ক্ষেত্রে  যাদের ওজন ভারি হবে, তারাই হবে বিজয়ী।"],
  "23:103": ["Those whose weights are light are the ones who lost their souls; they abide in Hell forever.","তাদের ক্ষেত্রে যাদের ওজন হালকা, তারা সেই ব্যক্তি যারা তাদের আত্মা হারিয়েছে; তারা চিরদিন নরকে বাস করবে।"],
  "23:104": ["Fire will overwhelm their faces, and they last miserably therein.","আগুণ তাদের মুখমণ্ডল ছেয়ে ফেলবে, এবং তারা সেখানে স্থায়ী হবে শোচনীয়ভাবে।"],
  "23:105": ["Were not My revelations recited to you, and you kept on rejecting them?","আমার প্রত্যাদেশাবলি কি তোমাদের কাছে পাঠ করা হয়নি, এবং তোমরা কি সেগুলো প্রত্যাখ্যান করে যাও নি?"],
  "23:106": ["They will say, \"Our Lord, our wickedness overwhelmed us, and we were people gone astray.","তারা বলবে, “আমাদের প্রভু, আমাদের অন্যায় আমাদের আচ্ছন্ন করেছে এবং আমরাই বিপথগামী লোক ছিলাম।"],
  "23:107": ["\"Our Lord, take us out of this; if we return (to our old behavior), then we are really wicked.\"","“আমাদের প্রভু, আমাদেরকে এর থেকে বের করুন; যদি আমরা (আমাদের পুরনো স্বভাবে) ফিরে যাই, তাহলে আমরা আসলেই অন্যায়কারী।”"],
  "23:108": ["He will say, \"Abide therein, humiliated, and do not speak to Me.","তিঁনি বলবেন, “সেখানে বাস কর, অপদস্থ হয়ে, এবং আমার সাথে কথা বলো না।”"],
  "23:109": ["\"A group of My servants used to say, 'Our Lord, we have believed, so forgive us and shower us with mercy. Of all the merciful ones, You are the Most Merciful.'","“আমার বান্দাদের একটি দল বলতো, ‘আমাদের প্রভু, আমরা বিশ্বাস করেছি, তাই আমাদের ক্ষমা করুন এবং আমাদের উপর দয়া বর্ষণ করুন। সকল দয়াশীলদের মধ্যে আপনি সবচেয়ে দয়াশীল।’"],
  "23:110": ["\"But you mocked and ridiculed them, to the extent that you forgot Me. You used to laugh at them.","\"“কিন্তু তোমরা তাদের ব্যঙ্গ ও পরিহাস করেছিলে, এতটা পরিমাণে যে তোমরা আঁমাকেই ভুলে গিয়েছিলে।"],
  "23:111": ["\"I have rewarded them today, in return for their steadfastness, by making them the winners.\"","“তাদের অবিচলতার বদলে, আজ আমি তাদের পুরস্কৃত করেছি,  তাদেরকে বিজয়ী করে।”"],
  "23:112": ["He said, \"How long have you lasted on earth? How many years?\"","তিনি বললেন, “তোমরা পৃথিবীতে কত সময় কাটিয়েছো? কত বছর?”"],
  "23:113": ["They said, \"We lasted a day or part of a day. Ask those who counted.\"","তারা বলল, “আমরা একদিন বা একদিনের কিছু অংশ কাটিয়েছি। যারা গননা করেছে তাদের জিজ্ঞেস করুন।”"],
  "23:114": ["He said, \"In fact, you stayed but a brief interim, if you only knew.","তিনি বললেন, “প্রকৃতপক্ষে, তোমরা মাত্র অল্পকালই অবস্থান করেছিলে, যদি তোমরা জানতে।"],
  "23:115": ["\"Did you think that we created you in vain; that you were not to be returned to us?\"","“তোমরা কি মনে করেছিলে যে আমরা তোমাদের অনর্থক সৃষ্টি করেছি; যে তোমাদেরকে আমাদের কাছে ফিরিয়ে আনা হবে না?”"],
  "23:116": ["Most exalted is Allah, the true Sovereign. There is no other god beside Him; the Most Honorable Lord, possessor of all authority.","আল্লাহ সবচেয়ে উর্ধ্বে, প্রকৃত সার্বভৌমত্বের অধিকারী। তাঁর পাশাপাশি অন্য কোনও উপাস্য নেই; সর্বোচ্চ সম্মানিত প্রভু, সকল কর্তৃত্বের অধিকারী।"],
  "23:117": ["Anyone who idolizes beside Allah any other god, and without any kind of proof, his reckoning rests with his Lord. The disbelievers never succeed.","যে আল্লাহর পাশা পাশি অন্য উপাস্যদের ডাকে, এবং কোনও ধরণের প্রমাণ ছাড়াই, তার হিসাবকৃত বিষয় তার প্রভুর নিকট। অবিশ্বাসীরা কখনো সফল হয় না।"],
  "23:118": ["Say, \"My Lord, shower us with forgiveness and mercy. Of all the merciful ones, You are the Most Merciful.\"","বল, “আমার প্রভু, আমাদেরকে ক্ষমা ও করুণা বর্ষণ করুন।সকল করুণাময়ের মধ্যে আপনিই সর্বশ্রেষ্ঠ করুণাময়।”"],
  "24:1": ["A sura that we have sent down, and we have decreed as law. We have revealed in it clear revelations, that you may take heed.","একটি সুরা যা আমরা অবতীর্ণ করেছি, এবং আমরা একটি আইন হিসেবে জারি করেছি। আমরা এতে স্পষ্ট প্রত্যাদেশ প্রকাশ করেছি, যাতে তোমরা মনোযোগ দিতে পারো।"],
  "24:2": ["The adulteress and the adulterer you shall whip each of them a hundred lashes. Do not be swayed by pity from carrying out Allah's law, if you truly believe in Allah and the Last Day. And let a group of believers witness their penalty.","ব্যভিচারিণী নারী এবং ব্যভিচারি পুরুষ, এদের প্রত্যেককে তোমরা একশত কশাঘাত করবে। তাদের প্রতি সমবেদনা দ্বারা প্রভাবিত হয়ে আল্লাহর আইন নির্বাহ করা থেকে পিছপা হইয়ো না, যদি তোমরা সত্যই আল্লাহ ও শেষ দিনে বিশ্বাস করে থাকো। এবং একদল বিশ্বাসীদের প্রত্যক্ষ করতে দাও তাদের শাস্তি।"],
  "24:3": ["The adulterer will end up marrying an adulteress or an idol worshiper, and the adulteress will end up marrying an adulterer or an idol worshiper. This is prohibited for the believers.","ব্যভিচারি পুরুষ শেষ পর্যন্ত ব্যভিচারিণী নারী অথবা প্রতিমা উপাসককে বিয়ে করবে। এবং ব্যভিচারিণী শেষ পর্যন্ত ব্যভিচারি পুরুষ অথবা প্রতিমা উপাসককে বিয়ে করবে। এটা বিশ্বাসীদের জন্য নিষিদ্ধ।"],
  "24:4": ["Those who accuse married women of adultery, then fail to produce four witnesses, you shall whip them eighty lashes, and do not accept any testimony from them; they are wicked.","যারা বিবাহিত নারীদের ব্যভিচারের অপরাধে অভিযুক্ত করে, এরপর চারজন সাক্ষী হাজির করতে ব্যর্থ হয়, তোমরা তাদেরকে আশিটি কশাঘাত করবে, এবং তাদের থেকে কোন সাক্ষী গ্রহণ করো না; তারা অন্যায়কারী।"],
  "24:5": ["If they repent afterwards and reform, then Allah is Forgiver, Merciful.","এরপর যদি তারা অনুশোচনা করে ও সংশোধিত হয়, তবে আল্লাহ ক্ষমাশীল, করুণাময়।"],
  "24:6": ["As for those who accuse their own spouses, without any other witnesses, then the testimony may be accepted if he swears by Allah four times that he is telling the truth.","তাদের ক্ষেত্রে যারা নিজেদের সঙ্গিদের অভিযুক্ত করে, অন্য কোন সাক্ষী ছাড়া, তবে সাক্ষ্যটি  গ্রহণযোগ্য হতে পারে যদি সে আল্লাহর নামে চার বার শপথ করে যে সে সত্য বলছে।"],
  "24:7": ["The fifth oath shall be to incur Allah's condemnation upon him, if he was lying.","পঞ্চম শপথটি হবে আল্লাহর দণ্ডাদেশ তার উপর টেনে আনা, যদি সে মিথ্যা বলে থাকে।"],
  "24:8": ["She shall be considered innocent if she swears by Allah four times that he is a liar.","সে (নারী) নির্দোষ বিবেচিত হবে যদি সে (নারী) আল্লাহর নামে চার বার শপথ করে যে সে (পুরুষ) একজন মিথ্যাবাদী।"],
  "24:9": ["The fifth oath shall incur Allah's wrath upon her if he was telling the truth.","পঞ্চম শপথটি হবে আল্লাহর ক্রোধ তার উপর টেনে আনা, যদি সে (পুরুষ) সত্য বলে থাকে।"],
  "24:10": ["This is Allah's grace and mercy towards you. Allah is Redeemer, Most Wise.","এটা আল্লাহর দয়া এবং করুণা তোমাদের প্রতি। আল্লাহ আত্মার মুক্তিদানকারী, সবচেয়ে জ্ঞানী।"],
  "24:11": ["A gang among you produced a big lie. Do not think that it was bad for you; instead, it was good for you. Meanwhile, each one of them has earned his share of the guilt. As for the one who initiated the whole incident, he has incurred a terrible retribution.","তোমাদের মধ্যে একটি দল এক বড় মিথ্যা তৈরি করেছে। ভেবো না যে এটা তোমাদের জন্য মন্দ ছিল, বরং, এটা তোমাদের জন্য ভালো ছিল। ইতোমধ্যে, তাদের প্রত্যেকে এ অপরাধে  তার নিজের অংশ অর্জন করেছে। আর তার ক্ষেত্রে যে এই পুরো ঘটনার সুত্রপাত করেছিল, সে এক ভয়ানক শাস্তি টেনে এনেছে।"],
  "24:12": ["When you heard it, the believing men and the believing women should have had better thoughts about themselves, and should have said, \"This is obviously a big lie.\"","যখন তোমরা তা শুনলে, বিশ্বাসী পুরুষ এবং বিশ্বাসী নারীদের উচিত ছিল নিজেদের ব্যাপারে উত্তম ধারনা রাখা, এবং বলা উচিত ছিল, “এটা স্পষ্টতই এক বড় মিথ্যা”।"],
  "24:13": ["Only if they produced four witnesses (you may believe them). If they fail to produce the witnesses, then they are, according to Allah, liars.","শুধু যদি তারা চারজন সাক্ষী উপস্থিত করতো (তোমরা তাদের বিশ্বাস করতে পারতে)। যদি তারা সাক্ষী উপস্থিত করতে ব্যর্থ হয়, তবে তারা, আল্লাহর কাছে, মিথ্যাবাদী।"],
  "24:14": ["If it were not for Allah's grace towards you, and His mercy in this world and in the Hereafter, you would have suffered a great retribution because of this incident.","যদি তোমাদের প্রতি এই দুনিয়া ও পরকালে আল্লাহর অনুগ্রহ, এবং  তাঁর দয়া না হতো, তোমরা এই ঘটনার কারনে এক মহা শাস্তি ভোগ করতে।"],
  "24:15": ["You fabricated it with your own tongues, and the rest of you repeated it with your mouths without proof. You thought it was simple, when it was, according to Allah, gross.","তোমরা নিজেদের মুখে এ মিথ্যা উদ্ভাবন করেছিলে, এবং তোমাদের অন্যরা তা নিজের মুখে পুনরাবৃত্তি করছিলে প্রমান ছাড়াই। তোমরা ভেবেছিলে এটা সাধারন কিছু, যখন এটা ছিল, আল্লাহর কাছে গুরুতর ব্যাপার।"],
  "24:16": ["When you heard it, you should have said, \"We will not repeat this. Glory be to You. This is a gross falsehood.\"","যখন তোমরা তা শুনেছিলে, তোমাদের বলা উচিত ছিল, “আমরা এর পুনরাবৃত্তি করবো না। মহিমা তোমার। এটা এক ঘোর মিথ্যাচার”।"],
  "24:17": ["Allah admonishes you that you shall never do it again, if you are believers.","আল্লাহ তোমাদের সাবধান করেন যে তোমরা পুনরায় এরকম কখনো করবে না, যদি তোমরা বিশ্বাসী হও।"],
  "24:18": ["Allah thus explains the revelations for you. Allah is Omniscient, Wise.","আল্লাহ এভাবে তোমাদের জন্য প্রকাশনাবলী ব্যাখ্যা করেন। আল্লাহ সর্বজ্ঞ, প্রজ্ঞাময়।"],
  "24:19": ["Those who love to see immorality spread among the believers have incurred a painful retribution in this life and in the Hereafter. Allah knows, while you do not know.","বিশ্বাসীদের মধ্যে অনৈতিকতা ছড়িয়ে যাওয়া দেখতে যারা ভালোবাসে তারা এই জীবনে ও পরকালে টেনে এনেছে এক যন্ত্রণাদায়্ক শাস্তি। আল্লাহ জানেন, যখন তোমরা জানো না।"],
  "24:20": ["Allah showers you with His grace and mercy. Allah is Most Kind towards the believers, Most Merciful.","আল্লাহ তোমাদেরকে তাঁর অনুগ্রহ ও দয়া বর্ষণ করেন। আল্লাহ বিশ্বাসীদের প্রতি সবচেয়ে দয়ালু, সবচেয়ে করুণাময়।"],
  "24:21": ["O you who believe, do not follow the steps of Satan. Anyone who follows the steps of Satan, should know that he advocates evil and vice. If it were not for Allah's grace towards you, and His mercy, none of you would have been purified. But Allah purifies whomever He wills. Allah is Hearer, Knower.","ও যারা তোমরা বিশ্বাস করো, শয়তানের পদাঙ্ক অনুসরণ করো না। যে কেউ শয়তানের পদাঙ্ক অনুসরণ করে, তার জানা উচিত যে, সে মন্দ ও অনৈতিকতার ওকালতি করে। যদি তোমাদের প্রতি আল্লাহর অনুগ্রহ ও তার দয়া না হতো, তোমাদের কেউ পরিশুদ্ধ হতে না। কিন্তু আল্লাহ যাকে ইচ্ছা পরিশুদ্ধ করেন। আল্লাহ  শ্রবণকারী, জ্ঞাতা।"],
  "24:22": ["Those among you who are blessed with resources and wealth shall be charitable towards their relatives, the poor, and those who have immigrated for the sake of Allah. They shall treat them with kindness and tolerance; do you not love to attain Allah's forgiveness? Allah is Forgiver, Most Merciful.","তোমাদের মধ্যে পুঁজি ও সম্পদে যারা সৌভাগ্যশালী তারা তাদের আত্মীয়সজন, দরিদ্র এবং যারা আল্লাহর উদ্দেশ্যে দেশত্যাগ করেছে তাদের প্রতি দানশীল হবে। তারা তাদের সাথে দয়াশীল ও সহনশীল ব্যবহার করবে; তোমরা কি আল্লাহর ক্ষমা পেতে ভালবাসো না? আল্লাহ ক্ষমাশীল, সবচেয়ে দয়াময়।"],
  "24:23": ["Surely, those who falsely accuse married women who are pious believers have incurred condemnation in this life and in the Hereafter; they have incurred a horrendous retribution.","নিশ্চয়, বিবাহিত ধর্মভীরু বিশ্বাসী নারীদের উপর যারা মিথ্যা অভিযোগ আরোপ করে, তারা এই জীবন ও পরকালে দন্ডাদেশ টেনে এনেছে; তারা টেনে এনেছে এক ভয়ানক শাস্তি।"],
  "24:24": ["The day will come when their own tongues, hands, and feet will bear witness to everything they had done.","সে দিন আসবে যখন তাদের নিজেদের জিহবা, হাত, ও পা, যাকিছু তারা করেছিল তার সাক্ষী দেবে।"],
  "24:25": ["On that day, Allah will requite them fully for their works, and they will find out that Allah is the Truth.","সেই দিন, আল্লাহ তদেরকে তাদের কাজের জন্য পরিপূর্ণ প্রতিদান দেবেন, এবং তারা দেখবে যে আল্লাহই সত্য।"],
  "24:26": ["The bad women for the bad men, and the bad men for the bad women, and the good women for the good men, and the good men for the good women. The latter are innocent of such accusations. They have attained forgiveness and a generous reward.","মন্দ নারীরা মন্দ পুরুষের জন্য, এবং মন্দ পুরুষরা মন্দ নারীদের জন্য, এবং ভালো নারীরা ভালো পুরুষদের জন্য, এবং ভালো পুরুষরা ভালো নারীদের জন্য। এরা এমন অভিযোগের ক্ষেত্রে নির্দোষ। তারা ক্ষমা এবং এক উদার পুরুস্কার লাভ করেছে।"],
  "24:27": ["O you who believe, do not enter homes other than yours without permission from their inhabitants, and without greeting them. This is better for you, that you may take heed.","হে তোমরা যারা বিশ্বাস করো, তোমাদের নিজেদের ঘর ছাড়া অন্যের ঘরে সেখানে বসবাসকারীদের অনুমতি ছাড়া, এবং তাদেরকে অভিবাদন না করে প্রবেশ করো না এটা তোমাদের জন্য উত্তম, যাতে তোমরা মনোযোগ দিতে পারো।"],
  "24:28": ["If you find no one in them, do not enter them until you obtain permission. If you are told, \"Go back,\" you must go back. This is purer for you. Allah is fully aware of everything you do.","যদি তোমরা সেখানে কাউকে না পাও, সেখানে প্রবেশ করো না, যতক্ষণ না তোমরা অনুমতি পাও। যদি তোমাদেরকে বলা হয়, “ফিরে যাও, ” তোমরা অবশ্যই ফিরে যাবে। এটাই তোমাদের জন্য অধিকতর শুদ্ধ। যা কিছু তোমরা করো আল্লাহ সে সম্পর্কে সম্পূর্ণ অবগত।"],
  "24:29": ["You commit no error by entering uninhabited homes wherein there is something that belongs to you. Allah knows everything you reveal, and everything you conceal.","তোমরা কোন ভুল করো না বসতিহীন বাড়িতে প্রবেশ করে  যেখানে তোমাদের কিছু আছে। আল্লাহ জানেন সবকিছু যা তোমরা প্রকাশ করো, এবং সবকিছু যা তোমরা গোপন করো।"],
  "24:30": ["Tell the believing men that they shall subdue their eyes (and not stare at the women), and to maintain their chastity. This is purer for them. Allah is fully Cognizant of everything they do.","বিশ্বাসী পুরুষদের বল যে তারা যেন তাদের দৃষ্টি নত রাখে (এবং নারীদের দিকে তাকিয়ে না থাকে), এবং তারা যেন চরিত্র বজায় রাখে। এটা তাদের জন্য অধিকতর শুদ্ধ। যা কিছু তারা করে আল্লাহ সে সবকিছু সম্পর্কে সম্পূর্ণ অবগত।"],
  "24:31": ["And tell the believing women to subdue their eyes, and maintain their chastity. They shall not reveal any parts of their bodies, except that which is necessary. They shall cover their chests, and shall not relax this code in the presence of other than their husbands, their fathers, the fathers of their husbands, their sons, the sons of their husbands, their brothers, the sons of their brothers, the sons of their sisters, other women, the male servants or employees whose sexual drive has been nullified, or the children who have not reached puberty. They shall not strike their feet when they walk in order to shake and reveal certain details of their bodies. All of you shall repent to Allah, O you believers, that you may succeed.","আর বিশ্বাসী নারীদের বল তাদের দৃষ্টি নত রাখতে, এবং তারা যেন চরিত্র বজায় রাখে। তারা তাদের শরীরের কোন অংশ প্রকাশ করবে না, সেগুলো ছাড়া যা প্রয়োজনীয়। তারা তাদের বক্ষ ঢেকে রাখবে তাদের স্বামী, তাদের পিতা, তাদের স্বামীদের পিতা, তাদের পুত্র, তাদের স্বামীদের পুত্র, তাদের ভাই, তাদের ভাইদের পুত্র, তাদের বোনদের পুত্র, অন্য নারী, সেসব পুরুষ চাকর বা কর্মচারী যাদের যৌনশক্তি নিষ্ক্রিয় হয়ে গেছে, অথবা সেসব শিশু যারা বয়: সন্ধিতে পৌঁছেনি তারা ব্যতীত অন্যদের সামনে এই পরিধান নীতি শিথিল করবে না। হাটার সময় তারা তাদের পা জোরে আঘাত করবে না, তাদের শরীরের নির্দিষ্ট অঙ্গগুলোকে ঝাঁকানো এবং প্রকাশ করার উদ্দেশ্যে। তোমরা সকলে আল্লাহর কাছে অনুশোচনা করবে, হে বিশ্বাসীরা, যাতে তোমরা সফলকাম হতে পারো।"],
  "24:32": ["You shall encourage those of you who are single to get married. They may marry the righteous among your male and female servants, if they are poor. Allah will enrich them from His grace. Allah is Bounteous, Knower.","তোমাদের মধ্যে যারা অবিবাহিত, তাদেরকে বিবাহের জন্য উৎসাহিত করো। তারা বিয়ে করতে পারে তোমাদের অধস্তন সৎ-কর্মশীল পুরুষ এবং নারীদের, যদি তারা দরিদ্র হয়।  আল্লাহ তাদের নিজ অনুগ্রহে ধনী করে তুলবেন। আল্লাহ উদার, জ্ঞানী।"],
  "24:33": ["Those who cannot afford to get married shall maintain morality until Allah provides for them from His grace. Those among your servants who wish to be freed in order to marry, you shall grant them their wish, once you realize that they are honest. And give them from Allah's money that He has bestowed upon you. You shall not force your girls to commit prostitution, seeking the materials of this world, if they wish to be chaste. If anyone forces them, then Allah, seeing that they are forced, is Forgiver, Merciful.","যারা বিয়ে করার ব্যয়ভার বহন করতে পারে না তারা নৈতিকতা বজায় রাখবে যতক্ষণ না আল্লাহ তাঁর অনুগ্রহ থেকে তাদেরকে জীবিকা প্রদান করেন। তোমাদের দাস-দাসীদের মধ্যে যারা বিয়ে করার জন্য মুক্তি পেতে আশা, তোমরা তাদের আশা পুরন করবে, যখন তোমরা উপলব্ধি করো যে তারা সৎ। আর তাদেরকে আল্লাহর অর্থ থেকে দাও যা তিনি তোমাদের উপর অর্পণ করেছেন। তোমরা তোমাদের মেয়েদের পতিতাবৃত্তিতে বলপ্রয়োগ করবে না, এই বিশ্বের বস্তুসামগ্রির খোঁজে, যদি তারা সতীত্ব বজায় রাখতে চায়। যদি কেউ তাদেরকে বলপ্রয়োগ করে, তবে আল্লাহ ক্ষমাশীল, করুণাময়, এ কারণে  যে তাদেরকে বলপ্রয়োগ করা হচ্ছে।"],
  "24:34": ["We have revealed to you clarifying revelations, and examples from the past generations, and an enlightenment for the righteous.","আমরা তোমার কাছে প্রকাশ করেছি স্পষ্টকারী প্রকাশনাবলি, এবং অতীত প্রজন্ম থেকে উদাহরণ, আর সৎ-কর্মীদের জন্য একটি আলোক বর্তিকা।"],
  "24:35": ["Allah is the light of the heavens and the earth. The allegory of His light is that of a concave mirror behind a lamp that is placed inside a glass container. The glass container is like a bright, pearl-like star. The fuel thereof is supplied from a blessed oil-producing tree, that is neither eastern, nor western. Its oil is almost self-radiating; needs no fire to ignite it. Light upon light. Allah guides to His light whomever He wills. Allah thus cites the parables for the people. Allah is fully aware of all things.","আল্লাহ আকাশমন্ডলী ও পৃথিবীর আলো। তাঁর আলোর উপমা যেন একটি কাচেঁর পাত্রে স্থাপিত কোন প্রদীপের পিছনে থাকা একটি অবতল দর্পণ। কাচেঁর পাত্রটি যেন একটি উজ্জ্বল, মুক্তার মত  তারা। এর জ্বালানি সরবরাহ করা হয় একটি বরকতময় তেল উৎপাদনকারী গাছ থেকে, যা না পূর্বদেশীয়, না পশ্চিমা। এর তেল প্রায় স্ব-দ্যুতিমান, একে জ্বালাতে কোন আগুনের প্রয়োজন হয় না। আলোর উপর আলো। আল্লাহ যাকে ইচ্ছা তাঁর আলোর দিকে পথ দেখান। আল্লাহ এভাবে লোকদের জন্য রূপক বর্ণনা করেন। আল্লাহ সবকিছু সম্পর্কে সম্পূর্ণ অবগত।"],
  "24:36": ["(Allah's guidance is found) in houses exalted by Allah, for His name is commemorated therein. Glorifying Him therein, day and night—","আল্লাহর দ্বারা মর্যাদায় উন্নিত ঘর গুলোতে (আল্লাহর পথনির্দেশনা পাওয়া যায়), কেননা সেখানে তাঁর নাম স্মরণ করা হয়। সেখানে তাঁর পবিত্রতা ঘোষণা করা হয়, দিনে ও রাতে-"],
  "24:37": ["People who are not distracted by business or trade from commemorating Allah; they observe the Contact Prayers (Salat), and give the obligatory charity (Zakat), and they are conscious of the day when the minds and the eyes will be horrified.","লোকেদের যারা কর্মব্যস্ততা বা ব্যবসার কারণে আল্লাহর স্মরণ থেকে অন্যমনষ্ক হয় না; তারা সংযোগ প্রার্থনা (সালাত) পালন করে, এবং বাধ্যতামূলক  দান (যাকাত) দেয়, আর তারা সেদিন সম্পর্কে সচেতন, যখন মন ও চোখ আতঙ্কিত হবে।"],
  "24:38": ["Allah will certainly reward them for their good works, and will shower them with His grace. Allah provides for whomever He wills without limits.","আল্লাহ অবশ্যই তাদের ভালো কাজের জন্য তাদের পুরস্কৃত করবেন, এবং তাঁর অনুগ্রহ তাদের প্রতি বর্ষণ করবেন। আল্লাহ যাকে ইচ্ছা সীমাহীন জীবিকা দান করেন।"],
  "24:39": ["As for those who disbelieve, their works are like a mirage in the desert. A thirsty person thinks that it is water. But when he reaches it, he finds that it is nothing, and he finds Allah there instead, to requite him fully for his works. Allah is the most efficient reckoner.","তাদের ক্ষেত্রে যারা অবিশ্বাস করে, তাদের কাজগুলো মরুভূমির মরীচিকার মতো। তৃষ্ণার্ত ব্যক্তি ভাবে যে এটা পানি। কিন্তু যখন সে এর কাছে পৌঁছায়, সে দেখে যে এটা কিছুই না এবং সেখানে সে পরিবর্তে আল্লাহকে পায়, তাকে তার কাজের পূর্ণ প্রতিফল দেয়ার জন্য। আল্লাহ সবচেয়ে দক্ষ হিসাব গ্রহণকারী।"],
  "24:40": ["Another allegory is that of being in total darkness in the midst of a violent ocean, with waves upon waves, in addition to thick fog. Darkness upon darkness—if he looked at his own hand, he could barely see it. Whomever Allah deprives of light, will have no light.","আরেকটি উপমা হলো কোন উত্তাল মহাসাগরের মধ্যভাগে থাকা যেখানে আছে পুরোপুরি অন্ধকার, সাথে আছে ঢেউ এর উপর ঢেউ, আরো আছে ঘন কুয়াশা। অন্ধকারের উপর অন্ধকার – যদি সে তার নিজের হাতের দিকে তাকাতো, সে তা প্রায় দেখতেই পেতো না। যাকে আল্লাহ আলো থেকে বঞ্চিত করেন, তার কোন আলো থাকবে না।"],
  "24:41": ["Do you not realize that everyone in the heavens and the earth glorifies Allah, even the birds as they fly in a column? Each knows its prayer and its glorification. Allah is fully aware of everything they do.","তুমি কি অনুধাবন করো না যে আকাশমণ্ডলী ও পৃথিবীর সকলে আল্লাহর মহিমা ঘোষণা করে, এমনকি পাখিরাও, যখন তারা শ্রেণীবদ্ধ হয়ে উড়ে? প্রত্যেকে জানে নিজের প্রার্থনা এবং গুণকীর্তন পদ্ধতি। আল্লাহ সম্পূর্ণ জানেন যা কিছু তারা করে।"],
  "24:42": ["To Allah belongs the sovereignty of the heavens and the earth, and to Allah is the final destiny.","আকাশমণ্ডলী ও পৃথিবীর সার্বভৌম ক্ষমতা আল্লাহর, এবং আল্লাহর দিকেই চূড়ান্ত নিয়তি।"],
  "24:43": ["Do you not realize that Allah drives the clouds, then gathers them together, then piles them on each other, then you see the rain coming out of them? He sends down from the sky loads of snow to cover whomever He wills, while diverting it from whomever He wills. The brightness of the snow almost blinds the eyes.","তুমি কি অনুধাবন করো না যে আল্লাহ মেঘমালাকে চালনা করেন, তারপর এদেরকে একত্রে পুঞ্জিভুত করেন, এরপর এদের একটির উপর অন্যটিকে স্তুপ করেন, তারপর তুমি এদের থেকে বৃষ্টি বের হয়ে আসতে দেখ? তিনি আকাশ থেকে ভারী তুষারপাতবর্ষণ করেন যাকে ইচ্ছা ঢেকে দিতে, আবার যার থেকে ইচ্ছা একে সরিয়ে দেন। তুষারের উজ্জলতা চোখকে প্রায় অন্ধ করে দেয়।"],
  "24:44": ["Allah controls the night and day. This should be a lesson for those who possess eyes.","আল্লাহ রাত ও দিনকে নিয়ন্ত্রন করেন। এটা তাদের জন্য শিক্ষা হওয়া উচিৎ যারা দৃষ্টির অধিকারী।"],
  "24:45": ["And Allah created every living creature from water. Some of them walk on their bellies, some walk on two legs, and some walk on four. Allah creates whatever He wills. Allah is Omnipotent.","আর আল্লাহ প্রত্যেক জীবন্ত সৃষ্টিকে পানি থেকে সৃষ্টি করেছেন। তাদের কেউ কেউ পেটে ভর দিয়ে হাটে, কেউ দুই পায়ে হাটে, এবং কেউ চার পায়ে হাটে। আল্লাহ সৃষ্টি করেন যা তিনি ইচ্ছা করেণ। আল্লাহ সর্বশক্তিমান।"],
  "24:46": ["We have sent down to you clarifying revelations, then Allah guides whoever wills in a straight path.","আমরা তোমার কাছে স্পষ্টকারী প্রকাশনাবলী অবতীর্ণ করেছি, এরপর আল্লাহ যাকে ইচ্ছা সরল পথে পরিচালিত করেন।"],
  "24:47": ["They say, \"We believe in Allah and in the messenger, and we obey,\" but then some of them slide back afterwards. These are not believers.","তারা বলে, “আমরা আল্লাহ ও বার্তাবাহককে বিশ্বাস করি, এবং আমরা মান্য করি,” কিন্তু এরপর তাদের কেউ কেউ পরবর্তীতে পিছলে পিছনে পরে যায়। এরা বিশ্বাসী নয়।"],
  "24:48": ["When they are invited to Allah and His messenger to judge among them, some of them get upset.","যখন তাদেরকে তাদের মধ্যে ফয়সালা করার জন্য আল্লাহ এবং তাঁর বার্তাবাহকের দিকে আমন্ত্রন জানানো হয়, তদের কেউ কেউ মর্মাহত হয়।"],
  "24:49": ["However, if the judgment is in their favor, they readily accept it!","কিন্তু, রায় তাদের পক্ষে হলে, তারা নির্দ্বিধায় তা মেনে নেয়।"],
  "24:50": ["Is there a disease in their hearts? Are they doubtful? Are they afraid that Allah and His messenger may treat them unfairly? In fact, it is they who are unjust.","তাদের হৃদয়ে কি কোন রোগ আছে? তারা কি সন্দিহান? তারা কি ভয় পায় যে আল্লাহ এবং তাঁর বার্তাবাহক তাদের সাথে অন্যায় করতে পারেন? প্রকৃতপক্ষে, তারই অন্যায়কারী।"],
  "24:51": ["The only utterance of the believers, whenever invited to Allah and His messenger to judge in their affairs, is to say, \"We hear and we obey.\" These are the winners.","যখন তাদের বিষয়ে ফয়সালার করার জন্য আল্লাহ এবং তাঁর বার্তাবাহকের দিকে আমন্ত্রন জানানো হয়, তখন বিশ্বাসীদের উক্তি কেবল এটাই হয় “আমরা শুনি এবং আমরা মান্য করি”। এরাই জয়ী।"],
  "24:52": ["Those who obey Allah and His messenger, and reverence Allah and observe Him, these are the triumphant ones.","যারা আল্লাহ এবং তাঁর বার্তাবাহককে মান্য করে, এবং আল্লাহকে ভক্তি করে এবং তাঁকে মেনে চলে, এরাই বিজয়ী।"],
  "24:53": ["They swear by Allah, solemnly, that if you commanded them to mobilize, they would mobilize. Say, \"Do not swear. Obedience is an obligation. Allah is fully Cognizant of everything you do.\"","তারা আল্লাহর নামে শপথ করে, দৃঢ়ভাবে, যে যদি তুমি তাদেরকে সমবেত হবার আদেশ করতে, তারা সমবেত হতো। বল, “শপথ করো না। অনুগত থাকা একটি  দায়িত্ব। তোমরা যা কিছু করো আল্লাহ তা সম্পর্কে সম্পূর্ণ অবগত।\""],
  "24:54": ["Say, \"Obey Allah, and obey the messenger.\" If they refuse, then he is responsible for his obligations, and you are responsible for your obligations. If you obey him, you will be guided. The sole duty of the messenger is to deliver (the message).","বল, “আল্লাহকে মান্য করো, এবং মান্য করো বার্তাবাহককে।\" যদি তারা অগ্রাহ্য করে, তবে সে তার দায়িত্বের জন্য দায়ী, এবং তোমরা তোমাদের দায়িত্বের জন্য দায়ী। যদি তোমরা তাকে মান্য করো, তোমরা সুপথপ্রাপ্ত হবে। বার্তাবাহকের কর্তব্য তো কেবল (বার্তা) পৌঁছে দেয়া।"],
  "24:55": ["Allah promises those among you who believe and lead a righteous life, that He will make them sovereigns on earth, as He did for those before them, and will establish for them the religion He has chosen for them, and will substitute peace and security for them in place of fear. All this because they worship Me alone; they never set up any idols beside Me. Those who disbelieve after this are the truly wicked.","তোমাদের মধ্যে যারা বিশ্বাস করে এবং সৎ জীবন যাপন করে তাদেরকে আল্লাহ প্রতিশ্রুতি দেন যে, তিনি পৃথিবীতে তাদেরকে শাসন কর্তৃত্ব দান করবেন, যেমন তিনি তাদের পূর্ববর্তীদের যারা ছিল তাদের জন্য করেছিলেন, এবং তাদের জন্য প্রতিষ্ঠিত করবেন সে ধর্মকে যা তিনি তাদের জন্য পছন্দ করেছেন, এবং তাদের জন্য ভয়কে শান্তি ও নিরাপত্তা দিয়ে প্রতিস্থাপন করবেন। এসবের কারন হচ্ছে, তারা একমাত্র  আমার উপাসনা করে; তারা কখনো আমার পাশে কোন উপাস্য স্থাপন করে না। যারা এরপরও অবিশ্বাস করে, তারা সত্যিকার পাপী।"],
  "24:56": ["You shall observe the Contact Prayers (Salat) and give the obligatory charity (Zakat), and obey the messenger, that you may attain mercy.","তোমরা সংযোগ প্রার্থনা (সালাত) পালন করবে ও বাধ্যতামূলক দান (যাকাত) দেবে, এবং বার্তাবাহককে মান্য করবে, যাতে তোমরা দয়া অর্জন করতে পারো।"],
  "24:57": ["Do not think that those who disbelieve will ever get away with it. Their final abode is Hell; what a miserable destiny.","ভেবো না যারা অবিশ্বাস যারা অবিশ্বাস কোরে তারা কখনো পার পেয়ে যাবে। তাদের চূড়ান্ত বাসস্থান নরক; কি এক শোচনীয় নিয়তি।"],
  "24:58": ["O you who believe, permission must be requested by your servants and the children who have not attained puberty (before entering your rooms). This is to be done in three instances—before the Dawn Prayer, at noon when you change your clothes to rest, and after the Night Prayer. These are three private times for you. At other times, it is not wrong for you or them to mingle with one another. Allah thus clarifies the revelations for you. Allah is Omniscient, Most Wise.","হে তোমরা যারা বিশ্বাস করো, তোমাদের ভৃত্য ও শিশুরা যারা বয়ঃসন্ধিতে পৌঁছেনি, তাদেরকে অবশ্যই  (তোমাদের কক্ষে প্রবেশের আগে) অনুমতির জন্য অনুরোধ করতে হবে। তিনটি সময়ে এটি করতে হবে- ভোরের প্রার্থনার আগে, দুপুরে যখন তোমরা বিশ্রামের জন্য তোমাদের পোশাক পরিবর্তন করো, এবং রাতের প্রার্থনার পর। এগুলো তোমাদের জন্য তিনটি ব্যক্তিগত সময়। অন্য সময়ে, একে অন্যের সাথে মিলে যাওয়াতে তোমাদের বা তাদের  কোন দোষ নেই। আল্লাহ এভাবে প্রকাশনাবলি তোমাদের জন্য সুস্পষ্ট করেন। আল্লাহ সর্বজ্ঞ, সবচেয়ে জ্ঞানী।"],
  "24:59": ["Once the children reach puberty, they must ask permission (before entering) like those who became adults before them have asked permission (before entering). Allah thus clarifies His revelations for you. Allah is Omniscient, Most Wise.","যখন শিশুরা বয়ঃসন্ধিতে পৌঁছায়, তাদেরকে অবশ্যই (প্রবেশের আগে) অনুমতি চাইতে হবে, তাদের মত যারা তাদের পূর্বে প্রাপ্তবয়স্ক হয়ে (প্রবেশের আগে) অনুমতি চেয়েছে। আল্লাহ এভাবে তোমাদের জন্য তাঁর প্রকাশনাবলি সুস্পষ্ট করেন। আল্লাহ সর্বজ্ঞ, সবচেয়ে জ্ঞানী।"],
  "24:60": ["The elderly women who do not expect to get married commit nothing wrong by relaxing their dress code, provided they do not reveal too much of their bodies. To maintain modesty is better for them. Allah is Hearer, Knower.","বয়স্কা নারী যারা বিবাহের প্রত্যাশা করে না, তারা পোশাক পরিধান নীতিতে শিথিলতা করে কোন দোষ করে না, এ শর্তে যে তারা শরীরের খুব বেশি প্রকাশ করবে না। শালীনতা বজায় রাখা তাদের জন্য উত্তম। আল্লাহ শ্রোতা, জ্ঞাতা।"],
  "24:61": ["The blind is not to be blamed, the crippled is not to be blamed, nor the handicapped is to be blamed, just as you are not to be blamed for eating at your homes, or the homes of your fathers, or the homes of your mothers, or the homes of your brothers, or the homes of your sisters, or the homes of your fathers' brothers, or the homes of your fathers' sisters, or the homes of your mothers' brothers, or the homes of your mothers' sisters, or the homes that belong to you and you possess their keys, or the homes of your friends. You commit nothing wrong by eating together or as individuals. When you enter any home, you shall greet each other a greeting from Allah that is blessed and good. Allah thus explains the revelations for you, that you may understand.","অন্ধের কোন দোষ নেই, পঙ্গুর কোন দোষ নেই, অক্ষমেরও কোন দোষ নেই, ঠিক যেমন তোমাদের কোন দোষ নেই পানাহার করতে যদি তা নিজেদের ঘরে করো, অথবা তোমাদের পিতাদের ঘরে, অথবা তোমাদের মাতাদের ঘরে, অথবা তোমাদের ভাইদের ঘরে, অথবা তোমাদের বোনদের ঘরে, অথবা তোমাদের চাচাদের ঘরে, অথবা তোমাদের ফুপুদের ঘরে, অথবা তোমাদের মামাদের ঘরে, অথবা তোমাদের খালাদের ঘরে, অথবা সে ঘরে যা তোমাদের আর যার চাবি তোমাদের কাছে আছে, অথবা তোমাদের বন্ধুদের ঘরে। তোমরা কোন ভুল করো না একসাথে বা আলাদাভাবে আহার করে। যখন তোমরা কোন ঘরে প্রবেশ করো, তোমরা পরস্পরকে অভিবাদন জানাবে আল্লাহর পক্ষ থেকে পাওয়া সে অভিবাদনের মাধ্যমে, যা পবিত্র ও মঙ্গলময়। আল্লাহ এভাবে  প্রকাশনাবলি তোমাদের জন্য ব্যাখ্যা করেন যাতে তোমরা বুঝতে পারো।"],
  "24:62": ["The true believers are those who believe in Allah and His messenger, and when they are with him in a community meeting, they do not leave him without permission. Those who ask permission are the ones who do believe in Allah and His messenger. If they ask your permission, in order to tend to some of their affairs, you may grant permission to whomever you wish, and ask Allah to forgive them. Allah is Forgiver, Most Merciful.","প্রকৃত বিশ্বাসী তারা যারা আল্লাহ ও তাঁর বার্তাবাহককে বিশ্বাস করে, আর যখন তার সাথে কোন সামাজিক বৈঠকে থাকে, তারা অনুমতি ছাড়া তাকে ছেড়ে যায় না। যারা অনুমতি চায় তারাই তো সে ব্যাক্তি যারা আল্লাহ ও তাঁর বার্তাবাহককে বিশ্বাস করে। যদি তারা তোমার অনুমতি চায়, তাদের কোন কাজে যাবার জন্য, তুমি যাকেই ইচ্ছা অনুমতি দিতে পার, এবং আল্লাহর কাছে তাদের জন্য ক্ষমা চাও। আল্লাহ ক্ষমাশীল, পরম দয়ালু।"],
  "24:63": ["Do not treat the messenger's requests as you treat each others' requests. Allah is fully aware of those among you who sneak away using flimsy excuses. Let them beware—those who disobey his orders—for a disaster may strike them, or a severe retribution.","বার্তাবাহকের অনুরোধকে সেভাবে গন্য করো না যেভাবে তোমরা পরস্পরের অনুরোধকে গন্য করো। আল্লাহ তোমাদের মধ্যে তাদের ব্যাপারে পূর্ণ অবগত যারা চুপিসারে সরে পড়ে তুচ্ছ অজুহাত দেখিয়ে। তাদেরকে সতর্ক করো- যারা তার হুকুম অমান্য করে- কেননা এক বিপর্যয় তাদের আঘাত করতে পারে, অথবা এক কঠোর শাস্তি।"],
  "24:64": ["Absolutely, to Allah belongs everything in the heavens and the earth. He fully knows every condition you may be in. The day you are returned to Him, He will inform them of everything they had done. Allah is fully aware of all things.","নিঃসন্দেহে, আল্লাহর অধীনে রয়েছে আকাশমণ্ডলী ও পৃথিবীর সবকিছু। তোমরা থাকতে পারো এমন প্রত্যেক অবস্থা সম্পর্কে সম্পূর্ণরূপে তিনি জানেন। যেদিন তোমরা তাঁর কাছে ফিরে যাবে, তিনি তাদেরকে জানাবেন সে সম্পর্কে যা কিছু তারা করেছিল। আল্লাহ সবকিছু সম্পর্কে সম্পূর্ণ অবগত।"],
  "25:1": ["Most blessed is the One who revealed the Statute Book to His servant, so he can serve as a warner to the whole world.","সবচেয়ে অনুগ্রহময় সেই সত্ত্বা যিনি তাঁর বান্দার কাছে বিধানগ্রন্থ প্রকাশ করেছেন, যাতে সে পুরো বিশ্বের কাছে একজন সতর্ককারী হিসেবে কাজে আসতে পারে।"],
  "25:2": ["The One to whom belongs all sovereignty of the heavens and the earth. He never had a son, nor does He have any partners in sovereignty. He created everything in exact measure; He precisely designed everything.","সেই সত্ত্বা যাঁর অধীনে রয়েছে আকাশমণ্ডলী ও পৃথিবীর সার্বভৌমত্ব। কখনো তাঁর পুত্র ছিল না, না তাঁর কোন অংশীদার আছে সার্বভৌমত্বে। তিনি সবকিছু যথাযথ পরিমাপে সৃষ্টি করেছেন; তিনি সবকিছুর নকশা করেছেন সুনির্দিষ্টভাবে।"],
  "25:3": ["Yet, they set up beside Him gods who do not create anything—they themselves are created—and who possess no power to even harm or benefit themselves, nor do they possess any power to control life, or death, or resurrection.","এরপরও, তারা তাঁর পাশে উপাস্যদের স্থাপন করে যারা কোনকিছু সৃষ্টি করেনি- তারা নিজেরাই সৃষ্টি হয়েছে- এবং এমনকি তাদের নিজেদের ক্ষতি বা উপকার করারও কোন ক্ষমতা নেই, না তাদের কোন ক্ষমতা আছে জীবন, বা মৃত্যু, বা পুনরুত্থান নিয়ন্ত্রণের।"],
  "25:4": ["Those who disbelieved said, \"This is a fabrication that he produced, with the help of some other people.\" They have uttered a blasphemy and a falsehood.","যারা অবিশ্বাস করেছে তারা বলল, “এটি একটি মিথ্যা উদ্ভাবন যা সে তৈরী করেছে, অন্য আরোকিছু লোকের সাহায্যে।” তারা আল্লাহনিন্দা এবং এক মিথ্যাচার করেছে।"],
  "25:5": ["They also said, \"Tales from the past that he wrote down; they were dictated to him day and night.\"","তারা আরো বলেছে, “অতীতের কল্পকাহীনি যা সে লিখে রেখেছে; তারা দিনে-রাতে তার কাছে পাঠ করতো।"],
  "25:6": ["Say, \"This was revealed by the One who knows the Secret in the heavens and the earth. He is Forgiving, Most Merciful.\"","বল, \"এটি সেই সত্ত্বার দ্বারা প্রকাশিত যিনি আকাশ ও পৃথিবীর গোপন বিষয় জানেন। তিনি ক্ষমাশীল, পরম করুণাময়।\""],
  "25:7": ["And they said, \"How come this messenger eats the food and walks in the markets? If only an angel could come down with him, to serve with him as a preacher!\"","এবং তারা বলল, \"কেমন করে এই বার্তাবাহক খাবার খায় এবং বাজারে হাটে? শুধু  যদি কোন ফেরেশতা তার সাথে আসতো, তার সাথে ধর্মপ্রচারক হিসেবে কাজ করতে।\""],
  "25:8": ["Or, \"If only a treasure could be given to him!\" Or, \"If only he could possess an orchard from which he eats!\" The transgressors also said, \"You are following a bewitched man.\"","অথবা, \"শুধু যদি তাকে একটি ধনভাণ্ডার দেয়া হতো!” অথবা, \"শুধু যদি তার একটি ফলবাগান থাকতো যা থেকে সে খেত!” সীমালঙ্ঘনকারীরা আরো বলে, \"তোমরা একজন জাদুগ্রস্থ মানুষের অনুসরণ করছো।\""],
  "25:9": ["Note how they called you all kinds of names, and how this led them astray, never to find their way back.","লক্ষ্য করো কিভাবে তারা তোমাকে ডেকেছিল সব ধরণের নামে, এবং কিভাবে এটি তাদের বিপথে  নিয়েছে, কখনো তাদের পথ পুনরায় পাবার মত নয়।"],
  "25:10": ["Most blessed is the One who can, if He wills, give you much better than their demands—gardens with flowing streams, and many mansions.","সবচেয়ে অনুগ্রহময় সেই সত্ত্বা যিনি পারেন, যদি তিনি ইচ্ছা করেন, তোমাকে তাদের দাবী থেকে অনেক উত্তম দেন- প্রবাহিত ঝর্ণাসহ বাগান, এবং অনেক প্রাসাদ।"],
  "25:11": ["In fact, they have disbelieved in the Hour (Day of Resurrection), and we have prepared for those who disbelieve in the Hour a flaming Hell.","প্রকৃতপক্ষে, তারা অবিশ্বাস করেছে সেই সময়ের (পুনরুত্থান দিনে), এবং যারা সেই  সময়ের অবিশ্বাস করে আমরা  তাদের জন্য  প্রস্তুত রেখেছি জ্বলন্ত নরক।"],
  "25:12": ["When it sees them from afar, they will hear its rage and fuming.","যখন এটি দূর থেকে তাদেরকে দেখবে, তারা এর ক্রোধ এবং ধোঁয়ার শব্দ শুনবে।"],
  "25:13": ["And when they are thrown into it, through a narrow place, all shackled, they will declare their remorse.","আর তাদেরকে যখন তাতে নিক্ষেপ করা হবে, এক সংকীর্ণ জায়গা  দিয়ে, সকলকে শিকলবদ্ধ করে, তারা তাদের অনুতাপ প্রকাশ করবে।"],
  "25:14": ["You will not declare just a single remorse, on that day; you will suffer through a great number of remorses.","ঐ দিন, তোমরা শুধু একবার  অনুতাপ প্রকাশ করবে না; তোমরা অসংখ্য অনুতাপের মধ্যে দিয়ে যাবে।"],
  "25:15": ["Say, \"Is this better or the eternal Paradise that is promised for the righteous? It is their well deserved reward; a well deserved destiny.\"","বল, \"এটা ভালো, নাকি চিরস্থায়ী স্বর্গোদ্যান, যার প্রতিশ্রুতি   সৎকর্মশীলদের দেয়া হয়েছে? এটি তাদের  যথাযোগ্য পুরষ্কার; এক যথাযোগ্য নিয়তি।"],
  "25:16": ["They get anything they wish therein, forever. This is your Lord's irrevocable promise.","তারা সেখানে যাকিছু তাদের ইচ্ছা তা পায়, চিরদিন ধরে। এটি তোমার প্রভুর অলঙ্ঘনীয় অঙ্গীকার।"],
  "25:17": ["On the day when He summons them, together with the idols they had set up beside Allah, He will say, \"Have you misled these servants of Mine, or did they go astray on their own?\"","সে দিন যখন তিনি তাদের একত্রে তলব করবেন, সেই সব উপাস্যদের সাথে  যাদেরকে তারা আল্লাহর পাশে স্থাপন করেছিল, তিনি বলবেন, \"তোমরা কি আমার এই বান্দাদের  বিপথে পরিচালিত করেছিলে, নাকি তারা নিজেরাই বিপথে গিয়েছিলো?\""],
  "25:18": ["They will say, \"Be You glorified, it was not right for us to set up any lords beside You. But You allowed them to enjoy, together with their parents. Consequently, they disregarded the message and thus became wicked people.\"","তারা বলবে, \"আপনি মহিমান্বিত, এটি আমাদের জন্য ঠিক হতো না যে আমরা আপনার পাশে কোন  উপাস্য স্থাপন করি। কিন্তু, আপনি তাদেরকে উপভোগ করতে দিয়েছিলেন, তাদের মাতা-পিতার সাথে। পরিনামে, তারা সেই বার্তা উপেক্ষা করেছিল, এবং এভাবে অন্যায়কারীতে পরিনত হয়েছিল।"],
  "25:19": ["They have disbelieved in the message you have given them, and, consequently, you can neither protect them from the retribution they have incurred, nor can you help them in any way. Anyone among you who commits evil, we will commit him to severe retribution.","আপনি যে  বার্তা তাদের দিয়েছিলেন তারা তা অবিশ্বাস করেছে, এবং, পরিনামে, না তোমরা তাদেরকে তাদের টেনে আনা শাস্তি থেকে রক্ষা করতে পারবে, না তোমরা তাদেরকে কোনভাবে  সাহায্য করতে পারবে। তোমাদের মধ্যে যেকেউ মন্দ কাজ করে, আমরা তাকে কঠিন শাস্তিতে সোপর্দ করবো।"],
  "25:20": ["We did not send any messengers before you who did not eat food and walk in the markets. We thus test you by each other; will you steadfastly persevere? Your Lord is Seer.","আমরা তোমার আগে কোন বার্তাবাহক পাঠাইনি যে খাবার খেতো না এবং বাজারে চলাফেরা করতো না। আমরা এভাবে তোমাদেরকে পরস্পরের মাধ্যমে পরীক্ষা করি;  তোমরা কি দৃড়তার  সাথে অবিচল থাকবে? তোমাদের প্রভু দেখেন।"],
  "25:21": ["Those who do not expect to meet us said, \"If only the angels could come down to us, or we could see our Lord (we would then believe)!\" Indeed, they have committed a gross arrogance, and have produced a gross blasphemy.","যারা আমাদের সাথে সাক্ষাতের আশা করে না তারা বলল, \"শুধু যদি ফেরেশতারা আমাদের কাছে নেমে আসতো, অথবা আমরা আমাদের প্রভুকে দেখতে পারতাম (তবে আমরা বিশ্বাস করতাম)!” প্রকৃতপক্ষে, তারা চরম ঔদ্ধত্য প্রকাশ করেছে, এবং তৈরি করেছে এক স্থূল অসৎকর্মশীলতা।"],
  "25:22": ["The day they see the angels, it will not be good news for the guilty; they will say, \"Now, we are irreversibly confined.\"","যেদিন তারা ফেরেশতাদের দেখবে,  অপরাধীদের জন্য তা সুখবর হবে না; তারা বলবে, \"এখন, আমরা স্থায়ীভাবে আটকে গেছি।\""],
  "25:23": ["We will look at all the works they have done, and render them null and void.","আমরা তাদের সব কাজ দেখবো, এবং সেগুলোকে নাকচ করে দেবো।"],
  "25:24": ["The dwellers of Paradise are far better on that day; they will hear better news.","স্বর্গের বাসিন্দারা ঐদিন অনেক  উত্তম অবস্থায় থাকবে; তারা উত্তম সংবাদ শুনবে।"],
  "25:25": ["The heaven will break apart, into masses of clouds, and the angels will descend in multitudes.","আকাশমণ্ডলী বিদীর্ণ হবে, মেঘপুঞ্জে, এবং ফেরেশতারা দলে দলে নেমে আসবে।"],
  "25:26": ["All sovereignty on that day belongs to the Most Gracious. For the disbelievers, it will be a difficult day.","ঐ দিন সকল সার্বভৌমত্ব হবে পরম করুনাময়ের অধীনে। অবিশ্বাসীদের জন্য, তা হবে এক কঠিন দিন।"],
  "25:27": ["The day will come when the transgressor will bite his hands (in anguish) and say, \"Alas, I wish I had followed the path with the messenger.","সেদিন আসবে যখন সীমালঙ্ঘনকারী (নিদারুন যন্ত্রণায়) নিজের হাত কামড়াবে এবং বলবে, \"হায়, আমি যদি বার্তাবাহকের পথ অনুসরণ করতাম।"],
  "25:28": ["\"Alas, woe to me, I wish I did not take that person as a friend.","\"হায়, দূর্ভোগ আমার, আমি যদি ঐ ব্যক্তিকে আমার বন্ধু হিসেবে না নিতাম।"],
  "25:29": ["\"He has led me away from the message after it came to me. Indeed, the devil lets down his human victims.\"","“সে আমাকে বার্তা থেকে দূরে সরিয়ে দিয়েছে তা আমার কাছে আসার পর। নিশ্চয়, শয়তান তার মানব শিকারকে হতাশ করে। \""],
  "25:30": ["The messenger said, \"My Lord, my people have deserted this Quran.\"","বার্তাবাহক বলল, \"আমার প্রভু, আমার লোকেরা এই কুরআন পরিত্যাগ করেছে”।"],
  "25:31": ["We also set up against every prophet enemies from among the guilty. Your Lord suffices as a guide, a master.","আমরা অপরাধীদের মধ্যে থেকে প্রত্যেক নবীর বিরুদ্ধে শত্রুদেরও দাড় করাই। তোমার প্রভু  একজন পথপ্রদর্শক, একজন মনিব হিসেবে যথেষ্ট।"],
  "25:32": ["Those who disbelieved said, \"Why did not the Quran come through him all at once?\" We have released it to you gradually, in order to fix it in your memory. We have recited it in a specific sequence.","যারা অবিশ্বাস করেছে তারা বলল, “তার মাধ্যমে কুরআন পুরোটাই একবারে আসলো না কেন?”একে আমরা  ধীরে ধীরে তোমার কাছে প্রকাশ করেছি, তোমার স্মৃতিতে একে নিবদ্ধ করার জন্য। এটি একটি নির্দিষ্ট ক্রমে আমরা আবৃতি করেছি।"],
  "25:33": ["Whatever argument they come up with, we provide you with the truth, and a better understanding.","যে যুক্তিই তারা  নিয়ে আসুক না কেন, আমরা তোমাকে সত্য, ও এক উত্তম বোধশক্তি প্রদান করি।"],
  "25:34": ["Those who are forcibly summoned to Hell are in the worst position; they are the farthest from the right path.","যাদেরকে জোরপূর্বক নরকে তলব করা হবে তারা রয়েছে নিকৃষ্টতম অবস্থানে; সঠিক পথ থেকে এরা সবচেয়ে দূরে।"],
  "25:35": ["We have given Moses the scripture, and appointed his brother Aaron to be his assistant.","আমরা মূসাকে দিয়েছি  ঐশীগ্রন্থ, আর তার ভাই হারুনকে  নিযুক্ত করেছিলাম তার সহকারী হিসাবে।"],
  "25:36": ["We said, \"Go, both of you, to the people who rejected our revelations,\" and subsequently, we utterly annihilated the rejectors.","আমরা বললাম, \"যাও, তোমরা দু'জনই, সে লোকদের কাছে যারা আমাদের প্রকাশনাবলি প্রত্যাখ্যান করেছে,”এবং পরবর্তীতে, প্রত্যাখ্যানকারীদেরকে আমরা পুরোপুরি ধ্বংস করে দিয়েছিলাম।"],
  "25:37": ["Similarly, when the people of Noah disbelieved the messengers, we drowned them, and we set them up as a sign for the people. We have prepared for the transgressors a painful retribution.","একইভাবে, যখন নূহের লোকেরা বার্তাবাহকদের অবিশ্বাস করেছিল, তাদেরকে আমরা ডুবিয়ে দিয়েছিলাম, এবং লোকদের জন্য আমরা তাদেরকে একটি নিদর্শন হিসাবে স্থাপন করেছিলাম। সীমালঙ্ঘনকারীদের জন্য আমরা প্রস্তুত করেছি এক যন্ত্রণাদায়ক শাস্তি।"],
  "25:38": ["Also 'Ãd, Thamûd, the inhabitants of Al-Russ, and many generations between them.","আদ, সামূদ, আল-রাসের অধিবাসী, এবং তাদের মধ্যকার অনেক প্রজন্মকেও।"],
  "25:39": ["To each of these groups, we delivered sufficient examples, before we annihilated them.","এদের প্রত্যেক দলের কাছে, আমরা যথেষ্ট পরিমান উদাহরণ পাঠিয়েছিলাম, তাদেরকে আমরা ধ্বংস করার আগে।"],
  "25:40": ["They have passed by the community that was showered with a miserable shower (Sodom). Did they not see it? The fact is, they never believed in resurrection.","তারা সে জনপদ পাশ দিয়ে গিয়েছে যাদের উপর বর্ষন করা হয়েছিল এক শোচনীয় বর্ষণ (সডম)। তারা কি তা দেখেনি? প্রকৃত বিষয় হচ্ছে, তারা  কখনোই পুনরুত্থানে বিশ্বাস করেনি।"],
  "25:41": ["When they saw you, they always ridiculed you: \"Is this the one chosen by Allah to be a messenger?","যখন তারা তোমাকে দেখতো, তারা সবসময় তোমাকে উপহাস করতো: \"এই ব্যক্তিকেই  কি  আল্লাহ বার্তাবাহক হবার জন্য বেছে নিয়েছেন?"],
  "25:42": ["\"He almost diverted us from our gods, if it were not that we steadfastly persevered with them.\" They will certainly find out, when they see the retribution, who are the real strayers from the path.","\"সে আমাদের উপাস্যদের থেকে আমাদেরকে প্রায় সরিয়েই দিয়েছিল, যদিনা আমরা তাদের প্রতি দৃঢ়তার সাথে অবিচল থাকতাম। তারা নিশ্চয়ই জানতে পারবে, যখন তারা শাস্তি দেখবে, কারা প্রকৃতপক্ষে পথভ্রষ্ট।"],
  "25:43": ["Have you seen the one whose god is his own ego? Will you be his advocate?","তুমি কি সে ব্যক্তিকে দেখেছ যার উপাস্য তার নিজের অহংবোধ? তুমি কি তার ওকালতি করবে?"],
  "25:44": ["Do you think that most of them hear, or understand? They are just like animals; no, they are far worse.","তুমি কি মনে করো যে তাদের বেশিরভাগ শুনে, বা বুঝে? তারা তো কেবল পশুর মতো; না, তারা আরো অনেক নিকৃষ্ট।"],
  "25:45": ["Have you not seen how your Lord designed the shadow? If He willed, He could have made it fixed, then we would have designed the sun accordingly.","তুমি কি দেখনি কিভাবে তোমার প্রভু ছায়াকে নকশা করেছেন? তিনি চাইলে, একে স্থির করে দিতে পারতেন, তাহলে সূর্যকে আমরা সেরুপে নকশা করতাম।"],
  "25:46": ["But we designed it to move slowly.","কিন্তু আমরা এভাবে নকশা করেছি যাতে তা ধীরে চলে।"],
  "25:47": ["He is the One who designed the night to be a cover, and for you to sleep and rest. And He made the day a resurrection.","তিনিই সেই সত্ত্বা যিনি রাতকে  নকশা করেছেন একটি আবরণ হবার জন্য, এবং তোমাদের ঘুম ও বিশ্রামের জন্য। আর, তিনি দিনকে করেছেন একটি পুনরুত্থান।"],
  "25:48": ["He is the One who sends the winds with good omens of His mercy, and we send down from the sky pure water.","তিনিই সেই সত্ত্বা যিনি তাঁর দয়ার শুভ ইংগিত দিয়ে বাতাসকে পাঠান, এবং আমরা আকাশ থেকে বিশুদ্ধ পানি অবতীর্ণ করি।"],
  "25:49": ["With it, we revive dead lands and provide drink for our creations—multitudes of animals and humans.","তা দিয়ে, আমরা মৃত ভূমিকে পুনরুজ্জীবিত করি এবং পানীয় প্রদান করি আমাদের সৃষ্টিকূল- বহুগুন পশু ও মানুষের জন্য।"],
  "25:50": ["We have distributed it among them in exact measure, that they may take heed. But most people insist upon disbelieving.","আমরা একে তাদের মাঝে যথাযথ পরিমানে বন্টন করেছি, যাতে তারা উপদেশ গ্রহন করতে পারে। কিন্তু অধিকাংশ লোক অবিশ্বাসে অনড় থাকে।"],
  "25:51": ["If we willed, we could have sent to every community a warner.","যদি আমরা চাইতাম, প্রত্যেক সম্প্রদায়ের কাছে আমরা একজন সতর্ককারী পাঠাতে পারতাম।"],
  "25:52": ["Therefore, do not obey the disbelievers, and strive against them with this, a great striving.","একারণে, অবিশ্বাসীদের মান্য করো না, এবং এটি দিয়ে তাদের বিরুদ্ধে সংগ্রাম করো, এক মহা সংগ্রাম।"],
  "25:53": ["He is the One who merges the two seas; one is fresh and palatable, while the other is salty and undrinkable. And He separated them with a formidable, inviolable barrier (evaporation).","তিনিই সে সত্ত্বা যিনি দুই সাগরকে মিলিয়ে দেন; একটি মিষ্ট ও সুস্বাদু, যখন অন্যটি লবনাক্ত ও পানের অনপুযুক্ত। আর, তিনি এদেরকে এক দুর্ভেদ্য, অনতিক্রম্য অন্তরায় (বাষ্পীভবন) দিয়ে আলাদা করেছেন।"],
  "25:54": ["He is the One who created from water a human being, then made him reproduce through marriage and mating. Your Lord is Omnipotent.","তিনিই সে সত্ত্বা যিনি পানি থেকে সৃষ্টি করেছেন মানুষকে, এরপর বিয়ে ও সংগমের দ্বারা তাকে বংশবৃদ্ধি করতে সক্ষম করেছেন। তোমার প্রভু সর্বশক্তিমান।"],
  "25:55": ["Yet, they still set up beside Allah idols that cannot benefit them, nor harm them. Indeed, the disbeliever is an enemy of his Lord.","এরপরও, তারা আল্লাহর পাশে উপাস্যদের স্থাপন করে যারা না তাদের উপকার করতে পারে, না তাদের ক্ষতি করতে পারে। নিশ্চয়, অবিশ্বাসী তার প্রভুর শত্রু।"],
  "25:56": ["We have sent you (Rashad) as a deliverer of good news, as well as a warner.","আমরা তোমাকে (রাশাদ) পাঠিয়েছি একজন সুসংবাদ বহনকারী, সেই সাথে একজন সতর্ককারী হিসেবে।"],
  "25:57": ["Say, \"I do not ask you for any money. All I seek is to help you find the right path to your Lord, if this is what you choose.\"","বল, \"আমি তোমাদের কাছে কোন অর্থ চাই না। আমি তো কেবল তোমাদেরকে সাহায্য করতে চাই তোমাদের প্রভুর দিকে  সঠিক পথ পেতে, যদি তা তোমরা পছন্দ করো।"],
  "25:58": ["You shall put your trust in the One who is Alive—the One who never dies—and praise Him and glorify Him. He is fully Cognizant of His creatures' sins.","তুমি তোমার আস্থা সে সত্ত্বার উপর রাখবে যিনি জীবিত - সেই সত্ত্বা যিনি কখনো মারা যান না- আর তাঁর প্রশংসা করো এবং তাঁর মহিমা নিবেদন করো। তিনি তাঁর সৃষ্টিকূলের পাপের বিষয়ে সম্পূর্ন অবগত।"],
  "25:59": ["He is the One who created the heavens and the earth, and everything between them, in six days, then assumed all authority. The Most Gracious; ask about Him those who are well founded in knowledge.","তিনিই সেই সত্ত্বা যিনি সৃষ্টি করেছেন আকাশমণ্ডলী ও পৃথিবী, এবং এদের মধ্যকার সবকিছু, ছয় দিনে, এরপর সকল কর্তৃত্ব গ্রহন করেছেন। পরম করুণাময় ; তাঁর বিষয়ে জিজ্ঞেস করো তাদেরকে যারা জ্ঞানে সুপ্রতিষ্ঠিত।"],
  "25:60": ["When they are told, \"Fall prostrate before the Most Gracious,\" they say, \"What is the Most Gracious? Shall we prostrate before what you advocate?\" Thus, it only augments their aversion.","যখন তাদেরকে বলা হয়, \"সেজদাবনত হও পরম করুনাময়ের সামনে, তারা বলে, \"পরম করুণাময় কি? আমরা কি তাকে সেজদা করবো যার ওকালতি তুমি করো? এভাবে, এটি কেবল তাদের বিমুখতা বাড়ায়।"],
  "25:61": ["Most blessed is the One who placed constellations in the sky, and placed in it a lamp, and a shining moon.","পরম অনুগ্রহময় সেই সত্ত্বা যিনি  আকাশে রেখেছেন নক্ষত্রপুঞ্জ, আর এতে  রেখেছেন একটি প্রদীপ, এবং এক উজ্জ্বল/দীপ্তিময় চাঁদ।"],
  "25:62": ["He is the One who designed the night and the day to alternate: a sufficient proof for those who wish to take heed, or to be appreciative.","তিনিই সে সত্ত্বা যিনি রাত এবং দিনকে  নকশা করেছেন পালা-বদল করতে: এটি যথেষ্ট প্রমান তাদের জন্য যারা উপদেশ গ্রহন করতে, বা কৃতজ্ঞ হতে চায়।"],
  "25:63": ["The worshipers of the Most Gracious are those who tread the earth gently, and when the ignorant speak to them, they only utter peace.","তারাই পরম করুণাময়ের উপাসনাকারী যারা পৃথিবীতে নম্রভাবে হাটে, আর যখন অজ্ঞরা তাদের সাথে কথা বলে, তারা কেবল বলে শান্তি।"],
  "25:64": ["In the privacy of the night, they meditate on their Lord, and fall prostrate.","রাতের একান্তে, তাদের প্রভুর বিষয়ে ধ্যান করে, এবং সেজদাবনত হয়।"],
  "25:65": ["And they say, \"Our Lord, spare us the agony of Hell; its retribution is horrendous.","আর তারা বলে, \"আমাদের প্রভু, আমাদেরকে নরকের যন্ত্রণা থেকে নিষ্কৃতি দিন; এর শাস্তি ভয়ংকর।"],
  "25:66": ["\"It is the worst abode; the worst destiny.\"","এটি নিকৃষ্টতম আবাস; নিকৃষ্টতম নিয়তি।\""],
  "25:67": ["When they give, they are neither extravagant, nor stingy; they give in moderation.","তারা যখন দেয়, তারা না অপব্যয় করে, না কৃপণতা করে; তারা দেয় পরিমিত পরিমানে।"],
  "25:68": ["They never implore beside Allah any other god, nor do they kill any soul—for Allah has made life sacred—except in the course of justice. Nor do they commit adultery. Those who commit these offenses will have to pay.","তারা কখনো আল্লাহর পাশে অন্য কোন উপাস্যের কাছে মিনতি করে না, না তারা কোন আত্মাকে হত্যা করে- কারন আল্লাহ জীবনকে পবিত্র/অতি মূল্যবান করেছেন- বিচার প্রক্রিয়া ছাড়া। না তারা ব্যাভিচার করে। এ অপরাধগুলো যারা করে তাদেরকে মূল্য দিতে হবে।"],
  "25:69": ["Retribution is doubled for them on the Day of Resurrection, and they abide therein humiliated.","তাদের জন্য পুনরুত্থান দিনে শাস্তি দ্বিগুন করা হয়, আর সেখানে তারা বাস করে অপদস্থ অবস্থায়।"],
  "25:70": ["Exempted are those who repent, believe, and lead a righteous life. Allah transforms their sins into credits. Allah is Forgiver, Most Merciful.","তারা ছাড় পাবে যারা অনুশোচনা করে, বিশ্বাস করে, এবং সৎ জীবন-যাপন করে। আল্লাহ তাদের পাপগুলোকে কৃতিত্বে রূপান্তর করেন। আল্লাহ ক্ষমাকারী, সবচেয়ে দয়ালু।"],
  "25:71": ["Those who repent and lead a righteous life, Allah redeems them; a complete redemption.","যারা অনুশোচনা করে এবং সৎ জীবন-যাপন করে, আল্লাহ তাদেরকে উদ্ধার করেন; পরিপূর্ণভাবে।"],
  "25:72": ["They do not bear false witness. When they encounter vain talk, they ignore it.","তারা মিথ্যা সাক্ষী দেয় না। যখন তারা অনর্থক কথার মুখোমুখি হয়, তারা তা উপেক্ষা করে।"],
  "25:73": ["When reminded of their Lord's revelations, they never react to them as if they were deaf and blind.","যখন তাদের প্রভুর প্রত্যাদেশাবলি স্মরণ করিয়ে দেয়া হয়, তারা কখনো সেগুলোর প্রতি  বধির ও অন্ধের মতো প্রতিক্রিয়া  করে না।"],
  "25:74": ["And they say, \"Our Lord, let our spouses and children be a source of joy for us, and keep us in the forefront of the righteous.\"","আর তারা বলে, “আমাদের প্রভু, আমাদের জন্য আমাদের সহধর্মী/সহধর্মীনি ও সন্তানদেরকে আনন্দের উৎস করুন, এবং আমাদেরকে সৎ-কর্মীদের অগ্রভাগে রাখুন\"।"],
  "25:75": ["These are the ones who attain Paradise in return for their steadfastness; they are received therein with joyous greetings and peace.","এরা সে  ব্যক্তি যারা তাদের অবিচলতার বিনিময়ে স্বর্গ অর্জন করে; সেখানে তাদেরকে আনন্দঘন সম্ভাষন ও শান্তিপূর্ণ ভাবে গ্রহণ করা হয়।"],
  "25:76": ["Eternally they abide therein; what a beautiful destiny; what a beautiful abode.","চিরকাল তারা সেখানে বসবাস করে; কতই না চমৎকার নিয়তি; কতই না চমৎকার আবাস।"],
  "25:77": ["Say, \"You attain value at my Lord only through your worship. But if you disbelieve, you incur the inevitable consequences.\"","বল, “আমার প্রভুর নিকট তোমাদের উপাসনা দ্বারাই কেবল তোমরা মূল্য অর্জন করো। কিন্তু যদি তোমরা অবিশ্বাস করো, তোমরা টেনে আনবে অনিবার্য পরিনাম।\""],
  "26:1": ["T. S. M.","ত. স.ম."],
  "26:2": ["These (letters) constitute proofs of this clarifying scripture.","এইসব (অক্ষরগুলো) এই সুস্পষ্টকারী ঐশীগ্রন্থের প্রমাণাদি গঠন করে।"],
  "26:3": ["You may blame yourself that they are not believers.","তুমি হয়তো নিজেকে দোষ দিবে যে তারা বিশ্বাসী নয়।"],
  "26:4": ["If we will, we can send from the sky a sign that forces their necks to bow.","যদি আমরা চাই, আমরা আকাশ থেকে একটি নিদর্শন পাঠাতে পারি যা বলপূর্বক তাদের ঘাড়কে অবনত করবে।"],
  "26:5": ["Whenever a reminder from the Most Gracious comes to them, that is new, they turn away in aversion.","যখনই পরম করুণাময়ের পক্ষ থেকে কোন স্মারক তাদের কাছে আসে, যা নতুন, তারা অনীহায় মুখ ফিরিয়ে নেয়।"],
  "26:6": ["Since they disbelieved, they have incurred the consequences of their heedlessness.","যেহেতু তারা অবিশ্বাস করেছে, তারা তাদের অমনোযোগীতার পরিণাম ডেকে এনেছে।"],
  "26:7": ["Have they not seen the earth, and how many kinds of beautiful plants we have grown thereon?","তারা কি পৃথিবীটা দেখেনি, এবং সেখানে কত ধরনের সুন্দর উদ্ভিদ আমরা জন্মিয়েছি?"],
  "26:8": ["This should be a sufficient proof for them, but most of them are not believers.","এটা তাদের জন্য যথেষ্ট প্রমান হওয়া উচিৎ, কিন্তু তাদের বেশির ভাগ বিশ্বাসী নয়।"],
  "26:9": ["Most assuredly, your Lord is the Almighty, Most Merciful.","অত্যন্ত নিশ্চিত ভাবে, তোমার প্রভু সর্বশক্তিমান, পরম দয়ালু।"],
  "26:10": ["Recall that your Lord called Moses: \"Go to the transgressing people.","স্মরণ করো যে তোমার প্রভু মুসাকে ডেকেছিলেনঃ “সীমালঙ্ঘনকারী লোকদের কাছে যাও”।"],
  "26:11": ["\"Pharaoh's people; perhaps they reform.\"","“ফেরাউনের  লোকেরা; হয়তো তারা সংশোধিত হবে।”"],
  "26:12": ["He said, \"My Lord, I fear lest they disbelieve me.","সে বলল, “আমার প্রভু, আমার ভয় হয় পাছে তারা আমাকে অবিশ্বাস করে।"],
  "26:13": ["\"I may lose my temper. My tongue gets tied; send for my brother Aaron.","“আমার মেজাজ বিগড়ে যেতে পারে। আমার জিহবা আটকে যায়; আমার ভাই হারুনকে ডেকে পাঠান।"],
  "26:14": ["\"Also, they consider me a fugitive; I fear lest they kill me.\"","“তাছাড়া, তারা আমাকে একজন পলাতক হিসাবে দেখে; আমার ভয় হয় পাছে তারা আমাকে হত্যা করে।”"],
  "26:15": ["He said, \"No, (they will not). Go with My proofs. We will be with you, listening.","তিনি বললেন, “না, (তারা তা করবে না)। আমার প্রমাণাদি নিয়ে যাও। আমরা তোমাদের সাথে থাকবো, শুনবো।"],
  "26:16": ["\"Go to Pharaoh and say, 'We are messengers from the Lord of the universe.","“ফেরাউনের কাছে যাও এবং বলো, ‘আমরা মহাবিশ্বের প্রভুর পক্ষ থেকে বার্তাবাহক।"],
  "26:17": ["\" 'Let the Children of Israel go.' \"","“‘ইসরাইলের সন্তানদের যেতে দাও।’”"],
  "26:18": ["He said, \"Did we not raise you from infancy, and you spent many years with us?","সে বলল, “আমরা কি শিশুকাল থেকে তোমাকে বড় করিনি, আর তুমি আমাদের সাথে বহু বছর থেকেছ?"],
  "26:19": ["\"Then you committed the crime that you committed, and you were ungrateful.\"","“এরপর তোমার যা অপরাধ তা তুমি করেছ, এবং তুমি ছিলে অকৃতজ্ঞ।”"],
  "26:20": ["He said, \"Indeed, I did it when I was astray.","সে বলল, “নিশ্চয়, আমি তা করেছিলাম যখন আমি পথভ্রষ্ট ছিলাম।"],
  "26:21": ["\"Then I fled, when I feared you, and my Lord endowed me with wisdom and made me one of the messengers.","“এরপর আমি তোমাদের ভয়ে পালালাম, এবং আমার প্রভু আমাকে প্রজ্ঞা দান করলেন এবং আমাকে করলেন বার্তাবাহকদের একজন।"],
  "26:22": ["\"You are boasting that you did me a favor, while enslaving the Children of Israel!\"","“তুমি অহংকার করছো যে তুমি আমাকে অনুগ্রহ করেছিলে, অথচ ইসরাইলের সন্তানদের দাস করে রেখেছো!”"],
  "26:23": ["Pharaoh said, \"What is the Lord of the universe?\"","ফেরাউন বলল, “মহাবিশ্বের প্রভু কি?”"],
  "26:24": ["He said, \"The Lord of the heavens and the earth, and everything between them. You should be certain about this.\"","সে বলল, “আকাশমণ্ডলী ও পৃথিবী, এবং এদের মধ্যকার সবকিছুর প্রভু। এ বিষয়ে তোমাদের নিশ্চিত হওয়া উচিত।\""],
  "26:25": ["He said to those around him, \"Did you hear this?\"","সে তার চারপাশে যারা ছিল তাদের বলল, “তোমরা কি এমনকিছু শুনেছো?”"],
  "26:26": ["He said, \"Your Lord and the Lord of your ancestors.\"","সে বলল, “তোমাদের প্রভু এবং তোমাদের পূর্বপুরুষদের প্রভু।”"],
  "26:27": ["He said, \"Your messenger who is sent to you is crazy.\"","সে বলল, “তোমাদের  বার্তাবাহক যাকে তোমাদের কাছে পাঠানো হয়েছে সে  পাগল।\""],
  "26:28": ["He said, \"The Lord of the east and the west, and everything between them, if you understand.\"","সে বলল, “পূর্ব ও পশ্চিম, এবং এদের মধ্যকার সবকিছুর প্রভু, যদি তোমরা বুঝো।”"],
  "26:29": ["He said, \"If you accept any god, other than me, I will throw you in the prison.\"","সে বলল, “যদি তুমি কোন উপাস্য গ্রহন করো, আমাকে ছাড়া, আমি তোমাকে কারারুদ্ধ করবো।”"],
  "26:30": ["He said, \"What if I show you something profound?\"","সে বলল, “আমি যদি তোমাকে প্রগাঢ় কিছু দেখাই?”"],
  "26:31": ["He said, \"Then produce it, if you are truthful.\"","সে বলল, “তাহলে তা দেখাও, যদি তুমি সত্যবাদী হয়ে থাকো।”"],
  "26:32": ["He then threw his staff, whereupon it became a profound snake.","সে তখন তার লাঠি নিক্ষেপ করলো, যার ফলে এটি এক দৃশ্যমান সাপে পরিণত হলো।"],
  "26:33": ["And he took out his hand, and it was white to the beholders.","আর সে তার হাত বের করলো, এবং এটি দর্শকদের কাছে শুভ্র দেখাল।"],
  "26:34": ["He said to the elders around him, \"This is an experienced magician.","সে তার চারপাশের সভাসদদের বলল, “এ এক অভিজ্ঞ যাদুকর।"],
  "26:35": ["\"He wants to take you out of your land, with his magic. What do you suggest?\"","“সে তোমাদেরকে তোমাদের দেশ থেকে বের করে নিতে চায়, তার যাদু দিয়ে। তোমাদের পরামর্শ কি?”"],
  "26:36": ["They said, \"Respite him and his brother, and send summoners to every town.","তারা বলল, “তাকে ও তার ভাইকে অবকাশ দিন, এবং আহবানকারী পাঠান প্রত্যেক শহরে।"],
  "26:37": ["\"Let them summon every experienced magician.\"","“তারা ডেকে আনুক প্রত্যেক অভিজ্ঞ যাদুকরকে।”"],
  "26:38": ["The magicians were gathered at the appointed time, on the appointed day.","যাদুকরদের জড়ো করা হলো নির্ধারিত সময়ে, নির্ধারিত দিনে।"],
  "26:39": ["The people were told: \"Come one and all; let us gather together here.","লোকদের বলা হলো: “প্রত্যেকে আসো; চল একসাথে সবাই এখানে জড়ো হই।"],
  "26:40": ["\"Maybe we will follow the magicians, if they are the winners.\"","“হয়তো আমরা জাদুকরদের অনুসরণ করবো, যদি তারা জয়ী হয়।”"],
  "26:41": ["When the magicians came, they said to Pharaoh, \"Do we get paid, if we are the winners?\"","যখন যাদুকররা আসলো, তারা ফেরাউনকে বলল, \"আমাদেরকে কি কিছু দেওয়া হবে, যদি আমরাই বিজয়ী  হই? ”"],
  "26:42": ["He said, \"Yes indeed; you will even be close to me.\"","সে বলল, “হ্যা নিশ্চয়; এমনকি তোমরা আমার কাছের হবে।”"],
  "26:43": ["Moses said to them, \"Throw what you are going to throw.\"","মূসা তাদেরকে বলল, “ছুঁড়ো যা তোমরা ছুড়তে যাচ্ছ।”"],
  "26:44": ["They threw their ropes and sticks, and said, \"By Pharaoh's majesty, we will be the victors.\"","তারা তাদের রশি ও লাঠি ছুড়লো, এবং বলল, “মহামান্য ফেরাউন শপথ, আমরাই বিজয়ী হবো।"],
  "26:45": ["Moses threw his staff, whereupon it swallowed what they fabricated.","মূসা তার  লাঠি ছুড়লো, যার ফলে এটি গিলে ফেললো যা তারা বানিয়েছিল।"],
  "26:46": ["The magicians fell prostrate.","যাদুকররা সেজদায় পড়লো।"],
  "26:47": ["They said, \"We believe in the Lord of the universe.","তারা বলল, \"আমরা মহাবিশ্বের প্রভুকে বিশ্বাস করি।"],
  "26:48": ["\"The Lord of Moses and Aaron.\"","\"মূসা এবং হারুনের প্রভু।\""],
  "26:49": ["He said, \"Did you believe with him before I give you permission? He must be your teacher, who taught you magic. You will surely find out. I will cut your hands and feet on alternate sides. I will crucify you all.\"","সে বলল, \"আমি তোমাদের অনুমতি দেয়ার আগেই কি তোমরা তার সাথে বিশ্বাস করলে? সে নিশ্চয় তোমাদের শিক্ষক হবে, যে তোমাদেরকে যাদু শিখিয়েছে। নিশ্চয় তোমরা দেখতে পাবে। আমি বিপরীত দিক থেকে তোমাদের হাত ও পা  কাটবো। তোমাদের সবাইকে আমি ক্রুশবিদ্ধ করবো। \""],
  "26:50": ["They said, \"This will not change our decision; to our Lord we will return.","তারা বলল, “তা আমাদের সিদ্ধান্ত পরিবর্তণ করবে না; আমরাতো আমাদের প্রভুর নিকট ফিরে যাবো।"],
  "26:51": ["\"We hope that our Lord will forgive us our sins, especially that we are the first believers.\"","“আমরা আশা করি যে আমাদের প্রভু আমাদের পাপগুলো মাফ করবেন, বিশেষত যখন আমরাই প্রথম বিশ্বাসী।”"],
  "26:52": ["We inspired Moses: \"Travel with My servants; you will be pursued.\"","আমরা মূসাকে প্রত্যাদেশ করলামঃ “আমার বান্দাদের নিয়ে যাত্রা করো; তোমাদের পিছু নেয়া হবে।”"],
  "26:53": ["Pharaoh sent to the cities callers.","ফেরাউন শহরগুলোতে আহ্বানকারী পাঠালো।"],
  "26:54": ["(Proclaiming,) \"This is a small gang.","(ঘোষনা করতে যে,) “এটি ছোট একটা চক্র।"],
  "26:55": ["\"They are now opposing us.","তারা এখন আমাদের বিরোধীতা করছে।"],
  "26:56": ["\"Let us all beware of them.\"","আসো আমরা সবাই এদের বিষয়ে সতর্ক হই।”"],
  "26:57": ["Consequently, we deprived them of gardens and springs.","পরিনামে, আমরা তাদেরকে বঞ্চিত করেছি বাগান ও ঝর্ণা থেকে।"],
  "26:58": ["And treasures and an honorable position.","আর সম্পদ ও  সম্মানিত অবস্থান থেকে।"],
  "26:59": ["Then we made it an inheritance for the Children of Israel.","এরপর আমরা একে ইসরাইলের সন্তানদের জন্য একটি উত্তরাধিকার করলাম।"],
  "26:60": ["They pursued them towards the east.","তারা তাদেরকে পূর্বদিকে ধাওয়া করলো।"],
  "26:61": ["When both parties saw each other, Moses' people said, \"We will be caught.\"","যখন উভয় দল একে অন্যকে দেখলো, মূসার লোকেরা বলল, “আমরা ধরা পড়ে যাবো।”"],
  "26:62": ["He said, \"No way. My Lord is with me; He will guide me.\"","সে বলল, “কোনভাবেই না। আমার প্রভু আমার সাথে আছেন; তিনি আমাকে পথ দেখাবেন।’’"],
  "26:63": ["We then inspired Moses: \"Strike the sea with your staff,\" whereupon it parted. Each part was like a great hill.","আমরা তখন মূসাকে প্রত্যাদেশ করলামঃ “তোমার লাঠি দিয়ে সাগরে আঘাত করো,” যারফলে এটি ভাগ হয়ে গেলো। প্রত্যেক ভাগ ছিল এক বিশাল পাহাড়ের মতো।"],
  "26:64": ["We then delivered them all.","তখন আমরা তাদের সবাইকে পার করালাম।"],
  "26:65": ["We thus saved Moses and all those who were with him.","এভাবে আমরা মূসাকে এবং তার সাথে যারা ছিল সকলকে বাচালাম।"],
  "26:66": ["And we drowned the others.","আর আমরা অন্যদের ডুবিয়ে দিলাম।"],
  "26:67": ["This should be a sufficient proof, but most people are not believers.","এটি যথেষ্ট প্রমান হওয়া উচিত, কিন্তু অধিকাংশ লোকই বিশ্বাসী নয়।"],
  "26:68": ["Most assuredly, your Lord is the Almighty, Most Merciful.","অত্যন্ত নিশ্চিতভাবে, তোমার প্রভু সর্বশক্তিমান, সবচেয়ে দয়ালু।"],
  "26:69": ["Narrate to them Abraham's history.","তাদের কাছে ইব্রাহিমের ইতিহাস বর্ণনা করো।"],
  "26:70": ["He said to his father and his people, \"What is this you are worshiping?\"","সে তার পিতা ও তার লোকদের বলেছিল, “এটা কিসের উপাসনা  তোমরা  করছো?”"],
  "26:71": ["They said, \"We worship statues; we are totally devoted to them.\"","তারা বলল, “আমরা মূর্তির উপাসনা করি; আমরা এদের প্রতি সম্পূর্ণ  নিবেদিত।"],
  "26:72": ["He said, \"Can they hear you when you implore?","সে বলল, “তোমরা যখন প্রার্থনা করো তারা কি শুনতে পায়?”"],
  "26:73": ["\"Can they benefit you, or harm you?\"","তারা কি তোমাদের উপকার, বা ক্ষতি করতে পারে?”"],
  "26:74": ["They said, \"No; but we found our parents doing this.\"","তারা বলল, “না; কিন্ত আমরা আমাদের পিতা-মাতাকে এটি করতে দেখেছি।”"],
  "26:75": ["He said, \"Do you see these idols that you worship.","সে বলল, “তোমরা কি এইসব উপাস্যদের দেখো, তোমরা যাদের উপাসনা করো।"],
  "26:76": ["\"You and your ancestors.","“তোমরা এবং তোমাদের পূর্বপুরুষরা।"],
  "26:77": ["\"I am against them, for I am devoted only to the Lord of the universe.","আমি তাদের বিরুদ্ধে, কারণ আমি কেবল মহাবিশ্বের প্রভুর প্রতিই নিবেদিত।"],
  "26:78": ["\"The One who created me, and guided me.","সেই সত্ত্বা যিনি আমায় সৃষ্টি করেছেন, এবং আমাকে পথ দেখিয়েছেন।"],
  "26:79": ["\"The One who feeds me and waters me.","সেই সত্ত্বা যিনি আমাকে খাবার দেন এবং আমাকে পানি দেন।"],
  "26:80": ["\"And when I get sick, He heals me.","“আর যখন আমি অসুস্থ হই, তিনি আমাকে নিরাময় করেন।"],
  "26:81": ["\"The One who puts me to death, then brings me back to life.","“সেই সত্ত্বা যিনি আমাকে মৃত্যু দেন, এরপর আবার আমাকে জীবন দেন।"],
  "26:82": ["\"The One who hopefully will forgive my sins on the Day of Judgment.","“সেই সত্ত্বা যিনি বিচার দিনে আশা করি   আমার পাপগুলো ক্ষমা করে দেবেন।"],
  "26:83": ["\"My Lord, grant me wisdom, and include me with the righteous.","“আমার প্রভু, আমাকে প্রজ্ঞা দান করূন, এবং আমাকে সৎকর্মশীলদের অন্তর্ভূক্ত করুন।"],
  "26:84": ["\"Let the example I set for the future generations be a good one.","“আমি যেন ভবিষ্যৎ প্রজন্মের জন্য একটি ভাল উদাহরণ স্থাপন করি।"],
  "26:85": ["\"Make me one of the inheritors of the blissful Paradise.","“আমাকে পরম সুখের স্বর্গের উত্তরাধিকারীদের একজন করুন।"],
  "26:86": ["\"And forgive my father, for he has gone astray.","“আর আমার পিতাকে ক্ষমা করুন, যেহেতু সে বিপথে গিয়েছে।"],
  "26:87": ["\"And do not forsake me on the Day of Resurrection.\"","“এবংপুনরুত্থান দিনে আমাকে পরিত্যাগ করবেন না।”"],
  "26:88": ["That is the day when neither money, nor children, can help.","এটা সে দিন যখন না অর্থ, না সন্তানাদি, সাহায্য করতে পারবে।"],
  "26:89": ["Only those who come to Allah with their whole heart (will be saved).","কেবল তারা (রক্ষা পাবে) যারা তাদের পুরো হৃদয় সহ আল্লাহর কাছে আসে।"],
  "26:90": ["Paradise will be presented to the righteous.","সৎকর্মশীলদের কাছে স্বর্গ উপাস্থাপন করা হবে।"],
  "26:91": ["Hell will be set up for the strayers.","পথভ্রষ্টদের জন্য নরক স্থাপন করা হবে।"],
  "26:92": ["They will be asked, \"Where are the idols you had worshiped","তাদেরকে জিজ্ঞেস করা হবে, “তোমাদের উপাস্যরা কোথায় তোমরা যাদের উপাসনা করতে।"],
  "26:93": ["\"beside Allah? Can they help you now? Can they help themselves?\"","“আল্লাহর পাশে? তারা কি এখন তোমাদের সাহায্য করতে পারে? তারা কি তাদের নিজেদের সাহায্য করতে পারে?”"],
  "26:94": ["They will be thrown therein, together with the strayers.","তাদেরকে তার মধ্যে নিক্ষেপ করা হবে, পথভ্রষ্টদের সাথে একসঙ্গে।"],
  "26:95": ["And all of Satan's soldiers.","আর শয়তানের সকল সৈন্যদের।"],
  "26:96": ["They will say as they feud therein,","তারা বলবে যেহেতু তারা সেখানে কলহ করবে,"],
  "26:97": ["\"By Allah, we were far astray.","“আল্লাহর শপথ, আমরা অনেক পথভ্রষ্ট ছিলাম।"],
  "26:98": ["\"How could we set you up to rank with the Lord of the universe?","“কিভাবে আমরা তোমাদেরকে মহাবিশ্বের প্রভুর সাথে সমকক্ষ করতে পারলাম?"],
  "26:99": ["\"Those who misled us were wicked.","“যারা আমাদেরকে ভুল পথে চালিয়েছিল তারা ছিল অন্যায়কারী।"],
  "26:100": ["\"Now we have no intercessors.","“এখন আমাদের কোন সুপারিশকারি নাই।"],
  "26:101": ["\"Nor a single close friend.","“না কোন অন্তরঙ্গ বন্ধু।"],
  "26:102": ["\"If only we could get another chance, we would then believe.\"","“যদি শুধু আমরা আরেকটি সুযোগ পেতাম, আমরা তবে বিশ্বাস করতাম”"],
  "26:103": ["This should be a good lesson. But most people are not believers.","এটি একটি ভালো শিক্ষা হওয়া উচিত। কিন্তু অধিকাংশ লোক বিশ্বাসী নয়।"],
  "26:104": ["Your Lord is the Almighty, Most Merciful.","তোমার প্রভু সর্বশক্তিমান, সবচেয়ে দয়ালু।"],
  "26:105": ["The people of Noah disbelieved the messengers.","নূহের লোকেরা বার্তাবাহকদের অবিশ্বাস করেছিলো।"],
  "26:106": ["Their brother Noah said to them, \"Would you not be righteous?","তাদের ভাই নূহ তাদেরকে বলল, “তোমরা কি সৎকর্মশীল হবে না?"],
  "26:107": ["\"I am an honest messenger to you.","“আমি তোমাদের প্রতি এক বিশ্বস্ত বার্তাবাহক।।"],
  "26:108": ["\"You shall reverence Allah and obey me.","“তোমরা আল্লাহকে ভক্তি করবে এবং আমাকে মান্য করবে।"],
  "26:109": ["\"I do not ask you for any wage. My wage comes from the Lord of the universe.","“আমি তোমাদের কাছে কোন পারিশ্রমিক চাই না। আমার পারিশ্রমিক আসে মহাবিশ্বের প্রভুর কাছ থেকে।"],
  "26:110": ["\"You shall reverence Allah and obey me.\"","“তোমরা আল্লাহকে ভক্তি করবে এবং আমাকে মান্য করবে।”"],
  "26:111": ["They said, \"How can we believe with you, when the worst among us have followed you?\"","তারা বলল, “কিভাবে আমরা তোমার সাথে বিশ্বাস করতে পারি, যখন আমাদের মধ্যে যারা নিকৃষ্ট তারা তোমাকে অনুসরণ করেছে?”"],
  "26:112": ["He said, \"How do I know what they did?","সে বলল, “তারা কি করেছে আমি  কেমন করে জানবো?"],
  "26:113": ["\"Their judgment rests only with my Lord, if you could perceive.","“তাদের বিচারের ভার তো কেবল আমার প্রভুর কাছে, যদি তোমরা অনুধাবন করতে পারতে।"],
  "26:114": ["\"I will never dismiss the believers.","“আমি কখনো বিশ্বাসীদের অগ্রাহ্য করবো না।"],
  "26:115": ["\"I am no more than a clarifying warner.\"","“আমি একজন স্পষ্ট সতর্ককারীর চেয়ে বেশি কিছু নই।”"],
  "26:116": ["They said, \"Unless you refrain, O Noah, you will be stoned.\"","তারা বলল, “যদি না তুমি বিরত হও, হে নূহ, তোমাকে পাথর মারা হবে।”"],
  "26:117": ["He said, \"My Lord, my people have disbelieved me.","সে বলল, “আমার প্রভু, আমার লোকেরা আমাকে অবিশ্বাস করেছে।"],
  "26:118": ["\"Grant me victory against them, and deliver me and my company of believers.\"","“আমাকে তাদের বিরুদ্ধে বিজয় দান করুন, আর আমাকে এবং আমার বিশ্বাসী সাথীদের উদ্ধার করুন।”"],
  "26:119": ["We delivered him and those who accompanied him in the loaded ark.","আমরা উদ্ধার করেছিলাম তাকে এবং তাদেরকে যারা তার সাথে ছিল বোঝাইকৃত নৌকায়।"],
  "26:120": ["Then we drowned the others.","এরপর আমরা অন্যদের ডুবিয়ে দিয়েছিলাম।"],
  "26:121": ["This should be a lesson, but most people are not believers.","এটা একটা শিক্ষা হওয়া উচিত, কিন্তু অধিকাংশ লোক বিশ্বাসী নয়।"],
  "26:122": ["Most assuredly, your Lord is the Almighty, Most Merciful.","অত্যন্ত নিশ্চিতভাবে, তোমার প্রভু সর্বশক্তিমান, সবচেয়ে দয়ালু।"],
  "26:123": ["Ãd disbelieved the messengers.","আদ জাতি  বার্তাবাহকদের অবিশ্বাস করেছিল।"],
  "26:124": ["Their brother Hûd said to them, \"Would you not be righteous?","তাদের ভাই হুদ তাদেরকে বলেছিল, \"তোমরা কি সৎকর্মশীল হবে না?"],
  "26:125": ["\"I am an honest messenger to you.","\"আমি তোমাদের কাছে এক বিশ্বস্ত বার্তাবাহক।"],
  "26:126": ["\"You shall reverence Allah, and obey me.","তোমরা আল্লাহকে ভক্তি করবে, এবং আমাকে মান্য করবে।"],
  "26:127": ["\"I do not ask you for any wage; my wage comes from the Lord of the universe.","\"আমি তোমাদের কাছে কোন পারিশ্রমিক চাই না; আমার পারিশ্রমিক আসে মহাবিশ্বের প্রভুর কাছ থেকে।"],
  "26:128": ["\"You build on every hill a mansion for vanity's sake.","\"তোমরা প্রত্যেক পাহাড়ে অট্রালিকা বানাও অহমিকা ভরে।"],
  "26:129": ["\"You set up buildings as if you last forever.","\"তোমরা দালান বানাও এমন ভাবে যেন তোমরা চিরকাল টিকে থাকবে।"],
  "26:130": ["\"And when you strike, you strike mercilessly.","\"আর যখন তোমরা আঘাত করো, তোমরা আঘাত করো নির্দয়ভাবে।"],
  "26:131": ["\"You shall reverence Allah and obey me.","\"তোমরা আল্লাহকে ভক্তি করবে এবং আমাকে মান্য করবে।"],
  "26:132": ["\"Reverence the One who provided you with all the things you know.","\"সে সত্ত্বাকে ভক্তি করো যিনি তোমাদের প্রদান করেছেন সে সবকিছু যা তোমরা জানো।"],
  "26:133": ["\"He provided you with livestock and children.","\"তিনি তোমাদেরকে গৃহপালিত পশু ও সন্তানাদি প্রদান করছেন।"],
  "26:134": ["\"And gardens and springs.","\"আর বাগান ও ঝর্ণাসমূহ।"],
  "26:135": ["\"I fear for you the retribution of an awesome day.\"","\"আমি তোমাদের জন্য এক ভয়ানক দিনের শাস্তির ভয় করি।\""],
  "26:136": ["They said, \"It is the same whether you preach, or not preach.","তারা বলল, \"তুমি প্রচার করো আর না করো উভয় সমান।"],
  "26:137": ["\"That affliction was limited to our ancestors.","\"ঐ দূর্ভোগ আমাদের পূর্বপুরুষ পর্যন্তই সীমাবদ্ধ ছিল।"],
  "26:138": ["\"No retribution will ever befall us.\"","\"কখনোই কোন শাস্তি আমাদের উপর  আসবে না।\""],
  "26:139": ["They thus disbelieved and, consequently, we annihilated them. This should be a lesson, but most people are not believers.","এভাবে তারা অবিশ্বাস করলো এবং, পরিনামে, আমরা তাদেরকে ধ্বংস করলাম। এটি একটি শিক্ষা হওয়া উচিত, কিন্তু অধিকাংশ লোক বিশ্বাসী নয়।"],
  "26:140": ["Most assuredly, your Lord is the Almighty, Most Merciful.","অত্যন্ত নিশ্চিতভাবে, তোমার প্রভু সর্বশক্তিমান, সবচেয়ে দয়ালু।"],
  "26:141": ["Thamûd disbelieved the messengers.","সামূদ জাতি বার্তাবাহকদের অবিশ্বাস করেছিল।"],
  "26:142": ["Their brother Sãleh said to them, \"Would you not be righteous?","তাদের ভাই সালেহ তাদেরকে বলেছিল, \"তোমরা কি সৎকর্মশীল হবে না?"],
  "26:143": ["\"I am an honest messenger to you.","\"আমি তোমাদের কাছে একজন বিশ্বস্ত বার্তাবাহক।"],
  "26:144": ["\"You shall reverence Allah, and obey me.","\"তোমরা আল্লাহকে ভক্তি করবে, এবং আমাকে মান্য করবে।"],
  "26:145": ["\"I do not ask you for any wage; my wage comes only from the Lord of the universe.","আমি তোমাদের কাছে কোন পারিশ্রমিক চাই না; আমার পারিশ্রমিক কেবল মহাবিশ্বের প্রভুর কাছ থেকে আসে।"],
  "26:146": ["\"Do you suppose you will be left forever, secure in this state?","তোমরা কি ধরে নিচ্ছ যে, তোমরা চিরকাল এই অবস্থায় নিরাপদে রয়ে যাবে?"],
  "26:147": ["\"You enjoy gardens and springs.","\"তোমরা বাগান ও ঝর্ণাসমূহ উপভোগ করো।"],
  "26:148": ["\"And crops and date palms with delicious fruits.","\"আর শস্যাদি ও সুস্বাদু ফল সহ খেঁজুর গাছ।"],
  "26:149": ["\"You carve out of the mountains luxurious mansions.","\"তোমরা পর্বতসমুহে বিলাসবহুল অট্রালিকা খোদাই করো।"],
  "26:150": ["\"You shall reverence Allah, and obey me.","\"তোমরা আল্লাহকে ভক্তি করবে, এবং আমাকে মান্য করবে।"],
  "26:151": ["\"Do not obey the transgressors.","\"সীমালঙ্ঘনকারীদের মান্য করো না।"],
  "26:152": ["\"Who commit evil, not good works.\"","\"যারা ভালো কাজ নয়, মন্দ করে।"],
  "26:153": ["They said, \"You are bewitched.","তারা বলল, \"তুমি যাদুগ্রস্থ।"],
  "26:154": ["\"You are no more than a human like us. Produce a miracle, if you are truthful.\"","\"তুমি আমাদের মতো মানুষের চেয়ে বেশি কিছু নও। একটি অলৌকিকতা দেখাও, যদি তুমি সত্যবাদী হও।\""],
  "26:155": ["He said, \"Here is a camel that will drink only on a day that is assigned to her; a day that is different from your specified days of drinking.","সে বলল, \"এই যে একটি উট যেটা এর জন্য নির্ধারিত দিনটিতেই শুধু পান করবে; সে দিনটি যা পান করার জন্য তোমাদের নির্দিষ্ট দিনগুলো থেকে আলাদা।"],
  "26:156": ["\"Do not touch her with any harm, lest you incur retribution on an awesome day.\"","\"কোন ক্ষতির উদ্দেশ্যে তাকে স্পর্শ করো না, পাছে তোমরা এক ভয়ানক দিনে শাস্তি টেনে আনো।\""],
  "26:157": ["They slaughtered her, and thus incurred sorrow.","তারা তাকে জবাই করলো, এবং এভাবে দুঃখ টেনে আনলো।"],
  "26:158": ["The retribution overwhelmed them. This should be a lesson, but most people are not believers.","শাস্তি তাদেরকে ছেয়ে ফেলল। এটি একটি শিক্ষা হওয়া উচিত, কিন্তু অধিকাংশ লোক বিশ্বাসী নয়।"],
  "26:159": ["Most assuredly, your Lord is the Almighty, Most Merciful.","অত্যন্ত নিশ্চিতভাবে, তোমার প্রভু সর্বশক্তিমান, সবচেয়ে দয়ালু।"],
  "26:160": ["The people of Lot disbelieved the messengers.","লূতের লোকেরা বার্তাবাহকদেরকে অবিশ্বাস করেছিলো।"],
  "26:161": ["Their brother Lot said to them, \"Would you not be righteous?","তাদের ভাই লূত তাদেরকে বলল, \"তোমরা কি সৎকর্মশীল হবে না?"],
  "26:162": ["\"I am an honest messenger to you.","\"আমি তোমাদের কাছে এক বিশ্বস্ত বার্তাবাহক।"],
  "26:163": ["\"You shall reverence Allah, and obey me.","\"তোমরা আল্লাহকে ভক্তি করবে, এবং আমাকে মান্য করবে।"],
  "26:164": ["\"I do not ask you for any wage; my wage comes only from the Lord of the universe.","\"আমি তোমাদের কাছে কোন পারিশ্রমিক চাই না; আমার পারিশ্রমিক কেবল মহাবিশ্বের প্রভুর কাছ থেকে আসে।"],
  "26:165": ["\"Do you have sex with the males, of all the people?","\"সকল লোকদের থেকে, তোমরা কি পুরুষদের সাথে যৌনচর্চা করো?"],
  "26:166": ["\"You forsake the wives that your Lord has created for you! Indeed, you are transgressing people.\"","\"তোমরা স্ত্রীদের পরিত্যাগ করো যাদেরকে তোমাদের প্রভু তোমাদের জন্য সৃষ্টি করেছেন! নিশ্চয়, তোমরা সীমালঙ্ঘনকারী লোক।\""],
  "26:167": ["They said, \"Unless you refrain, O Lot, you will be banished.\"","তারা বলল, \"যদি না তুমি বিরত হও, হে লূত, তুমি নির্বাসিত হবে।\""],
  "26:168": ["He said, \"I deplore your actions.\"","সে বলল, \"আমি তোমাদের কার্যকলাপের অত্যন্ত ঘৃণা করি।\""],
  "26:169": ["\"My Lord, save me and my family from their works.\"","\"আমার প্রভু, আমাকে এবং আমার পরিবারকে তাদের কাজগুলো থেকে রক্ষা করুন।\""],
  "26:170": ["We saved him and all his family.","আমরা তাকে এবং তার পরিবারের সকলকে রক্ষা করলাম।"],
  "26:171": ["But not the old woman; she was doomed.","কিন্তু বৃদ্ধ মহিলাকে নয়; সে ছিল দন্ডাজ্ঞাপ্রাপ্ত।"],
  "26:172": ["We then destroyed the others.","এরপর আমরা অন্যদের ধ্বংস করলাম।"],
  "26:173": ["We showered them with a miserable shower; what a terrible shower for those who had been warned!","আমরা তাদের প্রতি এক যন্ত্রণাদায়ক বৃষ্টি বর্ষণ করলাম; তাদের জন্য কতই না ভয়ংকর বর্ষণ ছিল যাদেরকে সতর্ক করা হয়েছিল!"],
  "26:174": ["This should be a lesson, but most people are not believers.","এটি একটি শিক্ষা হওয়া উচিত, কিন্তু অধিকাংশ লোক বিশ্বাসী নয়।"],
  "26:175": ["Most assuredly, your Lord is the Almighty, Most Merciful.","নিশ্চিতভাবে, তোমার প্রভু সর্বশক্তিমান, পরম দয়ালু।"],
  "26:176": ["The People of the Woods disbelieved the messengers.","বনবাসিরা বার্তাবাহকদের অবিশ্বাস করেছিল।"],
  "26:177": ["Shu'aib said to them, \"Would you not be righteous?","শোয়াইব তাদের বলেছিল, ““তোমরা কি সৎকর্মশীল হবে না?”"],
  "26:178": ["\"I am an honest messenger to you.","\"আমি তোমাদের কাছে এক বিশ্বস্ত বার্তাবাহক।"],
  "26:179": ["\"You shall reverence Allah, and obey me.","\"তোমরা আল্লাহকে ভক্তি করবে, এবং আমাকে মান্য করবে।"],
  "26:180": ["\"I do not ask you for any wage; my wage comes only from the Lord of the universe.","\"আমি তোমাদের কাছে কোন পারিশ্রমিক চাই না; আমার পারিশ্রমিক কেবল মহাবিশ্বের প্রভুর কাছ থেকে আসে।"],
  "26:181": ["\"You shall give full measure when you trade; do not cheat.","\"তোমরা পূর্ণ পরিমাপে দিবে যখন তোমরা লেনদেন করো, প্রতারণা করো না।"],
  "26:182": ["\"You shall weigh with an equitable scale.","\"তোমরা সঠিক পাল্লায় ওজন করবে।"],
  "26:183": ["\"Do not cheat the people out of their rights, and do not roam the earth corruptingly.","\"লোকদেরকে তাদের অধিকারের বিষয়ে প্রতারণা করো না, এবং পৃথিবীতে দূর্নীতি করে বেড়িও না।"],
  "26:184": ["\"Reverence the One who created you and the previous generations.\"","\"সেই সত্ত্বাকে ভক্তি করো যিনি তোমাদেরকে এবং পূর্ববর্তী প্রজন্মদেরকে সৃষ্টি করেছেন।\""],
  "26:185": ["They said, \"You are bewitched.","তারা বলল, \"তুমি যাদুগ্রস্থ।"],
  "26:186": ["\"You are no more than a human being like us. In fact, we think you are a liar.","\"তুমি আমাদের মতো একজন মানুষের চেয়ে বেশি কিছু না। প্রকৃতপক্ষে, আমরা মনে করি তুমি একজন মিথ্যাবাদী"],
  "26:187": ["\"Let masses from the sky fall on us, if you are truthful.\"","\"আকাশ থেকে আমাদের উপর বস্তুপিন্ড ফেল, যদি তুমি সত্যবাদী হও।\""],
  "26:188": ["He said, \"My Lord is the One who knows everything you do.\"","সে বলল, \"আমার প্রভু সে সত্ত্বা যিনি তোমরা  যা কিছু  করো সব জানেন।\""],
  "26:189": ["They disbelieved him and, consequently, they incurred the retribution of the Day of the Canopy. It was the retribution of an awesome day.","তারা তাকে অবিশ্বাস করলো এবং, পরিনামে, তারা আচ্ছাদন দিনের শাস্তি টেনে আনলো। এটি ছিল এক ভয়ানক দিনের শাস্তি।"],
  "26:190": ["This should be a lesson, but most people are not believers.","এটি একটি শিক্ষা হওয়া উচিত, কিন্তু অধিকাংশ লোক বিশ্বাসী নয়।"],
  "26:191": ["Most assuredly, your Lord is the Almighty, Most Merciful.","নিশ্চিতভাবে, তোমার প্রভু সর্বশক্তিমান, পরম দয়ালু।"],
  "26:192": ["This is a revelation from the Lord of the universe.","এটি মহাবিশ্বের প্রভুর কাছ থেকে একটি প্রত্যাদেশ।"],
  "26:193": ["The Honest Spirit (Gabriel) came down with it.","বিশ্বস্ত আত্মা (জিব্রাইল) একে নিয়ে অবতরন করেছিল।"],
  "26:194": ["To reveal it into your heart, that you may be one of the warners.","তোমার হৃদয়ে একে প্রকাশ করতে, যেন তুমি সতর্ককারীদের একজন হতে পারো।"],
  "26:195": ["In a perfect Arabic tongue.","নিখুঁত আরবি ভাষায়।"],
  "26:196": ["It has been prophesied in the books of previous generations.","এর ভবিষ্যৎবানী করা হয়েছে পূর্ববর্তী প্রজন্মের গ্রন্থগুলোতে।"],
  "26:197": ["Is it not a sufficient sign for them that it was known to the scholars among the Children of Israel?","তাদের জন্য এটি কি যথেষ্ট নিদর্শন নয় যে ইসরাইলের সন্তানদের মধ্যে পণ্ডিতগণের এটি জানা ছিল?"],
  "26:198": ["If we revealed this to people who do not know Arabic.","আমরা যদি এটা সেসব লোকদের কাছে প্রকাশ করতাম যারা আরবি জানে না।"],
  "26:199": ["And had him recite it (in Arabic), they could not possibly believe in it.","আর তাকে (আরবীতে) এটি আবৃতি করতে দিতাম,  তারা কখনোই এতে বিশ্বাস করতে পারতো না।"],
  "26:200": ["We thus render it (like a foreign language) in the hearts of the guilty.","আমরা এভাবে এটিকে অপরাধীদের হৃদয়ে (বিদেশী ভাষার মতো) করে দেই।"],
  "26:201": ["Thus, they cannot believe in it; not until they see the painful retribution.","সুতরাং,তারা এতে বিশ্বাস করতে পারে না; যতক্ষণ না তারা যন্ত্রণাদায়ক শাস্তি দেখে।"],
  "26:202": ["It will come to them suddenly, when they least expect it.","এটি তাদের কাছে হঠাৎ করেই আসবে, যখন তারা প্রায় তার আশা-ই করবে না।"],
  "26:203": ["They will then say, \"Can we have a respite?\"","তখন তারা বলবে, \"আমরা কি অবকাশ পেতে পারি?\""],
  "26:204": ["Did they not challenge our retribution?","তারা কি আমাদের শাস্তিকে চ্যালেঞ্জ করেনি?"],
  "26:205": ["As you see, we allowed them to enjoy for years.","তুমি যেমনটি দেখছ, আমরা তাদেরকে বছরের পর বছর উপভোগ করতে দিয়েছি।"],
  "26:206": ["Then the retribution came to them, just as promised.","এরপর শাস্তি তাদের কাছে চলে এসেছে,  ঠিক যেরকম প্রতিশ্রুতি দেয়া হয়েছে।"],
  "26:207": ["Their vast resources did not help them in the least.","তাদের বিপুল সম্পদ তাদেরকে সামান্যতম সাহায্যও করেনি।"],
  "26:208": ["We never annihilate any community without sending warners.","আমরা সতর্ককারী না পাঠিয়ে কখনো কোন সম্প্রদায়কে ধ্বংস করি না।"],
  "26:209": ["Therefore, this is a reminder, for we are never unjust.","অতএব, এটি একটি স্মারক, কারণ আমরা কখনো অন্যায়কারী নই।"],
  "26:210": ["The devils can never reveal this.","শয়তানেরা কখনো একে প্রকাশ করতে পারবে না।"],
  "26:211": ["They neither would, nor could.","না তারা তা করবে, না করতে পারবে।"],
  "26:212": ["For they are prevented from hearing.","কারণ তাদেরকে শুনতে বাঁধা দেয়া হয়।"],
  "26:213": ["Therefore, do not idolize beside Allah any other god, lest you incur the retribution.","অতএব, আল্লাহর পাশে অন্য কোন উপাস্যকে আল্লাহতুল্য করো না, পাছে তুমি শাস্তি টেনে আনো।"],
  "26:214": ["You shall preach to the people who are closest to you.","তুমি তোমার নিকটতম লোকদের কাছে প্রচার করবে।"],
  "26:215": ["And lower your wing for the believers who follow you.","আর বিশ্বাসীরা যারা তোমার অনুসরণ করে, তাদের প্রতি তোমর দয়ার বাহু প্রসারিত করো।"],
  "26:216": ["If they disobey you, then say, \"I disown what you do.\"","যদি তারা তোমাকে অমান্য করে, তাহলে বল, \"যা তোমরা করো তার জন্য আমি দায়ী নই।\""],
  "26:217": ["And put your trust in the Almighty, Most Merciful.","আর তোমার আস্থা রাখো সর্বশক্তিমান, পরম দয়ালুর প্রতি।"],
  "26:218": ["Who sees you when you meditate during the night.","যিনি তোমাকে দেখেন, যখন তুমি রাতে ধ্যান করো।"],
  "26:219": ["And your frequent prostrations.","এবং বারংবার তোমার সেজদা।"],
  "26:220": ["He is the Hearer, the Omniscient.","তিনি সর্বশ্রোতা, সর্বজ্ঞ।"],
  "26:221": ["Shall I inform you upon whom the devils descend?","আমি কি তোমাদের বলবো শয়তানরা কাদের কাছে অবতরণ করে।"],
  "26:222": ["They descend upon every guilty fabricator.","তারা অবতরণ করে প্রত্যেক অপরাধী উদ্ভাবনকারীদের কাছে।"],
  "26:223": ["They pretend to listen, but most of them are liars.","তারা শুনার ভান করে, কিন্তু তাদের বেশিরভাগ মিথ্যাবাদী।"],
  "26:224": ["As for the poets, they are followed only by the strayers.","কবিদের ক্ষেত্রে, পথভ্রষ্টরাই কেবল তাদের অনুসরণ করে।"],
  "26:225": ["Do you not see that their loyalty shifts according to the situation?","তুমি কি দেখো না যে, তাদের আনুগত্য পরিস্থিতি অনুসারে পরিবর্তিত হয়?"],
  "26:226": ["And that they say what they do not do?","আর যে, তারা বলে যা তারা করে না?"],
  "26:227": ["Exempted are those who believe, lead a righteous life, commemorate Allah frequently, and stand up for their rights. Surely, the transgressors will find out what their ultimate destiny is.","তাদের ছাড়া যারা বিশ্বাস করে, একটি সৎ জীবন যাপন করে, প্রতিনিয়ত আল্লাহর স্মরণ করে, এবং তাদের অধিকারের জন্য সোচ্চার হয়। নিশ্চয়ই সীমালঙ্ঘনকারীরা দেখতে পাবে যে তাদের চুড়ান্ত নিয়তি কি।"],
  "27:1": ["T. S. These (letters) constitute proofs of the Quran; a profound scripture.","ত. স. এই (অক্ষরগুলো) কুরআনে প্রমান গঠন করে; এক জ্ঞানগর্ভ ঐশীগ্রন্থ।"],
  "27:2": ["A beacon, and good news, for the believers.","একটি আলোকবর্তিকা, এবং সুসংবাদ, বিশ্বাসীদের জন্য।"],
  "27:3": ["Who observe the Contact Prayers (Salat), give the obligatory charity (Zakat), and they are, with regard to the Hereafter, absolutely certain.","যারা সংযোগ প্রার্থনা (সালাত) পালন করে, বাধ্যতামূলক দান (যাকাত)দেয়, এবং তারা পরকালের বিষয়ে সম্পূর্ণরূপে নিশ্চিত।"],
  "27:4": ["Those who do not believe in the Hereafter, we adorn their works in their eyes. Thus, they continue to blunder.","যারা পরকালে বিশ্বাস করে না, আমরা তাদের চোখে তাদের কাজকে সাজিয়ে দেই। ফলে, তারা ভুল করতে থাকে।"],
  "27:5": ["It is these who incur the worst retribution, and in the Hereafter, they will be the worst losers.","এরাই নিকৃষ্ট শাস্তি টেনে আনে, এবং পরকালে, তারা সর্বাধিক ক্ষতিগ্রস্থ হবে।"],
  "27:6": ["Surely, you are receiving the Quran from a Most Wise, Omniscient.","নিশ্চিতভাবে, তুমি কুরআন গ্রহণ করছো এক প্রজ্ঞাময়, সর্বজ্ঞের কাছ থেকে।"],
  "27:7": ["Recall that Moses said to his family, \"I see a fire; let me bring you news therefrom, or a torch to warm you.\"","স্মরণ করো যে মুসা তার পরিবারকে বলেছিল, “আমি আগুন দেখছি, আমি তোমাদের জন্য সেখান থেকে সংবাদ অথবা তোমাদেরকে উষ্ণ রাখতে মশাল নিয়ে আসছি।"],
  "27:8": ["When he came to it, he was called: \"Blessed is the One (who is speaking from) within the fire, and those around it.\" Glory be to Allah, Lord of the universe.","যখন সে এর কাছে আসলো, তাকে ডাকা হলঃ “পবিত্র সেই সত্ত্বা (যিনি কথা বলছেন) আগুনের মধ্যে থেকে, এবং তারা যারা এর চারিদিকে আছে”। মহিমা আল্লাহর, মহাবিশ্বের প্রভু।"],
  "27:9": ["\"O Moses, this is Me, Allah, the Almighty, Most Wise.","হে মুসা, এতো আমি, আল্লাহ, সর্বশক্তিমান, সবথেকে জ্ঞানী।"],
  "27:10": ["\"Throw down your staff.\" When he saw it moving like a demon, he turned around and fled. \"O Moses, do not be afraid. My messengers shall not fear.","“তোমার লাঠি নিচে ছুড়ে ফেলো।\" যখন সে এটাকে দানবের মত চলতে দেখল, সে ঘুরে দাঁড়ালো এবং পালালো। “হে মুসা ভয় করো না। আমার বার্তাবাহকেরা ভয় পায়না।"],
  "27:11": ["\"Except those who commit a transgression, then substitute righteousness after sinning; I am Forgiving, Most Merciful.","“তারা ছাড়া যারা কোন সীমালঙ্ঘন করে, এরপর পাপের পরিবর্তে সৎ-কর্ম করে; আমি ক্ষমাশীল, পরম দয়ালু।"],
  "27:12": ["\"Put your hand in your pocket; it will come out white, without a blemish. These are among nine miracles to Pharaoh and his people, for they are wicked people.\"","“তুমি তোমার হাত তোমার বাহুর মধ্যে রাখো; এটা সাদা হয়ে বেরিয়ে আসবে, কোন খুঁত ছাড়া। এইগুলো হলো ফেরাউন এবং তার লোকদের প্রতি নয়টি অলৌকিকতা, কারন তারা ছিল পাপী লোক”।"],
  "27:13": ["When our miracles were presented to them, clear and profound, they said, \"This is obviously magic.\"","যখন আমাদের অলৌকিকতাগুলো তাদের কাছে উপস্থাপন করা হোল, স্পষ্ট এবং প্রগাঢ়, তারা বলল, “এ তো স্পষ্টতই জাদু”।"],
  "27:14": ["They rejected them and were utterly convinced of their wrong ways, due to their arrogance. Note the consequences for the evildoers.","তারা সেগুলকে প্রত্যাখ্যান করলো এবং তাদের ভুল পথে একদম নিশ্চিত ছিল, তাদের ঔদ্ধত্যের কারনে। লক্ষ্য করো মন্দ কর্মীদের পরিণতি।"],
  "27:15": ["We endowed David and Solomon with knowledge, and they said, \"Praise Allah for blessing us more than many of His believing servants.\"","আমরা দাউদ এবং সুলাইমানকে জ্ঞান দান করেছিলাম, এবং তারা বলল, “প্রশংসা আল্লাহর তাঁর অনেক বিশ্বাসী বান্দাদের থেকে আমাদেরকে অধিক সৌভাগ্যশালী করার জন্য”।"],
  "27:16": ["Solomon was David's heir. He said, \"O people, we have been endowed with understanding the language of the birds, and all kinds of things have been bestowed upon us. This is indeed a real blessing.\"","সুলাইমান ছিল দাউদের উত্তরাধিকারী। সে বলল, “হে লোকেরা, আমাদেরকে পাখিদের ভাষা বোঝার ক্ষমতা দান করা হয়েছে, এবং আমাদের প্রদান করা হয়েছে সকল ধরনের জিনিস। এটা নিশ্চয় প্রকৃত আনুগ্রহ”।"],
  "27:17": ["Mobilized in the service of Solomon were his obedient soldiers of jinns and humans, as well as the birds; all at his disposal.","সুলাইমান সেবায় নিয়জিত ছিল তার বাধ্য জিন ও মানব সৈন্যরা, সেই সাথে পাখিরা, সকলেই ছিল তার আয়ত্তাধীন।"],
  "27:18": ["When they approached the valley of the ants, one ant said, \"O you ants, go into your homes, lest you get crushed by Solomon and his soldiers, without perceiving.\"","যখন তারা পিঁপড়াদের উপত্যকার কাছাকাছি আসলো, একটি পিঁপড়া বলল, “হে পিঁপড়াগণ, তোমাদের বাড়ির ভেতরে চলে যাও, পাছে তোমারা সুলাইমান ও তার সৈন্যদের অজ্ঞাতসারে পিষ্ট হয়ে যাও”।"],
  "27:19": ["He smiled and laughed at her statement, and said, \"My Lord, direct me to be appreciative of the blessings You have bestowed upon me and my parents, and to do the righteous works that please You. Admit me by Your mercy into the company of Your righteous servants.\"","সে তার (স্ত্রী লিঙ্গ) কথায় হাসল,  এবং বলল, “আমার প্রভু, আমাকে পরিচালিত করুন আপনার অনুগ্রহের প্রতি কৃতজ্ঞ হতে যা আপনি আমার এবং আমার পিতামাতার উপর অর্পণ করেছেন, এবং সেই সৎকর্ম করতে যা আপনাকে সন্তুষ্ট করে। আপনার দয়ায় আমাকে অন্তর্ভুক্ত করুন আপনার সৎ-কর্মী বান্দাদের সাহচর্যে।"],
  "27:20": ["He inspected the birds, and noted: \"Why do I not see the hoopoe? Why is he missing?","সে পাখিদের পরিদর্শন করলো, এবং বললঃ “আমি হুদহুদকে দেখছি না কেন? সে অনুপস্থিত কেন?"],
  "27:21": ["\"I will punish him severely or sacrifice him, unless he gives me a good excuse.\"","“আমি তাকে কঠোর শাস্তি দেবো বা তাকে জবেহ করবো যদিনা সে উপযুক্ত কারন দর্শায়।"],
  "27:22": ["He did not wait for long. (The hoopoe) said, \"I have news that you do not have. I brought to you from Sheba, some important information.","সে বেশিক্ষন অপেক্ষা করলো না। (হুপু পাখি) বলল, “আমার কাছে সংবাদ আছে যা আপনার কাছে নাই। আমি সাবা থেকে আপনার জন্য, কিছু গুরুত্বপূর্ণ তথ্য এনেছি।"],
  "27:23": ["\"I found a woman ruling them, who is blessed with everything, and possesses a tremendous palace.","আমি এক নারীকে দেখেছি তাদেরকে শাসন করতে, যাকে সবকিছু দিয়ে অনুগ্রহ করা হয়েছে, এবং সে এক অসাধারন প্রাসাদের অধিকারী।"],
  "27:24": ["\"I found her and her people prostrating before the sun, instead of Allah. The devil has adorned their works in their eyes, and has repulsed them from the path; consequently, they are not guided.\"","“আমি তাকে এবং তার লোকদের আল্লাহর বদলে সূর্যকে সেজদা করতে দেখেছি। শয়তান তাদের কাজকে তাদের চোখে সাজিয়ে দিয়েছে, এবং তাদেরকে পথ থেকে নিবৃত রেখেছে; ফলস্বরূপ, তারা পথপ্রাপ্ত নয়”।"],
  "27:25": ["They should have been prostrating before Allah, the One who manifests all the mysteries in the heavens and the earth, and the One who knows everything you conceal and everything you declare.","তাদের উচিৎ ছিল আল্লাহকে সেজদা করা, সেই সত্ত্বা যিনি আকাশমণ্ডলী ও পৃথিবীর সকল রহস্য প্রকাশ করেন, এবং সেই সত্ত্বা  যিনি জানেন যা কিছু তোমরা গোপন করো এবং যা কিছু তোমরা প্রকাশ করো।"],
  "27:26": ["Allah: there is no other god beside Him; the Lord with the great dominion.","ঈশ্বরঃ তাঁর পাশে অন্য কোন উপাস্য নাই, মহান রাজত্বের প্রভু।"],
  "27:27": ["(Solomon) said, \"We will see if you told the truth, or if you are a liar.","(সুলেমান) বলল, “আমরা দেখব তুমি কি সত্য বলেছো নাকি তুমি এক মিথ্যাবাদী।"],
  "27:28": ["\"Take this letter from me, give it to them, then watch for their response.\"","“আমার কাছ থেকে এই চিঠি নাও, এটা তাদেরকে দাও, এরপর তাদের জবাবের প্রতি লক্ষ্য রাখো।"],
  "27:29": ["She said, \"O my advisers, I have received an honorable letter.","সে বলল, “হে আমার উপদেষ্টা মণ্ডলী, আমি এক সন্মানিত চিঠি পেয়েছি।"],
  "27:30": ["\"It is from Solomon, and it is, 'In the name of Allah, Most Gracious, Most Merciful.'","“এটা সুলাইমানের কাছ থেকে, এবং এটা হলো, “পরম করুণাময়, পরম দয়ালু আল্লাহর নামে।\""],
  "27:31": ["\"Proclaiming: 'Do not be arrogant; come to me as submitters.' \"","“এই ঘোষণা দিয়ে “উদ্ধত হয়ো না; আমার কাছে আসো আত্মসমর্পণকারী হিসাবে”।"],
  "27:32": ["She said, \"O my advisers, counsel me in this matter. I am not deciding anything until you advise me.\"","সে বলল, “হে আমার উপদেষ্টা মণ্ডলী, আমাকে এই বিষয়ে পরামর্শ দাও। আমি কোন সিদ্ধান্ত নিচ্ছি না যতক্ষণ না তোমরা আমাকে উপদেশ দাও”।"],
  "27:33": ["They said, \"We possess the power, we possess the fighting skills, and the ultimate command is in your hand. You decide what to do.\"","তারা বলল, “আমাদের শক্তি আছে, আমাদের যুদ্ধের দক্ষতা আছে, আর চূড়ান্ত হুকুম আপনার হাতে। আপনি সিদ্ধান্ত নিন কি করতে হবে।"],
  "27:34": ["She said, \"The kings corrupt any land they invade, and subjugate its dignified people. This is what they usually do.","সে বলল, “রাজারা কোন ভূখণ্ডকে আক্রমণ করলে তা বিপর্যস্ত করে দেয়, এবং এর মর্যাদাসম্পন্ন লোকদের অধীনস্থ করে নেয়। এটাই তারা সাধারণত করে থাকে।"],
  "27:35": ["\"I am sending a gift to them; let us see what the messengers come back with.\"","“আমি তাদের কাছে একটি উপহার পাঠাচ্ছি; দেখি বার্তাবাহকরা কি নিয়ে ফিরে আসে”।"],
  "27:36": ["When the hoopoe returned to Solomon (he told him the news), and he responded (to Sheba's people): \"Are you giving me money? What Allah has given me is far better than what He has given you. You are the ones to rejoice in such gifts.\"","যখন হুপু পাখি সুলেমানের কাছে ফিরে এলো (সে তাকে সংবাদটি দিলো), এবং সে জবাবে বলল (সাবার লোকদের): “তোমরা কি আমাকে অর্থ দিচ্ছ? আল্লাহ আমাকে যা দিয়েছেন তা তোমাদেরকে যা  দিয়েছেন তা থেকে অনেক উত্তম। তোমরা সে লোক যারা এমন উপহারে আনন্দ করে”।"],
  "27:37": ["(To the hoopoe, he said,) \"Go back to them (and let them know that) we will come to them with forces they cannot imagine. We will evict them, humiliated and debased.\"","(হুপু পাখিকে, সে বলল) “তাদের কাছে ফিরে যাও (এবং তাদের জানাও যে) আমরা তাদের কাছে আসবো এমন সেনাবাহিনী নিয়ে যা তারা কল্পনা করতে পারে না। আমরা তাদেরকে উচ্ছেদ করবো, অপমানিত এবং অপদস্থ করে।"],
  "27:38": ["He said, \"O you elders, which of you can bring me her mansion, before they arrive here as submitters?\"","সে বলল, “হে সভাসদবর্গ/পরিষদবর্গ/প্রধানগণ, তোমাদের মধ্যে কে আমাকে তার প্রাসাদ এনে দিতে পারে, তারা এখানে  আত্মসমর্পণকারী হিসাবে পৌঁছনোর আগে।"],
  "27:39": ["One afrit from the jinns said, \"I can bring it to you before you stand up. I am powerful enough to do this.\"","জিনদের মধ্যে একজন শক্তিশালী জিন বলল, “আপনি উঠে দাঁড়ানোর আগে আমি তা আপনার কাছে নিয়ে আসতে পারি। আমি যথেষ্ট শক্তিশালী তা করার জন্য”।"],
  "27:40": ["The one who possessed knowledge from the book said, \"I can bring it to you in the blink of your eye.\" When he saw it settled in front of him, he said, \"This is a blessing from my Lord, whereby He tests me, to show whether I am appreciative or unappreciative. Whoever is appreciative is appreciative for his own good, and if one turns unappreciative, then my Lord is in no need for him, Most Honorable.\"","যে গ্রন্থ থেকে জ্ঞান অর্জন করেছিল সে বলল, “আপনি চোখের পলক ফেলার আগেই আপনার কাছে আমি তা নিয়ে আসতে পারি”।  সে যখন  তার সামনে তা রক্ষিত দেখল, সে বলল, “এটা আমার প্রভুর পক্ষ থেকে একটি অনুগ্রহ, যার দ্বারা তিনি আমাকে পরীক্ষা করেন,  এটা দেখাতে আমি কৃতজ্ঞ নাকি অকৃতজ্ঞ। যে কৃতজ্ঞ সে তার নিজের ভালোর জন্যই কৃতজ্ঞ, এবং যদি কেউ অকৃতজ্ঞ হয়, তবে আমার প্রভুর তাকে কোন প্রয়োজন নেই, পরম সন্মানিত।"],
  "27:41": ["He said, \"Remodel her mansion for her. Let us see if she will be guided, or continue with the misguided.\"","সে বলল, “তার প্রাসাদ তার জন্য পুনরায় সাজাও। দেখা যাক সে পথপ্রাপ্ত হবে, নাকি পথভ্রষ্টদের সাথে চলবে”।"],
  "27:42": ["When she arrived, she was asked, \"Does your mansion look like this?\" She said, \"It seems that this is it.\" (Solomon said,) \"We knew beforehand what she was going to do, and we were already submitters.\"","যখন সে পৌঁছাল, তাকে জিজ্ঞাসা করা হল, “তোমার প্রাসাদ কি দেখতে এমন?”সে বলল, “মনে হচ্ছে এটা যেন সেটাই”। “আমরা আগেই জানতাম সে কি করতে যাচ্ছে, এবং ইতিমধ্যে আমারা আত্মসমর্পণকারী ছিলাম”।"],
  "27:43": ["She had been diverted by worshiping idols instead of Allah; she belonged to disbelieving people.","সে আল্লাহর বদলে অন্য উপাস্যদের উপাসনা তাকে পথ থেকে সরিয়ে নিয়েছিল; সে অবিশ্বাসী লোকদের অন্তর্ভুক্ত ছিল।"],
  "27:44": ["She was told, \"Go inside the palace.\" When she saw its interior, she thought it was a pool of water, and she (pulled up her dress,) exposing her legs. He said, \"This interior is now paved with crystal.\" She said, \"My Lord, I have wronged my soul. I now submit with Solomon to Allah, Lord of the universe.\"","তাকে বলা হল, “প্রাসাদের ভেতরে যাও”। যখন সে এটার অভ্যন্তরভাগ দেখল, সে ভাবল এটা একটি জলাশয়, এবং সে (তার পোশাক উঁচু করে ধরল) তার পাগুলো অনাবৃত করে। সে বলল, “এই অভ্যন্তরভাগ এখন স্ফটিক দিয়ে বাঁধানো”। সে বলল, “আমার প্রভু, আমি আমার আত্মার ক্ষতি করেছি। আমি এখন সুলেমানের সাথে আল্লাহর কাছে আত্মসমর্পণ করছি, যিনি মহাবিশ্বের প্রভু”।"],
  "27:45": ["We have sent to Thamûd their brother Sãleh, saying, \"You shall worship Allah.\" But they turned into two feuding factions.","আমরা সামুদ জাতির কাছে তাদের ভাই সালেহকে পাঠিয়েছি, এই বলে যে, “তোমরা আল্লাহর উপাসনা করবে”। কিন্তু তারা দুটি বিবাদকারী দলে বিভক্ত হল।"],
  "27:46": ["He said, \"O my people, why do you hasten to commit evil instead of good works? If only you implore Allah for forgiveness, you may attain mercy.\"","সে বলল, “হে আমার লোকেরা, কেন তোমরা ভালো কাজের বদলে মন্দ কাজে তাড়াহুড়ো করো? যদি কেবল তোমরা আল্লাহর কাছে ক্ষমাপ্রাপ্তির জন্য মিনতি করো, তোমরা দয়া পেতে পারো”।"],
  "27:47": ["They said, \"We consider you a bad omen for us, you and those who joined you.\" He said, \"Your omen is fully controlled by Allah. Indeed, you are deviant people.\"","তারা বলল, “আমারা তোমাকে আমাদের জন্য  অশুভ লক্ষণ মনে করি, তোমাকে এবং তোমার সাথে যারা যোগ দিয়েছে ”। সে বলল, “তোমাদের পূর্ব লক্ষণ সম্পূর্ণরূপে আল্লাহর দ্বারা নিয়ন্ত্রিত। নিশ্চয়, তোমরা পথভ্রষ্ট লোক”।"],
  "27:48": ["There were nine gangsters in the city who were wicked, and never did anything good.","সেই শহরে ছিল নয়জন দুর্বৃত্তদলের লোক যারা ছিল পাপিষ্ঠ, এবং কখন ভালো কিছু করতো না।"],
  "27:49": ["They said, \"Let us swear by Allah that we kill him and his people, then tell his tribe, 'We know nothing about their death. We are truthful.'\"","তারা বলল “চল আমরা আল্লাহর নামে শপথ করি যে আমরা তাকে এবং তার লোকদের  হত্যা করবো, এরপর তার গোষ্ঠীকে বলব, “আমরা তাদের মৃত্যুর ব্যাপারে কিছুই জানি না। আমরা সত্যবাদী”।"],
  "27:50": ["They plotted and schemed, but we also plotted and schemed, while they did not perceive.","তারা কুমন্ত্রনা এবং চক্রান্ত করলো, এবং আমরা ও চক্রান্ত  করলাম এবং কৌশল অবলম্বন করলাম, যা তারা বুঝতে পারেনি।"],
  "27:51": ["Note the consequences of their plotting; we annihilated them and all their people.","লক্ষ্য করো তাদের চক্রান্তের পরিণাম; আমরা তাদেরকে এবং তাদের সব লোকদের ধ্বংস করেছিলাম।"],
  "27:52": ["Here are their homes utterly ruined, because of their transgression. This should be a lesson for people who know.","এইযে তাদের ঘরবাড়ি একদম ধংসপ্রাপ্ত, তাদের সীমালঙ্ঘনের কারনে। এটা একটা শিক্ষা হওয়া উচিৎ সেসব লোকদের জন্য যারা জানে।"],
  "27:53": ["We save those who believe and lead a righteous life.","আমরা রক্ষা করি তাদেরকে যারা বিশ্বাস করে এবং সৎ-জীবন যাপন করে।"],
  "27:54": ["Lot said to his people, \"How could you commit such an abomination, publicly, while you see?","লুত তার লোকদের বলল, “কেমন করে তোমরা জনসমক্ষে এমন নিদারুন ঘৃণ্য কাজ করতে পারো, যখন তোমরা দেখছ?"],
  "27:55": ["\"You practice sex with the men, lustfully, instead of the women. Indeed, you are ignorant people.\"","‘তোমরা পুরুষদের সাথে যৌন চর্চা করো, কামাসক্ত হয়ে, নারীদের বদলে। নিশ্চয় তোমরা অজ্ঞ লোক”।"],
  "27:56": ["The only response from his people was their saying, \"Banish Lot's family from your town; they are people who wish to be pure.\"","তার লোকদের থেকে একমাত্র জবাব ছিল, “লুতের পরিবারকে তোমাদের শহর থেকে বের করে দাও; তারা সে লোক যারা শুদ্ধ হতে চায়”।"],
  "27:57": ["Consequently, we saved him and his family, except his wife; we counted her among the doomed.","ফলসরুপ, আমরা তাকে এবং তার পরিবারকে রক্ষা করলাম, তার স্ত্রী ছাড়া, আমরা তাকে ধ্বংসপ্রাপ্তদের মধ্যে অন্তর্ভুক্ত করলাম।"],
  "27:58": ["We showered them with a certain shower. It was a miserable shower upon people who had been warned.","আমরা এক নির্দিষ্ট বর্ষা তাদের উপর বর্ষণ করেছিলাম। এটা ছিল এক শোচনীয় বর্ষা সে লোকদের উপর যাদেরকে সতর্ক করা হয়েছিল।"],
  "27:59": ["Say, \"Praise be to Allah and peace be upon His servants whom He chose. Is Allah better, or the idols some people set up?\"","বল, “প্রশংসা আল্লাহর এবং শান্তি বর্ষিত হোক তাঁর বান্দাদের উপর যাদেরকে তিনি পছন্দ করেছেন। আল্লাহ উত্তম, নাকি সেসব উপাস্যরা যাদেরকে কিছু লোক স্থাপন করে?”"],
  "27:60": ["Who is the One who created the heavens and the earth? Who is the One who sends down to you from the sky water, whereby we produce gardens full of beauty—you could not possibly manufacture its trees? Is it another god with Allah? Indeed, they are people who have deviated.","কে সেই সত্ত্বা যিনি আকাশমণ্ডলী এবং পৃথিবী সৃষ্টি করেছেন? কে সেই সত্ত্বা যিনি আকাশ থেকে তোমাদের কাছে পানি বর্ষণ করেন, যা দিয়ে আমরা উৎপন্ন করি সৌন্দর্যে পরিপূর্ণ বাগান- তোমরা এর বৃক্ষাদি উৎপাদন করতে পারতে না? সে কি আল্লাহর সাথে অন্য কোন উপাস্য? নিশ্চয়, তারা সে লোক যারা পথভ্রষ্ট হয়েছে।"],
  "27:61": ["Who is the One who made the earth habitable, caused rivers to run through it, placed on it mountains, and created a barrier between the two waters? Is it another god with Allah? Indeed, most of them do not know.","কে সেই সত্ত্বা যিনি পৃথিবীকে বাসযোগ্য করেছেন, নদীগুলোকে এর মাঝে প্রবাহিত করেছেন, এর উপর স্থাপন করেছেন পাহাড়-পর্বত, এবং দুই পানির মাঝে এক অন্তরায় সৃষ্টি করেছেন? সে কি আল্লাহর সাথে অন্য কোন উপাস্য? নিশ্চয়, তাদের বেশির ভাগই জানে না।"],
  "27:62": ["Who is the One who rescues those who become desperate and call upon Him, relieves adversity, and makes you inheritors of the earth? Is it another god with Allah? Rarely do you take heed.","কে সেই সত্ত্বা যিনি তাদেরকে উদ্ধার করেন যারা মরিয়া হয়ে তাঁকে ডাকতে থাকে, তিনি দুর্দশা দূর করেন, এবং তোমাদেরকে পৃথিবীর উত্তরাধিকারী করেন? সে কি আল্লাহর সাথে অন্য কোন উপাস্য? তোমরা খুব কমই মনোনিবেশ করো।"],
  "27:63": ["Who is the One who guides you in the darkness of land and sea? Who is the One who sends the winds with good news, signaling His mercy? Is it another god with Allah? Most exalted is Allah, above having any partner.","কে সেই সত্ত্বা যিনি তোমাদেরকে স্থল এবং সাগরের অন্ধকারে পথ দেখান? কে সেই সত্ত্বা যিনি সুসংবাদ সহ বায়ু প্রেরন করেন, তার দয়ার পূর্বাভাস হিসাবে? এটি  কি আল্লাহর সাথে অন্য কোন খোদা? আল্লাহ পরম মহিমান্বিত, কোন অংশীদার থাকার ঊর্ধ্বে।"],
  "27:64": ["Who is the One who initiates the creation, then repeats it? Who is the One who provides for you from the heaven and the earth? Is it another god with Allah? Say, \"Show me your proof, if you are truthful.\"","কে সেই সত্ত্বা যিনি সৃষ্টির সুচনা করেন, এরপর তার পুনরাবৃত্তি ঘটান? কে সেই সত্ত্বা যিনি আকাশমণ্ডলী এবং পৃথিবী থেকে তোমাদের জীবিকা প্রদান করেন। এটি  কি আল্লাহর সাথে অন্য কোন খোদা? বল, “আমাকে তোমাদের প্রমান দেখাও, যদি তোমরা সত্যবাদী হয়ে থাকো।”"],
  "27:65": ["Say, \"No one in the heavens and the earth knows the future except Allah. They do not even perceive how or when they will be resurrected.\"","বল, “আকাশমণ্ডলী এবং পৃথিবীতে আল্লাহ ছাড়া কেউই ভবিষ্যৎ জানে না। তারা এমনকি এটাও বুঝতে পারেনা কিভাবে এবং কখন তারা পুনরুত্থিত হবে”।"],
  "27:66": ["In fact, their knowledge concerning the Hereafter is confused. In fact, they harbor doubts about it. In fact, they are totally heedless thereof.","প্রকৃত পক্ষে, পরকাল সম্পর্কে তাদের জ্ঞান বিভ্রান্ত/দিধাগ্রস্থ। প্রকৃত পক্ষে, তারা এ বিষয়ে সন্ধেহ পোষণ করে। প্রকৃত পক্ষে, এ বিষয়ে তারা সম্পূর্ণ অমনোযোগী।"],
  "27:67": ["Those who disbelieved said, \"After we turn into dust, and also our parents, do we get brought out?","যারা অবিশ্বাস করে তারা বলল, “আমরা এবং আমাদের পিতামাতারা ধুলোতে পরিণত হবার পরও কি আমাদের বের করে আনা হবে?"],
  "27:68": ["\"We have been given the same promise in the past. These are nothing but tales from the past.\"","“অতীতেও আমাদেরকে একই প্রতিশ্রুতি দেয়া হয়েছে। এগুলো অতীতের কল্পকাহিনী ছাড়া কিছুই না”।"],
  "27:69": ["Say, \"Roam the earth and note the consequences for the guilty.\"","বল, “পৃথিবীতে ঘুরে দেখো এবং অপরাধীদের পরিণাম লক্ষ্য করো”।"],
  "27:70": ["Do not grieve over them, and do not be annoyed by their scheming.","তাদের জন্য দুঃখ করো না, এবং তাদের চক্রান্তে বিরক্ত হইও না।"],
  "27:71": ["They say, \"When will that promise come to pass, if you are truthful?\"","তারা বলে, “কখন সেই প্রতিশ্রুতি পূর্ণ হবে, যদি তোমরা সত্যবাদী হও?”"],
  "27:72": ["Say, \"You are already suffering some of the retribution you challenge.\"","বল, “তোমরা ইতিমধ্যেই তোমাদের চ্যালেঞ্জ করা কিছু শাস্তি ভোগ করছো”।"],
  "27:73": ["Your Lord is full of grace towards the people, but most of them are unappreciative.","তোমার প্রভু মানুষের প্রতি অত্যন্ত অনুগ্রহশীল, কিন্তু তাদের বেশির ভাগ অকৃতজ্ঞ।"],
  "27:74": ["Your Lord fully knows what their chests hide, and what they declare.","তোমার প্রভু সম্পূর্ণ রুপে জানেন তাদের বুকে কি লুকানো আছে, আর তারা  কি প্রকাশ করে।"],
  "27:75": ["There is nothing in the heavens and the earth that is hidden (from Allah); everything is in a profound record.","আকাশ মণ্ডলী এবং পৃথিবীতে কোন কিছু নেই যা (আল্লাহ থেকে) লুকানো আছে; সবকিছুই রয়েছে এক প্রগাঢ় নথিতে।"],
  "27:76": ["This Quran settles many issues for the Children of Israel; issues that they are still disputing.","এই কুরআন ইসরাইলের সন্তানদের জন্য অনেক বিষয়াদি নিষ্পত্তি করে; বিষয়াদি যেগুলো নিয়ে তারা এখনো বিবাদ করছে।"],
  "27:77": ["And most assuredly, it is a guide and mercy for the believers.","এবং সুনিশ্চিত ভাবে, এটা বিশ্বাসীদের জন্য একটি পথপ্রদর্শক এবং দয়া।"],
  "27:78": ["Your Lord is the One who judges among them in accordance with His rules. He is the Almighty, the Omniscient.","তোমার প্রভুই সেই সত্ত্বা যিনি তাঁর আইন অনুসারে তাদের মাঝে বিচার করেন।"],
  "27:79": ["Therefore, put your trust in Allah; you are following the manifest truth.","অতএব, আল্লাহর উপর তোমার আস্থা রাখো; তুমি সুস্পষ্ট সত্য অনুসরণ করছ।"],
  "27:80": ["You cannot make the dead, nor the deaf, hear the call, if they turn away.","তুমি পারবে না মৃতকে, না বধিরকে, ডাক শোনাতে, যদি তারা মুখ ফিরিয়ে নেয়।"],
  "27:81": ["Nor can you guide the blind out of their straying. The only ones who will hear you are those who believe in our revelations, and decide to be submitters.","না তুমি অন্ধদেরকে তাদের পথভ্রষ্টতা থেকে পথ দেখাতে পারবে। শুধু তারা তোমার কথা শুনবে যারা আমাদের প্রকাশনাবলীতে বিশ্বাস করে, এবং আত্মসমর্পণকারী হবার সিদ্ধান্ত নেয়।"],
  "27:82": ["At the right time, we will produce for them a creature, made of earthly materials, declaring that the people are not certain about our revelations.","সঠিক সময়ে আমরা তাদের জন্য উপস্থাপন করবো ভূমিজাত উপাদান দিয়ে বানানো এক সৃষ্টি, যা ঘোষণা করবে যে লোকরা আমাদের প্রকাশনাবলীর বিষয়ে নিশ্চিত নয়।"],
  "27:83": ["The day will come when we summon from every community some of those who did not believe in our proofs, forcibly.","সে দিন আসবে যখন আমরা প্রত্যেক জনপদ থেকে বলপূর্বক তলব করবো তাদের কতককে যারা আমাদের প্রমানগুলো বিশ্বাস করেনি।"],
  "27:84": ["When they arrive, He will say, \"You have rejected My revelations, before acquiring knowledge about them. Is this not what you did?\"","যখন তারা উপস্থিত হবে, তিনি বলবেন, “তোমরা আমার প্রকাশনাবলী প্রত্যাখ্যান করেছ, তার বিষয়ে জ্ঞান অর্জন করার আগেই। এটাই  কি তা নয় যা তোমরা করেছিলে।"],
  "27:85": ["They will incur the requital for their wickedness; they will say nothing.","তারা নিজেদের উপর টেনে আনবে তাদের অন্যায়াচরণের প্রতিফল, তারা কিছুই বলবে না।"],
  "27:86": ["Have they not seen that we made the night for their rest, and the day lighted? These should be sufficient proofs for people who believe.","তারা কি দেখেনি যে আমরা রাতকে বানিয়েছি তাদের বিশ্রামের জন্য, এবং দিনকে করেছি আলোকিত? এগুলো যথেষ্ট প্রমান হওয়া উচিৎ সে সব লোকদের জন্য যারা বিশ্বাস করে।"],
  "27:87": ["On the day when the horn is blown, everyone in the heavens and the earth will be horrified, except those chosen by Allah. All will come before Him, forcibly.","সেই দিনে যখন শিংগায় ফু দেয়া হবে, আকাশমণ্ডলী এবং পৃথিবীর সকলে ভীত হয়ে পড়বে, আল্লাহ যাদেরকে চান তারা ব্যতিত। সকলেই তাঁর সামনে আসবে, বলপূর্বক।"],
  "27:88": ["When you look at the mountains, you think that they are standing still. But they are moving, like the clouds. Such is the manufacture of Allah, who perfected everything. He is fully Cognizant of everything you do.","তুমি যখন পর্বতগুলোকে দেখো, তুমি মনে করো যে তারা নিশ্চল দাড়িয়ে আছে। কিন্তু তারা চলছে, মেঘমালার মত। এমনই আল্লাহর নির্মাণ, যিনি সবকিছুকে নিখুঁত করেছেন। তিনি সম্পূর্ণরুপে জানেন তোমরা যাকিছু করো।"],
  "27:89": ["Those who bring good works (in their records) will receive far better rewards, and they will be perfectly secure from the horrors of that day.","যারা (তাদের নথীতে) ভালো কাজ নিয়ে আসবে তারা অনেক উত্তম পুরস্কার পাবে, এবং তারা সেই দিনের বিভীষিকা থেকে সম্পূর্ণ নিরাপদ থাকবে।"],
  "27:90": ["As for those who bring evil works, they will be forced into Hell. Do you not get requited for what you did?","তাদের ক্ষেত্রে যারা মন্দ কাজ নিয়ে আসবে, তাদেরকে বলপূর্বক নরকে পাঠানো হবে। তোমরা কি তারই প্রতিফল পাওনা যা তোমরা করেছ?"],
  "27:91": ["I am simply commanded to worship the Lord of this town—He has made it a safe sanctuary—and He possesses all things. I am commanded to be a submitter.","আমি কেবল এই শহরের প্রভুর উপাসনা করতে আদেশ প্রাপ্ত হয়েছি-তিনি একে এক নিরাপদ উপাসনা স্থল করেছেন-এবং সকল বস্তু অধিকারী। আমি  আদেশ প্রাপ্ত হয়েছি একজন আত্মসমর্পণকারী হতে।"],
  "27:92": ["And to recite the Quran. Whoever is guided is guided for his own good, and if they go astray, then say, \"I am simply a warner.\"","এবং কুরআন পাঠ করতে। যেকেউ পথপ্রাপ্ত হয় সে তার নিজের ভালোর জন্যই পথপ্রাপ্ত হয়, এবং যদি তারা বিপথগামী হয়, তবে বল, “আমি কেবল একজন সতর্ককারী”।"],
  "27:93": ["And say, \"Praise be to Allah; He will show you His proofs, until you recognize them. Your Lord is never unaware of anything you do.\"","এবং বল, “প্রশংসা আল্লাহর; তিনি তোমাদেরকে তাঁর প্রমান দেখাবেন, যতক্ষণ না তোমরা সেগুলো চিনতে পারো। তোমরা যা কিছুই করো তোমার প্রভু তা সম্পর্কে কখনই অনবহিত নন”।"],
  "28:1": ["T. S. M.","ত. শ. ম."],
  "28:2": ["These (letters) constitute proofs of this profound book.","এই (অক্ষরগুলো) এই জ্ঞানগর্ভ গ্রন্থের প্রমান গঠন করে।"],
  "28:3": ["We recite to you herein some history of Moses and Pharaoh, truthfully, for the benefit of people who believe.","আমরা এখানে তোমার কাছে মুসা এবং ফেরাউনের কিছু ইতিহাস আবৃত্তি করছি, সত্য সহকারে, সেসব লোকদের উপকারের জন্য যারা বিশ্বাস করে।"],
  "28:4": ["Pharaoh turned into a tyrant on earth, and discriminated against some people. He persecuted a helpless group of them, slaughtering their sons, while sparing their daughters. He was indeed wicked.","ফেরাউন পৃথিবীতে স্বেচ্ছাচারী শাসকে পরিণত হয়েছিল, এবং কিছু লোকের বিরুদ্ধে বৈষম্যসূচক আচরণ করেছিল। সে অত্যাচার করছিল তাদের এক অসহায় দলের উপরে, যাদের পুত্রদের সে হত্যা করতো, আর তাদের কন্যাদের জীবিত রাখতো। নিশ্চয়, সে ছিল পাপী।"],
  "28:5": ["We willed to compensate those who were oppressed on earth, and to turn them into leaders, and make them the inheritors.","যারা পৃথিবীতে নির্যাতিত ছিল আমরা চাইলাম তাদেরকে ক্ষতিপূরণ দিতে, তাদেরকে নেতা বানাতে এবং উত্তরাধিকারী করতে।"],
  "28:6": ["And to establish them on earth, and to give Pharaoh, Hãmãn, and their troops a taste of their own medicine.","এবং তাদেরকে পৃথিবীতে প্রতিষ্ঠিত করতে, এবং ফেরাউন, হামান এবং তাদের সেনাবাহিনীকে আস্বাদন করাতে তাদের নিজেদের ঔষধের স্বাদ।"],
  "28:7": ["We inspired Moses' mother: \"Nurse him, and when you fear for his life, throw him into the river without fear or grief. We will return him to you, and will make him one of the messengers.\"","আমরা মুসার মাকে অনুপ্রেরণা দিলাম “তাকে দুধ পাণ করাও, এবং যখন তুমি তার জীবন নিয়ে আশঙ্কা করো, তাকে নদীতে ভাসিয়ে দাও, কোন ভয় বা দুঃখ না করে। আমরা তাকে তোমার কাছে ফিরিয়ে দেবো, এবং তাকে বানাবো বার্তাবাহকদের একজন।\""],
  "28:8": ["Pharaoh's family picked him up, only to have him lead the opposition and to be a source of grief for them. That is because Pharaoh, Hãmãn, and their troops were transgressors.","ফেরাউনের পরিবার তাকে তুলে নিল, পরিনামে সে কেবল বিরোধী দলের নেতৃত্ব দিল এবং তাদের দুঃখের কারন হয়ে দাঁড়ালো। এটা এ কারনে যে ফেরাউন, হামান এবং তাদের সেনাবাহিনী ছিল সীমালঙ্ঘনকারী।"],
  "28:9": ["Pharaoh's wife said, \"This can be a joyous find for me and you. Do not kill him, for he may be of some benefit for us, or we may adopt him to be our son.\" They had no idea.","ফেরাউনের স্ত্রী বলল, “এটা তোমার এবং আমার জন্য এক সুখকর প্রাপ্তি হতে পারে। তাকে হত্যা করো না, কারন সে হয়তো আমাদের কিছু উপকারে আসতে পারে, অথবা আমরা তাঁকে আমাদের সন্তান হিসাবে দত্তক নিতে পারি। \" তাদের কোন ধারনাই ছিল না।"],
  "28:10": ["The mind of Moses' mother was growing so anxious that she almost gave away his identity. But we strengthened her heart, to make her a believer.","মুসার মায়ের মন এতো উদ্বিগ্ন হয়ে পড়ছিল যে সে তার পরিচয় প্রায় প্রকাশ করেই ফেলেছিল। কিন্তু আমরা তার হৃদয়কে দৃঢ় করেছিলাম, তাকে একজন বিশ্বাসী বানানোর জন্য।"],
  "28:11": ["She said to his sister, \"Trace his path.\" She watched him from afar, while they did not perceive.","সে তার বোনকে বলল, “তার পথ অনুসরণ করো।\" সে তাকে দূর থকে লক্ষ্য করছিল, তাদের অজ্ঞাতসারে।"],
  "28:12": ["We forbade him from accepting all the nursing mothers. (His sister) then said, \"I can show you a family that can raise him for you, and take good care of him.\"","আমরা তাকে সব স্তন্যদানকারী মায়েদের থেকে বিরত রেখেছিলাম।(তার বোন) তখন বলল, “আমি তোমাদের একটি পরিবারের সন্ধান দিতে পারি যারা তাকে তোমাদের জন্য লালন পালন করতে পারবে, এবং তার ভালো যত্ন নেবে।\""],
  "28:13": ["Thus, we restored him to his mother, in order to please her, remove her worries, and to let her know that Allah's promise is the truth. However, most of them do not know.","এভাবে আমরা তাকে তার মায়ের কাছে ফিরিয়ে দিলাম, তাকে খুশি করতে, তার উদ্বেগ দূর করতে, এবং তাকে জানাতে যে আল্লাহর অঙ্গীকার সত্য। কিন্তু, তাদের বেশির ভাগই জানে না।"],
  "28:14": ["When he reached maturity and strength, we endowed him with wisdom and knowledge. We thus reward the righteous.","যখন সে পরিণত বয়সে পৌঁছল এবং সবল হলো, আমরা তাকে প্রজ্ঞা ও জ্ঞান দান করলাম। আমরা এভাবে সৎ-কর্মীদের পুরস্কৃত করি।"],
  "28:15": ["Once he entered the city unexpectedly, without being recognized by the people. He found two men fighting; one was (a Hebrew) from his people, and the other was (an Egyptian) from his enemies. The one from his people called on him for help against his enemy. Moses punched him, killing him. He said, \"This is the work of the devil; he is a real enemy, and a profound misleader.\"","একবার সে অপ্রত্যাশিতভাবে শহরে প্রবেশ করলো, যেন লোকেরা তাকে চিনতে না পারে। সে দুজন লোককে লড়াই করতে দেখল; একজন ছিল (হিব্রু) তার লোকদের মধ্যে থেকে, এবং অন্যজন ছিল (একজন মিশরীয়) তার শত্রুদের থেকে। তার দলের লোকটি শত্রুর বিরুদ্ধে সাহায্য চেয়ে তাকে ডাকল। মুসা তাকে ঘুষি মারল, এতে তার মৃত্যু হল। সে বলল, “এটা শয়তানের কাজ, সে এক প্রকৃত শত্রু, এবং ঘোর পথভ্রষ্টকারী।\""],
  "28:16": ["He said, \"My Lord, I have wronged my soul. Please forgive me,\" and He forgave him. He is the Forgiver, Most Merciful.","সে বলল, “আমার প্রভু, আমি আমার আত্মার ক্ষতি করেছি। দয়া করে আমাকে ক্ষমা করুন, ” এবং তিনি তাকে ক্ষমা করে দিলেন। তিনি ক্ষমাশীল, পরম দয়ালু।"],
  "28:17": ["He said, \"My Lord, in return for Your blessings upon me, I will never be a supporter of the guilty ones.\"","সে বলল, “আমর প্রভু, আমার উপর আপনার আশীর্বাদের বিনিময়ে, আমি কখনো কোন অপরাধীর সমর্থনকারী হবো না।\""],
  "28:18": ["In the morning, he was in the city, afraid and watchful. The one who sought his help yesterday, asked for his help again. Moses said to him, \"You are really a troublemaker.\"","সকালে, সে শহরের ভেতরে ছিল, ভীত এবং সতর্ক অবস্থায়। যে ব্যক্তি গতকাল তার কছে সাহায্য চেয়েছিল, সে পুনরায় তার কাছে সাহায্য চাইল। মুসা তাকে বলল, “তুমি আসলেই এক সমস্যা সৃষ্টিকারী।\""],
  "28:19": ["Before he attempted to strike their common enemy, he said, \"O Moses, do you want to kill me, as you killed the other man yesterday? Obviously, you wish to be a tyrant on earth; you do not wish to be righteous.\"","তাদের উভয়ের শত্রুকে আঘাত করতে উদ্যত হবার আগেই, সে বলে উঠল, “হে মুসা, তুমি কি আমাকে খুন করতে চাও, যেমন গতকাল আরেকজনকে খুন করেছিলে? স্পষ্টতই, তুমি পৃথিবীতে অত্যাচারী হতে চাও; তুমি সৎ-কর্মী হতে চাও না।"],
  "28:20": ["A man came running from the other side of the city, saying, \"O Moses, the people are plotting to kill you. You better leave immediately. I am giving you good advice.\"","শহরের অন্যপ্রান্ত থেকে এক লোক দৌড়ে এসে বলল, “হে মুসা, লোকেরা তোমাকে হত্যা করার পরিকল্পনা করছে। তুমি বরং অনতিবিলম্বে বেড়িয়ে পড়ো। আমি তোমাকে সু-পরামর্শ দিচ্ছি।\""],
  "28:21": ["He fled the city, afraid and watchful. He said, \"My Lord, save me from the oppressive people.\"","সে শহর থেকে পালালো, ভীত এবং সতর্ক অবস্থায়। সে বলল, “আমার প্রভু, আমাকে নিষ্ঠুর লোকদের থেকে রক্ষা করুন।\""],
  "28:22": ["As he traveled towards Midyan, he said, \"May my Lord guide me in the right path.\"","মাদিয়ানের উদ্দেশ্যে যাত্রা করার সময়, সে বলল, “আমার প্রভু যেন আমাকে সঠিক পথে পরিচালিত করেন।\""],
  "28:23": ["When he reached Midyan's water, he found a crowd of people watering, and noticed two women waiting on the side. He said, \"What is it that you need?\" They said, \"We are not able to water, until the crowd disperses, and our father is an old man.\"","যখন সে মাদিয়ানের পানির কাছে পৌঁছল, সে দেখল লোকেরা ভিড় করে (পশুদের) পানি পান করাচ্ছে, এবং লক্ষ্য করলো দুজন নারী পাশে অপেক্ষা করছে। সে বলল, “তোমাদের কি প্রয়োজন?” তারা বলল, \"আমরা আমাদের পশুদের পানি পান করাতে পারছি না, যতক্ষণ না ভিড় সরে যায়, এবং আমাদের পিতা একজন বৃদ্ধ লোক।\""],
  "28:24": ["He watered for them, then turned to the shade, saying, \"My Lord, whatever provision You send to me, I am in dire need for it.\"","সে তাদের পশুগুলোকে পানি পান করাল, এরপর ছায়ায় যেয়ে বলল, “আমার প্রভু, যা কিছুই আপনি আমার জন্য পাঠান, আমার তা ভীষণ প্রয়োজন।\""],
  "28:25": ["Soon, one of the two women approached him, shyly, and said, \"My father invites you to pay you for watering for us.\" When he met him, and told him his story, he said, \"Have no fear. You have been saved from the oppressive people.\"","অবিলম্বে, দুই নারীর একজন তার কাছে আসলো, লাজুকভাবে, এবং বলল, “আমার পিতা আপনাকে আমন্ত্রন করেছেন আপনাকে পারিশ্রমিক দিতে আমদের পশুগুলোকে পানি পান করানোর জন্য।\" যখন সে তার সাথে সাক্ষাৎ করলো, এবং তাকে তার কাহিনী শোনালো, সে বলল, “ভয় করো না। তুমি অত্যাচারী লোকদের থেকে রক্ষা পেয়েছো।\""],
  "28:26": ["One of the two women said, \"O my father, hire him. He is the best one to hire, for he is strong and honest.\"","দুজন নারীর একজন বলল, “হে আমার পিতা, তাকে কাজে নিযুক্ত করুন। কাজে নিযুক্ত করার জন্য সে সবচেয়ে ভালো, কারন সে শক্তিশালী এবং সৎ।\""],
  "28:27": ["He said, \"I wish to offer one of my two daughters for you to marry, in return for working for me for eight pilgrimages; if you make them ten, it will be voluntary on your part. I do not wish to make this matter too difficult for you. You will find me, Allah willing, righteous.\"","সে বলল, “আমি তোমাকে আমরা দুই কন্যার একজনকে বিয়ে করার প্রস্তাব দিতে চাই, আমার জন্য আট তীর্থযাত্রা কাজ করার বদলে, যদি তুমি তা দশ কর, তা হবে তোমার দিক থেকে ঐচ্ছিক। আমি এই বিষয়টি তোমার জন্য খুব কঠিন করতে চাই না। আল্লাহ চাইলে, তুমি আমাকে পাবে, সৎকর্মশীল।\""],
  "28:28": ["He said, \"It is an agreement between me and you. Whichever period I fulfill, you will not be averse to either one. Allah is the guarantor of what we said.\"","সে বলল, “আপনার ও আমার মধ্যে এটি একটি চুক্তি। যে সময়কালই আমি পূর্ণ করি, আপনি কোনটিতেই বিরূপ হবেন না। আমরা যা বললাম আল্লাহ তার জামিনদার। \""],
  "28:29": ["When he had fulfilled his obligation, he traveled with his family (towards Egypt). He saw from the slope of Mount Sinai a fire. He said to his family, \"Stay here. I have seen a fire. Maybe I can bring to you news, or a portion of the fire to warm you.\"","যখন সে তার চুক্তি পূর্ণ করল, সে তার পরিবারকে নিয়ে যাত্রা করল (মিশরের দিকে)। সে সিনাই পর্বতের ঢাল থেকে আগুন দেখল। সে তার পরিবারকে বলল, “এখানে থাকো। আমি আগুন দেখেছি। হতে পারে আমি তোমাদের জন্য কোন খবর আনতে পারবো, অথবা আগুনের এক অংশ, (আনতে পারবো) তোমাদের উষ্ণতা দিতে।\""],
  "28:30": ["When he reached it, he was called from the edge of the right side of the valley, in the blessed spot where the burning bush was located: \"O Moses, this is Me. Allah; Lord of the universe.","যখন সে তার কাছ পৌঁছাল, তাকে উপত্যকার ডান প্রান্ত থেকে ডাকা হল, পবিত্র স্থানে যেখানে জলন্ত ঝোপ অবস্থিত ছিলঃ “হে মুসা, এ হল আমি, আল্লাহ; মহা বিশ্বের প্রভু।"],
  "28:31": ["Throw down your staff. When he saw it moving like a demon, he turned around and fled. \"O Moses, come back; do not be afraid. You are perfectly safe.","“তোমার লাঠি ছুড়ে ফেল।\" যখন সে এটাকে দানবের মত চলতে দেখল, সে পেছনে ফিরে পালালো। “হে মুসা, ফিরে এসো; ভয় করো না। তুমি সম্পূর্ণ নিরাপদ।"],
  "28:32": ["Put your hand into your pocket; it will come out white without a blemish. Fold your wings and settle down from your fear. These are two proofs from your Lord, to be shown to Pharaoh and his elders; they have been wicked people.","“তোমার হাত তোমার পকেটে রাখো; এটি সাদা হয়ে বের হয়ে আসবে কোন ত্রুটি ছাড়াই। তোমার বাহুদ্বয় ভাঁজ করো এবং ভয় মুক্ত হও। এই হলো দুটি প্রমান তোমার প্রভুর পক্ষ থেকে, ফেরাউন এবং তার সভাসদদের দেখানোর জন্য; তারা হচ্ছে পাপী লোক।\""],
  "28:33": ["He said, \"My Lord, I killed one of them, and I fear lest they kill me.","সে বলল, “আমার প্রভু, আমি তাদের একজনকে হত্যা করেছি, এবং আমার ভয় হয় যে তারা আমাকে হত্যা করবে।"],
  "28:34": ["Also, my brother Aaron is more eloquent than I. Send him with me as a helper to confirm and strengthen me. I fear lest they disbelieve me.","“আর, আমার ভাই হারুন আমার চেয়ে অধিক বাকপটু। তাকে আমার সাথে পাঠান একজন সাহায্যকারী হিসাবে আমাকে সমর্থন করতে এবং আমার শক্তি জোগাতে। আমি ভয় করি পাছে তারা আমাকে অবিশ্বাস করে।\""],
  "28:35": ["He said, \"We will strengthen you with your brother, and we will provide you both with manifest authority. Thus, they will not be able to touch either one of you. With our miracles, the two of you, together with those who follow you, will be the victors.\"","তিনি বললেন, “আমরা তোমাকে তোমার ভাইয়ের দ্বারা শক্তিশালী করবো, এবং আমরা তোমাদের উভয়কে সুস্পষ্ট কর্তৃত্ব প্রদান করবো। ফলে, তারা তোমাদের দুজনের একজনকেও স্পর্শ করতে পারবে না। আমাদের নিদর্শনাবলীর নিয়ে, তোমরা দুজন, তোমাদেরকে যারা অনুসরণ করে তারা সহ, জয়ী হবে।\""],
  "28:36": ["When Moses went to them with our proofs, clear and profound, they said, \"This is fabricated magic. We have never heard of this from our ancient ancestors.\"","যখন মুসা তাদের কাছে গেল আমাদের স্পষ্ট এবং প্রগাঢ় প্রমান সহ, তারা বলল, “এটা তো অলীক জাদু। আমরা কখনো আমাদের প্রাচীন পূর্বপুরুষদের থেকে এরুপ শুনিনি।\""],
  "28:37": ["Moses said, \"My Lord knows best who brought the guidance from Him, and who will be the ultimate victors. Surely, the transgressors never succeed.\"","মুসা বলল, “আমার প্রভু সবচেয়ে ভাল জানেন কে তাঁর থেকে পথনির্দেশনা নিয়ে এসেছে, এবং কে হবে চূড়ান্ত বিজয়ী। নিশ্চিতভাবে, সীমালঙ্ঘনকারীরা কখনই সফল হয় না।\""],
  "28:38": ["Pharaoh said, \"O you elders, I have not known of any god for you other than me. Therefore, fire the adobe, O Hãmãn, in order to build a tower, that I may take a look at the god of Moses. I am sure that he is a liar.\"","ফেরাউন বলল, “হে আমার সভাসদগণ, তোমাদের জন্য আমি ছাড়া অন্য কোন উপাস্যকে আমার জানা নেই। অতএব, ইট পোড়াও, হে হামান, একটা মিনার তৈরি করার জন্য, যাতে আমি মুসার উপাস্যকে এক নজর দেখতে পারি। আমি নিশ্চিত যে সে এক মিথ্যাবাদী।\""],
  "28:39": ["Thus, he and his troops continued to commit arrogance on earth, without any right, and thought that they would not be returned to us.","এভাবে, সে এবং তার সৈন্যবাহিনী পৃথিবীতে ঔদ্ধত্য করতে থাকলো, কোন অধিকার ছাড়াই, এবং ভাবল যে তারা আমাদের কাছে ফিরে আসবে না।"],
  "28:40": ["Consequently, we punished him and his troops, by throwing them into the sea. Note the consequences for the transgressors.","ফলস্বরূপ, আমি তাকে এবং তার সৈন্যবাহিনীকে শাস্তি দিয়েছিলাম, তাদেরকে সমুদ্রে নিক্ষেপ করে। সীমালঙ্ঘনকারীদের পরিণাম লক্ষ্য করো।"],
  "28:41": ["We made them imams who led their people to Hell. Furthermore, on the Day of Resurrection, they will have no help.","আমরা তাদেরকে ইমাম করেছিলাম যারা তাদের লোকদের নরকের দিকে পরিচালিত করেছিল। উপরন্তু, পুনরুত্থানের দিনে, তাদের কোন সাহায্যকারী থাকবে না।"],
  "28:42": ["They incurred in this life condemnation, and on the Day of Resurrection they will be despised.","তারা এই জীবনে টেনে এনেছে দণ্ডাদেশ, এবং পুনরুত্থানের দিনে তারা হবে ঘৃণিত।"],
  "28:43": ["We gave Moses the scripture—after having annihilated the previous generations, and after setting the examples through them—to provide enlightenment for the people, and guidance, and mercy, that they may take heed.","আমরা মুসাকে দিয়েছিলাম ঐশীগ্রন্থ – পূর্ববর্তী প্রজন্মদের ধ্বংস করে দেবার পর, এবং তাদের মাধ্যমে উদাহরন স্থাপন করার পর – লোকদের জন্য প্রদান করতে, জ্ঞানবর্তিকা আর পথনির্দেশনা, এবং দয়া, যাতে তারা মনোযোগ দিতে পারে।"],
  "28:44": ["You were not present on the slope of the western mount, when we issued the command to Moses; you were not a witness.","তুমি উপস্থিত ছিলে না পশ্চিমা পর্বতের ঢালে, যখন আমরা মুসার কাছে হুকুম জারী করেছিলাম; তুমি প্রত্যক্ষদর্শী ছিলে না।"],
  "28:45": ["But we established many generations, and, because of the length of time, (they deviated). Nor were you among the people of Midyan, reciting our revelations to them. But we did send messengers.","কিন্তু আমরা প্রতিষ্ঠিত করেছিলাম অনেক প্রজন্মকে, এবং, সময়ের ব্যাপ্তির কারনে, (তারা পথভ্রষ্ট হয়েছিল)। না তুমি ছিলে মাদিয়ানের লোকদের মধ্যে, তাদের কাছে আমাদের প্রকাশনাবলী আবৃত্তি করতে। কিন্তু আমরা ঠিকই বার্তাবাহক পাঠিয়েছিলাম।"],
  "28:46": ["Nor were you on the slope of Mount Sinai when we called (Moses). But it is mercy from your Lord, (towards the people,) in order to warn people who received no warner before you, that they may take heed.","না তুমি ছিলে সিনাই পর্বতের ঢালে যখন আমারা (মুসাকে) ডেকেছিলাম। কিন্তু এটা তোমার প্রভুর পক্ষ থেকে করুনা, (লোকদের প্রতি), সেসব লোকদের সতর্ক করতে যারা তোমার আগে কোন সতর্ককারী পায়নি, যাতে তারা মনোযোগ দিতে পারে।"],
  "28:47": ["Thus, they cannot say, when a disaster strikes them as a consequence of their own deeds, \"Our Lord, had You sent a messenger to us, we would have followed Your revelations, and would have been believers.\"","যাতে, তারা বলতে না পারে, যখন কোন বিপর্যয় তাদের নিজেদের কাজের পরিণাম স্বরূপ তাদের আঘাত করে, “আমাদের প্রভু, আপনি যদি আমাদের কাছে কোন বার্তাবাহক পাঠাতেন, আমরা আপনার প্রকাশনাবলী অনুসরণ করতাম, এবং বিশ্বাসী হতাম।\""],
  "28:48": ["Now that the truth has come to them from us, they said, \"If only we could be given what was given to Moses!\" Did they not disbelieve in what was given to Moses in the past? They said, \"Both (scriptures) are works of magic that copied one another.\" They also said, \"We are disbelievers in both of them.\"","এখন যখন আমাদের পক্ষ থেকে সত্য তাদের কাছে এসেছে, তারা বলল, “শুধু যদি আমাদেরকে তা দেয়া হতো যা মুসাকে দেয়া হয়েছিল!” তারা কি অতীতে অবিশ্বাস করেনি যা মুসাকে দেয়া হয়েছিল তাতে? তারা বলল, “উভয় (ঐশীগ্রন্থই) জাদু, যার একটিকে অন্যটি নকল করেছে। তারা আরও বলল, “আমরা দুটিতেই অবিশ্বাসী।\""],
  "28:49": ["Say, \"Then produce a scripture from Allah with better guidance than the two, so I can follow it, if you are truthful.\"","বল, “তাহলে আল্লাহর কাছ থেকে এই দুটির থেকে উত্তম পথনির্দেশনা সহ একটি ঐশীগ্রন্থ নিয়ে আসো, যাতে আমি তা অনুসরণ করতে পারি, যদি তোমরা  সত্যবাদী হয়ে থাকো।\""],
  "28:50": ["If they fail to respond to you, then know that they follow only their own opinions. Who is farther astray than those who follow their own opinions, without guidance from Allah? Allah does not guide such wicked people.","যদি তারা তোমার ডাকে সাড়া দিতে ব্যর্থ হয়, তবে জেনে নাও যে তারা কেবল তাদের নিজেদের মতামতের অনুসরণ করে। তাদের থেকে কে অধিক পথভ্রষ্ট যারা তাদের নিজেদের মতামতের অনুসরণ করে, আল্লাহর থেকে পথনির্দেশনা ছাড়াই? আল্লাহ এমন অন্যায়কারী লোকদের পথপ্রদর্শন করেন না।"],
  "28:51": ["We have delivered the message to them, that they may take heed.","আমরা তাদের কাছে বার্তা পৌঁছিয়েছি, যাতে তারা মনোযোগ দেয়।"],
  "28:52": ["Those whom we blessed with the previous scriptures will believe in this.","যাদেরকে আমরা পূর্ববর্তী ঐশীগ্রন্থ দিয়ে আশীর্বাদ করেছি তারা এতে বিশ্বাস করবে।"],
  "28:53": ["When it is recited to them, they will say, \"We believe in it. This is the truth from our Lord. Even before we heard of it, we were submitters.\"","যখন এটি তাদের কাছে আবৃত্তি করা হয়, তারা বলে, “আমরা এটাতে বিশ্বাস করি, এটি আমাদের প্রভুর পক্ষ থেকে সত্য। এমনকি এটি শোনার আগেও, আমরা আত্মসমর্পণকারী ছিলাম।\""],
  "28:54": ["To these we grant twice the reward, because they steadfastly persevere. They counter evil works with good works, and from our provisions to them, they give.","এদেরকে আমরা দিগুন পুরস্কার প্রদান করি, কারন তারা দৃঢ়তার সাথে অধ্যবসায়ী। তারা মন্দ কাজকে প্রতিহত করে ভালো কাজ দিয়ে, এবং তাদের কাছে আমাদের জীবিকা থেকে, তারা দেয়।"],
  "28:55": ["When they come across vain talk, they disregard it and say, \"We are responsible for our deeds, and you are responsible for your deeds. Peace be upon you. We do not wish to behave like the ignorant ones.\"","যখন তারা অসার কথাবার্তার সম্মুখীন হয়, তারা তা উপেক্ষা করে এবং বলে, “আমরা দায়ী আমাদের কাজের জন্য, এবং তোমরা দায়ী তোমাদের কাজের জন্য। তোমাদের উপর শান্তি বর্ষিত হোক। আমরা অজ্ঞদের মতো আচরণ করতে চাই না।\""],
  "28:56": ["You cannot guide the ones you love. Allah is the only One who guides in accordance with His will, and in accordance with His knowledge of those who deserve the guidance.","তুমি যাকে ভালোবাসো তাকে পথ প্রদর্শন করতে পারো না। আল্লাহ-ই একমাত্র সত্ত্বা যিনি পথপ্রদর্শন করেন তাঁর ইচ্ছানুসারে, এবং যারা পথ পাবার যোগ্য তাদের বিষয়ে তাঁর জ্ঞান অনুসারে।"],
  "28:57": ["They said, \"If we follow your guidance, we will suffer persecution.\" Did we not establish for them a Sacred Sanctuary, to which all kinds of fruits are offered, as a provision from us? Indeed, most of them do not know.","তারা বলল, “যদি আমরা তোমার পথনির্দেশনা অনুসরণ করি, আমরা নির্যাতন ভোগ করবো।\" আমরা কি তাদের জন্য একটি পবিত্র আশ্রয় স্থল স্থাপন করিনি, যাতে সকল প্রকার ফল সহজলভ্য করা হয়েছে, আমাদের পক্ষ থেকে জীবিকা হিসাবে? নিশ্চয়, তাদের অধিকাংশ জানে না।"],
  "28:58": ["Many a community we annihilated for turning unappreciative of their lives. Consequently, here are their homes, nothing but uninhabited ruins after them, except a few. We were the inheritors.","অনেক সম্প্রদায়কে আমরা ধ্বংস করেছি জীবনের প্রতি তারা অকৃতজ্ঞ হয়ে পড়ার কারনে। ফলস্বরূপ, এই হচ্ছে তাদের ঘরবাড়ি, যেগুলো তাদের পর বসতিহীন ধ্বংসাবশেষ ছাড়া কিছুই নয়, অল্প কিছু ব্যতিক্রম। আমরাই উত্তরাধিকারী ছিলাম।"],
  "28:59": ["For your Lord never annihilates any community without sending a messenger in the midst thereof, to recite our revelations to them. We never annihilate any community, unless its people are wicked.","কারন তোমার প্রভু কখনই কোন জনপদকে ধ্বংস করেন না তাদের কাছে আমাদের প্রকাশনাবলী আবৃত্তি করতে তাদের মধ্যে বার্তাবাহক না পাঠিয়ে। আমরা কখনই কোন জনপদকে ধ্বংস করি না, যদিনা এর লোকরা অন্যায়কারী হয়।"],
  "28:60": ["Everything that is given to you is only the material of this life, and its vanity. What is with Allah is far better, and everlasting. Do you not understand?","যা কিছু তোমাদের দেওয়া হয়েছে তা শুধু এই জীবনের বস্তুসমগ্রি, এবং এর অসার আড়ম্বর। যা আল্লাহর কাছে আছে তা অনেক উত্তম, এবং চিরস্থায়ী। তোমারা কি বুঝো না।"],
  "28:61": ["Is one whom we promised a good promise that will surely come to pass, equal to one whom we provide with the temporary materials of this life, then suffers eternal doom on the Day of Resurrection?","যাকে আমরা অঙ্গিকার করেছি এক উত্তম প্রতিশ্রুতির যা অবশ্যই ঘটবে, সে  কি তার মতো যাকে আমরা এই জীবনের ক্ষণস্থায়ী বস্তুসমগ্রি প্রদান করেছি, এরপর পুনরুত্থান দিনে সে ভোগ করবে চিরস্থায়ী নরকভোগ।"],
  "28:62": ["The day will come when He calls upon them, saying, \"Where are those idols you had set up beside Me?\"","সে দিন আসবে যখন তিনি তাদের ডেকে বলবেন, “কোথাই সেই উপাস্যরা যাদেরকে তোমরা আমার পাশে স্থাপন করেছিলে?”"],
  "28:63": ["Those who incurred the judgment will say, \"Our Lord, these are the ones we misled; we misled them only because we ourselves had gone astray. We now devote ourselves totally to You. They were not really worshiping us.\"","যারা দণ্ডাদেশ প্রাপ্ত হয়েছে তারা বলবে, “আমাদের প্রভু, এরাই সেসব বাক্তি যাদের আমরা পথভ্রষ্ট করেছিলাম; আমরা তাদের পথভ্রষ্ট করেছিলাম শুধু এই কারনে যে আমরা নিজেরাই পথভ্রষ্ট ছিলাম। আমরা এখন নিজেদেরকে সম্পূর্ণ রুপে আপনার কাছে উৎসর্গ করছি। তারা আসলে আমাদের উপাসনা করত না।\""],
  "28:64": ["It will be said, \"Call upon your idols (to help you).\" They will call upon them, but they will not respond. They will suffer the retribution, and wish that they were guided!","তাদেরকে বলা হবে, “তোমাদের উপাস্যদের ডাকো (তোমাদেরকে সাহায্য করতে)।\" তারা তাদেরকে ডাকবে, কিন্তু তারা ডাকে সাড়া দেবে না। তারা শাস্তি ভোগ করবে, এবং আফসোস করবে “হায় যদি আমরা পথপ্রাপ্ত হতাম!”"],
  "28:65": ["On that day, He will ask everyone, \"How did you respond to the messengers?\"","সেই দিন, তিনি সকলকে জিজ্ঞাসা করবেন, “বার্তাবাহকদের ডাকে তোমাদের সাড়া কেমন ছিল?”"],
  "28:66": ["They will be so stunned by the facts on that day, they will be speechless.","সে দিন এসব ঘটনায় তারা এতোই স্তব্ধ হবে যে তারা নির্বাক হয়ে পড়বে।"],
  "28:67": ["As for those who repent, believe, and lead a righteous life, they will end up with the winners.","তাদের ক্ষেত্রে যারা অনুশোচনা করে, বিশ্বাস করে, এবং সৎ জীবন যাপন করে, তারা শেষ পর্যন্ত বিজয়ীদের অন্তর্ভুক্ত হবে।"],
  "28:68": ["Your Lord is the One who creates whatever He wills, and chooses; no one else does any choosing. Glory be to Allah, the Most Exalted. He is far above needing partners.","তোমার প্রভুই সেই সত্ত্বা যিনি সৃষ্টি করেন যা কিছু তার ইচ্ছা, এবং পছন্দ  করেন, আর কেউ  পছন্দ করতে অংশ নেয়না। মহিমা আল্লাহর, পরম সমুচ্চ। অংশীদারের প্রয়োজন থেকে তিনি অনেক ঊর্ধ্বে।"],
  "28:69": ["Your Lord knows the innermost thoughts hidden in their chests, as well as everything they declare.","তোমার প্রভু জানেন তাদের বুকে লুকানো গভীরতম চিন্তাগুলো, সেই সাথে যা কিছু তারা প্রকাশ করে।"],
  "28:70": ["He is the one Allah; there is no other god beside Him. To Him belongs all praise in this first life, and in the Hereafter. All judgment belongs with Him, and to Him you will be returned.","তিনি সেই এক আল্লাহ; তাঁর পাশে আর কোন উপাস্য নেই। সকল প্রশংসা তাঁর, এই প্রথম জীবনে, এবং পরকালে। তাঁর অধীনে সকল ফয়সালা  এবং তাঁর কাছেই তোমরা ফিরে যাবে।"],
  "28:71": ["Say, \"What if Allah made the night perpetual, until the Day of Resurrection? Which god, other than Allah, can provide you with light? Do you not hear?\"","বল, “কি হতো যদি আল্লাহ রাতকে চিরস্থায়ী করে দিতেন, পুনরুত্থান দিবস পর্যন্ত? আল্লাহ ছাড়া, কোন উপাস্য তোমাদের আলো দিতে পারে? তোমরা কি শোনো না?"],
  "28:72": ["Say, \"What if Allah made the daylight perpetual, until the Day of Resurrection? Which god, other than Allah, can provide you with a night for your rest? Do you not see?\"","বল, “কি হতো যদি আল্লাহ দিবালোককে চিরস্থায়ী করে দিতেন, পুনরুত্থান দিবস পর্যন্ত? আল্লাহ ছাড়া, কোন উপাস্য তোমাদের বিশ্রামের জন্য রাত দিতে পারে? তোমরা কি দেখো না?"],
  "28:73": ["It is mercy from Him that He created for you the night and the day in order to rest (during the night), then seek His provisions (during the day), that you may be appreciative.","এটা তাঁর পক্ষ থেকে করুনা যে তিনি তোমাদের জন্য সৃষ্টি করেছেন রাত এবং দিনকে, (রাতের বেলায়) বিশ্রাম নেবার জন্য এরপর (দিনের বেলায়) তাঁর দেওয়া জীবিকা অন্বেষণ করার জন্য, যাতে তোমরা কৃতজ্ঞ হতে পারো।"],
  "28:74": ["The day will come when He asks them, \"Where are the idols you had fabricated to rank with Me?\"","সে দিন আসবে যখন তিনি তাদেরকে জিজ্ঞাসা করবেন, “কোথায় সেই শরীক উপাস্যরা যাদেরকে তোমরা উদ্ভাবন করেছেন আমার সমকক্ষ করতে?”"],
  "28:75": ["We will select from every community a witness, then say, \"Present your proof.\" They will realize then that all truth belongs with Allah, while the idols they had fabricated will abandon them.","আমরা প্রত্যেক সম্প্রদায় থেকে একজন সাক্ষী বাছাই করবো, এরপর বলবো, “তোমাদের প্রমান উপস্থাপন করো”। তখন তারা উপলব্ধি করবে যে সকল সত্য আল্লাহর অধীন, আর তাদের মিথ্যা উদ্ভাবিত শরীক উপাস্যরা  তাদের পরিত্যাগ করবে।"],
  "28:76": ["Qãroon (the slave driver) was one of Moses' people who betrayed them and oppressed them. We gave him so many treasures that the keys thereof were almost too heavy for the strongest band. His people said to him, \"Do not be so arrogant; Allah does not love those who are arrogant.","কারুন (ক্রিতদাস পরিচালক) ছিল মুসার লোকদের একজন যে তাদের সাথে প্রতারণা করেছিল এবং তাদের নির্যাতন করতো। আমি তাকে এতো ধনসম্পদ দিয়েছিলাম যে সেগুলোর চাবি সবচেয়ে শক্তিশালী দলের জন্যও খুব ভারি ছিল। তার লোকেরা তাকে বলল, “এতো উদ্ধত হইও না; আল্লাহ তাদেরকে ভালোবাসেন না যারা উদ্ধত।"],
  "28:77": ["Use the provisions bestowed upon you by Allah to seek the abode of the Hereafter, without neglecting your share in this world. Be charitable, as Allah has been charitable towards you. Do not keep on corrupting the earth. Allah does not love the corruptors.","“পরকালের বাসস্থান অন্বেষণে তোমার উপর আল্লাহর অর্পণ করা জীবিকা ব্যবহার করো, এই দুনিয়ায় তোমার অংশ উপেক্ষা না করে। দানশীল হও, যেমন আল্লাহ তোমার প্রতি দানশীল হয়েছেন। পৃথিবীতে দুর্নীতি করতে থেকোকো না। আল্লাহ দুর্নীতিপরায়ণদের ভালোবাসেন না।"],
  "28:78": ["He said, \"I attained all this because of my own cleverness.\" Did he not realize that Allah had annihilated before him generations that were much stronger than he, and greater in number? The (annihilated) transgressors were not asked about their crimes.","সে বলল, “আমি এই সবকিছু অর্জন করেছি আমার নিজের কশুলতার কারনে।” সে কি উপলব্ধি করেনি যে আল্লাহ তার পূর্বে প্রজন্মদের ধ্বংস করেছিলেন যারা তার থেকে অধিক শক্তিশালী আর সংখ্যায় অধিক ছিল? সেই (ধ্বংস প্রাপ্ত) সীমালঙ্ঘনকারীরা তাদের অপরাধ সম্পর্কে জিজ্ঞাসিত হয়নি।"],
  "28:79": ["One day, he came out to his people in full splendor. Those who preferred this worldly life said, \"Oh, we wish that we possess what Qãroon has attained. Indeed, he is very fortunate.\"","এক দিন, সে তার লোকদের কাছে পূর্ণ জাঁকজমকের সাথে বের হয়ে আসলো। যারা এই পার্থিব জীবনকে প্রাধান্য দিত তারা বলল, “আহা, আমাদের যদি তা থাকতো যা কারুন অর্জন করেছে। নিশ্চয়, সে খুব সৌভাগ্যশালী।\""],
  "28:80": ["As for those who were blessed with knowledge, they said, \"Woe to you, Allah's recompense is far better for those who believe and lead a righteous life.\" None attains this except the steadfast.","তাদের ক্ষেত্রে যারা জ্ঞান পেয়ে সৌভাগ্যশালী ছিল, তারা বলল, “দুর্ভোগ তোমাদের,  আল্লাহর প্রতিদান তাদের জন্য অনেক উত্তম যারা বিশ্বাস করে এবং সৎ জীবন যাপন করে।\" অবিচলরা ছাড়া কেউ তা অর্জন করে না।"],
  "28:81": ["We then caused the earth to swallow him and his mansion. No army could have helped him against Allah; he was not destined to be a winner.","আমরা তখন তাকে ও তার প্রাসাদকে জমিন দিয়ে গ্রাস করালাম। কোন সেনাবাহিনী আল্লাহর বিরুদ্ধে তাকে সাহায্য করতে পারতো না; বিজয়ী হওয়া তার নিয়তিতে ছিল না।"],
  "28:82": ["Those who were envious of him the day before said, \"Now we realize that Allah is the One who provides for whomever He chooses from among His servants, and withholds. If it were not for Allah's grace towards us, He could have caused the earth to swallow us too. We now realize that the disbelievers never succeed.\"","আগের দিন যারা তার প্রতি ঈর্ষান্বিত ছিল তারা বলল, “আমরা এখন উপলব্ধি করলাম যে আল্লাহই সেই সত্ত্বা যিনি তাঁর বান্দাদের মধ্যে থেকে যাকে চান তাকে জীবিকা প্রদান করেন, এবং তা রোধ করেন। যদি আমাদের প্রতি আল্লাহর অনুগ্রহ না হতো, তিনি আমাদেরকেও জমিন দিয়ে  গ্রাস করাতে পারতেন। আমরা এখন উপলব্ধি করলাম যে অবিশ্বাসীরা কখনই সফলকাম হয় না।\""],
  "28:83": ["We reserve the abode of the Hereafter for those who do not seek exaltation on earth, nor corruption. The ultimate victory belongs to the righteous.","আমরা পরকালের গৃহ তাদের জন্য সংরক্ষিত রেখেছি যারা পৃথিবীতে না আত্মপ্রশংসা খোঁজে, না দুর্নীতি করে। চূড়ান্ত বিজয় সৎ-কর্মীদের।"],
  "28:84": ["Whoever works righteousness receives a far better reward. As for those who commit sins, the retribution for their sins is precisely equivalent to their works.","যে কেউ সৎ-কর্ম করে সে আরো উত্তম পুরস্কার পায়। তাদের ক্ষেত্রে যারা পাপ করে, তাদের পাপের শাস্তি ঠিক তাদের কাজের সমতুল্য।"],
  "28:85": ["Surely, the One who decreed the Quran for you will summon you to a predetermined appointment. Say, \"My Lord is fully aware of those who uphold the guidance, and those who have gone astray.\"","নিশ্চয়, সেই সত্ত্বা যিনি তোমার জন্য কুরআন আদিষ্ট করেছেন, তিনি তোমাকে তলব করবেন এক পূর্ব নির্ধারিত সাক্ষাৎকারে। বল, “আমার প্রভু সম্পূর্ণ অবগত তাদের ব্যাপারে যারা পথনির্দেশনা ধারন করে, এবং তাদের ব্যাপারে যারা বিপথগামী।\""],
  "28:86": ["You never expected this scripture to come your way; but this is a mercy from your Lord. Therefore, you shall not side with the disbelievers.","তুমি কখনই আশা করনি এই ঐশীগ্রন্থ তোমরা চলার পথে আসবে; কিন্তু এটা তোমার প্রভুর পক্ষ থেকে এক দয়া। অতএব, তুমি অবিশ্বাসীদের পক্ষ নেবে না।"],
  "28:87": ["Nor shall you be diverted from Allah's revelations, after they have come to you, and invite the others to your Lord. And do not ever fall into idol worship.","না তুমি আল্লাহর প্রকাশনাবলী থেকে সরে যাবে, সেগুলো তোমার কাছে আসার পর, এবং অন্যদের তোমার প্রভুর দিকে অমন্ত্রন করবে। এবং কখনোই শরিক উপাসনায় পতিত হবে না।"],
  "28:88": ["You shall not worship beside Allah any other god. There is no other god beside Him. Everything perishes except His presence. To Him belongs all sovereignty, and to Him you will be returned.","তুমি আল্লাহর পাশে অন্য কোন উপাস্যের উপাসনা করবে না। তাঁর পাশে অন্য কোন উপাস্য নেই। তাঁর উপস্থিতি ব্যতিত সবকিছু ধ্বংসশীল। সকল সার্বভৌমত্ব তাঁর, এবং তাঁর কাছেই তোমরা ফিরে যাবে।"],
  "29:1": ["A. L. M.","অ. ল. ম."],
  "29:2": ["Do the people think that they will be left to say, \"We believe,\" without being put to the test?","লোকেরা কি মনে করে যে তাদেরকে এই বললেই ছেড়ে দেয়া হবে,  \"আমরা বিশ্বাস করি,” পরীক্ষা করা ছাড়াই?"],
  "29:3": ["We have tested those before them, for Allah must distinguish those who are truthful, and He must expose the liars.","তাদের পূর্ববর্তীদেরকেও আমরা পরীক্ষা করেছি, কারণ আল্লাহ অবশ্যই সত্যবাদীদের আলাদা করবেন, আর তিনি অবশ্যই মিথ্যাবাদীদেরকে প্রকাশ করে দেবেন।"],
  "29:4": ["Do those who commit sins think that they can ever fool us? Wrong indeed is their judgment.","যারা পাপ করে তারা কি মনে করে যে তারা কখনো আমাদের বোকা বানাতে পারবে? নিশ্চয়, তাদের বিচার ভুল।"],
  "29:5": ["Anyone hoping to meet Allah, (should know that) such a meeting with Allah will most assuredly come to pass. He is the Hearer, the Omniscient.","যেকেউ আল্লাহর সাক্ষাত আশা করে, (তার জানা উচিত যে) আল্লাহর সাথে এমন এক সাক্ষাৎকার নিশ্চয় সংঘটিত হবে। তিনি সর্বশ্রোতা, সর্বজ্ঞ।"],
  "29:6": ["Those who strive, strive for their own good. Allah is in no need for anyone.","যারা সংগ্রাম করে, তাদের নিজেদের ভালোর জন্য সংগ্রাম করে। আল্লাহর কাউকে প্রয়োজন নেই।"],
  "29:7": ["Those who believe and lead a righteous life, we will certainly remit their sins, and will certainly reward them generously for their righteous works.","যারা বিশ্বাস করে ও সৎ জীবন-যাপন করে, আমরা অবশ্যই তাদের পাপগুলোকে মাফ করে দেবো, এবং নিশ্চয়ই তাদেরকে উদারভাবে পুরষ্কৃত করবো তাদের সৎকর্মের জন্য।"],
  "29:8": ["We enjoined the human being to honor his parents. But if they try to force you to set up idols beside Me, do not obey them. To Me is your ultimate return, then I will inform you of everything you had done.","আমরা মানুষকে তার পিতামাতাকে সম্মান করতে আদেশ দিয়েছি। কিন্তু যদি তারা আমার পাশে উপাস্যদের স্থাপন করতে তোমাকে জোর করার চেষ্টা করে, তাদেরকে মান্য করবে না। আমার কাছে তোমাদের চুড়ান্ত নিয়তি, এরপর আমি তোমাদেরকে জানাবো যাকিছু তোমরা করেছিলে।"],
  "29:9": ["Those who believe and lead a righteous life, we will certainly admit them with the righteous.","যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে, আমরা নিশ্চয় তাদেরকে সৎকর্মশীলদের সাথে প্রবেশ করাবো।"],
  "29:10": ["Among the people there are those who say, \"We believe in Allah,\" but as soon as they suffer any hardship because of Allah, they equate the people's persecution with Allah's retribution. But if blessings from your Lord come your way, they say, \"We were with you.\" Is Allah not fully aware of the people's innermost thoughts?","লোকদের মধ্যে এমন আছে যারা বলে, \"আমরা আল্লাহতে বিশ্বাস করি,”কিন্তু যখনই আল্লাহর কারনে তারা কোন কষ্ট ভোগ করে, তারা লোকদের অত্যাচারকে আল্লাহর শাস্তির মত মনে করে। কিন্তু তোমার কাছে তোমার প্রভুর অনুগ্রহ আসলে, তারা বলে, \"আমরা তোমাদের সাথে ছিলাম।”আল্লাহ কি লোকদের গভীরতম চিন্তাগুলোর বিষয়ে সম্পূর্ণ সচেতন নন?"],
  "29:11": ["Allah will most certainly distinguish those who believe, and He will most certainly expose the hypocrites.","যারা বিশ্বাস করে নিশ্চয় আল্লাহ তাদেরকে আলাদা করবেন,  এবং নিশ্চয় তিনি ভন্ডদের প্রকাশ করে দেবেন।"],
  "29:12": ["Those who disbelieved said to those who believed, \"If you follow our way, we will be responsible for your sins.\" Not true; they cannot bear any of their sins. They are liars.","যারা অবিশ্বাস করেছে তারা বিশ্বাসীদের  বলেছে, \"যদি তোমরা আমাদের পথ অনুসরণ করো, আমরা তোমাদের পাপভার  নিবো।” সত্য নয়; তারা তাদের কোন পাপভার বহন করতে পারবে না। তারা মিথ্যাবাদী।"],
  "29:13": ["In fact, they will carry their own sins, in addition to loads of other people's sins for which they were responsible. Most certainly, they will be asked on the Day of Resurrection about their false claims.","প্রকৃতপক্ষে, তারা তাদের নিজেদের পাপভার বহন করবে, সেই সাথে অন্যদের পাপের বোঝা, যেগুলোর জন্য তারা দায়ী ছিল। নিশ্চয়, পুনরুত্থান দিবসে তাদেরকে তাদের মিথ্যা দাবীর বিষয়ে জিজ্ঞেস করা হবে।"],
  "29:14": ["We sent Noah to his people, and he stayed with them one thousand years, less fifty. Subsequently, they incurred the flood because of their transgressions.","আমরা নূহকে তার লোকদের কাছে পাঠিয়েছিলাম, এবং সে তাদের সাথে পঞ্চাশ কম এক হাজার বছর  অবস্থান করেছিল। পরবর্তীতে, তারা তাদের সীমালঙ্ঘনের কারণে বন্যা টেনে এনেছিল।"],
  "29:15": ["We saved him and those who accompanied him in the ark, and we set it up as a lesson for all the people.","আমরা তাকে ও তার সাথে যারা নৌকায় ছিল তাদেরকে রক্ষা করেছিলাম, এবং আমরা একে সব লোকদের জন্য একটি শিক্ষা হিসেবে স্থাপন করলাম।"],
  "29:16": ["Abraham said to his people, \"You shall worship Allah, and reverence Him. This is better for you, if you only knew.","ইব্রাহিম তার লোকদের বলেছিল, \"তোমরা আল্লাহর উপাসনা করবে, এবং তাকে ভক্তি করবে। এটা তোমাদের জন্য উত্তম, যদি শুধু তোমরা জানতে।"],
  "29:17": ["\"What you worship instead of Allah are powerless idols; you have invented a lie.\" The idols you worship beside Allah do not possess any provisions for you. Therefore, you shall seek provisions only from Allah. You shall worship Him alone, and be appreciative of Him; to Him is your ultimate return.","\"তোমরা আল্লাহর পরিবর্তে যা কিছুর উপাসনা করো তা ক্ষমতাহীন শরিক-উপাস্য; তোমরা এক মিথ্যা উদ্ভাবন করেছো।\" আল্লাহর পাশে যেসব উপাস্যদের উপাসনা তোমরা করো তাদের কাছে তোমাদের জন্য কোন জীবিকা নেই। অতএব, তোমরা শুধু আল্লাহর কাছে জীবিকা খুঁজবে। তোমরা কেবল তার উপাসনা করবে, এবং তার প্রতি কৃতজ্ঞ  হও; তাঁর কাছেই তোমাদের চুড়ান্ত প্রত্যাবর্তন।"],
  "29:18": ["If you disbelieve, generations before you have also disbelieved. The sole function of the messenger is to deliver (the message).","যদি তোমরা অবিশ্বাস করো, তোমাদের আগও প্রজন্মগুলো অবিশ্বাস করেছে। বার্তাবাহকের একমাত্র কাজ (বার্তা) পৌঁছে দেয়া।"],
  "29:19": ["Have they not seen how Allah initiates the creation, then repeats it? This is easy for Allah to do.","তারা কি দেখেনি কিভাবে আল্লাহ সৃষ্টির সূচনা করেন, এরপর এর পুনরাবৃত্তি করেন? এটি করা আল্লাহর জন্য সহজ।"],
  "29:20": ["Say, \"Roam the earth and find out the origin of life.\" For Allah will thus initiate the creation in the Hereafter. Allah is Omnipotent.","বল, \"পৃথিবী ঘুড়ে বেড়াও এবং জীবনের উৎপত্তি খুঁজে বের করো।\" কারণ আল্লাহ এভাবে পরকালে সৃষ্টির সূচনা করবেন। আল্লাহ সর্বশক্তিমান।"],
  "29:21": ["He condemns to retribution whomever He wills, and showers His mercy upon whomever He wills. Ultimately, to Him you will be turned over.","তিনি যাকে ইচ্ছা শাস্তি দেন, এবং যার প্রতি ইচ্ছা তার দয়া বর্ষণ করেন। অবশেষে, তাঁর দিকেই  তোমরা ফিরবে।"],
  "29:22": ["None of you can escape from these facts, on earth or in the heaven, and you have none beside Allah as a Lord and Master.","তোমাদের কেউ এই বাস্তবতা এড়িয়ে যেতে পারবে না, পৃথিবীতে বা আকাশমণ্ডলীতে, এবং আল্লাহর পাশে প্রভু ও মনিব হিসেবে তোমাদের কেউ নেই।"],
  "29:23": ["Those who disbelieve in Allah's revelations, and in meeting Him, have despaired from My mercy. They have incurred a painful retribution.","যারা আল্লাহর প্রকাশনাবলিতে, আর তাঁর সাথে সাক্ষাতে অবিশ্বাস করে, তারা আমার দয়া থেকে নিরাশ হয়েছে। তারা টেনে এনেছে এক যন্ত্রণাকর শাস্তি।"],
  "29:24": ["The only response from his people was their saying, \"Kill him, or burn him.\" But Allah saved him from the fire. This should provide lessons for people who believe.","প্রতিক্রিয়ায় তার লোকেরা শুধু বলেছিল, \"তাকে হত্যা করো, অথবা  পুড়িয়ে ফেলো।” কিন্তু আল্লাহ তাকে আগুন থেকে রক্ষা করলেন। এটি সে লোকদের জন্য শিক্ষা হওয়া উচিত যারা বিশ্বাস করে।"],
  "29:25": ["He said, \"You worship beside Allah powerless idols due to peer pressure, just to preserve some friendship among you in this worldly life. But then, on the Day of Resurrection, you will disown one another, and curse one another. Your destiny is Hell, wherein you cannot help one another.\"","সে বলল, \"তোমরা  সামাজিক চাপের কারনে আল্লাহর পাশে ক্ষমতাহীন উপাস্যের উপাসনা করো, শুধুমাত্র এই পার্থিব জীবনে তোমাদের মধ্যে কিছু বন্ধুত্ব রক্ষার জন্য। কিন্তু এরপর, পুনরুত্থান দিবসে, তোমরা একে অপরকে পরিত্যাগ করবে, এবং একে অপরকে অভিশাপ দিবে। তোমাদের নিয়তি নরক, যেখানে তোমরা পরস্পরকে সাহায্য করতে পারবে না।\""],
  "29:26": ["Lot believed with him and said, \"I am emigrating to my Lord. He is the Almighty, the Most Wise.\"","লূত তার সাথে বিশ্বাস করেছিল এবং বলেছিল, \"আমি আমার প্রভুর উদ্দেশ্যে দেশত্যাগ করছি। তিনি সর্বশক্তিমান, সবচেয়ে জ্ঞানী। \""],
  "29:27": ["We granted him Isaac and Jacob, we assigned to his descendants prophethood and the scriptures, we endowed him with his due recompense in this life, and in the Hereafter he will surely be with the righteous.","আমরা তাকে ইসহাক ও ইয়াকুব দান করেছিলাম, আমরা তার বংশধরদের মধ্যে  নবুওয়ত ও কিতাবের নিয়োগ দিয়েছিলিম/ দায়িত্ব দিয়েছিলাম, আমরা তাকে দিয়েছিলাম তার প্রাপ্য প্রতিদান, এবং  পরকালে সে অবশ্যই সৎকর্মশীলদের সাথে থাকবে।"],
  "29:28": ["Lot said to his people, \"You commit such an abomination, no one in the world has ever done it before you.","লূত তার লোকদের বলল, \"তোমরা এমন ঘৃন্য কাজ করো, যা বিশ্বে তোমাদের আগে আর কেউ করেনি।"],
  "29:29": ["\"You practice sex with the men, you commit highway robbery, and you allow all kinds of vice in your society.\" The only response from his people was to say, \"Bring to us Allah's retribution, if you are truthful.\"","\"তোমরা পুরুষদের সাথে যৌন চর্চা করো, তোমরা রাজপথে ডাকাতি করো, এবং তোমাদের সমাজে তোমরা সব রকমের পাপ অনুমোদন করো।” প্রতিক্রিয়ায় তার লোকেরা কেবল বলেছিল, \"আমাদের কাছে আল্লাহর শাস্তি নিয়ে আসো, যদি তুমি সত্যবাদী হও।\""],
  "29:30": ["He said, \"My Lord, grant me victory over these wicked people.\"","সে বলল, \"আমার প্রভু, এইসব অন্যায়কারী লোকদের উপর আমাকে বিজয় দান করুন।"],
  "29:31": ["When our messengers went to Abraham with good news (about Isaac's birth), they also said, \"We are on our way to annihilate the people of that town (Sodom). For its people have been wicked.\"","যখন আমাদের ফেরেশতারা ইব্রাহিমের কাছে (ইসহাকের জন্মের) সুসংবাদ নিয়ে যায়, তারা এও বলে, “আমরা ঐ (সডম) শহরের  লোকদের ধ্বংস করতে যাচ্ছি। কারণ এর লোকেরা অন্যায়কারী। \""],
  "29:32": ["He said, \"But Lot is living there.\" They said, \"We are fully aware of everyone who lives in it. We will of course save him and his family, except his wife; she is doomed.\"","সে বলল, \"কিন্তু সেখানে লূত থাকে।” তারা বলল, \"সেখানে যারা থাকে আমরা তাদের প্রত্যেকের বিষয়ে সম্পূর্ণ অবগত। আমরা অবশ্যই তাকে ও তার পরিবারকে রক্ষা করবো, তার স্ত্রী ছাড়া; সে ধ্বংসপ্রাপ্ত।\""],
  "29:33": ["When our messengers arrived at Lot's place, they were mistreated, and he was embarrassed by their presence. But they said, \"Have no fear, and do not worry. We will save you and your family, except your wife; she is doomed.","যখন আমাদের ফেরেশতারা লূতের কাছে পৌঁছলো, তাদের সাথে দূর্ব্যবহার করা হলো, এবং সে তাদের উপস্থিতিতে বিব্রত হলো। কিন্তু তারা বলল, \"ভয় করো না, এবং দুশ্চিন্তা করো না। আমরা তোমাকে ও তোমার পরিবারকে রক্ষা করবো, তোমার স্ত্রী ছাড়া; সে ধ্বংসপ্রাপ্ত।"],
  "29:34": ["\"We will pour upon the people of this town a disaster from the sky, as a consequence of their wickedness.\"","\"আমরা আকাশ থেকে এই শহরের লোকদের উপর দূর্যোগ অবতীর্ণ করবো, তাদের অন্যায়ের পরিনামে।\""],
  "29:35": ["We left standing some of their ruins, to serve as a profound lesson for people who understand.","আমরা তাদের কিছু ধ্বংসস্তূপকে রেখে দিয়েছি, সেসব লোকদের জন্য একটি দিব্যমান শিক্ষা হিসেবে যারা বুঝে।"],
  "29:36": ["To Midyan we sent their brother Shu'aib. He said, \"O my people, you shall worship Allah and seek the Last Day, and do not roam the earth corruptingly.\"","মাদিয়ানবাসীদের কাছে আমরা তাদের ভাই শোয়াইবকে পাঠিয়েছিলাম। সে বলেছিল, \"হে আমার লোকেরা, তোমরা আল্লাহর উপাসনা করবে ও শেষ দিনের কামনা করবে, এবং পৃথিবীতে দূর্নীতি করে বেড়াবে না।\""],
  "29:37": ["They disbelieved him and, consequently, the earthquake annihilated them; they were left dead in their homes by morning.","তারা তাকে অবিশ্বাস করেছিল এবং পরিনামে, ভূমিকম্প তাদের ধ্বংস করেছিল; সকালের মধ্যেই তারা তাদের ঘরে মৃত পড়ে ছিল।"],
  "29:38": ["Similarly, 'Ãd and Thamûd (were annihilated). This is made manifest to you through their ruins. The devil had adorned their works in their eyes, and had diverted them from the path, even though they had eyes.","একইভাবে, আদ ও সামূদ (ধ্বংস হয়েছিল)। তাদের ধ্বংসস্তূপই তোমাদের কাছে তা সুস্পষ্ট করে তোলে। শয়তান তাদের চোখে তাদের কাজকে সাজিয়ে রেখেছিল, এবং পথ থেকে তাদেরকে সরিয়ে দিয়েছিল, যদিও তারা ছিল দৃষ্টি সম্পন্ন।"],
  "29:39": ["Also Qãroon, Pharaoh, and Hãmãn; Moses went to them with clear signs. But they continued to commit tyranny on earth. Consequently, they could not evade (the retribution).","এছাড়াও ক্বারুন, ফেরাউন, এবং হামান; মূসা তাদের কাছে পরিষ্কার নিদর্শনাবলি নিয়ে গিয়েছিল। কিন্তু পৃথিবীতে তারা অত্যাচার করেই যাচ্ছিলো। ফলস্বরুপ, তারা (শাস্তি) এড়াতে পারলো না।"],
  "29:40": ["All those disbelievers were doomed as a consequence of their sins. Some of them we annihilated by violent winds, some were annihilated by the quake, some we caused the earth to swallow, and some we drowned. Allah is not the One who wronged them; it is they who wronged their own souls.","সে সকল অবিশ্বাসীরা তাদের পাপের ফলস্বরূপ ধ্বংস হয়েছিল। আমরা তাদের কাউকে ধ্বংস করেছিলাম ঝড়ো বাতাস দিয়ে,  কাউকে ধ্বংস করেছিল ভূমিকম্প, কাউকে পৃথিবী গিলে ফেলেছিল, আর কাউকে আমরা ডুবিয়ে দিয়েছিলাম।  আল্লাহ তাদের প্রতি কোন অন্যায় করেননি; তারা নিজেরাই তাদের আত্মার প্রতি অন্যায় করেছিল।"],
  "29:41": ["The allegory of those who accept other masters beside Allah is that of the spider and her home; the flimsiest of all homes is the home of the spider, if they only knew.","যারা আল্লাহর পাশে অন্য মনিবদের গ্রহন করে তাদের উপমা হচ্ছে মাকড়সা ও তার ঘর সরুপ; সব ঘরের মধ্যে মাকড়সার ঘরই সবচেয়ে ভঙ্গুর, শুধু যদি তারা জানতো।"],
  "29:42": ["Allah knows full well that whatever they worship besides Him are really nothing. He is the Almighty, the Most Wise.","আল্লাহ ভালো করেই জানেন যে, তাঁকে বাদ দিয়ে তারা যা কিছুরই উপাসনা করে, তা আসলে কিছুই নয়।তিনি সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "29:43": ["We cite these examples for the people, and none appreciate them except the knowledgeable.","এইসব উদাহরণ আমরা লোকেদের জন্য বর্ণনা করি, এবং জ্ঞানীরা  ছাড়া কেউই এগুলোর মর্ম উপলব্ধি করে না।"],
  "29:44": ["Allah created the heavens and the earth, truthfully. This provides a sufficient proof for the believers.","আল্লাহ আকাশমন্ডলী ও পৃথিবী সৃষ্টি করেছেন, সত্যের সাথে। বিশ্বাসীদের জন্য এটি যথেষ্ঠ প্রমান যোগায়।"],
  "29:45": ["You shall recite what is revealed to you of the scripture, and observe the Contact Prayers (Salat), for the Contact Prayers prohibit evil and vice. But the remembrance of Allah (through Salat) is the most important objective. Allah knows everything you do.","তুমি আবৃতি করবে ঐশীগ্রন্থের যা তোমার কাছে প্রকাশ করা হয়েছে, এবং সংযোগ প্রার্থনা (সালাত) পালন করো, কারন সংযোগ প্রার্থনা মন্দ ও অধর্ম থেকে দূরে রাখে। কিন্তু (সালাতের মাধ্যমে) আল্লাহর স্মরণ করাই হলো সবচেয়ে গুরুত্বপূর্ণ লক্ষ্য। তোমরা যা কিছুই করো  আল্লাহ তা জানেন।"],
  "29:46": ["Do not argue with the people of the scripture (Jews, Christians, & Muslims) except in the nicest possible manner—unless they transgress— and say, \"We believe in what was revealed to us and in what was revealed to you, and our god and your god is one and the same; to Him we are submitters.\"","যথাসম্ভব উত্তম পন্থা ব্যতিত ঐশীগ্রন্থের লোকেদের (ইহুদি, খ্রিস্টান, ও মুসলিমদের) সাথে বিতর্ক করো না- যদি না তারা সীমালঙ্ঘন করে- আর বল, \"আমরা বিশ্বাস করি যা আমাদের কাছে প্রকাশ করা হয়েছে ও যা তোমাদের কাছে প্রকাশ করা হয়েছে, আর আমাদের উপাস্য ও তোমাদের উপাস্য এক এবং একই/অভিন্ন; তার কাছেই আমরা আত্মসমর্পণকারী। \""],
  "29:47": ["We have revealed to you this scripture, and those whom we blessed with the previous scripture will believe in it. Also, some of your people will believe in it. Indeed, those who disregard our revelations are the real disbelievers.","আমরা তোমার কাছে এই ঐশীগ্রন্থ প্রকাশ করেছি, এবং যাদেরকে আমরা পূর্বের ঐশীগ্রন্থ দিয়ে সৌভাগ্যশালী করেছি তারা এতে বিশ্বাস করবে। এছাড়াও, তোমার লোকদের কেউ কেউ এতে বিশ্বাস করবে। নিশ্চয়, যারা আমাদের প্রকাশনাবলি উপেক্ষা করে তারাই প্রকৃত অবিশ্বাসী।"],
  "29:48": ["You did not read the previous scriptures, nor did you write them with your hand. In that case, the rejectors would have had reason to harbor doubts.","তুমি পূর্ববর্তী ঐশীগ্রন্থগুলো পড়োনি, না তুমি সেগুলো নিজের হাতে লিখেছ। সেক্ষেত্রে, প্রত্যাখ্যানকারীদের সন্দেহ করার কারন থাকতে পারতো।"],
  "29:49": ["In fact, these revelations are clear in the chests of those who possess knowledge. Only the wicked will disregard our revelations.","প্রকৃতপক্ষে, এই আয়াতগুলি জ্ঞানীদের বুকের ভিতরে স্পষ্ট।শুধু অন্যায়কারীরাই আমাদের প্রকাশনাবলি প্রত্যাখ্যান করবে।"],
  "29:50": ["They said, \"If only miracles could come down to him from his Lord!\" Say, \"All miracles come only from Allah; I am no more than a manifest warner.\"","তারা বলল, \"শুধু যদি তার প্রভুর পক্ষ থেকে তার কাছে অলৌকিকতা আসতো!” বল, \"সকল অলৌকিকতা কেবল আল্লাহ থেকে আসে; আমি একজন স্পষ্ট সতর্ককারীর চেয়ে বেশি কিছু নই।\""],
  "29:51": ["Is it not enough of a miracle that we sent down to you this book, being recited to them? This is indeed a mercy and a reminder for people who believe.","এটি কি যথেষ্ট অলৌকিকতা নয় যে আমরা তোমার কাছে এই গ্রন্থ অবতীর্ণ করেছি, যা তাদের কাছে আবৃতি করা হয়? এটি নিশ্চয় একটি দয়া ও এক স্মারক সে লোকদের জন্য যারা বিশ্বাস করে।"],
  "29:52": ["Say, \"Allah suffices as a witness between me and you. He knows everything in the heavens and the earth. Surely, those who believe in falsehood and disbelieve in Allah are the real losers.\"","বল, \"আমার এবং তোমাদের মাঝে সাক্ষী হিসেবে আল্লাহ যথেষ্ট। তিনি আকাশমণ্ডলী ও পৃথিবীর সবকিছু জানেন। নিশ্চয়, যারা মিথ্যায় বিশ্বাস করে এবং আল্লাহতে অবিশ্বাস করে তারাই প্রকৃত ক্ষতিগ্রস্ত।\""],
  "29:53": ["They challenge you to bring the retribution! If it were not for a predetermined appointment, the retribution would have come to them immediately. Certainly, it will come to them suddenly, when they least expect it.","তারা তোমাকে শাস্তি আনার জন্য চ্যালেঞ্জ করে! যদি এক পূর্বনির্ধারিত সময় না থাকতো, শাস্তি তাদের কাছে তৎক্ষণাৎ আসতো। নিশ্চয়, এটি তাদের কাছে হঠাৎ করেই আসবে, যখন তারা খুব কমই এর আশা করবে।"],
  "29:54": ["They challenge you to bring retribution! Hell already surrounds the disbelievers.","শাস্তি আনার জন্য তারা তোমাকে চ্যালেঞ্জ করে! নরক তো ইতোমধ্যে অবিশ্বাসীদের ঘিরেই ফেলেছে।"],
  "29:55": ["The day will come when the retribution overwhelms them, from above them and from beneath their feet; He will say, \"Taste the consequences of your works.\"","সেদিন আসবে যখন শাস্তি তাদের ঘেরাও করে ফেলবে, তাদের উপর থেকে এবং তাদের পায়ের নিচ থেকে; সে বলবে, \"তোমাদের কাজের ফল আস্বাদন করো।\""],
  "29:56": ["O My servants who believed, My earth is spacious, so worship Me.","হে আমার বান্দারা যারা বিশ্বাস করো, আমার পৃথিবী প্রশস্ত, তাই আমার উপাসনা করো।"],
  "29:57": ["Every soul will taste death, then to us you will be ultimately returned.","প্রত্যেক আত্মা মৃত্যুর স্বাদ আস্বাদন করবে, এরপর পরিশেষে আমাদের কাছেই তোমরা ফিরে আসবে।"],
  "29:58": ["Those who believe and lead a righteous life, we will surely settle them in Paradise, with mansions and flowing streams. Eternally they abide therein. What a beautiful reward for the workers.","যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে, নিশ্চয় আমরা তাদেরকে প্রতিষ্ঠিত করবো স্বর্গে, অট্রালিকা ও প্রবাহিত ঝর্ণা সহ। তারা সেখানে চিরকাল বাস করে। কতই না সুন্দর পুরষ্কার তাদের জন্য যারা কর্ম করে!"],
  "29:59": ["They are the ones who steadfastly persevere, and trust in their Lord.","তারা সে ব্যক্তি যারা দৃঢ়তার সাথে অবিচল থাকে, আর তাদের প্রভুর উপর আস্থা রাখে।"],
  "29:60": ["Many a creature that does not carry its provision, Allah provides for it, as well as for you. He is the Hearer, the Omniscient.","বহু প্রানি আছে যেগুলো এদের জীবিকা বহন করে না, আল্লাহ এদের জন্য প্রদান করেন, একইভাবে তোমাদের জন্যও। তিনি শুনেন, সর্বজ্ঞ।"],
  "29:61": ["If you ask them, \"Who created the heavens and the earth, and put the sun and the moon in your service,\" they will say, \"Allah.\" Why then did they deviate?","যদি তুমি তাদের জিজ্ঞেস করো, \"কে আকাশমণ্ডলী ও পৃথিবী সৃষ্টি করেছেন, আর তোমাদের সেবায় সূর্য ও চাঁদকে নিয়োজিত করেছেন, ” তারা বলবে, \"আল্লাহ।” তাহলে কেন তারা বিচ্যুত হয়?"],
  "29:62": ["Allah is the One who increases the provision for whomever He chooses from among His creatures, and withholds it. Allah is fully aware of all things.","আল্লাহই সে সত্ত্বা যিনি তার সৃষ্টিকূল থেকে যে কারো জন্য ইচ্ছে জীবিকা বৃদ্ধি করেন, আর তা সীমাবদ্ধ রাখেন। আল্লাহ সবকিছুর বিষয়ে পূর্ণ সচেতন।"],
  "29:63": ["If you ask them, \"Who sends down from the sky water, to revive dead land,\" they will say, \"Allah.\" Say, \"Praise Allah.\" Most of them do not understand.","যদি তুমি তাদের জিজ্ঞেস করো, \"কে আকাশ থেকে পানি অবতীর্ণ করেন মৃত জমিকে পুনরুজ্জীবিত করার জন্য\" , তারা বলবে, \"আল্লাহ।\" বল, \"প্রশংসা আল্লাহর।\"  তাদের বেশির ভাগ বুঝে না।"],
  "29:64": ["This worldly life is no more than vanity and play, while the abode of the Hereafter is the real life, if they only knew.","এই পার্থিব জীবন অহমিকা এবং রঙ্গ-খেলার চেয়ে বেশি কিছু নয়, যেখানে পরকালের আবাসই সত্যিকার জীবন, যদি শুধু তারা জানতো।"],
  "29:65": ["When they ride on a ship, they implore Allah, devoting their prayers to Him. But as soon as He saves them to the shore, they revert to idolatry.","যখন তারা কোন জাহাজে আরোহণ করে, তারা আল্লাহর কাছে মিনতি করে, তাদের প্রার্থনাকে তাঁর কাছেই নিবেদন করে। কিন্তু যখনই তাদেরকে তিনি তীরে এনে রক্ষা করেন, তারা পুনরায় শিরক করতে থাকে।"],
  "29:66": ["Let them disbelieve in what we have given them, and let them enjoy temporarily; they will surely find out.","তাদেরকে অবিশ্বাস করতে দাও যা আমরা তাদেরকে দিয়েছি, এবং তাদেরকে কিছু কালের জন্য উপভোগ করতে দাও; তারা নিশ্চয় দেখতে পাবে।"],
  "29:67": ["Have they not seen that we have established a Sacred Sanctuary that we made secure, while all around them the people are in constant danger? Would they still believe in falsehood, and reject Allah's blessings?","তারা কি দেখেনি যে আমরা একটি পবিত্র উপাসনার স্থান প্রতিষ্ঠা করেছি যাকে আমরা নিরাপদ করেছি, যখন তাদের চারপাশের সকল লোকেরা অনবরত বিপদে আছে? তারা কি এরপরও মিথ্যায় বিশ্বাস করবে, এবং আল্লাহর অনুগ্রহকে প্রত্যাখ্যান করবে?"],
  "29:68": ["Who is more evil than one who fabricates lies and attributes them to Allah, or rejects the truth when it comes to him? Is Hell not a just retribution for the disbelievers?","তার চেয়ে কে বেশি মন্দ যে মিথ্যা উদ্ভাবন করে এবং সেগুলো আল্লাহর প্রতি আরোপ করে, অথবা সত্য প্রত্যাখ্যান করে যখন তা তার কাছে আসে? নরকই কি অবিশ্বাসীদের জন্য উচিত শাস্তি নয়?"],
  "29:69": ["As for those who strive in our cause, we will surely guide them in our paths. Most assuredly, Allah is with the pious.","আর যারা আমাদের কারনে সংগ্রাম করে, আমরা নিশ্চয় তাদেরকে আমাদের পথ দেখাবো।  নিশ্চিতই, আল্লাহ সৎকর্মশীলদের সাথে আছেন।"],
  "30:1": ["A. L. M.","অ.ল.ম"],
  "30:2": ["Certainly, the Romans will be defeated.","নিশ্চয়, রোমানরা পরাজিত হবে।"],
  "30:3": ["In the nearest land. After their defeat, they will rise again and win.","নিকটতম ভূমিতে। তাদের পরাজয়ের পর, তারা আবার জেগে উঠবে এবং জয়ী হবে।"],
  "30:4": ["Within several years. Such is Allah's decision, both in the first prophecy, and the second. On that day, the believers shall rejoice","কয়েক বছরের মধ্যে। এমনই আল্লাহর সিদ্ধান্ত, প্রথম এবং দ্বিতীয় উভয় ভবিষৎবাণীর ক্ষেত্রে। ঐ দিন, বিশ্বাসীরা আনন্দ করবে।"],
  "30:5": ["in Allah's victory. He grants victory to whomever He wills. He is the Almighty, Most Merciful.","আল্লাহর বিজয়ে। তিনি যাকে ইচ্ছা বিজয় দান করেন। তিনি সর্বশক্তিমান, সবচেয়ে দয়ালু।"],
  "30:6": ["Such is Allah's promise—and Allah never breaks His promise—but most people do not know.","এমনই আল্লাহর অঙ্গীকার এবং আল্লাহ কখনো তার অঙ্গীকার ভঙ্গ করেন না- কিন্তু অধিকাংশ লোক জানেনা।"],
  "30:7": ["They care only about things of this world that are visible to them, while being totally oblivious to the Hereafter.","তারা কেবল এই পার্থিব জিনিসের প্রতি গুরুত্ব দেয় যা তাদের কাছে দৃশ্যমান,  যখন পরকালের বিষয়ে পুরোপুরি বেখেয়াল থাকে।"],
  "30:8": ["Why do they not reflect on themselves? Allah did not create the heavens and the earth, and everything between them, except for a specific purpose, and for a specific life span. However, most people, with regard to meeting their Lord, are disbelievers.","কেন তারা নিজেদের বিষয়ে চিন্তা করে না? আল্লাহ আকাশমন্ডলী ও পৃথিবী, এবং এদের মধ্যকার সবকিছু, একটি সুনির্দিষ্ট উদ্দেশ্য, এবং একটি সুনির্দিষ্ট জীবনকাল ব্যতিত সৃষ্টি করেননি। কিন্তু, অধিকাংশ লোক, তাদের প্রভুর সাথে সাক্ষাতের বিষয়ে, অবিশ্বাসী।"],
  "30:9": ["Have they not roamed the earth and noted the consequences for those who preceded them? They used to be more powerful, more prosperous, and more productive on earth. Their messengers went to them with clear signs. Consequently, Allah was not the One who wronged them, they are the ones who wronged their own souls.","তারা কি পৃথিবী ঘুরে দেখেনি এবং তাদের পূর্বে যারা ছিল তাদের পরিনাম লক্ষ্য করেনি? তারা ছিল পৃথিবীতে আরো ক্ষমতাবান, আরো সমৃদ্ধশালী, এবং আরো উৎপাদনশীল। তাদের বার্তাবাহকগন তাদের কাছে পরিষ্কার নিদর্শনাবলি নিয়ে গিয়েছিল। পরিনামে, আল্লাহ তাদের প্রতি অন্যায় করেননি, তারাই তাদের নিজেদের আত্মার প্রতি অন্যায় করেছিল।"],
  "30:10": ["The consequences for those who committed evil had to be evil. That is because they rejected Allah's revelations, and ridiculed them.","যারা মন্দ কাজ করেছিল তাদের পরিনাম মন্দই হওয়ার ছিল। এর কারন হল তারা আল্লাহর প্রকাশনাবলি প্রত্যাখ্যান করত, এবং সেগুলোকে উপহাস করত।"],
  "30:11": ["Allah is the One who initiates the creation and repeats it. Ultimately, you will be returned to Him.","আল্লাহই সে সত্ত্বা যিনি সৃষ্টির সূচনা করেন এবং এর পুনরাবৃত্তি করেন। অবশেষে, তোমাদের তার কাছে ফিরে যেতে হবে।"],
  "30:12": ["On the Day when the Hour comes to pass, the guilty will be shocked.","সে দিনে যখন সে ঘণ্টা সংঘটিত হবে, অপরাধীরা আতংকিত হবে।"],
  "30:13": ["Their idols will have no power to intercede on their behalf; on the contrary, they will disown their idols.","তাদের উপাস্যদের কোন ক্ষমতা থাকবে না তাদের পক্ষ হয়ে সুপারিশ করার ; পক্ষান্তরে, তারা তাদের উপাস্যদের প্রত্যাখ্যান করবে।"],
  "30:14": ["On the day when the Hour comes to pass, they will part company.","যে দিন সময় আসবে, তারা পরস্পর থেকে দুরে চলে যাবে।"],
  "30:15": ["As for those who believe and lead a righteous life, they will be in Paradise, rejoicing.","আর যারা বিশ্বাস করে এবং সৎ জীবন যাপন করে, তারা থাকবে স্বর্গে, আনন্দের সাথে।"],
  "30:16": ["As for those who disbelieve, and reject our revelations and the meeting of the Hereafter, they will last in the retribution forever.","আর যারা অবিশ্বাস করে, আর আমাদের প্রকাশনাবলি এবং পরকালের সাক্ষাতকে প্রত্যাখ্যান করে, তারা চিরকাল শাস্তিতে থাকবে।"],
  "30:17": ["Therefore, you shall glorify Allah when you retire at night, and when you rise in the morning.","অতএব, তোমরা আল্লাহর মহিমা ঘোষণা করবে যখন তোমরা রাতে ঘুমাতে যাও, এবং যখন তোমরা সকালে ঘুম থেকে ওঠো।"],
  "30:18": ["All praise is due to Him in the heavens and the earth, throughout the evening, as well as in the middle of your day.","আকাশমন্ডলী এবং পৃথিবীতে সকল প্রশংসা তাঁর জন্য,  বিকেল জুড়ে, একই সাথে তোমাদের দিনের মধ্যভাগে।"],
  "30:19": ["He produces the live from the dead, and produces the dead from the live, and He revives the land after it had died; you are similarly resurrected.","তিনি মৃত থেকে জীবিতকে তৈরি করেন, আর মৃতকে তৈরি করেন জীবিত থেকে, এবং তিনি ভূমিকে পুনরুজ্জীবিত করেন তা মরে যাবার পর; একইভাবে তোমরা পুনরুজ্জীবিত হও।"],
  "30:20": ["Among His proofs is that He created you from dust, then you became reproducing humans.","তাঁর প্রমাণাদির মধ্যে আছে যে তিনি তোমাদেরকে ধূলা থেকে সৃষ্টি করেছেন, এরপর তোমরা প্রজননশীল মানুষ হয়ে ওঠো।"],
  "30:21": ["Among His proofs is that He created for you spouses from among yourselves, in order to have tranquility and contentment with each other, and He placed in your hearts love and care towards your spouses. In this, there are sufficient proofs for people who think.","তাঁর প্রমাণসমূহের মধ্যে রয়েছে যে তিনি তোমাদের মধ্যে থেকে তোমাদের জন্য স্বামী-স্ত্রী সৃষ্টি করেছেন, যাতে পরস্পরের সাথে প্রশান্তি ও সন্তুষ্টিতে থাকো,  আর তিনি তোমাদের সঙ্গীদের প্রতি তোমাদের হৃদয়ে ভালবাসা ও যত্ন রেখেছেন। এর মধ্যে, যথেষ্ট প্রমান আছে সে লোকদের জন্য যারা চিন্তা করে।"],
  "30:22": ["Among His proofs are the creation of the heavens and the earth, and the variations in your languages and your colors. In these, there are signs for the knowledgeable.","তাঁর প্রমাণসমূহের মধ্যে রয়েছে আকাশমণ্ডলী ও পৃথিবীর সৃষ্টি, এবং তোমাদের ভাষা ও রঙের ভিন্নতা। এসবের মধ্যে, নিদর্শনাবলি আছে জ্ঞানবানদের জন্য।"],
  "30:23": ["Among His proofs is your sleeping during the night or the day, and your working in pursuit of His provisions. In this, there are sufficient proofs for people who can hear.","তাঁর প্রমাণসমূহের মধ্যে রয়েছে তোমাদের ঘুম রাতে বা দিনে, এবং তাঁর জীবিকার খোঁজে তোমাদের কাজ করা। এর মাঝে, যথেষ্ট প্রমান রয়েছে সে লোকদের জন্য যারা শুনতে পারে।"],
  "30:24": ["Among His proofs is that He shows you the lightning as a source of fear, as well as hope, then He sends down from the sky water to revive a land that has been dead. In these, there are sufficient proofs for people who understand.","তাঁর প্রমাণসমূহের মধ্যে রয়েছে যে তিনি তোমাদের বজ্রপাত দেখান ভয় উদ্রেককারী সেই সাথে আশা স্বরূপ, এরপর তিনি আকাশ থেকে পানি বর্ষণ করেন জমিকে পুনরুজ্জীবিত করতে যা ছিল মৃত। এসবের মধ্যে, সে লোকদের জন্য যথেষ্ট প্রমান আছে যারা বুঝে।"],
  "30:25": ["Among His proofs is that the heaven and the earth are standing at His disposal. Finally, when He calls you out of the earth, one call, you will immediately come out.","তাঁর প্রমাণসমূহের মধ্যে রয়েছে যে আকাশ ও পৃথিবী তাঁর নিয়ন্ত্রনে দাঁড়িয়ে আছে। অবশেষে, যখন তিনি তোমাদেরকে ডাকেন মাটি থেকে বের হতে, একটি ডাক, তোমরা সাথে সাথে বের হয়ে আসবে।"],
  "30:26": ["To Him belongs everyone in the heavens and the earth; all are subservient to Him.","আকাশমণ্ডলী ও পৃথিবীর সবাই তাঁরই; সবাই তাঁর আজ্ঞাধীন।"],
  "30:27": ["And He is the One who initiates the creation, then repeats it; this is even easier for Him. To Him belongs the most sublime similitude, in the heavens and the earth, and He is the Almighty, Most Wise.","আর তিনিই সেই সত্ত্বা যিনি সৃষ্টির সূচনা করেন, এরপর তার পুনরাবৃত্তি করেন; এটা এমনকি তাঁর জন্য আরো  সহজ। সবচেয়ে মহিমান্বিত উপমা তারই, আকাশমণ্ডলী ও পৃথিবীতে, এবং তিনি সর্বশক্তিমান, সবথেকে জ্ঞানী।"],
  "30:28": ["He cites for you herein an example from among yourselves: Do you ever elevate your servants or subordinates to the level where they rival you, and to the point that you pay them as much allegiance as is being paid to you? We thus explain the revelations for people who understand.","তিনি তোমাদের জন্য এখানে একটি উদাহরণ দেন তোমাদের নিজেদের মধ্য থেকে: তোমরা কি তোমাদের ভৃত্য বা অধস্তনদের কখনো সে স্তরে উঠাও যেখানে তারা তোমাদের প্রতিদ্বন্দ্বিতা করে, এবং সে বিন্দুতে যে তোমরা তাদেরকে ততটুকু আনুগত্য প্রদর্শন করো যতটুকু তোমাদেরকে প্রদর্শন করা হয়? আমরা এভাবে সে লোকদের জন্য প্রকাশনাবলি ব্যাখ্যা করি যারা বুঝে।"],
  "30:29": ["Indeed, the transgressors have followed their own opinions, without knowledge. Who then can guide those who have been sent astray by Allah? No one can ever help them.","নিশ্চয়, সীমালঙ্ঘনকারীরা তাদের নিজেদের মত অনুসরণ করেছে, জ্ঞান ছাড়াই। কে তবে তাদেরকে পথ দেখাতে পারে যারা আল্লাহর দ্বারা পথভ্রষ্ট হয়েছে? কেউ কখনো তাদের সাহায্য করতে পারবে না।"],
  "30:30": ["Therefore, you shall devote yourself to the religion of strict monotheism. Such is the natural instinct placed into the people by Allah. Such creation of Allah will never change. This is the perfect religion, but most people do not know.","অতএব, তোমরা নিজেদেরকে উৎসর্গ করবে কঠোর একেশ্বরবাদী ধর্মের প্রতি। এমনই সহজাত প্রবৃত্তি যা আল্লাহ লোকদের মধ্যে রেখেছেন। আল্লাহর এমন সৃষ্টি কখনো পরিবর্তন হবে না। এটাই নিঃখুত ধর্ম, কিন্তু অধিকাংশ লোক জানে না।"],
  "30:31": ["You shall submit to Him, reverence Him, observe the Contact Prayers (Salat), and—whatever you do—do not ever fall into idol worship.","তোমরা তাঁর নিকট আত্মসমর্পণ করবে, তাঁকে ভক্তি-শ্রদ্ধা করবে, সংযোগ প্রার্থনা (সালাত) পালন করবে, এবং  তোমরা যা-ই করো না কেন – কখনো শরিক উপাসনায় পড়ো না।"],
  "30:32": ["(Do not fall in idol worship,) like those who divide their religion into sects; each party rejoicing with what they have.","(শিরক এ পড়ো না) তাদের মতো যারা নিজেদের ধর্মকে বিভিন্ন বর্ণে ভাগ করে; প্রত্যেকটি দল তাদের যা আছে তা নিয়ে আনন্দিত।"],
  "30:33": ["When adversity afflicts the people, they turn to their Lord, totally devoting themselves to Him. But then, as soon as He showers them with mercy, some of them revert to idol worship.","যখন মানুষ দুর্দশাগ্রস্থ হয়, তারা তাদের প্রভুর দিকে ফিরে, নিজেদেরকে পুরোপুরি তাঁর কাছে উৎসর্গ করে। কিন্তু তারপর, যখনি তিনি তাদের উপর দয়া বর্ষণ করেন, তাদের কেউ কেউ শিরক উপাসনায় ফিরে যায়।"],
  "30:34": ["Let them be unappreciative of what we have given them. Enjoy temporarily; you will surely find out.","আমরা তাদেরকে যা দিয়েছি তাতে তাদেরকে অকৃতজ্ঞ হতে দাও। সাময়িকভাবে উপভোগ করো; অবশ্যই তোমরা দেখতে পাবে।"],
  "30:35": ["Have we given them authorization that justifies their idolatry?","আমরা কি তাদেরকে এমন অনমুদন দিয়েছি যা তাদের শিরককে নিয়মসিদ্ধ করে?"],
  "30:36": ["When we bestow mercy upon the people, they rejoice therein. But when adversity befalls them, as a consequence of their own works, they become despondent.","যখন আমরা মানুষের উপর দয়া বর্ষণ করি, তারা তাতে আনন্দ করে। কিন্তু যখন তাদের উপর দুর্ভোগ পতিত হয়, তাদের নিজেদের কাজের পরিনামে, তারা হতাশ হয়ে যায়।"],
  "30:37": ["Do they not realize that Allah increases the provision for whomever He wills, or reduces it? These should be lessons for people who believe.","তারা কি এটা অনুধাবন করে না যে আল্লাহ যার জন্য ইচ্ছা জীবিকা বৃদ্ধি করেন, অথবা তা কমিয়ে দেন? এটা সেসব মানুষের জন্য শিক্ষা হওয়া উচিত যারা বিশ্বাস করে।"],
  "30:38": ["Therefore, you shall give the relatives their rightful share (of charity), as well as the poor, and the traveling alien. This is better for those who sincerely seek Allah's pleasure; they are the winners.","অত:এব, তোমরা আত্মীয়দের দিবে তাদের  ন্যায্য অংশ (দানের), গরীবদেরও, এবং ভ্রমণরত ভীনদেশীদের। এটি তাদের জন্য উত্তম যারা আন্তরিকভাবে আল্লাহর সন্তুষ্টি খোঁজে; তারাই বিজয়ী।"],
  "30:39": ["The usury that is practiced to increase some people's wealth, does not gain anything at Allah. But if you give to charity, seeking Allah's pleasure, these are the ones who receive their reward manifold.","চড়াসুদ, যা কিছু মানুষের সম্পদ বাড়ানোর জন্য চর্চা করা হয়, তা আল্লাহর দৃষ্টিতে কিছুই লাভ করে না। কিন্তু যদি তোমরা দান করো, আল্লাহর সন্তুষ্টির খোঁজে, এরাই সে ব্যক্তি যারা বহুগুণে তাদের পুরস্কার পায়।"],
  "30:40": ["Allah is the One who created you. He is the One who provides for you. He is the One who puts you to death. He is the One who resurrects you. Can any of your idols do any of these things? Be He glorified. He is much too exalted to have any partners.","আল্লাহই সে সত্ত্বা যিনি তোমাদের সৃষ্টি করেছেন। তিনিই সে সত্ত্বা যিনি তোমাদেরকে জীবিকা প্রদান করেন। তিনিই সে সত্ত্বা যিনি তোমাদের পুনরুত্থিত করেন। তোমাদের কোন উপাস্য কি এগুলোর কোনকিছু করতে পারে? মহিমা তাঁরই। কোন শরিক থাকা থেকে  তিনি অনেক উর্ধ্বে।"],
  "30:41": ["Disasters have spread throughout the land and sea, because of what the people have committed. He thus lets them taste the consequences of some of their works, that they may return (to the right works).","স্থল ও সাগর জুড়ে দূর্যোগ ছড়িয়ে পড়েছে, মানুষ যা করেছে তার কারনে। তিনি এভাবে তাদের কিছু কাজের পরিনাম অস্বাদন করান, যাতে তারা ( ভাল কাজের দিকে) ফিরে আসে।"],
  "30:42": ["Say, \"Roam the earth and note the consequences for those before you.\" Most of them were idol worshipers.","বল, \"পৃথিবীতে ঘুড়ে বেড়াও এবং তাদের পরিনাম লক্ষ্য করো যারা তোমাদের পূর্বে ছিল।” তাদের বেশির ভাগই ছিল শিরক কারি।"],
  "30:43": ["Therefore, you shall devote yourself completely to this perfect religion, before a day comes which is made inevitable by Allah. On that day, they will be shocked.","অত:এব, তোমরা নিজেদেরকে এই নি:খুত ধর্মে পুরোপুরি উৎসর্গ করবে, সে দিন আসার আগে যা আল্লাহর দ্বারা অনিবার্য করা হয়েছে। ঐদিন, তারা প্রচন্ডভাবে আতংগ্রস্ত হবে।"],
  "30:44": ["Whoever disbelieves, disbelieves to the detriment of his own soul, while those who lead a righteous life, do so to strengthen and develop their own souls.","যেকেউ অবিশ্বাস করে, তার নিজ আত্মার ক্ষতি করতেই অবিশ্বাস করে, পক্ষান্তরে যারা সৎ জীবন যাপন করে, তারা তা করে তাদের নিজের আত্মাকে শক্তিশালী ও উন্নত করতে।"],
  "30:45": ["For He will generously recompense those who believe and lead a righteous life from His bounties. He does not love the disbelievers.","কারণ তিনি তাঁর ভান্ডার থেকে তাদেরকে উদারভাবে প্রতিদান দিবেন যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে। তিনি অবিশ্বাসীদের ভালবাসেন না।"],
  "30:46": ["Among His proofs is that He sends the winds with good omen, to shower you with His mercy, and to allow the ships to run in the sea in accordance with His rules, and for you to seek His bounties (through commerce), that you may be appreciative.","তাঁর প্রমানসমূহের মধ্যে রয়েছে যে তিনি বাতাসকে শুভ পূর্বাভাস সহ পাঠান, তোমাদের প্রতি তাঁর দয়া বর্ষণ করতে, এবং তাঁর বিধান অনুসারে জাহাজগুলোকে সাগরে চলতে দিতে, এবং (বানিজ্যের মাধ্যমে) তোমাদের তাঁর ভান্ডার থেকে খুঁজতে দেওয়ার জন্য, যেন তোমরা কৃতজ্ঞ হতে পারো।"],
  "30:47": ["We have sent messengers before you to their people, with profound signs. Subsequently, we punished those who transgressed. It is our duty that we grant victory to the believers.","লোকদের কাছে, জ্ঞানগর্ভ নিদর্শনাবলী দিয়ে। পরবর্তীতে, যারা সীমালঙ্ঘন করেছে তাদেরকে আমরা শাস্তি দিয়েছি। এটা আমাদের দায়িত্ব যে আমরা বিশ্বাসীদের বিজয় দান করি।"],
  "30:48": ["Allah is the One who sends the winds, to stir up clouds, to be spread throughout the sky in accordance with His will. He then piles the clouds up, then you see the rain coming down therefrom. When it falls on whomever He chooses from among His servants, they rejoice.","আল্লাহই সে সত্ত্বা যিনি বাতাস পাঠান, মেঘমালাকে সঞ্চালিত করতে, যাতে তাঁর ইচ্ছা অনুসারে আকাশজুড়ে ছড়িয়ে পড়ে। তিনি এরপর মেঘমালাকে স্তুপ করেন, এরপর তুমি তার মধ্যে থেকে বৃষ্টি নেমে আসতে দেখো। যখন তা বর্ষিত হয় যাদের উপর তিনি চান তাঁর বান্দাদের মধ্য থেকে, তারা আনন্দ করে।"],
  "30:49": ["Before it fell on them, they had resorted to despair.","এটি তাদের উপর বর্ষণ হবার আগে, তারা হতাশা গ্রস্থ হয়েছিল।"],
  "30:50": ["You shall appreciate Allah's continuous mercy, and how He revives the land that has been dead. He will just as certainly resurrect the dead. He is Omnipotent.","তোমরা  মূল্যায়ন করবে আল্লাহর অবিরত দয়াকে, এবং যেভাবে তিনি যে ভূমি মৃত ছিল তাকে পুনরুজ্জীবিত করেন। তিনি ঠিক এমন নিশ্চিতভাবেই মৃতকে পুনরুজ্জীবিত করবেন। তিনি সর্বশক্তিমান।"],
  "30:51": ["Had we sent upon them instead a yellow sandstorm, they would have continued to disbelieve.","আমরা যদি পরিবর্তে তাদের উপর হলুদ বালুঝড় পাঠাতাম, তারা অবিশ্বাস করতেই থাকতো।"],
  "30:52": ["You cannot make the dead, nor the deaf, hear the call, once they turn away.","তুমি না মৃতকে, না বধিরকে, ডাক শুনাতে পারবে, তারা বিমুখ হয়ে পড়লে।"],
  "30:53": ["Nor can you guide the blind out of their straying. You can only be heard by those who believe in our revelations, and decide to become submitters.","না তুমি অন্ধকে তাদের পথভ্রষ্টতা হতে ফিরিয়ে পথ দেখাতে পারবে। তুমি কেবল তাদেরকেই শোনাতে পারবে যারা আমাদের প্রকাশনাবলিতে বিশ্বাস করে, আর আত্মসমর্পণকারী হবার সিদ্ধান্ত নেয়।"],
  "30:54": ["Allah is the One who created you weak, then granted you after the weakness strength, then substituted after the strength weakness and gray hair. He creates whatever He wills. He is the Omniscient, the Omnipotent.","আল্লাহই সে সত্ত্বা যিনি তোমাদের দূর্বল করে সৃষ্টি করেছেন, এরপর দূর্বলতার পর শক্তি দান করেছেন, এরপর শক্তির পরে দিয়েছেন দূর্বলতা এবং ধূসর চুল। তিনি যা ইচ্ছা সৃষ্টি করেন। তিনি সর্বজ্ঞ, সর্বশক্তিমান।"],
  "30:55": ["On the day when the Hour comes to pass, the guilty will swear that they lasted (in this world) only one hour. That is how wrong they were.","সেইদিনে যখন সে সময় সংঘটিত হবে, অপরাধীরা শপথ করে বলবে যে তারা (এই পৃথিবীতে) কেবল এক ঘন্টা অবস্থান করেছিল।  তারা এতোটাই ভুল ছিল।"],
  "30:56": ["Those who are blessed with knowledge and faith will say, \"You have lasted, according to Allah's decree, until the Day of Resurrection. Now, this is the Day of Resurrection, but you failed to recognize it.\"","যারা জ্ঞান ও বিশ্বাস দ্বারা অনুগ্রহপ্রাপ্ত হয়েছে তারা বলবে, \"তোমরা অবস্থান করেছ, আল্লাহর বিধান অনুসারে, পুনরুত্থান দিবস পর্যন্ত। এখন, এটাই পুনরুত্থান দিবস, কিন্তু তোমরা তা চিনতে ব্যর্থ হয়েছ।\""],
  "30:57": ["Therefore, no apology, on that day, will benefit the transgressors, nor will they be excused.","একারনে, কোন ক্ষমাপ্রার্থনা, ঐদিন, সীমালঙ্ঘনকারীদের কাজে আসবে না, না তারা ক্ষমাপ্রাপ্ত হবে।"],
  "30:58": ["Thus, we have cited for the people in this Quran all kinds of examples. Yet, no matter what kind of proof you present to the disbelievers, they say, \"You are falsifiers.\"","এভাবে, আমরা এই কোর'আনে লোকদের জন্য সব রকমের উদাহরণ দিয়েছি। এরপরও, অবিশ্বাসীদেরকে তুমি যে প্রমানই দেখাও না কেন, তারা বলে “তোমরা মিথ্যাপন্থী। \""],
  "30:59": ["Allah thus seals the hearts of those who do not know.","আল্লাহ এভাবে তাদের হৃদয় তালাবদ্ধ করে দেন যারা জানে না।"],
  "30:60": ["Therefore, you shall steadfastly persevere—for Allah's promise is the truth—and do not be intimidated by those who have not attained certainty.","অতএব, তুমি দৃঢ়তার সাথে অবিচল থাকবে- কেননা আল্লাহর প্রতিশ্রুতি সত্য- এবং তাদের দ্বারা ভীত হয়ো না যারা নিশ্চয়তা অর্জন করেনি।"],
  "31:1": ["A. L. M.","অ. ল. ম।"],
  "31:2": ["These (letters) constitute proofs of this book of wisdom.","এই (অক্ষরগুলো) এই জ্ঞানগর্ভ বইয়ের প্রমান গঠন করে।"],
  "31:3": ["A beacon and a mercy for the righteous.","সৎকর্মশীলদের জন্য একটি আলোকবর্তিকা এবং দয়া।"],
  "31:4": ["Who observe the Contact Prayers (Salat), give the obligatory charity (Zakat), and as regards the Hereafter, they are absolutely certain.","যারা সংযোগ প্রার্থনা (সালাত) প্রতিষ্ঠা করে, যাকাত দেয় এবং আখেরাতের ব্যাপারে তারা সম্পূর্ণ নিশ্চিত।"],
  "31:5": ["They are following the guidance from their Lord, and they are the winners.","তারা তাদের পালনকর্তার নির্দেশ অনুসরণ করে এবং তারাই বিজয়ী।"],
  "31:6": ["Among the people, there are those who uphold baseless Hadith, and thus divert others from the path of Allah without knowledge, and take it in vain. These have incurred a shameful retribution.","লোকদের মধ্যে, রয়েছে তারা যারা ভিত্তিহীন হাদীস সমর্থন করে, আর এভাবে কোন জ্ঞান ছাড়া অন্যদেরকে আল্লাহর পথ হতে সরিয়ে দেয়, এবং একে নেয় অর্থহীনভাবে। এরা টেনে এনেছে এক লজ্জাজনক শাস্তি।"],
  "31:7": ["And when our revelations are recited to the one of them, he turns away in arrogance as if he never heard them, as if his ears are deaf. Promise him a painful retribution.","আর যখন তাদের কারো কাছে আমাদের প্রকাশনাবলি আবৃত্তি করা হয়, সে ঔদ্ধত্যের সাথে মুখ ফিরিয়ে নেয় যেন সে কখনো সেগুলো শুনেনি, যেন তার কান বধির। তাকে এক যন্ত্রণাদায়ক শাস্তির প্রতিশ্রুতি দাও।"],
  "31:8": ["Surely, those who believe and lead a righteous life have deserved the gardens of bliss.","নিশ্চয়, যারা বিশ্বাস করে এবং সৎ জীবন যাপন করে তারা পরম সুখের বাগানগুলোর যোগ্য।"],
  "31:9": ["Eternally they abide therein. This is the truthful promise of Allah. He is the Almighty, Most Wise.","তারা সেখানে চিরকাল বাস করে। এটি আল্লাহর সত্য প্রতিশ্রুতি। তিনি সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "31:10": ["He created the heavens without pillars that you can see. He established on earth stabilizers (mountains) lest it tumbles with you, and He spread on it all kinds of creatures. We send down from the sky water to grow all kinds of beautiful plants.","তিনি আকাশমণ্ডলীকে খুঁটি ছাড়া সৃষ্টি করেছেন যা তোমরা দেখতে পাও। তিনি পৃথিবীতে স্থিতিস্থাপক (পর্বতমালা) স্থাপন করেছেন পাছে এটি তোমাদেরকে নিয়ে উলটে পড়ে, এবং তিনি এর উপর সব রকমের প্রাণী ছড়িয়ে দিয়েছেন। আমরা আকাশ থেকে পানি বর্ষন করি সব রকমের সুন্দর উদ্ভিদ জন্মাতে।"],
  "31:11": ["Such is the creation of Allah; show me what the idols you set up beside Him have created. Indeed, the transgressors are far astray.","এমনই আল্লাহর সৃষ্টি ; আমাকে দেখাও তাঁর পাশে তোমাদের স্থাপন করা উপাস্যরা কি সৃষ্টি করেছে। নিশ্চয়, সীমালঙ্ঘনকারীরা সুদূরে পথভ্রষ্ট।"],
  "31:12": ["We have endowed Luqmãn with wisdom: \"You shall be appreciative of Allah.\" Whoever is appreciative is appreciative for his own good. As for those who turn unappreciative, Allah is in no need, Praiseworthy.","আমরা লুকমানকে প্রজ্ঞা অর্পণ করেছিলাম: \"তুমি আল্লাহর প্রতি কৃতজ্ঞ হবে।” যেকেউ কৃতজ্ঞ সে তার নিজের ভালোর জন্যই কৃতজ্ঞ। আর যারা অকৃতজ্ঞ হয়ে যায়, আল্লাহ অভাবমুক্ত, প্রশংসনীয়।"],
  "31:13": ["Recall that Luqmãn said to his son, as he enlightened him, \"O my son, do not set up any idols beside Allah; idolatry is a gross injustice.\"","স্মরণ করো যে লুকমান তার ছেলেকে বলেছিল, যখন সে তাকে জ্ঞান দিচ্ছিল, “হে আমার পুত্র, আল্লাহর পাশে কোন উপাস্য স্থাপন করো না; শিরক করা একটি ঘোর অবিচার।\""],
  "31:14": ["We enjoined the human being to honor his parents. His mother bore him, and the load got heavier and heavier. It takes two years (of intensive care) until weaning. You shall be appreciative of Me, and of your parents. To Me is the ultimate destiny.","আমরা মানুষকে তার মাতাপিতার সম্মান করতে আদেশ করেছি। তার মা তাকে  গর্ভে ধারন করেছে, আর সেই ভার ভারী থেকে ভারী হয়েছে। দুধ ছাড়ানো অবধি  দু'বছর (নিবিড় পরিচর্যার) প্রয়োজন হয়। তোমরা কৃতজ্ঞ হবে আমার প্রতি, এবং তোমাদের মাতাপিতার প্রতি। আমার কাছেই চূড়ান্ত নিয়তি।"],
  "31:15": ["If they try to force you to set up any idols beside Me, do not obey them. But continue to treat them amicably in this world. You shall follow only the path of those who have submitted to Me. Ultimately, you all return to Me, then I will inform you of everything you have done.","যদি তারা আমার পাশে কোন উপাস্য স্থাপন করতে বল প্রয়োগ করে, তাদেরকে মান্য করো না। কিন্তু এই পৃথিবীতে তাদের সাথে অমায়িক আচরণ করে যাবে। তোমরা শুধু তাদের পথ অনুসরণ করবে যারা আমার কাছে আত্মসমর্পণ করেছে। শেষপর্যন্ত, তোমরা সবাই আমার কাছে ফিরবে, তখন আমি তোমাদের জানাবো যাকিছু তোমরা করেছো।"],
  "31:16": ["\"O my son, know that even something as tiny as a mustard seed, deep inside a rock, be it in the heavens or the earth, Allah will bring it. Allah is Sublime, Cognizant.","\"হে আমার পুত্র, জেনে রাখো যে যদি কোন কিছু একটি সরিষার দানার মতো ছোট-ও হয়, কোন পাথরের গভীরে, তা হোক আকাশমণ্ডলীতে বা পৃথিবীতে, আল্লাহ তা বের করে আনবেন। আল্লাহ মহিমান্বিত, অবগত।"],
  "31:17": ["\"O my son, you shall observe the Contact Prayers (Salat). You shall advocate righteousness and forbid evil, and remain steadfast in the face of adversity. These are the most honorable traits.","\"হে আমার পুত্র, তুমি সংযোগ প্রার্থনা (সালাত) পালন করবে। তুমি সৎকর্মের নির্দেশ দেবে এবং মন্দ কাজে নিষেধ করবে, আর প্রতিকূলতার মুখে দৃঢ় থাকবে। এগুলো সবচেয়ে সম্মানিত বৈশিষ্ট্য।"],
  "31:18": ["\"You shall not treat the people with arrogance, nor shall you roam the earth proudly. Allah does not like the arrogant showoffs.","তুমি লোকদের সাথে উদ্ধত আচরণ করবে না, না তুমি গর্বভরে পৃথিবীতে ঘুড়ে বেড়াবে। আল্লাহ উদ্ধত  লোক-দেখানো মানুষকে পছন্দ করেন না।"],
  "31:19": ["\"Walk humbly and lower your voice—the ugliest voice is the donkey's voice.\"","\"নম্রভাবে হাটো এবং তোমার স্বর নিচু করো-  গাধার স্বরই সবচেয়ে কর্কশ।\""],
  "31:20": ["Do you not see that Allah has committed in your service everything in the heavens and the earth, and has showered you with His blessings— obvious and hidden? Yet, some people argue about Allah without knowledge, without guidance, and without the enlightening scripture.","তোমরা কি দেখ না যে আল্লাহ তোমাদের সেবায়  নিয়োজিত করেছেন আকাশমণ্ডলী ও পৃথিবীর সবকিছুকে, এবং তোমাদের প্রতি বর্ষণ করেছেন  তাঁর প্রকাশ্য ও গোপন অনুগ্রহ? তবুও, কিছু লোক আল্লাহ সম্পর্কে তর্ক করে জ্ঞান ছাড়া, পথনির্দেশনা ছাড়া, এবং জ্ঞানালোকপূর্ণ ঐশীগ্রন্থ ছাড়াই।"],
  "31:21": ["When they are told, \"Follow these revelations of Allah,\" they say, \"No, we follow only what we found our parents doing.\" What if the devil is leading them to the agony of Hell?","যখন তাদেরকে বলা হয়, \"আল্লাহর এইসব প্রকাশনাবলি অনুসরণ করো,”তারা বলে, \"না, আমরা কেবল অনুসরণ করি যা আমাদের পিতামাতাকে করতে দেখেছি।” শয়তান যদি তাদেরকে নরকের তীব্র যন্ত্রণার দিকে পরিচালনা করে থাকে, তবুও কি?"],
  "31:22": ["Those who submit completely to Allah, while leading a righteous life, have gotten hold of the strongest bond. For Allah is in full control of all things.","যারা সম্পূর্ণরূপে আল্লাহর কাছে আত্মসমর্পণ করে, সৎ জীবন যাপন করা অবস্থায়, তারা সবচেয়ে শক্তিশালী বাঁধন আঁকড়ে ধরেছে। কারন আল্লাহ সবকিছুর পূর্ণ নিয়ন্ত্রনে আছেন।"],
  "31:23": ["As for those who disbelieve, do not be saddened by their disbelief. To us is their ultimate return, then we will inform them of everything they had done. Allah is fully aware of the innermost thoughts.","আর যারা অবিশ্বাস করে, তাদের অবিশ্বাসের কারনে দুঃখ পেওনা। আমাদের কাছেই তাদের চূড়ান্ত প্রত্যাবর্তন, তারপর আমরা তাদেরকে সবকিছু জানাবো যা তারা করেছিল। আল্লাহ গভীরতম চিন্তাগুলো সম্পর্কে সম্পূর্ণ অবগত।"],
  "31:24": ["We let them enjoy temporarily, then commit them to severe retribution.","আমরা তাদেরকে সাময়িক ভাবে উপভোগ করতে দেই, এরপর তাদেরকে কঠোর শাস্তিতে পতিত করি।"],
  "31:25": ["If you ask them, \"Who created the heavens and the earth,\" they will say, \"Allah.\" Say, \"Praise be to Allah.\" Yet, most of them do not know.","যদি তুমি তাদেরকে জিজ্ঞেস করো, \"কে আকাশমণ্ডলী ও পৃথিবী সৃষ্টি করেছেন, ” তারা বলবে, \"আল্লাহ।” বল, \"প্রশংসা আল্লাহর।” তবুও, তাদের বেশিরভাগ-ই জানে না।"],
  "31:26": ["To Allah belongs everything in the heavens and the earth. Allah is the Most Rich, Most Praiseworthy.","আকাশমণ্ডলী এবং পৃথিবীর সবকিছু আল্লাহর। আল্লাহ সবচেয়ে ধনী, সবচেয়ে প্রশংসনীয়।"],
  "31:27": ["If all the trees on earth were made into pens, and the ocean supplied the ink, augmented by seven more oceans, the words of Allah would not run out. Allah is Almighty, Most Wise.","যদি পৃথিবীর সকল গাছ দিয়ে কলম বানানো হতো, আর সাগর কালি সরবরাহ করতো, আরো সাত সাগর বাড়িয়ে দিয়ে, তবুও আল্লাহর কথা ফুরিয়ে যেতো না। আল্লাহ সর্বশক্তিমান, সবচেয়ে প্রজ্ঞাময়।"],
  "31:28": ["The creation and resurrection of all of you is the same as that of one person. Allah is Hearer, Seer.","তোমাদের সকলের সৃষ্টি ও পুনরুত্থান এক ব্যক্তির মতোই। আল্লাহ শুনেন, দেখেন।"],
  "31:29": ["Do you not realize that Allah merges the night into the day and merges the day into the night, and that He has committed the sun and the moon in your service, each running in its orbit for a specific life span, and that Allah is fully Cognizant of everything you do?","তোমরা কি অনুধাবন করো না যে আল্লাহ রাতকে দিনের মধ্যে মিলিয়ে দেন ও দিনকে রাতের মধ্যে মিলিয়ে দেন, এবং সূর্য ও চাঁদকে নিয়োজিত করেছেন তোমাদের সেবায়, প্রত্যেকেই নিজ কক্ষপথে একটি নির্দিষ্ট জীবনকালের জন্য চলছে, এবং আল্লাহ পুরোপুরি অবগত সবকিছু সম্পর্কে যা তোমরা করো?"],
  "31:30": ["This proves that Allah is the truth, while any idol they set up beside Him is falsehood, and that Allah is the Most High, Most Great.","এটি প্রমান করে যে আল্লাহ সত্য, যেখানে তাঁর পাশে তারা যে শরীক স্থাপন করে তা মিথ্যা, এবং যে আল্লাহ সর্বোচ্চ, সবচেয়ে মহান।"],
  "31:31": ["Do you not see that the ships roam the sea, carrying Allah's provisions, to show you some of His proofs? Indeed, these should be sufficient proofs for everyone who is steadfast, appreciative.","তুমি কি দেখো না যে জাহাজগুলো সাগরে ঘুড়ে বেড়ায়, আল্লাহর জীবিকা বহন করে, তোমাদেরকে তাঁর কিছু প্রমান দেখাতে? নিশ্চয়ই, এগুলো যথেষ্ট প্রমান হওয়া উচিত সকলের জন্য যারা অবিচল, কৃতজ্ঞ।"],
  "31:32": ["When violent waves surround them, they implore Allah, sincerely devoting their prayers to Him alone. But as soon as He saves them to the shore, some of them revert. None discards our revelations except those who are betrayers, unappreciative.","যখন প্রচন্ড ঢেউ তাদের ঘিরে ফেলে, তারা আল্লাহর কাছে মিনতি করে, তাদের প্রার্থনা কেবল তাঁর প্রতি আন্তরিকভাবে উৎসর্গ করে। কিন্তু যখনই তিনি তাদেরকে তীরে এনে উদ্ধার করেন, তাদের কেউ কেউ আগের অবস্থায় ফিরে যায়। কেউই আমাদের প্রকাশনাবলি অগ্রাহ্য করে না তারা ছাড়া যারা বিশ্বাসঘাতক, অকৃতজ্ঞ।"],
  "31:33": ["O people, you shall reverence your Lord, and fear a day when a father cannot help his own child, nor a child can help his father. Certainly, Allah's promise is truth. Therefore, do not be distracted by this life; do not be distracted from Allah by mere illusions.","হে লোকেরা, তোমরা তোমাদের প্রভুকে ভক্তি করবে, আর ভয় করো এমন এক দিনকে যখন কোন পিতা তার নিজ সন্তানকে সাহায্য করতে পারবে না, না কোন সন্তান তার পিতাকে সাহায্য করতে পারবে। অবশ্যই, আল্লাহর প্রতিশ্রুতি সত্য। একারনে, এই জীবন দ্বারা বিভ্রান্ত হইও না; আল্লাহ থেকে নিছক মোহের দ্বারা বিভ্রান্ত হইও না।"],
  "31:34": ["With Allah is the knowledge regarding the Hour (end of the world). He is the One who sends down the rain, and He knows the contents of the womb. No soul knows what will happen to it tomorrow, and no one knows in which land he or she will die. Allah is Omniscient, Cognizant.","আল্লাহর কাছে আছে সে ঘন্টা (বিশ্বের পরিসমাপ্তি) সম্পর্কিত জ্ঞান। তিনিই সে সত্ত্বা যিনি বৃষ্টি অবতীর্ণ করেন, এবং তিনি জানেন জরায়ুস্থ বস্তু সম্পর্কে। কোন আত্মা জানে না আগামীকাল তার সাথে কি ঘটবে, এবং কোন ব্যক্তি জানে না কোন স্থানে সে মারা যাবে। আল্লাহ সর্বজ্ঞ, অবগত।"],
  "32:1": ["A. L. M.","অ. ল. ম."],
  "32:2": ["The book is, without a doubt, a revelation from the Lord of the universe.","গ্রন্থটি, কোন সন্দেহ ছাড়াই, এক প্রত্যাদেশ  মহাবিশ্বের প্রভুর পক্ষ থেকে।"],
  "32:3": ["They said, \"He fabricated it.\" Indeed, this is the truth from your Lord, to warn people who never received a warner before you, that they may be guided.","তারা বলল, \"সে এটি বানিয়েছে।” নিশ্চয়ই, এটি তোমার প্রভুর পক্ষ থেকে সত্য, সেসব লোকদের সতর্ক করতে যারা তোমার আগে কখনো কোন সতর্ককারী পায়নি, যাতে তারা সুপথপ্রাপ্ত হতে পারে।"],
  "32:4": ["Allah is the One who created the heavens and the earth, and everything between them in six days, then assumed all authority. You have none beside Him as Lord, nor do you have an intercessor. Would you not take heed?","আল্লাহই সে সত্ত্বা যিনি সৃষ্টি করেছেন আকাশমন্ডলী ও পৃথিবী, এবং এদের মধ্যকার সবকিছু ছয় দিনে, এরপর সকল কর্তৃত্ব গ্রহন করেছেন। তাঁর পাশে প্রভু হিসেবে তোমাদের কেউ নেই, না তোমাদের কোন সুপারিশকারী আছে। তোমরা কি মনোযোগ দেবে না?"],
  "32:5": ["All matters are controlled by Him from the heaven to the earth. To Him, the day is equivalent to one thousand of your years.","আকাশ থেকে পৃথিবী পর্যন্ত সকল বিষয় তাঁর দ্বারা নিয়ন্ত্রিত। তাঁর কাছে দিনটি তোমাদের এক হাজার বছরের সমান।"],
  "32:6": ["Knower of all secrets and declarations; the Almighty, Most Merciful.","সকল গোপন ও প্রকাশ্য বিষয়ের জ্ঞাতা; সর্বশক্তিমান, সবচেয়ে দয়ালু।"],
  "32:7": ["He is the One who perfected everything He created, and started the creation of the human from clay.","তিনি সে সত্ত্বা যিনি নিখুঁত করেছেন সবকিছুকে যা তিনি সৃষ্টি করেছেন, আর মানুষের সৃষ্টি শুরু করেছেন কাঁদা থেকে।"],
  "32:8": ["Then He continued his reproduction through a certain lowly liquid.","তারপর তিনি একটি নির্দিষ্ট নীচুস্তরের তরলের মাধ্যমে তার প্রজনন অব্যাহত রাখেন।"],
  "32:9": ["He shaped him and blew into him from His spirit. And He gave you the hearing, the eyesight, and the brains; rarely are you thankful.","তিনি তাকে আকার দিলেন এবং তার মধ্যে তাঁর রুহ থেকে ফুঁকে দিলেন। আর তিনি তোমাদেরকে দিয়েছেন শ্রবণশক্তি, দৃষ্টিশক্তি, এবং মস্তিষ্ক ; তোমরা খুব কমই কৃতজ্ঞ।"],
  "32:10": ["They wonder, \"After we vanish into the earth, do we get created anew?\" Thus, as regards meeting their Lord, they are disbelievers.","তারা অবাক হয়, \"আমরা মাটিতে মিশে যাবার পর, আমরা কি আবার নতুন করে সৃষ্টি হবো?”এভাবে, তাদের প্রভুর সাথে সাক্ষাতের ব্যাপারে, তারা অবিশ্বাসী।"],
  "32:11": ["Say, \"You will be put to death by the angel in whose charge you are placed, then to your Lord you will be returned.\"","বল, \"তোমাদের মৃত্যু হবে ফেরেশতার মাধ্যমে যার দায়িত্বে তোমাদের রাখা হয়েছে, এরপর তোমাদের প্রভুর কাছে তোমরা ফিরে যাবে।\""],
  "32:12": ["If only you could see the guilty when they bow down their heads before their Lord: \"Our Lord, now we have seen and we have heard. Send us back and we will be righteous. Now we have attained certainty.\"","যদি শুধু তুমি অপরাধীদের দেখতে পারতে যখন তারা তাদের প্রভুর সামনে মাথা নোয়ায়ঃ \"আমাদের প্রভু, এখন আমরা দেখেছি এবং আমরা শুনেছি। আমাদের ফেরত পাঠান এবং আমরা সৎকর্মশীল হবো। আমরা এখন নিশ্চয়তা অর্জন করেছি।\""],
  "32:13": ["Had we willed, we could have given every soul its guidance, but it is already predetermined that I will fill Hell with jinns and humans, all together.","আমরা যদি চাইতাম, প্রত্যেক আত্মাকে আমরা তার পথনির্দেশনা দিতে পারতাম, কিন্তু এটা ইতোমধ্যেই পূর্বনির্ধারিত যে আমি জ্বীন ও মানুষ দিয়ে নরক পূর্ণ করবো, সবাইকে একসাথে।"],
  "32:14": ["Taste the consequences of your forgetting this day; now we forget you. You have incurred eternal retribution in return for your own works.","এই দিনটিকে তোমাদের ভুলে যাওয়ার পরিনাম ভোগ করো; এখন আমরা তোমাদের ভুলে গেলাম। তোমরা তোমাদের নিজেদের কাজের বদলে চিরস্থায়ী শাস্তি টেনে এনেছ।"],
  "32:15": ["The only people who truly believe in our revelations are those who fall prostrate upon hearing them. They glorify and praise their Lord, without any arrogance.","আমাদের প্রকাশনাবলিতে সত্যিকার অর্থে কেবল সে লোকেরা বিশ্বাস করে যারা তা শুনামাত্র সেজদায় পতিত হয়। তারা তাদের প্রভুর গুণকীর্তন এবং প্রশংসা করে, কোন ঔদ্ধত্যতা ছাড়া।"],
  "32:16": ["Their sides readily forsake their beds, in order to worship their Lord, out of reverence and hope, and from our provisions to them, they give.","তাদের পার্শ্ব নির্দ্বিধায় শয্যা ত্যাগ করে, তাদের প্রভুর উপাসনা করার জন্য, ভক্তি ও আশা থেকে, আর আমাদের জীবিকা থেকে তারা দেয়।"],
  "32:17": ["You have no idea how much joy and happiness are waiting for you as a reward for your (righteous) works.","তোমাদের কোন ধারণা নেই তোমাদের (সৎ) কাজের জন্য পুরষ্কার হিসেবে কী পরিমান আনন্দ ও সুখ তোমাদের জন্য অপেক্ষা করছে।"],
  "32:18": ["Is one who is a believer the same as one who is wicked? They are not equal.","যে ব্যক্তি একজন বিশ্বাসী সে কি ঐ ব্যক্তির মতো যে অন্যায়কারী? তারা সমান নয়।"],
  "32:19": ["As for those who believe and lead a righteous life, they have deserved the eternal Paradise. Such is their abode, in return for their works.","আর তাদের জন্য যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে, তারা যোগ্য হয়েছে চিরস্থায়ী স্বর্গের। এমনই তাদের আবাস, তাদের কাজের বদলায়।"],
  "32:20": ["As for the wicked, their destiny is Hell. Every time they try to leave it, they will be forced back. They will be told, \"Taste the agony of Hell which you used to disbelieve in.\"","আর অন্যায়কারীদের জন্য, তাদের নিয়তি নরক। প্রতিবার তারা এর থেকে বের হবার চেষ্টা করলে, তাদেরকে জোড়পূর্বক ফিরিয়ে দেয়া হবে। তাদেরকে বলা হবে, \"নরকের যন্ত্রনা আস্বাদন করো যাতে তোমরা অবিশ্বাস করতে।\""],
  "32:21": ["We let them taste the smaller retribution (of this world), before they incur the greater retribution (of the Hereafter), that they may (take a hint and) reform.","আমরা তাদেরকে (এই দুনিয়ায়) ছোট শাস্তি ভোগ করাই, তারা (পরকালের) বড় শাস্তি টেনে আনার আগে, যাতে তারা (একটি পূর্বাভাষ পায় এবং) সংশোধিত হতে পারে।"],
  "32:22": ["Who is more evil than one who is reminded of these revelations of his Lord, then insists upon disregarding them? We will certainly punish the guilty.","কে অধিক মন্দ সে ব্যক্তির চেয়ে যাকে তার প্রভুর এই প্রকাশনাবলি স্মরণ করিয়ে দেয়া হয়, এরপর সেগুলোকে উপেক্ষাই করতে থাকে? আমরা নিশ্চয় অপরাধীকে শাস্তি দিবো।"],
  "32:23": ["We have given Moses the scripture—do not harbor any doubt about meeting Him—and we made it a guide for the Children of Israel.","আমরা মূসাকে ঐশীগ্রন্থ দিয়েছি- তাঁর সাথে সাক্ষাতের ব্যাপারে কোন সন্দেহ করো না- এবং একে আমরা ইসরাইলের সন্তানদের জন্য একটি পথপ্রদর্শক করেছিলাম।"],
  "32:24": ["We appointed from among them imams who guided in accordance with our commandments, because they steadfastly persevered and attained certainty about our revelations.","আমরা তাদের মধ্য থেকে ইমাম নিযুক্ত করেছিলাম যারা আমাদের প্রত্যাদেশ অনুসারে পথ প্রদর্শন করতো, কারন তারা ছিল দৃঢ়তার সাথে অবিচল এবং নিশ্চয়তা অর্জন করেছিল আমাদের প্রকাশনাবলি সম্পর্কে।"],
  "32:25": ["Your Lord is the One who will judge them on the Day of Resurrection, regarding everything they disputed.","তোমাদের প্রভু সে সত্ত্বা যিনি পুনরুত্থান দিবসে তাদের বিচার করবেন, তাদের বিবাদ করা সবকিছুর ব্যাপারে।"],
  "32:26": ["Does it ever occur to them how many generations we have annihilated before them? They now live and walk in their ancestors' homes. This should provide sufficient proofs. Do they not hear?","তারা কি কখনো এটা উপলব্ধি করে যে তাদের আগে আমরা কত প্রজন্মকে ধ্বংস করেছি?  তারা এখন  বাস করে এবং চলাফেরা করে তাদের পূর্বপুরুষদের বাড়ি-ঘরে। এটি যথেষ্ট প্রমান হওয়া উচিত। তারা কি শুনে না?"],
  "32:27": ["Do they not realize that we drive the water to barren lands, and produce with it crops to feed their livestock, as well as themselves? Do they not see?","তারা কি অনুধাবন করে না যে আমরা অনুর্বর জমিতে পানি প্রবাহিত করি, এবং তা দিয়ে ফসল উৎপাদন করি তাদের পশু সম্পদ খাওয়াতে, সেই সাথে তাদেরকেও? তারা কি দেখে না?"],
  "32:28": ["They challenge: \"Where is that victory, if you are truthful?\"","তারা চ্যালেঞ্জ করে, \"কোথায় সেই বিজয়, যদি তোমরা সত্যবাদী হও?\""],
  "32:29": ["Say, \"The day such a victory comes, believing will not benefit those who did not believe before that, nor will they be given another chance.\"","বল, \"যেদিন এমন বিজয় আসবে, বিশ্বাস করা তাদের উপকারে আসবে না যারা তার আগে বিশ্বাস করেনি, না তাদেরকে আরেকবার সুযোগ দেয়া হবে।\""],
  "32:30": ["Therefore, disregard them and wait, they too are waiting.","অতএব, তাদের উপেক্ষা করো এবং অপেক্ষা করো, তারাও অপেক্ষা করছে।"],
  "33:1": ["O you prophet, you shall reverence Allah and do not obey the disbelievers and the hypocrites. Allah is Omniscient, Most Wise.","হে নবী, তুমি আল্লাহকে ভক্তি করবে এবং অবিশ্বাসী ও ভন্ডদের মান্য করবে না। আল্লাহ সর্বজ্ঞ, সবচেয়ে প্রজ্ঞাময়।"],
  "33:2": ["Follow what is revealed to you from your Lord. Allah is fully Cognizant of everything you all do.","অনুসরণ করো তোমার প্রভুর পক্ষ থেকে তোমার কাছে যা প্রকাশ করা হয়েছে। তোমরা সকলে যা করো তার সবকিছু সম্পর্কে আল্লাহ সম্পূর্ণ অবগত।"],
  "33:3": ["And put your trust in Allah. Allah suffices as an advocate.","আর আল্লাহর উপর তোমার আস্থা রাখো। সমর্থক হিসেবে আল্লাহ যথেষ্ট।"],
  "33:4": ["Allah did not give any man two hearts in his chest. Nor did He turn your wives whom you estrange (according to your custom) into your mothers. Nor did He turn your adopted children into genetic offspring. All these are mere utterances that you have invented. Allah speaks the truth, and He guides in the (right) path.","আল্লাহ কোন মানুষের বুকে দু'টি হৃদয় দেননি। না তিনি মা'তে পরিনত করেন তোমাদের স্ত্রীদেরকে, যাদেরকে তোমরা (তোমাদের প্রথা অনুসারে) আলাদা করো। না তিনি তোমাদের পালিত সন্তানকে বংশগত সন্তানে পরিনত করেন। এগুলো তো মুখের কথা মাত্র যা তোমরা উদ্ভাবন করেছো। আল্লাহ সত্য বলেন, এবং তিনি (সঠিক) পথ দেখান।"],
  "33:5": ["You shall give your adopted children names that preserve their relationship to their genetic parents. This is more equitable in the sight of Allah. If you do not know their parents, then, as your brethren in religion, you shall treat them as members of your family. You do not commit a sin if you make a mistake in this respect; you are responsible for your purposeful intentions. Allah is Forgiver, Most Merciful.","তোমরা তোমাদের পালিত সন্তানদের নাম দিবে যা তাদের বংশগত মাতাপিতার সাথে তাদের সম্পর্ক রক্ষা করে। এটা আল্লাহর দৃষ্টিতে অধিক ন্যায়সঙ্গত। যদি তোমরা তাদের মাতাপিতাকে না জানো, তাহলে, তোমাদের ধর্মের ভাই-বোন হিসেবে, তোমরা তাদেরকে তোমাদের পরিবারের  সদস্য হিসেবে গন্য করবে। তোমরা কোন পাপ করো না এইক্ষেত্রে যদি তোমরা ভুল করে ফেলো; তোমরা তোমাদের উদ্দেশ্যমূলক অভিপ্রায়ের জন্য দায়ী। আল্লাহ ক্ষমাকারী, পরম দয়ালু।"],
  "33:6": ["The prophet is closer to the believers than they are to each other, and his wives are like mothers to them. The relatives ought to take care of one another in accordance with Allah's scripture. Thus, the believers shall take care of their relatives who immigrate to them, provided they have taken care of their own families first. These are commandments of this scripture.","তাদের একে অন্যের চেয়ে নবী বিশ্বাসীদের নিকটতর, আর তাদের কাছে তার স্ত্রীরা মায়ের মতন।  আল্লাহর ঐশীগ্রন্থ অনুসারে আত্মীয়দের উচিত একে অন্যের দেখ-ভাল করা। এভাবে, বিশ্বাসীরা দেখভাল করবে তাদের আত্মীয়দের যারা দেশান্তরিত হয়ে তাদের কাছে এসেছে, তবে আগে তাদের নিজ পরিবারের দেখভাল করবে। এগুলো এই ঐশীগ্রন্থের প্রত্যাদেশাবলি।"],
  "33:7": ["Recall that we took from the prophets their covenant, including you (O Muhammad), Noah, Abraham, Moses, and Jesus the son of Mary. We took from them a solemn pledge.","স্মরণ করো যে আমরা নবীদের থেকে তাদের অঙ্গীকার নিয়েছিলাম, তোমাকে সহ (হে মুহাম্মদ), নূহ, ইব্রাহিম, মূসা, এবং মরিয়মের পূত্র ঈসা থেকেও। আমরা তাদের থেকে একটি  গুরুত্বপূর্ণ অঙ্গীকার নিয়েছিলাম।"],
  "33:8": ["Subsequently, He will surely question the truthful about their truthfulness, and has prepared for the disbelievers (in this Quranic fact) a painful retribution.","পরবর্তীতে, তিনি অবশ্যই সত্যবাদীদের প্রশ্ন করবেন তাদের সত্যবাদীতা সম্পর্কে, এবং অবিশ্বাসীদের জন্য প্রস্তুত করেছেন (এই কুরআনীয় ঘটনার বিষয়ে) এক যন্ত্রণাকর শাস্তি।"],
  "33:9": ["O you who believe, remember Allah's blessing upon you; when soldiers attacked you, we sent upon them violent wind and invisible soldiers. Allah is Seer of everything you do.","হে বিশ্বাসীরা, তোমাদের উপর আল্লাহর অনুগ্রহ স্মরণ কর।যখন সৈন্যরা তোমাদের আক্রমণ করেছিলো, আমরা তাদের উপর পাঠিয়েছিলাম ঝড়ো বাতাস এবং অদৃশ্য সৈন্য। আল্লাহ সবকিছু দেখেন যা তোমরা করো।"],
  "33:10": ["When they came from above you, and from beneath you, your eyes were terrified, your hearts ran out of patience, and you harbored unbefitting thoughts about Allah.","যখন তারা এসেছিল তোমাদের উপর থেকে, এবং তোমাদের নিচ থেকে, তোমাদের চোখ আতংকিত হয়েছিল, তোমাদের হৃদয়ে ধৈর্য্য ফুরিয়ে গিয়েছিলো, এবং তোমরা আল্লাহ সম্পর্কে বেমানান ধারনা পোষন করছিলে।"],
  "33:11": ["That is when the believers were truly tested; they were severely shaken up.","ঠিক তখনই বিশ্বাসীদের সত্যিকারভাবে পরীক্ষা করা হয়েছিল;  তারা প্রচন্ড ভাবে কম্পিত হয়েছিল।"],
  "33:12": ["The hypocrites and those with doubts in their hearts said, \"What Allah and His messenger promised us was no more than an illusion!\"","ভন্ডরা ও যাদের হৃদয়ে সন্দেহ ছিল তারা বলল, \"আল্লাহ ও তাঁর বার্তাবাহক আমাদেরকে যে প্রতিশ্রুতি দিয়েছেন তা এক মোহের চেয়ে বেশি কিছু নয়।"],
  "33:13": ["A group of them said, \"O people of Yathrib, you cannot attain victory; go back.\" Others made up excuses to the prophet: \"Our homes are vulnerable,\" when they were not vulnerable. They just wanted to flee.","তাদের এক দল বলল, \"হে ইয়াসরেবের (মদিনার) লোকেরা, তোমরা বিজয় অর্জন করতে পারবে না; ফিরে যাও।” বাকীরা নবীর কাছে অজুহাত দাঁড় করালোঃ \"আমাদের ঘর অরক্ষিত, “যখন সেগুলো অরক্ষিত ছিল না। তারা কেবল পালাতে চেয়েছিল।"],
  "33:14": ["Had the enemy invaded and asked them to join, they would have joined the enemy without hesitation.","যদি শত্রুরা হামলা করতো এবং তাদের যোগ দিতে বলতো, তারা নির্দ্বিধায় শত্রুদের সাথে যোগ দিতো।"],
  "33:15": ["They had pledged to Allah in the past that they would not turn around and flee; making a pledge with Allah involves a great responsibility.","তারা অতীতে আল্লাহর কাছে অঙ্গীকার করেছিল যে তারা পিছু হটে পালিয়ে যাবে না; আল্লাহর সাথে অঙ্গীকার করলে এক  মহা দায়িত্ব বর্তায়।"],
  "33:16": ["Say, \"If you flee, you can never flee from death or from being killed. No matter what happens, you only live a short while longer.\"","বল, \"যদি তোমরা পালাও, তোমরা কখনো পালাতে পারবে না মৃত্যু থেকে অথবা হত্যা হওয়া থেকে। যাই ঘটুক না কেন, তোমরা শুধু কিছুকাল বেশি বাঁচো। \""],
  "33:17": ["Say, \"Who would protect you from Allah if He willed any adversity, or willed any blessing for you?\" They can never find, beside Allah, any other Lord and Master.","বল, \"কে তোমাদেরকে আল্লাহ থেকে বাচাঁবে যদি তিনি তোমাদের জন্য কোন দূর্ভোগ চান, অথবা কোন অনুগ্রহ চান তোমাদের জন্য?” তারা কখনো পাবে না, আল্লাহর পাশে, অন্য কোন প্রভু ও মনিব।"],
  "33:18": ["Allah is fully aware of the hinderers among you, and those who say to their comrades, \"Let us all stay behind.\" Rarely do they mobilize for defense.","আল্লাহ পুরোপুরি অবগত তোমাদের মধ্যকার বিঘ্ন সৃষ্টিকারীদের বিষয়ে, এবং যারা তাদের সহযোদ্ধাদের বলে, \"চল আমরা সবাই পিছনে থাকি।” তারা খুব কমই প্রতিরক্ষার জন্য একত্রিত হয়।"],
  "33:19": ["Also, they are too stingy when dealing with you. If anything threatens the community, you see their eyes rolling with fear, as if death had already come to them. Once the crisis is over, they whip you with sharp tongues. They are too stingy with their wealth. These are not believers, and, consequently, Allah has nullified their works. This is easy for Allah to do.","এছাড়া, তারা তোমার সাথে আচরনে খুবই কৃপণ। যদি কোনকিছু সম্প্রদায়কে হুমকি দেয়, তুমি দেখ যে ভয়ে তাদের চোখ টলমল করে, যেন মৃত্যু তাদের কাছে এসেই পড়লো। একবার সংকট কেটে গেলে, তারা তোমাকে কষাঘাত করে তীক্ষ্ণ কথা দিয়ে। তারা তাদের সম্পদ নিয়েও খুব কৃপণ। এরা বিশ্বাসী নয়, আর, পরিনামে, আল্লাহ তাদের কাজকে নিষ্ফল করে দিয়েছেন। এটা করা আল্লাহর জন্য সহজ।"],
  "33:20": ["They thought that the parties might come back. In that case, they would wish that they were lost in the desert, asking about your news from afar. Had the parties attacked you while they were with you, they would rarely support you.","তারা ভেবেছিল হয়তো দলগুলো ফিরে আসতে পারে। সেক্ষেত্রে, তারা চাইতো যে  যদি তারা মরুভূমিতে হারিয়ে গিয়ে, দূর থেকে তোমাদের খবরাখবর নিতো। যদি তোমাদের সাথে তারা থাকাকালে দলগুলো তোমাদেরকে আক্রমণ করতো, তারা খুব কমই তোমাদের সহায়তা করতো।"],
  "33:21": ["The messenger of Allah has set up a good example for those among you who seek Allah and the Last Day, and constantly think about Allah.","তোমাদের মধ্যে তাদের জন্য আল্লাহর বার্তাবাহক একটি ভাল উদাহরণ স্থাপন করেছেন যারা আল্লাহ ও শেষ দিনের অন্বেষণ করে, এবং প্রতিনিয়ত আল্লাহর বিষয়ে চিন্তা করে।"],
  "33:22": ["When the true believers saw the parties (ready to attack), they said, \"This is what Allah and His messenger have promised us, and Allah and His messenger are truthful.\" This (dangerous situation) only strengthened their faith and augmented their submission.","যখন সত্যিকার বিশ্বাসীরা দলগুলোকে দেখলো (আক্রমণ করতে প্রস্তুত), তারা বলল, \"এর প্রতিজ্ঞাই আল্লাহ ও তাঁর বার্তাবাহক আমাদেরকে করেছিলেন, আর আল্লাহ ও তাঁর বার্তাবাহক সত্যবাদী।”এই (বিপজ্জনক পরিস্থিতি) কেবল তাদের বিশ্বাসকে শক্তিশালী করেছিল এবং তাদের আত্মসমর্পণ বাড়িয়ে দিয়েছিল।"],
  "33:23": ["Among the believers there are people who fulfill their pledges with Allah. Some of them died, while others stand ready, never wavering.","বিশ্বাসীদের মধ্যে সে সব লোকেরা রয়েছে যারা আল্লাহর সাথে তাদের অঙ্গীকার পরিপূর্ণ করে। তাদের কেউ কেউ মারা যায়, যখন অন্যরা প্রস্তুত হয়ে থাকে, কখনো দ্বিধান্বিত না হয়ে।"],
  "33:24": ["Allah will surely recompense the truthful for their truthfulness, and will punish the hypocrites, if He so wills, or redeem them. Allah is Forgiver, Most Merciful.","আল্লাহ অবশ্যই সত্যবাদীদের প্রতিদান দেবেন তাদের সত্যবাদিতার জন্য, এবং ভণ্ডদের শাস্তি দেবেন, যদি তিনি এমনই চান, অথবা পাপমুক্ত করবেন। আল্লাহ ক্ষমাশীল, পরম দয়ালু।"],
  "33:25": ["Allah repulsed those who disbelieved with their rage, and they left empty handed. Allah thus spared the believers any fighting. Allah is Powerful, Almighty.","যারা অবিশ্বাস করেছে আল্লাহ তাদেরকে পিছু হটতে বাধ্য করেছেন তাদের ক্রোধ নিয়ে, এবং তারা খালি হাতে ফিরেছে। আল্লাহ এভাবে কোন যুদ্ধ থেকে বিশ্বাসীদের নিষ্কৃতি দেন। আল্লাহ ক্ষমতাবান, সর্বশক্তিমান।"],
  "33:26": ["He also brought down their allies among the people of the scripture from their secure positions, and threw terror into their hearts. Some of them you killed, and some you took captive.","নিরাপদ অবস্থান থেকে নামিয়ে দিয়েছিলেন, এবং তাদের হৃদয়ে আতংক ছুঁড়ে দিয়েছিলেন। তাদের কতককে তোমরা হত্যা করেছো, আর কতককে বন্দী করেছো।"],
  "33:27": ["He made you inherit their land, their homes, their money, and lands you had never stepped on. Allah is in full control of all things.","তিনি তোমাদেরকে উত্তরাধিকারি হতে দিয়েছেন তাদের ভূমি, তাদের বাড়ি-ঘর, তাদের অর্থ, এবং সেসব ভূমি যাতে তোমরা কখনো পা রাখোনি। আল্লাহ সবকিছুর পূর্ণ নিয়ন্ত্রনে আছেন।"],
  "33:28": ["O prophet, say to your wives, \"If you are seeking this life and its vanities, then let me compensate you and allow you to go amicably.","হে নবী, তোমার স্ত্রীদের বল, \"যদি তোমরা এই জীবন এবং এর তুচ্ছ বিষয়াদির অন্বেষণ করো, তাহলে চলো আমি তোমাদের ক্ষতিপূরণ দিয়ে দেই এবং তোমাদেরকে আপসে চলে যেতে দেই।"],
  "33:29": ["\"But if you are seeking Allah and His messenger, and the abode of the Hereafter, then Allah has prepared for the righteous among you a great recompense.\"","\"কিন্তু যদি তোমরা অন্বেষণ করো আল্লাহ ও তাঁর বার্তাবাহককে, এবং পরকালের আবাস, তাহলে তোমাদের মধ্যকার সৎকর্মশীলদের জন্য আল্লাহ প্রস্তুত রেখেছেন এক মহা প্রতিদান।\""],
  "33:30": ["O wives of the prophet, if any of you commits a gross sin, the retribution will be doubled for her. This is easy for Allah to do.","হে নবীর স্ত্রীরা, যদি তোমাদের কেউ গুরুতর অপরাধ করো, শাস্তি তার জন্য দ্বিগুন হবে। এটি আল্লাহর জন্য করা সহজ।"],
  "33:31": ["Any one of you who obeys Allah and His messenger, and leads a righteous life, we will grant her double the recompense, and we have prepared for her a generous provision.","তোমাদের যেকেউ আল্লাহ ও তাঁর বার্তাবাহককে অনুসরণ করে, এবং সৎ জীবন-যাপন করে, আমরা তাকে দিবো দ্বিগুন প্রতিদান, এবং আমরা তার জন্য প্রস্তুত রেখেছি এক উদার জীবিকা।"],
  "33:32": ["O wives of the prophet, you are not the same as any other women, if you observe righteousness. (You have a greater responsibility.) Therefore, you shall not speak too softly, lest those with disease in their hearts may get the wrong ideas; you shall speak only righteousness.","হে নবীর স্ত্রীরা, তোমরা অন্য কোন নারীর মতো নও, যদি তোমরা সৎকর্মশীলতা পালন করো। (তোমাদের অধিকতর দায়িত্ব আছে।) অতএব, তোমরা খুব কোমলভাবে কথা বলবে না, পাছে যাদের হৃদয়ে রোগ আছে তারা ভুল ধারনা পেতে পারে; তোমরা শুধু ন্যায়সঙ্গত কথা বলবে।"],
  "33:33": ["You shall settle down in your homes, and do not mingle with the people excessively, like you used to do in the old days of ignorance. You shall observe the Contact Prayers (Salat), and give the obligatory charity (Zakat), and obey Allah and His messenger. Allah wishes to remove all unholiness from you, O you who live around the Sacred Shrine, and to purify you completely.","তোমরা তোমাদের ঘরে থাকবে,এবং লোকদের সাথে খুব বেশি মেলামেশা করবে না, যেমন তোমরা পুরনো অজ্ঞতার দিনগুলোতে করতে। তোমরা সংযোগ প্রার্থনা (সালাত) পালন করবে, এবং বাধ্যতামূলক দান (যাকাত) দিবে, এবং আল্লাহ ও তাঁর বার্তাবাহককে মান্য করবে। আল্লাহ তোমাদের থেকে সকল অপবিত্রতা দূর করতে চান, হে তোমরা যারা পবিত্র ঘরের চতুর্দিকে বাস করো, এবং চান তোমাদের পরিপূর্ণ পরিশুদ্ধ করতে।"],
  "33:34": ["Remember what is being recited in your homes of Allah's revelations and the wisdom inherent therein. Allah is Sublime, Cognizant.","স্মরণ রাখো তোমাদের ঘরে যা আবৃতি করা হয় আল্লাহর প্রকাশনাবলির এবং এর মধ্যে  বিদ্যমান প্রজ্ঞা। আল্লাহ মহিমান্বিত, অবগত।"],
  "33:35": ["The submitting men, the submitting women, the believing men, the believing women, the obedient men, the obedient women, the truthful men, the truthful women, the steadfast men, the steadfast women, the reverent men, the reverent women, the charitable men, the charitable women, the fasting men, the fasting women, the chaste men, the chaste women, and the men who commemorate Allah frequently, and the commemorating women; Allah has prepared for them forgiveness and a great recompense.","আত্মসমর্পণকারী পুরুষ, আত্মসমর্পণকারী নারী, বিশ্বাসী পুরুষ, বিশ্বাসী নারী, অনুগত পুরুষ, অনুগত নারী, সত্যবাদী পুরুষ, সত্যবাদী নারী, অবিচল পুরুষ, অবিচল নারী, ভক্তি-শ্রদ্ধাকারী  পুরুষ, ভক্তি-শ্রদ্ধাকারী  নারী, দানশীল পুরুষ, দানশীল নারী, রোজাদার পুরুষ, রোজাদার নারী, চরিত্রবান পুরুষ, চরিত্রবান নারী, এবং পুরুষ যে অহরহ আল্লাহকে স্মরণ করে, এবং স্মরণকারী নারী; আল্লাহ তাদের জন্য প্রস্তুত রেখেছেন ক্ষমা এবং এক মহা প্রতিদান।"],
  "33:36": ["No believing man or believing woman, if Allah and His messenger issue any command, has any choice regarding that command. Anyone who disobeys Allah and His messenger has gone far astray.","যদি আল্লাহ ও তাঁর বার্তাবাহক কোন আদেশ দেন তবে ঐ আদেশের ব্যাপারে, কোন বিশ্বাসী পুরুষ অথবা বিশ্বাসী নারীর কোন পছন্দ নেই। যেকেউ আল্লাহ ও তাঁর বার্তাবাহকের অবাধ্য হয়, সে বহুদূরে পথভ্রষ্ট হয়েছে।"],
  "33:37": ["Recall that you said to the one who was blessed by Allah, and blessed by you, \"Keep your wife and reverence Allah,\" and you hid inside yourself what Allah wished to proclaim. Thus, you feared the people, when you were supposed to fear only Allah. When Zeid was completely through with his wife, we had you marry her, in order to establish the precedent that a man can marry the divorced wife of his adopted son. Allah's commands shall be done.","স্মরণ করো যে তুমি সে ব্যক্তিকে বলেছিলে যে আল্লাহর অনুগ্রহপ্রাপ্ত ছিল, এবং তোমার অনুগ্রহপ্রাপ্ত ছিল, \"তোমার স্ত্রীকে থাকতে দাও এবং আল্লাহকে ভক্তি করো,” আর তুমি তোমার নিজের ভিতর লুকাচ্ছিলে যা আল্লাহ ঘোষনা করতে চেয়েছিলেন। এভাবে, তুমি লোকদের ভয় করেছিলে, যখন তোমার কাছে কেবল আল্লাহকে ভয় করাই প্রত্যাশিত ছিল। যখন জায়েদ তার স্ত্রীর প্রতি পুরোপুরি আগ্রহ হারিয়েছিল, আমরা তাকে তোমার সাথে বিয়ে করালাম,  উদাহরণ স্থাপন করতে যে কোন পুরুষ তার পালিত পুত্রের তালাকপ্রাপ্তা স্ত্রীকে বিয়ে করতে পারে। আল্লাহর আদেশ পরিপূর্ণ হবেই।"],
  "33:38": ["The prophet is not committing an error by doing anything that is made lawful by Allah. Such is Allah's system since the early generations. Allah's command is a sacred duty.","নবী কোন ভুল করছে না কোনকিছু করে যা আল্লাহর দ্বারা আইনসম্মত করা হয়েছে। এমনই আল্লাহর পদ্ধতি প্রারম্ভিক প্রজন্মগুলো থেকে। আল্লাহর আদেশ একটি পবিত্র দায়িত্ব।"],
  "33:39": ["Those who deliver Allah's messages, and who reverence Him alone, shall never fear anyone but Allah. Allah is the most efficient reckoner.","যারা আল্লাহর বার্তা পৌঁছে দেয়, এবং যারা একমাত্র তাঁর ভক্তি করে, তারা কখনো আল্লাহ ছাড়া কাউকে ভয় করবে না। আল্লাহ সবচেয়ে দক্ষ হিসাব গ্রহণকারী।"],
  "33:40": ["Muhammad was not the father of any man among you. He was a messenger of Allah and the final prophet. Allah is fully aware of all things.","মুহাম্মদ তোমাদের মধ্যে কোন পুরুষের পিতা ছিল না। সে ছিল আল্লাহর একজন বার্তাবাহক এবং শেষ নবী। আল্লাহ সবকিছু সম্পর্কে সম্পূর্ণ অবগত।"],
  "33:41": ["O you who believe, you shall remember Allah frequently.","হে বিশ্বাসীরা, তোমরা আল্লাহকে বেশি বেশি স্মরণ করো।"],
  "33:42": ["You shall glorify Him day and night.","তোমরা দিন  রাত তাঁর মহিমা প্রকাশ করবে।"],
  "33:43": ["He is the One who helps you, together with His angels, to lead you out of darkness into the light. He is Most Merciful towards the believers.","তিনিই সে সত্ত্বা যিনি তোমাদের সাহায্য করেন, তাঁর ফেরেশতাদের সাথে, তোমাদেরকে অন্ধকার থেকে আলোয় পরিচালিত করতে। তিনি বিশ্বাসীদের প্রতি পরম দয়ালু।"],
  "33:44": ["Their greeting the day they meet Him is, \"Peace,\" and He has prepared for them a generous recompense.","তাঁর সাথে তাদের সাক্ষাতের দিনের অভিবাদন হলো, \"শান্তি,”এবং তিনি তাদের জন্য প্রস্তুত রেখেছেন এক উদার প্রতিদান।"],
  "33:45": ["O prophet, we have sent you as a witness, a bearer of good news, as well as a warner.","হে নবী, আমরা তোমাকে পাঠিয়েছি একজন সাক্ষী হিসেবে, একজন সুসংবাদ বহনকারী, সেই সাথে একজন সতর্ককারী হিসেবে।"],
  "33:46": ["Inviting to Allah, in accordance with His will, and a guiding beacon.","আল্লাহর দিকে আমন্ত্রন জানাতে, তাঁর ইচ্ছানুসারে, এবং একটি পথপ্রদর্শক আলোকবর্তিকা।"],
  "33:47": ["Deliver good news to the believers, that they have deserved from Allah a great blessing.","বিশ্বাসীদের সুসংবাদ দাও, যে তারা আল্লাহর থেকে এক বিশাল অনুগ্রহ লাভ করেছে।"],
  "33:48": ["Do not obey the disbelievers and the hypocrites, disregard their insults, and put your trust in Allah; Allah suffices as an advocate.","অবিশ্বাসী ও ভন্ডদের মান্য করো না, তাদের অপমান উপেক্ষা করো, এবং আল্লাহর উপর তোমার আস্থা রাখো; একজন উকিল হিসেবে আল্লাহই যথেষ্ট।"],
  "33:49": ["O you who believe, if you married believing women, then divorced them before having intercourse with them, they do not owe you any waiting interim (before marrying another man). You shall compensate them equitably, and let them go amicably.","হে তোমরা যারা বিশ্বাস করো, যদি তোমরা বিশ্বাসী নারীদেরকে বিয়ে করে থাকো, এরপর তাদের সঙ্গে যৌন সহবাসের আগেই তাদের তালাক দাও, তারা তোমাদের কাছে বাধ্য নয় অন্তবর্তী সময় অপেক্ষা করতে (অপর পুরুষকে বিয়ে করার আগে)। তোমরা ন্যায়সঙ্গতভাবে তাদেরকে ক্ষতিপূরণ দিবে, এবং তাদেরকে আপোষে যেতে দাও।"],
  "33:50": ["O prophet, we made lawful for you your wives to whom you have paid their due dowry, or what you already have, as granted to you by Allah. Also lawful for you in marriage are the daughters of your father's brothers, the daughters of your father's sisters, the daughters of your mother's brothers, the daughters of your mother's sisters, who have emigrated with you. Also, if a believing woman gave herself to the prophet—by forfeiting the dowry—the prophet may marry her without a dowry, if he so wishes. However, her forfeiting of the dowry applies only to the prophet, and not to the other believers. We have already decreed their rights in regard to their spouses or what they already have. This is to spare you any embarrassment. Allah is Forgiver, Most Merciful.","হে নবী, আমরা তোমার জন্য আইনসম্মত করেছি তোমার স্ত্রীদের যাদেরকে তুমি তাদের ন্যায্য মোহরানা পরিশোধ করেছ, অথবা যা ইতোমধ্যে তোমার, যেমন আল্লাহ তোমাকে দিয়েছেন। এছাড়া, তোমার জন্য বিয়ের ক্ষেত্রে আইনসম্মত তোমার পিতার ভাইয়ের কন্যারা, তোমার পিতার বোনের কন্যারা, তোমার মায়ের ভাইয়ের কন্যারা, তোমার মায়ের বোনের কন্যারা,  যারা তোমার সাথে দেশান্তরিত হয়েছে। এছাড়াও, কোন বিশ্বাসী নারী যদি নিজেকে নবীর কাছে নিবেদন করে – স্বেচ্ছায় মোহরানা ত্যাগ করে- নবী তাকে মোহরানা ছাড়াই বিয়ে করতে পারে, যদি সে তা-ই চায়। যদিও, তার স্বেচ্ছায় মোহরানা ত্যাগ শুধু নবীর ক্ষেত্রে প্রযোজ্য, এবং অন্য বিশ্বাসীদের ক্ষেত্রে নয়। আমরা ইতোমধ্যেই তাদের অধিকারের বিষয় আদেশ করেছি, তাদের সহধর্মী/সহধর্মীনি বা ইতোমধ্যেই তাদের যা আছে সে ব্যাপারে। এটা তোমাকে কোনপ্রকার বিব্রতকর অবস্থা থেকে নিষ্কৃতি দেয়ার জন্য। আল্লাহ ক্ষমাকারী, পরম দয়ালু।"],
  "33:51": ["You may gently shun any one of them, and you may bring closer to you any one of them. If you reconcile with any one you had estranged, you commit no error. In this way, they will be pleased, will have no grief, and will be content with what you equitably offer to all of them. Allah knows what is in your hearts. Allah is Omniscient, Clement.","তুমি ভদ্রভাবে তাদের যে কোন কারো থেকে দূরে থাকতে পারো, এবং তুমি তাদের যে কোন কাউকে কাছে আনতে পারো। যদি তুমি যে কোন কারো সাথে পূনর্মিলিত হও যার সাথে তুমি বিছিন্ন হয়েছিলে, তুমি কোন ভুল করো না। এই ভাবে, তারা সন্তুষ্ট থাকবে, কোনপ্রকার শোক থাকবে না, এবং তাতে তৃপ্ত থাকবে যা তুমি তাদের সবাইকে ন্যায়সঙ্গতভাবে প্রস্তাব করো। আল্লাহ জানেন যা তোমাদের হৃদয়ে আছে। আল্লাহ সর্বজ্ঞ, সহনশীল।"],
  "33:52": ["Beyond the categories described to you, you are enjoined from marrying any other women, nor can you substitute a new wife (from the prohibited categories), no matter how much you admire their beauty. You must be content with those already made lawful to you. Allah is watchful over all things.","তোমার কাছে বর্ণনা করা প্রকারগুলোর  বাইরে, অন্য কোন নারীকে বিয়ে করা তোমার জন্য নিষেধ, না তুমি কোন নতুন স্ত্রী তাদের পরিবর্তে আনতে পারবে (নিষেধকৃত প্রকারগুলো থেকে), তুমি তাদের রূপে যতই মুগ্ধ হও না কেন। তুমি অবশ্যই তাদের নিয়ে তৃপ্ত থাকবে যাদেরকে ইতোমধ্যেই তোমার কাছে আইনসম্মত করা হয়েছে। আল্লাহ সবকিছুর উপর সতর্ক নজর রাখেন।"],
  "33:53": ["O you who believe, do not enter the prophet's homes unless you are given permission to eat, nor shall you force such an invitation in any manner. If you are invited, you may enter. When you finish eating, you shall leave; do not engage him in lengthy conversations. This used to hurt the prophet, and he was too shy to tell you. But Allah does not shy away from the truth. If you have to ask his wives for something, ask them from behind a barrier. This is purer for your hearts and their hearts. You are not to hurt the messenger of Allah. You shall not marry his wives after him, for this would be a gross offense in the sight of Allah.","হে যারা বিশ্বাস করো, নবীর ঘরে প্রবেশ করো না যদি না তোমাদেরকে খাওয়ার অনুমতি দেয়া হয়, না তোমরা কোনভাবে এমন আমন্ত্রণের জন্য জোর করবে। যদি তোমরা আমন্ত্রিত হও, তোমরা প্রবেশ করতে পারো। যখন তোমরা খাওয়া শেষ করো, তোমরা প্রস্থান করবে; তাকে দীর্ঘ আলোচনায় সম্পৃক্ত করো না। এটা নবীকে কষ্ট দিতো, এবং সে তোমাদেরকে বলতে খুব লজ্জা পেতো। কিন্তু, আল্লাহ সত্যে লজ্জা বোধ করেন না। যদি তার স্ত্রীদের কাছে তোমাদের কোন কিছু চাইতে হয়/ জিজ্ঞাসা করতে হয়, একটি পর্দার আড়াল থেকে তাদের জিজ্ঞাসা করো/ কাছে চাও। এটা তোমাদের হৃদয় এবং তাদের হৃদয়ের জন্য শুদ্ধতর। তোমরা তোমাদের আল্লাহর বার্তাবাহককে কষ্ট দিবে না। তোমরা তার পরে তার স্ত্রীদের বিয়ে করবে না, কারণ আল্লাহর দৃষ্টিতে তা হবে এক গুরুতর অপরাধ।"],
  "33:54": ["Whether you declare anything, or hide it, Allah is fully aware of all things.","তোমরা কোনকিছু প্রকাশ করো, অথবা তা গোপন করো, আল্লাহ সবকিছু সম্পর্কে সম্পূর্ণ অবগত।"],
  "33:55": ["The women may relax (their dress code) around their fathers, their sons, their brothers, the sons of their brothers, the sons of their sisters, the other women, and their (female) servants. They shall reverence Allah. Allah witnesses all things.","নারীরা (তাদের পোষাক নীতি) শিথিল করতে পারে তাদের পিতা, তাদের পুত্র, তাদের ভাই, তাদের ভাইদের পুত্র, তাদের বোনদের পুত্র, অন্য নারী, এবং তাদের (নারী) ভৃত্যদের কাছে। তারা আল্লাহকে ভক্তি করবে। আল্লাহ সবকিছু প্রত্যক্ষ করেন।"],
  "33:56": ["Allah and His angels help and support the prophet. O you who believe, you shall help and support him, and regard him as he should be regarded.","আল্লাহ ও তাঁর ফেরেশতারা নবীকে সাহায্য ও সমর্থন করেন। হে তোমরা যারা বিশ্বাস করো, তোমরা তাকে সাহায্য ও সমর্থন করবে, আর তাকে গণ্য করবে যেভাবে তাকে গণ্য করা উচিত।"],
  "33:57": ["Surely, those who oppose Allah and His messenger, Allah afflicts them with a curse in this life, and in the Hereafter; He has prepared for them a shameful retribution.","নিশ্চয়, যারা আল্লাহ ও তাঁর বার্তাবাহকের বিরোধীতা করে, আল্লাহ তাদেরকে অভিশাপ দেন কষ্ট দিতে এই জীবনে, এবং পরকালে; তিনি তাদের জন্য প্রস্তুত রেখেছেন এক লজ্জাকর শাস্তি।"],
  "33:58": ["Those who persecute the believing men and the believing women, who did not do anything wrong, have committed not only a falsehood, but also a gross sin.","যারা বিশ্বাসী পুরুষ ও বিশ্বাসী নারীকে কষ্ট দেয়, যারা কোন ভুল করেনি, তারা শুধু মিথ্যাচার করেনি, বরং এক ঘোর পাপ করেছে।"],
  "33:59": ["O prophet, tell your wives, your daughters, and the wives of the believers that they shall lengthen their garments. Thus, they will be recognized (as righteous women) and avoid being insulted. Allah is Forgiver, Most Merciful.","হে নবী, বলো তোমার স্ত্রীদের, তোমার কন্যাদের এবং বিশ্বাসীদের স্ত্রীদের যে তারা তাদের পোষাক দীর্ঘ করবে। এভাবে, তাদের চেনা যাবে (সৎকর্মশীল নারী হিসেবে) এবং অপমানিত হওয়া এড়াবে। আল্লাহ ক্ষমাশীল, পরম দয়ালু।"],
  "33:60": ["Unless the hypocrites, and those with disease in their hearts, and the vicious liars of the city refrain (from persecuting you), we will surely grant you the upper hand, then they will be forced to leave within a short while.","যদি না  ভন্ডরা, এবং যাদের হৃদয়ে রোগ আছে, এবং শহরের জঘন্য মিথ্যুকরা (তোমাদের উপর অত্যাচার করা থেকে) বিরত হয়, আমরা অবশ্যই তোমাকে কর্তৃত্ব দিবো, এরপর কিছু সময়ের মধ্যে স্থান ত্যাগের জন্য তারা বাধ্য হবে।"],
  "33:61": ["They have incurred condemnation wherever they go; (unless they stop attacking you,) they may be taken and killed.","যেখানেই তারা যাক, তারা শাস্তি টেনে এনেছে; (যদি না তারা তোমাদের উপর আক্রমন করা বন্ধ করে,) তাদেরকে হয়তো বন্দী এবং হত্যা করা হবে।"],
  "33:62": ["This is Allah's eternal system, and you will find that Allah's system is unchangeable.","এটি আল্লাহর চিরস্থায়ী পদ্ধতি, এবং তুমি দেখবে যে আল্লাহর পদ্ধতি অপরিবর্তনীয়।"],
  "33:63": ["The people ask you about the Hour (end of the world). Say, \"The knowledge thereof is only with Allah. For all that you know, the Hour may be close.\"","লোকেরা তোমাকে সে ঘন্টা (বিশ্বের সমাপ্তি) সম্পর্কে জিজ্ঞেস করে। বল, \"এর জ্ঞান কেবল আল্লাহর কাছে। যতটুকু তুমি জানো, সে সময় হয়তো নিকটে।\""],
  "33:64": ["Allah has condemned the disbelievers, and has prepared for them Hell.","আল্লাহ অবিশ্বাসীদের অভিশপ্ত করেছেন, এবং তাদের জন্য নরক প্রস্তুত রেখেছেন।"],
  "33:65": ["Eternally they abide therein. They will find no lord, nor a supporter.","সেখানে তারা চিরকাল থাকে। তারা কোন প্রভু পাবে না, না কোন সমর্থনকারী।"],
  "33:66": ["The day they are thrown into Hell, they will say, \"Oh, we wish we obeyed Allah, and obeyed the messenger.\"","যেদিন তারা নরকে নিক্ষিপ্ত হবে, তারা বলবে, \"আহা, আমরা যদি আল্লাহকে মান্য করতাম, এবং বার্তাবাহককে মান্য করতাম।"],
  "33:67": ["They will also say, \"Our Lord, we have obeyed our masters and leaders, but they led us astray.","তারা আরো বলবে, \"আমাদের প্রভু, আমরা আমাদের মনিব ও নেতাদের মান্য করেছিলাম, কিন্তু তারা আমাদের বিপথে পরিচালিত করেছে।"],
  "33:68": ["\"Our Lord, give them double the retribution, and curse them a tremendous curse.\"","\"আমাদের প্রভু, তাদেরকে দ্বিগুন শাস্তি দিন, এবং তাদেরকে এক ভয়ানক অভিশাপে অভিশপ্ত করুন।\""],
  "33:69": ["O you who believe, do not be like those who hurt Moses, then Allah absolved him of what they said. He was, in the sight of Allah, honorable.","হে তোমরা যারা বিশ্বাস করো, তাদের মতো হয়ো না যারা মূসাকে আঘাত করেছিল, এরপর তারা যা বলেছিল তা থেকে আল্লাহ তাকে নির্দোষ প্রমান করলেন। সে ছিল, আল্লাহর দৃষ্টিতে, সম্মানিত।"],
  "33:70": ["O you who believe, reverence Allah and utter only the correct utterances.","হে তোমরা যারা বিশ্বাস করো, আল্লাহকে ভক্তি করো এবং কেবল সঠিক কথাটিই বলো।"],
  "33:71": ["He will then fix your works, and forgive your sins. Those who obey Allah and His messenger have triumphed a great triumph.","তাহলে তিনি তোমাদের কাজগুলো ঠিক করে দেবেন, এবং তোমাদের পাপগুলো ক্ষমা করবেন। যারা আল্লাহ এবং তাঁর বার্তাবাহককে মান্য করে তারা এক মহা বিজয়ে জয়ী হলো।"],
  "33:72": ["We have offered the responsibility (freedom of choice) to the heavens and the earth, and the mountains, but they refused to bear it, and were afraid of it. But the human being accepted it; he was transgressing, ignorant.","আমরা আকাশমন্ডলী ও পৃথিবী, এবং পর্বতগুলোকে (ইচ্ছা স্বাধীনতার) দায়িত্ব নিতে প্রস্তাব করেছিলাম, কিন্তু তারা তা বহন করতে অস্বীকার করলো, এবং তাতে ভীত হল। কিন্তু মানুষ তা গ্রহন করলো; সে ছিল সীমালঙ্ঘনকারী, অজ্ঞ।"],
  "33:73": ["For Allah will inevitably punish the hypocrite men and the hypocrite women, and the idol worshiping men and the idol worshiping women. Allah redeems the believing men and the believing women. Allah is Forgiver, Most Merciful.","কারণ আল্লাহ অবধারিতভাবে ভন্ড পুরুষ ও ভন্ড নারীদের, এবং শরিক উপাসনাকারী পুরুষ ও শরিক উপাসনাকারী নারীদের শাস্তি দিবেন। আল্লাহ বিশ্বাসী পুরুষ ও বিশ্বাসী নারীদের পাপমুক্ত করেন। আল্লাহ ক্ষমাকারী, পরম দয়ালু।"],
  "34:1": ["Praise be to Allah—to whom belongs everything in the heavens and the earth; all praise is also due to Him in the Hereafter. He is the Most Wise, the Cognizant.","প্রশংসা আল্লাহর - যাঁর অধীনে রয়েছে আকাশমন্ডলী ও পৃথিবীর সবকিছু; অধিকন্তু পরকালের সকল প্রশংসাও তাঁর জন্যই। তিনি সবচেয়ে প্রজ্ঞাময়, অবগত।"],
  "34:2": ["He knows everything that goes into the earth, and everything that comes out of it, and everything that comes down from the sky, and everything that climbs into it. He is the Most Merciful, the Forgiving.","তিনি জানেন সবকিছু যা মাটির ভেতর যায়, আর সবকিছু যা এর থেকে বের হয়ে আসে, আর সবকিছু যা আকাশ থেকে নেমে আসে, আর সবকিছু যা এর মধ্যে উত্থিত হয়। তিনি পরম দয়ালু, ক্ষমাশীল।"],
  "34:3": ["Those who disbelieve have said, \"The Hour will never come to pass!\" Say, \"Absolutely—by my Lord—it will most certainly come to you. He is the Knower of the future. Not even the equivalent of an atom's weight is hidden from Him, be it in the heavens or the earth. Not even smaller than that, or larger (is hidden). All are in a profound record.\"","যারা অবিশ্বাস করে তারা বলেছে, \"সে সময় কখনো আসবে না!” বল, \"নিঃসন্দেহে - আমার প্রভুর শপথ - এটি অবশ্যই তোমাদের কাছে আসবে। তিনি ভবিষ্যৎ সম্পর্কে জানেন। এমনকি একটি পরমানুর ভরের সমতুল্য পরিমাণও তাঁর থেকে লুকানো নয়, হোক তা আকাশমন্ডলী অথবা পৃথিবীতে। না এমনকি তার চেয়ে ছোট কিছু অথবা বড় কিছু (লুকানো আছে)। সব কিছুই আছে এক জ্ঞানগর্ভ নথিতে।\""],
  "34:4": ["Most certainly, He will reward those who believe and lead a righteous life. These have deserved forgiveness and a generous provision.","অবশ্যই যারা বিশ্বাস করে এবং সৎ-জীবন-যাপন করে তিনি তাদেরকে পুরষ্কৃত করবেন। এরা ক্ষমা এবং এক উদার জীবিকার যোগ্য হয়েছে।"],
  "34:5": ["As for those who constantly challenge our revelations, they have incurred a retribution of painful humiliation.","আর যারা অনবরত আমাদের প্রকাশনাবলিকে চ্যালেঞ্জ করে, তারা এক যন্ত্রণাদায়ক অপমানের শাস্তি অর্জন করেছে।"],
  "34:6": ["It is evident to those who are blessed with knowledge that this revelation from your Lord to you is the truth, and that it guides to the path of the Almighty, the Most Praiseworthy.","এটা তাদের কাছে সুস্পষ্ট যারা জ্ঞান দ্বারা অনুগ্রহপ্রাপ্ত যে তোমার প্রভুর পক্ষ থেকে তোমার কাছে আসা এই প্রকাশনাবলি সত্য, এবং এটি সর্বশক্তিমান, সবচেয়ে প্রশংসনীয়ের দিকে পথনির্দেশ করে।"],
  "34:7": ["Those who disbelieve have said, \"Let us show you a man who tells you that after you are torn apart you will be created anew.","যারা অবিশ্বাস করে তারা বলেছে, \"চল আমরা তোমাদেরকে একজন মানুষকে দেখাই  যে তোমাদের বলে যে তোমরা ছিন্ন-বিচ্ছিন্ন হবার পর তোমাদেরকে নতুন করে সৃষ্টি করা হবে।"],
  "34:8": ["\"Either he fabricated lies about Allah, or he is crazy.\" Indeed, those who disbelieve in the Hereafter have incurred the worst retribution; they have gone far astray.","\"হয় সে আল্লাহ সম্পর্কে মিথ্যা বানিয়েছে, নতুবা সে পাগল।” নিশ্চয়, যারা পরকালে অবিশ্বাস করে তারা সবচেয়ে নিকৃষ্ট শাস্তি টেনে এনেছে; তারা বহুদূর পথভ্রষ্ট হয়েছে।"],
  "34:9": ["Have they not seen all the things in front of them and behind them, in the heaven and the earth? If we willed, we could have caused the earth to swallow them, or caused masses to fall on them from the sky. This should be a sufficient proof for every obedient servant.","তারা কি তাদের সম্মুখ এবং তাদের পিছনের সবকিছু দেখেনি, আকাশমণ্ডলী এবং পৃথিবীতে? যদি আমরা চাইতাম, আমরা পৃথিবীকে দিয়ে তাদের গ্রাস করাতে পারতাম, অথবা আকাশ থেকে তাদের উপর বস্তুপিণ্ডের পতন ঘটাতাম। এটা প্রত্যেক অনুগত বান্দার জন্য একটি যথেষ্ট প্রমান হওয়া উচিত।"],
  "34:10": ["We endowed David with blessings from us: \"O mountains, submit with him, and you too, O birds.\" We softened the iron for him.","আমরা দাউদকে আমাদের পক্ষ থেকে অনুগ্রহ দান করেছিলাম: \"হে পর্বতসমূহ, তার সাথে আত্মসমর্পণ করো, আর তোমরাও, হে পাখিরা।” আমরা তার জন্য লোহাকে নরম করে দিয়েছিলাম।"],
  "34:11": ["\"You may make shields that fit perfectly, and work righteousness. Whatever you do, I am Seer thereof.\"","\"তুমি আত্ম-রক্ষার্থে ঢাল বানাও যা যথার্থই মানানসই হয়, এবং সৎকর্ম করো। যা কিছু তোমরা করো, আমি তা দেখি।\""],
  "34:12": ["To Solomon we committed the wind at his disposal, traveling one month coming and one month going. And we caused a spring of oil to gush out for him. Also, the jinns worked for him, by his Lord's leave. Any one of them who disregarded our commands, we subjected him to a severe retribution.","সুলেমানের কাছে আমি বাতাসকে তার আজ্ঞাবহ করেছিলাম, যা আসতে ভ্রমন করতো একমাস আর যেতে একমাস। আর আমরা তার জন্য তেলের ঝর্ণা প্রবাহিত করেছিলাম। এছাড়াও, জীনরা তার জন্য কাজ করতো, তার প্রভুর অনুমতিতে। তাদের যেকেউ আমাদের আদেশকে উপেক্ষা করতো, আমরা তাকে কঠিন শাস্তি দিয়ে আয়ত্তে আনতাম।"],
  "34:13": ["They made for him anything he wanted—niches, statues, deep pools, and heavy cooking pots. O family of David, work (righteousness) to show your appreciation. Only a few of My servants are appreciative.","তারা তার জন্য সবকিছুই বানাতো যা সে চাইতো - কুলুঙ্গি, মূর্তি, গভীর জলাশয়, এবং ভারী রান্নার পাত্র। হে দাউদের পরিবার, (সৎ) কর্ম করো তোমাদের কৃতজ্ঞতা প্রদর্শন করতে। আমার বান্দাদের মধ্যে অল্প সংখ্যকই শুধু কৃতজ্ঞ।"],
  "34:14": ["When the appointed time for his death came, they had no clue that he had died. Not until one of the animals tried to eat his staff, and he fell down, that the jinns realized that he was dead. They thus realized that if they really knew the unseen, they would have stopped working so hard as soon as he died.","যখন তার মৃত্যুর নির্ধারিত সময় এসে পড়লো, তাদের কাছে কোন ইঙ্গিত ছিল না যে সে মারা গিয়েছে। যতক্ষণ না একটি প্রানী তার লাঠি খাওয়ার চেষ্টা করলো, আর সে পড়ে গেল, তখনই জীনেরা বুঝলো যে সে মৃত। এভাবে তারা অনুধাবন করলো যে যদি তারা সত্যই অদৃশ্য বিষয় জানতো, তবে সে মারা যাওয়া মাত্রই তারা এত কষ্টকর কাজ করা বন্ধ করে দিতো।"],
  "34:15": ["Sheba's homeland used to be a marvel, with two gardens on the right and the left. Eat from your Lord's provisions, and be appreciative of Him—good land, and a forgiving Lord.","সাবার মাতৃভূমি ছিল এক বিস্ময়, ডানে ও বায়ে দু'টি বাগান সহ। তোমাদের প্রভুর জীবিকা থেকে খাও, এবং তাঁর প্রতি কৃতজ্ঞ হও- ভাল জমিনের জন্য, এবং এক ক্ষমাশীল প্রভু।"],
  "34:16": ["They turned away and, consequently, we poured upon them a disastrous flood, and we substituted their two gardens into two gardens of bad tasting fruits, thorny plants, and a skimpy harvest.","তারা মুখ ফিরিয়ে নিলো এবং, পরিনামে, আমরা তাদের উপর সর্বনাশা বন্যা প্রবাহিত করলাম, এবং আমরা তাদের দুই বাগানকে বদলে দিলাম খারাপ স্বাদের ফল বাগান, কাঁটাযুক্ত উদ্ভিদ, এবং অপর্যাপ্ত ফসলে।"],
  "34:17": ["We thus requited them for their disbelief. Do we not requite only the disbelievers?","আমরা এভাবে তাদের অবিশ্বাসের জন্য তাদেরকে শাস্তি দিয়েছি। আমরা কি শুধু অবিশ্বাসীদেরকেই শাস্তি দেই না?"],
  "34:18": ["We placed between them and the communities that we blessed other oases, and we secured the journey between them: \"Travel therein days and nights in complete security.\"","আমরা তাদের ও যে সম্প্রদায়গুলোকে আমরা অনুগ্রহ করেছিলাম তাদের মাঝে অন্যান্য মরুদ্যান স্থাপন করেছিলাম, এবং আমরা এগুলোর মধ্যে যাত্রাকে নিরাপদ করেছিলাম: \"সেগুলোর মধ্যে দিনে এবং রাতে সম্পূর্ণ নিরাপদে ভ্রমণ করো।\""],
  "34:19": ["But they (turned unappreciative and) challenged: \"Our Lord, we do not care if You increase the distance of our journeys (without any stations).\" They thus wronged their own souls. Consequently, we made them history, and scattered them into small communities throughout the land. This should provide lessons for those who are steadfast, appreciative.","কিন্তু (তারা অকৃতজ্ঞ হয়ে পড়লো এবং) চ্যালেঞ্জ করলো: \"আমাদের প্রভু, আমরা পরোয়া করি না যদি আপনি (কোন বিশ্রামস্থল ছাড়াই) আমাদের যাত্রার দূরত্ব বাড়িয়ে দেন।”তারা এভাবে তাদের নিজেদের আত্মার প্রতি অন্যায় করলো। ফলশ্রুতিতে, আমরা তাদেরকে ইতিহাস বানালাম, এবং তাদেরকে দেশজুড়ে ছোট ছোট সম্প্রদায়ে বিচ্ছিন্ন করে দিলাম। এগুলো তাদের জন্য শিক্ষা হওয়া উচিত যারা অবিচল, কৃতজ্ঞ।"],
  "34:20": ["Satan found them readily fulfilling his expectations. They followed him, except a few believers.","শয়তান তাদেরকে তৎক্ষণাৎ তার প্রত্যাশা পূর্ণ করতে দেখল। তারা তাকে অনুসরণ করলো, অল্প সংখ্যক বিশ্বাসী ছাড়া।"],
  "34:21": ["He never had any power over them. But we thus distinguish those who believe in the Hereafter from those who are doubtful about it. Your Lord is in full control of all things.","তাদের উপর কখনো তার কোন ক্ষমতা ছিল না। কিন্তু এভাবে যারা পরকালে বিশ্বাস করে তাদেরকে আমরা আলাদা করি তাদের থেকে যারা এ বিষয়ে সন্দিহান। তোমার প্রভু সবকিছুর পূর্ণ নিয়ন্ত্রনে আছেন।"],
  "34:22": ["Say, \"Implore the idols you have set up beside Allah. They do not possess as much as a single atom in the heavens, or the earth. They possess no partnership therein, nor does He permit them to be His assistants.\"","বল, \"সে উপাস্যদের কাছে চাও যাদেরকে তোমরা আল্লাহর পাশে স্থাপন করেছো। তারা আকাশমণ্ডলী, অথবা পৃথিবীর একটি পরমানুরও মালিক না। তারা সেখানকার কোন অংশীদারিত্বের মালিক না, না তিনি তাদেরকে তার সহকারী হবার অনুমতি দেন।\""],
  "34:23": ["Intercession with Him will be in vain, unless it coincides with His will. When their minds are finally settled down, and they ask, \"What did your Lord say,\" they will say, \"The truth.\" He is the Most High, the Most Great.","তাঁর কাছে সুপারিশ করা অর্থহীন হবে, যদি না তা তাঁর ইচ্ছার সাথে মিলে যায়। তাদের মন যখন অবশেষে স্থির হয়, আর তারা জিজ্ঞেস কর, “তোমাদের প্রভু কি বলেছেন, ” তারা বলবে, \"সত্য।” তিনি সবচেয়ে উর্ধ্বে, সবচেয়ে মহান।"],
  "34:24": ["Say, \"Who provides for you, from the heavens and the earth?\" Say, \"Allah,\" and \"Either we or you are guided, or have gone far astray.\"","বল, \"কে তোমাদের জীবিকা দেন, আকাশমণ্ডলী ও পৃথিবী থেকে?” বল, \"আল্লাহ, ”এবং \"হয় আমরা না হয় তোমরা সুপথপ্রাপ্ত, অথবা বহুদূরে পথভ্রষ্ট হয়েছি।\""],
  "34:25": ["Say, \"You are not responsible for our crimes, nor are we responsible for what you do.\"","বল, \"তোমরা আমাদের অপরাধের জন্য দায়ী নও, না আমরা তার জন্য দায়ী যা তোমরা করো।\""],
  "34:26": ["Say, \"Our Lord will gather us all together before Him, then He will judge between us equitably. He is the Judge, the Omniscient.\"","বল, \"আমাদের প্রভু তাঁর সামনে আমাদের সকলকে একত্রিত করবেন, তারপর তিনি আমাদের মাঝে ন্যায়সঙ্গত বিচার করবেন। তিনিই বিচারক, সর্বজ্ঞ।”"],
  "34:27": ["Say, \"Show me the idols you have set up as partners with Him!\" Say, \"No; He is the one Allah, the Almighty, Most Wise.\"","বল, \"আমাকে সে উপাস্যদের দেখাও যাদেরকে তোমরা তাঁর সাথে শরিক হিসেবে স্থাপন করেছ!” বল, \"না; তিনিই সেই এক আল্লাহ, সর্বশক্তিমান, সবচেয়ে জ্ঞানী।\""],
  "34:28": ["We have sent you (O Rashad) to all the people, a bearer of good news, as well as a warner, but most people do not know.","(হে রাশাদ)  আমরা তোমাকে সব লোকদের কাছে পাঠিয়েছি, একজন সুসংবাদ বহনকারী, সেই সাথে একজন সতর্ককারী হিসেবে, কিন্তু অধিকাংশ লোক জানে না।"],
  "34:29": ["They challenge, \"When will this promise come to pass, if you are truthful?\"","তারা চ্যালেঞ্জ করে, “কখন এই প্রতিশ্রুতি পূর্ন হবে, যদি তোমরা সত্যবাদী হও?”"],
  "34:30": ["Say, \"You have a specific time, on a specific day, that you cannot delay by one hour, nor advance.\"","বল, \"তোমাদের জন্য একটি নির্দিষ্ট সময় রয়েছে, একটি নির্দিষ্ট দিনে, যা তোমরা এক ঘণ্টার জন্যও পিছাতে পারবে না, না আগাতে পারবে।”"],
  "34:31": ["Those who disbelieve have said, \"We will not believe in this Quran, nor in the previous scriptures.\" If you could only envision these transgressors when they stand before their Lord! They will argue with one another back and forth. The followers will tell their leaders, \"If it were not for you, we would have been believers.\"","যারা অবিশ্বাস করেছে তারা বলেছে, \"আমরা এই কোর'আনে বিশ্বাস করবো না, না পূর্ববর্তী ঐশীগ্রন্থে।” যদি শুধু তুমি এসব সীমালঙ্ঘনকারীদেরকে দেখতে পেতে যখন তারা তাদের প্রভুর সামনে দাঁড়ায়! তারা আগে পিছে পরস্পরের সাথে বাদানুবাদ করবে। অনুসারীরা তাদের নেতাদের বলবে, \"তোমরা যদি না থাকতে, আমরা বিশ্বাসীই হতাম।\""],
  "34:32": ["The leaders will say to those who followed them, \"Are we the ones who diverted you from the guidance after it came to you? No; it is you who were wicked.\"","সে নেতারা তাদেরকে বলবে যারা তাদের অনুসরণ করেছিল, \"আমরাই কি তোমাদের পথনির্দেশনা থেকে পথচ্যুত করেছি তোমাদের কাছে তা আসার পর? না; তোমরাই ছিলে অন্যায়কারী।\""],
  "34:33": ["The followers will say to their leaders, \"It was you who schemed night and day, then commanded us to be unappreciative of Allah, and to set up idols to rank with Him.\" They will be ridden with remorse, when they see the retribution, for we will place shackles around the necks of those who disbelieved. Are they not justly requited for what they did?","অনুসারীরা তাদের নেতাদের বলবে, \"তোমরাই রাত-দিন ষড়যন্ত্র করেছিলে, তারপর আমাদেরকে আল্লাহর প্রতি অকৃতজ্ঞ হবার জন্য, এবং তাঁর সাথে সমমর্যাদা দিয়ে শরিক স্থাপন করতে আদেশ করেছিলে। \" তারা অনুশোচনায় জর্জরিত হবে,  যখন তারা শাস্তি দেখবে, কেননা আমরা তাদের ঘাড়ে শিকল পরাবো যারা অবিশ্বাস করেছিল। তারা যা করেছে তার জন্য কি তারা  ন্যায়সঙ্গত প্রতিফল পায়নি?"],
  "34:34": ["Every time we sent a warner to a community, the leaders of that community said, \"We reject the message you are sent with.\"","প্রত্যেকবার যখন আমরা কোন সম্প্রদায়ের কাছে কোন সতর্ককারী পাঠিয়েছি, ওই সম্প্রদায়ের নেতারা বলেছে, \"আমরা সে বার্তা প্রত্যাক্ষান করি, যা নিয়ে তোমরা প্রেরিত হয়েছো।\""],
  "34:35": ["They also said, \"We are more powerful, with more money and children, and we will not be punished.\"","তারা আরো বলেছে, \"আমরা অধিক শক্তিশালী, বেশি টাকাকড়ি ও সন্তান-সন্ততিতে, আর আমাদেরকে শাস্তি দেয়া হবে না।\""],
  "34:36": ["Say, \"My Lord is the One who controls all provisions; He grants the provisions to whomever He wills, or reduces them, but most people do not know.\"","বল, \"আমার প্রভু সে সত্তা যিনি সকল জীবিকা নিয়ন্ত্রণ করেন; তিনি যার জন্য ইচ্ছা জীবিকা দেন, অথবা এগুলো কমিয়ে দেন, কিন্তু অধিকাংশ লোক জানে না।\""],
  "34:37": ["It is not your money or your children that bring you closer to us. Only those who believe and lead a righteous life will receive the reward for their works, multiplied manifold. In the abode of Paradise they will live in perfect peace.","তোমাদের টাকা-পয়সা বা তোমাদের সন্তানাদি তোমাদেরকে আমাদের নিকটে আনে না। যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে শুধু তারাই তাদের কাজগুলোর জন্য পুরষ্কার পাবে, বহুগুনে বর্ধিত। স্বর্গীয় আবাসে তারা পূর্ণাঙ্গ শান্তিতে বাস করবে।"],
  "34:38": ["As for those who consistently challenge our revelations, they will abide in retribution.","আর তাদের জন্য যারা আমাদের প্রকাশনাবলিকে অনাবরত চ্যালেঞ্জ করে যায়, তারা শাস্তিতে বাস করবে।"],
  "34:39": ["Say, \"My Lord is the One who controls all provisions; He increases the provisions for whomever He chooses from among His servants, or reduces them. Anything you spend (in the cause of Allah), He will reward you for it; He is the Best Provider.\"","বল, \"আমার প্রভু সে সত্তা যিনি সকল জীবিকা নিয়ন্ত্রণ করেন; তিনি তাঁর বান্দাদের মধ্য থেকে যার জন্য পছন্দ করেন জীবিকা বাড়িয়ে দেন, অথবা এগুলো কমিয়ে দেন। তোমরা যা কিছু ব্যয় করো (আল্লাহর উদ্দেশ্যে), তিনি তার জন্য তোমাদের পুরষ্কৃত করবেন; তিনিই সর্বোত্তম জীবিকা প্রদানকারী।\""],
  "34:40": ["On the day when He summons them all, He will say to the angels, \"Did these people worship you?\"","সেদিন যখন তিনি তাদের সবাইকে তলব করবেন, তিনি ফেরেশতাদের বলবেন, \"এই লোকেরা কি তোমাদের উপাসনা করতো?”"],
  "34:41": ["They will answer, \"Be You glorified. You are our Lord and Master, not them. Instead, they were worshiping the jinns; most of them were believers therein.\"","তারা উত্তর দিবে, “আপনি মহিমান্বিত। আপনি আমাদের প্রভু এবং আদেশ দাতা, তারা নয়। বরং, তারা জ্বীনদের উপাসনা করতো, তাদের অধিকাংশ তাতে বিশ্বাসী ছিল।”"],
  "34:42": ["On that day, you possess no power to help or harm one another, and we will say to the transgressors, \"Taste the retribution of the Hell that you used to deny.\"","সেদিন, একে অন্যকে সাহায্য বা ক্ষতি করার কোন ক্ষমতা তোমাদের থাকবে না, এবং আমরা সীমালঙ্ঘনকারীদের বলবো, “নরকের শাস্তি আস্বাদন করো যা তোমরা অস্বীকার করতে।”"],
  "34:43": ["When our proofs were recited to them, perfectly clear, they said, \"This is simply a man who wants to divert you from the way your parents are worshiping.\" They also said, \"These are fabricated lies.\" Those who disbelieved also said about the truth that came to them, \"This is obviously magic.\"","তাদের কাছে যখন আমাদের প্রমাণ আবৃত্তি করা হয়েছিল, সম্পূর্ণরুপে স্পষ্ট, তারা বলেছিল, \"এ তো কেবলই একজন মানুষ যে তোমাদেরকে সে পথ থেকে সরিয়ে দিতে চায় যেভাবে তোমাদের মাতা-পিতারা উপাসনা করছে।” তারা আরো বলল, \"এগুলো বানোয়াট মিথ্যা।\" যারা অবিশ্বাস করেছে তাদের কাছে আসা সত্য সম্পর্কে  তারা এ-ও বলেছিল যে, \"এটা স্পষ্ট যাদু।\""],
  "34:44": ["We did not give them any other books to study, nor did we send to them before you another warner.","আমরা তাদেরকে অধ্যয়ন করতে অন্যকোন গ্রন্থ দেইনি, না আমরা তোমার আগে তাদের কাছে অন্যকোন সতর্ককারী পাঠিয়েছি।"],
  "34:45": ["Those before them disbelieved, and even though they did not see one-tenth of (the miracle) we have given to this generation, when they disbelieved My messengers, how severe was My retribution!","যারা তাদের পূর্বে অবিশ্বাস করেছিল, এবং যদিও তারা এই প্রজন্মকে আমাদের দেয়া (অলৌকিকতার) এক-দশমাংশও দেখেনি, যখন তারা আমার বার্তাবাহকদের অবিশ্বাস করেছিল, কতই না কঠোর ছিল আমার শাস্তি!"],
  "34:46": ["Say, \"I ask you to do one thing: Devote yourselves to Allah, in pairs or as individuals, then reflect. Your friend (Rashad) is not crazy. He is a manifest warner to you, just before the advent of a terrible retribution.\"","বল, \"আমি তোমাদের একটা বিষয় করতে বলি: নিজেদেরকে আল্লাহর কাছে উৎসর্গ করো, জোড়ায় জোড়ায় বা ব্যক্তিগতভাবে, এরপর ভেবে দেখো। তোমাদের বন্ধু (রাশাদ) পাগল নয়। সে তোমাদের কাছে একজন সুস্পষ্ট সতর্ককারী, এক ভয়ানক শাস্তি আসার ঠিক আগে।”"],
  "34:47": ["Say, \"I do not ask you for any wage; you can keep it. My wage comes only from Allah. He witnesses all things.\"","বল, \"আমি তোমাদের কাছে কোন পারিশ্রমিক চাই না; তোমরা তা রাখতে পারো। আমার পারিশ্রমিক শুধুমাত্র আল্লাহর কাছ থেকে আসে। তিনি সবকিছু প্রত্যক্ষ করেন।\""],
  "34:48": ["Say, \"My Lord causes the truth to prevail. He is the Knower of all secrets.\"","বল, \"আমার প্রভু সত্যকে জয়ী করান। তিনি সকল গোপন বিষয় জানেন।\""],
  "34:49": ["Say, \"The truth has come; while falsehood can neither initiate anything, nor repeat it.\"","বল, \"সত্য এসেছে; যখন মিথ্যা না কোনকিছুর সূচনা করতে পারে, না এর পুনরাবৃত্তি করতে পারে।\""],
  "34:50": ["Say, \"If I go astray, I go astray because of my own shortcomings. And if I am guided, it is because of my Lord's inspiration. He is Hearer, Near.\"","বল, \"যদি আমি পথভ্রষ্ট হই, আমি পথভ্রষ্ট হই আমার নিজের ত্রুটির কারণে। আর যদি আমি পথপ্রাপ্ত হই, এটা আমার প্রভুর প্রত্যাদেশের বদৌলতে। তিনি শ্রবণকারী, নিকটবর্তী। \""],
  "34:51": ["If you could only see them when the great terror strikes them; they cannot escape then, and they will be taken away forcibly.","যদি শুধু তুমি তাদেরকে দেখতে পারতে যখন সে মহা আতংক তাদের আঘাত করে; তখন তারা পলাতে পারবে না, এবং তাদেরকে জোরপূর্বক তুলে নেয়া হবে।"],
  "34:52": ["They will then say, \"We now believe in it,\" but it will be far too late.","তারা তখন বলবে, \"আমরা এখন এতে বিশ্বাস করি,” কিন্তু তা অনেক বেশি দেরী হয়ে যাবে।"],
  "34:53": ["They have rejected it in the past; they have decided instead to uphold conjecture and guesswork.","তারা অতীতে এটা প্রত্যাখ্যান করেছিল; পরিবর্তে তারা  মেনে চলার সিদ্ধান্ত নিয়েছিল ধারণা এবং অনুমাননির্ভর কর্ম।"],
  "34:54": ["Consequently, they were deprived of everything they longed for. This is the same fate as their counterparts in the previous generations. They harbored too many doubts.","পরিনামে, তারা সবকিছু থেকে বঞ্চিত হয়েছিল যার আকাঙ্ক্ষা তারা করতো। এটা সে একই ভাগ্য পূর্ববর্তী প্রজন্মে তাদের অনুরূপ লোকদের মতো। তারা খুব বেশি সন্দেহ পোষন করতো।"],
  "35:1": ["Praise be to Allah, Initiator of the heavens and the earth, and appointer of the angels to be messengers with wings—two, three, and four (wings). He increases the creation as He wills. Allah is Omnipotent.","প্রশংসা আল্লাহর, আকাশমণ্ডলী ও পৃথিবীর সূচনাকারী, এবং ফেরেশতাদের নিয়োগকারী পাখাযুক্ত বার্তাবাহক হবার জন্য-দুই, তিন, ও চার (পাখা)। তিনি সৃষ্টি বৃদ্ধি করেন যেমন তিনি চান। আল্লাহ সর্বশক্তিমান।"],
  "35:2": ["When Allah showers the people with mercy, no force can stop it. And if He withholds it, no force, other than He, can send it. He is the Almighty, Most Wise.","যখন আল্লাহ লোকদের উপর দয়া বর্ষণ করেন, কোন শক্তি তা আটকাতে পারে না। এবং যদি তিনি তা আটকে রাখেন, কোন শক্তি, তিনি ব্যতিত, তা পাঠাতে পারে না। তিনিই সর্ব-শক্তিমান, সবথেকে জ্ঞানী।"],
  "35:3": ["O people, remember Allah's blessings upon you. Is there any creator other than Allah who provides for you from the heaven and the earth? There is no other god beside Him. How could you deviate?","হে মানুষ, তোমাদের উপর আল্লাহর অনুগ্রহকে স্মরণ করো। আল্লাহ ছাড়া অন্য কোন সৃষ্টিকর্তা কি আছে যে তোমাদের জীবিকা দান করে আকাশমণ্ডলী এবং পৃথিবী থেকে? তাঁর পাশে অন্য কোন উপাস্য নেই। কেমন করে তোমরা পথভ্রষ্ট হও?"],
  "35:4": ["If they disbelieve you, messengers before you have been disbelieved. Allah is in control of all things.","যদি তারা তোমাকে অবিশ্বাস করে, তোমার পূর্বেও বার্তাবাহকদের অবিশ্বাস করা হয়েছে। আল্লাহ সকল বস্তুর নিয়ন্ত্রনে আছেন।"],
  "35:5": ["O people, Allah's promise is the truth; therefore, do not be distracted by this lowly life. Do not be diverted from Allah by mere illusions.","হে মানুষ, আল্লাহর প্রতিশ্রুতি সত্য; অতএব, এই  নিম্নমানের জীবন দ্বারা বিভ্রান্ত হইও না। আল্লাহ থেকে নিছক বিভ্রমের দ্বারা বিচ্যুত হইও না।"],
  "35:6": ["The devil is your enemy, so treat him as an enemy. He only invites his party to be the dwellers of Hell.","শয়তান তোমাদের শত্রু, তাই তাকে শত্রু হিসাবে বিবেচনা করো। সে শুধু তার দলকে নরকের বাসিন্দা হতে আমন্ত্রন করে।"],
  "35:7": ["Those who disbelieve have incurred a severe retribution, and those who believe and lead a righteous life have deserved forgiveness and a great recompense.","যারা অবিশ্বাস করে তারা টেনে এনেছে এক ভীষণ শাস্তি, আর যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে তারা যোগ্য হয়েছে ক্ষমা ও এক মহা প্রতিদানের।"],
  "35:8": ["Note the one whose evil work is adorned in his eyes, until he thinks that it is righteous. Allah thus sends astray whoever wills (to go astray), and He guides whoever wills (to be guided). Therefore, do not grieve over them. Allah is fully aware of everything they do.","সে ব্যক্তির প্রতি লক্ষ্য করো যার মন্দ কাজকে তার চোখে সাজিয়ে দেয়া হয়েছে, যতক্ষণ না সে ভাবে যে এটা সৎকাজ। আল্লাহ এভাবে পথভ্রষ্ট করেন যেকেউ চায় (পথভ্রষ্ট হতে), এবং তিনি পথপ্রদর্শন করেন যেকেউ চায় (সুপথপ্রাপ্ত হতে)। অতএব, তাদের জন্য দুঃখ করো না। আল্লাহ সবকিছু সম্পর্কে পূর্ণ অবগত যা তারা করে।"],
  "35:9": ["Allah is the One who sends the winds to stir up clouds, then we drive them towards barren lands, and revive such lands after they were dead. Thus is the resurrection.","আল্লাহই সে সত্ত্বা যিনি বাতাস পাঠান মেঘমালাকে সঞ্চালিত করতে, এরপর আমরা সেগুলোকে অনুর্বর ভূমির দিকে চালনা করি, এবং এরকম ভূমিকে এগুলোর মৃত্যুর পর পুনরুজ্জীবিত করি। এভাবেই পুনরুত্থান হয়।"],
  "35:10": ["Anyone seeking dignity should know that to Allah belongs all dignity. To Him ascends the good words, and He exalts the righteous works. As for those who scheme evil works, they incur severe retribution; the scheming of such people is destined to fail.","যেকেউ মর্যাদা চায় তার জানা উচিত যে সকল মর্যাদা আল্লাহর। তাঁর দিকে ভালো কথা উত্থিত হয়, এবং তিনি সৎকর্মের উচ্চ-মূল্যায়ন করেন। আর যারা মন্দ কাজের ষড়যন্ত্র করে, তারা টেনে এনেছে কঠোর শাস্তি; এমন লোকদের ষড়যন্ত্রের নিয়তি হচ্ছে ব্যর্থ হওয়া।"],
  "35:11": ["Allah created you from dust, then from a tiny drop, then He causes you to reproduce through your spouses. No female becomes pregnant, nor gives birth, without His knowledge. No one survives for a long life, and no one's life is snapped short, except in accordance with a pre-existing record. This is easy for Allah.","আল্লাহ তোমাদেরকে ধুলো থেকে সৃষ্টি করেছেন, এরপর ক্ষুদ্র ফোঁটা থেকে, এরপর তিনি তোমাদের সঙ্গিদের মাধ্যমে তোমাদের বংশবৃদ্ধি করান। কোন নারী গর্ভধারণ করে না, না জন্ম দেয়, তাঁর জ্ঞানের বাইরে। না কেউ দীর্ঘকাল বেঁচে থাকে, আর না কারো জীবন সংক্ষিপ্ত করা হয়, আগে থেকে বিদ্যমান কোন রেকর্ড অনুযায়ী ছাড়া। এটা আল্লাহর জন্য সহজ।"],
  "35:12": ["The two seas are not the same; one is fresh and delicious, while the other is salty and undrinkable. From each of them you eat tender meat, and extract jewelry to wear. And you see the ships sailing through them, seeking His provisions, that you may be appreciative.","দুই সাগর এক নয়; একটি বিশুদ্ধ ও সুস্বাদু, যখন অন্যটি লবনাক্ত ও পানের অযোগ্য। তাদের প্রত্যেকটি থেকে তোমরা কোমল মাংস খাও, এবং পরিধানের অলঙ্কার আহরণ করো। এবং তোমরা জাহাজগুলোকে দেখো এগুলোর মাঝে চলাচল করে, তাঁর জীবিকা অন্বেষ্ণণে, যাতে তোমরা কৃতজ্ঞ হতে পারো।"],
  "35:13": ["He merges the night into the day, and merges the day into the night. He has committed the sun and the moon to run for a predetermined period of time. Such is Allah your Lord; to Him belongs all kingship. Any idols you set up beside Him do not possess as much as a seed's shell.","তিনি রাতকে দিনের মধ্যে মিলিয়ে দেন, এবং দিনকে রাতের মধ্যে মিলিয়ে দেন। তিনি সূর্য ও চাঁদকে একটি পূর্বনির্ধারিত সময়কালের জন্য চলতে নিয়োজিত করেছেন। এমনই আল্লাহ তোমাদের প্রভু; সকল রাজত্ব তাঁর। তাঁর পাশে যে উপাস্যই তোমরা স্থাপন করো না কেন তারা একটি বীজেরও মালিক না।"],
  "35:14": ["If you call on them, they cannot hear you. Even if they hear you, they cannot respond to you. On the Day of Resurrection, they will disown you. None can inform you like the Most Cognizant.","যদি তোমরা তাদেরকে ডাকো, তারা শুনতে পারে না। এমনকি যদি তারা তোমাদের ডাক শোনেও, তারা তোমারদের ডাকে সাড়া দিতে পারে না।পুনরুত্থান দিনে, তারা তোমাদের প্রত্যাখ্যান করবে। পরম সর্বজ্ঞের মতো কেউ তোমাকে অবহিত করতে পারবে না।"],
  "35:15": ["O people, you are the ones who need Allah, while Allah is in no need for anyone, the Most Praiseworthy.","হে মানুষ, তোমাদেরই আল্লাহকে প্রয়োজন, যখন আল্লাহর কাউকে কোন প্রয়োজন নেই, পরম প্রশংসনীয়।"],
  "35:16": ["If He wills, He can get rid of you and substitute a new creation.","তিনি যদি চান, তিনি তোমাদের সরিয়ে দিতে পারেন এবং পরিবর্তে নতুন সৃষ্টি করতে পারেন।"],
  "35:17": ["This is not too difficult for Allah.","এটা আল্লাহর জন্য খুব কঠিন নয়।"],
  "35:18": ["No soul can carry the sins of another soul. If a soul that is loaded with sins implores another to bear part of its load, no other soul can carry any part of it, even if they were related. The only people to heed your warnings are those who reverence their Lord, even when alone in their privacy, and observe the Contact Prayers (Salat). Whoever purifies his soul, does so for his own good. To Allah is the final destiny.","কোন আত্মা অন্য আত্মার পাপ বহন করতে পারে না। যদি কোন পাপ ভারাক্রান্ত আত্মা অন্যকাউকে তার ভার বহন করার জন্য ডাকে, অন্যকোন আত্মা এর কোন অংশ বহন করতে পারবে না, এমনকি যদি তারা আত্মীয়ও হয়। একমাত্র সেসব লোকেরাই তোমার সতর্কবার্তায় মনোযোগ দেবে যারা তাদের প্রভুকে ভক্তি করে, এমনকি তাদের একাকীত্বেও; এবং সংযোগ প্রার্থনা (সালাত) পালন করে। যেকেউ তার আত্মাকে পরিশুদ্ধ করে, সে তার নিজের ভালোর জন্য তা করে। আল্লাহর কাছেই চূড়ান্ত নিয়তি।"],
  "35:19": ["The blind and the seer are not equal.","অন্ধ এবং চক্ষুষ্মান সমান নয়।"],
  "35:20": ["Nor are the darkness and the light.","আর না অন্ধকার এবং আলো।"],
  "35:21": ["Nor are the coolness of the shade and the heat of the sun.","না ছায়ার শীতলতা আর সূর্যের তাপ।"],
  "35:22": ["Nor are the living and the dead; Allah causes whomever He wills to hear. You cannot make hearers out of those in the graves.","না জীবিত এবং মৃত; আল্লাহ যাকে ইচ্ছা শুনান। যারা কবরে আছে তাদেরকে তুমি শুনাতে পারো না।"],
  "35:23": ["You are no more than a warner.","তুমি একজন সতর্ককারীর চেয়ে বেশি কিছু নও।"],
  "35:24": ["We have sent you with the truth, a bearer of good news, as well as a warner. Every community must receive a warner.","আমরা তোমাকে পাঠিয়েছি সত্য সহকারে, একজন সুসংবাদ বহনকারী, সেই সাথে সতর্ককারী হিসেবে। প্রত্যেক জনপদ অবশ্যই একজন সতর্ককারী পাবে।"],
  "35:25": ["If they disbelieve you, those before them have also disbelieved. Their messengers went to them with clear proofs, and the Psalms, and the enlightening scriptures.","যদি তারা তোমাকে অবিশ্বাস করে, তাদের পূর্বে যারা ছিল তারাও অবিশ্বাস করেছিল। তাদের বার্তাবাহকেরা তাদের কাছে স্পষ্ট প্রমান, এবং জবুর ও জ্ঞানালোকপূর্ণ ঐশীগ্রন্থ সহ গিয়েছিল,"],
  "35:26": ["Subsequently, I punished those who disbelieved; how terrible was My retribution!","পরবর্তীতে, আমি তাদেরকে শাস্তি দিয়েছিলাম যারা অবিশ্বাস করেছিল; কত ভয়ানক ছিল আমার শাস্তি!"],
  "35:27": ["Do you not realize that Allah sends down from the sky water, whereby we produce fruits of various colors? Even the mountains have different colors; the peaks are white, or red, or some other color. And the ravens are black.","তোমরা কি উপলব্ধি করো না যে আল্লাহ আকাশ থেকে পানি বর্ষন করেণ, যা দ্বারা আমরা বিভিন্ন রঙের ফল উৎপন্ন করি? এমনকি পাহাড়গুলোর রয়েছে বিভিন্ন রঙ; চূড়াগুলো সাদা, অথবা লাল, অথবা অন্য কোন রঙের। এবং দাঁড় কাকগুলো কালো।"],
  "35:28": ["Also, the people, the animals, and the livestock come in various colors. This is why the people who truly reverence Allah are those who are knowledgeable. Allah is Almighty, Forgiving.","এছাড়াও, লোকেরা, প্রানীরা এবং পালিত পশুরা বিভিন্ন রঙের হয়। এ জন্যই আল্লাহকে সত্যিকারভাবে ভক্তি করে সেসব লোকেরা যারা জ্ঞানী। আল্লাহ সর্বশক্তিমান, ক্ষমাশীল।"],
  "35:29": ["Surely, those who recite the book of Allah, observe the Contact Prayers (Salat), and from our provisions to them they spend—secretly and publicly—are engaged in an investment that never loses.","নিশ্চয়, যারা আল্লাহর গ্রন্থ আবৃতি করে, সংযোগ প্রার্থনা (সালাত) পালন করে, এবং আমাদের জীবিকা থেকে তারা ব্যয় করে- গোপনে ও প্রকাশ্যে- তারা জড়িত রয়েছে একটি বিনিয়োগে যাতে কখনই লোকসান হয় না।"],
  "35:30": ["He will recompense them generously, and will multiply His blessings upon them. He is Forgiving, Appreciative.","তিনি তাদেরকে উদারভাবে প্রতিদান দেবেন, এবং তাদের প্রতি তাঁর অনুগ্রহ বহুগুনে বাড়িয়ে দেবেন। তিনি ক্ষমাশীল, গুণগ্রাহী।"],
  "35:31": ["What we revealed to you in this scripture is the truth, consummating all previous scriptures. Allah is fully Cognizant of His servants, Seer.","এই ঐশীগ্রন্থে যা আমরা তোমার কাছে প্রকাশ করেছি তা সত্য, যা পূর্ববর্তী সকল ঐশীগ্রন্থকে পূর্ণতা দেয়। আল্লাহ তাঁর বান্দাদের ব্যাপারে পূর্ণ অবগত, দ্রষ্টা।"],
  "35:32": ["We passed the scripture from generation to generation, and we allowed whomever we chose from among our servants to receive it. Subsequently, some of them wronged their souls, others upheld it only part of the time, while others were eager to work righteousness in accordance with Allah's will; this is the greatest triumph.","আমরা প্রজন্ম থেকে প্রজন্মে ঐশীগ্রন্থ পৌঁছিয়েছি, এবং আমাদের বান্দাদের মধ্যে যাদেরকে আমরা পছন্দ করেছি তাদেরকে এটি গ্রহন করার অনুমতি দিয়েছি। পরবর্তীতে, তাদের কেউ কেউ নিজেদের আত্মার প্রতি অন্যায় করেছিল, অন্যরা শুধু কিছুকালের জন্য একে সমর্থন করেছিল, যেখানে অন্যরা আল্লাহর ইচ্ছানুসারে সৎকর্ম করতে উৎসাহী ছিল, এটাই মহা বিজয়।"],
  "35:33": ["They will enter the gardens of Eden, where they will be adorned with bracelets of gold and pearls, and their garments in it will be made of silk.","তারা ইডেনের বাগানগুলোয় প্রবেশ করবে, যেখানে তাদেরকে সোনা ও মুক্তার কাঁকন দিয়ে সাজানো হবে, এবং সেখানে তাদের পোশাক হবে রেশমের তৈরি।"],
  "35:34": ["They will say, \"Praise Allah for removing all our worries. Our Lord is Forgiving, Appreciative.","তারা বলবে, “প্রশংসা আল্লাহর আমাদের সকল উদ্বেগ দূর করে দেয়ার জন্য। আমাদের প্রভু ক্ষমাশীল, গুণগ্রাহী।"],
  "35:35": ["\"He has admitted us into the abode of eternal bliss, out of His grace. Never do we get bored herein, never do we get tired.\"","“তিনি আমাদেরকে অনন্ত সুখের আবাসে প্রবেশ করিয়েছেন, তাঁর অনুগ্রহে। আমরা কখনই এখানে একঘেয়ে হই না, না কখনো আমরা ক্লান্ত হই।"],
  "35:36": ["As for those who disbelieve, they have incurred the fire of Hell, where they are never finished by death, nor is the retribution ever commuted for them. We thus requite the unappreciative.","তাদের ক্ষেত্রে যারা অবিশ্বাস করে, তারা টেনে এনেছে নরকের আগুন, যেখানে তারা কখনো মৃত্যুর মাধ্যমে শেষ হয় না, না শাস্তি তাদের জন্য কখনো লাঘব করা হয়। আমরা এভাবে অকৃতজ্ঞদের প্রতিফল দেই।"],
  "35:37": ["They will scream therein, \"Our Lord, if you get us out of here, we will work righteousness, instead of the works we used to do.\" Did we not give you a life-long chance, with continuous reminders for those who would take heed? Did you not receive the warner? Therefore, taste (the consequences). The transgressors will have no one to help them.","তারা সেখানে চিৎকার করবে, “আমাদের প্রভু, যদি আপনি এখান থেকে আমাদের বের করেন, আমরা সৎ কাজ করবো, যেসব কাজ আমরা করতাম তার পরিবর্তে”। আমরা কি তোমাদেরকে দীর্ঘ -জীবন দেইনি, সাথে অনবরত সতর্ক বার্তা তাদের জন্য যারা মনোযোগ দিতো? তোমরা কি সতর্ককারী পাওনি? অতএব, (পরিনাম) আস্বাদন করো। তাদেরকে সাহায্য করার জন্য সীমালঙ্ঘনকারীদের কেউ থাকবে না।"],
  "35:38": ["Allah is the Knower of the future of the heavens and the earth. He is the Knower of all innermost thoughts.","আল্লাহ আকাশমণ্ডলী এবং পৃথিবীর ভবিষ্যৎ সম্পর্কে অবগত।  তিনি সকল গভীরতম চিন্তা সম্পর্কে অবগত।"],
  "35:39": ["He is the One who made you inheritors of the earth. Subsequently, whoever chooses to disbelieve does so to his own detriment. The disbelief of the disbelievers only augments their Lord's abhorrence towards them. The disbelief of the disbelievers plunges them deeper into loss.","তিনি সেই সত্তা যিনি তোমাদেরকে পৃথিবীর উত্তরাধিকারী করেছেন। পরবর্তীতে, যেকেউ অবিশ্বাস করাকে পছন্দ করেছে তা তার নিজের ক্ষতির জন্য করেছে। অবিশ্বাসীদের অবিশ্বাস কেবল তাদের প্রতি তাদের প্রভুর ঘৃণাই বৃদ্ধি করে। অবিশ্বাসীদের অবিশ্বাস তাদেরকে ক্ষতির গভীরে নিমজ্জিত করে।"],
  "35:40": ["Say, \"Consider the idols you have set up beside Allah; show me what on earth have they created.\" Do they own any partnership in the heavens? Have we given them a book wherein there is no doubt? Indeed, what the transgressors promise one another is no more than an illusion.","বল, “আল্লাহর পাশে তোমাদের স্থাপন করা উপাস্যদের বিষয়ে ভেবে দেখো; আমাকে দেখাও পৃথিবীতে তারা কি সৃষ্টি করেছে?” তাদের কি কোন অংশীদারিত্ব রয়েছে আকাশমণ্ডলীতে? আমরা কি তাদেরকে কোন গ্রন্থ দিয়েছি যাতে কোন সন্দেহ নেই? নিশ্চয়, যা সীমালঙ্ঘনকারীরা পরস্পরকে অঙ্গীকার করে তা এক  বিভ্রমের চেয়ে বেশি কিছু নয়।"],
  "35:41": ["Allah is the One who holds the heavens and the earth, lest they vanish. If anyone else is to hold them, they will most certainly vanish. He is Clement, Forgiving.","আল্লাহ সেই সত্তা যিনি আকাশমণ্ডলী ও পৃথিবীকে ধরে আছেন, অন্যথায় সেগুলো মিলিয়ে যেতো। যদি অন্যকাউকে সেগুলো ধরতে হয়, সেগুলো অবশ্যই মিলিয়ে যাবে। আল্লাহ সহিষূ, ক্ষমাশীল।"],
  "35:42": ["They swore by Allah solemnly that if a warner went to them, they would be better guided than a certain congregation! However, now that the warner did come to them, this only plunged them deeper into aversion.","তারা ঈশরের নামে জোড়ালো শপথ করতো যে যদি কোন সতর্ককারী তাদের কাছে আসতো, তারা একটি নির্দিষ্ট জনপদ থেকে উত্তম পথপ্রাপ্ত হতো! কিন্তু, এখন যখন সতর্ককারী তাদের কাছে আসলো, এটি শুধু তাদেরকে আরো গভীর বিমুখতায় নিমজ্জিত করলো।"],
  "35:43": ["They resorted to arrogance on earth, and evil scheming, and the evil schemes only backfire on those who scheme them. Should they then expect anything but the fate of those who did the same things in the past? You will find that Allah's system is never changeable; you will find that Allah's system is immutable.","তারা পৃথিবীতে ঔদ্ধত্য, এবং মন্দ ষড়যন্ত্র  অবলম্বন করেছিল, আর মন্দ ষড়যন্ত্র উল্টো তাদের উপরই এসে পড়ে যারা সেগুলোর পরিকল্পনা করে। তবে কি ওদের উচিত তাদের ভাগ্য ছাড়া অন্যকিছু আশা করা যারা অতীতে একই জিনিস করেছিলো? তুমি দেখবে যে আল্লাহর নিয়ম কখনই পরিবর্তনশীল নয়; তুমি দেখবে যে আল্লাহর নিয়ম অপরিবর্তনীয়।"],
  "35:44": ["Have they not roamed the earth and noted the consequences for those who preceded them? They were even stronger than they. Nothing can be hidden from Allah in the heavens, nor on earth. He is Omniscient, Omnipotent.","তারা কি পৃথিবীতে ঘোরেনি এবং তাদের পূর্বে যারা ছিল তাদের পরিনাম লক্ষ্য করেনি? তারা এমনকি তাদের থেকে অধিক শক্তিশালী ছিল। আকাশমণ্ডলীতে কোনোকিছুই আল্লাহ থেকে গোপন থাকতে পারে না, না পৃথিবীতে। তিনি সর্বজ্ঞ, সর্বশক্তিমান।"],
  "35:45": ["If Allah punished the people for their sins, He would not leave a single creature on earth. But He respites them for a predetermined interim. Once their interim is fulfilled, then Allah is Seer of His servants.","যদি আল্লাহ মানুষকে তাদের পাপের জন্য শাস্তি দিতেন, তিনি পৃথিবীতে একটি সৃষ্টিকেও ছাড়তেন না। কিন্তু তিনি তাদেরকে এক পূর্বনির্ধারিত মেয়াদকাল পর্যন্ত অবকাশ দেন। একবার তাদের মেয়াদকাল সম্পূর্ণ হয়ে গেলে, তখন আল্লাহ তাঁর বান্দাদের দ্রষ্টা।"],
  "36:1": ["Y. S.","য়. শ. (ইয়া, সিন)"],
  "36:2": ["And the Quran that is full of wisdom.","এবং কুরআন যা প্রজ্ঞায় পরিপূর্ণ।"],
  "36:3": ["Most assuredly, you (Rashad) are one of the messengers.","অবশ্যই, তুমি (রাশাদ) বার্তাবাহকদের একজন।"],
  "36:4": ["On a straight path.","এক সরল পথের উপর।"],
  "36:5": ["This revelation is from the Almighty, Most Merciful.","এই প্রকাশনা সর্বশক্তিমান, পরম দয়ালুর পক্ষ থেকে।"],
  "36:6": ["To warn people whose parents were never warned, and therefore, they are unaware.","সে লোকদের সতর্ক করতে যাদের পিতামাতাদেরকে কখনো সতর্ক করা হয়নি, আর সেজন্য, তারা অসচেতন।"],
  "36:7": ["It has been predetermined that most of them do not believe.","এটা পূর্ব-নির্ধারিত যে তাদের বেশির ভাগ বিশ্বাস করে না।"],
  "36:8": ["For we place around their necks shackles, up to their chins. Consequently, they become locked in their disbelief.","কারন আমরা তাদের ঘাড়ে শৃঙ্খল পড়াই, তাদের চিবুক পর্যন্ত। ফলস্বরুপ, তারা তাদের অবিশ্বাসে আবদ্ধ হয়ে যায়।"],
  "36:9": ["And we place a barrier in front of them, and a barrier behind them, and thus, we veil them; they cannot see.","এবং আমরা তাদের সামনে একটি অন্তরায়, এবং তাদের পেছনে একটি অন্তরায় রাখি, আর এভাবে, আমরা তাদের পর্দাবৃত করি; তারা দেখতে পারে না।"],
  "36:10": ["It is the same whether you warn them or not, they cannot believe.","তুমি তাদেরকে সতর্ক কর অথবা না কর উভয় তাদের জন্য সমান, তারা বিশ্বাস করতে পারে না।"],
  "36:11": ["You will be heeded only by those who uphold this message, and reverence the Most Gracious—even when alone in their privacy. Give them good news of forgiveness and a generous recompense.","তোমার কথায় কেবল তারাই মনোযোগ দেবে যারা এই বার্তা মেনে চলে, এবং পরম করুণাময়কে ভক্তি করে- এমনকি তাদের একাকীত্বেও। তাদেরকে ক্ষমা এবং এক মহা প্রতিদানের সুসংবাদ দাও।"],
  "36:12": ["We will certainly revive the dead, and we have recorded everything they have done in this life, as well as the consequences that continue after their death. Everything we have counted in a profound record.","আমরা অবশ্যই মৃতকে পুনরুজ্জীবিত করবো, এবং আমরা সবকিছু নথিভুক্ত করেছি যা তারা এই জীবনে করেছে, সেই সাথে তার পরিণাম যা তাদের মৃত্যুর পরেও চলে। সবকিছু আমরা একটি সুস্পষ্ট নথিতে গুনে রেখেছি।"],
  "36:13": ["Cite for them the example of people in a community that received the messengers.","তাদের জন্য এক জনপদের লোকদের উদাহরণ বর্ণনা কর যারা বার্তাবাহকদের পেয়েছিল।"],
  "36:14": ["When we sent to them two (messengers), they disbelieved them. We then supported them by a third. They said, \"We are (Allah's) messengers to you.\"","যখন আমরা তাদের কাছে দুই জন (বার্তাবাহক) পাঠালাম, তারা তাদের অবিশ্বাস করল। আমরা তখন তৃতীয় জনের দ্বারা তাদের সমর্থন করলাম। তারা বলল, “আমরা তোমাদের কাছে (আল্লাহর) বার্তাবাহক”।"],
  "36:15": ["They said, \"You are no more than human beings like us. The Most Gracious did not send down anything. You are liars.\"","তারা বলল, “তোমরা তো আমাদের মত মানুষের চেয়ে বেশি কিছু নও। পরম করুণাময় কোন কিছু অবতীর্ণ করেননি। তোমরা মিথ্যাবাদী।\""],
  "36:16": ["They said, \"Our Lord knows that we have been sent to you.","তারা বলল, “আমাদের প্রভু জানেন যে আমাদেরকে তোমাদের কাছে পাঠানো হয়েছে।"],
  "36:17": ["\"Our sole mission is to deliver the message.\"","আমাদের একমাত্র উদ্দেশ্য বার্তা পৌঁছে দেওয়া।\""],
  "36:18": ["They said, \"We consider you bad omens. Unless you refrain, we will surely stone you, or afflict you with painful retribution.\"","তারা বলল, “আমরা তোমাদেরকে অমঙ্গলের কারন মনে করি। যদি তোমরা বিরত না হও, আমরা অবশ্যই তোমাদের পাথর মারব, অথবা যন্ত্রণাদায়ক শাস্তি ভোগ করাবো।\""],
  "36:19": ["They said, \"Your omen depends on your response, now that you have been reminded. Indeed, you are transgressing people.\"","তারা বলল, “তোমাদের মঙ্গল-অমঙ্গল তোমাদের সাড়াদানের উপর নির্ভর করে, যেহেতু এখন তোমাদেরকে স্মরণ করিয়ে দেয়া হয়েছে। নিশ্চয়, তোমরা সীমালঙ্ঘনকারী লোক।\""],
  "36:20": ["A man came from the other end of the city, saying, \"O my people, follow the messengers.","একজন লোক শহরের অন্য প্রান্ত থেকে আসলো, বলার জন্য যে, “হে আমার লোকেরা, বার্তাবাহকদের অনুসরন করো।\""],
  "36:21": ["\"Follow those who do not ask you for any wage, and are guided.","“তাদের অনুসরন করো যারা তোমাদের কাছে কোন পারিশ্রমিক চায় না, এবং সুপথপ্রাপ্ত।"],
  "36:22": ["\"Why should I not worship the One who initiated me, and to Him is your ultimate return?","“কেন আমি সেই সত্তার উপাসনা করবো না যিনি আমার সুচনা করেছেন এবং তাঁর দিকেই তোমাদের চূড়ান্ত প্রত্যাবর্তন।"],
  "36:23": ["\"Shall I set up beside Him gods? If the Most Gracious willed any harm for me, their intercession cannot help me one bit, nor can they rescue me.","“তাঁর পাশে আমি কি উপাস্য স্থাপন করবো? যদি পরম করুণাময় আমার জন্য কোন ক্ষতি চান, তাদের সুপারিশ আমাকে সামান্যতম সাহায্যও করতে পারবে না, না তারা আমাকে উদ্ধার করতে পারবে।"],
  "36:24": ["\"In that case, I would be totally astray.","“সেক্ষেত্রে, আমি সম্পূর্ণ পথভ্রষ্ট হব।"],
  "36:25": ["\"I have believed in your Lord; please listen to me.\"","“আমি তোমাদের প্রভুকে বিশ্বাস করেছি; দয়া করে আমার কথা শোন।\""],
  "36:26": ["(At the time of his death) he was told, \"Enter Paradise.\" He said, \"Oh, I wish my people knew.","(তার মৃত্যুর সময়) তাকে বলা হল, “স্বর্গে প্রবেশ করো”। সে বলল, “আহা। আমার লোকেরা যদি জানতো।\""],
  "36:27": ["\"That my Lord has forgiven me, and made me honorable.\"","“যে আমার প্রভু আমাকে ক্ষমা করেছেন, এবং আমাকে সন্মানিত করেছেন।\""],
  "36:28": ["We did not send down upon his people, after him, soldiers from the sky; we did not need to send them down.","তার পর আমরা তার লোকদের উপর আকাশ থেকে কোন সৈন্যবাহিনী অবতীর্ণ করিনি; তাদের অবতীর্ণ করার কোন প্রয়োজন আমাদের ছিল না।"],
  "36:29": ["All it took was one blow, whereupon they were stilled.","এটা কেবল ছিল একটি বিকট শব্দ, যার ফলে তারা স্তব্ধ হয়ে গেল।"],
  "36:30": ["How sorry is the people's condition! Every time a messenger went to them, they always ridiculed him.","কতটা দুঃখজনক লোকদের অবস্থা! যখনই কোন বার্তাবাহক তাদের কাছে গিয়েছে, তারা সবসময় তাকে উপহাস করেছে।"],
  "36:31": ["Did they not see how many generations we annihilated before them, and how they never return to them?","তারা কি দেখেনি যে তাদের আগে কত প্রজন্মকে আমরা ধ্বংস করেছি, এবং তারা কখনই তাদের কাছে ফিরে আসে না?"],
  "36:32": ["Every one of them will be summoned before us.","তাদের প্রত্যেককেই আমাদের সামনে তলব করা হবে।"],
  "36:33": ["One sign for them is the dead land: we revive it and produce from it grains for their food.","তাদের জন্য একটি নিদর্শন হলো মৃত ভুমিঃ আমরা একে পুনর্জীবিত করি এবং তাদের খাদ্যের জন্য তা থেকে শস্য উৎপাদন করি।"],
  "36:34": ["We grow in it gardens of date palms, and grapes, and we cause springs to gush out therein.","আমরা এতে উৎপাদন করি খেজুর ও আঙ্গুরের বাগান, এবং এর মধ্যে আমরা ঝর্ণাধারা উৎসারিত করি।"],
  "36:35": ["This is to provide them with fruits, and to let them manufacture with their own hands whatever they need. Would they be thankful?","তাদেরকে ফল-ফলাদি প্রদান করার জন্য, এবং তাদের নিজেদের হাতে উৎপন্ন করতে দেয়ার জন্য যা কিছু তাদের প্রয়োজন। তারা কি কৃতজ্ঞ হবে?"],
  "36:36": ["Glory be to the One who created all kinds of plants from the earth, as well as themselves, and other creations that they do not even know.","মহিমা সে সত্তার যিনি পৃথিবীতে সকল প্রকার গাছপালা সৃষ্টি করেছেন, আর তাদেরকেও, এবং অন্যান্য সৃষ্টিকূল যা তারা এমনকি জানেও না।"],
  "36:37": ["Another sign for them is the night: we remove the daylight therefrom, whereupon they are in darkness.","তাদের জন্য আরেকটি নিদর্শন হলো রাতঃ সেখান থেকে আমরা দিনের আলো দূর করি, যার ফলে তারা অন্ধকারাচ্ছন্ন হয়।"],
  "36:38": ["The sun sets into a specific location, according to the design of the Almighty, the Omniscient.","সূর্য একটি নির্দিষ্ট অবস্থানে অস্ত যায়, সর্বশক্তিমান, সর্বজ্ঞের নকশা অনুসারে।"],
  "36:39": ["The moon we designed to appear in stages, until it becomes like an old curved sheath.","আমরা চাঁদকে পর্যায়সমূহে দৃশ্যমান হবার জন্য নকশা করেছি, যতক্ষণ না এটি একটি পুরাতন বাঁকা আবরনের মত হয়ে যায়।"],
  "36:40": ["The sun is never to catch up with the moon—the night and the day never deviate—each of them is floating in its own orbit.","সূর্য কখনো চাঁদকে ধরতে পারে না- রাত এবং দিন কখনো বিচ্যুত হয় না-তাদের প্রত্যেকে এর নিজের কক্ষপথে ভাসছে।"],
  "36:41": ["Another sign for them is that we carried their ancestors on the loaded ark.","তাদের জন্য আরেকটি নিদর্শন হলো যে তাদের  পূর্বপুরুষদের আমরা বোঝাই নৌযানে আরোহণ করিয়েছি।"],
  "36:42": ["Then created the same for them to ride in.","অতঃপর তাদের আরোহণ করার জন্যও একই রকম সৃষ্টি করেছি।"],
  "36:43": ["If we willed, we could have drowned them, so that their screaming would not be heard, nor could they be saved.","আমরা যদি চাইতাম, আমরা তাদের ডুবিয়ে দিতে পারতাম, যাতে করে তাদের চিৎকার না শোনা যায়, না তারা রক্ষা পেতে পারে।"],
  "36:44": ["Instead, we shower them with mercy, and let them enjoy for awhile.","উপরন্তু, আমরা তাদের উপর করুনা বর্ষণ করেছি, এবং কিছু সময়ের জন্য তাদেরকে উপভোগ করতে দিয়েছি।"],
  "36:45": ["Yet, when they are told, \"Learn from your past, to work righteousness for your future, that you may attain mercy,\"","তা সত্ত্বেও, যখন তাদের বলা হয়, “তোমাদের অতীত থেকে শিক্ষা নিয়ে তোমাদের ভবিষ্যতে সৎকর্ম করো, যাতে তোমরা দয়া পেতে পারো,”"],
  "36:46": ["No matter what kind of proof is given to them from their Lord, they consistently disregard it.","তাদেরকে যে প্রমাণই তাদের প্রভুর পক্ষ থেকে দেয়া হোক না কেন, তারা তা অনবরত উপেক্ষা করে।"],
  "36:47": ["When they are told, \"Give from Allah's provisions to you,\" those who disbelieve say to those who believe, \"Why should we give to those whom Allah could feed, if He so willed? You are really far astray.\"","যখন তাদের বলা হয়, “তোমাদেরকে আল্লাহর দেয়া জীবিকা থেকে দাও, যারা অবিশ্বাস করে তারা তাদেরকে বলে যারা বিশ্বাস করে, “কেন আমরা তাদেরকে দিতে যাবো যাদেরকে আল্লাহ খাওয়াতে পারেন, যদি তিনি তা চান? তোমরা প্রকৃতই বহুদূর পথভ্রষ্ট।”"],
  "36:48": ["They also challenge, \"When will that promise come to pass, if you are truthful?\"","তারা আরো চ্যালেঞ্জ করে, “কখন সেই অঙ্গিকার পূর্ণ হবে, যদি তোমরা সত্যবাদী হও?”"],
  "36:49": ["All they see will be one blow that overwhelms them, while they dispute.","তারা কেবল দেখবে ভয়াবহ শব্দ যা তাদের আচ্ছন্ন করবে, যখন তারা বিবাদ করে।"],
  "36:50": ["They will not even have time to make a will, nor will they be able to return to their people.","এমনকি অছিয়তনামা করারও কোন সময় তাদের থাকবে না, না তারা তাদের লোকদের কাছে ফিরে যেতে সমর্থ হবে।"],
  "36:51": ["The horn will be blown, whereupon they will rise from the grave and go to their Lord.","শিঙ্গায় ফুঁ দেওয়া হবে, যার ফলে তারা কবর থেকে জেগে উঠবে এবং তাদের প্রভুর কাছে যাবে।"],
  "36:52": ["They will say, \"Woe to us. Who resurrected us from our death? This is what the Most Gracious has promised. The messengers were right.\"","তারা বলবে, “কতই না দুঃখ আমাদের। কে আমাদেরকে পুনরুত্থিত করলো আমাদের মৃত্যু থেকে? এটাই তো পরম করুণাময় অঙ্গিকার করেছিলেন। বার্তাবাহকরা ঠিক ছিল।”"],
  "36:53": ["All it will take is one blow, whereupon they are summoned before us.","শুধুমাত্র একটি বিকট শব্দ হবে, যার ফলে তাদেরকে আমাদের সামনে একত্রিত করা হবে।"],
  "36:54": ["On that day, no soul will be wronged in the least. You will be paid precisely for whatever you did.","সেই দিন, কোন আত্মার প্রতি সামান্যতম অন্যায় করা হবে না। তোমরা যাকিছু করেছিলে ঠিক তার জন্যই প্রতিদান পাবে।"],
  "36:55": ["The dwellers of Paradise will be, on that day, happily busy.","সেদিন, স্বর্গের বাসিন্দারা সানন্দে ব্যাস্ত থাকবে।"],
  "36:56": ["They abide with their spouses in beautiful shade, enjoying comfortable furnishings.","তারা তাদের সঙ্গিদের সাথে চমৎকার ছায়ায় বাস করে, উপভোগ করে আরামদায়ক আসবাবপত্র।"],
  "36:57": ["They will have fruits therein; they will have anything they wish.","সেখানে তাদের থাকবে ফল-ফলাদি, তারা যা চায় সবকিছু পাবে।"],
  "36:58": ["Greetings of peace from a Most Merciful Lord.","পরম করুণাময় প্রভুর পক্ষ থেকে শান্তির অভিবাদন।"],
  "36:59": ["As for you, O guilty ones, you will be set aside.","আর তোমাদের ক্ষেত্রে, হে অপরাধীরা, তোমাদেরকে আলাদা রাখা হবে।"],
  "36:60": ["Did I not covenant with you, O Children of Adam, that you shall not worship the devil? That he is your most ardent enemy?","আমি কি তোমাদের থেকে অঙ্গিকার নেইনি, হে আদম সন্তানেরা, যে, তোমরা শয়তানের উপাসনা করবে না? কেননা, সে তোমাদের ঘোরতম শত্রু?"],
  "36:61": ["And that you shall worship Me alone? This is the right path.","এবং যে তোমরা কেবল আমার উপাসনা করবে? এটাই সঠিক পথ।"],
  "36:62": ["He has misled multitudes of you. Did you not possess any understanding?","সে তোমাদের বহু সংখ্যককে পথভ্রষ্ট করেছে। তোমাদের কি কোন বুঝার ক্ষমতা নেই ?"],
  "36:63": ["This is the Hell that was promised for you.","এটা সেই নরক তোমাদেরকে যার প্রতিশ্রুতি দেয়া হয়েছিল।"],
  "36:64": ["Today you will burn in it, as a consequence of your disbelief.","আজ তোমরা এতে পুড়বে, তোমাদের অবিশ্বাসের ফলস্বরূপ।"],
  "36:65": ["On that day we will seal their mouths; their hands and feet will bear witness to everything they had done.","সে দিন আমরা তাদের মুখে মোহর এঁটে দেব তালা দেব; তাদের হাত ও পা সবকিছুর সাক্ষী দেবে যা তারা করেছিল।"],
  "36:66": ["If we will, we can veil their eyes and, consequently, when they seek the path, they will not see.","যদি আমরা চাই, আমরা তাদের চোখ পর্দাবৃত করতে পারি এবং, পরিনামে, যখন তারা পথ খুঁজবে, তারা দেখবে না।"],
  "36:67": ["If we will, we can freeze them in place; thus, they can neither move forward, nor go back.","যদি আমরা চাই, আমরা সেখানেই তাদেরকে স্থির করে দিতে পারি; ফলে, না তারা সামনে এগোতে পারে, না পিছনে যেতে পারে।"],
  "36:68": ["Whomever we permit to live for a long time, we revert him to weakness. Do they not understand?","যাকেই আমরা দীর্ঘ জীবন দেই, তাকে আমরা দুর্বলতায় ফিরিয়ে নেই। তারা কি বোঝে না?"],
  "36:69": ["What we taught him (the messenger) was not poetry, nor is he (a poet). This is but a formidable proof, and a profound Quran.","যা আমরা তাকে (বার্তাবাহককে) শিখিয়েছিলাম তা কবিতা ছিল না, না সে (একজন কবি)। এটা তো এক অকাট্য প্রমান, এবং জ্ঞানগর্ভ কুরআন।"],
  "36:70": ["To preach to those who are alive, and to expose the disbelievers.","তাদের কাছে প্রচার করতে যারা জীবিত, এবং অবিশ্বাসীদের প্রকাশ করতে।"],
  "36:71": ["Have they not seen that we created for them, with our own hands, livestock that they own?","তারা কি দেখেনি যে আমরা তাদের জন্য সৃষ্টি করেছি, আমাদের নিজেদের হাতে, পালিত পশু, তারা যেগুলোর মালিক?"],
  "36:72": ["And we subdued them for them; some they ride, and some they eat.","এবং আমরা সেগুলোকে তাদের জন্য বশীভূত করে দিয়েছি; কতকগুলোর উপর তারা আরোহণ করে,  আর কতকগুলো তারা খায়।"],
  "36:73": ["They derive other benefits from them, as well as drinks. Would they not be appreciative?","তারা সেগুলো  থেকে অন্য সুবিধা পায়, সেইসাথে পানীয়। তারা কি কৃতজ্ঞ হবে না?"],
  "36:74": ["They set up beside Allah other gods, perhaps they can be of help to them!","তারা আল্লাহর পাশে অন্য উপাস্য স্থাপন করে, হয়তো তারা তাদেরকে সাহায্য করতে পারবে!"],
  "36:75": ["On the contrary, they cannot help them; they end up serving them as devoted soldiers.","পক্ষান্তরে, তারা তাদের সাহায্য করতে পারে না; তারা শেষপর্যন্ত তাদের প্রতি নিবেদিত সৈন্য হিসেবে কাজ করতে থাকে।"],
  "36:76": ["Therefore, do not be saddened by their utterances. We are fully aware of everything they conceal and everything they declare.","অতএব, তাদের কথায় দুঃখিত হইও না। আমরা সম্পূর্ণ অবগত সেসব কিছুর ব্যাপারে যা তারা গোপন করে এবং সবকিছু যা তারা প্রকাশ করে।"],
  "36:77": ["Does the human being not see that we created him from a tiny drop, then he turns into an ardent enemy?","মানুষ কি দেখে না যে আমরা তাকে একটি ক্ষুদ্র ফোঁটা থেকে সৃষ্টি করেছি, এরপর সে ঘোর শত্রুতে পরিণত হয়?"],
  "36:78": ["He raises a question to us—while forgetting his initial creation—\"Who can resurrect the bones after they had rotted?\"","সে আমাদের কাছে প্রশ্ন উত্থাপন করে- যখন ভুলে যায় তার প্রথম সৃষ্টিকে- “কে হাড়গুলো পুনরূজ্জীবিত করতে পারে সেগুলো পচেঁ যাবার পর?”"],
  "36:79": ["Say, \"The One who initiated them in the first place will resurrect them. He is fully aware of every creation.\"","বল, “সে সত্তা তাদেরকে পুনরুত্থিত করবেন যিনি প্রথম বার তাদের সূচনা করেছিলেন। তিনি সকল সৃষ্টি সম্পর্কে পূর্ণ অবগত”।"],
  "36:80": ["He is the One who creates for you, from the green trees, fuel which you burn for light.","তিনি সে সত্তা যিনি তোমাদের জন্য সৃষ্টি করেছেন, সবুজ গাছপালা থেকে, জ্বালানী যা তোমরা আলোর জন্য পোড়াও।"],
  "36:81": ["Is not the One who created the heavens and the earth able to recreate the same? Yes indeed; He is the Creator, the Omniscient.","যে সত্তা আকাশমণ্ডলী এবং পৃথিবী সৃষ্টি করেছেন তিনি কি একই জিনিস পুনরায় সৃষ্টি করতে সক্ষম নন? হ্যা নিশ্চয়; তিনি সৃষ্টিকর্তা, সর্বজ্ঞ।"],
  "36:82": ["All He needs to do to carry out any command is say to it, \"Be,\" and it is.","কোন আদেশ সম্পন্ন করার জন্য এটিকে শুধু তাঁর বলতে হয়, “হও”আর তা হয়ে যায়।"],
  "36:83": ["Therefore, glory be to the One in whose hand is the sovereignty over all things, and to Him you will be returned.","অতএব, মহিমা সে সত্তার যার হাতে সবকিছুর উপর সর্বভৌম ক্ষমতা রয়েছে, এবং তাঁর কাছে তোমরা ফিরে যাবে।"],
  "37:1": ["The arrangers in columns.","সারিবদ্ধ সুবিন্যাসকারী।"],
  "37:2": ["The blamers of those to be blamed.","তাদের দোষারোপকারী যাদের প্রতি দোষারোপ করা হবে।"],
  "37:3": ["The reciters of the messages.","বার্তাসমূহের আবৃতিকারী।"],
  "37:4": ["Your god is only one.","তোমাদের উপাস্য কেবল একজন।"],
  "37:5": ["The Lord of the heavens and the earth, and everything between them, and Lord of the easts.","আকাশমন্ডলী ও পৃথিবী, এবং তাদের মধ্যকার সবকিছুর প্রভু, এবং পূর্বসমূহের প্রভু।"],
  "37:6": ["We have adorned the lowest heaven with adorning planets.","আমরা নিম্নতম আকাশকে সৌন্দর্যমন্ডিত গ্রহ দিয়ে সাজিয়েছি।"],
  "37:7": ["We guarded it from every evil devil.","আমরা একে প্রত্যেক মন্দ শয়তান থেকে সুরক্ষিত করেছি।"],
  "37:8": ["They cannot spy on the High Society; they get bombarded from every side.","তারা উর্ধ্ব সমাজে গুপ্তচরবৃত্তি করতে পারে না। প্রত্যেক পাশ থেকে তাদের দিকে বিস্ফোরক ছোড়া হয়।"],
  "37:9": ["They have been condemned; they have incurred an eternal retribution.","তারা দোষী সাব্যস্ত হয়েছে; তারা টেনে এনেছে এক চিরস্থায়ী শাস্তি।"],
  "37:10": ["If any of them ventures to charge the outer limits, he gets struck with a fierce projectile.","যদি তাদের কেউ শেষ সীমায় অনুপ্রবেশের স্পর্ধা দেখায়, সে এক ভয়ংকর উৎক্ষেপক দ্বারা আঘাতপ্রাপ্ত হয়।"],
  "37:11": ["Ask them, \"Are they more difficult to create, or the other creations?\" We created them from wet mud.","তাদের জিজ্ঞেস করো, “তাদেরকে সৃষ্টি করা কি বেশি কঠিন, না অন্যসব সৃষ্টি?” আমরা তাদেরকে কাদামাটি থেকে সৃষ্টি করেছি।"],
  "37:12": ["While you are awed, they mock.","যখন তুমি বিস্মিত হও, তারা উপহাস করে।"],
  "37:13": ["When reminded, they take no heed.","যখন স্মরণ করিয়ে দেয়া হয়, তারা কোন মনোযোগ দেয় না।"],
  "37:14": ["When they see proof, they ridicule it.","যখন তারা প্রমান দেখে, তারা এর ব্যঙ্গ-বিদ্রুপ করে।"],
  "37:15": ["They say, \"This is obviously magic!","তারা বলে, \"এটা স্পষ্টই জাদু!"],
  "37:16": ["\"After we die and become dust and bones, do we get resurrected?","\"আমরা মরে ধূলিকণা এবং হাড় হয়ে যাবার পরেও কি আমরা পুনরুত্থিত হবো?"],
  "37:17": ["\"Even our ancient ancestors?\"","\"এমনকি আমাদের প্রাচীন পূর্বপুরুষেরাও?\""],
  "37:18": ["Say, \"Yes, you will be forcibly summoned.\"","বল, \"হ্যা, তোমাদের জোড়পুর্বক তলব করা হবে।\""],
  "37:19": ["All it takes is one nudge, whereupon they (stand up) looking.","কেবল একটি মৃদু দাক্কাই যথেষ্ট, যার ফলে তারা (দাঁড়িয়ে) দেখতে থাকবে।"],
  "37:20": ["They will say, \"Woe to us; this is the Day of Judgment.\"","তারা বলবে, \"দুর্ভাগ্য আমাদের; এটাই সে বিচার দিবস।\""],
  "37:21": ["This is the day of decision that you used to disbelieve in.","এটাই সে সিদ্ধান্তের দিন যাতে তোমরা অবিশ্বাস করতে।"],
  "37:22": ["Summon the transgressors, and their spouses, and the idols they worshiped","তলব করো সীমালঙ্ঘনকারীদের, এবং তাদের সঙ্গীদের, এবং সে উপাস্যদের যাদেরকে তারা উপাসনা করতো"],
  "37:23": ["beside Allah, and guide them to the path of Hell.","আল্লাহর পাশে, এবং তাদেরকে নরকের পথ দেখাও।"],
  "37:24": ["Stop them, and ask them:","তাদেরকে থামাও, আর জিজ্ঞেস করো:"],
  "37:25": ["\"Why do you not help one another?\"","কেন তোমরা একে অন্যকে সাহায্য করো না?\""],
  "37:26": ["They will be, on that day, totally submitting.","তারা হবে, ঐদিন, পুরোপুরি সমর্পিত।"],
  "37:27": ["They will come to each other, questioning and blaming one another.","তারা একে অন্যের কাছে আসবে, পরস্পরকে প্রশ্ন এবং দোষারোপ করতে করতে।"],
  "37:28": ["They will say (to their leaders), \"You used to come to us from the right side.\"","তারা (তাদের নেতাদের) বলবে, \"তোমরা আমাদের কাছে ডান পাশ থেকে আসতে।\""],
  "37:29": ["They will respond, \"It is you who were not believers.","তারা উত্তর দিবে, \"তোমরাই তো বিশ্বাসী ছিলে না।"],
  "37:30": ["\"We never had any power over you; it is you who were wicked.","\"তোমাদের উপর আমাদের কোন ক্ষমতা ছিল না; তোমরাই অন্যায়কারী ছিলে।"],
  "37:31": ["\"We justly incurred our Lord's judgment; now we have to suffer.","\"আমরা আমাদের প্রভুর ন্যায্য বিচার পেয়েছি; এখন আমাদের ভোগ করতে হবে।"],
  "37:32": ["\"We misled you, only because we were astray.\"","\"আমরা তোমাদের ভুল পথে চালিয়েছি, কেবল একারনে যে আমরাই পথভ্রষ্ট ছিলাম।"],
  "37:33": ["Thus, together they will all partake of the retribution on that day.","সুতরাং, একসাথে তারা সবাই ঐদিন শাস্তির ভাগী হবে।"],
  "37:34": ["This is how we requite the guilty.","এভাবেই আমরা অপরাধীদের প্রতিফল দেই।"],
  "37:35": ["When they were told, \"Lã Elãha Ella Allãh (There is no other god beside Allah),\" they turned arrogant.","যখন তাদের বলা হতো, \"লা ইলাহা ইল্লাহ [আল্লাহর পাশে অন্যকোন উপাস্য নেই],” তারা উদ্ধত হয়ে পড়তো।"],
  "37:36": ["They said, \"Shall we leave our gods for the sake of a crazy poet?\"","তারা বলতো, \"আমরা কি একজন পাগল কবির জন্য আমাদের উপাস্যদের ত্যাগ করবো।"],
  "37:37": ["In fact, he has brought the truth, and has confirmed the messengers.","প্রকৃতপক্ষে, সে সত্য এনেছে, এবং বার্তাবাহকদের নিশ্চিত করেছে।"],
  "37:38": ["Most assuredly, you will taste the most painful retribution.","নিশ্চয়, তোমরা সবচেয়ে যন্ত্রণাকর শাস্তি আস্বাদন করবে।"],
  "37:39": ["You are requited only for what you have done.","তোমরা যা করেছ শুধু তার জন্য প্রতিফল পাও।"],
  "37:40": ["Only Allah's servants who are absolutely devoted to Him alone (will be saved).","শুধু আল্লাহর বান্দারা (রক্ষা পাবে) যারা সম্পূর্ণভাবে কেবল তার প্রতি নিবেদিত।"],
  "37:41": ["They have deserved provisions that are reserved specifically for them.","তারা সে জীবিকার যোগ্য  হয়েছে যা বিশেষভাবে তাদের জন্য সংরক্ষিত।"],
  "37:42": ["All kinds of fruits. They will be honored.","সকল প্রকার ফল। তারা হবে সম্মানিত।"],
  "37:43": ["In the gardens of bliss.","পরম সুখের বাগানগুলোয়।"],
  "37:44": ["On furnishings close to one another.","আসবাবপত্রের উপর পরস্পর কাছাকাছি।"],
  "37:45": ["Cups of pure drinks will be offered to them.","তাদেরকে বিশুদ্ধ পানীয়ের পেয়ালা পরিবেশন করা হবে।"],
  "37:46": ["Clear and delicious for the drinkers.","পানকারীদের জন্য স্বচ্ছ ও সুস্বাদু।"],
  "37:47": ["Never polluted, and never exhausted.","কখনো দূষিত নয়, এবং কখনো অবসাদগ্রস্থ করে না।"],
  "37:48": ["With them will be wonderful companions.","তাদের সাথে থাকবে চমৎকার সাথীরা।"],
  "37:49": ["Protected like fragile eggs.","ভঙ্গুর ডিমের মতো সুরক্ষিত।"],
  "37:50": ["They will come to each other, and confer with one another.","তারা পরস্পরের কাছে আসবে, এবং একে অন্যের সাথে পরামর্শ করবে।"],
  "37:51": ["One of them will say, \"I used to have a friend.","তাদের একজন বলবে, \"আমার এক বন্ধু ছিল।"],
  "37:52": ["\"He used to mock: 'Do you believe all this?","\"সে উপহাস করতো: 'তুমি কি এইসব বিশ্বাস করো?"],
  "37:53": ["\" 'After we die and turn into dust and bones, do we get called to account?' \"","\"'আমরা মরে ধুলো এবং হাড়ে পরিণত হবার পরেও কি আমাদেরকে হিসাবের জন্য ডাকা হবে?'\""],
  "37:54": ["He will say, \"Just take a look!\"","সে বলবে, \"একটু তাকিয়ে দেখো!\""],
  "37:55": ["When he looks, he will see his friend in the heart of Hell.","যখন সে তাকাবে, সে তার বন্ধুকে নরকের গভীরে দেখবে।"],
  "37:56": ["He (will go to him and) say, \"By Allah, you almost ruined me.","সে (তার কাছে যাবে এবং) বলবে, \"আল্লাহর শপথ, তুমি তো আমাকে প্রায় ধ্বংসই করে দিয়েছিলে।"],
  "37:57": ["\"If it were not for my Lord's blessing, I would have been with you now.","\"যদি আমার প্রভুর অনুগ্রহ না থাকতো, এখন আমি হয়তো তোমার সাথে থাকতাম।"],
  "37:58": ["\"(Do you still believe) that we die,","\"(তুমি কি এখনও বিশ্বাস করো) যে আমরা মারা যাই, \""],
  "37:59": ["\"only the first death, and we never receive any requital?\"","\"শুধু প্রথম মৃত্যুতেই, এবং আমরা কখনো কোন প্রতিফল পাই না?\""],
  "37:60": ["Such is the greatest triumph.","এমনই শ্রেষ্ঠ বিজয়।"],
  "37:61": ["This is what every worker should work for.","ঠিক এর জন্যই সকল কর্মীর কাজ করা উচিত।"],
  "37:62": ["Is this a better destiny, or the tree of bitterness?","এটা কি উত্তম নিয়তি, নাকি তিক্ততার গাছ?"],
  "37:63": ["We have rendered it a punishment for the transgressors.","একে আমরা সীমালঙ্ঘনকারীদের জন্য একটি শাস্তিস্বরুপ করেছি।"],
  "37:64": ["It is a tree that grows in the heart of Hell.","এটা একটি গাছ যা নরকের মাঝখানে জন্মায়।"],
  "37:65": ["Its flowers look like the devils' heads.","এর ফুলগুলো দেখায় শয়তানের মাথার মতো।"],
  "37:66": ["They will eat from it until their bellies are filled up.","এটি থেকে তারা খাবে যতক্ষণ না তাদের পেট পূর্ণ হয়।"],
  "37:67": ["Then they will top it with a hellish drink.","এরপর তাতে তারা নারকীয় পানীয় ঢালবে।"],
  "37:68": ["Then they will return to Hell.","এরপর তারা নরকে ফিরে যাবে।"],
  "37:69": ["They found their parents astray.","তারা তাদের মাতা-পিতার অন্ধ অনুসরণ করেছিল"],
  "37:70": ["And they blindly followed in their footsteps.","এবং তারা অন্ধভাবে তাদের পদাংক অনুসরণ করেছিল।"],
  "37:71": ["Most of the previous generations have strayed in the same manner.","পূর্ববর্তী অধিকাংশ প্রজন্মগুলো একইভাবে পথভ্রষ্ট হয়েছে।"],
  "37:72": ["We have sent to them warners.","তাদের কাছে আমরা সতর্ককারী পাঠিয়েছি।"],
  "37:73": ["Note the consequences for those who have been warned.","তাদের পরিনাম লক্ষ্য করো যাদেরকে সতর্ক করা হয়েছিল।"],
  "37:74": ["Only Allah's servants who are absolutely devoted to Him alone (are saved).","শুধু আল্লাহর বান্দারা (রক্ষা পাবে) যারা কেবল পুরোপুরি তাঁর নিকট নিবেদিত।"],
  "37:75": ["Thus, Noah called upon us, and we were the best responders.","এভাবে, নূহ আমাদেরকে ডেকেছিল, এবং আমরাই সর্বোত্তম সাড়া দানকারী ছিলাম।"],
  "37:76": ["We saved him and his family from the great disaster.","আমরা তাকে এবং তার পরিবারকে মহাদূর্যোগ থেকে রক্ষা করেছিলাম।"],
  "37:77": ["We made his companions the survivors.","আমরা তার সঙ্গী-সাথীদের বাচিয়ে রেখেছিলাম।"],
  "37:78": ["And we preserved his history for subsequent generations.","এবং পরবর্তী প্রজন্মের জন্য আমরা তার ইতিহাস সংরক্ষণ করেছিলাম।"],
  "37:79": ["Peace be upon Noah among the peoples.","লোকদের মধ্যে নূহের প্রতি শান্তি বর্ষিত হোক।"],
  "37:80": ["We thus reward the righteous.","আমরা এভাবে সৎকর্মশীলদের পুরষ্কার দেই।"],
  "37:81": ["He is one of our believing servants.","সে আমাদের বিশ্বাসী বান্দাদের একজন।"],
  "37:82": ["We drowned all the others.","অন্য সবাইকে আমরা ডুবিয়ে দিয়েছিলাম।"],
  "37:83": ["Among his followers was Abraham.","তার অনুসারীদের মধ্যে ছিল ইব্রাহিম।"],
  "37:84": ["He came to his Lord wholeheartedly.","সে তার প্রভুর কাছে এসেছিল সম্পূর্ণ হৃদয় নিয়ে।"],
  "37:85": ["He said to his father and his people, \"What are you worshiping?","সে তার পিতা এবং তার লোকদের বলল, \"তোমরা কিসের উপাসনা করছো?"],
  "37:86": ["\"Is it these fabricated gods, instead of Allah, that you want?","এইসব বানানো উপাস্যগুলোই কি তা, আল্লাহর বদলে, যা তোমরা চাও?\""],
  "37:87": ["\"What do you think of the Lord of the universe?\"","মহাবিশ্বের প্রভু সম্পর্কে তোমাদের ধারণা কি?\""],
  "37:88": ["He looked carefully at the stars.","সে তারাগুলোর দিকে মনোযোগ দিয়ে তাকালো।"],
  "37:89": ["Then he gave up and said, \"I am tired of this!\"","তারপর সে বাদ দিলো এবং বলল, “আমি এতে ক্লান্ত!\""],
  "37:90": ["They turned away from him.","তারা তার থেকে মুখ ফিরিয়ে নিল।"],
  "37:91": ["He then turned on their idols, saying, \"Would you like to eat?","তারপর সে তাদের উপাস্যদের দিকে ফিরলো, এ বলে যে, \"তোমরা কি খেতে পছন্দ করো?\""],
  "37:92": ["\"Why do you not speak?\"","\"কেন তোমরা কথা বলো না?\""],
  "37:93": ["He then destroyed them.","সে তারপর এগুলোকে ধ্বংস করলো?\""],
  "37:94": ["They went to him in a great rage.","তারা ভীষন রাগান্বিত হয়ে তার কাছে গেল।"],
  "37:95": ["He said, \"How can you worship what you carve?","সে বলল, \"কেমন করে তোমরা তার উপাসনা করো যা তোমরা খোদাই করো?"],
  "37:96": ["\"When Allah has created you, and everything you make!\"","\"অথচ আল্লাহ সৃষ্টি করেছেন তোমাদেরকে, এবং সবকিছুকে যা তোমরা বানাও!\""],
  "37:97": ["They said, \"Let us build a great fire, and throw him into it.\"","তারা বলল, \"চল আমরা এক বিশাল অগ্নিকুণ্ডলী বানাই, এবং তাকে এর মধ্যে নিক্ষেপ করি।\""],
  "37:98": ["They schemed against him, but we made them the losers.","তারা তার বিরুদ্ধে ষড়যন্ত্র করলো, কিন্তু আমরা তাদের পরাজিত করলাম।"],
  "37:99": ["He said, \"I am going to my Lord; He will guide me.\"","সে বলল, \"আমি আমার প্রভুর কাছে যাচ্ছি; তিনি আমাকে পথ দেখাবেন।\""],
  "37:100": ["\"My Lord, grant me righteous children.\"","\"আমার প্রভু, আমাকে সৎকর্মশীল সন্তান দান করুন।\""],
  "37:101": ["We gave him good news of a good child.","আমরা তাকে একটি ভালো সন্তানের সুসংবাদ দিলাম।"],
  "37:102": ["When he grew enough to work with him, he said, \"My son, I see in a dream that I am sacrificing you. What do you think?\" He said, \"O my father, do what you are commanded to do. You will find me, Allah willing, patient.\"","যখন সে তার সাথে কাজ করার মতো যথেষ্ঠ বড় হয়ে উঠলো, সে বলল, \"আমার পুত্র, আমি স্বপ্নে দেখি যে তোমাকে আমি উৎসর্গ করছি। তুমি কি ভাবছো? “সে বলল, \"হে আমার পিতা, আপনার প্রতি যা প্রত্যাদেশ হয় তা করুন। আল্লাহ চাইলে আপনি আমাকে পাবেন, ধৈর্যশীল।"],
  "37:103": ["They both submitted, and he put his forehead down (to sacrifice him).","তারা উভয়ে আত্মসমর্পণ করল, এবং সে তার কপাল নীচে রাখলো (তাকে উৎসর্গ করতে)।"],
  "37:104": ["We called him: \"O Abraham.","আমরা তাকে ডাকলাম: \"হে ইব্রাহীম।"],
  "37:105": ["\"You have believed the dream.\" We thus reward the righteous.","\"স্বপ্নটি তুমি বিশ্বাস করেছো।” আমরা এভাবে সৎকর্মশীলদের পুরষ্কার দেই।"],
  "37:106": ["That was an exacting test indeed.","নিশ্চয় এটা ছিল এক কঠোর পরীক্ষা।"],
  "37:107": ["We ransomed (Ismail) by substituting an animal sacrifice.","আমরা একটি পশু উৎসর্গের বদলে (ইসমাইলকে) মুক্তি দিলাম।"],
  "37:108": ["And we preserved his history for subsequent generations.","এবং আমরা তার ইতিহাসকে পরবর্তী প্রজন্মের জন্য সংরক্ষণ করলাম।"],
  "37:109": ["Peace be upon Abraham.","ইব্রাহিমের উপর শান্তি বর্ষিত হোক।"],
  "37:110": ["We thus reward the righteous.","আমরা এভাবে সৎকর্মশীলদের পুরষ্কার দেই।"],
  "37:111": ["He is one of our believing servants.","সে ছিল আমাদের বিশ্বাসী বান্দাদের একজন।"],
  "37:112": ["Then we gave him the good news about the birth of Isaac, to be one of the righteous prophets.","এরপর আমরা তাকে ইসহাকের জন্মের সুসংবাদ দিলাম, যে হবে সৎকর্মশীল নবীদের একজন।"],
  "37:113": ["We blessed him and Isaac. Among their descendants, some are righteous, and some are wicked transgressors.","আমরা তাকে ও ইসহাককে সৌভাগ্যশীল করেছিলাম। তাদের বংশধরদের মধ্যে, কেউ কেউ সৎকর্মশীল, আর কেউ কেউ নীতিবিবর্জিত সীমালঙ্ঘনকারী।"],
  "37:114": ["We also blessed Moses and Aaron.","আমরা মূসা ও হারুনকেও আশীর্বাদ করেছিলাম।"],
  "37:115": ["We delivered them and their people from the great disaster.","আমরা এক মহাদূর্যোগ থেকে তাদেরকে এবং তাদের লোকদের উদ্ধার করেছিলাম।"],
  "37:116": ["We supported them, until they became the winners.","আমরা তাদেরকে সমর্থন করেছিলাম, যতক্ষণ না তারা জয়ী হয়েছিল।"],
  "37:117": ["We gave both of them the profound scripture.","আমরা তাদের উভয়কে জ্ঞানগর্ভ ঐশীগ্রন্থ দিয়েছিলাম।"],
  "37:118": ["We guided them in the right path.","আমরা তাদেরকে সঠিক পথ প্রদর্শন করেছিলাম।"],
  "37:119": ["We preserved their history for subsequent generations.","পরবর্তী প্রজন্মের জন্য আমরা তাদের ইতিহাস সংরক্ষণ করেছিলাম।"],
  "37:120": ["Peace be upon Moses and Aaron.","মূসা এবং হারুনের উপর শান্তি বর্ষিত হোক।"],
  "37:121": ["We thus reward the righteous.","এভাবে আমরা সৎকর্মশীলদের পুরষ্কার দেই।"],
  "37:122": ["Both of them were among our righteous servants.","তাদের উভয়ে ছিল আমাদের সৎকর্মশীল বান্দাদের অন্তর্ভুক্ত।"],
  "37:123": ["Elias was one of the messengers.","ইলিয়াস ছিল বার্তাবাহকদের একজন।"],
  "37:124": ["He said to his people, \"Would you not work righteousness?","সে তার লোকদের বলেছিল, \"তোমরা কি সৎকর্ম করবে না?"],
  "37:125": ["\"Do you worship a statue, instead of the Supreme Creator?","\"তোমরা কি উপাসনা করো এক মূর্তির, পরম সৃষ্টিকর্তার পরিবর্তে?"],
  "37:126": ["\"Allah; your Lord, and the Lord of your forefathers!\"","\"আল্লাহ; তোমাদের প্রভু, এবং তোমাদের পূর্বপুরুষের প্রভু!\""],
  "37:127": ["They disbelieved him. Consequently, they had to be called to account.","তারা তাকে অবিশ্বাস করলো। পরিনামে, তাদেরকে হিসাবের জন্য ডাকা হবে।"],
  "37:128": ["Only Allah's servants who are absolutely devoted to Him alone (are saved).","শুধু্ আল্লাহর বান্দারা (রক্ষা পায়) যারা কেবল তাঁর প্রতি নিবেদিত।"],
  "37:129": ["We preserved his history for subsequent generations.","আমরা তার ইতিহাস পরবর্তী প্রজন্মের জন্য সংরক্ষণ করেছিলাম।"],
  "37:130": ["Peace be upon Elias, and all those like Elias.","শান্তি বর্ষিত হোক ইলিয়াসের উপর, এবং ইলিয়াসের মত সবার উপর।"],
  "37:131": ["We thus reward the righteous.","আমরা এভাবে সৎকর্মশীলদের পুরষ্কার দেই।"],
  "37:132": ["He was one of our believing servants.","সে ছিল আমাদের বিশ্বাসী বান্দাদের একজন।"],
  "37:133": ["Lot was one of the messengers.","লূত ছিল বার্তাবাহকদের একজন।"],
  "37:134": ["We saved him and all his family.","আমরা তাকে এবং তার পরিবারের সকলকে রক্ষা করেছিলাম।"],
  "37:135": ["Only the old woman was doomed.","কেবল সেই বৃদ্ধ মহিলা ধ্বংস হয়েছিল।"],
  "37:136": ["We annihilated all the others.","আমরা অন্যদের সকলকে নির্মূল করলাম।"],
  "37:137": ["You still pass by their ruins by day.","এখনও তোমরা তাদের ধ্বংসস্তূপের পাশ দিয়ে যাও দিনে।"],
  "37:138": ["And by night. Would you understand?","এবং রাতে। তোমরা কি বুঝবে?"],
  "37:139": ["Jonah was one of the messengers.","ইউনুছ ছিল বার্তাবাহকদের একজন।"],
  "37:140": ["He escaped to the loaded ship.","সে বোঝাইকৃত জাহাজে পালালো।"],
  "37:141": ["He rebelled and thus, he joined the losers.","সে বিদ্রোহ করেছিল আর এভাবে, সে পরাজিতদের সাথে যোগ দিল।"],
  "37:142": ["Consequently, the fish swallowed him, and he was the one to blame.","ফলশ্রুতিতে, মাছ তাকে গিলে ফেললো, এবং সে-ই ছিল দোষী ব্যক্তি।"],
  "37:143": ["If it were not that he resorted to meditation (on Allah),","যদি সে (আল্লাহর) ধ্যানে মগ্ন না হতো,"],
  "37:144": ["he would have stayed in its belly until the Day of Resurrection.","সে হয়তো এর পেটেই থাকতো পুনরুত্থান দিনের আগ পর্যন্ত।"],
  "37:145": ["We had him thrown up into the desert, exhausted.","আমরা তাকে মরুভূমিতে নিক্ষেপ করলাম, মৃতপ্রায় অবস্থায়।"],
  "37:146": ["We had a tree of edible fruit grown for him.","আমরা তার জন্য একটি ভক্ষনযোগ্য ফলের গাছ জন্মাতে দিলাম।"],
  "37:147": ["Then we sent him to a hundred thousand, or more.","এরপর আমরা তাকে একশ হাজার, বা তার চেয়ে বেশির নিকট পাঠালাম।"],
  "37:148": ["They did believe, and we let them enjoy this life.","তারা বিশ্বাস করেছিলো, এবং আমরা তাদেরকে এই জীবন উপভোগ করতে দিলাম।"],
  "37:149": ["Ask them if your Lord has daughters, while they have sons!","তাদেরকে জিজ্ঞেস করো তোমার প্রভুর কি কন্যা রয়েছে, যখন তাদের রয়েছে পুত্র!"],
  "37:150": ["Did we create the angels to be females? Did they witness that?","আমরা কি ফেরেশতাদের নারী রুপে সৃষ্টি করেছিলাম? তারা কি তা প্রত্যক্ষ করেছিল?"],
  "37:151": ["Indeed, they grossly blaspheme when they say—","নিশ্চয়, তারা গুরুতর ধর্মনিন্দা করে যখন তারা বলে-"],
  "37:152": ["\"Allah has begotten a son.\" Indeed, they are liars.","\"আল্লাহ পুত্র জন্ম দিয়েছেন।” নিশ্চয়, তারা মিথ্যাবাদী।"],
  "37:153": ["Did He choose the girls over the boys?","তিনি কি ছেলেদের উপর মেয়েদের পছন্দ করেছিলেন?"],
  "37:154": ["What is wrong with your logic?","তোমাদের যুক্তিতে সমস্যা কোথায়?"],
  "37:155": ["Why do you not take heed?","কেন তোমরা মনোযোগ দাও না?"],
  "37:156": ["Do you have any proof?","তোমাদের কি কোন প্রমান আছে?"],
  "37:157": ["Show us your book, if you are truthful.","আমাদেরকে তোমাদের কিতাব দেখাও, যদি তোমরা সত্যবাদী হও।"],
  "37:158": ["They even invented a special relationship between Him and the jinns. The jinns themselves know that they are subservient.","তারা এমনকি তাঁর এবং জ্বীনদের মাঝে বিশেষ সম্পর্ক উদ্ভাবন করেছিল।"],
  "37:159": ["Allah be glorified; far above their claims.","মহিমা আল্লাহর; তাদের দাবির অনেক উর্ধ্বে।"],
  "37:160": ["Only Allah's servants who are devoted to Him alone (are saved).","শুধু আল্লাহর বান্দারা (রক্ষা পাবে) যারা কেবল তার প্রতি নিবেদিত।"],
  "37:161": ["Indeed, you and what you worship.","নিশ্চয়, তোমরা এবং যার উপাসনা তোমরা করো।"],
  "37:162": ["Cannot impose anything on Him.","তাঁর উপর কিছু চাপিয়ে দিতে পারে না।"],
  "37:163": ["Only you will burn in Hell.","শুধু তোমরাই নরকে পুড়বে।"],
  "37:164": ["Each one of us has a specific job.","আমাদের প্রত্যেকের একটি নির্দিষ্ট কাজ আছে।"],
  "37:165": ["We are the arrangers.","আমরাই বিন্যাসকারী।"],
  "37:166": ["We have duly glorified (our Lord).","আমরা যথাযথভাবে (আমাদের প্রভুর) গুণগান করি।"],
  "37:167": ["They used to say,","তারা বলতো যে,"],
  "37:168": ["\"Had we received the correct instructions from our parents,","যদি আমরা আমাদের পিতা-মাতা থেকে সঠিক নির্দেশনা পেতাম,"],
  "37:169": ["\"we would have been worshipers; devoted to Allah alone.\"","\"আমরা উপাসনাকারী হতাম; কেবল আল্লাহর প্রতি নিবেদিত। \""],
  "37:170": ["But they disbelieved, and they will surely find out.","কিন্তু তারা অবিশ্বাস করেছিল, এবং তারা অবশ্যই দেখবে।"],
  "37:171": ["Our decision is already decreed for our servants the messengers.","আমাদের বার্তাবাহক বান্দাদের জন্য আমাদের সিদ্ধান্ত ইতোমধ্যেই নির্ধারণ করা হয়েছে।"],
  "37:172": ["They are surely the victors.","নিশ্চয় তারাই বিজয়ী।"],
  "37:173": ["Our soldiers are the winners.","আমাদের সৈন্যরাই জয়লাভকারী।"],
  "37:174": ["So disregard them for awhile.","অতএব কিছু সময়ের জন্য তাদের উপেক্ষা করো।"],
  "37:175": ["Watch them; they too will watch.","তাদেরকে লক্ষ্য করো; তারাও লক্ষ্য রাখবে।"],
  "37:176": ["Do they challenge our retribution?","তারা কি আমাদের শাস্তিকে চ্যালেঞ্জ করে?"],
  "37:177": ["When it hits them one day, it will be a miserable day; they have been sufficiently warned.","একদিন যখন তা তাদের আঘাত করবে, এটা হবে এক শোচনীয় দিন; তাদেরকে যথেষ্ট পরিমানে সতর্ক করা হয়েছে।"],
  "37:178": ["Disregard them for awhile.","তাদেরকে কিছু সময়ের জন্য উপেক্ষা করো।"],
  "37:179": ["Watch them; they too will watch.","তাদেরকে লক্ষ্য করো; তারাও লক্ষ্য রাখবে।"],
  "37:180": ["Glory be to your Lord, the great Lord; far above their claims.","মহিমা তোমার প্রভুর, মহান প্রভু; তাদের দাবির অনেক উর্ধ্বে।"],
  "37:181": ["Peace be upon the messengers.","বার্তাবাহকদের উপর শান্তি বর্ষিত হোক।"],
  "37:182": ["Praise be to Allah, Lord of the universe.","প্রশংসা আল্লাহর, মহাবিশ্বের প্রভু।"],
  "38:1": ["S. (Saad), and the Quran that contains the proof.","স. (সা'দ), এবং কোর'আন যা বহন করে প্রমান।"],
  "38:2": ["Those who disbelieve have plunged into arrogance and defiance.","যারা অবিশ্বাস করে তারা ঔদ্ধত্য এবং অবাধ্যতায় নিমজ্জিত হয়েছে।"],
  "38:3": ["Many a generation before them we annihilated. They called for help; in vain.","তাদের আগে অনেক প্রজন্মকে আমরা ধ্বংস করেছিলাম। তারা সাহায্যের জন্য ডেকেছিলো; বৃথাই।"],
  "38:4": ["They wondered that a warner should come to them, from among them. The disbelievers said, \"A magician; a liar.","তারা অবাক হয়েছিল যে তাদের কাছে একজন সতর্ককারী এসেছে, তাদের মধ্য থেকে। অবিশ্বাসীরা বলল, \"একজন যাদুকর; মিথ্যুক।"],
  "38:5": ["\"Did he make the gods into one god? This is really strange.\"","সে কি বহু উপাস্যকে এক উপাস্য বানিয়ে ফেলেছে? এটি সত্যিই বিস্ময়কর।\""],
  "38:6": ["The leaders announced, \"Go and steadfastly persevere in worshiping your gods. This is what is desired.","নেতারা ঘোষনা করল, \"যাও এবং দৃড়তার সাথে অবিচল থেকে তোমাদের উপাস্যদের উপাসনা করো। এটাই তো কাম্য।"],
  "38:7": ["\"We never heard of this from the religion of our fathers. This is a lie.","\"আমরা আমাদের পিতৃপুরুষদের ধর্ম থেকে কখনো এমন শুনিনি। এটি একটি মিথ্যা।"],
  "38:8": ["\"Why did the proof come down to him, instead of us?\" Indeed, they are doubtful of My proof. Indeed, they have not yet tasted My retribution.","\"কেন তার কাছেই প্রমান আসলো, আমাদের পরিবর্তে? \"নিশ্চয়, তারা আমার প্রমানের বিষয়ে সন্দিহান। নিশ্চয়ই, তারা এখনো আমার শাস্তি আস্বাদন করেনি।"],
  "38:9": ["Do they own the treasures of mercy of your Lord, the Almighty, the Grantor?","তারা কি তোমার প্রভুর দয়ার ভান্ডারের মালিক, যিনি সর্বশক্তিমান, দাতা?"],
  "38:10": ["Do they possess the sovereignty of the heavens and the earth, and everything between them? Let them help themselves.","তারা কি আকাশমণ্ডলী ও পৃথিবী, এবং এগুলোর মধ্যকার সবকিছুর সার্বভৌমত্ব অধিকার করে? তাদেরকে সাহায্য করতে দাও তাদের নিজেদেরকেই।"],
  "38:11": ["Instead, whatever forces they can muster—even if all their parties banded together—will be defeated.","পরিবর্তে, তারা যে শক্তিই একত্রিত করতে পারুক- এমনকি যদি তাদের সকল দল একত্রে জড়ো হয়ও- তারা পরাজিত হবে।"],
  "38:12": ["Disbelieving before them were the people of Noah, 'Ãd, and the mighty Pharaoh.","তাদের পূর্বে অবিশ্বাস করেছিল নূহের লোকেরা, আদ, এবং শক্তিশালী ফেরাউন।"],
  "38:13": ["Also, Thamûd, the people of Lot, the dwellers of the Woods (of Midyan); those were the opponents.","এছাড়া, সামূদ, লূতের লোকেরা, (মাদিয়ানে) গভীর জংগলের অধিবাসীরা; তারা ছিল বিরোধী।"],
  "38:14": ["Each of them disbelieved the messengers and thus, My retribution was inevitable.","তাদের প্রত্যেকে বার্তাবাহককে অবিশ্বাস করেছিল আর এভাবে, আমার শাস্তি ছিল অবধারিত।"],
  "38:15": ["These people can expect a single blow, from which they never recover.","এই লোকেরা কেবল একটি আঘাত প্রত্যাশা করতে পারে, যা থেকে তারা কখনো পূর্বাবস্থায় ফেরে না।"],
  "38:16": ["They challenged: \"Our Lord, why do you not rush the retribution for us, before the Day of Reckoning.\"","তারা চ্যালেঞ্জ করেছিল: আমাদের প্রভু, কেন আপনি আমাদেরকে দ্রুত শাস্তি দেন না, বিচার দিনের পূর্বে।"],
  "38:17": ["Be patient in the face of their utterances, and remember our servant David, the resourceful; he was obedient.","তাদের কথায় ধৈর্য ধরো, এবং আমাদের বান্দা দাউদকে স্মরণ করো, প্রাচুর্যশালী; সে ছিল অনুগত।"],
  "38:18": ["We committed the mountains in his service, glorifying with him night and day.","আমরা পাহাড়কে তার সেবায় নিয়োজিত করেছিলাম, যারা তার সাথে গুণকীর্তন করতো রাতে এবং দিনে।"],
  "38:19": ["Also the birds were committed to serve him; all were obedient to him.","পাখিরাও ছিল তার সেবায় নিয়োজিত; সকলে তার অনুগত ছিল।"],
  "38:20": ["We strengthened his kingship, and endowed him with wisdom and good logic.","আমরা তার রাজত্বকে শক্তিশালী করেছিলাম, এবং তাকে প্রজ্ঞা ও ভাল যুক্তি দান করেছিলাম।"],
  "38:21": ["Have you received news of the feuding men who sneaked into his sanctuary?","তুমি কি সেই বিবাদকারী লোকদের খবর পেয়েছো যারা চুপিসারে তার উপাসনাস্থলে ঢুকে পড়েছিল?"],
  "38:22": ["When they entered his room, he was startled. They said, \"Have no fear. We are feuding with one another, and we are seeking your fair judgment. Do not wrong us, and guide us in the right path.","যখন তারা তার কক্ষে প্রবেশ করলো, সে চমকে উঠলো। তারা বলল, \"ভয় পাবেন না। আমরা একে অন্যের সাথে বিবাদে করছি এবং আমরা আপনার কাছে ন্যায় বিচার চাচ্ছি। আমাদের প্রতি অন্যায় করবেন না, এবং আমাদেরকে সঠিক পথ প্রদর্শন করুন।"],
  "38:23": ["\"This brother of mine owns ninety-nine sheep, while I own one sheep. He wants to mix my sheep with his, and continues to pressure me.\"","আমার এই ভাই নিরান্নবইটি ভেড়ার মালিক, যেখানে আমি একটি ভেড়ার মালিক। সে আমার ভেড়াকে তারগুলোর সাথে মিশিয়ে ফেলতে চায়, এবং আমাকে চাপ দিয়েই যাচ্ছে।"],
  "38:24": ["He said, \"He is being unfair to you by asking to combine your sheep with his. Most people who combine their properties treat each other unfairly, except those who believe and work righteousness, and these are so few.\" Afterwards, David wondered if he made the right judgment. He thought that we were testing him. He then implored his Lord for forgiveness, bowed down, and repented.","সে বলল, “সে তোমার প্রতি অন্যায় করেছে তোমার ভেড়াটি তারগুলোর সাথে মিশিয়ে ফেলতে বলে। বেশির ভাগ লোকই যারা তাদের সম্পদ মিশিয়ে ফেলে তারা একে অন্যের সাথে অন্যায় আচরণ করে, তারা ছাড়া যারা বিশ্বাস করে এবং সৎকর্ম করে, এবং এরা সংখ্যায় খুবই অল্প।” পরবর্তীতে, দাউদ সন্দেহ পোষন করলো যে সে সঠিক বিচার করেছে কিনা। সে ভাবলো আমরা তাকে পরীক্ষা করছিলাম। সে এরপর তার প্রভুর কাছে ক্ষমার জন্য মিনতি করলো, নত হলো এবং অনুশোচনা করলো।"],
  "38:25": ["We forgave him in this matter. We have granted him a position of honor with us, and a beautiful abode.","এই বিষয়ে তাকে আমরা ক্ষমা করে দিয়েছিলাম। আমরা তাকে প্রদান করেছি আমাদের সাথে এক সম্মানিত অবস্থান, এবং এক চমৎকার আবাস।"],
  "38:26": ["O David, we have made you a ruler on earth. Therefore, you shall judge among the people equitably, and do not follow your personal opinion, lest it diverts you from the way of Allah. Surely, those who stray off the way of Allah incur severe retribution for forgetting the Day of Reckoning.","হে দাউদ, আমরা তোমাকে পৃথিবীতে একজন শাসক বানিয়েছি। অতএব, তুমি লোকদের মাঝে ন্যায় বিচার করবে, এবং তোমার ব্যক্তিগত মতের অনুসরণ করো না, পাছে তা তোমাকে আল্লাহর পথ থেকে সরিয়ে দেয়। অবশ্যই, যারা আল্লাহর পথ থেকে বিচ্যুত হয় তারা কঠোর শাস্তি টেনে আনে বিচার দিবসকে ভুলে যাবার জন্য।"],
  "38:27": ["We did not create the heaven and the earth, and everything between them, in vain. Such is the thinking of those who disbelieve. Therefore, woe to those who disbelieve; they will suffer in Hell.","আমরা আকাশমন্ডলী ও পৃথিবী, এবং এগুলোর মধ্যকার সবকিছু অনর্থক সৃষ্টি করিনি। যারা অবিশ্বাস করে তাদের চিন্তা-ভাবনা এমনই। অতএব, দূর্ভোগ তাদের প্রতি যারা অবিশ্বাস করে; তারা নরকে ভুগবে।"],
  "38:28": ["Shall we treat those who believe and lead a righteous life as we treat those who commit evil on earth? Shall we treat the righteous as we treat the wicked?","যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে তাদের সাথে কি আমরা তেমন আচরণ করবো যেমন আচরণ আমরা করি তাদের সাথে যারা পৃথিবীতে মন্দকর্ম করে? আমরা কি সৎকর্মশীলদের সাথে তেমন আচরণ করবো যেমন আচরণ আমরা করি অন্যায়কারীদের সাথে?"],
  "38:29": ["This is a scripture that we sent down to you, that is sacred—perhaps they reflect on its verses. Those who possess intelligence will take heed.","এটি একটি ঐশীগ্রন্থ যা আমরা তোমার কাছে অবতীর্ণ করেছি- যা পবিত্র - হয়তো তারা এর আয়াতগুলো নিয়ে চিন্তা-ভাবনা করবে। যারা বুদ্ধিমত্তার অধিকারী তারা মনোযোগ দিবে।"],
  "38:30": ["To David we granted Solomon; a good and obedient servant.","আমরা দাঊদকে দান করেছিলাম সোলায়মান, একজন ভালো এবং অনুগত ভৃত্য।"],
  "38:31": ["One day he became preoccupied with beautiful horses, until the night fell.","একদিন সে সুন্দর ঘোড়া নিয়ে আচ্ছন্ন হয়ে পড়লো, যতক্ষন না রাত নামলো।"],
  "38:32": ["He then said, \"I enjoyed the material things more than I enjoyed worshiping my Lord, until the sun was gone.","সে তখন বলল, “আমি আমার প্রভুর উপাসনা উপভোগের চেয়ে পার্থিব বিষয় বেশি উপভোগ করেছিলাম, যতক্ষন না সূর্য ডুবে গেল।"],
  "38:33": ["\"Bring them back.\" (To bid farewell,) he rubbed their legs and necks.","“এগুলোকে ফিরিয়ে আনো।” (বিদায় জানাতে,) সে এগুলোর পা ও ঘাড়ে হাত বুলিয়ে দিল।"],
  "38:34": ["We thus put Solomon to the test; we blessed him with vast material wealth, but he steadfastly submitted.","আমরা এভাবে সোলায়মানকে পরীক্ষায় ফেলেছিলাম; তাকে প্রচুর পার্থিব সম্পদ দিয়ে আমরা অনুগ্রহ করেছিলাম, কিন্তু সে দৃড়ভাবে সমর্পিত ছিল।"],
  "38:35": ["He said, \"My Lord, forgive me, and grant me a kingship never attained by anyone else. You are the Grantor.\"","সে বলল, “আমার প্রভু, আমাকে ক্ষমা করুন, এবং আমাকে একটি রাজত্য দিন যা কখনো কারো দ্বারা অর্জিত হয়নি। আপনি মঞ্জুরকারী।”"],
  "38:36": ["We (answered his prayer and) committed the wind at his disposal, pouring rain wherever he wanted.","আমরা (তার প্রার্থনায় সাড়া দিয়েছিলাম এবং) বাতাসকে তার আজ্ঞাবহ করলাম, সে যেখানেই চাইতো বৃষ্টি পতিত হতো।"],
  "38:37": ["And the devils, building and diving.","আর শয়তানরা, নির্মান করতো এবং ডুব দিতো।"],
  "38:38": ["Others were placed at his disposal.","অন্যদেরকে তার আয়ত্তাধীনে রাখা হয়েছিল।"],
  "38:39": ["\"This is our provision to you; you may give generously, or withhold, without limits.\"","“এটি তোমার প্রতি আমাদের জীবিকা; তুমি উদারভাবে দিতে পারো, অথবা বিরত থাকতে পারো, সীমাহীনভাবে।”"],
  "38:40": ["He has deserved an honorable position with us, and a wonderful abode.","সে আমাদের সাথে একটি সম্মানিত অবস্থানের, এবং একটি চমৎকার আবাসের যোগ্য হয়েছে।"],
  "38:41": ["Remember our servant Job: he called upon his Lord, \"The devil has afflicted me with hardship and pain.\"","স্মরণ করো আমাদের বান্দা আইয়ুবের কথা: সে তার প্রভুকে ডেকেছিল, “শয়তান আমাকে দুর্দশাগ্রস্থ করেছে অসচ্ছলতা ও যন্ত্রণা দিয়ে।”"],
  "38:42": ["\"Strike the ground with your foot. A spring will give you healing and a drink.\"","“তোমার পা দিয়ে ভূমিতে আঘাত করো। একটি ঝর্ণা তোমাকে নিরাময় এবং পানীয় দিবে।”"],
  "38:43": ["We restored his family for him; twice as many. Such is our mercy; a reminder for those who possess intelligence.","আমরা তার জন্য তার পরিবারকে ফিরিয়ে দিলাম; দ্বিগুন করে। এমনই আমাদের দয়া; যারা বুদ্ধিমত্তার অধিকারী তাদের জন্য একটি স্মারক।"],
  "38:44": ["\"Now, you shall travel the land and preach the message, to fulfill your pledge.\" We found him steadfast. What a good servant! He was a submitter.","“এখন, তুমি ভূখন্ডে ভ্রমণ করবে এবং বার্তা প্রচার করবে, তোমার অঙ্গীকার পূর্ণ করতে।” আমরা তাকে দৃড় পেয়েছিলাম। কতই না ভাল বান্দা! সে ছিল একজন আত্মসমর্পণকারী।"],
  "38:45": ["Remember also our servants Abraham, Isaac, and Jacob. They were resourceful, and possessed vision.","আরো স্মরণ করো আমাদের বান্দা ইব্রাহিম, ইসহাক এবং ইয়াকুবকে। তারা ছিল প্রাচুর্যশালী, এবং অন্তর্দৃষ্টিসম্পন্ন।"],
  "38:46": ["We bestowed upon them a great blessing: awareness of the Hereafter.","আমরা তাদেরকে দান করেছিলাম এক মহা অনুগ্রহ: পরকালের সচেতনতা।"],
  "38:47": ["They were chosen, for they were among the most righteous.","তারা ছিল পছন্দকৃত, কারণ তারা ছিল সর্বাধিক সৎকর্মশীলদের অন্তর্ভূক্ত।"],
  "38:48": ["Remember Ismail, Elisha, and Zal-Kifl; among the most righteous.","স্মরণ করো ইসমাইল, ইয়াসা, এবং যুলকিফলকে; সর্বাধিক সৎকর্মশীলদের মাঝে।"],
  "38:49": ["This is a reminder: The righteous have deserved a wonderful destiny.","এটি একটি স্মারক: সৎকর্মশীলরা এক চমৎকার নিয়তির অর্জন করেছে।"],
  "38:50": ["The gardens of Eden will open up their gates for them.","ইডেনের বাগানগুলো তাদের জন্য দরজা খুলে দেবে।"],
  "38:51": ["Relaxing therein, they will be given many kinds of fruits and drinks.","সেখানে আরাম করা অবস্থায়, তাদেরকে নানা রকম ফল এবং পানীয় দেয়া হবে।"],
  "38:52": ["They will have wonderful spouses.","তাদের থাকবে চমৎকার সঙ্গী।"],
  "38:53": ["This is what you have deserved on the Day of Reckoning.","এরই যোগ্য তোমরা হয়েছ হিসাবের দিনে।"],
  "38:54": ["Our provisions are inexhaustible.","আমাদের জীবিকা অফুরন্ত।"],
  "38:55": ["As for the transgressors, they have incurred a miserable destiny.","সীমালঙ্ঘনকারীদের ক্ষেত্রে, তারা টেনে এনেছে এক শোচনীয় নিয়তি।"],
  "38:56": ["Hell is where they burn; what a miserable abode!","নরক হচ্ছে সে জায়গা যেখানে তারা পুড়বে; কি এক শোচনীয় আবাস!"],
  "38:57": ["What they taste therein will be hellish drinks and bitter food.","সেখানে তারা যা আস্বাদন করবে তা হবে নারকীয় পানীয় এবং তিক্ত খাদ্য।"],
  "38:58": ["And much more of the same kind.","এবং এই রকমের আরো অনেক কিছু।"],
  "38:59": ["\"This is a group to be thrown into Hell with you.\" They will not be welcomed (by the residents of Hell). They have deserved to burn in the hellfire.","“এটি একটি দল যাদেরকে তোমাদের সাথে নিক্ষেপ করা হবে।” তারা (নরকের বাসিন্দাদের দ্বারা) সাদরে গৃহীত হবে না। তারা নরকাগ্নিতে পোড়ার যোগ্য।"],
  "38:60": ["The newcomers will respond, \"Nor are you welcomed. You are the ones who preceded us and misled us. Therefore, suffer this miserable end.\"","নবাগতরা উত্তর দিবে, “তোমরাও সাদরে গৃহীত নও। তোমরাই তো আমাদের পূর্ববর্তী ছিলে এবং আমাদেরকে পথভ্রষ্ট করেছো। অতএব, এই শোচনীয় সমাপ্তি ভোগ করো।"],
  "38:61": ["They will also say, \"Our Lord, these are the ones who led us into this; double the retribution of hellfire for them.\"","তারা আরো বলবে, “আমাদের প্রভু, এরাই সে ব্যক্তি যারা আমাদেরকে এর মাঝে পরিচালিত করেছিল; তাদের জন্য নরকাগ্নির শাস্তি দ্বিগুন করে দিন।”"],
  "38:62": ["They will say, \"How come we do not see (in Hell) people we used to count among the wicked?","তারা বলবে, “কেমন করে আমরা (নরকে) সে লোকদের দেখছি না যাদেরকে আমরা অন্যায়কারীদের সাথে গুনতাম?"],
  "38:63": ["\"We used to ridicule them; we used to turn our eyes away from them.\"","\"আমরা তাদেরকে উপহাস করতাম; আমরা তাদের থেকে আমাদের চোখ ফিরিয়ে নিতাম।”"],
  "38:64": ["This is a predetermined fact: the people of Hell will feud with one another.","এটি একটি পূর্বনির্ধারিত সত্য: নরকের লোকেরা একে অন্যের সাথে বিবাদ করবে।"],
  "38:65": ["Say, \"I warn you; there is no other god beside Allah, the One, the Supreme.","বল, “আমি তোমাদের সতর্ক করি; আল্লাহর পাশে অন্যকোন উপাস্য নেই, একক, সর্বোচ্চ।"],
  "38:66": ["\"The Lord of the heavens and the earth, and everything between them; the Almighty, the Forgiving.\"","“আকাশমণ্ডলী ও পৃথিবী, এবং এদের মধ্যকার সবকিছুর প্রভু; সর্বশক্তিমান, ক্ষমাকারী।”"],
  "38:67": ["Say, \"Here is awesome news.","বল, “এখানে এক মহা সংবাদ আছে।"],
  "38:68": ["\"That you are totally oblivious to.","“যাতে তোমরা সম্পূর্ণ অন্যমনস্ক।"],
  "38:69": ["\"I had no knowledge previously, about the feud in the High Society.","“উর্ধ সমাজের (মালা-ইল-আলা) বিবাদ সম্বন্ধে পূর্বে আমার কোন জ্ঞান ছিল না৷”"],
  "38:70": ["\"I am inspired that my sole mission is to deliver the warnings to you.\"","“আমি প্রত্যাদেশপ্রাপ্ত যে আমার একমাত্র দায়িত্ব তোমাদের কাছে সতর্কবানী পৌছে দেয়া।”"],
  "38:71": ["Your Lord said to the angels, \"I am creating a human being from clay.","তোমার প্রভু ফেরেশতাদের বললেন, “আমি কাদামাটি থেকে একজন মানুষ সৃষ্টি করছি।"],
  "38:72": ["\"Once I design him, and blow into him from My spirit, you shall fall prostrate before him.\"","“আমি তার নকশা করলে, এবং আমার রুহ থেকে তার মধ্যে ফুকে দিলে, তোমরা তার সামনে সেজদাবনত হবে।”"],
  "38:73": ["The angels fell prostrate, all of them,","ফেরেশতারা সেজদায় পড়েছিল, তাদের সকলে,"],
  "38:74": ["except Satan; he refused, and was too arrogant, unappreciative.","শয়তান ছাড়া; সে প্রত্যাখান করছিল, এবং অত্যন্ত ঔদ্ধত, অকৃতজ্ঞ ছিল।"],
  "38:75": ["He said, \"O Satan, what prevented you from prostrating before what I created with My hands? Are you too arrogant? Have you rebelled?\"","তিনি বল্লেন, “হে শয়তান, কিসে তোমাকে তার সামনে সেজদা করা থেকে বিরত রেখেছে যাকে আমি আমার নিজ হাতে সৃষ্টি করেছি? তুমি কি খুব উদ্ধত? তুমি কি বিদ্রোহ করছো?”"],
  "38:76": ["He said, \"I am better than he; You created me from fire, and created him from clay.\"","সে বলল, “আমি তার চেয়ে উত্তম; আপনি আমাকে আগুন থেকে সৃষ্টি করেছেন, এবং তাকে সৃষ্টি করেছেন কাদামাটি থেকে।”"],
  "38:77": ["He said, \"Therefore, you must be exiled, you will be banished.","তিনি বললেন, “একারণে, তুমি অবশ্যই নির্বাসিত হবে, তুমি বিতাড়িত হবে।"],
  "38:78": ["\"You have incurred My condemnation until the Day of Judgment.\"","“তুমি বিচার দিবস পর্যন্ত আমার অভিশাপ টেনে এনেছ।”"],
  "38:79": ["He said, \"My Lord, respite me till the Day of Resurrection.\"","সে বলল, “আমার প্রভু, পূনরুত্থান দিবস পর্যন্ত আমাকে অবকাশ দিন।”"],
  "38:80": ["He said, \"You are respited.","তিনি বললেন, “তোমাকে অবকাশ দেয়া হল।"],
  "38:81": ["\"Until the appointed day.\"","“নির্ধারিত দিন পর্যন্ত।”"],
  "38:82": ["He said, \"I swear by Your majesty, that I will send them all astray.","সে বলল, “আমি আপনার মহিমার শপথ করছি, যে আমি তাদের সকলকে পথভ্রষ্ট করবো।"],
  "38:83": ["\"Except Your worshipers who are devoted absolutely to You alone.\"","\"আপনার উপাসনাকারীদের ব্যতীত যারা সম্পূর্ণরূপে একমাত্র আপনার প্রতি নিবেদিত।”"],
  "38:84": ["He said, \"This is the truth, and the truth is all that I utter.","তিনি বললেন, “এটাই সত্য, এবং সত্য হল সবই যা আমি বলি।"],
  "38:85": ["I will fill Hell with you and all those who follow you.","\"আমি তোমাকে এবং যারা তোমার অনুসরণ করে তাদের সবাইকে দিয়ে নরক পূর্ণ করবো।”"],
  "38:86": ["Say, \"I do not ask you for any wage, and I am not an imposter.","বল, “আমি তোমাদের কাছে কোন পারিশ্রমিক চাই না, এবং আমি কোন ছদ্মবেশী নই।"],
  "38:87": ["\"This is a reminder for the world.","“এটি বিশ্বের জন্য একটি স্মারক।"],
  "38:88": ["\"And you will certainly find out in awhile.\"","“এবং তোমরা অবশ্যই অল্প সময়ের মধ্যে বুঝতে পারবে।”"],
  "39:1": ["This is a revelation of the scripture, from Allah, the Almighty, the Wise.","এটি ঐশীগ্রন্থের একটি প্রত্যাদেশ সর্বশক্তিমান, প্রজ্ঞাময় আল্লাহর পক্ষ থেকে।"],
  "39:2": ["We sent down to you this scripture, truthfully; you shall worship Allah, devoting your religion to Him alone.","আমরা তোমার কাছে এই ঐশীগ্রন্থ অবতীর্ণ করেছি,সত্য নিষ্ঠার সঙ্গে; তুমি আল্লাহর উপাসনা করবে,তোমার ধর্মকে একমাত্র তাঁর প্রতি উৎসর্গ করে।"],
  "39:3": ["Absolutely, the religion shall be devoted to Allah alone. Those who set up idols beside Him say, \"We idolize them only to bring us closer to Allah; for they are in a better position!\" Allah will judge them regarding their disputes. Allah does not guide such liars, disbelievers.","নিঃসন্দেহে, ধর্ম একমাত্র আল্লাহর জন্য উৎসর্গকৃত হবে। যারা তাঁর পাশে উপাস্য স্থাপন করে তারা বলে,“আমাদেরকে আল্লাহর নিকটে আনার জন্যই শুধু তাদেরকে আমরা শরিক বানাই; কারণ তারা এক উত্তম অবস্থানে রয়েছে!” তাদের বিতর্কের বিষয়ে আল্লাহ তাদের বিচার করবেন। আল্লাহ এমন মিথ্যাবাদী,অবিশ্বাসীদের পথ দেখান না।"],
  "39:4": ["If Allah wanted to have a son, He could have chosen whomever He willed from among His creations. Be He glorified; He is Allah, the One, the Supreme.","যদি আল্লাহ কোণ পুত্র চাইতেন, তিনি তাঁর সৃষ্টি থেকে যাকেই চাইতেন পছন্দ করতে পারতেন। মহিমা তাঁরই; তিনি আল্লাহ, একক স্বত্বা,সর্বোচ্চ।"],
  "39:5": ["He created the heavens and the earth truthfully. He rolls the night over the day, and rolls the day over the night. He committed the sun and the moon, each running for a finite period. Absolutely, He is the Almighty, the Forgiving.","তিনি আকাশমণ্ডলী এবং পৃথিবী সৃষ্টি করেছেন সত্য নিষ্ঠার সঙ্গে।তিনি রাতকে দিনের উপর গড়িয়ে দেন, এবং দিনকে রাতের উপর গড়িয়ে দেন। তিনি সূর্য এবং চাঁদকে নিয়োজিত করেছেন, প্রত্যেকে চলছে একটি সুনির্ধারিত মেয়াদের জন্য। নিঃসন্দেহে,তিনি সর্বশক্তিমান, ক্ষমাশীল।"],
  "39:6": ["He created you from one person, then created from him his mate. He sent down to you eight kinds of livestock. He creates you in your mothers' bellies, creation after creation, in trimesters of darkness. Such is Allah your Lord. To Him belongs all sovereignty. There is no other god beside Him. How could you deviate?","তিনি তোমাদেরকে এক ব্যক্তি থেকে সৃষ্টি করেছেন, তারপর তার থেকে সৃষ্টি করেছেন তার সঙ্গিনীকে। তিনি তোমাদের প্রতি আট প্রকার পালিত-পশু অবতীর্ণ করেছেন। তিনি তোমাদের সৃষ্টি করেন তোমাদের মায়ের পেটে,সৃষ্টির পর সৃষ্টি,তিন ধাপ অন্ধকারের মধ্যে। এমনই আল্লাহ তোমাদের প্রভু। তাঁর অধীনেই রয়েছে সকল সার্বভৌমত্ব। তাঁর পাশে অন্য কোন উপাস্য নেই। কি করে তোমরা পথভ্রষ্ট হতে পার?"],
  "39:7": ["If you disbelieve, Allah does not need anyone. But He dislikes to see His servants make the wrong decision. If you decide to be appreciative, He is pleased for you. No soul bears the sins of any other soul. Ultimately, to your Lord is your return, then He will inform you of everything you had done. He is fully aware of the innermost thoughts.","যদি তোমরা অবিশ্বাস কর, আল্লাহর কাউকে প্রয়োজন নেই। কিন্তু তিনি তাঁর বান্দাদের ভুল সিদ্ধান্ত নেওয়া দেখতে অপছন্দ করেন। কোন আত্মা অন্য কোন আত্মার পাপ বহন করে না। অবশেষে,তোমাদের প্রভুর কাছেই তোমাদের ফিরে যাওয়া,তখন তিনি তোমাদের সবকিছু জানাবেন যা তোমরা করেছিলে। তিনি গভীরতম চিন্তাগুলো সম্পর্কে পুরোপুরি অবগত।"],
  "39:8": ["When the human being is afflicted, he implores his Lord, sincerely devoted to Him. But as soon as He blesses him, he forgets his previous imploring, sets up idols to rank with Allah and to divert others from His path. Say, \"Enjoy your disbelief temporarily; you have incurred the hellfire.\"","যখন মানুষ দূর্দশাগ্রস্থ হয়, সে তার প্রভুর কাছে মিনতি করে,আন্তরিকভাবে তাঁর প্রতি নিবেদিত হয়ে। কিন্তু তিনি তাকে অনুগ্রহ করা মাত্রই, সে তার পূর্বের মিনতি ভুলে যায়, উপাস্য স্থাপন করে আল্লাহর সাথে সমকক্ষ করতে এবং অন্যদেরকে তাঁর পথ থেকে বিচ্যুত করতে। বল, “তোমাদের অবিশ্বাসকে কিছুকাল ভোগ করে নাও; তোমরা টেনে এনেছ নরকাগ্নি।”"],
  "39:9": ["Is it not better to be one of those who meditate in the night, prostrating and staying up, being aware of the Hereafter, and seeking the mercy of their Lord? Say, \"Are those who know equal to those who do not know?\" Only those who possess intelligence will take heed.","এটা কি উত্তম নয় তাদের একজন হওয়া যারা রাতে ধ্যান করে, সেজদা করে এবং জেগে থাকে, পরকালের বিষয়ে সচেতন হয়ে, এবং তাদের প্রভুর দয়া অন্বেষণ করে? বল, “যারা জানে তারা কি তাদের সমান যারা জানে না?”কেবল যারা বুদ্ধিমত্তার অধিকারী তারাই মনোযোগ দেবে।"],
  "39:10": ["Say, \"O My servants who believed, you shall reverence your Lord.\" For those who worked righteousness in this world, a good reward. Allah's earth is spacious, and those who steadfastly persevere will receive their recompense generously, without limits.","বল, “হে,আমার বান্দারা যারা বিশ্বাস করেছ, তোমরা তোমাদের প্রভুকে ভক্তি করবে।” যারা এই দুনিয়ায় সৎকর্ম করবে তাদের জন্য, এক ভালো পুরস্কার। আল্লাহর পৃথিবী প্রশস্ত, এবং যারা দৃঢ়তার সাথে অধ্যবসায়ী তারা তাদের প্রতিফল উদারভাবে পাবে, অফুরুন্ত।"],
  "39:11": ["Say, \"I have been commanded to worship Allah, devoting the religion absolutely to Him alone.","বল, “আমি আদেশপ্রাপ্ত হয়েছি আল্লাহর উপাসনা করতে, ধর্মকে সম্পূর্ণরূপে একমাত্র তাঁর প্রতি উৎসর্গ করে।"],
  "39:12": ["\"And I was commanded to be the utmost submitter.\"","“এবং আমি আদেশপ্রাপ্ত হয়েছিলাম সর্বাধিক আত্মসমর্পণকারী হতে।”"],
  "39:13": ["Say, \"I fear, if I disobeyed my Lord, the retribution of a great day.\"","বল, “আমি ভয় করি, যদি আমি আমার প্রভুকে অমান্য করি, এক মহা দিনের শাস্তিকে।”"],
  "39:14": ["Say, \"Allah is the only One I worship, devoting my religion absolutely to Him alone.","বল, “আল্লাহই একমাত্র সত্ত্বা যার উপাসনা আমি করি,আমার ধর্মকে সপুরোপুরি একমাত্র তাঁর প্রতি উৎসর্গ করে।"],
  "39:15": ["\"Therefore, worship whatever you wish besides Him.\" Say, \"The real losers are those who lose their souls, and their families, on the Day of Resurrection.\" Most certainly, this is the real loss.","“অতএব, তাঁর পাশে যা কিছুকে তোমাদের ইচ্ছা উপাসনা করো।” বল, “প্রকৃত ক্ষতিগ্রস্ত তারাই পুনরুত্থান দিনে যারা তাদের আত্মা, এবং তাদের পরিবার হারিয়েছে।” সুনিশ্চিতভাবে,এটাই আসল ক্ষতি।"],
  "39:16": ["They will have masses of fire on top of them, and under them. Allah thus alerts His servants: O My servants, you shall reverence Me.","তাদের উপরে এবং তাদের নিচে আগুনের পিণ্ড থাকবে। আল্লাহ এভাবে তাঁর বান্দাদের সতর্ক করেনঃ হে আমার বান্দারা,তোমরা আমাকে ভক্তি করবে।"],
  "39:17": ["As for those who discard the worship of all idols, and devote themselves totally to Allah alone, they have deserved happiness. Give good news to My servants.","তাদের ক্ষেত্রে যারা সকল উপাস্যের উপাসনা পরিত্যাগ করে, এবং নিজেদেরকে পুরোপুরি একমাত্র আল্লাহর প্রতি উৎসর্গ করে, তারা সুখ পাওয়ার উপযুক্ত হয়েছে। আমার বান্দাদের সুসংবাদ দাও।"],
  "39:18": ["They are the ones who examine all words, then follow the best. These are the ones whom Allah has guided; these are the ones who possess intelligence.","তারা হল সেই ব্যক্তি যারা সকল বানী পরীক্ষা করে, তারপর সর্বোৎকৃষ্টটি অনুসরণ করে। এরাই সে ব্যক্তি যাদেরকে আল্লাহ পথ- প্রদর্শন করেছেন; এরাই সে ব্যক্তি যারা বুদ্ধিমত্তার অধিকারী।"],
  "39:19": ["With regard to those who have deserved the retribution, can you save those who are already in Hell?","তাদের সম্পর্কে যারা শাস্তির উপযুক্ত হয়েছে, তুমি কি তাদের রক্ষা করতে পার যারা ইতোমধ্যেই নরকে রয়েছে?"],
  "39:20": ["As for those who reverence their Lord, they will have mansions upon mansions constructed for them, with flowing streams. This is Allah's promise, and Allah never breaks His promise.","তাদের ক্ষেত্রে যারা তাদের প্রভুকে ভক্তি-শ্রদ্ধা করে, তাদের জন্য প্রাসাদের উপর প্রাসাদ নির্মিত থাকবে, প্রবাহিত ঝর্ণাসহ। এটা আল্লাহর অঙ্গীকার, এবং আল্লাহ কখনো তাঁর অঙ্গীকার ভঙ্গ করেন না।"],
  "39:21": ["Do you not see that Allah sends down from the sky water, then places it into underground wells, then produces with it plants of various colors, then they grow until they turn yellow, then He turns them into hay? This should be a reminder for those who possess intelligence.","তুমি কি দেখ না যে আল্লাহ আকাশ থেকে পানি বর্ষণ করেন, তারপর একে ভূগর্ভস্থ কূপে রাখেন, এরপর তা দ্বারা উৎপাদন করেন বিভিন্ন রঙের গাছপালা, এরপর তারা বাড়তে থাকে হলুদ হয়ে যাওয়া পর্যন্ত, এরপর তিনি তাদেরকে খড়কুটো করে দেন? এটি তাদের জন্য একটি স্মারক হওয়া উচিৎ যাদের বুদ্ধিমত্তা আছে।"],
  "39:22": ["If Allah renders one's heart content with Submission, he will be following a light from his Lord. Therefore, woe to those whose hearts are hardened against Allah's message; they have gone far astray.","যদি আল্লাহ কারো হৃদয়কে আত্মসমর্পনে সন্তুষ্ট রাখেন, সে অনুসরণ করতে থাকবে তার প্রভুর পক্ষ থেকে একটি আলো। অতএব, তাদের জন্য দুর্ভাগ্য যাদের হৃদয় আল্লাহর বার্তার বিপক্ষে কঠিন; তারা বহুদূরে পথভ্রষ্ট।"],
  "39:23": ["Allah has revealed herein the best Hadith; a book that is consistent, and points out both ways (to Heaven and Hell). The skins of those who reverence their Lord cringe therefrom, then their skins and their hearts soften up for Allah's message. Such is Allah's guidance; He bestows it upon whomever He wills. As for those sent astray by Allah, nothing can guide them.","আল্লাহ এর মধ্যে প্রকাশ করেছেন সর্বোৎকৃষ্ট হাদিস; একটি গ্রন্থ যা সামঞ্জস্যপূর্ণ, এবং নির্দেশ করে উভয় পথ (স্বর্গ ও নরক)। যারা তাদের প্রভুকে ভক্তি-শ্রদ্ধা করে তাদের চামড়া তা থেকে শিহরিত হয়, এরপর তাদের চামড়া এবং তাদের হৃদয় আল্লাহর বার্তার জন্য নরম হয়। এমনই আল্লাহর পথনির্দেশনা। যার উপর ইচ্ছা তিনি তা অর্পণ করেন। তাদের ক্ষেত্রে যারা আল্লাহ দ্বারা পথভ্রষ্ট, কোনকিছুই তাদের পথ-প্রদর্শন করতে পারে না।"],
  "39:24": ["What is better than saving one's face from the terrible retribution on the Day of Resurrection? The transgressors will be told, \"Taste the consequences of what you earned.\"","পুনরুত্থান দিনে কারো মুখমন্ডলকে ভয়ঙ্কর শাস্তি থেকে রক্ষা পাওয়া থেকে উত্তম আর কি হতে পারে? সীমালঙ্ঘনকারীদের বলা হবে, “তোমরা যা অর্জন করেছ তার পরিণাম আস্বাদন করো।\""],
  "39:25": ["Others before them have disbelieved and, consequently, the retribution afflicted them whence they never expected.","তাদের পূর্বে অন্যরা অবিশ্বাস করেছে এবং, ফলস্বরূপ, শাস্তি তাদের দুর্দশাগ্রস্থ করেছে যেখান থেকে তারা কখনো আশাই করেনি।"],
  "39:26": ["Allah has condemned them to humiliation in this life, and the retribution in the Hereafter will be far worse, if they only knew.","আল্লাহ তাদের অভিশপ্ত করেছেন এই জীবনে অপমানিত করে, এবং পরকালের শাস্তি হবে আরো অধিকতর মন্দ, যদি শুধু তারা জানতো।"],
  "39:27": ["We have cited for the people every kind of example in this Quran, that they may take heed.","আমরা লোকদের জন্য এই কুরআনে সকল প্রকার উদাহরণ উদ্ধৃত করেছি, যাতে তারা সতর্ক হতে পারে।"],
  "39:28": ["An Arabic Quran, without any ambiguity, that they may be righteous.","একটি আরবি কুরআন, কোন অস্পষ্টতা ছাড়াই, যাতে তারা সৎকর্মশীল হতে পারে।"],
  "39:29": ["Allah cites the example of a man who deals with disputing partners (Hadith), compared to a man who deals with only one consistent source (Quran). Are they the same? Praise be to Allah; most of them do not know.","আল্লাহ এক লোকের উদাহরণ দেন যে বিরোধপূর্ণ অংশীদারদের (হাদিস) সাথে কারবার করে, সে লোকের তুলনায় যে কারবার করে শুধু একটি সামঞ্জস্যপূর্ণ উৎসের (কুরআনের) সাথে। তারা কি একই রকম? প্রশংসা আল্লাহর; তাদের বেশিরভাগই জানে না।"],
  "39:30": ["You (Muhammad) will surely die, just like they will die.","তুমি (মুহাম্মদ) অবশ্যই মারা যাবে, ঠিক যেমন তারা মারা যাবে।"],
  "39:31": ["On the Day of Resurrection, before your Lord, you people will feud with one another.","পুনরুত্থানের দিনে, তোমাদের প্রভুর সামনে, তোমরা পরস্পর বিবাদ করবে।"],
  "39:32": ["Who is more evil than one who attributes lies to Allah, while disbelieving in the truth that has come to him? Is Hell not a just requital for the disbelievers?","তার থেকে অধিক মন্দ আর কে যে আল্লাহর প্রতি মিথ্যা আরোপ করে, এবং অবিশ্বাস করে সে সত্যে যা তার কাছে এসেছে? নরক কি অবিশ্বাসীদের জন্য সঠিক প্রতিফল নয়?"],
  "39:33": ["As for those who promote the truth, and believe therein, they are the righteous.","তাদের ক্ষেত্রে যারা সত্যকে তুলে ধরে, এবং তাতে বিশ্বাস করে, তারাই হল সৎকর্মশীল।"],
  "39:34": ["They will get everything they wish, at their Lord. Such is the reward for the righteous.","তারা যা আকাঙ্ক্ষা করবে সবকিছুই পাবে, তাদের প্রভুর কাছে। সৎকর্মশীলদের জন্য এটাই পুরস্কার।"],
  "39:35": ["Allah remits their sinful works, and rewards them generously for their good works.","আল্লাহ তাদের পাপপূর্ণ কাজগুলোকে মোচন করে দেন, এবং তাদের ভালো কাজের জন্য তাদেরকে উদারভাবে পুরস্কৃত করেন।"],
  "39:36": ["Is Allah not sufficient for His servant? They frighten you with the idols they set up beside Him. Whomever Allah sends astray, nothing can guide him.","আল্লাহ কি তাঁর বান্দার জন্য যথেষ্ট নয়? তারা তোমাকে ভয় দেখায় আল্লাহর পাশে তাদের স্থাপন করা উপাস্যদের দিয়ে। যাকে আল্লাহ পথভ্রষ্ট করেন, কোনকিছুই তাকে পথ প্রদর্শন করতে পারে না।"],
  "39:37": ["And whomever Allah guides, nothing can send him astray. Is Allah not Almighty, Avenger?","এবং যাকে আল্লাহ পথ প্রদর্শন করেন, কোনকিছুই তাকে পথভ্রষ্ট করতে পারে না। আল্লাহ কি সর্বশক্তিমান, প্রতিশোধগ্রহণকারী নন?"],
  "39:38": ["If you ask them, \"Who created the heavens and the earth?\" they will say, \"Allah.\" Say, \"Why then do you set up idols beside Allah? If Allah willed any adversity for me, can they relieve such an adversity? And if He willed a blessing for me, can they prevent such a blessing?\" Say, \"Allah is sufficient for me.\" In Him the trusters shall trust.","যদি তুমি তাদের জিজ্ঞাসা করো, “কে আকাশমন্ডলী এবং পৃথিবী সৃষ্টি করেছে?” তারা বলবে, “আল্লাহ।” বল, “কেন তবে তোমরা আল্লাহর পাশে উপাস্যদের স্থাপন করো? যদি আল্লাহ আমার জন্য কোন দুর্দশা চান, তারা কি এমন দুর্দশা লাঘব করতে পারে? এবং তিনি যদি আমার জন্য কল্যান চান, তারা কি এমন কল্যান আটকাতে পারে?’’ বল, ‘আল্লাহ আমার জন্য যথেষ্ট।” তাঁরই প্রতি আস্থাশীলদের আস্থা রাখা উচিত।"],
  "39:39": ["Say, \"O my people, do your best and I will do my best; you will surely find out.","বল, “হে আমার লোকেরা, তোমাদের সর্বোত্তমটি করো আর আমি আমার সর্বোত্তমটি করবো; তোমরা অবশ্যই দেখতে পাবে।"],
  "39:40": ["\"(You will find out) who has incurred shameful punishment, and has deserved an eternal retribution.\"","“(তোমরা দেখতে পাবে) কে টেনে এনেছে নিজের লজ্জাজনক শাস্তি, এবং যোগ্য হয়েছে এক চিরস্থায়ী শাস্তির।”"],
  "39:41": ["We have revealed the scripture through you for the people, truthfully. Then, whoever is guided is guided for his own good, and whoever goes astray goes astray to his own detriment. You are not their advocate.","আমরা তোমার মাধ্যমে মানুষের জন্য ঐশী-গ্রন্থ প্রকাশ করেছি, সত্যসহকারে। অতপর, যেকেউ সুপথপ্রাপ্ত হয় সে তার নিজের ভালোর জন্যই সুপথপ্রাপ্ত হয়, এবং যেকেউ বিপথে যায় সে বিপথে যেয়ে তার নিজেরই ক্ষতি করে। তুমি তাদের উকিল নও।"],
  "39:42": ["Allah puts the souls to death when the end of their life comes, and also at the time of sleep. Thus, He takes some back during their sleep, while others are allowed to continue living until the end of their predetermined interim. This should provide lessons for people who reflect.","ঈশ্বর আত্মাদের মৃত্যু দেন যখন তাদের জীবনের শেষ হয়, এবং ঘুমের সময় ও। এভাবে, তিনি কতককে ফিরিয়ে নেন তাদের ঘুমের মধ্যে, এবং অন্যরা জীবিত থাকার অনুমতি পায় তাদের পূর্ব নির্ধারিত সময় কালের শেষ পর্যন্ত। এটা সেসব লোকদের জন্য শিক্ষা হওয়া উচিৎ যারা ভেবে দেখে।"],
  "39:43": ["Have they invented intercessors to mediate between them and Allah? Say, \"What if they do not possess any power, nor understanding?\"","তারা কি তাদের এবং ঈশ্বরের মঝে মধ্যস্থতা করার জন্য সুপারিশকারী উদ্ভাবন করেছে? বল, “যদি এমন হয় যে তাদের কোন ক্ষমতা বা বোধশক্তি নেই?”"],
  "39:44": ["Say, \"All intercession belongs to Allah.\" To Him belongs all sovereignty of the heavens and the earth, then to Him you will be returned.","বল, “সকল সুপারিশ ঈশ্বরের অধীনে।” তাঁর অধীনেই রয়েছে আকাশ মণ্ডলী এবং পৃথিবীর সকল সার্বভৌমত্ব, এরপর তাঁর কাছেই তোমারা ফিরে যাবে।"],
  "39:45": ["When Allah ALONE is mentioned, the hearts of those who do not believe in the Hereafter shrink with aversion. But when others are mentioned beside Him, they become satisfied.","যখন শুধু মাত্র ঈশ্বরকে উল্লেখ করা হয়, যারা পরকালে বিশ্বাস করে না তাদের হৃদয় বিমুখতায় সঙ্কুচিত হয়ে যায়। কিন্তু যখন তাঁর পাশে অন্যদের উল্লেখ করা হয়, তখন তারা সন্তুষ্ট হয়।"],
  "39:46": ["Proclaim: \"Our god, Initiator of the heavens and the earth, Knower of all secrets and declarations, You are the only One who judges among Your servants regarding their disputes.\"","ঘোষণা করঃ “আমাদের উপাস্য, আকাশমণ্ডলী ও পৃথিবীর সূচনাকারী, সকল গোপন এবং প্রকাশ্য বিষয়ের জ্ঞাতা, আপনিই একমাত্র সত্ত্বা যিনি তাঁর বান্দাদের মধ্যে বিচার করবেন তাঁদের বিবাদের বিষয়ে।”"],
  "39:47": ["If those who transgressed owned everything on earth, even twice as much, they would readily give it up to avoid the terrible retribution on the Day of Resurrection. They will be shown by Allah what they never expected.","যারা সীমালঙ্ঘন করেছে তারা যদি পৃথিবীর সবকিছুর মালিক হয়, এমনকি এর দিগুন পরিমাণের, তারা তৎক্ষণাৎ তা দিয়ে দিবে পুনরুত্থান দিনের ভয়ানক শাস্তি এড়াতে। ঈশ্বর কর্তৃক তাদেরকে দেখানো হবে যা তারা কখনই আশা করেনি।"],
  "39:48": ["The sinful works they had earned will be shown to them, and the very things they used to mock will come back to haunt them.","তাদেরকে পাপপূর্ণ কাজগুলো দেখানো হবে যা তারা অর্জন করেছিলো,এবং যে জিনিসকে তারা উপহাস করতো সেগুলোই তাদেরকে হানা দিতে ফিরে আসবে।"],
  "39:49": ["If the human is touched by adversity, he implores us, but as soon as we bestow a blessing upon him, he says, \"I attained this because of my cleverness!\" Indeed, this is only a test, but most of them do not know.","যদি মানুষকে দুর্দশা স্পর্শ করে, সে আমাদের কাছে মিনতি করে, কিন্তু আমরা তার প্রতি কোন অনুগ্রহ দান করা মাত্রই, সে বলে,“আমি এটা পেয়েছি আমার চতুরতার কারনে!” নিশ্চয়, এটি কেবলমাত্র একটি পরীক্ষা, কিন্তু তাদের বেশির ভাগই জানে না।"],
  "39:50": ["Those before them have uttered the same thing, and their earnings did not help them in the least.","তাদের পূর্বে যারা ছিল তারাও একই রকম বলেছে, এবং তাদের উপার্জন তাদেরকে সমান্যতম সাহায্যও করেনি।"],
  "39:51": ["They suffered the consequences of their evil works. Similarly, the transgressors among the present generation will suffer the consequences of their evil works; they cannot escape.","তারা ভোগ করেছিলো তাদের মন্দ কাজের পরিণতি। একইভাবে, বর্তমান প্রজন্মদের মধ্যে সীমালঙ্ঘনকারীরা ভোগ করবে তাদের মন্দ কাজের পরিণতি; তারা পালাতে পারবে না।"],
  "39:52": ["Do they not realize that Allah is the One who increases the provision for whomever He chooses, and withholds? These are lessons for people who believe.","তারা কি উপলব্ধি করে না যে ঈশ্বরই সে সত্ত্বা যিনি যার জন্য পছন্দ করেন জীবিকা বৃদ্ধি করে দেন, আর আটকিয়ে রাখেন? এগুলো লোকদের জন্য শিক্ষা যারা বিশ্বাস করে।"],
  "39:53": ["Proclaim: \"O My servants who exceeded the limits, never despair of Allah's mercy. For Allah forgives all sins. He is the Forgiver, Most Merciful.\"","ঘোষণা করঃ “হে আমার বান্দারা যারা সীমাতিক্রম করেছ, ঈশ্বরের দয়া থেকে কখনো হতাশ হইয়ো না। কারন ঈশ্বর সকল পাপ ক্ষমা করেন। তিনি ক্ষমাকারী, সবচেয়ে দয়ালু।”"],
  "39:54": ["You shall obey your Lord, and submit to Him totally, before the retribution overtakes you, then you cannot be helped.","তোমরা তোমাদের প্রভুকে মান্য করবে, এবং তাঁর কাছে পরিপূর্ণ আত্মসমর্পণ করবে, শাস্তি তোমাদের কাছে আসার আগেই, তখন তোমরা সাহায্য প্রাপ্ত হবে না।"],
  "39:55": ["And follow the best path that is pointed out for you by your Lord, before the retribution overtakes you suddenly when you least expect it.","এবং সর্বোত্তম পথ অনুসরণ করো যা তোমাদের জন্য নির্দেশ করা হয়েছে তোমাদের প্রভুর পক্ষ থেকে, শাস্তি তোমাদের কাছে হঠাৎ আসার আগেই যখন তোমরা সামান্যই তা আশা করো।"],
  "39:56": ["Lest a soul may say, \"How sorry I am for disregarding Allah's commandments; I was certainly one of the mockers.\"","পাছে কোন আত্মা বলে, \"আল্লাহর আদেশ অমান্য করার জন্য আমি কত দুঃখিত! আমি অবশ্যই বিদ্রূপকারীদের একজন ছিলাম।\""],
  "39:57": ["Or say, \"Had Allah guided me, I would have been with the righteous.\"","অথবা বলে, \"যদি আল্লাহ আমাকে পথ দেখাতেন, তাহলে আমি অবশ্যই সৎকর্মশীলদের অন্তর্ভুক্ত হতাম।\""],
  "39:58": ["Or say, when it sees the retribution, \"If I get another chance, I will work righteousness.\"","অথবা যখন এটি শাস্তি দেখে, তখন বলে, \"যদি আমি আবার সুযোগ পাই, আমি সৎকর্ম করব।\""],
  "39:59": ["Yes indeed (you did get enough chances). My proofs came to you, but you rejected them, turned arrogant, and became a disbeliever.","হ্যাঁ মূলত (তুমি যথেষ্ট সুযোগ পেয়েছ)। আমার প্রমাণ তোমার কাছে এসেছিল, কিন্তু তুমি সেগুলো প্রত্যাখ্যান করেছ, অহংকার করেছ এবং অবিশ্বাসী হয়ে গিয়েছিলে।"],
  "39:60": ["On the Day of Resurrection you will see the faces of those who lied about Allah covered with misery. Is Hell not the right retribution for the arrogant ones?","যারা আল্লাহর উপর মিথ্যা আরোপ করেছে, পুরুন্থানের দিন তুমি তাদের মুখমণ্ডল দুর্বিষহ দেখতে পাবে। নরক কি অহংকারীদের জন্য উপযুক্ত শাস্তি নয়?"],
  "39:61": ["And Allah will save those who have maintained righteousness; He will reward them. No harm will touch them, nor will they have any grief.","আর যারা সৎকর্ম করেছে, আল্লাহ তাদেরকে রক্ষা করবেন; তিনি তাদেরকে প্রতিদান দেবেন। তাদের কোন ক্ষতি স্পর্শ করবে না এবং তাদের কোন দুঃখও থাকবেনা।"],
  "39:62": ["Allah is the Creator of all things, and He is in full control of all things.","আল্লাহ সকল কিছুর স্রষ্টা, এবং তিনি সকল কিছুর উপর পূর্ণ নিয়ন্ত্রণ রাখেন।"],
  "39:63": ["To Him belongs all decisions in the heavens and the earth, and those who disbelieve in Allah's revelations are the real losers.","আসমান ও পৃথিবীর সকল সিদ্ধান্ত তাঁরই, আর যারা আল্লাহর প্রত্যাদেশসমূহ অবিশ্বাস করে, তারাই প্রকৃত ক্ষতিগ্রস্ত।"],
  "39:64": ["Say, \"Is it other than Allah you exhort me to worship, O you ignorant ones?\"","বল, \"হে অজ্ঞরা, তোমরা কি আমাকে আল্লাহ ব্যতীত অন্যের উপাসনা করতে উৎসাহিত করছো?\""],
  "39:65": ["It has been revealed to you, and to those before you that if you ever commit idol worship, all your works will be nullified, and you will be with the losers.","তোমার প্রতি এবং তোমার পূর্ববর্তীদের প্রতি প্রকাশ করা হয়েছে যে, যদি তুমি কখনও প্রতিমা উপাসনা করো, তাহলে তোমার সমস্ত আমল নিষ্ফল হয়ে যাবে এবং তুমি ক্ষতিগ্রস্তদের অন্তর্ভুক্ত হবে।"],
  "39:66": ["Therefore, you shall worship Allah alone, and be appreciative.","অতএব, তোমরা একমাত্র আল্লাহর ইবাদত করবে এবং কৃতজ্ঞ হবে।"],
  "39:67": ["They can never fathom the greatness of Allah. The whole earth is within His fist on the Day of Resurrection. In fact, the universes are folded within His right hand. Be He glorified; He is much too high above needing any partners.","তারা কখনোই আল্লাহর বিশালত্ব উপলব্ধি করতে পারবে না। পুনরন্থানের দিন সমগ্র পৃথিবী তাঁর মুঠোয় থাকবে। বস্তুত, সমস্ত বিশ্বজগৎ তাঁর ডান হাতে ভাঁজ করা থাকবে।* তিনি মহিমান্বিত; তিনি কোন অংশীদারের প্রয়োজনের চেয়ে অনেক উঁচুতে।"],
  "39:68": ["The horn will be blown, whereupon everyone in the heavens and the earth will be struck unconscious, except those who will be spared by Allah. Then it will be blown another time, whereupon they will all rise up, looking.","শিঙ্গায় ফুঁ দেওয়া হবে, যার ফলে আকাশ ও পৃথিবীর সকলেই অজ্ঞান হয়ে পড়বে, তবে আল্লাহ যাদেরকে রক্ষা করবেন তারা ছাড়া। তারপর আরেকবার ফুঁ দেওয়া হবে, যার ফলে তারা সকলেই উঠে দাঁড়াবে, আর দেখতে থাকবে।"],
  "39:69": ["Then the earth will shine with the light of its Lord. The record will be proclaimed, and the prophets and the witnesses will be brought forth. Everyone will then be judged equitably, without the least injustice.","অতঃপর পৃথিবী তার প্রতিপালকের আলোতে আলোকিত হবে। লিপিবদ্ধ নথি ঘোষণা করা হবে, নবীগন ও সাক্ষীদের সামনে আনা হবে। অতঃপর প্রত্যেকের ন্যায়সঙ্গত বিচার করা হবে, সামান্যতম অন্যায় ছাড়াই।"],
  "39:70": ["Every soul will be paid for whatever it did, for He is fully aware of everything they have done.","প্রত্যেক আত্মা যা কিছু করেছে তার প্রতিদান পাবে, কারণ তিনি তাদের কৃতকর্ম সম্পর্কে পূর্ণ অবগত।"],
  "39:71": ["Those who disbelieved will be led to Hell in throngs. When they get to it, and its gates are opened, its guards will say, \"Did you not receive messengers from among you, who recited to you the revelations of your Lord, and warned you about meeting this day?\" They will answer, \"Yes indeed. But the word 'retribution' was already stamped upon the disbelievers.\"","যারা অবিশ্বাস করেছিল তাদেরকে দলে দলে নরকের দিকে নিয়ে যাওয়া হবে। যখন তারা নরকের কাছে পৌঁছাবে এবং তার দরজাগুলো খুলে দেওয়া হবে, তখন তার রক্ষীরা বলবে, \"তোমাদের মধ্যে কি তোমাদের কাছে এমন বার্তাবাহকরা আসেনি যারা তোমাদের কাছে তোমাদের প্রতিপালকের প্রত্যাদেশ পাঠ করতেন এবং এই দিনের সাক্ষাতের বিষয়ে তোমাদের সতর্ক করতেন?\" তারা বলবে, \"হ্যাঁ, অবশ্যই। কিন্তু অবিশ্বাসীদের উপর 'শাস্তি' শব্দটি ইতিমধ্যেই সীলমোহর করে দেয়া হয়েছে।\""],
  "39:72": ["It will be said, \"Enter the gates of Hell, wherein you abide forever.\" What a miserable destiny for the arrogant.","বলা হবে, \"নরকের দরজা দিয়ে প্রবেশ করো, সেখানে তোমরা চিরকাল থাকবে।\" অহংকারীদের জন্য কতই না নিকৃষ্ট পরিণতি!"],
  "39:73": ["Those who reverenced their Lord will be led to Paradise in throngs. When they get to it, and its gates are opened, its guards will say, \"Peace be upon you; you have won. Therefore, you abide herein forever.\"","যারা তাদের প্রতিপালকের প্রতি ভিতশ্রদ্‌ধ ছিল, তাদেরকে দলে দলে সর্গের দিকে নিয়ে যাওয়া হবে। যখন তারা সর্গের কাছে পৌঁছাবে এবং তার দরজাগুলো খুলে দেওয়া হবে, তখন তার রক্ষীরা বলবে, \"তোমাদের উপর শান্তি বর্ষিত হোক; তোমরা জয়ী হয়েছো। অতএব, তোমরা এখানে চিরকাল অবস্থান করবে।\""],
  "39:74": ["They will say, \"Praise be to Allah, who fulfilled His promise to us, and made us inherit the earth, enjoying Paradise as we please.\" What a beautiful recompense for the workers!","তারা বলবে, \"সমস্ত প্রশংসা আল্লাহর, যিনি আমাদের সাথে করা তাঁর প্রতিশ্রুতি পূর্ণ করেছেন এবং আমাদেরকে পৃথিবীর উত্তরাধিকারী করেছেন, আমরা যেমন ইচ্ছা সর্গ উপভোগ করব।\" কর্মশীলদের জন্য কত সুন্দর প্রতিদান!"],
  "39:75": ["You will see the angels floating around the throne, glorifying and praising their Lord. After the equitable judgment is issued to all, it will be proclaimed: \"Praise be to Allah, Lord of the universe.\"","তুমি দেখতে পাবে যে, ফেরেশতারা আরশের চারপাশে ভেসে বেড়াচ্ছে, তাদের প্রতিপালকের প্রশংসা ও মহিমা ঘোষণা করছে। সকলের প্রতি ন্যায়সঙ্গত রায় ঘোষণার পর ঘোষণা করা হবে: \"সমস্ত প্রশংসা আল্লাহর, যিনি মহাবিশ্বের প্রতিপালক।\""],
  "40:1": ["H. M.","হ. ম. (হা মীম)"],
  "40:2": ["This revelation of the scripture is from Allah, the Almighty, the Omniscient.","ঐশীগ্রন্থের এই প্রকাশনাবলি সর্বশক্তিমান, সর্বজ্ঞ আল্লাহর পক্ষ থেকে।"],
  "40:3": ["Forgiver of sins, acceptor of repentance, strict in enforcing retribution, and possessor of all power. There is no other god beside Him. To Him is the ultimate destiny.","পাপসমূহ ক্ষমাকারী, অনুশোচনা গ্রহনকারী, শাস্তি প্রয়োগে কঠোর এবং সকল ক্ষমতার মালিক। তাঁর পাশে অন্য কোন উপাস্য নেই। তাঁর কাছেই চূড়ান্ত নিয়তি।"],
  "40:4": ["None argues against Allah's revelations except those who disbelieve. Do not be impressed by their apparent success.","তারা ব্যতীত কেউ আল্লাহর প্রকাশনাবলির বিরুদ্ধে তর্ক করে না যারা অবিশ্বাস করে। তাদের আপাত সফলতায় অভিভূত হইও না।"],
  "40:5": ["Disbelieving before them were the people of Noah, and many other opponents after them. Every community persecuted their messenger to neutralize him. And they argued with falsehood, to defeat the truth. Consequently, I punished them; how terrible was My retribution!","তাদের আগে নূহের লোকেরা অবিশ্বাসী ছিল, আর তাদের পরে ছিল অন্য অনেক বিরোধী। প্রত্যেক সম্প্রদায় তাদের বার্তাবাহককে কষ্ট দিতো তাকে নিষ্ক্রিয় করতে। আর তারা মিথ্যা দিয়ে তর্ক করতো। পরিনামে, আমি তাদেরকে শাস্তি দিয়েছিলাম; কত ভয়াবহ ছিল আমার শাস্তি!"],
  "40:6": ["Thus, the judgment of your Lord is already stamped upon those who disbelieve, that they are the dwellers of Hell.","সুতরাং, যারা অবিশ্বাস করে তাদের উপর তোমার প্রভুর রায় ইতিমধ্যেই এটে দেয়া আছে, যে তারা নরকের বাসিন্দা।"],
  "40:7": ["Those who serve the throne and all those around it glorify and praise their Lord, and believe in Him. And they ask forgiveness for those who believe: \"Our Lord, Your mercy and Your knowledge encompass all things. Forgive those who repent and follow Your path, and spare them the retribution of Hell.","যারা আরশের কাজে নিয়োজিত এবং যারা এর আশেপাশে আছে তারা সবাই তাদের প্রভুর  মহিমা ঘোষণা করে এবং গুণকীর্তণ করে,  এবং তাঁর প্রতি বিশ্বাস রাখে। আর তারা তাদের জন্য ক্ষমা প্রার্থনা করে যারা বিশ্বাস করে:\"আমাদের প্রভু, আপনার ক্ষমা এবং আপনার জ্ঞান সবকিছু পরিবেষ্টন করে। তাদেরকে ক্ষমা করুন যারা অনুশোচনা করে এবং আপনার পথ অনুসরণ করে, এবং তাদেরকে নরকের শাস্তি থেকে নিষ্কৃতি দিন।\""],
  "40:8": ["\"Our Lord, and admit them into the gardens of Eden that You promised for them and for the righteous among their parents, spouses, and children. You are the Almighty, Most Wise.","“আমাদের প্রভু, এবং তাদেরকে ইডেন বাগানগুলোয় প্রবেশ করান যার প্রতিশ্রুতি আপনি দিয়েছেন তাদের জন্য এবং তাদের পিতা-মাতা, স্বামী-স্ত্রী, ও সন্তানদের মধ্যে সৎকর্মশীলদের জন্য। আপনি সর্বশক্তিমান, সবচেয়ে জ্ঞানী।\""],
  "40:9": ["\"And protect them from falling in sin. Whomever You protect from falling in sin, on that day, has attained mercy from You. This is the greatest triumph.\"","“এবং তাদেরকে পাপে পতিত হওয়া থেকে রক্ষা করুন। যাকে আপনি পাপে পতিত হওয়া থেকে রক্ষা করেন, ঐদিন, সে আপনার দয়া পেয়েছে। এটাই সর্বশ্রেষ্ঠ বিজয়”।"],
  "40:10": ["Those who disbelieve will be told, \"Allah's abhorrence towards you is even worse than your own abhorrence towards yourselves. For you were invited to believe, but you chose to disbelieve.\"","যারা অবিশ্বাস করে তাদেরকে বলা হবে, “এমনকি তোমাদের নিজেদের প্রতি তোমাদের ঘৃনার চেয়ে তোমাদের প্রতি আল্লাহর ঘৃনা নিকৃষ্টতম। কারন তোমাদেরকে বিশ্বাস করতে আমন্ত্রণ করা হয়েছিল, কিন্তু তোমরা অবিশ্বাস করা পছন্দ করেছিলে।"],
  "40:11": ["They will say, \"Our Lord, you have put us to death twice, and You gave us two lives; now we have confessed our sins. Is there any way out?\"","তারা বলবে, \"আমাদের প্রভু, আপনি আমাদের দুই মৃত্যু দিয়েছেন, ” এবং আপনি আমাদের দুই জীবন দিয়েছেন; এখন আমরা আমাদের পাপ স্বীকার করেছি। কোন উপায় আছে কি?"],
  "40:12": ["This is because when Allah ALONE was advocated, you disbelieved, but when others were mentioned beside Him, you believed. Therefore, Allah's judgment has been issued; He is the Most High, the Great.","এটা এ কারণে যে যখন একমাত্র আল্লাহর কথা বলা হতো তোমরা তখন অবিশ্বাস করতে, কিন্তু যখন তাঁর সাথে অন্যদের উল্লেখ করা হতো, তোমরা বিশ্বাস করতে। অতএব, আল্লাহর রায় হয়ে গেছে; তিনি সবচেয়ে উর্ধ্বে, মহান।"],
  "40:13": ["He is the One who continuously shows you His proofs, and sends down to you from the sky provisions. Only those who totally submit will be able to take heed.","তিনিই সে সত্ত্বা যিনি অনবরত তোমাদেরকে তাঁর প্রমানাদি দেখান, এবং আকাশ থেকে তোমাদের কাছে জীবিকা পাঠান। যারা পুরোপুরি আত্মসমর্পণ করে তারাই কেবল মনোযোগ দিতে পারে।"],
  "40:14": ["Therefore, you shall devote your worship absolutely to Allah ALONE, even if the disbelievers dislike it.","অতএব, তোমরা তোমাদের উপাসনা পুরোপুরিভাবে একমাত্র আল্লাহর প্রতি নিবেদন করবে, এমনকি যদিও অবিশ্বাসীরা তা অপছন্দ করে।"],
  "40:15": ["Possessor of the highest ranks, and Ruler of the whole dominion. He sends inspiration, bearing His commands, to whomever He chooses from among His servants, to warn about the Day of Summoning.","সর্বোচ্চ পদমর্যাদাসমূহের মালিক, এবং সমস্ত রাজত্বের শাসক। তিনি অনুপ্রেরণা পাঠান, তাঁর প্রত্যাদেশ দিয়ে, তাঁর বান্দাদের মধ্যে থেকে যার কাছেই তিনি পছন্দ করেন, তলবের দিন সম্পর্কে সতর্ক করতে।"],
  "40:16": ["That is the day when everyone will be completely exposed; none of them will hide anything from Allah. To whom belongs all sovereignty on that day? To Allah, the One, the Supreme.","এটা সে দিন যখন সকলে পুরোপুরি প্রকাশিত হবে; তাদের কেউ আল্লাহ থেকে কোন কিছু লুকাবে না। ঐদিনের সকল সার্বভৌমত্ব কার অধীনে? আল্লাহর, একক, সর্বোচ্চ।"],
  "40:17": ["On that day, every soul will be requited for whatever it had earned. There will be no injustice on that day. Allah is most efficient in reckoning.","ঐদিন, প্রত্যেক তার জন্য আত্মা প্রতিদান পাবে যাকিছুই সে অর্জন করেছে। সেদিন কোন অবিচার থাকবে না। আল্লাহ হিসাব গ্রহনে দক্ষ।"],
  "40:18": ["Warn them about the imminent day, when the hearts will be terrified, and many will be remorseful. The transgressors will have no friend nor an intercessor to be obeyed.","তাদেরকে আসন্ন দিন সম্পর্কে সতর্ক করো, যখন হৃদয়গুলো আতংকিত হবে, এবং অনেকে হবে অনুতপ্ত। সীমালঙ্ঘনকারীদের কোন বন্ধু থাকবে না, না থাকবে কোন সুপারিশকারী যার কথা মান্য করা হবে।"],
  "40:19": ["He is fully aware of what the eyes cannot see, and everything that the minds conceal.","তিনি সম্পূর্ণ অবগত চোখ যা দেখে না, এবং সবকিছু সম্পর্কে যা মন গোপন করে।"],
  "40:20": ["Allah judges equitably, while the idols they implore beside Him cannot judge anything. Allah is the One who is the Hearer, the Seer.","আল্লাহ ন্যায়সঙ্গতভাবে বিচার করেন, যখন তাঁর পাশে তারা যে উপাস্যদের কাছে মিনতি করে, তারা কোনকিছু বিচার করতে পারে না। আল্লাহ সে সত্ত্বা যিনি শুনেন, দেখেন।"],
  "40:21": ["Did they not roam the earth and note the consequences for those before them? They used to be stronger than they, and more productive on earth. But Allah punished them for their sins, and nothing could protect them from Allah.","তারা কি পৃথিবীতে ঘুড়ে দেখেনি এবং তাদের পূর্ববর্তীদের পরিনতি লক্ষ্য করেনি? পৃথিবীতে তারা তাদের চেয়ে শক্তিশালী, এবং অধিক উৎপাদনশীল ছিল। কিন্তু আল্লাহ তাদের পাপসমূহের জন্য তাদেরকে শাস্তি দিয়েছিলেন, এবং কিছুই তাদেরকে আল্লাহ থেকে রক্ষা করতে পারেনি।"],
  "40:22": ["That is because their messengers went to them with clear proofs, but they disbelieved. Consequently, Allah punished them. He is Mighty, strict in enforcing retribution.","এটা এ কারণে যে তাদের বার্তাবাহকরা তাদের কাছে স্পষ্ট প্রমাণাদি নিয়ে গিয়েছিল, কিন্তু তারা অবিশ্বাস করেছিল। পরিনামে, আল্লাহ তাদের শাস্তি দিয়েছিলেন। তিনি শক্তিমান, শাস্তি প্রদানে কঠোর।"],
  "40:23": ["We sent Moses with our signs and a profound authority.","আমরা মূসাকে আমাদের নিদর্শনাবলী এবং অসমান্য কর্তৃত্ব দিয়ে পাঠিয়েছিলাম।"],
  "40:24": ["To Pharaoh, Hãmãn, and Qãroon. But they said, \"A magician; a liar.\"","ফেরাউন, হামান, এবং ক্বারুনের কাছে। কিন্তু তারা বলেছিল, “একজন যাদুকর; মিথ্যুক।"],
  "40:25": ["And when he showed them the truth from us, they said, \"Kill the sons of those who believed with him, and spare their daughters.\" Thus, the scheming of the disbelievers is always wicked.","যখন সে তাদেরকে আমাদের পক্ষ থেকে সত্য দেখালো, তারা বলেছিল, \"তার সাথে যারা বিশ্বাস করেছে তাদের পুত্রদের হত্যা করো, এবং কন্যাদের রেহাই দাও।” এভাবে, অবিশ্বাসীদের চক্রান্ত সবসময় অন্যায়।"],
  "40:26": ["Pharaoh said, \"Let me kill Moses, and let him implore his Lord. I worry lest he corrupts your religion, or spreads evil throughout the land.\"","ফেরাউন বলেছিল, \"চল মূসাকে আমি হত্যা করি, এবং তার প্রভুর কাছে তাকে মিনতি করতে দাও। আমার ভয় হয় পাছে সে তোমাদের ধর্মকে কলুষিত করে ফেলে, অথবা স্থলভাগ জুড়ে মন্দ ছড়ায়।"],
  "40:27": ["Moses said, \"I seek refuge in my Lord and your Lord, from every arrogant one who does not believe in the Day of Reckoning.\"","মুসা বলেছিল, \"আমি আমার প্রভু এবং তোমাদের প্রভুর কাছে আশ্রয় প্রার্থনা করছি, প্রত্যেক উদ্ধত ব্যক্তি থেকে যে হিসাবগ্রহণের দিনে বিশ্বাস করে না।"],
  "40:28": ["A believing man among Pharaoh's people, who was concealing his belief, said, \"How can you kill a man just for saying, 'My Lord is Allah,' and he has shown you clear proofs from your Lord? If he is a liar, that is his problem, and if he is truthful, you benefit from his promises. Surely, Allah does not guide any transgressor, liar.","ফেরাউনের লোকদের মধ্যে একজন বিশ্বাসী লোক, যে তার সত্য গোপন করেছিল, বলেছিল, ”কেমন করে তুমি একজন মানুষকে হত্যা করবে শুধুমাত্র বলার জন্য, \"আমার প্রভু আল্লাহ, এবং সে তোমার প্রভুর পক্ষ থেকে তোমাকে পরিষ্কার প্রমাণ দেখিয়েছে? যদি সে মিথ্যাবাদী হয়, সেটা তার সমস্যা এবং যদি সে সত্যবাদী হয়, তুমি তার প্রতিশ্রুতি থেকে উপকৃত হও। নিশ্চয়, আল্লাহ সীমালঙ্ঘনকারী, মিথ্যাবাদীদের পথপ্রদর্শন করেন না।"],
  "40:29": ["\"O my people, today you have kingship and the upperhand. But who will help us against Allah's judgment, should it come to us?\" Pharaoh said, \"You are to follow only what I see fit; I will guide you only in the right path.\"","যে বিশ্বাস করেছিল সে বলল, ”হে আমার লোকেরা, আমি ভয় করি যে পূর্ববর্তী বিরোধীদের মত তোমাদেরও একই পরিণতি হয়।"],
  "40:30": ["The one who believed said, \"O my people, I fear for you the same fate as the previous opponents.","যে বিশ্বাস করেছিল সে বলল, ”হে আমার লোকেরা, আমি ভয় করি যে পূর্ববর্তী বিরোধীদের মত তোমাদেরও একই পরিণতি হয়।"],
  "40:31": ["\"The opponents of Noah, and 'Ãd, Thamûd, and others who came after them. Allah does not wish any injustice for the people.","নূহ, এবং আদম, সামূদ, এবং অন্য বিরোধীরা যারা তাদের পরে এসেছিল। আল্লাহ মানুষের জন্য কোন অবিচার চান না।"],
  "40:32": ["\"O my people, I fear for you the Day of Summoning.","\"হে আমার লোকেরা, আমি তোমাদের জন্য ভয় করি সেই আহ্বানের দিবসের।\""],
  "40:33": ["\"That is the day when you may wish to turn around and flee. But nothing will protect you then from Allah. Whomever Allah sends astray, nothing can guide him.\"","এটা সেই দিন, যখন তোমরা ঘুড়ে দাড়াতে এবং পালানোর ইচ্ছা করতে পার। কিন্তু কোন কিছুই তখন তোমাদেরকে আল্লাহ থেকে রক্ষা করতে পারবে না। যাকেই আল্লাহ পথভ্রষ্ট করেন, কোনকিছুই তাকে পথ দেখাতে পারে না।"],
  "40:34": ["Joseph had come to you before that with clear revelations, but you continued to doubt his message. Then, when he died you said, \"Allah will not send any other messenger after him. (He was the last messenger)!\" Allah thus sends astray those who are transgressors, doubtful.","এর আগে ইউসুফ তোমাদের কাছে এসেছিল স্পষ্ট প্রকাশনাবলী  নিয়ে, কিন্তু  তোমরা তার বার্তায় সন্দেহ করে যাচ্ছিলে। তারপর সে যখন মারা গেল তোমরা বলেছো, \"আল্লাহ তার পরে অন্য কোন বার্তাবাহক পাঠাবেন না। (সে-ই শেষ বার্তাবাহক ছিল)! আল্লাহ এভাবে তাদেরকে পথভ্রষ্ট করেন যারা সীমালঙ্ঘনকারী, সন্দিহান।"],
  "40:35": ["They argue against Allah's revelations, without any basis. This is a trait that is most abhorred by Allah and by those who believe. Allah thus seals the hearts of every arrogant tyrant.","তারা আল্লাহর প্রকাশনাবলীর বিরুদ্ধে তর্ক করে, কোন ভিত্তি ছাড়া। এটি একটি বৈশিষ্ট্য যা আল্লাহ এবং যারা বিশ্বাস করে তাদের দ্বারা তীব্রভাবে ঘৃনিত হয়।"],
  "40:36": ["Pharaoh said, \"O Hãmãn, build for me a high tower, that I may reach out and discover.","ফেরাউন বলেছিল, \"হে হামান, আমার জন্য একটি উচুঁ মিনার তৈরি করো, যেন আমি পৌঁছাতে পারি এবং আবিষ্কার করি।"],
  "40:37": ["\"I want to reach the heaven, and take a look at the god of Moses. I believe he is a liar.\" Thus were the evil works of Pharaoh adorned in his eyes, and thus was he kept from following (the right) path. Pharaoh's scheming was truly evil.","\"আমি স্বর্গে পৌঁছাতে চাই, এবং মুসার উপাস্যকে একবার দেখে নিতে চাই। আমি বিশ্বাস করি যে সে একজন মিথ্যুক।” এভাবে ফেরাউনের মন্দ কাজগুলোকে তার চোখে সুশোভিত করে দেয়া হয়েছে, এবং এভাবে (সে সঠিক) পথ অনুসরণ করা থেকে বিরত ছিল। ফেরাউনের চক্রান্ত সত্যই মন্দ।"],
  "40:38": ["The one who believed said, \"O my people, follow me, and I will guide you in the right way.","সে ব্যক্তি বলল যে বিশ্বাস করেছিল যে, ”হে আমার লোকেরা, আমাকে অনুসরণ করো, এবং আমি তোমাদেরকে সঠিক পথ প্রদর্শন করবো।"],
  "40:39": ["\"O my people, this first life is a temporary illusion, while the Hereafter is the eternal abode.\"","\"হে আমার লোকেরা, এই প্রথম জীবন একটি সাময়িক বিভ্রম, যখন পরকালই হলো চিরস্থায়ী আবাস।\""],
  "40:40": ["Whoever commits a sin is requited for just that, and whoever works righteousness—male or female—while believing, these will enter Paradise wherein they receive provisions without any limits.","যেকেউ একটি পাপ করে, শুধু তার জন্য প্রতিফল গ্রহন করে এবং যেকেউ সৎ কাজ করে- পুরুষ অথবা নারী - বিশ্বাসী অবস্থায়, এরা প্রবেশ করবে স্বর্গে যেখানে তারা জীবিকা পায়, সীমাহীনভাবে।"],
  "40:41": ["\"O my people, while I invite you to be saved, you invite me to the hellfire.","\"হে আমার লোকেরা, যখন আমি তোমাদেরকে বাচাঁতে আমন্ত্রণ করি, তোমরা আমাকে  আমন্ত্রণ করো নরকাগ্নির দিকে।"],
  "40:42": ["\"You invite me to be unappreciative of Allah, and to set up beside Him idols that I do not recognize. I am inviting you to the Almighty, the Forgiver.","\"তোমরা আমাকে  আমন্ত্রণ করো আল্লাহর প্রতি অকৃতজ্ঞ হওয়ার জন্য, এবং তাঁর পাশে  উপাস্যদের স্থাপন করার জন্য যাদেরকে আমি চিনি না। আমি তোমাদেরকে সর্বশক্তিমান, ক্ষমাকারীর দিকে আমন্ত্রণ করি।"],
  "40:43": ["\"There is no doubt that what you invite me to do has no basis in this world, nor in the Hereafter, that our ultimate return is to Allah, and that the transgressors have incurred the hellfire.","\"কোন সন্দেহ নেই যে আমাকে যা করতে তোমরা আমন্ত্রণ করো এই বিশ্বে তার কোন ভিত্তি নেই, না আছে পরকালে, আর আমাদের চুড়ান্ত প্রত্যাবর্তন আল্লাহর কাছে, এবং যে সীমালঙ্ঘনকারীরা টেনে এনেছে নরকাগ্নি।"],
  "40:44": ["\"Some day you will remember what I am telling you now. I leave the judgment of this matter to Allah; Allah is the Seer of all the people.\"","\"একদিন তোমাদের স্মরণ হবে যা এখন আমি তোমাদের বলছি। আমি এ ব্যাপারে আল্লাহর উপর বিচার ছেড়ে দিচ্ছি; আল্লাহ সকল লোকদের দ্রষ্টা।"],
  "40:45": ["Allah then protected him from their evil schemes, while the people of Pharaoh have incurred the worst retribution.","আল্লাহ এরপর তাকে তাদের মন্দ ষড়যন্ত্র থেকে রক্ষা করলেন, যেখানে ফেরাউনের লোকেরা টেনে এনেছে নিকৃষ্টতম শাস্তি।"],
  "40:46": ["The Hell will be shown to them day and night, and on the Day of Resurrection: \"Admit Pharaoh's people into the worst retribution.\"","তাদের কাছে নরক দেখানো হবে দিনে এবং রাতে, এবং পুনরুত্থান দিনে: \"ফেরাউনের লোকদের নিকৃষ্টতম শাস্তিতে প্রবেশ করাও।\""],
  "40:47": ["As they argue in Hell, the followers will say to their leaders, \"We used to be your followers, can you spare us any part of this Hell?\"","যখন তারা নরকে তর্ক করবে, অনুসারীরা তাদের নেতাদের বলবে, \"আমরা তোমাদের অনুসারী ছিলাম, তোমরা কি এই নরকের কোন অংশ থেকে নিষ্কৃতি দিতে পারো?\""],
  "40:48": ["The leaders will say, \"We are all in this together. Allah has judged among the people.\"","নেতারা বলবে, “আমরা এখানে একসাথে সবাই আছি। আল্লাহ লোকদের মাঝে বিচার করেছেন।\""],
  "40:49": ["Those in the hellfire will say to the guardians of Hell, \"Call upon your Lord to reduce the retribution for us, for even one day.\"","যারা নরকাগ্নিতে তারা নরকের তত্ত্বাবধায়কদের বলবে, \"তোমাদের প্রভুকে ডাকো তোমাদের জন্য শাস্তি কমাতে, একদিনের জন্য হলেও।\""],
  "40:50": ["They will say, \"Did you not receive your messengers who delivered to you clear messages?\" They will reply, \"Yes we did.\" They will say, \"Then implore (as much as you wish); the imploring of the disbelievers is always in vain.\"","তারা বলবে, \"তোমরা কি তোমাদের বার্তাবাহকদের পাওনি যারা তোমাদের কাছে পরিষ্কার বার্তা পৌঁছিয়েছিল?” তারা উত্তর দিবে, \"হ্যা আমরা পেয়েছিলাম।” তারা বলবে, \"তাহলে মিনতি করো (তোমাদের যতটুক ইচ্ছা); অবিশ্বাসীদের মিনতি সবসময় বৃথা।\""],
  "40:51": ["Most assuredly, we will give victory to our messengers and to those who believe, both in this world and on the day the witnesses are summoned.","নিশ্চিতভাবে, আমরা আমাদের বার্তাবাহকদের এবং যারা বিশ্বাস করে তাদেরকে বিজয় দিবো, এই দুনিয়ায় এবং সে দিনও যখন সাক্ষীদের তলব করা হবে।"],
  "40:52": ["On that day, the apologies of the disbelievers will not benefit them. They have incurred condemnation; they have incurred the worst destiny.","ঐদিন, অবিশ্বাসীদের কৈফিয়তগুলো তাদের উপকারে আসবে না। তারা টেনে এনেছে নিন্দা; তারা টেনে এনেছে নিকৃষ্ট নিয়তি।"],
  "40:53": ["We have given Moses the guidance, and made the Children of Israel inherit the scripture.","আমরা মূসাকে পথনির্দেশনা দিয়েছিলাম, এবং ইসরাইলের সন্তানদের ঐশীগ্রন্থের উত্তরাধিকার করালাম।"],
  "40:54": ["(Their history) is a lesson and a reminder for those who possess intelligence.","(তাদের ইতিহাস) হলো একটি শিক্ষা এবং তাদের জন্য একটি স্মারক যারা বুদ্ধিমত্তা অধিকার করে।"],
  "40:55": ["Therefore, be patient, for Allah's promise is true, and ask forgiveness for your sin, and glorify and praise your Lord night and day.","সেজন্য, ধৈর্যশীল হও, কারণ আল্লাহর প্রতিশ্রুতি সত্য, এবং তোমাদের পাপের জন্য ক্ষমা চাও, এবং তোমার প্রভুর গুণকীর্তন ও প্রশংসা করো দিনে ও রাতে।"],
  "40:56": ["Surely, those who argue against Allah's revelations without proof are exposing the arrogance that is hidden inside their chests, and they are not even aware of it. Therefore, seek refuge in Allah; He is the Hearer, the Seer.","নিশ্চিতভাবে, আল্লাহর প্রকাশনাবলীর বিরুদ্ধে যারা প্রমাণ ছাড়া তর্ক করে, তারা ঔদ্ধত্যতা প্রকাশ করে যা তাদের বুকে লুকায়িত, এবং এ বিষয়ে তারা সচেতনও নয়। অতএব, আল্লাহর কাছে আশ্রয় প্রার্থনা করো; তিনি শ্রবণকারী, দ্রষ্টা।"],
  "40:57": ["The creation of the heavens and the earth is even more awesome than the creation of the human being, but most people do not know.","এমনকি মানব জাতি সৃষ্টির চেয়ে আরো বেশি অসাধারণ আকাশমণ্ডলী এবং পৃথিবীর সৃষ্টি, কিন্তু বেশিরভাগ মানুষ জানে না।"],
  "40:58": ["Not equal are the blind and the seer. Nor are those who believe and work righteousness equal to the sinners. Rarely do you take heed.","অন্ধ এবং চক্ষুষ্মান সমান নয়। না  যারা বিশ্বাস করে এবং সৎ কাজ করে তারা পাপীদের সমান। কদাচিৎ, তোমরা সতর্ক হও।"],
  "40:59": ["Most certainly, the Hour (Day of Judgment) is coming, no doubt about it, but most people do not believe.","নিশ্চিতভাবে, সে ঘন্টা (বিচার দিবস) আসছে, এ বিষয়ে কোন সন্দেহ নেই, কিন্তু অধিকাংশ লোক বিশ্বাস করে না।"],
  "40:60": ["Your Lord says, \"Implore Me, and I will respond to you. Surely, those who are too arrogant to worship Me will enter Gehenna, forcibly.\"","তোমাদের প্রভু বলেন, \"আমার কাছে অনুনয় করো, এবং আমি তোমাদের প্রতি সাড়া দিবো। নিশ্চয়, যারা আমার উপাসনা করতে অত্যন্ত উদ্ধত তারা জাহান্নামে প্রবেশ করবে, বলপূর্বকভাবে।\""],
  "40:61": ["Allah is the One who designed the night so you can rest in it, and the day lighted. Allah bestows many blessings upon the people, but most people are not thankful.","আল্লাহ সে সত্ত্বা যিনি রাতের নকশা করেছেন যেন তাতে তোমরা বিশ্রাম নিতে পারো, এবং দিনকে করেছেন আলোকিত। আল্লাহ লোকদের প্রতি অনেক অনুগ্রহ প্রদান করেছেন, কিন্তু অধিকাংশ লোক কৃতজ্ঞ নয়।"],
  "40:62": ["Such is Allah your Lord, the Creator of all things. There is no god except He. How could you deviate?","এমনই আল্লাহ - তোমাদের প্রভু, সবকিছুর সৃষ্টিকর্তা। তিনি ছাড়া কোন উপাস্য নেই। কিভাবে তোমরা বিচ্যুত হও?"],
  "40:63": ["Deviating are those who disregard Allah's revelations.","তারা বিচ্যুত হয় যারা আল্লাহর প্রকাশনাবলি উপেক্ষা করে।"],
  "40:64": ["Allah is the One who rendered the earth habitable for you, and the sky a formidable structure, and He designed you, and designed you well. He is the One who provides you with good provisions. Such is Allah your Lord; Most Exalted is Allah, Lord of the universe.","আল্লাহ সে সত্ত্বা যিনি তোমাদের জন্য পৃথিবীকে বাসযোগ্য, এবং আকাশকে দূর্ভেদ্য করেছেন, এবং তিনি তোমাদের নকশা করেছেন, এবং তোমাদের নকশা করেছেন ভালোভাবে। তিনি সে সত্ত্বা যিনি তোমাদেরকে ভাল জীবিকা সরবরাহ করেন। এমনই আল্লাহ তোমাদের প্রভু; আল্লাহ সবচেয়ে মর্যাদাসম্পন্ন, মহাবিশ্বের প্রভু।"],
  "40:65": ["He is the Living; there is no god except He. You shall worship Him alone, devoting your religion absolutely to Him alone. Praise be to Allah, Lord of the universe.","তিনি চিরজীবী ; তিনি ছাড়া কোন উপাস্য নেই। তোমরা একমাত্র তার উপাসনা করো, তোমাদের ধর্মকে পুরোপুরি একমাত্র তার নিকট উৎসর্গ করে। প্রশংসা আল্লাহর, মহাবিশ্বের প্রভু।"],
  "40:66": ["Say, \"I have been enjoined from worshiping the idols you worship beside Allah, when the clear revelations came to me from my Lord. I was commanded to submit to the Lord of the universe.\"","বল, ”তোমরা আল্লাহর পাশে যে উপাসিতদের উপাসনা করো আমাকে সেগুলোর উপাসনা করতে নিষেধ করা হয়েছে, যখন আমার প্রভুর কাছ থেকে আমার নিকট স্পষ্ট প্রকাশনাবলী এসেছে। আমাকে আদেশ করা হয়েছে, মহাবিশ্বের প্রভুর নিকট আত্মসমর্পন করতে।\""],
  "40:67": ["He is the One who created you from dust, and subsequently from a tiny drop, then from a hanging embryo, then He brings you out as a child, then He lets you reach maturity, then you become old—some of you die earlier. You attain a predetermined age, that you may understand.","তিনি সে সত্ত্বা যিনি তোমাদেরকে ধূলিকণা থেকে সৃষ্টি করেছেন, এবং পরবর্তীতে অতিক্ষুদ্র একটি ফোঁটা থেকে, তারপর ঝুলন্ত ভ্রুন থেকে, তারপর তিনি তোমাদেরকে শিশু হিসেবে বের করে আনেন, তারপর তিনি তোমাদেরকে প্রাপ্ত-বয়ষ্কে পৌঁছতে দেন, তারপর তোমরা বৃদ্ধ হও- তোমাদের কেউ কেউ এর আগেই মারা যাও। তোমরা অর্জন কর একটি পূর্বনির্ধারিত বয়স, যাতে তোমরা বুঝতে পার।"],
  "40:68": ["He is the only One who controls life and death. To have anything done, He simply says to it, \"Be,\" and it is.","তিনিই একমাত্র সত্ত্বা যিনি নিয়ন্ত্রণ করেন জীবন এবং মৃত্যু। কোন কিছু সম্পন্ন করতে তিনি শুধু একে বলেন, “হও”এবং তা হয়ে যায়।"],
  "40:69": ["Have you noted those who argue against Allah's proofs, and how they have deviated?","তুমি কি তাদের লক্ষ্য করেছো যারা আল্লাহর প্রমাণাদির বিরুদ্ধে তর্ক করে, এবং কিভাবে তারা পথচ্যুত হয়?"],
  "40:70": ["They are the ones who have disbelieved in the scripture, and in the messages we have sent with our messengers. Therefore, they will surely find out.","তারাই সে ব্যাক্তি যারা অবিশ্বাস করেছিল ঐশীগ্রন্থে, এবং বার্তাসমূহে, যা আমরা আমাদের বার্তাবাহকদের দিয়ে পাঠিয়েছিলাম। অতএব, তারা অবশ্যই খুঁজে পাবে।"],
  "40:71": ["The shackles will be around their necks, and the chains will be used to drag them.","তাদের গলার চারপাশে থাকবে শিকল, এবং তাদেরকে টানতে সে শিকল ব্যবহার করা হবে।"],
  "40:72": ["In the Inferno, then in the Fire, they will burn.","নিন্মস্তরে, এরপর আগুনে, তারা পুড়বে।"],
  "40:73": ["They will be asked, \"Where are the idols you used to worship,","তাদেরকে জিজ্ঞেস করা হবে, \"কোথায় সে উপাসিতরা যাদেরকে তোমরা উপাসনা করতে,"],
  "40:74": ["\"beside Allah?\" They will say, \"They have abandoned us. In fact, when we worshiped them, we were worshiping nothing.\" Thus does Allah send the disbelievers astray.","\"আল্লাহর পাশে?” তারা বলবে, \"তারা আমাদেরকে পরিত্যাগ করেছে। প্রকৃতপক্ষে, যখন আমরা তাদের উপাসনা করেছিলাম, আমরা কোনকিছুরই উপাসনা করছিলাম না।” এভাবে আল্লাহ অবিশ্বাসীদের পথভ্রষ্ট করেন।"],
  "40:75": ["This is because you used to rejoice in false doctrines, on earth, and you used to promote them.","এর কারন পৃথিবীতে তোমরা মিথ্যা মতবাদে আনন্দ করতে, এবং তোমরা সেগুলোর প্রচার করতে।"],
  "40:76": ["Enter the gates of Gehenna, wherein you abide forever. What a miserable destiny for the arrogant ones.","জাহান্নামের দরজা দিয়ে প্রবেশ করো, যেখানে তোমরা চিরকাল বাস করো। উদ্ধত ব্যক্তিদের জন্য শোচনীয় নিয়তি।"],
  "40:77": ["You shall be patient, for Allah's promise is truth. Whether we show you some of (the retribution) we have promised for them, or terminate your life before that, they will be returned to us.","তুমি ধৈর্যশীল হবে, কারন আল্লাহর প্রতিশ্রুতি সত্য। যদি আমরা তোমাকে এমন কিছু (শাস্তি) দেখাই, যার প্রতিশ্রুতি আমরা তাদের দিয়েছিলাম, অথবা এর পূর্বে তোমার জীবনাবসান করি, তারা আমাদের কাছে ফিরে আসবে।"],
  "40:78": ["We have sent messengers before you—some of them we mentioned to you, and some we did not mention to you. No messenger can produce any miracle without Allah's authorization. Once Allah's judgment is issued, the truth dominates, and the falsifiers are exposed and humiliated.","আমরা তোমার আগে বার্তাবাহকদের পাঠিয়েছিলাম - যাদের কাউকে কাউকে আমরা তোমার কাছে উল্লেখ করেছিলাম এবং কাউকে কাউকে তোমার কাছে উল্লেখ করিনি। আল্লাহর অনুমোদন ছাড়া বার্তাবাহক কোন অলৌকিকতা উপস্থাপন করতে পারে না। একবার আল্লাহর বিচার প্রকাশ হলে, সত্য কর্তৃত্ব করে এবং মিথ্যাবাদীরা প্রকাশিত হয় এবং অপদস্থ হয়।"],
  "40:79": ["Allah is the One who created the livestock for you; some you ride, and some you eat.","আল্লাহ সে সত্ত্বা যিনি তোমাদের জন্য পালিত-পশু তৈরি করেছেন, কয়েকটিতে তোমরা আরোহণ করো এবং কয়েকটিকে তোমরা খাও।"],
  "40:80": ["They also provide you with additional benefits that satisfy many of your needs. On them, as well as on the ships, you are carried.","তারা তোমাদেরকে বাড়তি সুবিধাও দেয় যা তোমাদের অনেকের প্রয়োজনীয়তা পূর্ণ করে। তাদের উপর, এবং জাহাজে, তোমাদেরকে বহন করা হয়।"],
  "40:81": ["He thus shows you His proofs. Which of Allah's proofs can you deny?","তিনি এভাবে তোমাদেরকে তাঁর প্রমাণসমূহ দেখান। আল্লাহর কোন প্রমাণগুলোকে তোমরা অস্বীকার করবে?"],
  "40:82": ["Have they not roamed the earth and noted the consequences for those who preceded them? They used to be greater in number, greater in power, and possessed a greater legacy on earth. Yet, all their achievements did not help them in the least.","তারা  কি পৃথিবীতে ঘুরে বেড়ায়নি এবং তাদের পরিণাম লক্ষ্য করে না, যারা তাদের আগে এসেছিল? তারা সংখ্যায় বড়, ক্ষমতায় বড়,  এবং পৃথিবীতে একটি বড় উত্তরাধিকারের মালিক ছিল। অথচ তাদের কোন অর্জন তাদেরকে নুন্যতম সাহায্য করতে পারে নি।"],
  "40:83": ["When their messengers went to them with clear proofs, they rejoiced in the knowledge they had inherited, and the very things they ridiculed were the cause of their fall.","যখন তাদের বার্তাবাহক তাদের কাছে স্পষ্ট প্রমাণাদি নিয়ে গিয়েছিল, তারা উত্তরাধিকারসূত্রে প্রাপ্ত জ্ঞানে মত্ত ছিল, এবং ঠিক যে বিষয়টি নিয়ে তারা উপহাস করতো তা-ই তাদের পতনের কারণ ছিল।"],
  "40:84": ["Subsequently, when they saw our retribution they said, \"Now we believe in Allah ALONE, and we now disbelieve in the idol worship that we used to practice.\"","পরবর্তীতে, তারা যখন আমাদের শাস্তি দেখল তারা বলেছিল, \"এখন আমরা আল্লাহর একত্বে বিশ্বাস করি, এবং আমরা এখন অবিশ্বাস করি সে প্রতিমা উপাসনাকে যা আমরা চর্চা করতাম।"],
  "40:85": ["Their belief then could not help them in the least, once they saw our retribution. Such is Allah's system that has been established to deal with His creatures; the disbelievers are always doomed.","তাদের বিশ্বাস তখন তাদেরকে সামান্যতম সাহায্য করতে পারেনি, একবার যখন তারা আমাদের শাস্তি দেখেছিল। এমনই আল্লাহর পদ্ধতি যা তাঁর সৃষ্টিগুলোর ব্যাপারে প্রতিষ্ঠিত; অবিশ্বাসীরা সর্বদা ধ্বংসপ্রাপ্ত।"],
  "41:1": ["H. M.","হ. ম. (হা মীম)"],
  "41:2": ["A revelation from the Most Gracious, Most Merciful.","পরম করুণাময়, পরম দয়ালু আল্লাহর কাছ থেকে একটি প্রকাশনা।"],
  "41:3": ["A scripture whose verses provide the complete details, in an Arabic Quran, for people who know.","একটি ঐশীগ্রন্থ যার আয়াতগুলো পূর্ণ বিস্তারিতভাবে জানায়, আরবি কুরআনে, মানুষের জন্য যারা জানে।"],
  "41:4": ["A bearer of good news, as well as a warner. However, most of them turn away; they do not hear.","একটি শুভ সংবাদ বহনকারী, একইসাথে সতর্ককারী। তবে, তাদের অধিকাংশই মুখ ফিরিয়ে নেয়; তারা শুনে না।"],
  "41:5": ["They said, \"Our minds are made up, our ears are deaf to your message, and a barrier separates us from you. Do what you want, and so will we.\"","তারা বলেছিল, \"পূর্ব থেকে আমাদের মন স্থির হয়ে আছে, আমাদের কান তোমার বার্তার প্রতি বধির এবং একটি অন্তরায় তোমার থেকে আমাদেরকে আলাদা করে। তুমি যা চাও করো, এবং আমরাও তা-ই করবো।\""],
  "41:6": ["Say, \"I am no more than a human being like you, who has been inspired that your god is one god. You shall be devoted to Him, and ask His forgiveness. Woe to the idol worshipers.","বল, আমি তোমাদের মত একজন মানুষের চেয়ে বেশি কিছু নই, যাকে প্রত্যাদেশ দেয়া হয়েছে যে তোমাদের খোঁদা এক। তোমরা তাঁর প্রতি নিবেদিত হবে এবং তাঁর কাছে ক্ষমা চাও। দু:খ তো প্রতিমা উপাসকদের।"],
  "41:7": ["\"Who do not give the obligatory charity (Zakat), and with regard to the Hereafter, they are disbelievers.\"","যারা বাধ্যতামূলক দান (যাকাত) দেয় না, এবং পরকাল সম্পর্কে, তারা অবিশ্বাসী।"],
  "41:8": ["As for those who believe and lead a righteous life, they receive a well deserved recompense.","তাদের ক্ষেত্রে যারা বিশ্বাস করে এবং সৎ জীবন যাপন করে,তারা একটি যথোপযুক্ত প্রতিদান পায়।"],
  "41:9": ["Say, \"You disbelieve in the One who created the earth in two days, and you set up idols to rank with Him, though He is Lord of the universe.\"","বল, \"তোমরা অবিশ্বাস কর  সে সত্ত্বাকে যিনি  দুই দিনে পৃথিবী সৃষ্টি করেছিলেন, এবং তোমরা তাঁর সাথে সমমর্যাদা দিতে শরিক স্থাপন করো, যদিও তিনি মহাবিশ্বের প্রভু।"],
  "41:10": ["He placed on it stabilizers (mountains), made it productive, and He calculated its provisions in four days, to satisfy the needs of all its inhabitants.","তিনি এর উপর স্থাপন করেছেন ভারসাম্যরক্ষাকারী (পর্বতমালা), একে উর্বর করেছেন, এবং তিনি চার দিনে এর জীবিকা গণনা করেছেন, এর অধিবাসীদের চাহিদা মেটাতে"],
  "41:11": ["Then He turned to the sky, when it was still gas, and said to it, and to the earth, \"Come into existence, willingly or unwillingly.\" They said, \"We come willingly.\"","তারপর তিনি আকাশের দিকে ফিরলেন, যখন তা তখনও গ্যাস ছিল, এবং বলেছিলেন একে, ও পৃথিবীকে,\"অস্তিত্বে আসো, ইচ্ছায় বা অনিচ্ছায়। ”তারা বলেছিল, \"আমরা আসি স্বেচ্ছায়।\""],
  "41:12": ["Thus, He completed the seven universes in two days, and set up the laws for every universe. And we adorned the lowest universe with lamps, and placed guards around it. Such is the design of the Almighty, the Omniscient.","এভাবে, তিনি সাতটি  মহাবিশ্ব দুই দিনে সম্পূর্ণ করেছিলেন, এবং প্রত্যেক মহাবিশ্বের জন্য আইনসমূহ প্রকাশ করলেন। এবং আমরা নিম্নতম মহাবিশ্বকে বাতি দিয়ে সুশোভিত করেছিলাম, এবং এর চারপাশে পাহারাদারদের বসিয়েছি। এমনি সর্বশক্তিমান, সর্বজ্ঞের নকশা।"],
  "41:13": ["If they turn away, then say, \"I am warning you of a disaster like the disaster that annihilated 'Ãd and Thamûd.\"","যদি তারা মুখ ফিরিয়ে নেয়, তাহলে বল, “আমি তোমাদেরকে সতর্ক করছি একটি বিপর্যয়ের বিষয়ে, এটা সেই বিপর্যয়ের মতো যা আদ এবং সামূদ জাতিকে বিলুপ্ত করেছিল।"],
  "41:14": ["Their messengers went to them, as well as before them and after them, saying, \"You shall not worship except Allah.\" They said, \"Had our Lord willed, He could have sent angels. We are disbelievers in what you say.\"","তাদের বার্তাবাহক তাদের কাছে গিয়েছিল, সেই সাথে তাদের আগে এবং তাদের পরে, এ বলে যে, \"তোমরা আল্লাহ ছাড়া উপাসনা করবে না। “তারা বলেছিল, \"যদি আমাদের প্রভু চাইতেন, তিনি ফেরেশতা পাঠাতেন। যা তুমি বল তাতে আমরা অবিশ্বাসী।\""],
  "41:15": ["As for 'Ãd, they turned arrogant on earth, opposed the truth, and said, \"Who is more powerful than we?\" Did they not realize that Allah, who created them, is more powerful than they? They were unappreciative of our revelations.","আদের ক্ষেত্রে, তারা পৃথিবীতে উদ্ধত হয়ে পড়েছিল, সত্যের বিরোধিতা করতো, এবং বলেছিল, \"কে আমাদের চেয়ে বেশি ক্ষমতাধর?”তারা কি অনুধাবন করেনি যে আল্লাহ, যিনি তাদের সৃষ্টি করেছেন, তাদের চেয়ে বেশি ক্ষমতাধর? তারা আমাদের প্রকাশনাবলীর প্রতি অকৃতজ্ঞ ছিল।"],
  "41:16": ["Consequently, we sent upon them violent wind, for a few miserable days. We thus afflicted them with humiliating retribution in this life, and the retribution of the Hereafter is more humiliating; they can never win.","ফলস্রুতিতে, আমরা তাদের উপর তীব্র বাতাস পাঠিয়েছিলাম, শোচনীয় কিছু দিনের জন্য। এই জীবনে আমরা এভাবে অপমানকর শাস্তি দিয়ে তাদেরকে কষ্ট দিয়েছিলাম, এবং পরকালের শাস্তি আরো অপমানকর, তারা কখনোই জয়লাভ করতে পারবে না।"],
  "41:17": ["As for Thamûd, we provided them with guidance, but they preferred blindness over guidance. Consequently, the disastrous and shameful retribution annihilated them, because of what they earned.","আর সামুদের ক্ষেত্রে, তাদেরকে আমরা পথনির্দেশনা প্রদান করেছিলাম, কিন্তু তারা পথনির্দেশনার উপরে পছন্দ করেছিল অন্ধত্বকে। পরিনামে, সর্বনাশা এবং লজ্জাজনক শাস্তি তাদেরকে ধ্বংস করেছিল, তারা যা অর্জন করেছিল তার কারনে।"],
  "41:18": ["We always save those who believe and lead a righteous life.","আমরা সবসময় তাদেরকে রক্ষা করি যারা বিশ্বাস করে এবং সৎ জীবনযাপন করে।"],
  "41:19": ["The day will come when the enemies of Allah will be summoned to the hellfire, forcibly.","সে দিনটি আসবে যখন আল্লাহর শত্রুদেরকে নরকাগ্নির দিকে তলব করা হবে, বলপূর্বকভাবে।"],
  "41:20": ["Once they get there, their own hearing, eyes, and skins will bear witness to everything they had done.","একবার তারা সেখানে পৌছঁলে, তাদের নিজেদের শ্রবণশক্তি, চোখ, এবং চামড়া সাক্ষী বহন করবে সবকিছুর যা তারা করেছিল।"],
  "41:21": ["They will say to their skins, \"Why did you bear witness against us?\" They will reply, \"Allah made us speak up; He is the One who causes everything to speak. He is the One who created you the first time, and now you have been returned to Him.\"","তারা তাদের চামড়াকে বলবে, \"কেন তোমরা আমাদের বিরুদ্ধে সাক্ষী বহন করেছো? তারা উত্তর দিবে, \"আল্লাহ আমাদেরকে বাকশক্তি দিয়েছেন; তিনিই সে সত্ত্বা যিনি সবকিছুকে কথা বলার শক্তি দেন। তিনি সেই সত্ব্বা যিনি তোমাকে প্রথম বার সৃষ্টি করেছিলেন, এবং এখন তুমি তার কাছে ফিরে এসেছো।,\""],
  "41:22": ["There is no way you can hide from your own hearing, your eyes, or your skins. In fact, you thought that Allah was unaware of much of what you do.","তোমাদের লুকানোর কোন উপায় নেই তোমাদের নিজেদের কান, তোমাদের চোখ, অথবা তোমাদের চামড়া থেকে। প্রকৃতপক্ষে, তোমরা ভেবেছিলে যে তোমরা যা করো তার বেশির ভাগ সম্পর্কে আল্লাহ অনবগত ছিলেন।"],
  "41:23": ["This kind of thinking about your Lord will cause you to fall, and then you become losers.","তোমাদের প্রভু সম্পর্কে এ ধরণের ভাবনা তোমাদের পতনের কারন হবে, এবং এরপর তোমরা ক্ষতিগ্রস্ত হয়ে পড়ো।"],
  "41:24": ["If they continue the way they are, Hell will be their destiny, and if they make up excuses, they will not be excused.","যদি তারা তাদের পথে চলতে থাকে, নরক হবে তাদের নিয়তি, এবং যদি তারা অজুহাত তৈরি করে, তাদেরকে ক্ষমা করা হবে না।"],
  "41:25": ["We assign to them companions who adorn everything they do in their eyes. Thus, they end up incurring the same fate as the previous communities of jinns and humans, who were also losers.","আমরা তাদেরকে সহচর নিযুক্ত করি যারা তাদের চোখে সাজিয়ে দেয় সবকিছু, যা তারা করে। এভাবে, তারা শেষপর্যন্ত একই পরিনতি টেনে আনে পূর্ববর্তী জীন ও মানুষ সম্প্রদায়গুলোর মতো, ওরাও ক্ষতিগ্রস্থ ছিল।"],
  "41:26": ["Those who disbelieved said, \"Do not listen to this Quran and distort it, that you may win.\"","যারা অবিশ্বাস করেছিল তারা বলল, \"এই কুরআনের প্রতি মনোযোগ দিও না এবং একে বিকৃত করো, যাতে তোমরা জয়ী হতে পারো।"],
  "41:27": ["We will certainly afflict these disbelievers with a severe retribution. We will certainly requite them for their evil works.","আমরা নিশ্চিতভাবে এই অবিশ্বাসীদেরকে কঠোর শাস্তির মাধ্যমে কষ্ট দিবো। আমরা নিশ্চিতভাবে তাদের মন্দ কাজের জন্য তাদেরকে প্রতিদান দিবো।"],
  "41:28": ["Such is the requital that awaits Allah's enemies. Hell will be their eternal abode; a just requital for discarding our revelations.","এমনই হলো প্রতিফল যা আল্লাহর শত্রুদের জন্য অপেক্ষা করে। নরক হবে তাদের চিরস্থায়ী আবাস; আমাদের প্রকাশনাবলী পরিত্যাগ করার জন্য একটি ন্যায্য প্রতিফল।"],
  "41:29": ["Those who disbelieved will say, \"Our Lord, show us those among the two kinds—jinns and humans—who misled us, so we can trample them under our feet, and render them the lowliest.\"","যারা অবিশ্বাস করেছিল তারা বলবে, \"আমাদের প্রভু, আমাদের দেখান - জ্বীন ও মানুষ - এই দুই প্রকারের মধ্যে তাদেরকে যারা আমাদেরকে বিভ্রান্ত করেছিল, যাতে আমরা তাদেরকে আমাদের পায়ের নিচে পদদলিত করতে পারি, এবং তাদেরকে নিম্নতম অবস্থায় রাখুন।\""],
  "41:30": ["Those who proclaim: \"Our Lord is Allah,\" then lead a righteous life, the angels descend upon them: \"You shall have no fear, nor shall you grieve. Rejoice in the good news that Paradise has been reserved for you.","যারা ঘোষনা করে,\"আমাদের প্রভু হলো আল্লাহ, ” এরপর সৎ জীবন-যাপন করে, ফেরেশতারা তাদের উপর অবতরণ করে: \"তোমাদের কোন ভয় থাকবে না, না তোমরা শোক করবে। আনন্দ করো শুভ সংবাদে যে স্বর্গ তোমাদের জন্য সংরক্ষণ করা হয়েছে।"],
  "41:31": ["\"We are your allies in this life, and in the Hereafter. You will have in it anything you wish for; you will have anything you want.","আমরা তোমাদের বন্ধু, এই জীবনে এবং পরকালে। এতে তোমাদের জন্য থাকবে যে কোন কিছু যার জন্য তোমরা ইচ্ছা পোষন করো; তোমাদের জন্য থাকবে যে কোন কিছু যা তোমরা চাও।"],
  "41:32": ["\"(Such is your) ultimate abode, from a Forgiver, Most Merciful.\"","\"(এমনই তোমাদের) চূড়ান্ত আবাস, একজন ক্ষমাকারী, সবচেয়ে দয়ালুর পক্ষ থেকে। \""],
  "41:33": ["Who can utter better words than one who invites to Allah, works righteousness, and says, \"I am one of the submitters\"?","কে তার চেয়ে উত্তম কথা বলতে পারে যে আল্লাহর দিকে আহবান করে, সৎ কাজ করে এবং বলে, \"আমি আত্মসমর্পণকারীদের একজন\"?"],
  "41:34": ["Not equal is the good response and the bad response. You shall resort to the nicest possible response. Thus, the one who used to be your enemy, may become your best friend.","ভালো প্রতিক্রিয়া এবং মন্দ প্রতিক্রিয়া সমান নয়। তুমি যথাসম্ভব সুন্দর প্রতিক্রিয়া অবলম্বন করবে। এভাবে, যে ব্যক্তি তোমার শত্রু ছিল, সে তোমার সবচেয়ে ভাল বন্ধু হয়ে যেতে পারে।"],
  "41:35": ["None can attain this except those who steadfastly persevere. None can attain this except those who are extremely fortunate.","কেউ তা অর্জন করতে পারে না তারা ব্যতিত যারা দৃড়তার সাথে অধ্যবসায়ী। কেউ তা অর্জন করতে পারে না তারা ব্যতিত যারা অত্যন্ত সৌভাগ্যবান।"],
  "41:36": ["When the devil whispers an idea to you, you shall seek refuge in Allah. He is the Hearer, the Omniscient.","যখন শয়তান তোমার কাছে কোন ধারনা ফিস ফিস করে, তুমি আল্লাহর নিকট আশ্রয় খুঁজবে। তিনি শ্রোতা, সর্বজ্ঞ।"],
  "41:37": ["Among His proofs are the night and the day, and the sun and the moon. Do not prostrate before the sun, nor the moon; you shall fall prostrate before the Allah who created them, if you truly worship Him alone.","তাঁর প্রমানসমূহের মধ্যে রয়েছে রাত ও দিন, এবং সূর্য ও চাঁদ। সূর্যের সামনে সেজদা করো না, চাঁদের সামনেও না; তোমরা আল্লাহর সামনে সেজদায় পতিত হবে যিনি তাদের সৃষ্টি করেছেন, যদি সত্যি তোমরা কেবল তাঁর উপাসনা করো।"],
  "41:38": ["If they are too arrogant to do this, then those at your Lord glorify Him night and day, without ever tiring.","যদি তারা এটা করতে অত্যন্ত উদ্ধত হয়, তাহলে তোমার প্রভুর সান্নিধ্যে যারা রয়েছে তারা তাঁর মহিমা প্রকাশ করে রাতে ও দিনে, কখনো ক্লান্ত না হয়ে।"],
  "41:39": ["Among His proofs is that you see the land still, then, as soon as we shower it with water, it vibrates with life. Surely, the One who revived it can revive the dead. He is Omnipotent.","তাঁর প্রমানসমূহের মধ্যে রয়েছে যে তুমি ভূমিকে দেখো স্থির, এরপর, যখনই আমরা এর উপর পানি বর্ষণ করি, এতে জীবনের স্পন্দন হয়। নিশ্চয়, যে সত্ত্বা একে পূনরূজ্জীবিত করেছেন মৃতকেও তিনি পূনরূজ্জীবিত করতে পারেন। তিনি সর্বশক্তিমান।"],
  "41:40": ["Surely, those who distort our revelations are not hidden from us. Is one who gets thrown into Hell better, or one who comes secure on the Day of Resurrection? Do whatever you wish; He is Seer of everything you do.","নিশ্চয়, যারা আমাদের প্রকাশনাবলি বিকৃত করে তারা আমাদের কাছ থেকে গোপন নয়। যে ব্যক্তিকে নরকে নিক্ষেপ করা হয় সে উত্তম, নাকি যে ব্যক্তি পুনরুত্থান দিনে আসে নিরাপদ হয়ে? তোমরা যা চাও করো; তিনি সবকিছুর দেখেন যা তোমরা করো।"],
  "41:41": ["Those who have rejected the Quran's proof  when it came to them, have also rejected an Honorable book.","যারা কুরআনের প্রমানকে প্রত্যাখ্যান করেছে যখন তা তাদের কাছে এসেছিল, তারা প্রত্যাখ্যান করেছে একটি সম্মানিত গ্রন্থকেও।"],
  "41:42": ["No falsehood could enter it, in the past or in the future; a revelation from a Most Wise, Praiseworthy.","কোন মিথ্যা এতে প্রবেশ করতে পারতো না, অতীতে বা ভবিষ্যতে; সবচেয়ে প্রজ্ঞাবান, প্রশংসনীয়ের পক্ষ থেকে একটি প্রকাশনা।"],
  "41:43": ["What is said to you is precisely what was said to the previous messengers. Your Lord possesses forgiveness, and He also possesses painful retribution.","যা তোমাকে বলা হয়, ঠিক একই কথা পূর্ববর্তী বার্তাবাহকদেরও বলা হয়েছিল। তোমার প্রভু ক্ষমাশীলতার অধিকারী, এবং তিনি যন্ত্রনাদায়ক শাস্তিরও অধিকারী।"],
  "41:44": ["If we made it a non-Arabic Quran they would have said, \"Why did it come down in that language?\" Whether it is Arabic or non-Arabic, say, \"For those who believe, it is a guide and healing. As for those who disbelieve, they will be deaf and blind to it, as if they are being addressed from faraway.\"","যদি আমরা একে একটি অ-আরবী কুরআন করতাম তারা বলতো, “এটি কেন ঐ ভাষায় এসেছে?” হোক এটি আরবিয় অথবা অ-আরবীয়, বল, “যারা বিশ্বাস করে তাদের জন্য, এটি একটি পথপ্রদর্শক এবং নিরাময়। আর যারা অবিশ্বাস করে, তারা এর প্রতি হবে বধির এবং অন্ধ, যেন তাদেরকে বহুদূর থেকে ডাকা হচ্ছে।”"],
  "41:45": ["We have given Moses the scripture and it was also disputed. If it were not for your Lord's predetermined decision, they would have been judged immediately. Indeed, they harbor too many doubts.","আমরা মূসাকে ঐশীগ্রন্থ দিয়েছি এবং এতেও বিবাদ করা হয়েছিল। যদি এটি তোমার প্রভুর পূর্বনির্ধারিত সিদ্ধান্ত না হতো, অবিলম্বে তাদের বিচার করা হতো। প্রকৃতপক্ষে, তারা অনেক বেশি সন্দেহ পোষন করে।"],
  "41:46": ["Whoever works righteousness, does so for his own good, and whoever works evil does so to his own detriment. Your Lord is never unjust towards the people.","যেকেউ সৎকর্ম করে, তা তার নিজের ভালোর জন্য করে, এবং যেকেউ মন্দকর্ম করে তা তার নিজের ক্ষতির জন্য করে। তোমার প্রভু লোকদের প্রতি কখনো অন্যায়কারী নন।"],
  "41:47": ["With Him is the knowledge about the Hour (end of the world). No fruits emerge from their sheaths, nor does any female conceive or give birth, without His knowledge. The day will come when He asks them: \"Where are those idols that you set up beside Me?\" They will say, \"We proclaim to You that none of us bears witness to that.\"","তাঁর কাছেই রয়েছে সে ঘন্টা (মহাবিশ্বের পরিসমাপ্তি) সম্পর্কে জ্ঞান। কোন ফলই তাদের খোল থেকে বেরিয়ে আসে না, না কোন নারী গর্ভধারণ করে বা জন্ম দেয়, তাঁর জ্ঞান ছাড়া। সে দিন আসবে যখন তিনি তাদের জিজ্ঞেস করবেন: \"কোথায় সে উপাস্যরা যা তোমরা আমার পাশে স্থাপন করেছ?”তারা বলবে, \"আমরা আপনার কাছে ঘোষনা করি যে আমাদের কেউ এর সাক্ষ্য বহন করে না।"],
  "41:48": ["The idols they had idolized will disown them, and they will realize that there will be no escape.","তারা যাদেরকে প্রতিমায় করেছিল সেই উপাস্যরা তাদেরকে প্রত্যাখ্যান করবে, এবং তারা অনুধাবন করবে যে পালানোর কোন উপায় নেই।"],
  "41:49": ["The human being never tires of imploring for good things. And when adversity befalls him, he turns despondent, desperate.","মানুষ ভাল জিনিসের জন্য মিনতি করে কখনো ক্লান্ত হয় না। এবং যখন দুর্দশা তার উপর পতিত হয়, সে হতাশ, বেপরোয়া হয়ে যায়।"],
  "41:50": ["And when we bless him after suffering some adversity, he says, \"This belongs to me. I do not believe that the Hour will ever come to pass. Even if I am returned to my Lord, I will find at Him better things.\" Most certainly, we will inform the disbelievers of all their works, and will commit them to severe retribution.","এবং যখন আমরা তাকে কিছু দূর্ভোগের পর অনুগ্রহ করি, সে বলে, \"এটা আমার অধীনে। আমি বিশ্বাস করি না যে সে সময় কখনো সংঘটিত হবে। এমনকি আমি আমার প্রভুর কাছে ফিরে গেলেও আমি তাঁর কাছে উত্তম জিনিস পাবো। সুনিশ্চিতভভাবে, আমরা অবিশ্বাসীদেরকে তাদের কাজের বিষয়ে অবহিত করবো, এবং তাদেরকে কঠোর শাস্তি দেব।"],
  "41:51": ["When we bless the human being, he turns away, and drifts farther and farther away, and when he suffers any affliction, he implores loudly.","যখন আমরা মানুষকে অনুগ্রহ করি, সে মুখ ফিরিয়ে নেয়, এবং বিমুখতায় আরো বেশি ঝুঁকে পড়ে, এবং যখন সে কোন দূর্দশা ভোগ করে, সে উচ্চৈঃস্বরে মিনতি করে।"],
  "41:52": ["Proclaim: \"What if this is truly from Allah, then you decide to reject it? Who are farther astray than those who decide to oppose this?\"","ঘোষনা করো: \"যদি এটি সত্যিই আল্লাহ থেকে হয়,  আর তোমরা একে প্রত্যাখ্যান করার সিদ্ধান্ত নাও? কে তার চেয়ে অধিক পথভ্রষ্ট যে এর বিরোধিতা করার সিদ্ধান্ত নেয়?\""],
  "41:53": ["We will show them our proofs in the horizons, and within themselves, until they realize that this is the truth. Is your Lord not sufficient, as a witness of all things?","আমরা তাদেরকে আমাদের প্রমাণাদি দেখাবো দিগন্তসমূহে, এবং তাদের নিজেদের মধ্যে, যতক্ষণ না তারা অনুধাবন করে যে এটাই সত্য। তোমার প্রভু কি যথেষ্ট নয়, সবকিছুর সাক্ষী হিসেবে?"],
  "41:54": ["Indeed, they are doubtful about meeting their Lord. He is fully aware of all things.","প্রকৃতপক্ষে, তারা তাদের প্রভুর সাথে সাক্ষাতের বিষয়ে সন্দিহান। তিনি সবকিছুর বিষয়ে পূর্ণ অবগত।"],
  "42:1": ["H.M.","হ. ম. (হা মীম)"],
  "42:2": ["A. S. Q.","আ. স. ক.  (আয়িন সিন কাফ)"],
  "42:3": ["Inspiring you, and those before you, is Allah, the Almighty, Most Wise.","তোমার, এবং তোমার পূর্ববর্তীদের অনুপ্রেরণায় আছেন, আল্লাহ, সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "42:4": ["To Him belongs everything in the heavens and everything on earth, and He is the Most High, the Great.","আকাশমন্ডলীর সবকিছু এবং পৃথিবীর সবকিছু তাঁর অধীনে,এবং তিনি সর্বাধিক উচ্চ, মহান।"],
  "42:5": ["The heavens above them almost shatter, out of reverence for Him, and the angels praise and glorify their Lord, and they ask forgiveness for those on earth. Absolutely, Allah is the Forgiver, Most Merciful.","তাদের উপর আকাশমন্ডলী প্রায় চূর্ণ হয়ে যায়, তাঁর প্রতি ভক্তিতে এবং স্বর্গদূতরা তাদের প্রভুর প্রশংসা এবং মহিমা ঘোষনা করে, এবং তারা ক্ষমা চায় তাদের জন্য যারা পৃথিবীর উপর আছে। নি:সন্দেহে,আল্লাহ ক্ষমাকারী,সবচেয়ে দয়ালু।"],
  "42:6": ["Those who set up other lords beside Him, Allah is the One in charge of them; you are not their advocate.","যারা তাঁর পাশে অন্য উপাস্য স্থাপন করে,আল্লাহ সেই সত্ত্বা যিনি তাদের দায়িত্বে রয়েছেন; তুমি তাদের উকিল নও।"],
  "42:7": ["We thus reveal to you an Arabic Quran to warn the central community and all around it, and to warn about the Day of Summoning that is inevitable. Some will end up in Heaven, and some in Hell.","আমরা এভাবে তোমার কাছে আরবি কুরআন প্রকাশ করি কেন্দ্রীয় সম্প্রদায় এবং এর আশেপাশের সবাইকে সতর্ক করতে, এবং সতর্ক করতে আহবান দিনের বিষয়ে যা অনিবার্য। শেষপর্যন্ত কারো পরিনতি হবে স্বর্গে, আর কারো নরকে।"],
  "42:8": ["Had Allah willed, He could have made them one community. But He redeems into His mercy whomever He wills. As for the transgressors, they have no master, nor a helper.","যদি আল্লাহ চাইতেন, তিনি তাদেরকে এক সম্প্রদায়ভুক্ত করতে পারতেন। কিন্তু তিনি তাঁর দয়ায় যাকেই চান উদ্ধার করেন। আর সীমালঙ্ঘনকারীদের ক্ষেত্রে, তাদের না আছে কোন অভিভাবক, আর না কোন সাহায্যকারী।"],
  "42:9": ["Did they find other lords beside Him? Allah is the only Lord and Master. He is the One who resurrects the dead, and He is the Omnipotent One.","তারা কি তাঁর পাশে অন্য প্রভুদের খুঁজে পেয়েছে? শুধুমাত্র আল্লাহ প্রভু এবং মনিব। তিনিই সে সত্ত্বা যিনি মৃতকে পুনরুজ্জীবিত করেন, এবং তিনি সর্বশক্তিমান সত্ত্বা।"],
  "42:10": ["If you dispute any part of this message, the judgment for doing this rests with Allah. Such is Allah my Lord. In Him I trust, and to Him I submit.","তোমরা এই বার্তার কোন অংশ নিয়ে বিবাদ করলে,এর বিচারের ভার আল্লাহর হাতে। এমনই আল্লাহ আমার প্রভু। আমি তাঁর উপর আস্থা রাখি,এবং তাঁর কাছে আমি আত্মসমর্পণ করি।"],
  "42:11": ["Initiator of the heavens and the earth. He created for you from among yourselves spouses—and also for the animals. He thus provides you with the means to multiply. There is nothing that equals Him. He is the Hearer, the Seer.","আকাশমণ্ডলী এবং পৃথিবীর সূচনাকারী। তিনি তোমাদের জন্য স্বামী-স্ত্রী সৃষ্টি করেছেন তোমাদের নিজেদের মধ্য থেকে, এবং প্রাণীদের জন্যও। তিনি এভাবে তোমাদেরকে বংশবৃদ্ধির উপায় প্রদান করেন। কোন কিছু নেই যা তাঁর সমান। তিনি শ্রোতা, দ্রষ্টা।"],
  "42:12": ["To Him belongs absolute control of the heavens and the earth. He is the One who increases the provision for whomever He wills, or reduces it. He is fully aware of all things.","আকাশমণ্ডলী এবং পৃথিবী তাঁর একচ্ছত্র নিয়ন্ত্রণাধীন। তিনিই সে সত্ত্বা যিনি যার জন্য ইচ্ছা জীবিকা বৃদ্ধি করেন, অথবা তা কমিয়ে দেন। তিনি সবকিছু সম্পর্কে পূর্ণ অবগত।"],
  "42:13": ["He decreed for you the same religion decreed for Noah, and what we inspired to you, and what we decreed for Abraham, Moses, and Jesus: \"You shall uphold this one religion, and do not divide it.\"The idol worshipers will greatly resent what you invite them to do. Allah redeems to Himself whomever He wills; He guides to Himself only those who totally submit.","তিনি তোমাদের জন্য জারি করেছেন সে একই ধর্ম যা জারি করেছিলেন নুহের জন্য, এবং যা আমরা প্রত্যাদেশ করেছিলাম তোমার প্রতি, এবং যা আমরা জারি করেছিলাম ইব্রাহীম, মুসা, এবং ঈসার উপর: \"তুমি এই একটি ধর্ম মেনে চলবে, এবং একে বিভক্ত করবে না। প্রতিমা-উপাসকরা তাতে ভীষন ক্ষুব্ধ হবে যা করতে  তুমি তাদের আমন্ত্রণ করো। আল্লাহ নিজের দিকে পুনরুদ্ধার করেন যাকেই তিনি চান;  আল্লাহ শুধু তাদেরকে নিজের পথ দেখান যারা পুরোপুরিভাবে আত্মসমর্পণ করে।"],
  "42:14": ["Ironically, they broke up into sects only after the knowledge had come to them, due to jealousy and resentment among themselves. If it were not for a predetermined decision from your Lord to respite them for a definite interim, they would have been judged immediately. Indeed, the later generations who inherited the scripture are full of doubts.","দুঃখজনকভাবে, তারা দলে-উপদলে ভাগ হয়েছিল শুধুমাত্র জ্ঞান আসার পর, তাদের নিজেদের মধ্যে ঈর্ষা এবং বিদ্বেষের কারণে। যদি তাদেরকে একটি সুনির্দিষ্ট অন্তর্বর্তী সময়ের জন্য অবকাশ দেয়ার পূর্বনির্ধারিত সিদ্ধান্ত তোমার প্রভুর পক্ষ থেকে না থাকতো, তাদের বিচার অবিলম্বে করা হত।"],
  "42:15": ["This is what you shall preach, and steadfastly maintain what you are commanded to do, and do not follow their wishes. And proclaim: \"I believe in all the scriptures sent down by Allah. I was commanded to judge among you equitably. Allah is our Lord and your Lord. We have our deeds and you have your deeds. There is no argument between us and you. Allah will gather us all together; to Him is the ultimate destiny.\"","এটাই তুমি প্রচার করবে এবং অবিচলভাবেকরতে থাকো যা করতে তোমাকে আদেশ করা হয়, এবং তাদের ইচ্ছার অনুসরণ করো না। এবং ঘোষনা করো, \"আমি বিশ্বাস করি আল্লাহর অবতীর্ণ সকল ঐশিগ্রন্থে। আমাকে তোমাদের মধ্যে ন্যায়সঙ্গতভাবে বিচার করতে আদেশ করা হয়েছে। আল্লাহ একইসাথে আমাদের প্রভু এবং তোমাদের প্রভু। আমাদের রয়েছে আমাদের কর্ম, তোমাদের রয়েছে তোমাদের কর্ম। আমাদের এবং তোমাদের মাঝে কোন তর্ক-বিবাদ নেই। আল্লাহ আমাদের সবাইকে একসাথে একত্রিত করবেন; তাঁর কাছেই চূড়ান্ত নিয়তি।"],
  "42:16": ["Those who argue about Allah, after receiving His message, their argument is nullified at their Lord. They have incurred condemnation, and have deserved a severe retribution.","যারা আল্লাহ সম্পর্কে তর্ক করে, তাঁর বার্তা পাওয়ার পর, তাদের তর্ক আল্লাহ বাতিল করে দেন। তারা টেনে এনেছে নিন্দা, এবং তারা কঠিন শাস্তি অর্জন করেছে।"],
  "42:17": ["Allah is the One who sent down the scripture, to deliver the truth and the law. For all that you know, the Hour (Day of Judgment) may be very close.","আল্লাহ সেই সত্ত্বা যিনি ঐশিগ্রন্থ পাঠিয়েছেন, সত্য এবং আইন পৌঁছে দিতে। যতটুকু তুমি জানো, সে সময় (বিচার দিবস) হয়তো খুব নিকটে।\""],
  "42:18": ["Challenging it are those who do not believe in it. As for those who believe, they are concerned about it, and they know that it is the truth. Absolutely, those who deny the Hour have gone far astray.","যারা এতে বিশ্বাস করে না তারা এর প্রতি চ্যালেঞ্জ করছে। আর যারা বিশ্বাস করে, তারা এটা সম্পর্কে উদ্বিগ্ন, এবং তারা জানে যে এটা সত্য। নিঃসন্দেহে, যারা সে সময়কে অস্বীকার করে, তারা বহুদূরে পথভ্রষ্ট হয়েছে।"],
  "42:19": ["Allah is fully aware of all His creatures; He provides for whomever He wills. He is the Powerful, the Almighty.","আল্লাহ তাঁর সব সৃষ্টি সম্পর্কে পূর্ণ  অবগত; তিনি যাকেই ইচ্ছা জীবিকা দেন। তিনি ক্ষমতাশালী, সর্বশক্তিমান।"],
  "42:20": ["Whoever seeks the rewards of the Hereafter, we multiply the rewards for him. And whoever seeks the materials of this world, we give him therefrom, then he receives no share in the Hereafter.","যে কেউ পরকালের পুরষ্কার খোঁজে, আমরা তার জন্য পুরষ্কার বহুগুনে বাড়িয়ে দেই। এবং যে কেউ দুনিয়ার বস্তু খোঁজে, আমরা তাকে তা থেকে দেই, কিন্তু পরকালে সে কোন অংশ পায় না।"],
  "42:21": ["They follow idols who decree for them religious laws never authorized by Allah. If it were not for the predetermined decision, they would have been judged immediately. Indeed, the transgressors have incurred a painful retribution.","তারা অনুসরণ করে উপাস্যদের যারা তাদের জন্য জারি করে ধর্মীয় আইনসমূহ যা কখনো আল্লাহ দ্বারা অনুমোদিত হয়নি। যদি পূর্বনির্ধারিত সিদ্ধান্ত না থাকতো,তৎক্ষণাৎ তাদের বিচার হয়ে যেতো। আসলে, সীমালঙ্ঘনকারীরা টেনে এনেছে এক যন্ত্রনাদায়ক শাস্তি ।"],
  "42:22": ["You will see the transgressors worried about everything they had committed; everything will come back and haunt them. As for those who believed and led a righteous life, they will be in the gardens of Paradise. They will receive whatever they wish from their Lord. This is the great blessing.","তুমি দেখবে যে সীমালঙ্ঘনকারীরা সবকিছু সম্পর্কে চিন্তিত যা তারা করেছিল ; সবকিছু ফিরে আসবে এবং তাদেরকে তাড়া করবে। আর তাদের ক্ষেত্রে যারা বিশ্বাস করেছিল এবং সৎ জীবন যাপন করেছিল, তারা স্বর্গের বাগানগুলোতে থাকবে। তারা তাদের প্রভুর কাছ থেকে পাবে, যা কিছুই তারা ইচ্ছা করে। এটি সে বিশাল অনুগ্রহ।"],
  "42:23": ["This is the good news from Allah to His servants who believe and lead a righteous life. Say, \"I do not ask you for any wage. I do ask each of you to take care of your own relatives.\" Anyone who does a righteous work, we multiply his reward for it. Allah is Forgiver, Appreciative.","এটি আল্লাহর পক্ষ থেকে তাঁর বান্দাদের জন্য সুসংবাদ যারা বিশ্বাস করে ও সৎ জীবনযাপন করে। বল, \"আমি তোমাদের কাছে কোন পারিশ্রমিক চাই না। আমি চাই যে তোমাদের প্রত্যেকে নিজ নিজ আত্মীয়-স্বজনদের যত্ন নাও।\" যেকেউ একটি সৎকাজ করে, আমরা তার পুরষ্কারকে এর জন্য বহুগুণে বাড়িয়ে দেই। আল্লাহ ক্ষমাকারী, কৃতজ্ঞ।"],
  "42:24": ["Are they saying, \"He (Rashad) has fabricated lies about Allah!\"? If Allah willed, He could have sealed your mind, but Allah erases the falsehood and affirms the truth with His words. He is fully aware of the innermost thoughts.","তারা কি বলছে, \"সে (রাশাদ) আল্লাহ সম্বন্ধে মিথ্যা রচনা করেছে!\"? যদি আল্লাহ চাইতেন, তিনি তোমাদের মনে মোহর মেরে দিতে পারতেন, কিন্তু আল্লাহ মিথ্যা মুছে ফেলেন এবং তাঁর শব্দাবলী দিয়ে সত্য স্থাপন করেন। তিনি গভীরতম চিন্তাগুলো সম্পর্কে পূর্ণ অবগত।"],
  "42:25": ["He is the One who accepts the repentance from His servants, and remits the sins. He is fully aware of everything you do.","তিনি সে সত্ত্বা যিনি তাঁর বান্দাদের থেকে অনুশোচনা গ্রহন করেন, এবং পাপগুলো ক্ষমা করে দেন। তোমাদের করা সবকিছু সম্পর্কে তিনি সম্পূর্ণ অবগত।"],
  "42:26": ["Responding to Him are those who believe and lead a righteous life. He will shower them with His blessings. As for the disbelievers, they have incurred a severe retribution.","যারা বিশ্বাস করে এবং সৎ জীবনযাপন করে তারা তাঁর প্রতি সাড়া দেয় । তিনি তাদের উপর তাঁর অনুগ্রহ বর্ষণ করবেন। আর অবিশ্বাসীদের ক্ষেত্রে,তারা টেনে এনেছে এক কঠোর শাস্তি।"],
  "42:27": ["If Allah increased the provision for His servants, they would transgress on earth. This is why He sends it precisely measured to whomever He wills. He is fully Cognizant and Seer of His servants.","যদি আল্লাহ তাঁর বান্দাদের জন্য জীবিকা বৃদ্ধি করতেন, তারা পৃথিবীতে সীমালঙ্ঘন করতো। এজন্যই তিনি এটি পরিমিতভাবে পাঠান যার জন্যই তিনি চান। তিনি তাঁর বান্দাদের বিষয়ে পূর্ণ অবগত এবং দ্রষ্টা।"],
  "42:28": ["He is the One who sends down the rain after they had despaired, and spreads His mercy. He is the only Master, Most Praiseworthy.","তিনিই সে সত্ত্বা যিনি বৃষ্টি অবতীর্ণ করেন তারা হতাশ হবার পর, এবং তাঁর দয়া ছড়িয়ে দেন। শুধুমাত্র তিনিই মনিব, সবচেয়ে প্রশংসনীয়।"],
  "42:29": ["Among His proofs is the creation of the heavens and the earth, and the creatures He spreads in them. He is able to summon them, when He wills.","তাঁর প্রমাণাদির মধ্যে রয়েছে আকাশমণ্ডলী এবং পৃথিবীর সৃষ্টি, এবং সে সৃষ্টিগুলো যা তিনি এদের মধ্যে ছড়িয়ে দেন। তিনি তাদেরকে তলব করতে সক্ষম, যখন তিনি চান।"],
  "42:30": ["Anything bad that happens to you is a consequence of your own deeds, and He overlooks many (of your sins).","খারাপ যা কিছুই তোমাদের ক্ষেত্রে ঘটে তা তোমাদের নিজেদের কর্মের ফল, এবং (তোমাদের পাপের) অনেকগুলো তিনি এড়িয়ে যান।"],
  "42:31": ["You can never escape, and you have none beside Allah as a Lord and Master.","তোমরা কখনো পালাতে পারবে না, এবং আল্লাহর পাশে প্রভু এবং মনিব হিসেবে তোমাদের কেউ নেই।"],
  "42:32": ["Among His proofs are the ships that sail the sea with sails like flags.","তার প্রমাণাদির মধ্যে আছে জাহাজগুলো, যা পতাকার মত পালতোলে সমুদ্রে ভেসে বেড়ায়।"],
  "42:33": ["If He willed, He could have stilled the winds, leaving them motionless on top of the water. These are proofs for those who are steadfast, appreciative.","যদি তিনি চাইতেন, তিনি বাতাসকে স্থির করে দিতে পারতেন, যা তাদেরকে পানির উপরিভাগে গতিহীন করে দেয়। এগুলো তাদের জন্য প্রমাণ যারা অবিচল, কৃতজ্ঞ।"],
  "42:34": ["He can annihilate them, as a consequence of their own works. Instead, He overlooks many (of their sins).","তিনি তাদেরকে ধ্বংস করতে পারতেন, তাদের নিজেদের কাজের প্রতিফল হিসেবে। তা সত্ত্বেও, তিনি (তাদের পাপের) অনেকগুলো এড়িয়ে যান।"],
  "42:35": ["Those who argue against our proofs will find out that they have no basis.","আমাদের প্রমাণের বিরুদ্ধে যারা তর্ক করে,তারা খু্ঁজে পাবে যে তাদের কোন ভিত্তি নেই।"],
  "42:36": ["Whatever you are given is no more than temporary material of this life. What Allah possesses is far better and everlasting, for those who believe and trust in their Lord.","তোমাদের যা কিছুই দেওয়া হোক না কেন, তা এই জীবনের ক্ষণস্থায়ী বস্তুর চেয়ে বেশি কিছু নয়। আল্লাহ যা অধিকার করেন তা অনেক উত্তম এবং চিরস্থায়ী,  তাদের জন্য যারা বিশ্বাস করে এবং তাদের আল্লাহতে আস্থা রাখে।"],
  "42:37": ["They avoid gross sins and vice, and when angered they forgive.","তারা গুরুতর পাপসমূহ এবং অনৈতিকতা এড়িয়ে চলে, এবং যখন  রাগান্বিত হয়, তারা ক্ষমা করে দেয়।"],
  "42:38": ["They respond to their Lord by observing the Contact Prayers (Salat). Their affairs are decided after due consultation among themselves, and from our provisions to them they give (to charity).","তারা সংযোগ প্রার্থনার মাধ্যমে তাদের আল্লাহর প্রতি সাড়া দেয়। তাদের বিষয়াদিতে সিদ্ধান্ত হয় তাদের নিজেদের মধ্যে পরামর্শের পর, এবং তাদের প্রতি আমাদের জীবিকা থেকে তারা দেয় (দানে)।"],
  "42:39": ["When gross injustice befalls them, they stand up for their rights.","যখন তাদের সাথে স্পষ্ট অবিচার করা হয়, তারা তাদের অধিকারের জন্য সোচ্চার হয়।"],
  "42:40": ["Although the just requital for an injustice is an equivalent retribution, those who pardon and maintain righteousness are rewarded by Allah. He does not love the unjust.","যদিও কোন অবিচারের সঠিক শাস্তি হলো একটি সমতুল্য শাস্তি,যারা ক্ষমা করে এবং সৎকর্মশীলতা বজায় রাখে তারা আল্লাহর দ্বারা পুরষ্কৃত হয়। তিনি অন্যায়কে ভালবাসেন না।"],
  "42:41": ["Certainly, those who stand up for their rights, when injustice befalls them, are not committing any error.","নিশ্চয়, তারা কোন ভুল করে না, যারা তাদের অধিকারের জন্য সোচ্চার হয়, যখন তাদের সাথে অবিচার করা হয়।"],
  "42:42": ["The wrong ones are those who treat the people unjustly, and resort to aggression without provocation. These have incurred a painful retribution.","তারাই ভুল, যারা লোকদের সাথে অন্যায় আচরণ করে এবং কোন উস্কানি না থাকা সত্ত্বেও আগ্রাসন অবলম্বন করে। এরা টেনে এনেছে এক যন্ত্রণাদায়ক শাস্তি।"],
  "42:43": ["Resorting to patience and forgiveness reflects a true strength of character.","ধৈর্য্য এবং ক্ষমাশীলতা অবলম্বন করা চরিত্রের প্রকৃত জোরকে প্রতিফলন করে।"],
  "42:44": ["Whomever Allah sends astray will never find any other lord, and you will see such transgressors, when they see the retribution, saying, \"Can we get another chance?\"","যাকেই আল্লাহ পথভ্রষ্ট করেন, সে কখনো অন্য কোন প্রভু খুঁজে পাবে না, এবং তুমি এমন সীমালঙ্ঘনকারীদের দেখবে, যখন তারা শাস্তি দেখে  বলছে যে,\"আমরা কি আরেকবার সুযোগ পেতে পারি? \""],
  "42:45": ["You will see them facing it, humiliated and debased, and looking, yet trying to avoid looking. Those who believed will proclaim: \"The real losers are those who lost their souls and their families on the Day of Resurrection. The transgressors have deserved an everlasting retribution.\"","তুমি তাদেরকে দেখবে, অপমানিত এবং অপদস্থ হয়ে, এর মুখোমুখি হবে, এবং তাকাবে, যদিও না তাকানোর চেষ্টা করবে। যারা বিশ্বাস করেছিল তারা ঘোষনা করবে, \"তারা প্রকৃত ক্ষতিগ্রস্ত যারা পূনরুত্থান দিবসে তাদের আত্না এবং তাদের পরিবারকে হারিয়েছে। সীমালঙ্ঘনকারীরা চিরস্থায়ী শাস্তির যোগ্য হয়েছে।\""],
  "42:46": ["There will be no allies to help them against Allah. Whomever Allah sends astray can never be guided.","আল্লাহর বিরুদ্ধে তাদেরকে সাহায্য করার জন্য সেখানে কোন মিত্র থাকবে না। যাকেই আল্লাহ পথভ্রষ্ট করেন, সে কখনো পথপ্রাপ্ত হয় না।"],
  "42:47": ["You shall respond to your Lord before a day comes which is decreed inevitable by Allah. There will be no refuge for you on that day, nor an advocate.","তোমরা তোমাদের প্রভুর প্রতি সাড়া দিবে, সে দিনের আগে যা আল্লাহর দ্বারা অনিবার্য করা হয়েছে। ঐদিন তোমাদের জন্য না থাকবে কোন আশ্রয়স্থল, না কোন উকিল।"],
  "42:48": ["If they turn away, we did not send you as their guardian. Your sole mission is delivering the message. When we shower the human beings with mercy, they become proud, and when adversity afflicts them, as a consequence of their own deeds, the human beings turn into disbelievers.","যদি তারা মুখ ফিরিয়ে নেয়, আমরা তোমাকে তাদের অভিভাবক হিসেবে পাঠাইনি। তোমার একমাত্র দায়িত্ব বার্তা পৌঁছে দেয়া। যখন আমরা মানুষের উপর দয়া বর্ষণ করি, তারা গর্বিত হয়ে ওঠে, এবং দুর্দশা যখন তাদেরকে পীড়া দেয়, তাদের নিজেদের কাজের পরিনামে, মানুষ অবিশ্বাসীতে পরিনত হয়।"],
  "42:49": ["To Allah belongs the sovereignty of the heavens and the earth. He creates whatever He wills, granting daughters to whomever He wills, and granting sons to whomever He wills.","আকাশমণ্ডলী এবং পৃথিবীর সার্বভৌমত্ব আল্লাহর অধীনে। তিনি সৃষ্টি করেন যা কিছুই তিনি ইচ্ছা করেন, তিনি যাকে ইচ্ছা কন্যা সন্তান দেন, এবং যাকে ইচ্ছা পুত্র  সন্তান দেন।"],
  "42:50": ["Or, He may have the males and the females marry each other, then render whomever He wills sterile. He is Omniscient, Omnipotent.","অথবা, হয়তো তিনি নারী এবং পুরুষদের একে অন্যকে বিয়ে করতে দেন, এরপর যাকেই তিনি চান বন্ধ্যা করেন। তিনি সর্বজ্ঞ, সর্বশক্তিমান।"],
  "42:51": ["No human being can communicate with Allah except through inspiration, or from behind a barrier, or by sending a messenger through whom He reveals what He wills. He is the Most High, Most Wise.","কোন মানুষ আল্লাহর সাথে যোগাযোগ করতে পারে না, প্রত্যাদেশের মাধ্যমে, অথবা কোন অন্তরালের পেছন থেকে, অথবা কোন বার্তাবাহক পাঠানোর মাধ্যম ব্যতীত, যার দ্বারা তিনি যা চান প্রকাশ করেন।তিনি সবচেয়ে উর্দ্ধে, সবচেয়ে প্রজ্ঞাবান।"],
  "42:52": ["Thus, we inspired to you a revelation proclaiming our commandments. You had no idea about the scripture, or faith. Yet, we made this a beacon to guide whomever we choose from among our servants. Surely, you guide in a straight path.","এভাবে, আমরা তোমাকে অনুপ্রাণিত করেছি একটি প্রকাশনার বিষয়ে যা আমাদের প্রত্যাদেশ ঘোষনা করে। ঐশিগ্রন্থ, অথবা বিশ্বাস সম্পর্কে তোমার কোন ধারণা ছিল না। তাসত্ত্বেও, আমরা একে একটি অলোকবর্তিকা করেছি পথনির্দেশনা দেওয়ার জন্য আমাদের বান্দাদের মধ্য থেকে যাকেই আমরা পছন্দ করি। নিশ্চয় তুমি সরল পথে পরিচালিত করো।"],
  "42:53": ["The path of Allah, to whom belongs everything in the heavens and everything on earth. Absolutely, all matters are controlled by Allah.","আল্লাহর পথ, যাঁর অধীনে আকাশমণ্ডলীর সবকিছু এবং পৃথিবীর সবকিছু। নিঃসন্দেহে,সব ব্যাপার আল্লাহর দ্বারা নিয়ন্ত্রিত হয়।"],
  "43:1": ["H. M.","হ. ম. (হা মীম)"],
  "43:2": ["And the enlightening scripture.","এবং সে জ্ঞানালোকপূর্ণ ঐশীগ্রন্থ।"],
  "43:3": ["We have rendered it an Arabic Quran, that you may understand.","আমরা একে একটি আরবি কুরআন করেছি,  যাতে তোমরা বুঝতে পারো।"],
  "43:4": ["It is preserved with us in the original master, honorable and full of wisdom.","এটি আমাদের মাধ্যমে মূল গ্রন্থে সংরক্ষিত, যা সম্মানিত এবং প্রজ্ঞাপূর্ণ।"],
  "43:5": ["Should we just ignore the fact that you have transgressed the limits?","আমাদের কি উচিত শুধু এই বাস্তব সত্যটা উপেক্ষা করা যে তোমরা সীমা-লংঘন করেছো?"],
  "43:6": ["We have sent many a prophet to the previous generations.","আমরা পূর্ববর্তী প্রজন্মগুলোতে অনেক নবী পাঠিয়েছি।"],
  "43:7": ["Every time a prophet went to them, they ridiculed him.","প্রতিবার যখন একজন বার্তাবাহক তাদের কাছে গিয়েছিলো, তারা তার প্রতি উপহাস করেছিল।"],
  "43:8": ["Consequently, we annihilated people who were even more powerful than these. We thus set the examples from the previous communities.","পরিনামে, আমরা লোকদের নিশ্চিহ্ন করেছিলাম যারা এমনকি এদের চেয়ে আরো বেশি ক্ষমতাধর ছিল। আমরা এভাবে পূর্ববর্তী সম্প্রদায়গুলো থেকে উদাহরণ স্থাপন করি।"],
  "43:9": ["If you asked them, \"Who created the heavens and the earth,\" they would say, \"The Almighty, the Omniscient has created them.\"","যদি তুমি তাদের জিজ্ঞেস করতে, \"কে আকাশমণ্ডলী ও পৃথিবী সৃষ্টি করেছিলেন, \" তারা বলতো, \"সর্বশক্তিমান, সর্বজ্ঞ তাদের সৃষ্টি  করেছেন।\""],
  "43:10": ["He is the One who made the earth habitable for you, and created for you roads therein, that you may follow the right way.","তিনিই সে সত্ত্বা যিনি পৃথিবীকে তোমাদের জন্য বাসযোগ্য করেছেন, এবং সেখানে তোমাদের জন্য রাস্তা সৃষ্টি করেছেন, যাতে তোমরা সঠিক পথ অনুসরণ করতে পারো।"],
  "43:11": ["He is the One who sends down from the sky water, in exact measure, to revive dead lands therewith. Similarly, you will be resurrected.","তিনিই সে সত্ত্বা যিনি আকাশ থেকে পানি বর্ষণ করেন, যথাযথ পরিমানে, তার দ্বারা মৃত জমিকে জীবিত করতে। একইভাবে, তোমরা পুনরুত্থিত হবে।"],
  "43:12": ["He is the One who created all kinds, in pairs (male and female), and He created for you ships and livestock to ride.","তিনিই সে সত্ত্বা যিনি সৃষ্টি করেছেন সকল প্রকার, জোড়ায় জোড়ায় (পুরুষ ও নারী), এবং তিনি তোমাদের আরোহণের জন্য জাহাজ এবং পালিত পশু সৃষ্টি করেছেন।"],
  "43:13": ["As you rest on top of them, you shall appreciate such a blessing from your Lord, and say, \"Glory be to the One who subdued this for us. We could not have controlled them by ourselves.","তোমরা যখন তাদের উপর অবস্থান করো,তোমরা তোমাদের প্রভুর পক্ষ থেকে এমন অনুগ্রহের মূল্যায়ন করবে,এবং বলো,\"মহিমা সে সত্ত্বার যিনি আমাদের জন্য একে বশীভূত করেছেন। আমরা নিজেরা তাদেরকে নিয়ন্ত্রণ করতে পারতাম না।"],
  "43:14": ["\"We ultimately return to our Lord.\"","\"আমরা অবশেষে আমাদের প্রভুর কাছে ফিরে যাই।\""],
  "43:15": ["They even assigned for Him a share from His own creation! Surely, the human being is profoundly unappreciative.","এমনকি  তারা তাঁর নিজের সৃষ্টি থেকে একটি অংশকে তাঁর জন্য নির্ধারণ করে! নিশ্চয়, মানুষ চরম অকৃতজ্ঞ।"],
  "43:16": ["Has He chosen from among His creations daughters for Himself, while blessing you with sons?","তিনি কি তাঁর সৃষ্টিজগতের  মধ্য থেকে নিজের জন্য কন্যাদের পছন্দ করেছেন, যখন তোমাদেরকে পূত্র দিয়ে অনুগ্রহ করেন?"],
  "43:17": ["When one of them is given news (of a daughter) as they claimed for the Most Gracious, his face is darkened with misery and anger!","যখন তাদের কাউকে (একটি কন্যা সন্তানের) সংবাদ দেয়া হয় যেমন তারা সবচেয়ে দয়ালুর জন্য দাবি করেছিল, তার মুখমণ্ডল   দুর্দশা এবং রাগে  অন্ধকারাচ্ছন্ন হয়!"],
  "43:18": ["(They say,) \"What is good about an offspring that is brought up to be beautiful, and cannot help in war?\"","(তারা বলে,) \"সে সন্তানে কি ভাল আছে যাকে লালন-পালন করা হয় রমনীয় হওয়ার জন্য, এবং যুদ্ধে সাহায্য করতে পারে না?\""],
  "43:19": ["They claimed that the angels, who are servants of the Most Gracious, are females! Have they witnessed their creation? Their claims are recorded, and they will be asked.","তারা দাবি করেছিল যে, সবচেয়ে দয়ালুর বান্দা ফেরেশতারা হলো নারী! তারা কি তাদের সৃষ্টি প্রত্যক্ষ করেছে? তাদের দাবী লিপিবদ্ধ আছে, এবং তাদেরকে জিজ্ঞেস করা হবে।"],
  "43:20": ["They even said, \"If the Most Gracious willed, we would not have worshiped them.\" They have no basis for such a claim; they only conjecture.","তারা এমনকি বলেছিল, \"যদি সবচেয়ে দয়ালু ইচ্ছা করতেন, আমরা তাদের উপাসনা করতাম না।\" তাদের এমন দাবীর কোন ভিত্তি নেই; তারা শুধু অনুমান করে।"],
  "43:21": ["Have we given them a book before this, and they are upholding it?","আমরা কি তাদেরকে এর পূর্বে কোন গ্রন্থ দিয়েছি, আর তারা এর সমর্থন করছে?"],
  "43:22": ["The fact is: they said, \"We found our parents carrying on certain practices, and we are following in their footsteps.\"","বাস্তবতা হচ্ছে: তারা বলেছিল, \"আমরা আমাদের মাতা-পিতাকে পেয়েছিলাম নির্দিষ্ট কিছু অনুশীলন চালিয়ে যেতে, এবং আমরা তাদের পদাঙ্ক অনুসরণ করছি।\""],
  "43:23": ["Invariably, when we sent a warner to any community, the leaders of that community would say, \"We found our parents following certain practices, and we will continue in their footsteps.\"","ঠিক তেমনি, যখন আমরা কোন সম্প্রদায়ের কাছে একজন সতর্ককারী পাঠাতাম, ঐ সম্প্রদায়ের নেতারা বলতো, \"আমরা আমাদের মাতা-পিতাকে পেয়েছিলাম নির্দিষ্ট কিছু অনুশীলন অনুসরণ করতে , এবং আমরা তাদের পদাঙ্ককে বহাল থাকবো।\""],
  "43:24": ["(The messenger) would say, \"What if I brought to you better guidance than what you inherited from your parents?\" They would say, \"We are disbelievers in the message you brought.\"","(বার্তাবাহক) বলতো, \"যদি এমন হয় যে তোমরা  তোমাদের পিতা-মাতা থেকে উত্তরাধিকারসূত্রে যা পেয়েছো তার চেয়ে আমি তোমাদের কাছে উত্তম পথনির্দেশনা নিয়ে এসেছি? \"তারা বলতো, \"তুমি যে বার্তা এনেছো তাতে আমরা অবিশ্বাসী ।\""],
  "43:25": ["Consequently, we requited them. Note the consequences for the rejectors.","পরিনামে, আমরা তদের প্রতিদান দিয়েছিলাম। প্রত্যাখ্যানকারীদের পরিনামসমূহ লক্ষ্য করো।"],
  "43:26": ["Abraham said to his father and his people, \"I disown what you worship.","ইব্রাহিম তার পিতাকে এবং তার লোকদের বলেছিল, \"আমি প্রত্যাখ্যান করি যা তোমরা উপাসনা করো।"],
  "43:27": ["\"Only the One who initiated me can guide me.\"","আমাকে পথ দেখাতে পারেন শুধু সে সত্ত্বা যিনি আমার সূচনা করেছেন।\""],
  "43:28": ["This example (of Abraham) was rendered an everlasting lesson for subsequent generations; perhaps they redeem their souls.","(ইব্রাহিমের) এই উদাহরণ পরবর্তী প্রজন্মগুলোর জন্য একটি চিরস্থায়ী উদাহরণ উপস্থাপন করে; হয়তো তারা তাদের আত্মাকে পুনরুদ্ধার করবে।"],
  "43:29": ["Indeed, I have given these people and their ancestors sufficient chances, then the truth came to them, and a clarifying messenger.","প্রকৃতপক্ষে, আমি এই লোকদের এবং তাদের পূর্বপুরুষদের যথেষ্ট সুযোগ দিয়েছি, এরপর তাদের কাছে এসেছিল সত্য, এবং একজন স্পষ্ট বার্তাবাহক।"],
  "43:30": ["When the truth came to them, they said, \"This is magic, and we are disbelievers therein.\"","যখন সত্য তাদের কাছে এসেছিল, তারা বলেছিল, \"এটা জাদু, এবং আমরা তাতে অবিশ্বাসী। \""],
  "43:31": ["They said, \"If only this Quran was sent down through another man from the two communities (Mecca or Yathrib) who is prominent!\"","তারা বলেছিল, \"যদি শুধু এই কুরআন  দুই সম্প্রদায়ের (মক্কা বা ইয়াথরিবের) অন্যকোন বিশিষ্ট মানুষের মাধ্যমে অবতীর্ণ হতো!\""],
  "43:32": ["Are they the ones who assign your Lord's mercy? We have assigned their shares in this life, raising some of them above others in ranks, in order to let them serve one another. The mercy from your Lord is far better than any material they may hoard.","তারা কি সে ব্যক্তি যারা তোমার প্রভুর দয়া নির্ধারণ করে? আমরা এই জীবনে তাদের অংশ নির্ধারণ করেছি, মর্যাদায়  তাদের কাউকে অন্যদের উপর স্থান দিয়ে, যেন তারা একে অন্যকে সেবা দিতে পারে। তোমার প্রভু থেকে দয়া অনেক উত্তম যেকোন জিনিসের চেয়ে যা তারা জমা করতে পারে।"],
  "43:33": ["If it were not that all the people might become one (disbelieving) congregation, we would have granted everyone who disbelieves in the Most Gracious mansions with silver roofs, and stairs upon which they could climb.","যদি সব মানুষ এক (অবিশ্বাসী) ধর্মগোষ্ঠী হয়ে যাওয়ার আশংকা না থাকতো, যারা পরম দয়াময়কে অবিশ্বাস করে আমরা তাদের সবাইকে দান করতাম  রুপার ছাঁদবিশিষ্ট অট্রালিকা আর সিঁড়ি যা দিয়ে তারা আরোহণ করতে পারতো।"],
  "43:34": ["Their mansions would have impressive gates, and luxurious furnishings.","তাদের অট্রালিকাগুলোতে থাকতো চিত্তাকর্ষক দরজা, এবং বিলাসবহুল আসবাবপত্র।"],
  "43:35": ["Also many ornaments. All these are the temporary materials of this lowly life. The Hereafter—at your Lord—is far better for the righteous.","এছাড়া অনেক অলংকার। এগুলো হলো এই নিম্নমানের জীবনের অস্থায়ী বস্তুসামগ্রী। পরকাল- তোমার প্রভুর নিকট- সৎকর্মশীলদের জন্য অনেক অনেক উত্তম।"],
  "43:36": ["Anyone who disregards the message of the Most Gracious, we appoint a devil to be his constant companion.","যেকেউ সবচেয়ে দয়ালুর বার্তাকে উপেক্ষা করে, আমরা একজন শয়তানকে তার ধ্রুব সহচর হিসেবে  নিযুক্ত  করি।"],
  "43:37": ["Such companions will divert them from the path, yet make them believe that they are guided.","এমন সহচর তাদেরকে পথ থেকে সরিয়ে দিবে, যদিও তাদেরকে বিশ্বাস করায় যে তারা সুপথপ্রাপ্ত"],
  "43:38": ["When he comes before us he will say, \"Oh I wish you were as far from me as the two easts. What a miserable companion!\"","যখন সে আমাদের সামনে আসে সে বলবে, \"ওহ তুমি যদি আমার থেকে দুই পূর্বের দূরত্বের মতো দূরে থাকতে। কি এক শোচনীয় সহচর! \""],
  "43:39": ["It will not console you on that day, as transgressors, that both of you will share in the retribution.","তোমরা দু'জনেই যে শাস্তির ভাগিদার হবে, সীমালঙ্ঘনকারী হিসেবে,সেটা তোমাকে সেদিন সান্ত্বনা দিবে না।"],
  "43:40": ["Can you make the deaf hear; can you make the blind see, or those who are far astray?","তুমি কি বধিরকে শুনাতে পারো; তুমি কি অন্ধকে দেখাতে পারো, অথবা তাদেরকে যারা বহুদূর পথভ্রষ্ট?"],
  "43:41": ["Whether we let you die before it or not, we will surely requite them.","আমরা এর আগে তোমাকে মরতে দেই অথবা না দেই, অবশ্যই আমরা তাদেরকে প্রতিদান দিবো।"],
  "43:42": ["Or, we may show you (the retribution) we promised for them. We are in full control over them.","অথবা,আমরা হয়তো তোমাকে (সে শাস্তি) দেখাবো যা আমরা তাদেরকে অঙ্গীকার করেছিলাম। তারা আমাদের পূর্ণ নিয়ন্ত্রণে।"],
  "43:43": ["You shall steadfastly preach what is revealed to you; you are in the right path.","যা তোমার কাছে প্রকাশ করা হয় তা তুমি অবিচলভাবে প্রচার করবে ; তুমি সঠিক পথে আছো।"],
  "43:44": ["This is a message for you and your people; all of you will be questioned.","এটি তোমার এবং তোমার লোকদের জন্য একটি বার্তা; তোমাদের সবাইকে প্রশ্ন করা হবে।"],
  "43:45": ["Check the messengers we sent before you: \"Have we ever appointed any other gods—beside the Most Gracious—to be worshiped?\"","তোমার পূর্বে পাঠানো বার্তাবাহকদের যাচাই করো: \"আমরা কি কখনো অন্যকোন উপাস্য নিয়োগ করেছি- সবচেয়ে দয়ালুর পাশে- উপাসিত হতে?\""],
  "43:46": ["For example, we sent Moses with our proofs to Pharaoh and his elders, proclaiming: \"I am a messenger from the Lord of the universe.\"","উদাহরণস্বরুপ, আমরা মূসাকে ফেরাউন এবং তার সভাসদের কাছে আমাদের প্রমাণাদিসহ পাঠিয়েছিলাম, ঘোষনা করে যে: \"আমি মহাবিশ্বের প্রভুর পক্ষ থেকে একজন বার্তাবাহক। \""],
  "43:47": ["When he showed them our proofs, they laughed at them.","যখন সে তাদেরকে আমাদের প্রমাণাদি দেখালো, তারা তাদেরকে নিয়ে উপহাস করলো।"],
  "43:48": ["Every sign we showed them was bigger than the one before it. We afflicted them with the plagues, perhaps they repent.","প্রত্যেকটি নিদর্শন যা আমরা তাদেরকে দেখিয়েছিলাম পূর্বের কোন একটির চেয়ে বড় ছিল। আমরা তাদেরকে মহামারী দিয়ে কষ্ট দিয়েছিলাম, হয়তো তারা অনুশোচনা করবে।"],
  "43:49": ["They said, \"O you magician, implore your Lord on our behalf, since you have an agreement with Him (to relieve this plague); we will then be guided.\"","তারা বলেছিল, “হে যাদুকর!, আমাদের পক্ষ হয়ে তোমার প্রভুর কাছে মিনতি করো, যেহেতু  (এই মহামারী দূর করতে) তাঁর সাথে তোমার একটি চুক্তি আছে; আমরা তারপর সুপথপ্রাপ্ত হবো।”"],
  "43:50": ["But as soon as we relieved their affliction, they reverted.","কিন্তু যখনই আমরা তাদের দুর্দশা দূর করেছিলাম, তারা মুখ ফিরিয়ে নিয়েছিল।"],
  "43:51": ["Pharaoh announced to his people, \"O my people, do I not possess the kingship over Egypt, and these flowing rivers belong to me? Do you not see?","ফেরাউন তার লোকদের কাছে ঘোষনা করলো, “হে আমার লোকেরা, আমি কি মিশরের রাজত্বের অধিকারী  নই, এবং এই প্রবাহিত নদীগুলো কি আমার অধীনে নয়? তোমরা কি দেখো না?"],
  "43:52": ["\"Which one is better; me or that one who is lowly and can hardly speak?","“কোন ব্যক্তি উত্তম; আমি নাকি সে ব্যক্তি যে নিচু স্বভাবের এবং  কথা বলতে কষ্ট হয়?"],
  "43:53": ["\"How come he does not possess a treasure of gold; how come the angels do not accompany him?\"","“কেন তাহলে সে কোন স্বর্ন ভান্ডারের মালিক নয়; কেন তাহলে ফেরেশতারা তার সঙ্গে থাকে না?”"],
  "43:54": ["He thus fooled his people, and they obeyed him; they were wicked people.","সে এভাবে তার লোকদের বোকা বানিয়েছিল, এবং তারা তাকে মান্য করেছিল; তারা ছিল অন্যায়কারী লোক।"],
  "43:55": ["When they persisted in opposing us, we punished them and drowned them all.","যখন তারা আমাদের বিরোধীতায় স্থির থাকলো, আমরা তাদেরকে শাস্তি দিয়েছিলাম এবং তাদের সবাইকে ডুবিয়ে দিলাম।"],
  "43:56": ["We rendered them a precedent and an example for the others.","আমরা তাদেরকে পূর্ববর্তী করেছিলাম এবং অন্যদের জন্য একটি উদাহরণ।"],
  "43:57": ["When the son of Mary was cited as an example, your people disregarded it.","যখন মরিয়মের পুত্রকে একটি উদাহরণ হিসেবে উদ্ধৃত করা হয়েছিল, তোমার লোকেরা তা উপেক্ষা করেছিলো।"],
  "43:58": ["They said, \"Is it better to worship our gods, or to worship him?\" They said this only to argue with you. Indeed, they are people who have joined the opposition.","তারা বলেছিল, “আমাদের উপাস্যদের উপাসনা করা উত্তম, নাকি তার উপাসনা করা?” তারা এটা বলেছিল শুধু তোমার সাথে তর্ক করার জন্য। প্রকৃতপক্ষে, তারা সে লোক যারা বিরোধিতায় যোগ দিয়েছে।"],
  "43:59": ["He was no more than a servant whom we blessed, and we sent him as an example for the Children of Israel.","সে একজন বান্দার চেয়ে বেশি কিছু ছিল না যার প্রতি আমরা অনুগ্রহ করেছিলাম, এবং আমরা তাকে ইসরাইলের সন্তাদের জন্য একটি উদাহরণ হিসেবে পাঠিয়েছিলাম।"],
  "43:60": ["If we willed, we could have made you angels who colonize and reproduce on earth.","যদি আমরা চাইতাম, আমরা তোমাদের স্বর্গদূত করতে পারতাম যারা বসতি স্থাপন করতো এবং পৃথিবীতে বংশ বিস্তার করতো।"],
  "43:61": ["He is to serve as a marker for knowing the end of the world, so you can no longer harbor any doubt about it. You shall follow Me; this is the right path.","বিশ্বের সমাপ্তি জানার জন্য সে কাজ করবে চিহ্নিতকারী হিসেবে, যেন এ সম্পর্কে তোমরা আর  কখনো কোন সন্দেহ পোষন না করো। তোমরা আমার অনুসরণ করবে; এটাই সঠিক পথ।"],
  "43:62": ["Let not the devil repel you; he is your most ardent enemy.","তোমরা শয়তানকে বাধা দিতে দিও না; সে তোমাদের সবচেয়ে স্পষ্ট  শত্রু।"],
  "43:63": ["When Jesus went with the proofs, he said, \"I bring to you wisdom, and to clarify some of the matters in which you dispute. You shall reverence Allah and obey me.","যখন ঈসা প্রমানসমূহ নিয়ে গিয়েছিল, সে বলল, “আমি তোমাদের কাছে প্রজ্ঞা নিয়ে, এবং কিছু বিষয় সুস্পষ্ট করতে আসি যেগুলো নিয়ে তোমরা বিবাদ করো। তোমরা আল্লাহর ভক্তি করবে এবং আমাকে মান্য করবে।"],
  "43:64": ["\"Allah is my Lord and your Lord, you shall worship Him alone. This is the right path.\"","আল্লাহ আমার এবং তোমাদের প্রভু, তোমরা কেবল তাঁর উপাসনা করবে। এটাই সঠিক পথ।\""],
  "43:65": ["The opponents disputed among themselves. Woe to those who transgress from the retribution of a painful day.","বিরোধীরা নিজেদের মধ্যে বিবাদ করেছিল। দুর্ভোগ তাদের প্রতি যারা এক যন্ত্রণাদায়ক দিনের শাস্তি থেকে সীমালঙ্ঘন করে।"],
  "43:66": ["Are they waiting for the Hour (Day of Judgment) to come to them suddenly when they least expect it?","তারা কি অপেক্ষা করছে সে সময়ের (বিচার দিবস) আকস্মিকভাবে আসার জন্য যখন তারা এর প্রত্যাশা খুব কমই করে?"],
  "43:67": ["The close friends on that day will become enemies of one another, except for the righteous.","ঐদিন ঘনিষ্ঠ বন্ধুরাও একে অন্যের শত্রু হয়ে পড়বে, সৎকর্মশীলরা ব্যতীত ।"],
  "43:68": ["O My servants, you will have no fear on that day, nor will you grieve.","হে আমার বান্দারা, ঐদিন তোমাদের কোন ভয় থাকবে না, না তোমরা শোক করবে।"],
  "43:69": ["They are the ones who believed in our revelations, and were submitters.","তারা সে ব্যক্তি যারা আমাদের প্রকাশনাবলিতে বিশ্বাস করেছিল, এবং আত্মসমর্পণকারী ছিল।"],
  "43:70": ["Enter Paradise, together with your spouses, and rejoice.","স্বর্গে প্রবেশ করো, তোমাদের সঙ্গীদের সাথে, এবং আনন্দ করো।"],
  "43:71": ["Offered to them will be golden trays and cups, and they will find everything the hearts desire and the eyes wish for. You live therein forever.","তাদেরকে পরিবেশন করা হবে সোনালী ট্রে এবং পেয়ালা, এবং তারা সবকিছু পাবে যার জন্য হৃদয় আকাঙ্ক্ষা করে এবং চোখ ইচ্ছা পোষণ করে। তোমরা সেখানে চিরকাল বসবাস করো।"],
  "43:72": ["Such is the Paradise that you inherit, in return for your works.","তোমাদের কর্মের বিনিময়ে তোমরা এই স্বর্গের উত্তরাধিকারী হবে।"],
  "43:73": ["You will have in it all kinds of fruits, from which you eat.","এতে তোমরা পাবে সব রকমের ফল, যা থেকে তোমরা খাও।"],
  "43:74": ["Surely, the guilty will abide in the retribution of Gehenna forever.","নিশ্চয়, অপরাধী ব্যাক্তি জাহান্নামের শাস্তিতে চিরকাল বাস করবে।"],
  "43:75": ["Never will the retribution be commuted for them; they will be confined therein.","তাদের জন্য শাস্তি কখনো কমানো হবে না; তারা তাতে আবদ্ধ থাকবে।"],
  "43:76": ["It is not us who wronged them; it is they who wronged their own souls.","তাদের ক্ষতি আমরা করিনি; তারাই তাদের নিজ আত্মার ক্ষতি করেছিল।"],
  "43:77": ["They will implore: \"O Mãlek, let your Lord finish us off.\" He will say, \"You are staying forever.","তারা মিনতি করবে: \"হে মালেক, তোমার প্রভু যেন আমাদের ধ্বংস করেন।\" সে বলবে, \"তোমরা অবস্থান করছো চিরকাল।"],
  "43:78": ["\"We have given you the truth, but most of you hate the truth.\"","\"আমরা তোমাদেরকে সত্য দিয়েছি, কিন্তু তোমাদের বেশির ভাগ সত্যকে ঘৃনা করো।\""],
  "43:79": ["Have they schemed some scheme? We too are scheming.","তারা কি কিছু ষড়যন্ত্রের পরিকল্পনা করেছে? আমরাও পরিকল্পনা করছি।"],
  "43:80": ["Do they think that we do not hear their secrets and conspiracies? Yes indeed; our messengers are with them, recording.","তারা কি মনে করে যে আমরা তাদের গোপনীয়তা এবং ষড়যন্ত্রগুলো শুনি না? হ্যা নিশ্চয়; আমাদের বার্তাবাহকেরা তাদের সাথে আছে, লিপিবদ্ধ করছে।"],
  "43:81": ["Proclaim: \"If the Most Gracious did have a son, I would still be the foremost worshiper.\"","ঘোষনা করো: \"যদি সবচেয়ে দয়ালুর একজন পূত্রসন্তান থাকতো, এরপরেও আমি সর্বপ্রথম উপাসনাকারী হতাম।\""],
  "43:82": ["Be He glorified; He is the Lord of the heavens and the earth, the Lord with the great dominion, far above their claims.","তিনি মহিমান্বিত; তিনি আকাশমণ্ডলী এবং পৃথিবীর প্রভু, বিশাল রাজত্বের প্রভু, তাদের দাবির অনেক উর্দ্ধে।"],
  "43:83": ["Let them blunder and play until they meet their day that is awaiting them.","তাদেরকে বিভ্রমে এবং ক্রিড়া-কৌতুকে থাকতে দাও যতক্ষণ না পর্যন্ত তারা তাদের দিনের সাক্ষাত করে যা তাদের জন্য অপেক্ষা করছে"],
  "43:84": ["He is the only One who is a deity in the heaven and a deity on earth. He is the Most Wise, the Omniscient.","তিনিই সে একমাত্র সত্ত্বা যিনি আকাশে একজন দেবতা এবং পৃথিবীতে একজন দেবতা। তিনি সবচেয়ে জ্ঞানী, সর্বজ্ঞ।"],
  "43:85": ["Most Exalted is the One who possesses all sovereignty of the heavens and the earth, and everything between them. With Him is the knowledge about the Hour (end of the world), and to Him you will be returned.","সবচেয়ে প্রশংসিত সে সত্ত্বা যিনি আকাশমন্ডলী এবং পৃথিবী, এবং এদের মধ্যকার সবকিছুর সকল সার্বভৌমত্বের অধিকারী। তাঁর কাছেই রয়েছে সে সময় (বিশ্বের সমাপ্তি) সম্পর্কিত জ্ঞান, এবং তাঁর কাছেই তোমরা ফিরে যাবে।"],
  "43:86": ["None of those whom they idolize beside Him possess any power to intercede, unless their intercession coincides with the truth, and they fully know.","যাদেরকে তারা তাঁর পাশে উপাস্য স্থাপন করে তাদের কারোরই মধ্যস্থতা করার কোন ক্ষমতা নেই,  যদি না তাদের মধ্যস্থতা সত্যের সাথে মিলে যায়, এবং তারা পুরোপুরি জানে।"],
  "43:87": ["If you asked them who created them, they would say, \"Allah.\" Why then did they deviate?","যদি তুমি তাদেরকে জিজ্ঞেস করতে, কে তাদেরকে সৃষ্টি করেছে, তারা বলত, \"আল্লাহ\"। তবে কেন তারা পথচ্যুত হয়?"],
  "43:88": ["It will be proclaimed: \"O my Lord, these people do not believe.\"","ঘোষনা করা হবে যে: \"হে আমার প্রভু, এই লোকেরা বিশ্বাস করে না।\""],
  "43:89": ["You shall disregard them and say, \"Peace;\" they will surely find out.","তুমি তাদেরকে উপেক্ষা করবে এবং বল, \"শান্তি;\" তারা নিশ্চয়ই খুঁজে পাবে।"],
  "44:1": ["H. M.","হ. ম. (হা মীম)"],
  "44:2": ["And this enlightening scripture.","এবং এই জ্ঞানালোকপূর্ণ ঐশীগ্রন্থ।"],
  "44:3": ["We have sent it down in a blessed night, for we are to warn.","আমরা একে অবতীর্ণ করেছি একটি অনুগ্রহপ্রাপ্ত রাতে, কারণ আমরা সতর্ক করি।"],
  "44:4": ["In it (the scripture), every matter of wisdom is clarified.","এতে (ঐশীগ্রন্থে), প্রজ্ঞার প্রত্যেকটি বিষয় সহজবোধ্য করা হয়েছে।"],
  "44:5": ["It is a predetermined command from us that we send messengers.","এটা আমাদের থেকে একটি পূর্বনির্ধারিত আদেশ যে আমরা বার্তাবাহকদের প্রেরণ করি।"],
  "44:6": ["This is a mercy from your Lord. He is the Hearer, the Omniscient.","এটি তোমার প্রভুর পক্ষ থেকে একটি দয়া। তিনি শ্রবণকারী, সর্বজ্ঞ।"],
  "44:7": ["Lord of the heavens and the earth, and everything between them. If only you could be certain!","আকাশমণ্ডলী এবং পৃথিবীর প্রভু, এবং এদের মধ্যকার সবকিছুর প্রভু। যদি শুধু তুমি নিশ্চিত হতে পারতে!"],
  "44:8": ["There is no other god beside Him. He controls life and death; your Lord and the Lord of your ancestors.","তাঁর পাশে অন্য কোন উপাস্য নেই। তিনি নিয়ন্ত্রণ করেন জীবন এবং মৃত্যু; তোমাদের প্রভু এবং তোমাদের পূর্বপুরুষদের প্রভু।"],
  "44:9": ["Indeed, they are doubtful, heedless.","নিশ্চয়, তারা সন্দিহান, অমনোযোগী।"],
  "44:10": ["Therefore, watch for the day when the sky brings a profound smoke.","অত:এব, সে দিনটির জন্য অপেক্ষা করো যখন আকাশ পরিবেষ্টনকারী ধোঁয়া নিয়ে আসে।"],
  "44:11": ["It will envelop the people; this is a painful retribution.","এটা লোকদের পুরোপুরি ঢেকে ফেলবে; এটি একটি যন্ত্রণাদায়ক শাস্তি।"],
  "44:12": ["\"Our Lord, relieve this retribution for us; we are believers.\"","\"আমাদের প্রভু, আমাদের জন্য এই শাস্তি দূর করুন; আমরা বিশ্বাসী।\""],
  "44:13": ["Now that it is too late, they remember! An enlightening messenger had come to them.","এখন যখন অনেক দেরী হয়ে গেছে, তারা স্মরন করে! একজন জ্ঞান দানকারী বার্তাবাহক তাদের কাছে এসেছিল।"],
  "44:14": ["But they turned away from him, saying, \"Well educated, but crazy!\"","কিন্তু তারা তার থেকে মুখ ফিরিয়ে নিয়েছিল, এ বলে যে, \"উচ্চ শিক্ষিত, কিন্তু পাগল!\""],
  "44:15": ["We will relieve the retribution for awhile; you will soon revert.","আমরা কিছু সময়ের জন্য শাস্তি দূর করবো; দ্রুতই তোমরা প্রত্যাবর্তন করবে।"],
  "44:16": ["The day we strike the big stroke, we will avenge.","সেদিন যখন আমরা বড় আঘাতটি দিয়ে আঘাত করি , তখন আমরা প্রতিশোধ নিবো।"],
  "44:17": ["We have tested before them the people of Pharaoh; an honorable messenger went to them.","আমরা তাদের পূর্বে পরীক্ষা করেছি ফেরাউনের লোকদের; একজন সম্মানিত বার্তাবাহক তাদের কাছে গিয়েছিল।"],
  "44:18": ["Proclaiming: \"Listen to me, servants of Allah. I am an honest messenger to you.\"","ঘোষনা করে যে: \"আল্লাহর বান্দারা, আমার কথা শোনো। আমি তোমাদের প্রতি একজন বিশ্বস্ত বার্তাবাহক।"],
  "44:19": ["And, \"Do not transgress against Allah. I bring to you powerful proofs.","এবং, \"আল্লাহর বিরুদ্ধে সীমালঙ্ঘন করো না। আমি তোমাদের কাছে নিয়ে আসি শক্তিশালী প্রমাণসমূহ।"],
  "44:20": ["\"I seek refuge in my Lord and your Lord, if you oppose me.","\"আমি আশ্রয় প্রার্থনা করি আমার প্রভু এবং তোমাদের প্রভুর কাছে, যদি তোমরা আমার বিরোধিতা করো।"],
  "44:21": ["\"If you do not wish to believe, then simply leave me alone.\"","\"যদি তোমরা বিশ্বাস করতে না চাও, তাহলে আমাকে শুধু আমার মতো থাকতে দাও।\""],
  "44:22": ["Subsequently, he implored his Lord: \"These are wicked people.\"","পরবর্তীতে, সে তার প্রভুর কাছে মিনতি করেছিল: \"এরা অন্যায়কারী লোক'"],
  "44:23": ["(Allah said,) \"Travel with My servants during the night; you will be pursued.","(আল্লাহ বললেন, ) \" আমার বান্দাদের নিয়ে রাতে ভ্রমন করো; তোমাদেরকে ধাওয়া করা হবে।"],
  "44:24": ["\"Cross the sea quickly; their troops will be drowned.\"","\"দ্রুত সাগর পার হও; তাদের সৈন্যরা ডুবে যাবে।\""],
  "44:25": ["Thus, they left behind many gardens and springs.","এভাবে, তারা ফেলে এসেছিল অনেক বাগান এবং ঝর্ণা।"],
  "44:26": ["Crops and a luxurious life.","শস্যসমূহ এবং একটি বিলাসবহুল জীবন।"],
  "44:27": ["Blessings that they enjoyed.","অনুগ্রহসমূহ যা তারা উপভোগ করেছিল।"],
  "44:28": ["All these we caused to be inherited by other people.","এই সবকিছু আমরা অন্য লোকদের দ্বারা উত্তরাধিকার করতে দিয়েছিলাম।"],
  "44:29": ["Neither the heaven, nor the earth wept over them, and they were not respited.","না আকাশমণ্ডলী, না পৃথিবী তাদের জন্য কেঁদেছিল, এবং তাদেরকে অবকাশ দেয়া হয়নি।"],
  "44:30": ["Meanwhile, we saved the Children of Israel from the humiliating persecution.","ইতোমধ্যে, আমরা ইসরাইলের সন্তানদের অপমানজনক অত্যাচার থেকে রক্ষা করেছিলাম।"],
  "44:31": ["From Pharaoh; he was a tyrant.","ফেরাউনের কাছ থেকে; সে ছিল একজন স্বৈরশাসক।"],
  "44:32": ["We have chosen them from among all the people, knowingly.","আমরা তাদেরকে সকল লোকদের থেকে পছন্দ করেছিলাম, জ্ঞাতসারে।"],
  "44:33": ["We showed them so many proofs, which constituted a great test.","আমরা তাদেরকে এতোগুলো প্রমান দেখিয়েছিলাম, যা স্থাপন করেছিল এক মহা-পরীক্ষা।"],
  "44:34": ["The present generations say,","বর্তমান প্রজন্মগুলো বলে,"],
  "44:35": ["\"We only die the first death; we will never be resurrected!","\"আমরা প্রথম মৃত্যুতেই শুধু মারা যাই; আমরা কখনোই পুনরুত্থিত হবো না!"],
  "44:36": ["\"Bring back our forefathers, if you are truthful.\"","\"আমাদের পূর্বপুরুষদের ফিরিয়ে আনো, যদি তোমরা সত্যবাদী হও।\""],
  "44:37": ["Are they better than the people of Tubba' and others before them? We annihilated them for their crimes.","তারা কি তুব্বার লোকদের চেয়ে এবং তাদের পূর্বের অন্যদের চেয়ে উত্তম? আমরা তাদের অপরাধের জন্য তাদেরকে নিশ্চিহ্ন করেছিলাম"],
  "44:38": ["We did not create the heavens and the earth, and everything between them, just to play.","আমরা সৃষ্টি করিনি আকাশমণ্ডলী এবং পৃথিবী, এবং এদের মধ্যকার সবকিছু, কেবল খেল-তামাশা করতে।"],
  "44:39": ["We created them for a specific purpose, but most of them do not know.","আমরা তাদেরকে একটি নির্দিষ্ট উদ্দেশ্যে সৃষ্টি করেছি, কিন্তু তাদের অধিকাংশ জানে না।"],
  "44:40": ["The Day of Decision awaits them all.","সিদ্ধান্তের দিনটি তাদের জন্য অপেক্ষা করছে।"],
  "44:41": ["That is the day when no friend can help his friend in any way; no one can be helped.","এটা সে দিন যখন কোন বন্ধু তার বন্ধুকে কোনভাবে সাহায্য করতে পারবে না; না কেউ সাহায্য পাবে।"],
  "44:42": ["Only those who attain mercy from Allah. He is the Almighty, Most Merciful.","কেবলমাত্র তারা যারা আল্লাহ থেকে দয়া অর্জন করে। তিনি সর্বশক্তিমান, সবচেয়ে দয়ালু।"],
  "44:43": ["Surely, the tree of bitterness—","নিশ্চয়, তিক্ততার গাছ-"],
  "44:44": ["will provide the food for the sinful.","পাপীদের জন্য খাদ্য সরবরাহ করবে।"],
  "44:45": ["Like lye, it will boil in the stomachs.","ক্ষারের মতো, এটি পাকস্থলীতে ফুটবে।"],
  "44:46": ["Like the boiling of hellish drinks.","নারকীয় পানীয়ের ফুটন্ত জলের মতো।"],
  "44:47": ["Take him and throw him into the center of Hell.","তাকে ধরো এবং নরকের কেন্দ্রে নিক্ষেপ করো।"],
  "44:48": ["Then pour upon his head the retribution of the Inferno.","তারপর তার মাথার উপর নরকের শাস্তি ঢালো।"],
  "44:49": ["\"Taste this; you were so powerful, so honorable.\"","\"এর স্বাদ নাও; তুমি তো ছিলে বেশ ক্ষমতাধর, বেশ সম্মানিত।\""],
  "44:50": ["This is what you used to doubt.","এটা তা-ই, যাতে তোমরা সন্দেহ করতে।"],
  "44:51": ["The righteous will be in a secure position.","সৎকর্মশীলরা থাকবে একটি নিরাপদ অবস্থানে।"],
  "44:52": ["Enjoying gardens and springs.","বাগান এবং ঝর্ণাসমূহ উপভোগরত।"],
  "44:53": ["Wearing velvet and satin; close to each other.","মখমল এবং রেশমী বস্ত্র পরিধানরত; একে অন্যের কাছাকাছি।"],
  "44:54": ["We grant them wonderful spouses.","আমরা তাদেরকে চমৎকার জীবন-সঙ্গী প্রদান করলাম।"],
  "44:55": ["They enjoy in it all kinds of fruits, in perfect peace.","তারা সেখানে সকল প্রকারের ফল উপভোগ করে, পরিপূর্ণ শান্তিতে।"],
  "44:56": ["They do not taste death therein— beyond the first death—and He has spared them the retribution of Hell.","তারা সেখানে মৃত্যুর স্বাদ গ্রহন করে না- প্রথম মৃত্যুর পর- এবং তিনি তাদেরকে নরকের শাস্তি থেকে নিষ্কৃতি দিয়েছেন।"],
  "44:57": ["Such is the blessing from your Lord. Such is the great triumph.","এমনই তোমার প্রভুর পক্ষ থেকে অনুগ্রহ। এমনই হলো মহা বিজয়।"],
  "44:58": ["We have thus clarified it in your language, that they may take heed.","আমরা এভাবে এটিকে তোমার ভাষায় স্পষ্ট করেছি, যাতে তারা মনোযোগ দিতে পারে।"],
  "44:59": ["Therefore, wait; they too will have to wait.","অতএব, অপেক্ষা করো; তাদেরকেও অপেক্ষা করতে হবে।"],
  "45:1": ["H. M.","হ. ম. (হা মীম)"],
  "45:2": ["The revelation of this scripture is from Allah, the Almighty, Most Wise.","এই ঐশীগ্রন্থের প্রকাশনা আল্লাহ থেকে, সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "45:3": ["The heavens and the earth are full of proofs for the believers.","বিশ্বাসীদের জন্য আকাশমণ্ডলী এবং পৃথিবী প্রমানাদিতে পূর্ণ।"],
  "45:4": ["Also in your creation, and the creation of all the animals, there are proofs for people who are certain.","তোমাদের সৃষ্টিতে, এবং সকল প্রানীদের সৃষ্টিতেও, লোকদের জন্য প্রমাণ রয়েছে যারা নিশ্চিত।"],
  "45:5": ["Also, the alternation of the night and the day, and the provisions that Allah sends down from the sky to revive dead lands, and the manipulation of the winds; all these are proofs for people who understand.","এছাড়া, রাত এবং দিনের পরিবর্তনে, এবং জীবিকাসমূহ যা আল্লাহ আকাশ থেকে অবতীর্ণ করেন মৃত ভূমিকে পুনর্জীবিত করতে, এবং বায়ূপ্রবাহ নিয়ন্ত্রনে; এই সবকিছু লোকদের জন্য প্রমান যারা বোঝে।"],
  "45:6": ["These are Allah's revelations that we recite to you truthfully. In which Hadith other than Allah and His revelations do they believe?","এগুলো আল্লাহর প্রকাশনাবলি যা আমরা তোমার কাছে সত্য সহকারে আবৃতি করি। আল্লাহ এবং তাঁর প্রকাশনাবলি ব্যতীত অন্য কোন হাদীসে তারা বিশ্বাস করে?"],
  "45:7": ["Woe to every fabricator, guilty.","দূর্ভোগ প্রত্যেক মিথ্যা উদ্ভাবক, অপরাধীর প্রতি।"],
  "45:8": ["The one who hears Allah's revelations recited to him, then insists arrogantly on his way, as if he never heard them. Promise him a painful retribution.","যে ব্যক্তি তার কাছে আবৃতি করা আল্লাহর প্রকাশনাবলি শুনে, এরপর ঔদ্ধতের সাথে তার পথের উপরেই জোর দেয়, যেন সে কখনো সেগুলো শুনেনি। তাকে এক যন্ত্রণাকর শাস্তির প্রতিশ্রুতি দাও।"],
  "45:9": ["When he learns anything about our revelations, he mocks them. These have incurred a shameful retribution.","যখন সে আমাদের প্রকাশনাবলি সম্পর্কে কোনকিছু শিখে, সে সেগুলোকে উপহাস করে। এরা টেনে এনেছে এক লজ্জাকর শাস্তি।"],
  "45:10": ["Awaiting them is Gehenna. Their earnings will not help them, nor the idols they had set up beside Allah. They have incurred a terrible retribution.","তাদের জন্য অপেক্ষায় আছে জাহান্নাম। তাদের উপার্জন তাদেরকে সাহায্য করবে না, না করবে আল্লাহর পাশে তাদের স্থাপিত প্রতিমা। তারা টেনে এনেছে এক ভয়ানক শাস্তি।"],
  "45:11": ["This is a beacon, and those who disbelieve in these revelations of their Lord have incurred condemnation and a painful retribution.","এটি একটি আলোকবর্তিকা, এবং যারা তাদের প্রভুর এই প্রকাশনাবলিতে অবিশ্বাস করে তারা টেনে এনেছে নিন্দা এবং একটি যন্ত্রণাদায়ক শাস্তি।"],
  "45:12": ["Allah is the One who committed the sea in your service, so that the ships can roam it in accordance with His laws. You thus seek His provisions, that you may be appreciative.","আল্লাহ সে সত্ত্বা যিনি সাগরকে তোমাদের সেবায় নিয়োজিত করেছেন, যাতে করে জাহাজগুলো এতে ঘুড়ে-বেড়াতে পারে তাঁর আইনানুসারে। তোমরা এভাবে তাঁর জীবিকা খোঁজ, যাতে তোমরা কৃতজ্ঞ হও।"],
  "45:13": ["He committed in your service everything in the heavens and the earth; all from Him. These are proofs for people who reflect.","তিনি তোমাদের সেবায় আকাশমন্ডলী এবং পৃথিবীর সবকিছুকে নিয়োজিত করেছেন; সবকিছু তাঁর পক্ষ থেকে। এগুলো সে লোকদের জন্য প্রমান যারা অনুধাবন করে।"],
  "45:14": ["Tell those who believed to forgive those who do not expect the days of Allah. He will fully pay everyone for whatever they have earned.","যারা বিশ্বাস করেছে তাদের বলো ক্ষমা করতে তাদেরকে যারা আল্লাহর দিনগুলোর প্রত্যাশা করে না। সবাইকে তিনি সম্পূর্ণ মূল্য দিবেন, যা কিছুই তারা অর্জন করেছে।"],
  "45:15": ["Whoever works righteousness does so for his own good, and whoever works evil does so to his own detriment. To your Lord you will be returned.","যেকেউ সৎকর্ম করে তার নিজের ভালোর জন্যই তা করে, এবং যেকেউ মন্দকর্ম করে তার নিজের ক্ষতির জন্যই তা করে। তোমাদের প্রভুর কাছে তোমরা ফিরে যাবে।"],
  "45:16": ["We have given the Children of Israel the scripture, wisdom, and prophethood, and provided them with good provisions; we bestowed upon them more blessings than any other people.","আমরা ইসরাইলের সন্তানদেরকে ঐশীগ্রন্থ, প্রজ্ঞা এবং নবীত্ব দিয়েছিলাম, এবং তাদেরকে ভাল জীবিকা দিয়েছিলাম; অন্য লোকদের চেয়ে তাদের উপর আমরা অধিক অনুগ্রহ অর্পণ করেছিলাম।"],
  "45:17": ["We have given them herein clear commandments. Ironically, they did not dispute this until the knowledge had come to them. This is due to jealousy on their part. Surely, your Lord will judge them on the Day of Resurrection regarding everything they have disputed.","আমরা এখানে তাদেরকে সুস্পষ্ট প্রত্যাদেশ দিয়েছি। দূ:খজনকভাবে, তাদের কাছে জ্ঞান আসার পূর্ব পর্যন্ত তারা এই নিয়ে বিবাদ করেনি।  এটা তাদের পক্ষ থেকে হিংসার ফল। নিশ্চয়, তোমার প্রভু পুনরুত্থান দিবসে তাদের বিচার করবেন সবকিছুর বিষয়ে যাতে তারা বিবাদ করেছে।"],
  "45:18": ["We then appointed you to establish the correct laws; you shall follow this, and do not follow the wishes of those who do not know.","আমরা এরপর তোমাকে সঠিক আইনগুলো প্রতিষ্ঠা করতে মনোনীত করেছিলাম; তুমি এর অনুসরণ করো, এবং তাদের ইচ্ছার অনুসরণ করো না যারা জানে না।"],
  "45:19": ["They cannot help you at all against Allah. It is the transgressors who ally themselves with one another, while Allah is the Lord of the righteous.","আল্লাহর বিরুদ্ধে তারা তোমাকে সামান্যতম সাহায্য করতে পারে না। সীমালঙ্ঘনকারীরাই নিজেদের মধ্যে একে অন্যের সাথে মিত্রতা করে, যখন আল্লাহ সৎকর্মশীলদের প্রভু।"],
  "45:20": ["This provides enlightenments for the people, and guidance, and mercy for those who are certain.","এটা লোকদের জন্য প্রদান করে জ্ঞানালোক, এবং পথনির্দেশনা, এবং দয়া তাদের জন্য যারা নিশ্চিত।"],
  "45:21": ["Do those who work evil expect that we will treat them in the same manner as those who believe and lead a righteous life? Can their life and their death be the same? Wrong indeed is their judgment.","যারা মন্দ কাজ করে তারা কি আশা করে যে আমরা তাদের সাথে একইরকম আচরণ করবো যেমন করি তাদের সাথে যারা বিশ্বাস করে এবং সৎকর্মশীল জীবন-যাপন করে? তাদের জীবন এবং তাদের মৃত্যু কি একই রকম? নিশ্চয়, তাদের বিচার ভুল।"],
  "45:22": ["Allah created the heavens and the earth for a specific purpose, in order to pay each soul for whatever it earned, without the least injustice.","আল্লাহ আকাশমণ্ডলী এবং পৃথিবীকে সৃষ্টি করেছেন একটি নির্দিষ্ট উদ্দেশ্যে, প্রত্যেক আত্মাকে তার জন্য মূল্য দিতে যাকিছুই এটি অর্জন করেছে, সামান্যতম অবিচার ছাড়া।"],
  "45:23": ["Have you noted the one whose god is his ego? Consequently, Allah sends him astray, despite his knowledge, seals his hearing and his mind, and places a veil on his eyes. Who then can guide him, after such a decision by Allah? Would you not take heed?","তুমি কি সে ব্যক্তিকে লক্ষ্য করেছো যার দেবতা তার অহংকার? পরিনামে, আল্লাহ তাকে পথভ্রষ্ট করেন, তার জ্ঞান থাকা সত্ত্বেও, তার শ্রবণশক্তি এবং তার মনে মোহর মেরে দেন, এবং তার চোখে পর্দা দিয়ে দেন। আল্লাহর এমন সিদ্ধান্তের পর, কে তখন তাকে পথ দেখাতে পারে? তোমরা কি সতর্ক হবে না?"],
  "45:24": ["They said, \"We only live this life; we live and die and only time causes our death!\" They have no sure knowledge about this; they only conjecture.","তারা বলেছিল, \"আমরা শুধুমাত্র এই জীবনে বেচেঁ থাকি; আমরা বেচেঁ থাকি এবং মারা যাই এবং সময়ই কেবল আমাদের মৃত্যু ঘটায়!\" এ সম্পর্কে তাদের কোন নিশ্চিত জ্ঞান নেই; তারা শুধু অনুমান করে।"],
  "45:25": ["When our revelations are recited to them, clearly, their only argument is to say, \"Bring back our forefathers, if you are truthful.\"","যখন তাদের কাছে আমাদের প্রকাশনাবলি আবৃতি করা হয়, স্পষ্টভাবে, তারা শুধু এই তর্ক করে যে, \"আমাদের পূর্বপুরুষদের ফিরিয়ে আনো, যদি তুমি সত্যবাদী হও।\""],
  "45:26": ["Say, \"Allah has granted you life, then He puts you to death, then He will summon you to the Day of Resurrection, which is inevitable. But most people do not know.\"","বল, \"আল্লাহ তোমাদেরকে জীবন দান করেছেন, এরপর তিনি তোমাদেরকে মৃত করেন, এরপর তিনি পুনরুত্থান দিবসে তোমাদের তলব করবেন, যা অনিবার্য। কিন্তু অধিকাংশ লোক জানে না।"],
  "45:27": ["To Allah belongs all sovereignty of the heavens and the earth. The day the Hour (Judgment) comes to pass, that is when the falsifiers lose.","আকাশমন্ডলী এবং পৃথিবীর সকল সার্বভৌমত্ব আল্লাহর অধীনে। সেদিন যখন সে সময় (বিচার) সংঘটিত হয়, সেদিনই মিথ্যাবাদীরা হেরে যায়।"],
  "45:28": ["You will see every community kneeling. Every community will be called to view their record. Today, you get paid for everything you have done.","তুমি প্রত্যেক সম্প্রদায়কে নতজানু হতে দেখবে । প্রত্যেক সম্প্রদায়কে তাদের নথি দেখতে ডাকা হবে। আজকে তোমরা সবকিছুর জন্য মূল্য পাও যা তোমরা করেছ।"],
  "45:29": ["This is our record; it utters the truth about you. We have been recording everything you did.","এটা আমাদের রেকর্ড; এটা তোমাদের সম্পর্কে সত্য বলে। আমরা রেকর্ড করে আসছি সবকিছু যা তোমরা করেছো।"],
  "45:30": ["As for those who believe and work righteousness, their Lord will admit them into His mercy. This is the great triumph.","আর যারা বিশ্বাস করে এবং সৎকর্ম করে, তাদের প্রভু তাদেরকে তাঁর দয়ায় প্রবেশ করাবেন। এটা মহাবিজয়।"],
  "45:31": ["As for those who disbelieve: \"Were not My revelations recited to you, but you turned arrogant and were wicked people?\"","আর যারা অবিশ্বাস করে: \"আমার প্রকাশনাবলি কি তাদের কাছে আবৃতি করা হয়নি, কিন্তু তোমরা উদ্ধত হয়ে পড়েছিলে এবং অন্যায়কারী মানুষ ছিলে?"],
  "45:32": ["When it is proclaimed that Allah's promise is the truth and that the Hour (of Judgment) is inevitable, you said, \"We do not know what the Hour is! We are full of conjecture about it; we are not certain.\"","যখন এটা ঘোষনা করা হয় যে আল্লাহর প্রতিশ্রুতি সত্য এবং (বিচারের) সে সময় অনিবার্য, তোমরা বলেছিলে, \"আমরা জানি না কি সে সময়! আমরা এটা সম্পর্কে পুরোপুরি অনুমানে আছি; আমরা  নিশ্চিত নই।\""],
  "45:33": ["The evils of their works will become evident to them, and the very things they mocked will come back and haunt them.","তাদের কাজের মন্দগুলো তাদের কাছে সহজবোধ্য হয়ে উঠবে, এবং ঠিক যে বিষয়গুলো নিয়ে তারা তামাশা করেছিল সেগুলো ফিরে আসবে এবং তাদেরকে তাড়া করবে।"],
  "45:34": ["It will be proclaimed: \"Today we forget you, just as you forgot the meeting of this day. Your abode is the hellfire, and you will have no helpers.","এটা ঘোষনা করা হবে: \"আজ আমরা তোমাদের ভুলে গিয়েছি, ঠিক যেমন তোমরা এই দিনের সাক্ষাতকে ভুলে গিয়েছিলে। তোমাদের আবাস নরকাগ্নিতে, এবং তোমাদের কোন সাহায্যকারী থাকবে না।"],
  "45:35": ["\"This is because you took Allah's revelations in vain, and were preoccupied with the first life.\" Consequently, they will never exit therefrom, nor will they be excused.","এর কারণ তোমরা আল্লাহর প্রকাশনাবলি নিরর্থকভাবে নিয়েছিলে এবং প্রথম জীবন নিয়ে ব্যস্ত ছিলে। পরিনামে, তারা সেখান থেকে কখনো বের হতে পারবে না, না তাদেরকে ক্ষমা করা হবে।"],
  "45:36": ["To Allah belongs all praise; Lord of the heavens, Lord of the earth, Lord of the universe.","সকল প্রশংসা আল্লাহর অধীনে; আকাশমন্ডলীর প্রভু, পৃথিবীর প্রভু, মহাবিশ্বের প্রভু।"],
  "45:37": ["To Him belongs all supremacy in the heavens and the earth. He is the Almighty, Most Wise.","তাঁর অধীনেই আকাশমন্ডলী এবং পৃথিবীর সকল আধিপত্য। তিনি সর্বশক্তিমান, পরম দয়ালু।"],
  "46:1": ["H. M.","হ. ম. (হা মীম)"],
  "46:2": ["The revelation of this scripture is from Allah, the Almighty, Most Wise.","এই ঐশিগ্রন্থের অবতরণ সর্বশক্তিমান, সবচেয়ে জ্ঞানী ঈশ্বরের পক্ষ থেকে।"],
  "46:3": ["We did not create the heavens and the earth, and everything between them except for a specific purpose, and for a finite interim. Those who disbelieve are totally oblivious to the warnings given to them.","আমরা আকাশমণ্ডলী এবং পৃথিবী, এবং এদের মধ্যকার সবকিছু সৃষ্টি করিনি, একটি সুনির্দিষ্ট উদ্দেশ্য, এবং একটি সসীম সময়ের জন্য ছাড়া।"],
  "46:4": ["Say, \"Consider the idols you have set up beside Allah. Show me what on earth did they create. Do they own part of the heavens? Show me any other scripture before this one, or any piece of established knowledge that supports your idolatry, if you are truthful.\"","বল, \"ঈশ্বরের পাশে তোমরা যে উপাস্যদের স্থাপন করেছ তাদের বিষয়ে ভেবে দেখো। তারা পৃথিবীতে কী সৃষ্টি করেছিল আমাকে দেখাও। স্বর্গের কোন অংশের মালিকানা কি তাদের আছে? এই গ্রন্থের পূর্ববর্তী অন্যকোন ঐশিগ্রন্থ, অথবা প্রতিষ্ঠিত জ্ঞানের কোন অংশ আমাকে দেখাও যা তোমাদের শিরককে সমর্থন করে, যদি তোমরা সত্যবাদী হও।\""],
  "46:5": ["Who is farther astray than those who idolize beside Allah idols that can never respond to them until the Day of Resurrection, and are totally unaware of their worship?","তাদের চেয়ে কে অধিকতর পথভ্রষ্ট যারা ঈশ্বরের পাশে অংশীদার স্থাপন করে উপাস্যদের যা তাদের প্রতি কখনো সাড়া দিতে পারে না যতক্ষণ না বিচারের দিন আসে, এবং তাদের উপাসনা সম্পর্কে সম্পূর্ণ অসচেতন?"],
  "46:6": ["And when the people are summoned (on the Day of Judgment), their idols will become their enemies, and will denounce their idolatry.","এবং যখন মানুষকে তলব করা হয় (বিচার দিবসে),তাদের উপাস্যরা তাদের শত্রু হয়ে পড়বে, এবং তাদের অংশীদারবাদকে প্রত্যাখ্যান করবে।"],
  "46:7": ["When our revelations were recited to them, perfectly clear, those who disbelieved said of the truth that came to them, \"This is obviously magic!\"","যখন আমাদের প্রকাশনাবলী তাদের কাছে আবৃতি করা হয়েছিল, যথেষ্ট পরিষ্কারভাবে, যারা অবিশ্বাস করেছিল তারা তাদের কাছে আসা সত্য সম্পর্কে বলেছিল, \"এটা স্পষ্টত জাদু!\""],
  "46:8": ["When they say, \"He fabricated this,\" say, \"If I fabricated this, then you cannot protect me from Allah. He is fully aware of everything you scheme. He suffices as a witness between me and you. He is the Forgiver, Most Merciful.\"","যখন তারা বলে,\"সে এটি বানিয়েছে,\" বল, \"যদি আমি এটি বানাতাম, তাহলে তুমি আমাকে ঈশ্বরের কাছ থেকে রক্ষা করতে পারতে না। তিনি তোমাদের পরিকল্পনার সবকিছু সম্পর্কে সম্পূর্ণ সচেতন। আমার এবং তোমাদের মধ্যে সাক্ষী হিসেবে তিনি যথেষ্ট। তিনি ক্ষমাকারী, সবচেয়ে দয়ালু।\""],
  "46:9": ["Say, \"I am not different from other messengers. I have no idea what will happen to me or to you. I only follow what is revealed to me. I am no more than a profound warner.\"","বল, \"আমি অন্য বার্তাবাহকদের থেকে আলাদা নই। আমার কোন ধারণা নেই আমার অথবা তোমাদের সাথে কি ঘটবে। আমি কেবল অনুসরণ করি যা আমার কাছে প্রকাশ হয়। আমি একজন স্পষ্ট সতর্ককারীর চেয়ে বেশি কিছু নই।\""],
  "46:10": ["Say, \"What if it is from Allah and you disbelieved in it? A witness from the Children of Israel has borne witness to a similar phenomenon, and he has believed, while you have turned arrogant. Surely, Allah does not guide the wicked people.\"","বল, \"যদি এটি ঈশ্বরের পক্ষ থেকে হয় আর তোমরা একে অবিশ্বাস করেছো? ইসরাইলের সন্তানদের মধ্য থেকে একজন সাক্ষী একই রকম একটি ঘটনার সাক্ষ্য বহন করেছে, এবং সে বিশ্বাস করেছে, যখন তোমরা উদ্ধত হয়ে পড়েছো। নিশ্চয়, ঈশ্বর অন্যায়কারী লোকদের পথ দেখান না।\""],
  "46:11": ["Those who disbelieved said about those who believed, \"If it were anything good, they would not have accepted it before us.\" Because they were not guided to it, they said, \"This is an old fabrication!\"","যারা অবিশ্বাস করেছিল তারা তাদের সম্পর্কে বলেছিল যারা বিশ্বাস করেছিল, \"যদি এটি ভাল কিছু হতো, তারা এটি আমাদের আগে গ্রহন করতো না।\" যেহেতু তারা এর দিকে পথ-নির্দেশিত ছিল না, তারা বলেছিল, \"এটি একটি পুরাতন মিথ্যা-উদ্ভাবন!\""],
  "46:12": ["Before this, the book of Moses provided guidance and mercy. This too is a scripture that confirms, in Arabic, to warn those who transgressed, and to give good news to the righteous.","এর আগে, মূসার গ্রন্থ পথ-নির্দেশনা এবং দয়া   প্রদান করেছিল। এটিও একটি ঐশীগ্রন্থ যা নিশ্চিত করে, আরবিতে, তাদেরকে সতর্ক করতে যারা সীমালঙ্ঘন করেছিল, এবং সৎকর্মশীলদের সুসংবাদ দিতে।"],
  "46:13": ["Surely, those who say, \"Our Lord is Allah,\" then lead a righteous life, will have no fear, nor will they grieve.","নিশ্চয়, যারা বলে, \"আমাদের প্রভু ঈশ্বর, \" এরপর সৎ জীবন-যাপন করে, তাদের কোন ভয় থাকবে না, না তারা শোক করবে।"],
  "46:14": ["They have deserved Paradise, where they abide forever; a reward for their works.","তারা উপযুক্ত হয়েছে স্বর্গের, যেখানে তারা চিরকাল বাস করে; তাদের কাজের জন্য একটি পুরষ্কার।"],
  "46:15": ["We enjoined the human being to honor his parents. His mother bore him arduously, gave birth to him arduously, and took intimate care of him for thirty months. When he reaches maturity, and reaches the age of forty, he should say, \"My Lord, direct me to appreciate the blessings You have bestowed upon me and upon my parents, and to do the righteous works that please You. Let my children be righteous as well. I have repented to You; I am a submitter.\"","আমরা মানুষকে তার মাতা-পিতার প্রতি সম্মান করতে আদেশ করেছি। কষ্ট করে তার মা তাকে গর্ভধারণ করেছে, কষ্ট করে তাকে জন্ম দিয়েছে, এবং ত্রিশ মাস কাছ থেকে তার যত্ন নিয়েছে। যখন সে পৌঁছে পূর্ণ-বয়সে, এবং পৌঁছে ৪০ বছরে, তার বলা উচিত, “আমার প্রভু, আমাকে চালনা করুন সে অনুগ্রহের মূল্য উপলব্ধিতে যা আপনি আমার উপর এবং আমার মাতা-পিতার উপর অর্পণ করেছেন, এবং সৎকর্মে যা আপনাকে সন্তুষ্ট করে। আমার সন্তানদেরও সৎকর্মশীল হতে দিন। আমি আপনার কাছে অনুশোচনা করেছি; আমি একজন আত্মসমর্পণকারী।"],
  "46:16": ["It is from these that we accept the righteous works, and overlook their sins. They have deserved Paradise. This is the truthful promise that is promised to them.","তাদের থেকে আমরা সৎকর্ম গ্রহণ করি, আর পাপগুলো এড়িয়ে যাই। তারা স্বর্গের উপযুক্ত। এটা সে সত্য প্রতিশ্রুতি, যে প্রতিশ্রুতি তাদেরকে দেয়া হয়।"],
  "46:17": ["Then there is the one who says to his parents, \"Woe to you; are you telling me that (after death) I will come back to life? How come those who died before us never come back?\" The parents would cry for Allah's help and say, \"Woe to you; please believe! Allah's promise is the truth.\" He would say, \"Tales from the past!\"","এরপর রয়েছে সে ব্যক্তি যে তার মাতা-পিতাকে বলে, \"দূর্ভোগ তোমাদের প্রতি; তোমরা কি আমাকে বলছো যে (মৃত্যুর পর) আমি আবার জীবিত হবো? কেমন করে যারা আমাদের পূর্বে মারা গিয়েছে তারা কখনো ফিরে আসে না? মাতা-পিতারা ঈশ্বরের সাহায্যের জন্য কান্না করে এবং বলে, \"দূর্ভোগ তোমার প্রতি; দয়া করে বিশ্বাস করো! ঈশ্বরের প্রতিশ্রুতি সত্য।\" সে বলে, \"অতীতের কল্প-কাহিনী!\""],
  "46:18": ["Such are the ones stamped as disbelievers among every generation of jinns and humans; they are losers.","এমনই হলো সে ব্যক্তিরা যারা প্রত্যেক জীন ও মানুষ প্রজন্মের মধ্যে অবিশ্বাসী হিসেবে চিহ্নিত; তারা ক্ষতিগ্রস্থ।"],
  "46:19": ["They all attain the ranks they have deserved, in accordance with their works. He will pay them for their works, without the least injustice.","তারা সবাই তাদের প্রাপ্য পদমর্যাদা অর্জন করে, তাদের কর্ম অনুযায়ী। তাদের কাজের জন্য তাদেরকে তিনি মূল্য পরিশোধ করবেন, সামান্যতম অবিচার ছাড়া।"],
  "46:20": ["The day will come when those who disbelieved will be introduced to the hellfire: \"You have wasted the good chances given to you during your worldly life, and you rejoiced in them. Consequently, today you incur a shameful retribution as a requital for the arrogance you committed on earth without any basis, and for your evil works.\"","সেদিন আসবে যখন যারা অবিশ্বাস করেছিল তাদের কাছে নরকাগ্নি উপস্থাপন করা হবেঃ \"তোমরা তোমাদের পার্থিব জীবনে তোমাদেরকে দেয়া ভাল সুযোগগুলো নষ্ট করেছো, এবং তোমরা সেগুলো নিয়ে আনন্দিত ছিলে। পরিনামে, আজ তোমরা লজ্জাজনক শাস্তি লাভ করেছো পৃথিবীতে, কোন ভিত্তি ছাড়া তোমাদের সম্পাদিত ঔদ্ধত্যের একটি প্রতিফল হিসেবে, এবং তোমাদের মন্দ কাজগুলোর জন্য।\""],
  "46:21": ["Recall that the brother of 'Ãd warned his people at the dunes—numerous warnings were also delivered before him and after him: \"You shall not worship except Allah. I fear for you the retribution of a great day.\"","স্মরণ করো যে বালিয়াড়িতে আ'দের ভাই তার লোকদের সতর্ক করেছিল, তার আগে এবং তার পরেও অসংখ্য সতর্কবার্তা প্রদান করা হয়েছিল: \"তোমরা ঈশ্বর ব্যতীত কারো উপাসনা করবে না। আমি তোমাদের জন্য এক গুরুত্বপূর্ণ দিনের শাস্তির ভয় করি।\""],
  "46:22": ["They said, \"Did you come to divert us from our gods? We challenge you to bring (the retribution) you threaten, if you are truthful.\"","তারা বলেছিল, \"তুমি কি এসেছো আমাদেরকে আমাদের উপাস্যদের থেকে দূরে সরিয়ে দিতে? তুমি যার হুমকি দাও (সে শাস্তি) আনার জন্য আমরা তোমাকে চ্যালেঞ্জ করি, যদি তুমি সত্যবাদী হও।"],
  "46:23": ["He said, \"The knowledge about this is with Allah; I only deliver to you what I was sent to deliver. However, I see that you people are ignorant.\"","সে বলেছিল, \"এ বিষয়ে জ্ঞান রয়েছে ঈশ্বরের কাছে; আমি তোমাদের কাছে শুধু তা-ই পৌঁছে দেই যা পৌঁছানোর জন্য আমাকে পাঠানো হয়েছে। তবে, আমি দেখি যে তোমরা অজ্ঞ লোক।\""],
  "46:24": ["When they saw the storm heading their way, they said, \"This storm will bring to us much needed rain.\" Instead, this is what you challenged (Hûd) to bring; violent wind wherein there is painful retribution.","যখন তারা দেখলো ঝড় তাদের দিকে আসছে, তারা বলল, \"এই ঝড় আমাদের জন্য অতি প্রয়োজনীয় বৃষ্টি নিয়ে আসবে।\" বরং, এটা তা-ই যা আনতে তোমরা (হূদকে) চ্যালেঞ্জ করেছিলে; প্রচন্ড বাতাস যেখানে আছে যন্ত্রনাদায়ক শাস্তি।"],
  "46:25": ["It destroyed everything, as commanded by its Lord. By morning, nothing was standing except their homes. We thus requite the guilty people.","এটি সবকিছু ধ্বংস করেছিল, যেভাবে এর প্রভু নির্দেশ করেছিলেন। সকালের মধ্যে, তাদের বাড়িগুলো ছাড়া কিছুই দাড়িয়ে ছিল না। আমরা এভাবে অপরাধী লোকদের প্রতিফল দেই।"],
  "46:26": ["We had established them in the same way as we established you, and provided them with hearing, eyes, and minds. But their hearing, eyes, and minds did not help them at all. This is because they decided to disregard Allah's revelations. Thus, the prophecies and warnings that they ridiculed have caused their doom.","আমরা তাদেরকে একইভাবে প্রতিষ্ঠা করেছিলাম ঠিক যেমন তোমাদেরকে প্রতিষ্ঠা করেছিলাম,  এবং প্রদান করেছিলাম শ্রবণশক্তি, চোখ ও মন। কিন্তু তাদের শ্রবণশক্তি, চোখ এবং মন তাদেরকে সামান্যতম সাহায্য করেনি। এটা এ কারনে যে তারা ঈশ্বরের প্রকাশনাবলি উপেক্ষা করার  সিদ্ধান্ত নিয়েছিল।  তাই,  যেসব ভবিষ্যদ্বাণী ও সতর্কবার্তা নিয়ে তারা উপহাস করেছিল সেগুলোই তাদের ধ্বংসের কারণ হয়েছিল।"],
  "46:27": ["We have annihilated many communities around you, after we had explained the proofs, that they might repent.","আমরা তোমাদের চারপাশের অনেক সম্প্রদায়কে  নিশ্চিহ্ন করেছি, আমরা প্রমানগুলোর ব্যাখ্যা দেয়ার পর, যাতে তারা অনুশোচনা করে।"],
  "46:28": ["Why then did the idols they set up to bring them closer to Allah fail to help them? Instead, they abandoned them. Such were the false gods they idolized; such were the innovations they fabricated.","কেন তাহলে সে উপাস্যরা তাদেরকে সাহায্য করতে ব্যর্থ হয় যাদেরকে তারা ঈশ্বরের নিকটবর্তী হওয়ার জন্য স্থাপন করে? তারাই উল্টো তাদেরকে পরিত্যাগ করেছে। এমনই ছিল মিথ্যা উপাস্যরা, তারা যাদের উপাসনা করেছিল; তাদের উদ্ভাবিত উদ্ভাবনগুলি ছিল এরকম।"],
  "46:29": ["Recall that we directed a number of jinns to you, in order to let them hear the Quran. When they got there, they said, \"Listen.\" As soon as it was over, they rushed to their people, warning.","স্মরণ করো যে আমরা কিছু সংখ্যক জীনকে তোমার দিকে পরিচালিত করেছিলাম, যাতে করে তারা কুরআন শুনতে পারে। যখন তারা সেখানে পৌঁছে গিয়েছিল, তারা বলেছিল, \"শোন\"। এটি সমাপ্ত হওয়া মাত্রই, তারা তাদের লোকদের নিকট ছুটলো, সতর্ক করতে।"],
  "46:30": ["They said, \"O our people, we have heard a book that was revealed after Moses, and confirms the previous scriptures. It guides to the truth; to the right path.","তারা বলল, \"হে আমাদের লোকেরা, আমরা একটি গ্রন্থ শুনেছি যা মূসার পরে প্রকাশিত হয়েছে, এবং পূর্ববর্তী ঐশীগ্রন্থগুলোকে নিশ্চিত করে। এটি দিকনির্দেশনা দেয় সত্যের দিকে; সঠিক পথের দিকে।"],
  "46:31": ["O our people, respond to the call of Allah, and believe in Him. He will then forgive your sins, and spare you a painful retribution.","\"হে আমাদের লোকেরা, ঈশ্বরের ডাকে সাড়া দাও, এবং তাঁর প্রতি বিশ্বাস রাখো। তাহলে তিনি তোমাদের পাপগুলো ক্ষমা করে দিবেন, এবং এক যন্ত্রনাদায়ক শাস্তি থেকে তোমাদেরকে নিষ্কৃতি দিবেন।\""],
  "46:32": ["Those who fail to respond to Allah's call cannot escape, and will have no Lord other than Him; they have gone far astray.","যারা ঈশ্বরের ডাকে সাড়া দিতে ব্যর্থ হয় তারা পালাতে পারবে না, এবং তাঁকে ছাড়া কোন প্রভু পাবে না; তারা বহুদূর পথভ্রষ্ট হয়েছে।"],
  "46:33": ["Do they not realize that Allah, who created the heavens and the earth without the least effort is able to revive the dead? Yes indeed; He is Omnipotent.","তারা কি অনুধাবন করে না যে ঈশ্বর, যিনি আকাশমন্ডলী ও পৃথিবী সৃষ্টি করেছেন সামান্যতম প্রচেষ্টা ছাড়া, মৃতকে পুনর্জীবিত করতে সক্ষম? হ্যাঁ নিশ্চয়; তিনি সর্বশক্তিমান।"],
  "46:34": ["The day the disbelievers are introduced to the Hellfire, they will be asked, \"Is this not the truth?\" They will answer, \"Yes indeed, by our Lord.\" He will say, \"Then suffer the retribution for your disbelief.\"","সেদিন যখন অবিশ্বাসীদের কাছে নরকাগ্নি উপস্থাপন করা হবে, তাদেরকে জিজ্ঞেস করা হবে, \"এটা কি সত্য নয়?\" তারা উত্তর দিবে, \"হ্যাঁ নিশ্চয়, আমাদের প্রভুর শপথ।\" তিনি বলবেন, \"তাহলে তোমাদের অবিশ্বাসের জন্য শাস্তি ভোগ করো।\""],
  "46:35": ["Therefore, be patient like the messengers before you who possessed strength and resorted to patience. Do not be in a hurry to see the retribution that will inevitably come to them. The day they see it, it will seem as if they lasted one hour of the day. This is a proclamation: Is it not the wicked who are consistently annihilated?","একারনে, ধৈর্যশীল হও তোমার পূর্বের বার্তাবাহকদের মতো যারা ছিল শক্তিমত্তার অধিকারী এবং ধৈর্য্য-অবলম্বন করতো। শাস্তি দেখার জন্য তাড়াহুড়োয় থেকো না, এটা তাদের কাছে অনিবার্যভাবে আসবে। তারা যেদিন এটি দেখবে, এটি মনে হবে যেন তারা দিনের এক ঘন্টা অবস্থান করেছিল। এটি একটি ঘোষণা :  এরা কি অন্যায়কারীরা নয় যারা প্রতিনিয়ত নির্মূল হয়?"],
  "47:1": ["Those who disbelieve and repel from the path of Allah, He nullifies their works.","যারা অবিশ্বাস করে এবং ঈশ্বরের পথে বাধা দেয়, তিনি তাদের কাজগুলো অকার্যকর করে দেন।"],
  "47:2": ["Those who believe and work righteousness, and believe in what was sent down to Muhammad—which is the truth from their Lord—He remits their sins, and blesses them with contentment.","যারা বিশ্বাস করে এবং সৎকর্মশীল কাজ করে, এবং বিশ্বাস করে যা অবতীর্ণ করা হয়েছিল মুহাম্মদের উপর- যা তাদের ঈশ্বরের পক্ষ থেকে আসা সত্য- তিনি তাদের পাপগুলো ক্ষমা করে দেন, এবং তাদেরকে পরিতৃপ্তি দিয়ে সৌভাগ্যবান করেন।"],
  "47:3": ["This is because those who disbelieve are following falsehood, while those who believe are following the truth from their Lord. Allah thus cites for the people, their examples.","এটা এ কারণে যে, যারা অবিশ্বাস করে তারা অনুসরণ করছে মিথ্যা, আর যারা বিশ্বাস করে তারা অনুসরণ করছে তাদের প্রভুর পক্ষ থেকে আসা সত্য। ঈশ্বর এভাবে লোকদের জন্য উদ্ধৃতি দেন, তাদের উদাহরণসমূহ।"],
  "47:4": ["If you encounter (in war) those who disbelieve, you may strike the necks. If you take them as captives you may set them free or ransom them, until the war ends. Had Allah willed, He could have granted you victory, without war. But He thus tests you by one another. As for those who get killed in the cause of Allah, He will never put their sacrifice to waste.","যদি তোমরা (যুদ্ধে) তাদের মুখোমুখি হও যারা অবিশ্বাস করে, তোমরা আঘাত করতে পারো ঘাড়ে। যদি তোমরা তাদেরকে বন্দী হিসেবে নাও তোমরা তাদেরকে মুক্ত করতে পারো অথবা তাদের থেকে মুক্তিপণ নিতে পারো, যতক্ষণ না যুদ্ধ শেষ হয়। যদি ঈশ্বর চাইতেন, তিনি তোমাদেরকে বিজয় দান করতে পারতেন, যুদ্ধ করা ছাড়া। কিন্তু এভাবে তিনি তোমাদেরকে একে অন্যের দ্বারা পরীক্ষা করেন। আর তাদের ক্ষেত্রে যারা আল্লাহর উদ্দেশ্যে নিহত হয়, তিনি তাদের উৎসর্গকে কখনো নষ্ট হতে দেন না।"],
  "47:5": ["He will guide them, and bless them with contentment.","তিনি তাদেরকে পথ দেখাবেন, এবং তাদেরকে পরিতৃপ্তি দিয়ে অনুগ্রহ করবেন।"],
  "47:6": ["He will admit them into Paradise, that He described to them.","তিনি তাদেরকে স্বর্গে প্রবেশ করাবেন, যা তিনি তাদের কাছে বর্ণনা করেছিলেন।"],
  "47:7": ["O you who believe, if you support Allah, He will support you, and strengthen your foothold.","হে তোমরা যারা বিশ্বাস করো, যদি তোমরা ঈশ্বরকে সমর্থন করো, তিনি তোমাদেরকে সমর্থন করবেন, এবং তোমাদের অবস্থানকে দৃঢ় করবেন।"],
  "47:8": ["Those who disbelieve incur misery; He causes their works to be utterly in vain.","যারা অবিশ্বাস করে তারা দু:খ-কষ্ট টেনে আনে। তিনি তাদের কাজগুলো একেবারেই বৃথা করে দেন।"],
  "47:9": ["That is because they hated what Allah revealed and consequently, He nullifies their works.","এটা এ কারণে যে তারা ঘৃনা করেছিল যা ঈশ্বর প্রকাশ করেছিলেন এবং পরিনামে, তিনি তাদের কাজগুলো অকার্যকর করে দেন।"],
  "47:10": ["Did they not roam the earth and see the consequences for those before them? Allah destroyed their works; all disbelievers will suffer the same fate.","তারা কি পৃথিবীতে ঘুড়ে বেড়ায়নি এবং তাদের পূর্ববর্তীদের পরিনাম দেখেনি? ঈশ্বর তাদের কাজগুলো  ধ্বংস করে দিয়েছিলেন; সকল অবিশ্বাসীরা একই নিয়তি ভোগ করবে।"],
  "47:11": ["This is because Allah is the Lord of those who believe, while the disbelievers have no lord.","এটা এ কারণে যে ঈশ্বর তাদের প্রভু যারা বিশ্বাস করে, অপরদিকে অবিশ্বাসীদের কোন প্রভু নেই।"],
  "47:12": ["Allah admits those who believe and lead a righteous life into gardens with flowing streams. As for those who disbelieve, they live and eat like the animals eat, then end up in the hellfire.","যারা বিশ্বাস করে এবং সৎকর্মশীল জীবন-যাপন করে ঈশ্বর তাদেরকে প্রবেশ করান প্রবাহিত ঝর্ণাসহ বাগানসমূহে। আর তাদের ক্ষেত্রে যারা অবিশ্বাস করে, তারা বাচেঁ এবং খায় যেমন খায় অন্য প্রানীরা, এরপর নরকাগ্নীতে শেষ হয়।"],
  "47:13": ["Many a community was much stronger than the community that evicted you from your town; when we annihilated them, no one could help them.","অনেক সম্প্রদায় সে সম্প্রদায়ের চেয়ে অনেক বেশি শক্তিশালী ছিল যারা তোমাকে তোমার শহর থেকে উচ্ছেদ করেছিল; যখন আমরা তাদের ধ্বংস করেছিলাম, কেউ তাদের সাহায্য করতে পারেনি।"],
  "47:14": ["Are those enlightened by their Lord the same as those whose evil works are adorned in their eyes, and they follow their own opinions?","যারা তাদের প্রভুর দ্বারা আলোকিত তারা কি তাদের মতো যাদের মন্দ কাজগুলো তাদের চোখে সুশোভিত করা হয়েছে, এবং তারা তাদের নিজের মত অনুসরণ করে?"],
  "47:15": ["The allegory of Paradise that is promised for the righteous is this: it has rivers of unpolluted water, and rivers of fresh milk, and rivers of wine— delicious for the drinkers—and rivers of strained honey. They have all kinds of fruits therein, and forgiveness from their Lord. (Are they better) or those who abide forever in the hellfire, and drink hellish water that tears up their intestines?","স্বর্গ, যা সৎকর্মশীলদের জন্য অঙ্গীকার করা হয়েছে তার উপমা হলোঃ এর আছে অদূষিত পানির নদীসমূহ, এবং বিশুদ্ধ  দুধের নদীসমূহ, এবং শরাবের নদীসমূহ- যা পানকারীদের জন্য সুস্বাদু- এবং পরিশোধিত মধুর নদীসমূহ। সেখানে তাদের আছে সব ধরণের ফল, এবং তাদের প্রভুর পক্ষ থেকে ক্ষমা। (তারা কি উত্তম) নাকি যারা চিরকালের জন্য নরকাগ্নীতে বাস করে, এবং নারকীয় পানি পান করে যা তাদের অন্ত্রগুলোকে ছিঁড়ে ফেলে?"],
  "47:16": ["Some of them listen to you, then as soon as they leave they ask those who were enlightened, \"What did he just say?\" Allah thus seals their hearts and, consequently, they follow only their opinions.","তাদের কেউ কেউ তোমার কথা শুনে, এরপর এরা চলে যাওয়া মাত্রই তাদেরকে জিজ্ঞেস করে যারা বিজ্ঞ, “সে এইমাত্র কি বলেছে?” ঈশ্বর এভাবে তাদের হৃদয়ে মোহর এঁটে দেন এবং, পরিনামে, তারা তাদের নিজেদের মতামত অনুসরণ করে।"],
  "47:17": ["As for those who are guided, He augments their guidance, and grants them their righteousness.","আর তাদের ক্ষেত্রে যারা পথনির্দেশনা পেয়েছে, তিনি তাদের পথনির্দেশনা ত্বরান্বিত করেন, এবং তাদের জন্য সৎকর্মশীলতা মঞ্জুর করেন।"],
  "47:18": ["Are they waiting until the Hour comes to them suddenly? All the signs thereof have already come. Once the Hour comes to them, how will they benefit from their message?","তারা কি অপেক্ষা করছে- যে পর্যন্ত না সে সময় তাদের কাছে হঠাৎ করে আসে? ইতিমধ্যে এর সব নিদর্শন এসে গেছে। একবার যখন সে ঘন্টা তাদের কাছে আসে, কিভাবে তারা তাদের বার্তা থেকে উপকৃত হবে?"],
  "47:19": ["You shall know that: \"There is no other god beside Allah,\" and ask forgiveness of your sins and the sins of all believing men and women. Allah is fully aware of your decisions and your ultimate destiny.","তোমরা জেনে রাখো যে: ঈশ্বরের পাশে অন্যকোন উপাস্য নেই, \"  এবং ক্ষমা চাও তোমাদের পাপ এবং সকল বিশ্বাসী নারী-পুরুষের পাপের জন্য। ঈশ্বর তোমাদের  সিদ্ধান্ত এবং তোমাদের চূড়ান্ত নিয়তি সম্পর্কে পূর্ণ অবগত।"],
  "47:20": ["Those who believed said: \"When will a new sura be revealed?\" But when a straightforward sura was revealed, wherein fighting was mentioned, you would see those who harbored doubts in their hearts looking at you, as if death had already come to them. They were thus exposed.","যারা বিশ্বাস করেছিল তারা বলেছিল: \"কখন একটি নতুন সূরা প্রকাশিত হবে?\" কিন্তু যখন একটি সহজবোধ্য সূরা প্রকাশিত হলো, যেখানে যুদ্ধের উল্লেখ করা হয়েছিল, তখন তুমি তাদেরকে দেখতে তোমার দিকে তাকিয়ে আছে যারা তাদের হৃদয়ে সন্দেহ পোষন করেছিল, যেন মৃত্যু তাদের কাছে এসেই পড়েছে। তারা এইভাবে উন্মোচিত হয়েছিল।"],
  "47:21": ["Obedience and righteous utterances are expected of them. If only they showed confidence in Allah, when mobilization was called for, it would have been better for them.","অনুগত থাকা এবং ন্যায়নিষ্ঠ কথাই তাদের কাছ থেকে প্রত্যাশিত। যদি শুধু তারা ঈশ্বরের প্রতি আত্মবিশ্বাস দেখাতো, যখন যুদ্ধের জন্য একত্রিত হতে ডাকা হয়েছিল, এটা তাদের জন্য উত্তম হতো।"],
  "47:22": ["Is it also your intention that as soon as you leave you will commit evil and mistreat your relatives?","এটাও কি তোমাদের উদ্দেশ্য যে তোমরা চলে যাবার সাথে সাথেই মন্দ কাজ করবে এবং তোমাদের আত্মীয়দের সাথে দুর্ব্যবহার করবে?"],
  "47:23": ["It is those who incurred a curse from Allah, whereby He rendered them deaf and blind.","এরা তারাই যারা ঈশ্বর থেকে অভিশাপ টেনে এনেছিল, যার দ্বারা তিনি তাদেরকে বধির এবং অন্ধ করেছিলেন।"],
  "47:24": ["Why do they not study the Quran carefully? Do they have locks on their minds?","কেন তারা যত্নসহকারে কুরআন অধ্যয়ন করে না? তাদের অন্তর কি তালাবদ্ধ?"],
  "47:25": ["Surely, those who slide back, after the guidance has been manifested to them, the devil has enticed them and led them on.","নিশ্চয়, যারা পিছনে ধাবিত হয়, তাদের কাছে সুস্পষ্টভাবে পথ-নির্দেশনা প্রকাশিত হবার পর, শয়তান তাদেরকে প্ররোচিত করেছে এবং তাদেরকে বিপথগামী করেছে।"],
  "47:26": ["This is because they said to those who hated what Allah has sent down, \"We will obey you in certain matters.\" Allah fully knows their secret conspiracies.","এটা এ কারনে যে তারা তাদেরকে বলেছিল যারা ঘৃনা করতো যা ঈশ্বর অবতীর্ণ করেছেন, \"আমরা তোমাদেরকে মান্য করবো সুনির্দিষ্ট ব্যাপারে।\" ঈশ্বর সম্পূর্ণভাবে তাদের গোপন ষড়যন্ত্র  জানেন।"],
  "47:27": ["How will it be for them when the angels put them to death? They will beat them on their faces and their rear ends.","এটা তাদের জন্য কেমন হবে যখন ফেরেশতারা তাদের মৃত্যু ঘটাবে? তারা তাদের প্রহার করবে তাদের মুখে এবং তাদের পশ্চাৎপ্রান্তে।"],
  "47:28": ["This is because they followed what angered Allah and hated the things that please Him. Consequently, He has nullified their works.","এটা একারণে যে তারা অনুসরণ করেছিল যা আল্লাহকে রাগান্বিত করেছিল এবং ঘৃনা করতো সে বিষয়গুলো যা তাঁকে সন্তুষ্ট করে। ফলশ্রুতিতে, তিনি তাদের কাজগুলো নিষ্ফল করে দিয়েছেন।"],
  "47:29": ["Did those who harbor doubts in their hearts think that Allah will not bring out their evil thoughts?","যারা তাদের হৃদয়ে সন্দেহ পোষণ করেছিল তারা কি মনে করে যে আল্লাহ তাদের মন্দ চিন্তাগুলো প্রকাশ করবেন না?"],
  "47:30": ["If we will, we can expose them for you, so that you can recognize them just by looking at them. However, you can recognize them by the way they talk. Allah is fully aware of all your works.","যারা তাদের হৃদয়ে সন্দেহ পোষণ করেছিল তারা কি মনে করে যে আল্লাহ তাদের মন্দ চিন্তাগুলো প্রকাশ করবেন না?"],
  "47:31": ["We will certainly put you to the test, in order to distinguish those among you who strive, and steadfastly persevere. We must expose your true qualities.","নিশ্চয় আমরা তোমাদের পরীক্ষা করবো, তোমাদের মধ্যে তাদেরকে আলাদা করতে যারা সংগ্রাম করে, এবং দৃড়তার সাথে অধ্যবসায়ী। আমরা অবশ্যই তোমাদের সত্যিকার বৈশিষ্ট্য প্রকাশ করবো।"],
  "47:32": ["Those who disbelieve and repel from the path of Allah, and oppose the messenger after the guidance has been manifested for them, will never hurt Allah in the least. Instead, He nullifies their works.","যারা অবিশ্বাস করে এবং ঈশ্বরের পথে বাধা দেয়, এবং তাদের জন্য পথ-নির্দেশনা সুস্পষ্টভাবে প্রকাশিত হবার পর বার্তাবাহকদের বিরোধিতা করে, কখনোই ঈশ্বরকে সামান্যতম আঘাত করবে না। উল্টো, তিনি তাদের কাজগুলোঅকার্যকর করেন।"],
  "47:33": ["O you who believe, you shall obey Allah, and obey the messenger. Otherwise, all your works will be in vain.","হে তোমরা যারা বিশ্বাস করো, তোমরা মান্য করবে ঈশ্বরকে, এবং মান্য করবে বার্তাবাহককে। অন্যথায়, তোমাদের সকল কাজ বৃথা হয়ে যাবে।"],
  "47:34": ["Those who disbelieve and repel from the path of Allah, then die as disbelievers, Allah will never forgive them.","যারা অবিশ্বাস করে এবং ঈশ্বরের পথে বাঁধা দেয়, এরপর অবিশ্বাসী হিসেবে মারা যায়, ঈশ্বর তাদেরকে কখনো ক্ষমা করবেন না।"],
  "47:35": ["Therefore, you shall not waver and surrender in pursuit of peace, for you are guaranteed victory, and Allah is with you. He will never waste your efforts.","একারণে, তোমরা দ্বিধান্বিত হইও না এবং শান্তির আশায় আত্মসমর্পণ করো না, কারণ তোমাদেরকে বিজয়ের নিশ্চয়তা দেয়া হয়, এবং আল্লাহ তোমাদের সাথে আছেন। তিনি কখনো তোমাদের চেষ্টা বিফলে যেতে দিবেন না।"],
  "47:36": ["This worldly life is no more than play and vanity. But if you believe and lead a righteous life, He will reward you, without asking you for any money.","এই পার্থিব জীবন খেলা এবং অহমিকার চেয়ে বেশি কিছু নয়। কিন্তু যদি তোমরা বিশ্বাস করো এবং সৎ জীবন-যাপন করো, তিনি তোমাদের পুরষ্কৃত করবেন, তোমাদের কাছে কোন টাকা না চেয়ে।"],
  "47:37": ["If He asked you for money, to the extent of creating a hardship for you, you might have become stingy, and your hidden evil might be exposed.","যদি তিনি তোমাদের কাছে টাকা চাইতেন, এতো পরিমানে যে তোমাদের জন্য কষ্টকর হয়ে দাঁড়ায়, তোমরা কৃপন হয়ে পড়তে, এবং তোমাদের লুকায়িত মন্দকর্ম প্রকাশ হয়ে যেতো।"],
  "47:38": ["You are invited to spend in the cause of Allah, but some of you turn stingy. The stingy are stingy towards their own souls. Allah is Rich, while you are poor.  If you turn away, He will substitute other people in your place, and they will not be like you.","তোমরা আল্লাহর উদ্দেশ্যে ব্যয় করতে আমন্ত্রিত, কিন্তু তোমাদের কেউ কেউ কৃপণ হয়ে পড়ো। কৃপণরা তাদের নিজ আত্নার প্রতিই কৃপণ। ঈশ্বর ধনী, যেখানে তোমরা দরিদ্র।"],
  "48:1": ["We have bestowed upon you (O Messenger) a great victory.","(হে বার্তাবাহক) আমরা তোমার উপর অর্পণ করেছি এক মহা বিজয়।"],
  "48:2": ["Whereby Allah forgives your past sins, as well as future sins, and perfects His blessings upon you, and guides you in a straight path.","এর দ্বারা ঈশ্বর ক্ষমা করেন তোমার অতীতের পাপসমূহ, একই সাথে ভবিষ্যত্বের পাপসমূহ, আর তোমার উপর তাঁর অনুগ্রহসমূহ পূর্ণ করেন এবং তোমাকে সরল পথে পরিচালিত করেন ।"],
  "48:3": ["Additionally, Allah will support you with an unwavering support.","উপরন্তু, ঈশ্বর তোমাকে সমর্থন করবেন - যে সমর্থন নড়বড়ে নয়  ।"],
  "48:4": ["He is the One who places contentment into the hearts of believers to augment more faith, in addition to their faith. To Allah belongs all forces of the heavens and the earth. Allah is Omniscient, Most Wise.","তিনিই সে সত্ত্বা যিনি বিশ্বাসীদের হৃদয়ে পরিতৃপ্তি দেন- তাদের বিশ্বাসে আরো বিশ্বাস দিয়ে ত্বরান্বিত করতে । আকাশমন্ডলী এবং পৃথিবীর সকল বাহিনী ঈশ্বরের অধীনে। ঈশ্বর সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "48:5": ["He will certainly admit the believing men and women into gardens with flowing streams, wherein they abide forever. He will remit their sins. This is, in the sight of Allah, a great triumph.","নিশ্চয় তিনি বিশ্বাসী পুরুষ এবং নারীদের প্রবেশ করাবেন প্রবাহিত ঝর্ণাসহ বাগানসমূহে, যেখানে তারা চিরকাল বাস করবে। তিনি তাদের পাপসমূহ ক্ষমা করে দেবেন। এটি, ঈশ্বরের দৃষ্টিতে, এক মহা বিজয়।"],
  "48:6": ["And He will requite the hypocrite men and women and the idol worshiping men and women, for they have harbored evil thoughts about Allah. Their evil will backfire against them. For Allah is angry with them, condemns them, and has prepared for them Gehenna. What a miserable destiny!","এবং তিনি প্রতিশোধ গ্রহন করবেন ভণ্ড পুরুষ ও নারী এবং প্রতিমা উপাসনাকারী পুরুষ ও নারীদের থেকে, কারণ তারা ঈশ্বর সম্পর্কে   মন্দ ধারণা পোষণ করেছে।  তাদের মন্দকর্ম উল্টো তাদেরই বিপর্যয় ঘটাবে। কারণ ঈশ্বর তাদের প্রতি রাগান্বিত, তাদের নিন্দা করেন এবং তাদের জন্য প্রস্তুত রেখেছেন নরক । কি এক শোচনীয় পরিণতি!"],
  "48:7": ["To Allah belongs all the forces in the heavens and the earth. Allah is Almighty, Most Wise.","আকাশমন্ডলী এবং পৃথিবীর সকল বাহিনী ঈশ্বরের অধীনে। ঈশ্বর সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "48:8": ["We have sent you as a witness, a bearer of good news, and a warner.","তোমাকে আমরা পাঠিয়েছি একজন সাক্ষী, সুসংবাদবহনকারী, এবং সতর্ককারী হিসেবে।"],
  "48:9": ["That you people may believe in Allah and His messenger, and reverence Him, and observe Him, and glorify Him, day and night.","যাতে তোমরা লোকেরা হয়তো  ঈশ্বর ও তাঁর বার্তাবাহককে বিশ্বাস করবে, এবং  তাঁকে ভক্তি করবে, এবং তাঁকে মান্য করবে, এবং তাঁর মহিমা ঘোষণা করবে, দিনে ও রাতে।"],
  "48:10": ["Surely, those who pledge allegiance to you, are pledging allegiance to Allah. Allah approves their pledge; He places His hand above their hands. Those who violate such a pledge, commit the violation to their own detriment. As for those who fulfill their pledge with Allah, He will grant them a great recompense.","নিশ্চয়, যারা তোমার প্রতি আনুগত্যের অঙ্গিকার করে, তারা ঈশ্বরের প্রতিই আনুগত্যের অঙ্গিকার করছে । ঈশ্বর তাদের অঙ্গিকারকে সমর্থন করেন; তিনি তাঁর হাত রাখেন তাদের হাতের উপর। যারা এমন অঙ্গিকার লংঘন করে, তারা লংঘন করে তাদের নিজের ক্ষতি করতে। আর তাদের ক্ষেত্রে যারা আল্লাহর সাথে তাদের অঙ্গীকার পূর্ণ করে, তিনি তাদেরকে এক মহা প্রতিদান প্রদান করবেন।"],
  "48:11": ["The sedentary Arabs who stay behind will say, \"We have been preoccupied with our money and our families, so ask forgiveness for us!\" They utter with their tongues what is not in their hearts. Say, \"Who can protect you from Allah, if He willed any adversity for you, or if He willed any blessing for you?\" Allah is fully Cognizant of everything you do.","অলস আরবরা যারা পিছনে রয়ে যায়, বলবে, \"আমরা আমাদের টাকা-পয়সা এবং আমাদের পরিবার নিয়ে আচ্ছন্ন ছিলাম, তাই আমাদের জন্য ক্ষমা প্রার্থনা করো।\" তারা তাদের মুখে বলে, যা তাদের অন্তরে নেই। বল, \"কে তোমাদেরকে ঈশ্বর থেকে রক্ষা করতে পারে, যদি তিনি তোমাদের জন্য কোন দূর্ভোগ চান, অথবা যদি তিনি তোমাদের জন্য কোন অনুগ্রহ চান ? \" ঈশ্বর তোমাদের করা সবকিছু সম্পর্কে পূর্ণ অবগত।"],
  "48:12": ["You secretly believed that the messenger and the believers will be defeated and never come back to their families, and this was firmly established in your hearts. You harbored evil thoughts and turned into wicked people.","তোমরা গোপনে বিশ্বাস করেছিলে যে, বার্তাবাহক ও বিশ্বাসীরা পরাজিত হবে এবং  কখনো তাদের পরিবারে ফিরে আসবে না, আর এটা তোমাদের হৃদয়ে দৃঢ়ভাবে প্রতিষ্ঠিত ছিল। তোমরা মন্দ ধারণা পোষণ করেছিলে এবং অন্যায়কারী মানুষে পরিণত হয়েছিলে।"],
  "48:13": ["Anyone who refuses to believe in Allah and His messenger, we have prepared for the disbelievers a hellfire.","যেকেউ ঈশ্বর ও তাঁর বার্তাবাহককে বিশ্বাস করা প্রত্যাখ্যান করে, আমরা অবিশ্বাসীদের জন্য প্রস্তুত রেখেছি একটি নরকাগ্নি ।"],
  "48:14": ["To Allah belongs the sovereignty of the heavens and the earth. He forgives whomever He wills, and punishes whomever He wills. Allah is Forgiver, Most Merciful.","আকাশমণ্ডলী ও পৃথিবীর সার্বভৌমত্ব ঈশ্বরের অধীনে । তিনি যাকে ইচ্ছা ক্ষমা করেন, এবং যাকে ইচ্ছা শাস্তি দেন। ঈশ্বর ক্ষমাকারী, সবচেয়ে দয়ালু।"],
  "48:15": ["The sedentary who stay behind will say, when you are expected to collect spoils of war, \"Let us follow you to share in this!\" They thus wish to alter Allah's words. Say, \"You will not follow us. This is Allah's decision.\" They will then say, \"You must be envious of us (for staying behind).\" Indeed, they rarely understood anything.","যখন তোমাদের যুদ্ধলব্ধ মাল সংগ্রহের সময় হয়, তখন সে বসে থাকা লোকেরা যারা পিছনে রয়ে যায় বলবে , \"চল এটি ভাগাভাগি করতে আমরা তোমাদের অনুসরণ করি!\" তারা এভাবে ঈশ্বরের বানী বিকৃত করার ইচ্ছা করে। বল, \"তোমরা আমাদের অনুসরণ করবে না। এটি ঈশ্বরের সিদ্ধান্ত।\" তারা এরপর বলবে, \" আমাদের প্রতি  তোমরা নিশ্চয় ঈর্শান্বিত (পিছনে থেকে যাবার  কারণে) \"। প্রকৃতপক্ষে, তারা খুব কমই কিছু বুঝে।"],
  "48:16": ["Say to the sedentary Arabs who stay behind, \"You will be invited to face powerful people and to fight them, unless they submit. If you obey, Allah will reward you with a generous recompense. But if you turn away again, as you did in the past, He will requite you with a painful retribution.\"","অলস আরবদের বল যারা পিছনে রয়ে যায়, \"তোমাদের আমন্ত্রণ  করা হবে শক্তিশালী মানুষদের মুখোমুখি হতে আর তাদের সাথে লড়াই করতে, যদিনা তারা আত্মসমর্পন করে। যদি তোমরা মেনে চল, ঈশ্বর তোমাদেরকে এক মহা প্রতিদান দিয়ে পুরষ্কৃত করবেন । কিন্তু যদি তোমরা আবারো মুখ ফিরিয়ে নাও, যেমন তোমরা অতীতে করেছিলে, তিনি এক যন্ত্রণাদায়ক শাস্তি দিয়ে তোমাদের থেকে প্রতিশোধ গ্রহণ করবেন ।"],
  "48:17": ["The blind is not to be blamed, the crippled is not to be blamed, and the sick is not to be blamed. Those who obey Allah and His messenger, He will admit them into gardens with flowing streams. As for those who turn away, He will requite them with a painful retribution.","অন্ধরা দোষী হবে না, পঙ্গুরা দোষী হবে না, অসুস্থরা দোষী হবে না। যারা ঈশ্বর এবং তাঁর বার্তাবাহককে মেনে চলে, তিনি তাদেরকে প্রবাহিত ঝর্ণাসহ বাগানসমূহে প্রবেশ করাবেন। আর যারা মুখ ফিরিয়ে নেয়, তিনি এক যন্ত্রণাদায়ক শাস্তি দিয়ে তাদের থেকে প্রতিশোধ গ্রহণ করবেন।"],
  "48:18": ["Allah is pleased with the believers who pledged allegiance to you under the tree. He knew what was in their hearts and, consequently, He blessed them with contentment, and rewarded them with an immediate victory.","ঈশ্বর সে বিশ্বাসীদের প্রতি সন্তুষ্ট যারা গাছের নিচে তোমার প্রতি আনুগত্যের অঙ্গীকার  করেছিল । তিনি জানতেন তাদের হৃদয়ে কী ছিল এবং, ফলশ্রুতিতে, তিনি তাদেরকে পরিতৃপ্তি দিয়ে অনুগ্রহ করলেন এবং তাদেরকে একটি আসন্ন বিজয় দিয়ে পুরস্কৃত করলেন ।"],
  "48:19": ["Additionally, they gained many spoils. Allah is Almighty, Most Wise.","উপরন্ত,  তারা অনেক যুদ্ধলব্ধ মাল অর্জন করেছিল। ঈশ্বর সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "48:20": ["Allah has promised you many spoils that you will gain. He thus advanced some benefits for you in this life, and He has withheld the people's hands of aggression against you, and has rendered this a sign for the believers. He thus guides you in a straight path.","ঈশ্বর তোমাদেরকে অনেক যুদ্ধলব্ধ মালের প্রতিস্রুতি দিয়েছেন যা তোমরা অর্জন করবে। এভাবে তিনি তোমাদের জন্য কিছু সুবিধা  এই জীবনে অগ্রীম প্রদান করলেন এবং তিনি তোমাদের বিরুদ্ধে লোকেদের আগ্রাসনের হাতকে ঠেকিয়ে রেখেছেন, আর একে বিশ্বাসীদের জন্য করেছেন একটি নিদর্শন। তিনি এভাবে তোমাদেরকে সরল পথ প্রদর্শন করেন।"],
  "48:21": ["As for the group that you could not possibly defeat, Allah took care of them; Allah is Omnipotent.","আর সে দলটির ক্ষেত্রে যাদেরকে তোমরা কখনোই পরাজিত করতে পারতে না, ঈশ্বর তাদের ভার নিয়েছিলেন; ঈশ্বর সর্বশক্তিমান।"],
  "48:22": ["If the disbelievers ever fought you, they would turn around and flee. They have no Lord and Master; they have no helper.","যদি কখনো অবিশ্বাসীরা তোমাদের সাথে লড়াই করতো, তারা ঘুরে দাঁড়াতো এবং  পালিয়ে যেতো। তাদের কোন প্রভু ও মনিব নেই; তাদের কোন সাহায্যকারী  নেই।"],
  "48:23": ["Such is Allah's system throughout history, and you will find that Allah's system is unchangeable.","ইতিহাসের সর্বত্র ঈশ্বরের নিয়ম এমনই, এবং তুমি ঈশ্বরের নিয়ম অপরিবর্তনীয় পাবে।"],
  "48:24": ["He is the One who withheld their hands of aggression against you, and withheld your hands of aggression against them in the valley of Mecca, after He had granted you victory over them. Allah is Seer of everything you do.","তিনিই সে সত্ত্বা যিনি তোমাদের বিরুদ্ধে তাদের আগ্রাসনের হাতকে ঠেকিয়ে রেখেছেন, এবং মক্কা উপত্যকায় তাদের বিরুদ্ধে তোমাদের আগ্রাসনের হাতকে ঠেকিয়ে রেখেছেন, তাদের উপর তোমাদের বিজয় প্রদান  করার পর। ঈশ্বর সবকিছুর দ্রষ্টা, যা কিছু তোমরা করো।"],
  "48:25": ["It is they who disbelieved and barred you from the Sacred Masjid, and even prevented your offerings from reaching their destination. There were believing men and women (within the enemy camp) whom you did not know, and you were about to hurt them, unknowingly. Allah thus admits into His mercy whomever He wills. If they persist, He will requite those among them who disbelieve with a painful retribution.","তারাই তো অবিশ্বাস করেছিল এবং তোমাদেরকে পবিত্র মসজিদে যেতে বাঁধা দিয়েছিল, আর এমনকি তোমাদের উৎসর্গগুলোকেও তাদের গন্তব্যে পৌঁছতে দেয়নি। সেখানে (শত্রু শিবিরের ভেতর) ছিল বিশ্বাসী পুরুষ ও নারীরা যাদেরকে তোমরা চিনতে না, এবং তাদেরকে তোমরা প্রায় আঘাতই  করে ফেলেছিলে, অজ্ঞাতসারে। ঈশ্বর এভাবে তাঁর দয়ায় যাকেই চান প্রবেশ করান। যদি তারা অনড় থাকে, তবে তিনি এক যন্ত্রণাদায়ক শাস্তি দিয়ে তাদের মধ্যে যারা অবিশ্বাস করে তাদের থেকে প্রতিশোধ নিবেন।"],
  "48:26": ["While those who disbelieved were enraged, and their hearts were filled with the pride of the days of ignorance, Allah blessed His messenger and the believers with peaceful contentment, and directed them to uphold the word of righteousness. This is what they well deserved. Allah is fully aware of all things.","যেখানে যারা অবিশ্বাস করেছিল তারা ছিল রাগান্বিত আর তাদের হৃদয় ছিল অজ্ঞতার দিনগুলোর গর্বে পূর্ণ, সেখানে আল্লাহ তাঁর বার্তাবাহক ও বিশ্বাসীদের অনুগ্রহ করলেন শান্তিপূর্ণ পরিতৃপ্তি দিয়ে,  এবং তাদের পরিচালিত করলেন সৎকর্মশীলতার কথা মেনে চলার দিকে । এটা তা-ই যার জন্য তারা যথাযোগ্য ছিল। ঈশ্বর সবকিছু সম্পর্কে পূর্ণ সচেতন।"],
  "48:27": ["Allah has fulfilled His messenger's truthful vision: \"You will enter the Sacred Masjid, Allah willing, perfectly secure, and you will cut your hair or shorten it (as you fulfill the pilgrimage rituals) there. You will not have any fear. Since He knew what you did not know, He has coupled this with an immediate victory.\"","ঈশ্বর তাঁর বার্তাবাহকের সত্যনিষ্ঠ দূরদৃষ্টি পূর্ণ করেছেন : তোমরা পবিত্র মসজিদে প্রবেশ করবে, ঈশ্বর চাইলে, পুরোপুরি নিরাপদে, এবং  সেখানে তোমরা তোমাদের  চুল কাটবে অথবা ছোট করবে (তীর্থযাত্রার আচারানুষ্ঠানগুলো সম্পন্ন করার জন্য) । তোমাদের কোন ভয় থাকবে না। যেহেতু তিনি জানতেন  যা তোমরা জানতে না, তিনি এটিকে এক আসন্ন বিজয় দিয়ে জুড়ে দিয়েছেন।"],
  "48:28": ["He is the One who sent His messenger with the guidance and the religion of truth, to make it prevail over all other religions. Allah suffices as a witness.","তিনিই সে সত্ত্বা যিনি তাঁর বার্তাবাহককে পথ-নির্দেশনা এবং সত্যের ধর্ম  দিয়ে পাঠিয়েছেন, অন্য সকল ধর্মের উপর একে জয়ী করতে। সাক্ষী হিসেবে আল্লাহই যথেষ্ট ।"],
  "48:29": ["Muhammad—the messenger of Allah—and those with him are harsh and stern against the disbelievers, but kind and compassionate amongst themselves. You see them bowing and prostrating, as they seek Allah's blessings and approval. Their marks are on their faces, because of prostrating. This is the same example as in the Torah. Their example in the Gospel is like plants that grow taller and stronger, and please the farmers. He thus enrages the disbelievers. Allah promises those among them who believe and lead a righteous life forgiveness and a great recompense.","মোহাম্মদ- ঈশ্বরের বার্তাবাহক- আর তার সাথে যারা আছে তারা অবিশ্বাসীদের বিরুদ্ধে কঠোর  ও অনমনীয় , কিন্তু নিজেদের মধ্যে দয়ালু ও সহানুভূতিশীল। তুমি তাদের দেখবে অবনত হয় ও সিজদা করে, যেহেতু তারা ঈশ্বরের অনুগ্রহ ও সমর্থন অন্বেষণ করে। তাদের চিহ্নসমূহ রয়েছে তাদের মুখমণ্ডলে, সিজদা করার কারণে । এই একই উদাহরণ আছে তাওরাতে। ইঞ্জিলে তাদের উদাহরণ চারাগাছের মত যা বৃদ্ধি পেয়ে লম্বা ও মজবুত হয়, আর কৃষকদের পরিতৃপ্ত করে। তিনি এভাবে অবিশ্বাসীদের ক্রোধান্বিত করে। ঈশ্বর তাদের মধ্যে যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে তাদেরকে ক্ষমা ও এক মহা প্রতিদানের প্রতিশ্রুতি দেন।"],
  "49:1": ["O you who believe, do not place your opinion above that of Allah and His messenger. You shall reverence Allah. Allah is Hearer, Omniscient.","হে তোমরা যারা বিশ্বাস করো, আল্লাহ এবং তাঁর বার্তাবাহকের উপর তোমাদের মতকে স্থান দিবে না।  তোমরা আল্লাহকে ভক্তি করবে। আল্লাহ শ্রবণকারী, সর্বজ্ঞ।"],
  "49:2": ["O you who believe, do not raise your voices above the voice of the prophet, nor shall you shout at him as you shout at each other, lest your works become nullified while you do not perceive.","হে তোমরা যারা বিশ্বাস করো, তোমাদের কন্ঠকে নবীর কন্ঠের চেয়ে উঁচু করবে না, না তোমরা তার প্রতি চিৎকার-চেচাঁমেচি করবে যেমন তোমরা একে-অন্যের সাথে  চিৎকার-চেচাঁমেচি করো, পাছে তোমাদের কাজগুলো অকার্যকর হয়ে পড়ে যখন তোমরা খেয়াল করো না।"],
  "49:3": ["Surely, those who lower their voices at the messenger of Allah are the ones whose hearts are prepared by Allah to become righteous. They have deserved forgiveness and a great recompense.","নিশ্চয়, যারা তাদের কন্ঠকে আল্লাহর বার্তাবাহকের সামনে নিচু করে তারা সে ব্যক্তি যাদের হৃদয় আল্লাহর দ্বারা সৎকর্মশীল হয়ে উঠতে প্রস্তুত করা হয়। তারা ক্ষমা ও এক মহা প্রতিদানের অর্জন করেছে।"],
  "49:4": ["As for those who call on you from outside the walls, most of them do not understand.","যারা দেয়ালের বাহির থেকে তোমাকে ডাকে, তাদের অধিকাংশ বুঝে না।"],
  "49:5": ["Had they been patient until you came out to them, it would have been better for them. Allah is Forgiver, Most Merciful.","যদি তারা ধৈর্য ধারণ করতো তুমি বের হয়ে তাদের কাছে না আসা পর্যন্ত, এটি তাদের জন্য উত্তম হতো। আল্লাহ ক্ষমাকারী, সবচেয়ে দয়ালু।"],
  "49:6": ["O you who believe, if a wicked person brings any news to you, you shall first investigate, lest you commit injustice towards some people, out of ignorance, then become sorry and remorseful for what you have done.","হে তোমরা যারা বিশ্বাস করো, যদি কোন অন্যায়কারী লোক তোমাদের কাছে কোন সংবাদ নিয়ে আসে, তোমরা প্রথমে অনুসন্ধান করবে, পাছে তোমরা, অজ্ঞতাবশত, কিছু লোকের প্রতি অন্যায় করে বসো,এরপর যা তোমরা করেছো তার জন্য দুখি:ত ও অনুতপ্ত হও।"],
  "49:7": ["And know that Allah's messenger has come in your midst. Had he listened to you in many things, you would have made things difficult for yourselves. But Allah made you love faith and adorned it in your hearts, and He made you abhor disbelief, wickedness, and disobedience. These are the guided ones.","এবং  জানো যে তোমাদের মাঝে আল্লাহর বার্তাবাহক এসেছেন। সে যদি তোমাদের অনেক কিছুতে কান দিতো, তোমরা তোমাদের জন্য বিষয়গুলো কঠিন করে ফেলতে। কিন্তু আল্লাহ তোমাদেরকে শিখিয়েছেন বিশ্বাসকে ভালবাসতে,  এবং একে তোমাদের হৃদয়ে সুশোভিত করেছেন; এবং তিনি তোমাদের তৈরি করেছেন অবিশ্বাস, অন্যায়, আর অবাধ্যতার প্রতি ঘৃনা দিয়ে। এরাই পথপ্রাপ্ত ব্যক্তি।"],
  "49:8": ["Such is grace from Allah and His blessings. Allah is Omniscient, Most Wise.","এমনই আল্লাহর পক্ষ থেকে দয়া এবং  তাঁর অনুগ্রহ। আল্লাহ সর্বজ্ঞ, সবচেয়ে প্রজ্ঞাবান।"],
  "49:9": ["If two groups of believers fought with each other, you shall reconcile them. If one group aggresses against the other, you shall fight the aggressing group until they submit to Allah's command. Once they submit, you shall reconcile the two groups equitably. You shall maintain justice; Allah loves those who are just.","যদি বিশ্বাসীদের দুই দল একে অন্যের সাথে যুদ্ধ করে থাকে, তোমরা তাদের পূন:র্মিলিত করবে। যদি একদল অন্যটির উপর আগ্রাসী হয়, তোমরা আগ্রাসী দলটির সাথে লড়াই করবে যতক্ষণ না তারা আল্লাহর আদেশের কাছে সমর্পণ করে।  একবার যখন তারা সমর্পণ করে, তোমরা ন্যায়সংগতভাবে দল দু'টিকে পূন:র্মিলিত করবে।  তোমরা ন্যায়পরায়ণতা বজায় রাখবে; আল্লাহ তাদেরকে ভালবাসেন যারা ন্যায়পরায়ণ।"],
  "49:10": ["The believers are members of one family; you shall keep the peace within your family and reverence Allah, that you may attain mercy.","বিশ্বাসীরা একটি পরিবারের সদস্য; তোমরা তোমাদের পরিবারে শান্তি বজায় রাখবে এবং আল্লাহকে ভক্তি-শ্রদ্ধা করো, যাতে তোমরা দয়া অর্জন করতে পারো।"],
  "49:11": ["O you who believe, no people shall ridicule other people, for they may be better than they. Nor shall any women ridicule other women, for they may be better than they. Nor shall you mock one another, or make fun of your names. Evil indeed is the reversion to wickedness after attaining faith. Anyone who does not repent after this, these are the transgressors.","হে তোমরা যারা বিশ্বাস করো,  কোন লোক অন্য লোককে নিয়ে উপহাস করবে না, কারণ তারা তাদের চেয়ে উত্তম হতে পারে। না কোন নারী অন্য নারীকে নিয়ে উপহাস করবে,কারণ তারা তাদের চেয়ে উত্তম হতে পারে। না তোমরা একে অন্যকে নিয়ে হাসাহাসি  করবে, অথবা তোমাদের নাম নিয়ে মজা করবে। বিশ্বাস অর্জনের পর অনৈতিকতায় ফিরে যাওয়া অবশ্যই মন্দ। যেকেউ এর পরে অনুশোচনা করে না, এরাই সীমালঙ্ঘনকারী।"],
  "49:12": ["O you who believe, you shall avoid any suspicion, for even a little bit of suspicion is sinful. You shall not spy on one another, nor shall you backbite one another; this is as abominable as eating the flesh of your dead brother. You certainly abhor this. You shall observe Allah. Allah is Redeemer, Most Merciful.","হে তোমরা যারা বিশ্বাস করো, তোমরা কোন প্রকার সন্দেহ করা এড়িয়ে চলবে, এমনকি সামান্যতম সন্দেহ করাও পাপ। তোমরা একে অন্যকে নিয়ে গোয়েন্দাগিরি করবে না, না তোমরা একে অন্যকে নিয়ে গীবত করবে; এটা তেমন ঘৃন্যকর যেমন তোমাদের মৃত ভাইয়ের মাংস খাওয়া। তোমরা নিশ্চয় একে ঘৃনা করো। তোমরা আল্লাহকে মান্য করবে। আল্লাহ উদ্ধারকারী, সবচেয়ে দয়ালু।"],
  "49:13": ["O people, we created you from the same male and female, and rendered you distinct peoples and tribes, that you may recognize one another. The best among you in the sight of Allah is the most righteous. Allah is Omniscient, Cognizant.","হে মানুষ, আমরা তোমাদের একই নর এবং নারী থেকে সৃষ্টি করেছি, আর তোমাদেরকে করেছি স্বতন্ত্র মানুষ এবং গোত্র, যাতে তোমরা একে অন্যকে চিনতে পারো।  আল্লাহর দৃষ্টিতে তোমাদের মধ্যে সর্বোত্তম হচ্ছে যে সবচেয়ে বেশি সৎকর্মশীল।"],
  "49:14": ["The Arabs said, \"We are Mu'mens (believers).\" Say, \"You have not believed; what you should say is, 'We are Muslims (submitters),' until belief is established in your hearts.\" If you obey Allah and His messenger, He will not put any of your works to waste. Allah is Forgiver, Most Merciful.","আরবরা বলেছিল, \"আমরা মুমিন (বিশ্বাসী)।\" বল, \"তোমরা বিশ্বাসী হওনি; তোমাদের বলা উচিত ছিল, 'আমরা মুসলিম (আত্মসমর্পণকারী), যতক্ষন না বিশ্বাস তোমাদের হৃদয়ে স্থাপিত হয়।\" যদি তোমরা আল্লাহ এবং তাঁর বার্তাবাহককে মান্য করো, তিনি তোমাদের কোন কাজকে  বিফলে দিবেন না। আল্লাহ ক্ষমাকারী, সবচেয়ে দয়ালু।"],
  "49:15": ["Mu'mens (believers) are those who believe in Allah and His messenger, then attain the status of having no doubt whatsoever, and strive with their money and their lives in the cause of Allah. These are the truthful ones.","তারাই মুমিন (বিশ্বাসী) যারা আল্লাহ এবং তাঁর বার্তাবাহককে বিশ্বাস করে, তারপর কোনরূপ সন্দেহ না থাকার মর্যাদা অর্জন করে, আর তাদের অর্থ এবং জীবন দিয়ে আল্লাহর উদ্দেশ্যে সংগ্রাম করে। এরাই সত্যবাদী ব্যক্তি।"],
  "49:16": ["Say, \"Are you informing Allah about your religion? Allah knows everything in the heavens and the earth. Allah is Omniscient.\"","বল, \"তোমরা কি আল্লাহকে তোমাদের ধর্ম সম্পর্কে জানাচ্ছো? আল্লাহ আকাশমন্ডলী এবং পৃথিবীর সবকিছু জানেন। আল্লাহ সর্বজ্ঞ।\""],
  "49:17": ["They act as if they are doing you a favor by embracing Submission! Say, \"You are not doing me any favors by embracing Submission. Allah is the One who is doing you a great favor by guiding you to the faith, if you are sincere.\"","তারা এমন আচরণ করে যেন আত্মসমর্পণ আলিঙ্গন করে তারা তোমাকে অনুগ্রহ করছে! বল, \"তোমরা আত্মসমর্পণ আলিঙ্গন করে আমাকে কোনভাবে অনুগ্রহ করছো না। আল্লাহই সে সত্ত্বা যিনি তোমাদেরকে বিশ্বাসে পথ দেখানোর মাধ্যমে তোমাদের প্রতি বিশাল অনুগ্রহ করছেন, যদি তোমরা আন্তরিক হও।\""],
  "49:18": ["Allah knows all the secrets in the heavens and the earth; Allah is Seer of everything you do.","আল্লাহ আকাশমন্ডলী এবং পৃথিবীর সকল গোপনীয়তা জানেন; আল্লাহ তোমাদের করা সবকিছুর দ্রষ্টা।"],
  "50:1": ["Q., and the glorious Quran.","ক. (ক্বাফ) এবং মহিমান্বিত কুরআন।"],
  "50:2": ["They found it strange that a warner from among them came to them! The disbelievers said, \"This is really strange.","তাদের মধ্য থেকে তাদের কাছে একজন সতর্ককারী আসাটা তাদের কাছে অদ্ভুত লেগেছিল! অবিশ্বাসীরা বলল, “এটা আসলেই অদ্ভুত।"],
  "50:3": ["\"After we die and become dust; this is impossible.\"","“আমরা মরে গিয়ে ধুলো হয়ে যাবার পর, তা অসম্ভব।”"],
  "50:4": ["We are fully aware of any one of them who gets consumed by the earth; we have an accurate record.","তাদের মধ্যে কে মাটির সাথে মিশে যায় সে সম্পর্কে আমরা সম্পূর্ণ অবগত; আমাদের কাছে আছে নির্ভুল নথি ।"],
  "50:5": ["They rejected the truth when it came to them; they are utterly confused.","তারা সত্য প্রত্যাখ্যান করেছিল যখন তা তাদের কাছে এসেছিল; তারা পুরোপুরি সন্দিহান।"],
  "50:6": ["Have they not looked at the sky above them, and how we constructed it and adorned it, without a flaw?","তারা কি তাদের উপর আকাশের দিকে তাকায়নি, আর কেমন করেই বা একে আমরা নির্মাণ করলাম এবং একে সুসজ্জিত করলাম, কোন ত্রুটি ছাড়া?"],
  "50:7": ["And we created the earth, and scattered on it mountains, and grew in it all kinds of beautiful plants.","এবং আমরা সৃষ্টি করলাম পৃথিবী, আর এর উপর ছড়িয়ে দিলাম পর্বতসমূহ, আর এতে ফলিয়েছি  সকল প্রকার সুন্দর উদ্ভিদ।"],
  "50:8": ["This is an enlightenment, and a reminder for every pious worshiper.","এটি একটি জ্ঞানালোক, এবং একটি স্মারক প্রত্যেক সৎকর্মশীল উপাসনাকারীর জন্য।"],
  "50:9": ["And we sent from the sky blessed water, to grow with it gardens and grains to be harvested.","এবং আমরা আকাশ থেকে অনুগ্রহপূর্ণ পানি পাঠালাম, এটি দিয়ে বাগান বিকশিত করতে ও শস্য ফলাতে।"],
  "50:10": ["Tall date palms, with clustered fruit.","লম্বা খেজুর গাছ, গুচ্ছবদ্ধ ফল সহ।"],
  "50:11": ["Provisions for the people. And we revive with it dead lands; you are similarly resurrected.","লোকদের জন্য রিজিক। এবং আমরা এর দ্বারা মৃত ভূমিকে পুনরুজ্জীবিত করি; তোমাদেরকে একই ভাবে পুনরুত্থিত করা হয়।"],
  "50:12": ["Disbelieving before them were the people of Noah, the dwellers of Russ, and Thamûd.","তাদের পূর্বে অবিশ্বাসী ছিল নূহের লোকেরা, রাসের অধিবাসীরা, ও সামুদ।"],
  "50:13": ["And 'Ãd, Pharaoh, and the brethren of Lot.","এবং আদ, ফেরাউন, ও লুত-ভ্রাতৃবৃন্দ।"],
  "50:14": ["And the dwellers of the woods, and the people of Tubba'. All of them disbelieved the messengers and, consequently, My retribution befell them.","এবং বনের অধিবাসী, ও তুবার লোকেরা। তাদের সকলেই বার্তাবাহকদের অবিশ্বাস করেছিল আর, পরিণামে, আমার শাস্তি তাদের উপর পড়েছিল।"],
  "50:15": ["Were we too burdened by the first creation? Is this why they doubt resurrection?","আমরা কি প্রথম সৃষ্টি দ্বারা অত্যধিক ভারগ্রস্ত হয়ে গেলাম? এ কারনে-ই কি তারা পুনরুত্থান নিয়ে সন্দেহ করে?"],
  "50:16": ["We created the human, and we know what he whispers to himself. We are closer to him than his jugular vein.","আমরা মানুষ সৃষ্টি করলাম, আর আমরা জানি সে নিজের কাছে চুপি চুপি কি বলে। আমরা তার গ্রীবাস্থিত শিরার চেয়েও অধিকতর নিকটবর্তী।"],
  "50:17": ["Two recording (angels), at right and at left, are constantly recording.","দু'জন লিপিবদ্ধকারী (ফেরেশতা), ডানে ও বায়ে, অনবরত লিপিবদ্ধ করছে।"],
  "50:18": ["Not an utterance does he utter without an alert witness.","সতর্ক সাক্ষ্য ব্যতিত কোন কিছু সে বলে না।"],
  "50:19": ["Finally, the inevitable coma of death comes; this is what you tried to evade.","পরিশেষে, মৃত্যুর সে অনিবার্য অচেতনাবস্থা আসে; ঠিক যেটা তুমি এড়াতে চেয়েছিলে।"],
  "50:20": ["The horn is blown; this is the promised day.","শিঙ্গায় ফুঁ দেয়া হয়; এটি সেই প্রতিশ্রুত দিন।"],
  "50:21": ["Every soul comes with a herder and a witness.","প্রত্যেক আত্মা একজন পরিচালনাকারী ও একজন সাক্ষী সহ আসে।"],
  "50:22": ["You used to be oblivious to this. We now remove your veil; today, your vision is (as strong as) steel.","তুমি এর প্রতি উদাসীন থাকতে। আমরা এখন তোমার মুখাবরণ সরিয়ে দেই; আজ, তোমার দৃষ্টি ইস্পাত (এর মতো দৃঢ়)।"],
  "50:23": ["The companion said, \"Here is my formidable testimony.\"","সঙ্গী বলল, “এই যে আমার জোরালো সাক্ষ্য।”"],
  "50:24": ["Throw into Gehenna every stubborn disbeliever.","জাহান্নামে নিক্ষেপ করো প্রত্যেক একগুঁয়ে অবিশ্বাসীকে।"],
  "50:25": ["Forbidder of charity, aggressor, full of doubt.","দান করতে নিষেধকারী, আগ্রাসক, সন্দেহে পূর্ণ।"],
  "50:26": ["He set up besides Allah another god. Throw him into severe retribution.","সে ঈশ্বরের পাশে স্থাপন করে অন্য উপাস্য। তাকে নিক্ষেপ করো কঠিন শাস্তিতে।"],
  "50:27": ["His companion said, \"Our Lord, I did not mislead him; he was far astray.\"","তার সঙ্গী বলল, “আমাদের প্রভু, আমি তাকে পথভ্রষ্ট করিনি; সে ছিল বহুদূর পথভ্রষ্ট।”"],
  "50:28": ["He said, \"Do not feud in front of Me; I have sufficiently warned you.","তিনি বললেন, ‘আমার সামনে বিবাদ করো না; আমি তোমাদেরকে যথেষ্ট সতর্ক করেছি।"],
  "50:29": ["\"Nothing can be changed now. I am never unjust towards the people.\"","“এখন আর কিছুই পরিবর্তিত হতে পারে না। আমি লোকদের প্রতি কখনই অবিচারক নই।”"],
  "50:30": ["That is the day when we ask Hell, \"Have you had enough?\" It will say, \"Give me more.\"","এটা-ই সে দিন যখন আমরা নরককে জিজ্ঞেস করবো, “তোমার কি যথেষ্ট আছে?” এটি বলবে, “আমাকে আরো দাও।”"],
  "50:31": ["Paradise will be offered to the righteous, readily.","সৎকর্মশীলদের স্বর্গ প্রদান করা হবে, অনায়াসে।"],
  "50:32": ["This is what was promised to every repenter, steadfast.","এটা তা-ই যা প্রত্যেক অনুশোচনাকারী, অবিচল ব্যক্তিকে অঙ্গীকার করা হয়েছিল।"],
  "50:33": ["They reverenced the Most Gracious, in their privacy, and came wholeheartedly.","তারা তাদের একান্তে পরম করুনাময়কে ভক্তি করেছিল, আর এসেছে পূর্ণহৃদয় নিয়ে।"],
  "50:34": ["Enter it in peace; this is the Day of Eternity.","এতে প্রবেশ করো শান্তিতে; এটি চিরস্থায়িত্বের দিন।"],
  "50:35": ["They get anything they wish therein, and we have even more.","তারা সেখানে যা চায় তা-ই পায়, এবং আমাদের কাছে এমনকি আরও বেশি আছে।"],
  "50:36": ["Many a generation before them, who were more powerful, we annihilated. They searched the land; did they find an escape?","তাদের পূর্বে অনেক প্রজন্ম, যারা অধিক শক্তিশালী ছিল, আমরা তাদের ধ্বংস করেছিলাম। তারা জমিনে খুঁজে বেরিয়েছিল, তারা কি পালানোর কোন পথ পেয়েছিল?"],
  "50:37": ["This should be a lesson for everyone who possesses a mind, or is able to hear and witness.","তাদের প্রত্যেকের জন্য এটি শিক্ষা হওয়া উচিত, যাদের একটি মন আছে, অথবা শুনতে ও প্রত্যক্ষ করতে সক্ষম।"],
  "50:38": ["We have created the heavens and the earth, and everything between them in six days, and no fatigue touched us.","আমরা আকাশমণ্ডলী ও পৃথিবী এবং এদের মধ্যকার সবকিছু ছয় দিনে সৃষ্টি করেছি, এবং কোন ক্লান্তি আমাদের স্পর্শ করেনি।"],
  "50:39": ["Therefore, be patient in the face of their utterances, and praise and glorify your Lord before sunrise, and before sunset.","অতএব, তাদের কথায় ধৈর্যশীল হও, এবং সূর্যোদয়ের পূর্বে ও সূর্যাস্তের পূর্বে তোমার প্রভুর প্রশংসা ও মহিমা ঘোষণা করো।"],
  "50:40": ["During the night you shall meditate on His name, and after prostrating.","তুমি তাঁর নাম নিয়ে ধ্যান করো রাতে, এবং সেজদার পর।"],
  "50:41": ["Prepare for the day when the caller calls from a place that is near.","সেদিনের জন্য প্রস্তুত হও যখন আহবানকারী আহবান করে এক স্থান থেকে যা নিকটবর্তী।"],
  "50:42": ["When they hear the inevitable cry; that is the day you come out.","যখন তারা সে অবশ্যম্ভাবী কান্না শোনে; ঐ দিন-ই তোমরা বেরিয়ে আসো।"],
  "50:43": ["We are the ones who control life and death; to us is the final destiny.","আমরা সেই সত্তা যারা জীবন ও মৃত্যু নিয়ন্ত্রণ করি; আমাদের কাছে রয়েছে সে চুড়ান্ত নিয়তি।"],
  "50:44": ["The day will come when the earth cracks in a hurry, giving rise to them. Such summoning is easy for us to do.","সেদিন আসবে যখন পৃথিবী তাড়াহুড়ায় ফেটে যাবে, যা তাদের জাগিয়ে দিবে। এমন আহবান আমাদের জন্য সহজ।"],
  "50:45": ["We are fully aware of everything they utter, while you have no power over them. Therefore, remind with this Quran, those who reverence My warnings.","তারা যা কিছু বলে সে সম্পর্কে আমরা পূর্ণ অবগত, যখন তাদের উপর তোমার কোন ক্ষমতা নেই। অতএব, তাদেরকে এই কুরআন দিয়ে স্মরণ করিয়ে দাও যারা আমার সতর্ক-বার্তাকে ভক্তি করে।"],
  "51:1": ["The blowing winds.","প্রবাহমান বাতাস।"],
  "51:2": ["Bearing rain.","বহন করে বৃষ্টি।"],
  "51:3": ["Bringing provisions.","নিয়ে আসে রিজিক।"],
  "51:4": ["Distributing them as commanded.","বিতরণ করে এগুলোকে আদেশ অনুযায়ী।"],
  "51:5": ["What is promised to you will surely come to pass.","যা তোমাদের কাছে অঙ্গীকার করা হয় তা অবশ্যই ঘটবে।"],
  "51:6": ["The Day of Judgment is inevitable.","বিচারের দিন অনিবার্য।"],
  "51:7": ["Despite the perfectly created sky.","নিখুঁতভাবে সৃষ্ট আকাশ থাকা সত্ত্বেও।"],
  "51:8": ["You continue to dispute the truth.","সত্যকে তোমরা বিতর্কিত করে যাচ্ছো।"],
  "51:9": ["Deviating therefrom are the deviators.","এ থেকে বিচ্যুত করে বিচ্যুতকারীরা।"],
  "51:10": ["Woe to the falsifiers.","দূর্ভোগ মিথ্যাপন্থিদের।"],
  "51:11": ["In their blundering, they are totally heedless.","তাদের ভুলের বিষয়ে, তারা সম্পূর্ণ অমনোযোগী।"],
  "51:12": ["They question the Day of Judgment.","তারা বিচারের দিনকে প্রশ্নবিদ্ধ করে।"],
  "51:13": ["The day they are presented to the fire.","সেদিন তাদেরকে আগুনের সামনে হাজির করা হয়।"],
  "51:14": ["Taste the retribution; this is what you used to challenge.","আস্বাদন করো শাস্তি; একেই তোমরা চ্যালেঞ্জ করতে।"],
  "51:15": ["The righteous have deserved gardens and springs.","সৎকর্মশীলরা বাগান ও ঝর্ণাগুলো অর্জন করেছে।"],
  "51:16": ["They receive their Lord's rewards, for they used to be pious.","তারা তাদের প্রভুর পুরস্কার পায়, কারন তারা সৎকর্মশীল ছিল।"],
  "51:17": ["Rarely did they sleep the whole night.","কদাচিৎ তারা সম্পূর্ণ রাত ঘুমাতো।"],
  "51:18": ["At dawn, they prayed for forgiveness.","রাতের শেষ প্রহরে, তারা ক্ষমা প্রাপ্তির জন্য প্রার্থনা করতো।"],
  "51:19": ["A portion of their money was set aside for the beggar and the needy.","তাদের অর্থের একটি অংশ আলাদা থাকতো ভিক্ষুক ও অভাবগ্রস্তদের জন্য।"],
  "51:20": ["The earth is full of signs for those who are certain.","যারা নিশ্চিত, তাদের জন্য ভরপুর নিদর্শন আছে পৃথিবীতে।"],
  "51:21": ["And within yourselves; can you see?","আর তোমাদের নিজেদের মধ্যে; তোমরা কি দেখতে পাও?"],
  "51:22": ["In the heaven is your provision, and everything that is promised to you.","আকাশে আছে তোমাদের জীবিকা, এবং সবকিছু যার প্রতিশ্রুতি তোমাদেরকে দেয়া হয়।"],
  "51:23": ["By the Lord of the heaven and the earth, this is as true as the fact that you speak.","আকাশ ও পৃথিবীর প্রভুর শপথ, এটি তোমাদের কথা বলার মতোই বাস্তব সত্য।"],
  "51:24": ["Have you noted the history of Abraham's honorable guests?","তুমি কি ইব্রাহিমের সন্মানিত অতিথিদের ইতিহাস লক্ষ্য করেছ?"],
  "51:25": ["They visited him, saying, \"Peace.\" He said, \"Peace to you, strangers!\"","তার সাথে তারা সাক্ষাত করেছিল, আর বলল, “শান্তি।” সে বলল, “তোমাদের প্রতি শান্তি, অপরিচিত লোকেরা!”"],
  "51:26": ["He asked his family to prepare a fat calf.","সে তার পরিবারকে একটি মোটাতাজা বাছুর প্রস্তুত করতে বলল।"],
  "51:27": ["When he offered it to them, he remarked, \"Do you not eat?\"","যখন সে এটি তাদের খেদমতে রাখল, সে খেয়াল করে বলল, “তোমরা কি খাবে না?”"],
  "51:28": ["He harbored fear of them. They said, \"Have no fear,\" and they gave good news of a knowledgeable son.","সে তাদের ব্যাপারে মনে মনে ভয় পোষণ করলো। তারা বলল, “ভয় পেয়ো না,” এবং তারা একটি জ্ঞানবান সন্তানের সুসংবাদ দিল।"],
  "51:29": ["His wife was astonished. Noting her wrinkled face: \"I am a sterile old woman.\"","তার স্ত্রী অবাক হলো। তার মুখমণ্ডলে কুঞ্চিত ভাব নিয়ে: “আমি এক বৃদ্ধ বন্ধ্যা।\""],
  "51:30": ["They said, \"Thus said your Lord. He is the Most Wise, the Omniscient.\"","তারা বলল, “এমনি তোমার প্রভু বলেছেন। তিনি সবথেকে জ্ঞানী, সর্বজ্ঞ।”"],
  "51:31": ["He said, \"What are you up to, O messengers?\"","সে বলল, “তোমাদের উদ্দেশ্য কি, হে বার্তাবাহকগণ?”"],
  "51:32": ["They said, \"We have been dispatched to criminal people.","তারা বলল, “আমরা অপরাধী লোকদের প্রতি প্রেরিত হয়েছি?”"],
  "51:33": ["\"We will shower them with rocks of clay.","\"আমরা তাদের উপর কাদামাটির পাথর বর্ষণ করবো।"],
  "51:34": ["\"Marked by your Lord for the transgressors.\"","“সীমালঙ্ঘনকারীদের জন্য তোমার প্রভুর দ্বারা চিহ্নিত।”"],
  "51:35": ["We then delivered all the believers.","আমরা এরপর সকল বিশ্বাসীদের উদ্ধার করেছিলাম।"],
  "51:36": ["We did not find in it except one house of submitters.","আমরা সেখানে একটি ঘরের বেশি আত্মসমর্পণকারী পাইনি।"],
  "51:37": ["We set it up as a lesson for those who fear the painful retribution.","আমরা একে একটি শিক্ষা হিসাবে স্থাপন করেছি তাদের জন্য যারা যন্ত্রণাদায়ক শাস্তিকে ভয় পায়।"],
  "51:38": ["In Moses (there is a lesson). We sent him to Pharaoh with manifest signs.","মুসার জীবনীতে (শিক্ষা রয়েছে)। আমরা তাকে স্পষ্ট নিদর্শনসহ ফেরাউনের কাছে পাঠিয়েছিলাম ।"],
  "51:39": ["But he turned away, in arrogance, and said, \"Magician, or crazy.\"","কিন্তু সে অহংকারে মুখ ফিরিয়ে নিল, এবং বলল, “জাদুকর, অথবা উম্মাদ।”"],
  "51:40": ["Consequently, we punished him and his troops. We threw them into the sea, and he is the one to blame.","ফলস্বরূপ, আমরা তাকে ও তার সৈন্য বাহিনীকে শাস্তি দিলাম। আমরা তাদেরকে সমুদ্রে নিক্ষেপ করলাম, সে-ই ছিল দোষী ব্যাক্তি।"],
  "51:41": ["In 'Ãd (there is a lesson). We sent upon them disastrous wind.","আদ জাতির মাঝে (শিক্ষা রয়েছে)। আমরা তাদের উপর পাঠিয়েছিলাম  সর্বনাশা বায়ু।"],
  "51:42": ["Anything that it came upon was utterly destroyed.","এটি যা কিছুর উপর এসেছিল, একে সম্পূর্ণ ধ্বংস করেছিল ।"],
  "51:43": ["In Thamûd (there is a lesson). They were told, \"Enjoy temporarily.\"","সামুদ জাতির মাঝে (শিক্ষা রয়েছে)। তাদেরকে বলা হয়েছিল, “কিছুকাল উপভোগ করো।"],
  "51:44": ["They rebelled against the command of their Lord. Consequently, the lightning struck them as they looked.","তারা বিদ্রোহ করেছিল তাদের প্রভুর হুকুমের বিরুদ্ধে। ফলস্বরূপ, বজ্রপাত তাদেরকে আঘাত করেছিল যখন তারা তাকিয়েছিল।"],
  "51:45": ["They could never get up, nor were they helped.","তারা কখনই উঠে দাড়াতে পারলো না, না তারা সাহায্য পেল।"],
  "51:46": ["And the people of Noah before that; they were wicked people.","এবং তার পূর্বে নূহের লোকরা; তারা ছিল পাপী লোক।"],
  "51:47": ["We constructed the sky with our hands, and we will continue to expand it.","আমরা আকাশকে সৃষ্টি করেছি আমাদের হাত দিয়ে এবং আমরা একে সম্প্রসারিত করতে থাকবো।"],
  "51:48": ["And we made the earth habitable; a perfect design.","এবং আমরা পৃথিবীকে বানিয়েছি বাসযোগ্য; একটি নিখুঁত নকশা।"],
  "51:49": ["We created a pair (male and female) of everything, that you may take heed.","আমরা সবকিছুর একটি জোড়া (পুরুষ ও নারী) সৃষ্টি করেছি, যাতে তোমরা মনোযোগ দাও।"],
  "51:50": ["You shall escape to Allah. I am sent by Him to you as a manifest warner.","তোমরা ঈশ্বরের কাছে পলায়ন করো। আমি তোমাদের নিকট এক স্পষ্ট সতর্ককারী হিসেবে তাঁর দ্বারা প্রেরিত।"],
  "51:51": ["Do not set up besides Allah any other god. I am sent by Him to you as a manifest warner.","ঈশ্বরের পাশে অন্য কোন উপাস্য স্থাপন করো না। আমি তোমাদের কাছে এক স্পষ্ট সতর্ককারী হিসেবে তাঁর দ্বারা প্রেরিত।"],
  "51:52": ["Consistently, when a messenger went to the previous generations, they said, \"Magician,\" or, \"Crazy.\"","অনবরত, যখনি কোন বার্তাবাহক পূর্ববর্তী প্রজন্মদের কাছে গিয়েছিল, তারা বলেছিল, “জাদুকর, ” নয়তো “ঊম্মাদ।”"],
  "51:53": ["Did they make an agreement with each other? Indeed, they are transgressors.","তারা কি পরস্পর চুক্তি করেছিল? নিশ্চয়, তারা সীমালঙ্ঘনকারী।"],
  "51:54": ["You may disregard them; you cannot be blamed.","তুমি তাদের উপেক্ষা করতে পারো, তোমাকে দোষারোপ করা হবেনা ।"],
  "51:55": ["And remind, for the reminder benefits the believers.","এবং স্মরণ করিয়ে দাও, কারন স্মরণ করানো বিশ্বাসীদের উপকার করে।"],
  "51:56": ["I did not create the jinns and the humans except to worship Me alone.","একমাত্র আমার উপাসনা করার উদ্দেশ্য ছাড়া আমি জিন ও মানুষদের সৃষ্টি করিনি ।"],
  "51:57": ["I need no provisions from them, nor do I need them to feed Me.","তাদের কাছে আমার কোন জীবিকার প্রয়োজন নেই, না আমাকে খাওয়ানোর জন্য তাদেরকে আমার প্রয়োজন আছে।"],
  "51:58": ["Allah is the Provider, the Possessor of all power, the Supreme.","ঈশ্বর জীবিকাদাতা, সকল শক্তির অধিকারী, সর্বোচ্চ।"],
  "51:59": ["The transgressors have incurred the same fate as their previous counterparts; they should not challenge.","সীমালঙ্ঘনকারীরা তাদের পূর্ববর্তী অনুরূপদের মতো একই ভাগ্য টেনে এনেছে; তাদের উচিত নয় চ্যালেঞ্জ করা।"],
  "51:60": ["Woe to those who disbelieved from the day that is awaiting them.","তাদের প্রতি দুঃখ যারা অবিশ্বাস করে সেই দিনকে যা তাদের জন্য অপেক্ষা করছে।"],
  "52:1": ["Mt. Sinai.","সিনাই পর্বত।"],
  "52:2": ["The recorded scripture.","লিপিবদ্ধ সে ঐশীগ্রন্থ।"],
  "52:3": ["Published in books.","বইপত্র আকারে প্রকাশিত।"],
  "52:4": ["The frequented Shrine.","আবাদকৃত সে তীর্থস্থান।"],
  "52:5": ["The exalted ceiling.","সুউচ্চ সে ছাদ।"],
  "52:6": ["The sea that is set aflame.","সে সমুদ্র যা প্রজ্বলিত করা হয়।"],
  "52:7": ["Your Lord's requital is unavoidable.","তোমার প্রভুর প্রতিশোধ অনিবার্য।"],
  "52:8": ["No force in the universe can stop it.","মহাবিশ্বের কোন শক্তি একে থামাতে পারে না।"],
  "52:9": ["The day will come when the sky will violently thunder.","সেদিন আসবে যখন আকাশ প্রচণ্ড বজ্রপাত ঘটাবে।"],
  "52:10": ["The mountains will be wiped out.","পর্বতগুলো মুছে ফেলা হবে।"],
  "52:11": ["Woe on that day to the disbelievers—","ঐদিন দূর্ভোগ অবিশ্বাসীদের-"],
  "52:12": ["who are in their blundering, heedless.","যারা তাদের ভুলের মাঝে, অসতর্ক।"],
  "52:13": ["They will be herded into Gehenna, forcibly.","তাদেরকে একত্রে জাহান্নামের দিকে নিয়ে যাওয়া হবে, বলপূর্বক।"],
  "52:14": ["This is the Fire in which you used to disbelieve.","এটা-ই সে আগুন যাতে তোমরা অবিশ্বাস করতে।"],
  "52:15": ["Is this magic, or do you not see?","এটা কি জাদু, নাকি তোমরা দেখো না?"],
  "52:16": ["Suffer the burning. Whether you are patient or impatient, it will be the same for you. This is the just requital for what you did.","অগ্নিদহন ভোগ করো। তোমরা ধৈর্য্য ধরো অথবা অধৈর্য্য হও, তা তোমাদের জন্য সমান হবে। তোমরা যা করেছ এটি তার সঠিক প্রতিফল।"],
  "52:17": ["The righteous have deserved gardens and bliss.","সৎকর্মশীলরা অর্জন করেছে বাগানগুলো ও পরম সুখ।"],
  "52:18": ["They enjoy what their Lord has reserved for them; their Lord has spared them the retribution of Hell.","তারা উপভোগ করে যা তাদের প্রভু তাদের জন্য সংরক্ষিত রেখেছেন; তাদের প্রভু তাদেরকে নরকের আগুন থেকে নিষ্কৃতি দিয়েছেন।"],
  "52:19": ["Eat and drink happily, in return for your works.","খুশি মনে খাও ও পান করো, তোমাদের কাজের বিনিময়ে।"],
  "52:20": ["They relax on luxurious furnishings, and we match them with beautiful spouses.","তারা বিলাসবহুল আসবাবপত্রে আরাম করে এবং আমরা তাদেরকে সুন্দর সঙ্গী দিয়ে জুড়বো।"],
  "52:21": ["For those who believed, and their children also followed them in belief, we will have their children join them. We never fail to reward them for any work. Every person is paid for what he did.","তাদের জন্য যারা বিশ্বাস করেছিল এবং তাদের সন্তানেরাও বিশ্বাসে তাদের অনুসরণ করেছিল, আমরা তাদের সন্তানদের তাদের সাথে মিলিত করবো। আমরা কখনই কোন কাজের জন্য তাদের পুরস্কার দিতে ব্যর্থ হই না। প্রত্যেক ব্যক্তি যা সে করেছিল তার প্রাপ্য পায়।"],
  "52:22": ["We will supply them with fruits and meats that they love.","আমরা তাদেরকে সরবরাহ করবো ফল ও মাংস যা তারা ভালবাসে।"],
  "52:23": ["They will enjoy drinks that are never polluted, and never sinful to drink.","তারা উপভোগ করবে পানীয় যেগুলো কখনো দূষিত নয়, আর পান করা কখনো পাপ নয়।"],
  "52:24": ["Serving them will be servants like protected pearls.","তাদের সেবায় থাকবে সুরক্ষিত মুক্তার মতো সেবকরা।"],
  "52:25": ["They will meet each other and reminisce among themselves.","তারা পরস্পরের সাথে সাক্ষাত করবে এবং নিজেদের মধ্যে স্মৃতিচারণ করবে।"],
  "52:26": ["They will say, \"We used to be kind and humble among our people.","তারা বলবে, “আমরা আমাদের লোকদের মধ্যে দয়ালু ও নম্র ছিলাম।"],
  "52:27": ["\"Allah has blessed us, and has spared us the agony of ill winds.","“ঈশ্বর আমাদেরকে অনুগ্রহ করেছেন এবং মন্দ বাতাসের নিদারুন যন্ত্রণা থেকে আমাদের নিষ্কৃতি দিয়েছেন।"],
  "52:28": ["\"We used to implore Him; He is the Most Kind, Most Merciful.\"","“আমরা তাঁর কাছে মিনতি করতাম; তিনি পরম দয়ালু, পরম করুনাময়।\""],
  "52:29": ["You shall remind the people. With your Lord's blessings upon you, you are neither a soothsayer, nor crazy.","তুমি লোকদের স্মরণ করিয়ে দাও। তোমার প্রতি তোমার প্রভুর অনুগ্রহে, না তুমি গণক, না উম্মাদ।"],
  "52:30": ["They may say, \"He is a poet; let us just wait until he is dead.\"","তারা বলতে পারে, “সে একজন কবি; চল আমরা শুধু তার মৃত্যু পর্যন্ত অপেক্ষা করি।”"],
  "52:31": ["Say, \"Go on waiting; I will wait along with you.\"","বল, “যাও অপেক্ষা করো; আমিও তোমাদের সাথে অপেক্ষা করবো।”"],
  "52:32": ["Is it their dreams that dictate their behavior, or are they naturally wicked?","তাদের স্বপ্নই কি তাদের আচরণ নির্দেশ করে নাকি তারা স্বভাবতই মন্দ?"],
  "52:33": ["Do they say, \"He made it all up?\" Instead, they are simply disbelievers.","তারা কি বলে, “সে এর সবই বানিয়েছে?” নাকি, তারা কেবলই অবিশ্বাসী।"],
  "52:34": ["Let them produce a Hadith like this, if they are truthful.","তারা এর মতো একটি হাদিস তৈরি করুক, যদি তারা সত্যবাদী হয়।"],
  "52:35": ["Were they created from nothing? Are they the creators?","তারা কি শূন্য থেকে সৃষ্টি হয়েছে? তারা কি সৃষ্টিকর্তা?"],
  "52:36": ["Did they create the heavens and the earth? Indeed, they have no certainty.","তারা কি আকাশমণ্ডলী ও পৃথিবী সৃষ্টি করেছিল? প্রকৃতপক্ষে, তারা কোন বিষয়ে নিশ্চিত নয়।"],
  "52:37": ["Do they possess the treasures of your Lord? Are they in control?","তাদের কাছে কি তোমার প্রভুর ধনভাণ্ডার আছে? তারা কি নিয়ন্ত্রনে রয়েছে?"],
  "52:38": ["Do they climb a ladder that enables them to listen? Let their listeners show their proof.","তারা কি এমন সিঁড়ি বেয়ে ওঠে যা তাদের শুনতে সাহায্য করে? তাদের শ্রবণকারীরা তাদের প্রমাণ দেখাক।"],
  "52:39": ["Does He have daughters, while you have sons?","তাঁর কি কন্যা আছে, যখন তোমাদের আছে পুত্র?"],
  "52:40": ["Are you asking them for any wage, and they are burdened thereby?","তুমি কি তাদের কাছে কোন পারিশ্রমিক চাচ্ছো, এবং তারা এর দ্বারা ভারগ্রস্থ?"],
  "52:41": ["Do they know the future, and have it recorded?","তারা কি ভবিষ্যৎ জানে, আর তা নথিভুক্ত করেছে?"],
  "52:42": ["Are they plotting and scheming? The disbelievers' schemes backfire against them.","তারা কি ষড়যন্ত্রের নকশা করছে? অবিশ্বাসীদের ষড়যন্ত্র তাদের নিজেদের বিরুদ্ধেই উল্টো কাজ করে।"],
  "52:43": ["Do they have another god besides Allah? Allah be glorified, far above having partners.","তাদের কি ঈশ্বরের পাশে অন্য উপাস্য আছে? ঈশ্বর পবিত্র, অংশীদার থাকা থেকে অনেক ঊর্ধ্বে।"],
  "52:44": ["When they see masses falling from the sky, they will say, \"Piled clouds!\"","যখন তারা আকাশ থেকে বস্তুপিণ্ড পড়তে দেখবে, তারা বলবে, “পুঞ্জিভূত মেঘ!”"],
  "52:45": ["Disregard them until they meet the day in which they are struck.","তাদেরকে উপেক্ষা করো যতক্ষন না তারা সেদিনের সম্মুখীন হয় যাতে তারা আবদ্ধ হয়ে যায়।"],
  "52:46": ["On that day, their schemes will not protect them, nor will they be helped.","সে দিনে, তাদের চক্রান্ত তাদের রক্ষা করতে পারবে না, না তারা সাহায্যপ্রাপ্ত হবে।"],
  "52:47": ["Those who transgress suffer retribution here, but most of them do not know.","যারা সীমালঙ্ঘন করে তারা এখানেই শাস্তি ভোগ করে, কিন্তু তাদের অধিকাংশই জানে না।"],
  "52:48": ["You shall steadfastly persevere in carrying out your Lord's command—you are in our eyes—and glorify and praise your Lord when you get up.","তুমি তোমার প্রভুর হুকুম পালনে দৃঢ়ভাবে অধ্যবসায়ী হও- তুমি আমাদের দৃষ্টিতে আছো- এবং তোমাদের প্রভুর পবিত্রতা ঘোষণা করো ও প্রশংসা করো যখন তোমরা উঠো।"],
  "52:49": ["Also during the night glorify Him, and at dawn as the stars fade away.","এছাড়া রাতের বেলায় তাঁর পবিত্রতা ঘোষণা করো, এবং উষাতে যখন তারাগুলো মলিন হয়ে যায়।"],
  "53:1": ["As the stars fell away.","যখন তারকারাজি ঝরে পরে।"],
  "53:2": ["Your friend (Muhammad) was not astray, nor was he deceived.","তোমাদের বন্ধু (মুহাম্মদ) পথভ্রষ্ট ছিল না, না সে প্রতারিত ছিল।"],
  "53:3": ["Nor was he speaking out of a personal desire.","না সে মনগড়া কথা বলতো।"],
  "53:4": ["It was divine inspiration.","এটি ছিল ঐশ্বরিক উদ্দীপনা।"],
  "53:5": ["Dictated by the Most Powerful.","সবচেয়ে শক্তিশালী দ্বারা নির্দেশিত।"],
  "53:6": ["Possessor of all authority. From His highest height.","সকল কর্তৃত্বের অধিকারী। তাঁর সর্বোচ্চ উচ্চতা থেকে।"],
  "53:7": ["At the highest horizon.","সর্বোচ্চ দিগন্তটিতে।"],
  "53:8": ["He drew nearer by moving down.","তিনি নিচে নেমে আরও নিকটবর্তী করলেন।"],
  "53:9": ["Until He became as close as possible.","যে পর্যন্ত না তিনি যথাসম্ভব কাছাকাছি হলেন।"],
  "53:10": ["He then revealed to His servant what was to be revealed.","তিনি এরপর তাঁর বান্দার কাছে প্রকাশ করলেন যা প্রকাশ করার ছিল।"],
  "53:11": ["The mind never made up what it saw.","মন কখনোই কল্পনা করেনি যা সে দেখেছিল।"],
  "53:12": ["Are you doubting what he saw?","যা সে দেখেছিল তাতে কি তোমরা সন্দেহ করছো?"],
  "53:13": ["He saw him in another descent.","তিনি তাকে দেখেছিলেন অন্য এক অবতরণে।"],
  "53:14": ["At the ultimate point.","পরম স্থানটিতে।"],
  "53:15": ["Where the eternal Paradise is located.","যেখানে চিরস্থায়ী স্বর্গ অবস্থিত।"],
  "53:16": ["The whole place was overwhelmed.","সম্পূর্ণ স্থানটি অভিভূতময় ছিল।"],
  "53:17": ["The eyes did not waver, nor go blind.","চোখগুলো দ্বিধাগ্রস্ত হয়নি, না হয়েছিল অন্ধ।"],
  "53:18": ["He saw great signs of his Lord.","সে তাঁর প্রভুর মহা নিদর্শনাবলি দেখেছিল।"],
  "53:19": ["Compare this with the female idols Allaat and Al-'Uzzah.","একে তুলনা করো উদ্ভাবিত নারী উপাস্য আলা'ত ও আল-উযযাহ- এর সাথে।"],
  "53:20": ["And Manaat, the third one.","এবং মানা'ত, তৃতীয় জন।"],
  "53:21": ["Do you have sons, while He has these as daughters?","তোমাদের কি পুত্র আছে যখন তাঁর এগুলো আছে কন্যা হিসেবে?"],
  "53:22": ["What a disgraceful distribution!","কি এক অসন্মানকর বণ্টন!"],
  "53:23": ["These are but names that you made up, you and your forefathers. Allah never authorized such a blasphemy. They follow conjecture, and personal desire, when the true guidance has come to them herein from their Lord.","এগুলো কেবলই নাম যা তোমরা বানিয়েছ, তোমরা আর তোমাদের পিতৃপুরুষরা। আল্লাহ কখনোই এমন মিথ্যাচারের অনুমোদন দেননি। তারা অনুসরণ করে অনুমানের, এবং ব্যক্তিগত ইচ্ছার, যখন এখানে তাদের প্রভুর পক্ষ থেকে সত্য পথনির্দেশনা এসেছে।"],
  "53:24": ["What is it that the human being desires?","মানুষ আসলে কি চায়?"],
  "53:25": ["To Allah belongs both the Hereafter, and this world.","পরকাল ও এই দুনিয়া উভয়ই ঈশ্বরের অধীনে।"],
  "53:26": ["Not even the angels in heaven possess authority to intercede. The only ones permitted by Allah are those who act in accordance with His will and His approval.","এমনকি স্বর্গের ফেরেশতাদেরও সুপারিশ করার অধিকার নেই। কেবল সে লোকেরাই ঈশ্বর দ্বারা অনুমোদিত যারা তাঁর ইচ্ছা ও তাঁর অনুমোদন অনুসারে কাজ করে।"],
  "53:27": ["Those who disbelieve in the Hereafter have given the angels feminine names.","পরকালে যারা অবিশ্বাস করে তারা ফেরেশতাদের নারীবাচক নাম দিয়েছে।"],
  "53:28": ["They had no knowledge about this; they only conjectured. Conjecture is no substitute for the truth.","এ বিষয়ে তাদের কোন জ্ঞান ছিল না; তারা কেবল অনুমান করেছিল। অনুমান সত্যের কোন বিকল্প নয়।"],
  "53:29": ["You shall disregard those who turn away from our message, and become preoccupied with this worldly life.","তুমি তাদেরকে উপেক্ষা করো যারা আমাদের বার্তা থেকে মুখ ফিরিয়ে নেয় এবং দুনিয়ার এই জীবন নিয়ে মোহাচ্ছন্ন হয়ে থাকে।"],
  "53:30": ["This is the extent of their knowledge. Your Lord is fully aware of those who strayed away from His path, and He is fully aware of those who are guided.","এটা তাদের জ্ঞানের সীমা। তোমার প্রভু তাদের বিষয়ে সম্পূর্ণ অবগত যারা তাঁর পথ থেকে পথভ্রষ্ট হয়েছে, এবং তিনি তাদের বিষয়ে সম্পূর্ণ অবগত যারা সুপথপ্রাপ্ত।"],
  "53:31": ["To Allah belongs everything in the heavens and everything on earth. He will requite those who commit evil for their works, and will reward the righteous for their righteousness.","আকাশমণ্ডলীর সবকিছু ও পৃথিবীর সবকিছু ঈশ্বরের। যারা মন্দ কাজ করে তিনি তাদের প্রতিফল দেবেন আর সৎকর্মশীলদের পুরস্কৃত করবেন তাদের সৎকর্মশীলতার জন্য।"],
  "53:32": ["They avoid gross sins and transgressions, except for minor offenses. Your Lord's forgiveness is immense. He has been fully aware of you since He initiated you from the earth, and while you were embryos in your mothers' bellies. Therefore, do not exalt yourselves; He is fully aware of the righteous.","তারা স্পষ্ট পাপ ও সীমালঙ্ঘন এড়িয়ে চলে, ছোটখাটো অপরাধসমূহ ব্যতীত। তোমার প্রভুর ক্ষমাশীলতা বিশাল। তখন থেকেই তিনি তোমাদের সম্পর্কে পূর্ণ অবগত যখন পৃথিবী থেকে তিনি তোমাদের সূচনা করেছিলেন , আর যখন তোমরা তোমাদের মায়ের পেটে ভ্রুন ছিলে। সুতরাং, নিজেকে নিয়ে বড়াই করো না; তিনি সৎকর্মশীলদের ব্যাপারে পূর্ণ অবগত।"],
  "53:33": ["Have you noted the one who turned away?","তুমি কি সে ব্যক্তির দিকে খেয়াল করেছ যে মুখ ফিরিয়ে নিয়েছিল?"],
  "53:34": ["Rarely did he give to charity, and then very little.","কদাচিৎ সে দান করতো আর তা-ও খুব সামান্য।"],
  "53:35": ["Did he possess knowledge of the future? Could he see it?","তার কি ভবিষ্যত জ্ঞান ছিল? সে কি তা দেখতে পারতো?"],
  "53:36": ["Was he not informed of the teachings in the scripture of Moses?","সে কি অবগত ছিল না মুসার ঐশীগ্রন্থের শিক্ষার বিষয়ে?"],
  "53:37": ["And Abraham who fulfilled?","আর ইব্রাহিমের যে পূর্ণ করেছিল?"],
  "53:38": ["No soul bears the sins of another soul.","কোন আত্মা অন্য আত্মার পাপ বহন করে না।"],
  "53:39": ["Every human being is responsible for his own works.","প্রত্যেক মানুষ তার নিজের কাজের জন্য দায়ী।"],
  "53:40": ["And everyone's works will be shown.","এবং প্রত্যেকের কাজগুলো দেখানো হবে।"],
  "53:41": ["Then they will be paid fully for such works.","এরপর তাদের এসব কাজের জন্য পূর্ণ প্রাপ্য দেয়া হবে।"],
  "53:42": ["To your Lord is the final destiny.","তোমার প্রভুর দিকেই চূড়ান্ত নিয়তি।"],
  "53:43": ["He is the One who makes you laugh or cry.","তিনিই সে সত্ত্বা যিনি তোমাদের হাসান ও কাঁদান।"],
  "53:44": ["He is the One who controls death and life.","তিনিই সে সত্ত্বা যিনি মৃত্যু ও জীবন নিয়ন্ত্রণ করেন।"],
  "53:45": ["He is the One who created the two kinds, male and female—","তিনিই সে সত্ত্বা যিনি সৃষ্টি করেছেন দুই প্রকার, পুরুষ ও নারী-"],
  "53:46": ["from a tiny drop of semen.","এক অতি ক্ষুদ্র বীর্যের ফোঁটা থেকে।"],
  "53:47": ["He will effect the recreation.","তিনি পুনঃসৃষ্টি ঘটাবেন।"],
  "53:48": ["He is the One who makes you rich or poor.","তিনিই সে সত্ত্বা যিনি তোমাদের ধনী অথবা দরিদ্র করেন।"],
  "53:49": ["He is the Lord of the galaxies.","তিনি নক্ষত্রপুঞ্জের প্রভু।"],
  "53:50": ["He is the One who annihilated ancient 'Ãd.","তিনিই সে সত্ত্বা যিনি প্রাচীন “আদ” সম্প্রদায়কে বিলুপ্ত করেছিলেন।"],
  "53:51": ["And wiped out Thamûd.","এবং মুছে দিয়েছিলেন ‘সামুদ’ সম্প্রদায়কে।"],
  "53:52": ["Also the people of Noah before that; they were evil transgressors.","এছাড়া এর পূর্বে নূহের লোকদের; তারা ছিল মন্দ সীমালঙ্ঘনকারী।"],
  "53:53": ["The evil communities (of Sodom and Gomorrah) were the lowliest.","ছডম ও গোমোরা -এর) দুষ্ট জনপদগুলো ছিল সবচেয়ে নীচু।"],
  "53:54": ["Consequently, they utterly vanished.","ফলস্বরুপ, তারা একদম নিশ্চিহ্ন হয়েছিল।"],
  "53:55": ["Which of your Lord's marvels can you deny?","তোমার প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পারো?"],
  "53:56": ["This is a warning like the older ones.","এটি একটি সতর্কবানী পুরনোগুলোর মতো।"],
  "53:57": ["The inevitable is imminent.","অনিবার্য সময়টি আসন্ন।"],
  "53:58": ["None besides Allah can relieve it.","ঈশ্বর ব্যতিত কেউ তা প্রকাশ করতে পারে না।"],
  "53:59": ["Are you questioning this matter?","তোমরা কি এ বিষয়ে প্রশ্ন করছো?"],
  "53:60": ["Are you laughing, instead of crying?","তোমরা কি কান্নার বদলে হাসছো?"],
  "53:61": ["Are you insisting on your ways?","তোমরা কি তোমাদের পথে গোঁ ধরে আছো?"],
  "53:62": ["You shall fall prostrate before Allah, and worship.","তোমরা ঈশ্বরের সামনে সেজদাবনত হও, এবং উপাসনা করো।"],
  "54:1": ["The Hour has come closer, and the moon has split.","সে সময় নিকটবর্তি হয়েছে, এবং চাঁদ বিভক্ত হয়েছে।"],
  "54:2": ["Then they saw a miracle; but they turned away and said, \"Old magic.\"","তারপর তারা একটি অলৌকিক নিদর্শন দেখল; কিন্তু তারা মুখ ফিরিয়ে নিল এবং বলল, “পুরনো জাদু”।"],
  "54:3": ["They disbelieved, followed their opinions, and adhered to their old traditions.","তারা অবিশ্বাস করলো, তাদের মতের অনুসরণ করলো এবং তাদের পুরনো প্রথায় লেগে থাকলো।"],
  "54:4": ["Sufficient warnings have been delivered to alert them.","তাদের সাবধান করতে যথেষ্ট সতর্কবানী প্রদান করা হয়েছে।"],
  "54:5": ["Great wisdom; but all the warnings have been in vain.","বিশাল প্রজ্ঞা; কিন্তু সকল সতর্কবানী বিফল হয়েছে।"],
  "54:6": ["Ignore them; the day will come when the caller will announce a terrible disaster.","তাদের উপেক্ষা করো; সেদিন আসবে যখন আহবানকারী এক ভয়াবহ দুর্যোগের ঘোষণা দিবে।"],
  "54:7": ["With their eyes humiliated, they come out of the graves like scattered locusts.","তাদের অপমানিত চোখগুলো নিয়ে, তারা কবর থেকে বেরিয়ে আসে বিক্ষিপ্ত পঙ্গপালের মতো।"],
  "54:8": ["As they respond to the caller, the disbelievers will say, \"This is a difficult day.\"","যখন তারা আহবানকারীর ডাকে সাড়া দেবে, অবিশ্বাসীরা বলবে, “এ এক কঠিন দিন।”"],
  "54:9": ["The people of Noah disbelieved before them. They disbelieved our servant and said, \"Crazy!\" He was persecuted.","তাদের আগে নূহের লোকেরা অবিশ্বাস করেছিল। তারা আমাদের বান্দাকে অবিশ্বাস করেছিল আর বলেছিল, “উন্মাদ!” তার উপর নির্যাতন করা হয়েছিল।"],
  "54:10": ["He implored his Lord, \"I am oppressed; grant me victory.\"","সে তার প্রভুর কাছে মিনতি করলো, “আমি নির্যাতিত; আমাকে বিজয় দিন।”"],
  "54:11": ["We then opened the gates of the sky, pouring water.","আমরা তখন আকাশের দরজাগুলো খুলে দিয়েছিলাম, পানি বর্ষণ করতে।"],
  "54:12": ["And we caused springs to gush out of the earth. The waters met to effect a predetermined decision.","এবং আমরা পৃথিবী থেকে সজোরে ঝর্ণা প্রবাহিত করেছিলাম। পানিগুলো এক পূর্বনির্ধারিত সিদ্ধান্ত কার্যকর করতে।"],
  "54:13": ["We carried him on a watercraft made of logs and ropes.","আমরা তাকে গাছের গুড়ি ও দড়ি দিয়ে নির্মিত জলযানে চড়িয়েছিলাম।"],
  "54:14": ["It ran under our watchful eyes; a reward for one who was rejected.","এটি চলেছিল আমাদের সতর্ক দৃষ্টির আওতায়; সে ব্যক্তির জন্য পুরষ্কার যাকে প্রত্যাখান করা হয়েছিল।"],
  "54:15": ["We have set it up as a lesson. Does any of you wish to learn?","একে আমরা একটি শিক্ষা হিসেবে স্থাপন করেছি। তোমাদের কেউ কি শিখতে চাও?"],
  "54:16": ["How terrible was My retribution after the warnings!","সতর্কবানীর পর কত ভয়াবহ ছিল আমার শাস্তি!"],
  "54:17": ["We made the Quran easy to learn. Does any of you wish to learn?","আমরা কুরআনকে শেখার জন্য সহজ করেছি। তোমাদের কেউ কি শিখতে চাও?"],
  "54:18": ["Ãd disbelieved. Consequently, how terrible was My retribution after the warnings.","আদ জাতি অবিশ্বাস করেছিল। পরিনামে, সতর্কবানীর পর কত ভয়াবহ ছিল আমার শাস্তি।"],
  "54:19": ["We sent upon them violent winds, on a day of continuous misery.","আমরা তাদের উপর প্রবল বাতাস প্রেরন করেছিলাম, এক অবিরাম দুর্দশার দিনে।"],
  "54:20": ["It tossed the people around as if they were decayed palm tree trunks.","এটি লোকদের চারদিকে ছুড়ে ফেলেছিল যেন তারা ছিল জীর্ণশীর্ণ খেজুর গাছের গুড়ি।"],
  "54:21": ["How terrible was My retribution after the warnings!","সতর্কবানীর পর কত ভয়াবহ ছিল আমার শাস্তি!"],
  "54:22": ["We made the Quran easy to learn. Does any of you wish to learn?","আমরা কুরআনকে শেখার জন্য সহজ করেছি। তোমাদের কেউ কি শিখতে চাও?"],
  "54:23": ["Thamûd rejected the warnings.","সামুদ জাতি সতর্ক-বাণী প্রত্যাখ্যান করেছিল।"],
  "54:24": ["They said, \"Shall we follow one of us; a human being? We will then go astray, then end up in Hell.","তারা বলেছিল, “আমরা কি অনুসরণ করবো আমাদেরই একজনকে; একজন মানুষকে? আমরা তাহলে পথভ্রষ্ট হবো, এরপর শেষ পর্যন্ত নরকে যাবো।"],
  "54:25": ["\"Did the message come down to him, instead of us? He is a flagrant liar.\"","“বার্তা কি আমাদের পরিবর্তে তার কাছে পৌঁছাল? সে ঘোর মিথ্যাবাদী।”"],
  "54:26": ["They will find out tomorrow who the flagrant liar is.","আগামীকাল তারা দেখতে পাবে কে ঘোর মিথ্যাবাদী।"],
  "54:27": ["We are sending the camel as a test for them. Watch them and be patient.","আমরা উটকে তাদের জন্য পরীক্ষা হিসেবে পাঠাচ্ছি। তাদের প্রতি দৃষ্টি রাখো এবং ধৈর্য ধর।"],
  "54:28": ["Inform them that the water shall be divided among them; (the camel) shall be allowed to drink on her designated day.","তাদেরকে জানাও যে পানি তাদের মধ্যে ভাগ করে দেয়া হবে; (উটটি) তার জন্য নির্দিষ্ট দিনে পানি পানের অনুমতি পাবে।"],
  "54:29": ["But they persuaded their friend to kill (the camel), and he obliged.","কিন্তু তারা (উটটিকে) হত্যা করতে তাদের বন্ধুকে প্ররোচিত করলো, আর সে রাজি হয়েছিল।"],
  "54:30": ["Consequently, how terrible was My retribution! They have been warned.","পরিণামে, কত ভয়াবহ ছিল আমার শাস্তি! তাদেরকে সতর্ক করা হয়েছিল।"],
  "54:31": ["We sent upon them one blow, whereupon they became like harvested hay.","আমরা তাদের উপর পাঠিয়েছিলাম বায়ুপ্রবাহ, যার ফলে তারা কর্তিত খড়কুটোর মতো হয়ে গিয়েছিল ।"],
  "54:32": ["We made the Quran easy to learn. Does any of you wish to learn?","আমরা কুরআনকে শেখার জন্য সহজ করেছি। তোমাদের কেউ কি শিখতে চাও?"],
  "54:33": ["The people of Lot rejected the warnings.","লুতের লোকেরা সতর্কবানী প্রত্যাখ্যান করেছিল।"],
  "54:34": ["We showered them with rocks. Only Lot's family was saved at dawn.","আমরা তাদের উপর পাথর বর্ষণ করেছিলাম। শুধু লুতের পরিবারকে ভোর-বেলায় রক্ষা করা হয়েছিল।"],
  "54:35": ["We blessed him and his family; we thus reward the appreciative.","আমরা তাকে ও তার পরিবারকে সৌভাগ্যশালী করেছিলাম; আমরা এভাবে কৃতজ্ঞদের পুরস্কৃত করি।"],
  "54:36": ["He warned them about our requital, but they ridiculed the warnings.","সে তাদেরকে আমাদের প্রতিশোধের বিষয়ে সতর্ক করেছিল, কিন্তু তারা সতর্কবার্তাকে উপহাস করেছিল।"],
  "54:37": ["They negotiated with him about his guests; we blinded them. Suffer My retribution; you have been warned.","তারা তার মেহমানদের বিষয়ে তার সাথে স্বার্থপর আলোচনা করেছিল; আমরা তাদের অন্ধ করে দিয়েছিলাম। আমার শাস্তি ভোগ কর; তোমাদের সতর্ক করা হচ্ছিল।"],
  "54:38": ["Early the next morning, a devastating retribution struck them.","পরের দিন খুব ভোরে, এক বিধ্বংসী শাস্তি তাদের উপর আঘাত হানলো।"],
  "54:39": ["Suffer My retribution; you have been warned.","আমার শাস্তি ভোগ করো; তোমাদের সতর্ক করা হচ্ছিল।"],
  "54:40": ["We made the Quran easy to learn. Does any of you wish to learn?","আমরা কুরআনকে শেখার জন্য সহজ করেছি। তোমাদের কেউ কি শিখতে চাও?"],
  "54:41": ["Pharaoh's people were warned.","ফেরাউনের লোকদের সতর্ক করা হয়েছিল।"],
  "54:42": ["They rejected all our signs. Consequently, we requited them as an Almighty, Omnipotent should.","তারা আমাদের সকল নিদর্শন প্রত্যাখ্যান করেছিল। পরিণামে, আমরা তাদের থেকে তেমন প্রতিশোধ নিয়েছিলাম যেমন একজন সর্বশক্তিমান, সর্বজ্ঞের উচিৎ।"],
  "54:43": ["Are your disbelievers better than those disbelievers? Have you been absolved by the scripture?","তোমাদের অবিশ্বাসীরা কি ঐসব অবিশ্বাসীদের থেকে উত্তম? ঐশীগ্রন্থ কি তোমাদের পাপ-মুক্ত করে দিয়েছে?"],
  "54:44": ["Perhaps they think, \"We will be the winners.\"","সম্ভবত তারা ভাবে, “আমরাই জয়ী হব।”"],
  "54:45": ["All of them will be defeated; they will turn around and flee.","তাদের সকলে পরাজিত হবে; তারা মুখ ফিরিয়ে নিবে আর পালাবে।"],
  "54:46": ["The Hour is awaiting them, and the Hour is far worse and more painful.","সে ঘণ্টা তাদের জন্য অপেক্ষা করছে আর সে ঘণ্টা অধিক মন্দ এবং অধিক যন্ত্রণাদায়ক।"],
  "54:47": ["Certainly, the guilty are astray, and will end up in Hell.","নিশ্চয়, অপরাধীরা পথভ্রষ্ট, আর শেষ পর্যন্ত নরকে যাবে।"],
  "54:48": ["They will be dragged into the hellfire, forcibly. Suffer the agony of retribution.","তাদেরকে নরকের আগুনে টেনে নিয়ে যাওয়া হবে, বলপূর্বক। শাস্তির যন্ত্রনা ভোগ কর।"],
  "54:49": ["Everything we created is precisely measured.","আমাদের সৃষ্ট সবকিছু সঠিকভাবে পরিমিত।"],
  "54:50": ["Our commands are done within the blink of an eye.","আমাদের হুকুম চোখের এক পলকেই সম্পন্ন হয়।"],
  "54:51": ["We annihilated your counterparts. Does any of you wish to learn?","আমরা তোমাদের অনুরূপ ব্যক্তিদের ধ্বংস করেছিলাম। তোমরা কেউ কি শিখতে চাও?"],
  "54:52": ["Everything they did is recorded in the scriptures.","তারা যা কিছু করেছিল তা ঐশীগ্রন্থগুলোতে লিপিবদ্ধ রয়েছে।"],
  "54:53": ["Everything, small or large, is written down.","সবকিছু, ছোট অথবা বড় লিপিবদ্ধ করা হয়।"],
  "54:54": ["Surely, the righteous have deserved gardens and rivers.","নিশ্চয়, সৎকর্মশীলরা বাগান ও নদীগুলো লাভের যোগ্য।"],
  "54:55": ["In a position of honor, at an Omnipotent King.","সন্মানজনক একটি অবস্থানের, একজন সর্বশক্তিমান রাজার কাছে।"],
  "55:1": ["The Most Gracious.","পরম করুণাময়।"],
  "55:2": ["Teacher of the Quran.","কুরআনের শিক্ষক।"],
  "55:3": ["Creator of the human beings.","মানুষের সৃষ্টিকর্তা।"],
  "55:4": ["He taught them how to distinguish.","তিনি তাদেরকে শিখিয়েছেন কিভাবে পার্থক্য করতে হয়।"],
  "55:5": ["The sun and the moon are perfectly calculated.","সূর্য ও চাঁদ নিখুঁতভাবে গণনাকৃত।"],
  "55:6": ["The stars and the trees prostrate.","তারকারাজি ও বৃক্ষকূল সেজদা করে।"],
  "55:7": ["He constructed the sky and established the law.","তিনি আকাশ সৃষ্টি করেছেন এবং আইন প্রতিষ্ঠা করেছেন।"],
  "55:8": ["You shall not transgress the law.","তোমরা আইনের সীমা অতিক্রম করো না।"],
  "55:9": ["You shall establish justice; do not violate the law.","তোমরা ন্যায় বিচার প্রতিষ্ঠা কর; আইন লঙ্ঘন কর না।"],
  "55:10": ["He created the earth for all creatures.","তিনি সকল সৃষ্টির জন্য পৃথিবী সৃষ্টি করেছেন।"],
  "55:11": ["In it there are fruits, and date palms with their hanging fruit.","এতে রয়েছে ফল-ফলাদি, এবং খেজুর গাছ - এদের ঝুলন্ত ফলসহ।"],
  "55:12": ["Also grains and the spices.","আরও আছে খাদ্যশস্য ও মসলা।"],
  "55:13": ["(O humans and jinns,) which of your Lord's marvels can you deny?","(হে মানুষ ও জিন) তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:14": ["He created the human from aged clay, like the potter's clay.","তিনি মানুষকে সৃষ্টি করেছেন, কুমোরের কাঁদা সদৃশ পুরনো কাঁদা থেকে।"],
  "55:15": ["And created the jinns from blazing fire.","এবং জিনদের সৃষ্টি করেছেন জ্বলন্ত আগুন থেকে।"],
  "55:16": ["(O humans and jinns,) which of your Lord's marvels can you deny?","(হে মানুষ ও জিন) তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:17": ["Lord of the two easts and the two wests.","দুই পূর্ব এবং দুই পশ্চিমের প্রভু।"],
  "55:18": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:19": ["He separates the two seas where they meet.","তিনি দুই সাগরকে আলাদা করেন যখন এরা মিলিত হয়।"],
  "55:20": ["A barrier is placed between them, to prevent them from transgressing.","এদের মধ্যে একটি দেয়াল রাখা হয়, যা এদেরকে সীমাতিক্রমে বাধা দেয়।"],
  "55:21": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:22": ["Out of both of them you get pearls and coral.","এদের উভয়ের থেকে তোমরা মুক্তা ও প্রবাল পাও।"],
  "55:23": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:24": ["He gave you ships that roam the sea like flags.","তিনি তোমাদেরকে জাহাজ দিয়েছেন যা পতাকার মত সাগরে ঘুরে বেড়ায়।"],
  "55:25": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:26": ["Everyone on earth perishes.","পৃথিবীর প্রত্যেকে ধ্বংসশীল।"],
  "55:27": ["Only the presence of your Lord lasts. Possessor of Majesty and Honor.","কেবলমাত্র তোমার প্রভুর উপস্থিতি স্থায়ী হয়। যিনি রাজকীয় ক্ষমতা ও সন্মানের অধিকারী।"],
  "55:28": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:29": ["Imploring Him is everyone in the heavens and the earth. Every day He is in full control.","আকাশমণ্ডলী ও পৃথিবীর সকলে তাঁর কাছে মিনতি করে। প্রত্যেক দিন তিনি সম্পূর্ণ নিয়ন্ত্রনরত।"],
  "55:30": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:31": ["We will call you to account, O humans and jinns.","হে মানুষ ও জিন, আমরা তোমাদের হিসাবের জন্য ডাকবো।"],
  "55:32": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:33": ["O you jinns and humans, if you can penetrate the outer limits of the heavens and the earth, go ahead and penetrate. You cannot penetrate without authorization.","হে জীন ও মানুষ, যদি তোমরা আকাশমণ্ডলী ও পৃথিবীর শেষ সীমা ভেদ করতে পারো, তবে এগিয়ে যাও আর ভেদ করো।  অনুমোদন ছাড়া তোমরা প্রবেশ করতে পারো না।"],
  "55:34": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:35": ["You get bombarded with projectiles of fire and metal, and you cannot win.","তোমরা আগুন ও ধাতুর গোলাবর্ষণে ধ্বংসপ্রাপ্ত হও, এবং তোমরা জয়ী হতে পারো না।"],
  "55:36": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:37": ["When the sky disintegrates, and turns rose colored like paint.","যখন আকাশ ভেঙ্গে যায় এবং রঙের মতো গোলাপি বর্ণ ধারণ করে।"],
  "55:38": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:39": ["On that day, no human, nor a jinn, will be asked about his sins.","ঐ দিন, না কোন মানুষ, না কোন জীন, তার পাপ সম্পর্কে জিজ্ঞাসিত হবে।"],
  "55:40": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:41": ["(This is because) the guilty will be recognized by their looks; they will be taken by the forelocks and the feet.","(এটি এ কারনে যে) অপরাধীদেরকে তাদের অঙ্গভঙ্গি দেখে চেনা যাবে; তাদেরকে মাথার অগ্রভাগের চুল ও পা ধরে নিয়ে যাওয়া হবে।"],
  "55:42": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:43": ["This is Gehenna that the guilty used to deny.","এটা জাহান্নাম যা অপরাধীরা প্রত্যাখ্যান করতো।"],
  "55:44": ["They will circulate between it and an intolerable inferno.","এটিতে এবং এক অসহনীয় নিন্মস্তরের (হামিম) মধ্যে তারা ঘুরতে থাকবে।"],
  "55:45": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:46": ["For those who reverence the majesty of their Lord, two gardens (one for the jinns and one for the humans).","যারা তাদের প্রভুর মহিমাকে সম্মান করে তাদের জন্য, দুটি বাগান (একটি জিনদের জন্য এবং একটি মানুষদের জন্য)।"],
  "55:47": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:48": ["Full of provisions.","খাদ্যসামগ্রীতে পরিপূর্ণ।"],
  "55:49": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার"],
  "55:50": ["Two springs are in them, flowing.","এদের মধ্যে রয়েছে দুটি ঝর্ণা, প্রবাহমান।"],
  "55:51": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:52": ["Of every fruit in them, two kinds.","এদের প্রত্যেকটি ফল, দুই প্রকার।"],
  "55:53": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:54": ["While relaxing on furnishings lined with satin, the fruits are within reach.","যখন সাটিনের  আবরণযুক্ত আসবাবে আরাম করবে, ফলগুলো তখন তাদের হাতের নাগালে থাকে।"],
  "55:55": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:56": ["Their beautiful mates were never touched by any human or jinn.","তাদের সুন্দর সঙ্গিদের কখনই কোন মানুষ অথবা জিন স্পর্শ করেনি।"],
  "55:57": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:58": ["They look like gems and coral.","তারা রত্ন ও প্রবলের মত দেখতে।"],
  "55:59": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:60": ["Is the reward of goodness anything but goodness?","ভালোত্বের পুরস্কার ভালোত্ব ছাড়া কি হতে পারে?"],
  "55:61": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:62": ["Below them are two gardens (one for the jinns and one for the humans).","এদের নিচে আছে দুটি বাগান (একটি জিনদের জন্য এবং একটি মানুষদের জন্য)।"],
  "55:63": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:64": ["Side by side.","পাশাপাশি।"],
  "55:65": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:66": ["In them, wells to be pumped.","এদের মধ্যে আছে পানির কূপ যা থেকে উত্তোলন করতে হয়।"],
  "55:67": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:68": ["In them are fruits, date palms, and pomegranate.","এদের মধ্যে আছে ফল, খেজুর গাছ, এবং আনার।"],
  "55:69": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:70": ["In them are beautiful mates.","এদের মধ্যে আছে সুন্দর সঙ্গিরা।"],
  "55:71": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:72": ["Confined in the tents.","তাঁবুতে আবদ্ধ"],
  "55:73": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:74": ["No human ever touched them, nor a jinn.","কোন মানুষ কখনো তাদের স্পর্শ করেনি, না কোন জিন।"],
  "55:75": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:76": ["They relax on green carpets, in beautiful surroundings.","তারা সবুজ গালিচায় আরাম করে, সুন্দর পারিপার্শ্বিকতায়। চতুর্দিকের পরিবেষ্টনে।"],
  "55:77": ["Which of your Lord's marvels can you deny?","তোমাদের প্রভুর কোন বিস্ময়কে তোমরা অস্বীকার করতে পার?"],
  "55:78": ["Most exalted is the name of your Lord, Possessor of Majesty and Honor.","তোমার প্রভুর নাম, যিনি মহিমা ও সম্মানের অধিকারী, অত্যন্ত মহিমান্বিত"],
  "56:1": ["When the inevitable comes to pass.","যখন সে অনিবার্য ঘটনা ঘটবে।"],
  "56:2": ["Nothing can stop it from happening.","কোন কিছু এর ঘটার সময়কে থামাতে পারে না।"],
  "56:3": ["It will lower some, and raise others.","এটি কাউকে নিচে নামাবে, আর কাউকে উপরে তুলবে।"],
  "56:4": ["The earth will be shaken up.","পৃথিবীকে ঝাঁকানো হবে।"],
  "56:5": ["The mountains will be wiped out.","পর্বতমালা মুছে ফেলা হবে।"],
  "56:6": ["As if they never existed.","যেন কখনো তাদের অস্তিত্ব ছিল না।"],
  "56:7": ["You will be stratified into three kinds.","তোমরা তিন স্তরে বিভক্ত হয়ে পড়বে।"],
  "56:8": ["Those who deserved bliss will be in bliss.","যারা পরম সুখের যোগ্য তারা পরম সুখে থাকবে।"],
  "56:9": ["Those who deserved misery will be in misery.","যারা দুর্দশার যোগ্য তারা দুর্দশায় থাকবে।"],
  "56:10": ["Then there is the elite of the elite.","এরপর আছে অভিজাতদের অভিজাত।"],
  "56:11": ["They are those who will be closest (to Allah).","তারাই (ঈশ্বরের) সবচেয়ে নিকটবর্তী হবে।"],
  "56:12": ["In the gardens of bliss.","পরম সুখের বাগানগুলোতে।"],
  "56:13": ["Many from the first generations.","অনেকেই প্রথম প্রজন্মগুলো থেকে ।"],
  "56:14": ["Few from the later generations.","পরবর্তী প্রজন্মগুলো থেকে অল্প সংখ্যক।"],
  "56:15": ["On luxurious furnishings.","বিলাসবহুল আসবাবপত্রে।"],
  "56:16": ["Enjoying everything, they will be neighbors.","সবকিছু উপভোগ করে, তারা হবে প্রতিবেশী।"],
  "56:17": ["Serving them will be immortal servants.","তাদের সেবায় থাকবে অমর সেবকগন।"],
  "56:18": ["With cups, pitchers and pure drinks.","পেয়ালা, জগ এবং বিশুদ্ধ পানীয় নিয়ে।"],
  "56:19": ["They never run out, nor do they get bored.","এগুলো কখনো ফুরিয়ে যায় না, না এরা একঘেয়ে হয়ে যায়।"],
  "56:20": ["Fruits of their choice.","তাদের পছন্দের ফল-ফলাদি।"],
  "56:21": ["Meat of birds that they desire.","পাখির মাংস যা তারা আকাংখা করে।"],
  "56:22": ["Beautiful mates.","সুন্দর সঙ্গীরা।"],
  "56:23": ["Like protected pearls.","সুরক্ষিত মুক্তার মতো।"],
  "56:24": ["Rewards for their works.","তাদের কাজের জন্য পুরস্কার।"],
  "56:25": ["They never hear any nonsense therein, nor sinful utterances.","তারা কখনই সেখানে কোন ভিত্তিহীন কথা শোনে না, না পাপপূর্ণ কথাবার্তা।"],
  "56:26": ["Only the utterance: \"Peace, peace.\"","শুধু উচ্চারিত হবেঃ “শান্তি, শান্তি।”"],
  "56:27": ["Those of the right side, will be on the right side.","যারা ডান পাশের তারা ডান পাশে থাকবে।"],
  "56:28": ["In lush orchards.","ঘন ফল বাগানে।"],
  "56:29": ["Fragrant fruits.","সুগন্ধি ফল-ফলাদি।"],
  "56:30": ["Extended shade.","দীর্ঘ ছায়া।"],
  "56:31": ["Abundant water.","পর্যাপ্ত পানি।"],
  "56:32": ["Many fruits.","অনেক ফল।"],
  "56:33": ["Never ending; never forbidden.","কখনো শেষ হবার নয়; কখনো নিষিদ্ধ নয়।"],
  "56:34": ["Luxurious furnishings.","বিলাসবহুল আসবাবপত্র।"],
  "56:35": ["We create for them mates.","আমরা তাদের জন্য সঙ্গি -সঙ্গিনী সৃষ্টি করি।"],
  "56:36": ["Never previously touched.","পূর্বে কখনো স্পর্শ করা হয়নি।"],
  "56:37": ["Perfectly matched.","একেবারে মানানসই।"],
  "56:38": ["For those on the right side.","তাদের জন্য যারা ডান পাশের।"],
  "56:39": ["Many from the early generations.","অনেকেই প্রথমদিককার প্রজন্মগুলো থেকে।"],
  "56:40": ["Many from the later generations.","অনেকেই পরবর্তী প্রজন্মগুলো থেকে।"],
  "56:41": ["Those of the left, will be on the left.","যারা বাঁ দিকের, তারা বাঁ দিকে থাকবে।"],
  "56:42": ["In misery and inferno.","দুর্দশা ও অগ্নিকাণ্ডে।"],
  "56:43": ["Even their shade is hot.","এমনকি তাদের ছায়াও উত্তপ্ত।"],
  "56:44": ["Never cool, never tolerable.","কখনই ঠাণ্ডা নয়, কখনই সহনীয় নয়।"],
  "56:45": ["They used to be rich.","তারা ধনী ছিল।"],
  "56:46": ["They insisted on the great blasphemy.","তারা ঈশ্বরের প্রতি ঘোর মিথ্যাচারে অটল থাকত।"],
  "56:47": ["They said, \"After we die and turn to dust and bones, we get resurrected?","তারা বলতো, “আমরা মরে যাবার পর এবং ধুলো ও হাড় হয়ে যাবার পর, আমরা পুনরুত্থিত হবো?"],
  "56:48": ["\"Does this include our forefathers?\"","“আমাদের পূর্ব পুরুষরাও কি হবে?”"],
  "56:49": ["Say, \"The early generations and the later generations.","বল, “প্রথমদিককার প্রজন্মগুলো এবং পরবর্তী প্রজন্মগুলো।"],
  "56:50": ["\"Will be summoned to a meeting on a predetermined day.","তলব করা হবে এক পূর্ব নির্ধারিত দিনের সাক্ষাতকারে ।"],
  "56:51": ["\"Then you, O disbelieving strayers.","“তখন তোমরা, হে অবিশ্বাসী পথভ্রষ্টরা।"],
  "56:52": ["\"Will eat from the trees of bitterness.","“খাবে তিক্ততার বৃক্ষ থেকে।"],
  "56:53": ["\"Filling your bellies therefrom.","“তা দিয়ে তোমাদের পেট ভরিয়ে।"],
  "56:54": ["\"Then drinking on top of it hellish drinks.","“এরপর এর সাথে নারকীয় পানীয় পান করে ।"],
  "56:55": ["\"Then adding drinks of sand.\"","“এরপর বালুর পানীয় মিলিয়ে।”"],
  "56:56": ["Such is their share on the Day of Judgment.","বিচারের দিনে এমনি তাদের অংশ।"],
  "56:57": ["We have created you, if you could only believe!","আমরা তোমাদের সৃষ্টি করেছি, যদি কেবল তোমরা বিশ্বাস করতে পারতে!"],
  "56:58": ["Have you noted the semen that you produce?","তোমরা কি লক্ষ্য করেছ সে বীর্য যা তোমরা উৎপাদন করো?"],
  "56:59": ["Did you create it, or did we?","এটা কি তোমরা সৃষ্টি করেছিলে, নাকি আমরা করেছিলাম?"],
  "56:60": ["We have predetermined death for you. Nothing can stop us—","তোমাদের জন্য আমাদের কাছে রয়েছে পূর্ব নির্ধারিত মৃত্যু। কোন কিছুই আমাদের থামাতে পারে না-"],
  "56:61": ["from substituting new generations in your place, and establishing what you do not know.","প্রতিস্থাপন করা হতে তোমাদের পরিবর্তে নতুন প্রজন্মকে, এবং প্রতিষ্ঠা করতে যা তোমরা জানো না।"],
  "56:62": ["You know about the first creation. Do you not remember?","তোমরা প্রথম সৃষ্টি সম্পর্কে জানো। তোমরা কি স্মরণ করো না?"],
  "56:63": ["Have you noted the crops you reap?","তোমরা কি লক্ষ্য করেছ সে শস্যগুলো যা তোমরা কাটো?"],
  "56:64": ["Did you grow them, or did we?","তোমরা কি সেগুলো উৎপন্ন করেছিলে, নাকি আমরা করেছিলাম?"],
  "56:65": ["If we will, we can turn it into hay. Then you will lament:","যদি আমরা চাই, আমরা একে খড় কুটো করে দিতে পারি। তখন তোমরা বিলাপ করবেঃ"],
  "56:66": ["\"We lost.","“আমরা ক্ষতিগ্রস্থ।"],
  "56:67": ["\"We are deprived.\"","“আমাদের বঞ্চিত করা হয়েছে।”"],
  "56:68": ["Have you noted the water you drink?","তোমরা কি লক্ষ্য করেছ সে পানি যা তোমরা পান করো?"],
  "56:69": ["Did you send it down from the clouds, or did we?","তোমরা কি একে মেঘ থেকে নামিয়ে এনেছিলে, নাকি আমরা এনেছিলাম?"],
  "56:70": ["If we will, we can make it salty. You should be thankful.","যদি আমরা চাই, তবে আমরা একে লবণাক্ত করে দিতে পারি। তোমাদের কৃতজ্ঞ হওয়া উচিৎ।"],
  "56:71": ["Have you noted the fire you ignite?","তোমরা কি সে আগুনকে লক্ষ্য করেছ যা তোমরা জ্বালাও?"],
  "56:72": ["Did you initiate its tree, or did we?","তোমরা কি এর গাছগুলোর সূচনা করেছিলে, নাকি আমরা করেছিলাম?"],
  "56:73": ["We rendered it a reminder, and a useful tool for the users.","আমরা একে করলাম একটি স্মারক এবং একটি কার্যকর বস্তু ব্যবহারকারীদের জন্য।"],
  "56:74": ["You shall glorify the name of your Lord, the Great.","তুমি তোমরা প্রভুর নামের পবিত্রতা ঘোষণা করো, যিনি মহান।"],
  "56:75": ["I swear by the positions of the stars.","আমি নক্ষত্রদের অবস্থানের শপথ করছি।"],
  "56:76": ["This is an oath, if you only knew, that is awesome.","এটি একটি শপথ, যদি তোমরা কেবল জানতে, যা অসাধারণ।"],
  "56:77": ["This is an honorable Quran.","এটি একটি সন্মানিত কুরআন।"],
  "56:78": ["In a protected book.","একটি সংরক্ষিত গ্রন্থে।"],
  "56:79": ["None can grasp it except the sincere.","কেউ এটি উপলব্ধি করতে পারে না আন্তরিক ব্যক্তি ব্যতীত।"],
  "56:80": ["A revelation from the Lord of the universe.","মহাবিশ্বের প্রভুর পক্ষ থেকে একটি প্রকাশনা।"],
  "56:81": ["Are you disregarding this narration?","তোমরা কি এই বর্ণনাকে অবজ্ঞা করছো?"],
  "56:82": ["Do you make it your business that you disbelieve?","তোমরা কি তোমাদের অবিশ্বাস করাকে ব্যবসা বানাও?"],
  "56:83": ["When the time comes and it (your soul) reaches your throat—","যখন সময় এসে যায় আর এটি (তোমাদের আত্মা) তোমাদের কণ্ঠে পৌঁছে-"],
  "56:84": ["you will then look around.","তখন তোমরা চারদিকে তাকাবে।"],
  "56:85": ["We are closer to it than you are, but you do not see.","তোমাদের চেয়ে আমরা এর অধিক নিকটবর্তী, কিন্তু তোমরা দেখ না।"],
  "56:86": ["If it is true that you do not owe any accounting—","যদি এটি সত্য হয় যে তোমাদের কোন জবাবদিহিতা নেই-"],
  "56:87": ["why do you not restore (your soul), if you are truthful?","কেন তোমরা (তোমাদের আত্মাকে) পুনরায় ফিরিয়ে নাও না, যদি তোমরা সত্যবাদী হয়ে থাক?"],
  "56:88": ["If he is one of those close to Me—","যদি সে আমার নিকটবর্তীদের একজন হয়-"],
  "56:89": ["then joy, flowers, and gardens of bliss.","তবে আনন্দ, ফুলসম্ভার এবং পরম সুখের বাগানসমূহ।"],
  "56:90": ["And if he is one of the right—","আর যদি সে ডান পার্শ্বস্থদের একজন হয়-"],
  "56:91": ["peace is the lot of those on the right.","শান্তিই তাদের ভাগ্য যারা ডান পার্শ্বস্থ।"],
  "56:92": ["But if he is one of the disbelievers, the strayers—","কিন্তু যদি সে অবিশ্বাসী, পথভ্রষ্টদের একজন হয়-"],
  "56:93": ["then an abode of inferno—","তবে আগুনের একটি বাসস্থান-"],
  "56:94": ["and burning in Hell.","আর নরকে জ্বলতে থাকা,"],
  "56:95": ["This is the absolute truth.","এটি ধ্রুব সত্য।"],
  "56:96": ["You shall glorify the name of your Lord, the Great.","তুমি তোমরা প্রভুর নামের পবিত্রতা ঘোষণা করো, যিনি মহান।"],
  "57:1": ["Glorifying Allah is everything in the heavens and the earth. He is the Almighty, Most Wise.","আকাশমণ্ডলী ও পৃথিবীর সবকিছু ঈশ্বরের মহিমা ঘোষণা করছে। তিনি সর্বশক্তিমান, সবচেয়ে প্রজ্ঞাবান।"],
  "57:2": ["To Him belongs the kingship of the heavens and the earth. He controls life and death. He is Omnipotent.","তাঁর অধীনে রয়েছে আকাশমণ্ডলী ও পৃথিবীর রাজত্ব। তিনি জীবন ও মৃত্যু নিয়ন্ত্রন করেন। তিনি সর্বশক্তিমান।"],
  "57:3": ["He is the Alpha and the Omega. He is the Outermost and the Innermost. He is fully aware of all things.","তিনি শুরু এবং শেষ। তিনি বাহিরতম এবং ভিতরতম। তিনি সকল বস্তু সম্পর্কে পূর্ণ অবগত।"],
  "57:4": ["He is the One who created the heavens and the earth in six days, then assumed all authority. He knows everything that enters into the earth, and everything that comes out of it, and everything that comes down from the sky, and everything that climbs into it. He is with you wherever you may be. Allah is Seer of everything you do.","তিনি সেই সত্ত্বা যিনি আকাশমণ্ডলী ও পৃথিবী সৃষ্টি করেছিলেন ছয় দিনে, এরপর সকল কর্তৃত্ব গ্রহন করলেন। সবকিছু তিনি জানেন যা পৃথিবীতে প্রবেশ করে এবং যা এর থেকে বের হয়ে আসে, আর সবকিছু যা আকাশ থেকে নেমে আসে, এবং যা এতে আরোহন করে। তিনি তোমাদের সাথে আছেন যেখানেই তোমরা থাক না কেন। ঈশ্বর সবকিছু দেখেন যা তোমরা করো।"],
  "57:5": ["To Him belongs the kingship of the heavens and the earth. All matters are controlled by Allah.","তাঁর অধীনে রয়েছে আকাশমণ্ডলী ও পৃথিবীর রাজত্ব। সকল বস্তু ঈশ্বর দ্বারা নিয়ন্ত্রিত হয়।"],
  "57:6": ["He merges the night into the day, and merges the day into the night. He is fully aware of the innermost thoughts.","তিনি রাতকে দিনের সাথে মিলিয়ে দেন এবং দিনকে রাতের সাথে মিলিয়ে দেন। তিনি ভিতরকার চিন্তাগুলো সম্পর্কে পূর্ণ অবগত।"],
  "57:7": ["Believe in Allah and His messenger, and give from what He has bestowed upon you. Those among you who believe and give (to charity) have deserved a great recompense.","ঈশ্বর এবং তাঁর বার্তাবাহককে বিশ্বাস করো, আর তা থেকে দাও যা তিনি তোমাদের উপর অর্পণ করেছেন। তোমাদের মধ্যে যারা বিশ্বাস করে এবং (দান হিসেবে) দেয় তারা এক মহা প্রতিদানের যোগ্য হয়েছে।"],
  "57:8": ["Why should you not believe in Allah when the messenger is inviting you to believe in your Lord? He has taken a pledge from you, if you are believers.","কেন তোমরা ঈশ্বর ও তাঁর বার্তাবাহককে বিশ্বাস করছো না যখন বার্তাবাহক তোমাদের দাওয়াত দিচ্ছে তোমাদের প্রভুর প্রতি বিশ্বাস আনতে? তিনি তোমাদের থেকে একটি অঙ্গীকার নিয়েছেন, যদি তোমরা বিশ্বাসী হয়ে থাক।"],
  "57:9": ["He is the One who sends down to His servant clear revelations, in order to lead you out of the darkness into the light. Allah is Compassionate towards you, Most Merciful.","তিনি সেই সত্ত্বা যিনি তাঁর বান্দার কাছে স্পষ্ট প্রকাশনাবলি অবতীর্ণ করেন, তোমাদেরকে অন্ধকার থেকে আলোতে পরিচালিত করতে। ঈশ্বর তোমাদের প্রতি করুণাময়, পরম দয়ালু।"],
  "57:10": ["Why do you not spend in the cause of Allah, when Allah possesses all wealth in the heavens and the earth? Distinguished from the rest are those among you who spend before the victory and strive. They attain a greater rank than those who spend after the victory and strive. For each, Allah promises salvation. Allah is Cognizant of everything you do.","কেন তোমরা ঈশ্বরের পথে ব্যয় করো না, যখন আকাশমণ্ডলী ও পৃথিবীর সকল সম্পদ ঈশ্বরের? তোমাদের মধ্যে যারা বিজয়ের পূর্বে ব্যয় করে ও সংগ্রাম করে তারা বাকিদের থেকে আলাদা। তারা অর্জন করে অধিকতর পদমর্যাদা তাদের চেয়ে যারা বিজয়ের পরে ব্যয় করে ও সংগ্রাম করে। প্রত্যেকের জন্য, ঈশ্বর মুক্তির অঙ্গীকার করেন। তোমরা যা কিছু করো ঈশ্বর সে সম্পর্কে পূর্ণ অবগত।"],
  "57:11": ["Who would like to loan Allah a loan of righteousness, to have it multiplied for him manifold, and end up with a generous recompense?","কে ঈশ্বরকে ঋণ দিতে পছন্দ করে, সৎকর্মশীলতার ঋণ, যেন তা তার জন্য বহুগুনে বর্ধিত হয়, এবং পরিনত হয় এক মহা প্রতিদানে?"],
  "57:12": ["The day will come when you see the believing men and women with their lights radiating ahead of them and to their right. Good news is yours that, on that day, you will have gardens with flowing streams. You will abide therein forever. This is the great triumph.","সেদিন আসবে যখন তুমি বিশ্বাসী পুরুষ ও নারীদের দেখবে তাদের আলো বিচ্ছুরিত হচ্ছে তাদের সামনে এবং তাদের ডান দিক থেকে । তোমাদের জন্য সুসংবাদ যে, ঐ দিন, তোমাদের থাকবে প্রবাহিত ঝর্ণাসহ বাগান। তোমরা চিরকাল সেখানে বাস করবে। এটাই মহাবিজয়।"],
  "57:13": ["On that day, the hypocrite men and women will say to those who believed, \"Please allow us to absorb some of your light.\" It will be said, \"Go back behind you, and seek light.\" A barrier will be set up between them, whose gate separates mercy on the inner side, from retribution on the outer side.","ঐদিন, যারা বিশ্বাস করেছিল তাদেরকে ভণ্ড পুরুষ ও নারীরা বলবে, “দয়া করে তোমাদের কিছু আলো আমাদের (শোষণ করতে) দাও।” বলা হবে, “তোমরা পিছনে ফিরে যাও, এবং আলোর খোঁজ করো।” তাদের মধ্যে একটি অন্তরায় স্থাপন করা হবে, যার দরজা ভিতর দিকের দয়াকে আলাদা করে, বাইরের শাস্তি থেকে।"],
  "57:14": ["They will call upon them, \"Were we not with you?\" They will answer, \"Yes, but you cheated your souls, hesitated, doubted, and became misled by wishful thinking, until Allah's judgment came. You were diverted from Allah by illusions.","তারা তাদেরকে ডেকে বলবে, “আমরা কি তোমাদের সাথে ছিলাম না?” তারা উত্তর দেবে, “হ্যাঁ, কিন্তু তোমরা তোমাদের আত্মার সাথে প্রতারণা করেছিলে, সন্দেহকারী ছিলে, এবং মন-মতো চিন্তার কারণে বিপথগামী হয়েছিলে, যে পর্যন্ত না ঈশ্বরের বিচার এসে পড়েছিল। তোমরা মোহের কারণে ঈশ্বর থেকে সরে পড়েছিলে।"],
  "57:15": ["\"Therefore, today no ransom can be taken from you, nor from those who disbelieved. Your abode is the fire; it is your lord, and miserable abode.\"","“অতএব, আজ তোমাদের থেকে কোন মুক্তিপণ নেয়া হবে না, না তাদের থেকে যারা অবিশ্বাস করেছিল। আগুন হল তোমাদের বাসস্থান; এটি তোমাদের প্রভু এবং শোচনীয় বাসস্থান।”"],
  "57:16": ["Is it not time for those who believed to open up their hearts for Allah's message, and the truth that is revealed herein? They should not be like the followers of previous scriptures whose hearts became hardened with time and, consequently, many of them turned wicked.","যারা বিশ্বাস করেছে তাদের জন্য তাদের হৃদয় খুলে দেয়ার এটাই কি সময় নয় ঈশ্বরের বার্তার জন্য, এবং সে সত্যের জন্য যা এখানে প্রকাশ হয়? তাদের উচিত নয় পূর্ববর্তী ঐশীগ্রন্থের অনুসারিদের মতো হওয়া যাদের হৃদয় সময়ের সাথে সাথে কঠিন হয়ে পড়েছিল এবং, পরিণামে, তাদের অনেকেই অন্যায়কারীতে পরিনত হয়েছিল।"],
  "57:17": ["Know that Allah revives the land after it had died. We thus explain the revelations for you, that you may understand.","জেনে রাখো যে ঈশ্বর জমিনকে এর মৃত্যুর পর পুনরুজ্জীবিত করেন। এইভাবে আমরা প্রকাশনাবলি তোমাদের জন্য ব্যাখ্যা করি, যাতে হয়তো তোমরা বুঝবে।"],
  "57:18": ["Surely, the charitable men and women have loaned Allah a loan of goodness. They will receive their reward multiplied manifold; they have deserved a generous recompense.","নিশ্চয়, দানশীল পুরুষ ও নারীরা ঈশ্বরকে ঋণ  দেয়- ভালো কাজের ঋণ। তারা তাদের পুরস্কার বহুগুনে বর্ধিত অবস্থায় পাবে; তারা উদার প্রতিদানের যোগ্য হয়েছে।"],
  "57:19": ["Those who believed in Allah and His messengers are the saints and martyrs. Reserved for them at their Lord are their rewards and their light. As for those who disbelieved and rejected our revelations, they have incurred Hell.","যারা ঈশ্বর ও তাঁর বার্তাবাহককে বিশ্বাস করেছে তারা সাধু ও শহীদ। তাদের জন্য তাদের প্রভুর কাছে সংরক্ষিত আছে তাদের পুরস্কার এবং তাদের আলো। আর যারা অবিশ্বাস করেছে এবং আমাদের প্রকাশনাবলি প্রত্যাখ্যান করেছে, তারা টেনে এনেছে নরক।"],
  "57:20": ["Know that this worldly life is no more than play and games, and boasting among you, and hoarding of money and children. It is like abundant rain that produces plants and pleases the disbelievers. But then the plants turn into useless hay, and are blown away by the wind. In the Hereafter there is either severe retribution, or forgiveness from Allah and approval. This worldly life is no more than a temporary illusion.","জেনে রাখো যে এই দুনিয়ার জীবন খেলা আর তামাশা, আর তোমাদের মধ্যে গর্ব করা, অর্থ ও সন্তান জমা করার চেয়ে বেশি কিছু নয়। এটি প্রচুর বৃষ্টির মত যা চারাগাছ উৎপন্ন করে এবং অবিশ্বাসীদের সন্তুষ্ট করে। কিন্তু এরপর চারাগাছগুলো অপ্রয়োজনীয় খড় কুটোয় পরিণত হয়, আর বাতাস তা উড়িয়ে নিয়ে যায়। পরকালে রয়েছে হয় কঠিন শাস্তি, নয়তো ঈশ্বর থেকে ক্ষমা ও সম্মতি। এই দুনিয়ার জীবন ক্ষণস্থায়ী মোহের চেয়ে বেশি কিছু নয়।"],
  "57:21": ["Therefore, you shall race towards forgiveness from your Lord, and a Paradise whose width encompasses the heaven and the earth. It awaits those who believed in Allah and His messengers. Such is Allah's grace that He bestows upon whomever He wills. Allah is Possessor of Infinite Grace.","অতএব, তোমরা প্রতিযোগিতা করো তোমাদের প্রভুর পক্ষ থেকে ক্ষমা আর এমন এক স্বর্গের জন্য যার ব্যাপ্তি আকাশ ও পৃথিবীকে পরিবেষ্টন করে। এটি তাদের জন্য অপেক্ষা করে যারা ঈশ্বর ও তাঁর বার্তাবাহককে বিশ্বাস করেছিল। এমনি ঈশ্বরের করুণা যা তিনি যার উপর ইচ্ছা অর্পণ করেন। ঈশ্বর অসীম করুণার অধিকারী।"],
  "57:22": ["Anything that happens on earth, or to you, has already been recorded, even before the creation. This is easy for Allah to do.","যা কিছু পৃথিবীতে, বা তোমাদের সাথে ঘটে তা ইতিমধ্যেই লিপিবদ্ধ আছে, এমনকি সৃষ্টির পূর্বেই। এটি করা ঈশ্বরের জন্য সহজ।"],
  "57:23": ["Thus, you should not grieve over anything you miss, nor be proud of anything He has bestowed upon you. Allah does not love those who are boastful, proud.","সুতরাং, তোমাদের যাকিছুই হারায় তার জন্য দু:খ করা উচিত নয়, না কোনকিছু নিয়ে গর্ব করা উচিত যা তিনি তোমাদের উপর অর্পণ করেছেন। ঈশ্বর তাদের ভালোবাসেন না যারা  দাম্ভিক, অহংকারী।"],
  "57:24": ["They are stingy, and enjoin the people to be stingy. If one turns away, then Allah is the Rich, the Praiseworthy.","তারা কৃপণ এবং লোকদের কৃপণ হতে উৎসাহ দেয়। কেউ মুখ ফিরিয়ে নিলেও ঈশ্বর ধনী, প্রশংসিত।"],
  "57:25": ["We sent our messengers supported by clear proofs, and we sent down to them the scripture and the law, that the people may uphold justice. And we sent down the iron, wherein there is strength, and many benefits for the people. All this in order for Allah to distinguish those who would support Him and His messengers, on faith. Allah is Powerful, Almighty.","আমরা আমাদের বার্তাবাহকদের স্পষ্ট প্রমানের সমর্থন দিয়ে পাঠিয়েছিলাম এবং আমরা তাদের কাছে নাজিল করেছিলাম ঐশীগ্রন্থ ও আইন যাতে লোকেরা ন্যায় বিচার প্রতিষ্ঠিত রাখতে পারে। আর আমরা পাঠিয়ে ছিলাম লোহা, যাতে রয়েছে শক্তি ও লোকদের জন্য অনেক উপকারিতা। এই সবকিছু ঈশ্বরের আলাদা করার জন্য তাদেরকে যারা তাঁকে ও তাঁর বার্তাবাহককে সমর্থন করা বেছে নেবে, অটল বিশ্বাস থেকে। ঈশ্বর ক্ষমতাধর, সর্ব শক্তিমান।"],
  "57:26": ["We sent Noah and Abraham, and we granted their descendants prophethood and the scripture. Some of them were guided, while many were wicked.","আমরা নুহ এবং ইব্রাহিমকে পাঠিয়েছিলাম, আর আমরা তাদের বংশধরদের প্রদান করেছিলাম নবুয়াত ও ঐশীগ্রন্থ। তাদের কেউ কেউ সুপথে ছিল, যখন অনেকেই ছিল অন্যায়কারী।"],
  "57:27": ["Subsequent to them, we sent our messengers. We sent Jesus the son of Mary, and we gave him the Injeel (Gospel), and we placed in the hearts of his followers kindness and mercy. But they invented hermitism which we never decreed for them. All we asked them to do was to uphold the commandments approved by Allah. But they did not uphold the message as they should have. Consequently, we gave those who believed among them their recompense, while many of them were wicked.","তাদের পরবর্তীতে, আমরা আমাদের বার্তাবাহকদের পাঠালাম । আমরা পাঠিয়েছিলাম মরিয়ম পুত্র ঈসাকে, এবং আমরা তাকে দিয়েছিলাম ইঞ্জিল, আর আমরা তার অনুসারীদের অন্তরে সমমর্মিতা ও দয়ার সঞ্চার করলাম। কিন্তু তারা বৈরাগ্যবাদ চালু করলো যা আমরা কখনই তাদের জন্য জারি করিনি। আমরা তাদেরকে কেবল ঈশ্বরের অনুমোদিত হুকুমসমূহ মেনে চলতে বলেছিলাম।  কিন্তু তারা বার্তা মেনে চলেনি যেমন ভাবে তাদের উচিৎ ছিল। পরিণামে, তাদের মধ্যে যারা বিশ্বাস করেছিল আমরা তাদেরকে তাদের প্রতিদান দিয়েছিলাম, যখন তাদের অনেকেই ছিল অন্যায়কারী।"],
  "57:28": ["O you who believe, you shall reverence Allah and believe in His messenger. He will then grant you double the reward from His mercy, endow you with light to guide you, and forgive you. Allah is Forgiver, Most Merciful.","হে তোমরা যারা বিশ্বাস করো, তোমরা ঈশ্বরকে ভক্তি করো এবং তাঁর বার্তাবাহককে বিশ্বাস করো। তাহলে তিনি তাঁর  দয়ায় তোমাদের জন্য দ্বিগুন পুরস্কার দিবেন, তোমাদেরকে পথ দেখাতে আলো দিয়ে অলংকৃত করবেন এবং তোমাদের ক্ষমা করবেন। ঈশ্বর ক্ষমাকারী, পরম দয়ালু।"],
  "57:29": ["Thus, the followers of previous scripture should know that they have not monopolized Allah's mercy and grace, and that all grace is in Allah's hand. He bestows it upon whomever He wills. Allah is Possessor of Infinite Grace.","সুতরাং, পূর্ববর্তী ঐশীগ্রন্থের অনুসারীদের জানা উচিত যে তারা ঈশ্বরের দয়া ও করুণার একচ্ছত্র মালিক না এবং সকল করুণা ঈশ্বরের হাতে। তিনি যার উপর ইচ্ছা তা আরোপ করেন। ঈশ্বর সীমাহীন করুণার অধিকারী।"],
  "58:1": ["Allah has heard the woman who debated with you about her husband, and complained to Allah. Allah heard everything the two of you discussed. Allah is Hearer, Seer.","ঈশ্বর সে নারীর কথা শুনেছেন যে তার স্বামীর বিষয়ে তোমার সাথে বিতর্ক করেছিল, এবং ঈশ্বরের কাছে অভিযোগ করেছিল। তোমরা দুজনে যা আলোচনা করেছিলে ঈশ্বর এর সবকিছু শুনেছেন। ঈশ্বর শ্রবণকারী, দ্রষ্টা।"],
  "58:2": ["Those among you who estrange their wives (by declaring them as forbidden in sex) as their mothers know full well that they are not their mothers. Their mothers are the women who gave birth to them. Indeed, they are committing a blasphemy and a falsehood. Allah is Pardoner, Forgiver.","তোমাদের মধ্যে যারা তাদের স্ত্রীকে মা গন্য করে (তাদের সাথে যৌন সহবাস নিষিদ্ধ ঘোষণা করে আর) আলাদা থাকে, তারা ভালো করেই জানে যে তারা তাদের মা নয়। তাদের মা হলো সে নারী যে তাদের জন্ম দিয়েছিল। নিশ্চয়, তারা ধর্মনিন্দা ও মিথ্যাচার করছে। ঈশ্বর মার্জনাকারী, ক্ষমাকারী।"],
  "58:3": ["Those who estrange their wives in this manner, then reconcile thereafter, shall atone by freeing a slave before resuming their sexual relations. This is to enlighten you. Allah is Cognizant of everything you do.","যারা এই পন্থায় স্ত্রীদের থেকে আলাদা থাকে, এরপর পুনর্মিলিত হয়, তারা যৌন সম্পর্ক পুনরায় শুরু করার পূর্বে একজন দাস মুক্ত করে প্রায়শ্চিত্ত করবে। এটি তোমাদেরকে জ্ঞান দিয়ে আলোকিত করার জন্যে। ঈশ্বর জানেন যাকিছু তোমরা করো।"],
  "58:4": ["If you cannot find a slave to free, you shall fast two consecutive months before resuming sexual relations. If you cannot fast, then you shall feed sixty poor people. You shall believe in Allah and His messenger. These are Allah's laws. The disbelievers have incurred a painful retribution.","যদি তোমরা মুক্ত করার জন্য কোন দাস না পাও, যৌন সম্পর্ক পুনরায় শুরু করার পূর্বে টানা দুই মাস রোজা থাকবে। যদি তোমরা রোজা থাকতে না পার, তবে তোমরা ষাট জন গরীব লোককে খাওয়াবে। তোমরা ঈশ্বর ও তাঁর বার্তাবাহককে বিশ্বাস করবে। এগুলো ঈশ্বরের আইন। অবিশ্বাসীরা টেনে এনেছে এক যন্ত্রণাদায়ক শাস্তি।"],
  "58:5": ["Surely, those who fight Allah and His messenger are committed to defeat, like their previous counterparts were committed to defeat. We have sent down clear proofs, and the rejectors have incurred a shameful retribution.","নিশ্চয়, যারা ঈশ্বর ও তাঁর বার্তাবাহকের বিরুদ্ধে লড়াই করে তারা পরাজিত হয়, যেমন তাদের পূর্ববর্তী অনুরূপ ব্যক্তিরা পরাজিত হয়েছিল। আমরা স্পষ্ট প্রমাণাদি অবতীর্ণ করেছি, আর প্রত্যাখ্যানকারীরা টেনে এনেছে এক লজ্জাজনক শাস্তি।"],
  "58:6": ["The day will come when Allah will resurrect them all, then inform them of everything they had done. Allah has recorded everything, while they have forgotten it. Allah witnesses all things.","সে দিন আসবে যখন ঈশ্বর তাদের সকলকে পুনরুত্থিত করবেন, এরপর তাদের জানাবেন যা কিছু তারা করেছিল। ঈশ্বর সবকিছু লিপিবদ্ধ করেছেন, যদিও তারা তা ভুলে গেছে। ঈশ্বর সবকিছু প্রত্যক্ষ করেন।"],
  "58:7": ["Do you not realize that Allah knows everything in the heavens and everything on earth? No three people can conspire secretly without Him being their fourth, nor five without Him being the sixth, nor less than that, nor more, without Him being there with them wherever they may be. Then, on the Day of Resurrection, He will inform them of everything they had done. Allah is fully aware of all things.","তুমি কি অনুধাবন করো না যে ঈশ্বর আকাশমণ্ডলী ও পৃথিবীর সবকিছু জানেন? কোন তিন ব্যক্তি গোপন চক্রান্ত করতে পারে না তাঁকে ছাড়া- তাদের চতুর্থ ব্যক্তি হিসেবে, না পাঁচ ব্যক্তি তাঁকে ছাড়া - তাদের ষষ্ঠ ব্যক্তি হিসাবে, না এর চেয়ে কম, না এর বেশি হিসেবে, সেখানে তাদের সাথে তিনি থাকেন যেখানেই তারা থাকুক না কেন। অতঃপর, পুনরুত্থান দিনে, তিনি তাদের জানাবেন যাকিছু তারা করেছিল। ঈশ্বর সবকিছু সম্পর্কে সম্পূর্ণ অবগত।"],
  "58:8": ["Have you noted those who were enjoined from conspiring secretly, then insist on conspiring? They conspire to commit sin, transgression, and disobedience of the messenger. When they come to you, they greet you with a greeting other than that decreed by Allah. They say inside themselves, \"Allah will not punish us for our utterances.\" Their only requital is Gehenna, wherein they burn; what a miserable destiny.","তুমি কি তাদের লক্ষ্য করেছো যাদেরকে নিষেধ করা হয়েছিল গোপনে চক্রান্ত করতে, এরপর চক্রান্তে জেদ ধরে থাকে? তারা চক্রান্ত করে পাপ, সীমালঙ্ঘন ও বার্তাবাহকের অবাধ্যতা করতে। যখন তারা তোমার কাছে আসে, তারা তোমাকে অভিবাদন জানায়, ঈশ্বর যা জারি করেছেন তা ব্যতীত অন্য এক অভিবাদন দিয়ে। তারা নিজেরা মনে মনে বলে, “আমাদের কথার জন্য ঈশ্বর আমাদের শাস্তি দেবেন না।” জাহান্নাম হল তাদের একমাত্র প্রতিফল, যেখানে তারা জ্বলবে; কি এক শোচনীয় ভাগ্য।"],
  "58:9": ["O you who believe, if you have to confer secretly, you shall not confer to commit sin, transgression, and to disobey the messenger. You shall confer to work righteousness and piety. You shall reverence Allah, before whom you will be summoned.","হে যারা বিশ্বাস কর, যদি তোমাদের গোপনে পরামর্শ করতে হয়, তবে তোমরা পাপ, সীমালঙ্ঘন ও বার্তাবাহককে অমান্য করতে পরামর্শ করো না। তোমরা সৎকর্ম ও পূন্য করার জন্য পরামর্শ কর। তোমরা ঈশ্বরকে ভক্তি করো, যার সামনে তোমাদের একত্রিত করা হবে।"],
  "58:10": ["Secret conspiracy is the devil's idea, through which he seeks to hurt those who believed. However, he cannot hurt them against Allah's will. In Allah the believers shall trust.","গোপন চক্রান্ত শয়তানের ধারণা, যারা দ্বারা সে তাদের ক্ষতি করতে চায় যারা বিশ্বাস করেছে। কিন্তু, সে তাদেরকে ঈশ্বরের ইচ্ছার বিরুদ্ধে ক্ষতি করতে পারে না। বিশ্বাসীরা ঈশ্বরে আস্থা রাখবে।"],
  "58:11": ["O you who believe, if you are told, \"Please make room,\" you shall make room for each other to sit. Allah will then make room for you. If you are asked to get up and move, get up and move. Allah raises those among you who believe, and those who acquire knowledge to higher ranks. Allah is fully Cognizant of everything you do.","হে যারা বিশ্বাস করো, যদি তোমাদের বলা হয়, “দয়া করে জায়গা দাও, ” তোমরা পরস্পরকে বসার জন্য জায়গা দেবে। ঈশ্বর তবে তোমাদের জন্য জায়গা তৈরি করবেন। যদি তোমাদের বলা হয় জেগে উঠো এবং এগিয়ে যাও, জেগে উঠবে এবং এগিয়ে যাবে। তোমাদের মধ্যে যারা বিশ্বাস করে, আর যারা জ্ঞানার্জন করে ঈশ্বর তাদেরকে উচ্চ পদমর্যাদায় উন্নীত করেন। তোমরা যাকিছু করো ঈশ্বর সে সম্পর্কে সম্পূর্ণ অবগত।"],
  "58:12": ["O you who believe, when you wish to confer with the messenger, you shall offer a charity (to the poor) before you do so. This is better for you, and purer. If you cannot afford it, then Allah is Forgiver, Most Merciful.","হে তোমরা যারা বিশ্বাস করো, যখন তোমরা বার্তাবাহকের সাথে আলোচনা করতে চাও, তোমরা তা করার পূর্বে (গরিবদের) দান করবে। এটি তোমাদের জন্য উত্তম ও পবিত্রতর। যদি তোমরা তা করতে সমর্থ না হও, তবে ঈশ্বর ক্ষমাশীল, পরম দয়ালু।"],
  "58:13": ["If you failed to give to charity before conferring, then repented thereafter, Allah accepts your repentance. You shall observe the contact prayers (Salat), give the obligatory charity (Zakat), and obey Allah and His messenger. Allah is fully Cognizant of everything you do.","যদি তোমরা আলোচনা করার পূর্বে দান করতে ব্যর্থ হও, তারপর অনুশোচনা করো, ঈশ্বর তোমাদের অনুশোচনা গ্রহন করেন। তোমরা সংযোগ প্রার্থনা (সালাত) পালন করো, যাকাত আদায় করো এবং ঈশ্বর ও তাঁর বার্তাবাহককে মান্য করো। তোমরা যা কিছু করো ঈশ্বর সে বিষয়ে সম্পূর্ণ অবগত।"],
  "58:14": ["Have you noted those who befriended people with whom Allah is angry? They neither belong with you, nor with them. They deliberately swear lies!","তুমি কি তাদের লক্ষ্য করেছো যারা সেসব লোকদের বন্ধু বানায় যাদের উপর ঈশ্বর রাগান্বিত? তারা না তোমার সাথে, না তাদের সাথে। তারা জেনে-শুনে মিথ্যা শপথ করে!"],
  "58:15": ["Allah has prepared for them a severe retribution. Miserable indeed is what they used to do.","ঈশ্বর তাদের জন্য কঠোর শাস্তি প্রস্তুত রেখেছেন। নিশ্চয় শোচনীয় যা তারা করে চলেছে।"],
  "58:16": ["They used their oaths as a means of repelling from the path of Allah. Consequently, they have incurred a shameful retribution.","তারা তাদের শপথকে ঈশ্বরের পথে বাধা দেবার উপায় হিসেবে ব্যবহার করে। পরিণামে, তারা টেনে এনেছে এক লজ্জাজনক শাস্তি।"],
  "58:17": ["Neither their money, nor their children will help them against Allah. They have incurred the hellfire, wherein they abide forever.","না তাদের অর্থ, না তাদের সন্তানেরা ঈশ্বরের বিরুদ্ধে তাদের সাহায্য করবে। তারা টেনে এনেছে নরকাগ্নি, যেখানে তারা চিরকাল বাস করে।"],
  "58:18": ["The Day will come when Allah resurrects them all. They will swear to Him then, just as they swear to you now, thinking that they really are right! Indeed, they are the real liars.","সে দিন আসবে যখন ঈশ্বর তাদের সকলকে পূনরুত্থিত করবেন। তারা তখন তাঁর কাছে শপথ করবে, ঠিক যেমন এখন তারা তোমাদের কাছে শপথ করে, এই ভেবে যে তারা আসলেই সঠিক! নিশ্চয়, তারাই আসল মিথ্যাবাদী।"],
  "58:19": ["The devil has possessed them, and has caused them to disregard Allah's message. These are the party of the devil. Absolutely, the party of the devil are the losers.","শয়তান তাদের উপর ভর করেছে, এবং তাদেরকে দিয়ে ঈশ্বরের বার্তা অবজ্ঞা করিয়েছে।  এরাই শয়তানের দল। নিঃসন্দেহে, শয়তানে দল পরাজিত।"],
  "58:20": ["Surely, those who oppose Allah and His messenger will be with the lowliest.","নিশ্চয়, যারা ঈশ্বর ও তাঁর বার্তাবাহকের বিরোধিতা করে তারা হবে নিম্নতমদের সাথে।"],
  "58:21": ["Allah has decreed: \"I and My messengers will most assuredly win.\" Allah is Powerful, Almighty.","ঈশ্বর আইন জারি করেছেনঃ “ আমি ও আমার বার্তাবাহকরা অবশ্যই জয়ী হব।”"],
  "58:22": ["You will not find people who believe in Allah and the Last Day befriending those who oppose Allah and His messenger, even if they were their parents, or their children, or their siblings, or their tribe. For these, He decrees faith into their hearts, and supports them with inspiration from Him, and admits them into gardens with flowing streams wherein they abide forever. Allah is pleased with them, and they are pleased with Him. These are the party of Allah. Most assuredly, Allah's party are the winners.","যারা ঈশ্বর ও শেষ দিনে বিশ্বাস করে তুমি সে লোকদের বন্ধুত্ব করতে দেখবে না তাদের সাথে যারা ঈশ্বর ও তাঁর বার্তাবাহকের বিরোধিতা করে, এমনকি যদিও তারা তাদের পিতামাতা, অথবা তাদের সন্তান, অথবা তাদের ভাই-বোন, অথবা তাদের গোত্র হয়। এদের জন্য, তিনি তাদের হৃদয়ে বিশ্বাস স্থাপিত করেন, এবং তাঁর পক্ষ থেকে  প্রেরণা দিয়ে তাদের সমর্থন দেন, এবং তাদেরকে প্রবেশ করান প্রবাহিত ঝর্ণা সহ বাগানে যেখানে তারা চিরকাল বাস করে। ঈশ্বর তাদের প্রতি সন্তুষ্ট এবং তারাও  তাঁর প্রতি সন্তুষ্ট। এরাই ঈশ্বরের দল। অবশ্যই, ঈশ্বরের দলই জয়ী।"],
  "59:1": ["Glorifying Allah is everything in the heavens and the earth, and He is the Almighty, Most Wise.","ঈশ্বরের মহিমা ঘোষণা করছে আকাশমণ্ডলী ও পৃথিবীর সবকিছু, এবং তিনি সর্বশক্তিমান, সবচেয়ে প্রজ্ঞাবান।"],
  "59:2": ["He is the One who evicted those who disbelieved among the people of the scripture from their homes in a mass exodus. You never thought that they would leave, and they thought that their preparations would protect them from Allah. But then Allah came to them whence they never expected, and threw terror into their hearts. Thus, they abandoned their homes on their own volition, in addition to pressure from the believers. You should learn from this, O you who possess vision.","তিনিই সে সত্ত্বা যিনি ঐশ্বীগ্রন্থের লোকদের মধ্যে যারা অবিশ্বাস করেছিল তাদেরকে তাদের ঘর থেকে একসাথে উচ্ছেদ করেছিলেন। তোমরা কখনো ধারনা করোনি যে তারা প্রস্থান করবে, আর তারা ভেবেছিল যে তাদের প্রস্তুতি ঈশ্বর থেকে তাদের রক্ষা করবে। কিন্তু এরপর ঈশ্বর তাদের কাছে এমনভাবে আসলেন যা তারা কখনো আশা করেনি, আর তাদের হৃদয়ে আতংক ছুঁড়ে দিয়েছিলেন। তাই, তারা তাদের ঘর-বাড়ি ত্যাগ করেছিল স্বেচ্ছায়, তদুপরি বিশ্বাসীদের চাপে। এর থেকে তোমাদের শিক্ষা নেয়া উচিত, হে তোমরা যারা দূরদর্শিতার অধিকারী।"],
  "59:3": ["If Allah did not force them to leave, He would have requited them in this life (even worse than forcing them to leave). In the Hereafter He will commit them to the retribution of Hell.","ঈশ্বর যদি তাদের যেতে বাধ্য না করতেন, তিনি হয়তো তাদেরকে  (চলে যেতে বাধ্য করার চেয়েও অধিকতর মন্দ) প্রতিদান এই জীবনে দিতেন। পরকালে তিনি তাদের নরকের শাস্তি দেবেন।"],
  "59:4": ["This is because they opposed Allah and His messenger. For those who oppose Allah and His messenger, Allah is most strict in enforcing retribution.","এটি এই কারনে যে তারা ঈশ্বর ও তাঁর বার্তাবাহকের বিরোধিতা করেছিল। যারা ঈশ্বর ও তাঁর বার্তাবাহকের বিরোধিতা করে, ঈশ্বর তাদের জন্য শাস্তি প্রয়োগে অত্যন্ত কঠোর।"],
  "59:5": ["Whether you chop a tree, or leave it standing on its trunk, is in accordance with Allah's will. He will surely humiliate the wicked.","তোমরা কোন গাছ কাট, অথবা একে এর কাণ্ডের উপর দাড়িয়ে থাকতে দাও, তা ঈশ্বরের ইচ্ছা অনুসারে হয়। তিনি অবশ্যই অন্যায়কারীদের অপমানিত করবেন।"],
  "59:6": ["Whatever Allah restored for His messenger was not the result of your war efforts, whether you fought on horses or on foot. Allah is the One who sends His messengers against whomever He wills. Allah is Omnipotent.","যাকিছু ঈশ্বর তাঁর বার্তাবাহকের জন্য ফিরিয়ে দিয়েছিলেন তা তোমাদের যুদ্ধ প্রচেষ্টার ফল ছিল না, তা তোমরা ঘোড়ার উপর লড়াই করে থাকো অথবা পায়ের উপর। ঈশ্বরই সে সত্ত্বা যিনি যার জন্য ইচ্ছা তার বিরুদ্ধে তাঁর বার্তাবাহকদের পাঠান। ঈশ্বর সর্বশক্তিমান।"],
  "59:7": ["Whatever Allah restored to His messenger from the (defeated) communities shall go to Allah and His messenger (in the form of a charity). You shall give it to the relatives, the orphans, the poor, and the traveling alien. Thus, it will not remain monopolized by the strong among you. You may keep the spoils given to you by the messenger, but do not take what he enjoins you from taking. You shall reverence Allah. Allah is strict in enforcing retribution.","যাকিছু ঈশ্বর (পরাজিত) সম্প্রদায়গুলো থেকে তাঁর বার্তাবাহককে ফিরিয়ে দেন তা ঈশ্বর এবং তাঁর বার্তাবাহকের কাছে যাবে (দান হিসাবে)। তোমরা তা আত্মীয়-স্বজন, এতিম, গরীব ও ভ্রমণরত বিদেশীদের দাও। এভাবে, এটি তোমাদের শক্তিশালীদের একচেটিয়া অধিকারে থাকবে না। তোমাদেরকে বার্তাবাহকের দেয়া যুদ্ধলব্ধ সম্পদ তোমরা রাখতে পার, কিন্তু যা তিনি তোমাদের নিতে নিষেধ করেন তা নিও না। তোমরা ঈশ্বরকে ভক্তি কর। ঈশ্বর শাস্তি প্রদানে কঠোর।"],
  "59:8": ["(You shall give) to the needy who immigrated. They were evicted from their homes and deprived of their properties, because they sought Allah's grace and pleasure, and because they supported Allah and His messenger. They are the truthful.","সে অভাবিদের (তোমরা দিবে) যারা দেশত্যাগ করেছিল। তাদেরকে তাদের বাড়ি থেকে উচ্ছেদ করা হয়েছিল আর তাদের ভূসম্পত্তি থেকে বঞ্চিত করা হয়েছিল কারন তারা ঈশ্বরের করুণা ও সন্তুষ্টি অন্বেষণ করতো, এবং কারন তারা ঈশ্বর ও তাঁর বার্তাবাহককে সমর্থন করেছিল। এরাই সত্যবাদী।"],
  "59:9": ["As for those who provided them with a home and a refuge, and were believers before them, they love those who immigrated to them, and find no hesitation in their hearts in helping them. In fact, they readily give them priority over themselves, even when they themselves need what they give away. Indeed, those who overcome their natural stinginess are the successful ones.","আর যারা তাদেরকে ঘর ও আশ্রয় দিয়েছিল, এবং তাদের পূর্ব থেকেই বিশ্বাসী ছিল, তারা তাদেরকে ভালোবাসে যারা দেশত্যাগ করে তাদের কাছে এসেছিল, এবং তাদেরকে সাহায্য করায় তাদের হৃদয়ে কোন সংশয় বোধ করে না। প্রকৃতপক্ষে, তারা অনায়াসে নিজেদের চেয়ে তাদেরকে অগ্রাধিকার দেয়, এমনকি তারা তা দিয়ে দেয় যা তাদেরই প্রয়োজন। নিশ্চয়, যারা তাদের সহজাত কৃপণতাকে জয় করতে পারে তারাই সফলকাম।"],
  "59:10": ["Those who became believers after them say, \"Our Lord, forgive us and our brethren who preceded us to the faith, and keep our hearts from harboring any hatred towards those who believed. Our Lord, You are Compassionate, Most Merciful.\"","যারা তাদের পর বিশ্বাসী হয়েছিল তারা বলে, “আমাদের প্রভু, ক্ষমা করুন আমাদের ও আমাদের ভাইদের যারা বিশ্বাসে আমাদের অগ্রণী এবং আমাদের হৃদয়কে রক্ষা করুন তাদের বিরুদ্ধে কোন ঘৃণা পোষণ করা থেকে যারা বিশ্বাস করেছে।  আমাদের প্রভু,  আপনি দয়াবান, পরম করুণাময়।”"],
  "59:11": ["Have you noted those who are plagued with hypocrisy, and how they said to their companions in disbelief among the people of the scripture, \"If you are evicted we will go out with you, and will never obey anyone who opposes you. If anyone fights you, we will fight on your side.\" Allah bears witness that they are liars.","তুমি কি তাদের লক্ষ্য করেছো যারা ভণ্ডামি নামক মহামারীতে আক্রান্ত, এবং কেমন করে তারা বলেছিল ঐশীগ্রন্থের লোকদের যারা অবিশ্বাসে তাদের সঙ্গী, “যদি তোমাদের উচ্ছেদ করা হয় আমরাও তোমাদের সাথে বের হয়ে যাব, এবং কখনো এমন কাউকে মানবো না যারা তোমাদের বিরোধিতা করে। যদি কেউ তোমাদের সাথে লড়াই করে, আমরা তোমাদের হয়ে লড়াই করবো।” ঈশ্বর সাক্ষ্য দেন যে তারা মিথ্যাবাদী।"],
  "59:12": ["In fact, if they were evicted, they would not have gone out with them, and if anyone fought them, they would not have supported them. Even if they supported them, they would have turned around and fled. They could never win.","প্রকৃতপক্ষে, যদি তাদের উচ্ছেদ করা হতো, তারা তাদের সাথে বের হতো না, এবং যদি কেউ তাদের সাথে লড়াই করতো, তারা তাদের সমর্থণ দিতো না। এমনকি তারা সমর্থন দিলেও, তারা মুখ ফিরিয়ে নিতো এবং পালিয়ে যেতো। তারা কখনো জয়ী হতে পারতো না।"],
  "59:13": ["Indeed, you strike more terror in their hearts than their fear of Allah. This is because they are people who do not comprehend.","নিশ্চয়, তোমরা তাদের হৃদয়ে আরো বেশি আতংক সঞ্চার করো তাদের ঈশ্বর ভীতির চেয়ে। এটি এই কারনে যে তারা সেসব লোক যারা অনুধাবন না।"],
  "59:14": ["They do not get together to fight you unless they are in well-shielded buildings, or behind walls. Their might appears formidable among themselves. You would think that they are united, when in fact their hearts are divided. This is because they are people who do not understand.","তারা তোমাদের সাথে লড়াই করতে মিলিত হয় না যদিনা তারা সুরক্ষিত দালানে, অথবা দেয়ালের আড়ালে থাকে। তাদের কাছে নিজেদের শক্তিকে দুর্দান্ত মনে হয়। তুমি হয়তো ভাববে যে তারা ঐক্যবদ্ধ, আসলে তাদের হৃদয়গুলো বিভক্ত। এটি এই কারনে যে তারা সেসব লোক যারা বোঝে না।"],
  "59:15": ["Their fate is the same as their counterparts who preceded them. They suffered the consequences of their decisions. They have incurred a painful retribution.","তাদের ভাগ্য তাদের অনুরূপ ব্যক্তিদের মত যারা তাদের পূর্ববর্তী ছিল।  তারা তাদের সিদ্ধান্তের পরিণাম ভোগ করেছিল। তারা নিজেদের উপর টেনে এনেছে এক যন্ত্রণাদায়ক শাস্তি।"],
  "59:16": ["They are like the devil: he says to the human being, \"Disbelieve,\" then as soon as he disbelieves, he says, \"I disown you. I fear Allah, Lord of the universe.\"","তারা শয়তানের মতঃ যে মানবজাতিকে বলে, “অবিশ্বাস করো,” এরপর সে অবিশ্বাস করা মাত্র, সে বলে, “আমি তোমাকে অস্বীকার করছি। আমি মহাবিশ্মের প্রভু ঈশ্বরকে ভয় করি।”"],
  "59:17": ["The destiny for both of them is the Hellfire, wherein they abide forever. This is the requital for the transgressors.","তাদের উভয়ের নিয়তি নরকাগ্নি, যেখানে তারা চিরকাল বাস করে। সীমালঙ্ঘনকারীদের জন্য এটাই প্রতিফল।"],
  "59:18": ["O you who believe, you shall reverence Allah, and let every soul examine what it has sent ahead for tomorrow. You shall reverence Allah; Allah is fully Cognizant of everything you do.","হে যারা বিশ্বাস কর, তোমরা ঈশ্বরকে ভক্তি কর, এবং প্রত্যেক আত্মা যাচাই করে দেখুক যে সে কি করেছে আগামীকালের জন্য। তোমরা ঈশ্বরকে ভক্তি কর, তোমরা যাকিছু কর ঈশ্বর সে সম্পর্কে সম্পূর্ণ অবগত।"],
  "59:19": ["Do not be like those who forgot Allah, so He made them forget themselves. These are the wicked.","তাদের মত হইও না যারা ঈশ্বরকে ভুলে গিয়েছিল, তাই তিনি তাদের নিজেদের ভুলিয়ে দিয়েছিলেন। এরাই অন্যায়কারী।"],
  "59:20": ["Not equal are the dwellers of the Hellfire and the dwellers of Paradise; the dwellers of Paradise are the winners.","নরকাগ্নি এবং স্বর্গের বাসিন্দারা সমান নয়; স্বর্গের বাসিন্দারা বিজয়ী।"],
  "59:21": ["If we revealed this Quran to a mountain, you would see it trembling, crumbling, out of reverence for Allah. We cite these examples for the people, that they may reflect.","যদি আমরা এই কুরআনকে কোন পর্বতের উপর নাজিল করতাম, তুমি একে দেখতে কাঁপতে কাঁপতে টুকরো হয়ে যাচ্ছে, ঈশ্বরের প্রতি ভক্তিতে। আমরা লোকদের জন্য এই উদাহরণগুলো দেই, যাতে তারা ভেবে দেখে।"],
  "59:22": ["He is the One Allah; there is no other god besides Him. Knower of all secrets and declarations. He is the Most Gracious, Most Merciful.","তিনিই সে এক ঈশ্বর; তাঁর পাশে অন্য কোন উপাস্য নেই। সকল গোপন ও প্রকাশ্য বিষয় জানেন। তিনি সবচেয়ে করুনাময়, সবচেয়ে দয়ালু।"],
  "59:23": ["He is the One Allah; there is no other god besides Him. The King, the Most Sacred, the Peace, the Most Faithful, the Supreme, the Almighty, the Most Powerful, the Most Dignified. Allah be glorified; far above having partners.","তিনিই সে এক ঈশ্বর; তাঁর পাশে অন্য কোন উপাস্য নেই। রাজা, সবচেয়ে পবিত্র, শান্তি, সবচেয়ে বিশ্বস্ত, সর্বোচ্চ, সর্বশক্তিমান, সবচেয়ে শক্তিধর, সবচেয়ে সন্মানিত। মহিমা ঈশ্বরের, অংশীদার থাকা থেকে অনেক ঊর্ধ্বে।"],
  "59:24": ["He is the One Allah; the Creator, the Initiator, the Designer. To Him belong the most beautiful names. Glorifying Him is everything in the heavens and the earth. He is the Almighty, Most Wise.","তিনিই সে এক ঈশ্বর; সৃষ্টিকর্তা, সূচনাকারী, নকশাকারী। সবচেয়ে সুন্দর নামগুলো তাঁর। আকাশমণ্ডলী ও পৃথিবীর সবকিছু তাঁর মহিমা ঘোষণা করে। তিনি সর্বশক্তিমান, সবচেয়ে প্রজ্ঞাবান।"],
  "60:1": ["O you who believe, you shall not befriend My enemies and your enemies, extending love and friendship to them, even though they have disbelieved in the truth that has come to you. They persecute the messenger, and you, just because you believe in Allah, your Lord. If you mobilize to struggle in My cause, seeking My blessings, how can you secretly love them? I am fully aware of everything you conceal, and everything you declare. Those among you who do this have indeed strayed off the right path.","হে তোমরা যারা বিশ্বাস কর, তোমরা বন্ধু  করো না আমার শত্রু এবং তোমাদের শত্রুদের, তাদের প্রতি ভালোবাসা ও বন্ধুত্বের হাত প্রসারিত করে দিয়ে, তা সত্ত্বেও যে তারা সেই সত্যে অবিশ্বাস করেছে যা তোমাদের কাছে এসেছে। তারা বার্তাবাহক ও তোমাদের প্রতি অত্যাচার করে শুধু এই কারনে যে তোমরা বিশ্বাস করো তোমাদের প্রভু ঈশ্বরকে। যদি তোমরা আমার পথে সংগ্রামের জন্য একত্রিত হও, আমার অনুগ্রহ সন্ধানে, তবে কেমন  করে গোপনে তোমরা তাদের ভালবাসতে পার? আমি পুরোপুরি অবগত যা তোমরা লুকাও আর যা তোমরা প্রকাশ করো। তোমাদের মধ্যে যারা তা করে তারা নিশ্চয় সঠিক পথ থেকে বিচ্যুত হয়েছে।"],
  "60:2": ["Whenever they encounter you, they treat you as enemies, and hurt you with their hands and tongues. They want you to disbelieve.","যখনি তারা তোমাদের মুখোমুখি হয়, তারা তোমাদের সাথে শত্রুর মত আচরণ করে, এবং তোমাদের আঘাত করে তাদের হাত ও তাদের জিহবা দিয়ে। তারা চায় তোমরা অবিশ্বাস করো।"],
  "60:3": ["Your relatives and your money can never help you. On the Day of Resurrection, He will judge among you. Allah is Seer of everything you do.","তোমাদের আত্মীয়-স্বজন এবং তোমাদের অর্থ কখনো তোমাদের সাহায্য করতে পারে না। পুনরুত্থান দিনে, তিনি তোমাদের মাঝে বিচার করবেন। ঈশ্বর দেখেন যা কিছু তোমরা করো।"],
  "60:4": ["A good example has been set for you by Abraham and those with him. They said to their people, \"We disown you and the idols that you worship besides Allah. We denounce you, and you will see nothing from us except animosity and hatred until you believe in Allah ALONE.\" However, a mistake was committed by Abraham when he said to his father, \"I will pray for your forgiveness, but I possess no power to protect you from Allah.\" \"Our Lord, we trust in You, and submit to You; to You is the final destiny.","তোমাদের জন্য রয়েছে ইব্রাহিম ও তার সাথীদের দারা স্থাপিত একটি ভাল উদাহরণ। তারা তাদের লোকদের বলেছিল, “আমরা তোমাদের এবং সে উপাস্যদের প্রত্যাখ্যান করি যাদেরকে তোমরা ঈশ্বরের পাশে উপাসনা করো। আমরা তোমাদের অভিযুক্ত করি, এবং তোমরা  আমাদের থেকে শত্রুতা ও ঘৃণা ছাড়া কিছু দেখবে না যতক্ষণ পর্যন্ত না তোমরা এক ঈশ্বরে বিশ্বাস কর।” কিন্তু, ইব্রাহীমের একটি ভুল হয়েছিল যখন সে তার পিতাকে বলেছিল, “আমি তোমার ক্ষমার জন্য প্রার্থনা করবো, কিন্তু আমার কোন ক্ষমতা নেই ঈশ্বর থেকে তোমাকে রক্ষা করার।”  “আমাদের প্রভু, আমরা আপনার উপর আস্থা রাখি এবং আপনার নিকট আত্মসমর্পণ করি; আপনার কাছেই চূড়ান্ত নিয়তি।"],
  "60:5": ["\"Our Lord, let us not be oppressed by those who disbelieved, and forgive us. You are the Almighty, Most Wise.\"","“আমাদের প্রভু, অবিশ্বাসীদের দ্বারা আমাদের নিপীড়িত হতে দিয়েন না, এবং আমাদের ক্ষমা করুন। আপনি সর্বশক্তিমান, সবচেয়ে প্রজ্ঞাবান”।"],
  "60:6": ["A good example has been set by them for those who seek Allah and the Last Day. As for those who turn away, Allah is in no need (of them), Most Praiseworthy.","যারা ঈশ্বর ও শেষ দিনকে চায় তাদের জন্য একটি ভাল উদাহরণ স্থাপিত আছে। আর তাদের ক্ষেত্রে যারা মুখ ফিরিয়ে নেয়, (তাদেরকে) ঈশ্বরের কোন প্রয়োজন নেই, সবচেয়ে প্রশংসিত।"],
  "60:7": ["Allah may change the animosity between you and them into love. Allah is Omnipotent. Allah is Forgiver, Most Merciful.","ঈশ্বর হয়তো তোমাদের ও তাদের মধ্যে শত্রুতাকে ভালোবাসায় পরিবর্তিত করে দেবেন। ঈশ্বর সর্বশক্তিমান। ঈশ্বর ক্ষমাশীল, সবচেয়ে করুণাময়।"],
  "60:8": ["Allah does not enjoin you from befriending those who do not fight you because of religion, and do not evict you from your homes. You may befriend them and be equitable towards them. Allah loves the equitable.","ঈশ্বর তোমাদের নিষেধ করেন না তাদের সাথে বন্ধুসুলভ হতে যারা ধর্ম নিয়ে তোমাদের সাথে লড়াই করে না, এবং তোমাদেরকে তোমাদের ঘর থেকে উচ্ছেদ করে না। তোমরা তাদের সাথে বন্ধুসুলভ হতে পারো এবং তাদের প্রতি ন্যায়পরায়ণ হও। ঈশ্বর  ন্যায়পরায়ণদের ভালোবাসেন।"],
  "60:9": ["Allah enjoins you only from befriending those who fight you because of religion, evict you from your homes, and band together with others to banish you. You shall not befriend them. Those who befriend them are the transgressors.","ঈশ্বর তোমাদেরকে শুধু তাদের সাথে বন্ধুসুলভ হতে নিষেধ করেন যারা তোমাদের সাথে যুদ্ধ করে ধর্ম নিয়ে, তোমাদেরকে তোমাদের ঘর থেকে উচ্ছেদ করে,  এবং তোমাদের নির্বাসিত করতে অন্যদের সাথে সঙ্ঘবদ্ধ হয়। তোমরা তাদের সাথে বন্ধুসুলভ হবে না। যারা তাদের সাথে বন্ধুসুলভ হয় তারা সীমালঙ্ঘনকারী।"],
  "60:10": ["O you who believe, when believing women (abandon the enemy and) ask for asylum with you, you shall test them. Allah is fully aware of their belief. Once you establish that they are believers, you shall not return them to the disbelievers. They are not lawful to remain married to them, nor shall the disbelievers be allowed to marry them. Give back the dowries that the disbelievers have paid. You commit no error by marrying them, so long as you pay them their due dowries. Do not keep disbelieving wives (if they wish to join the enemy). You may ask them for the dowry you had paid, and they may ask for what they paid. This is Allah's rule; He rules among you. Allah is Omniscient, Most Wise.","হে যারা বিশ্বাস করো, যখন বিশ্বাসী নারীরা (শত্রুদের পরিত্যাগ করে আর) তোমাদের কাছে আশ্রয় চায়, তোমরা তাদের পরীক্ষা করো। ঈশ্বর তাদের বিশ্বাস সম্পর্কে পূর্ণ অবগত। যদি তোমরা একবার নিশ্চিত করো যে তারা বিশ্বাসী, তোমরা অবিশ্বাসীদের কাছে তাদের ফেরত পাঠাবে না। তারা বৈধ নয় তাদের সাথে বিবাহ বন্ধনে আবদ্ধ থাকতে, না অবিশ্বাসীরা অনুমোদিত তাদের বিয়ে করতে। অবিশ্বাসীরা যে মোহরানা দিয়েছে তা ফিরিয়ে দাও। তাদের বিয়ে করে তোমরা কোন ভুল করো না, যদি না তোমরা তাদেরকে তাদের প্রাপ্য মোহরানা পরিশোধ কর। অবিশ্বাসী স্ত্রীদের রেখো না (যদি তারা শত্রুদের সাথে যোগ দিতে চায়)। তোমরা তাদের কাছে সে মোহরানা চাইতে পার যা তোমরা পরিশোধ করেছিলে, এবং তারা তা চাইতে পারে যা তারা দিয়েছিল। এটা ঈশ্বরের নিয়ম, তিনি তোমাদের মধ্যে শাসন করেন। ঈশ্বর সর্বজ্ঞ, সবচেয়ে প্রজ্ঞাবান।"],
  "60:11": ["If any of your wives join the enemies' camp, and you are forced to fight, you shall force the enemy to compensate the men who lost their wives, by giving them what they spent on their wives. You shall reverence Allah, in whom you believe.","যদি তোমাদের কারো স্ত্রী শত্রু শিবিরে যোগ দেয়, এবং তোমরা লড়াই করতে বাধ্য হও, তোমরা শত্রুদের বাধ্য করবে সে লোকদের ক্ষতিপূরণ দিতে যারা তাদের স্ত্রীদের হারিয়েছিল, তাদেরকে তা দিয়ে যা তারা তাদের স্ত্রীদের জন্য খরচ করেছিল। তোমরা ঈশ্বরকে ভক্তি করবে, যার উপর তোমরা বিশ্বাস করো।"],
  "60:12": ["O you prophet, when the believing women (who abandoned the disbelievers) to seek asylum with you pledge to you that they will not set up any idols besides Allah, nor steal, nor commit adultery, nor kill their children, nor fabricate any falsehood, nor disobey your righteous orders, you shall accept their pledge, and pray to Allah to forgive them. Allah is Forgiver, Most Merciful.","হে নবী, যখন বিশ্বাসী নারীরা (যারা অবিশ্বাসীদের পরিত্যাগ করেছে) তোমার কাছে আশ্রয় অন্বেষণ চায়, তোমার কাছে অঙ্গীকার করে যে তারা ঈশ্বরের পাশে অন্য উপাস্য স্থাপন করবে না, না চুরি করবে, না ব্যাভিচার করবে, না তাদের সন্তানদের হত্যা করবে, না কোন মিথ্যা উদ্ভাবন করবে, না তোমার ন্যায়নিষ্ঠ হুকুম অমান্য করবে, তুমি তাদের অঙ্গীকার গ্রহন কর, এবং ঈশ্বরের কাছে তাদের ক্ষমার জন্য প্রার্থনা কর । ঈশ্বর ক্ষমাশীল, পরম করুণাময়।"],
  "60:13": ["O you who believe, do not befriend people with whom Allah is angry, and who are hopelessly stuck in disbelief; they are just as hopeless as the disbelievers who are already in the graves.","হে যারা বিশ্বাস কর, তাদের সাথে বন্ধুসুলভ হইও না যাদের প্রতি ঈশ্বর রাগান্বিত, এবং যারা অবিশ্বাসে আশাহীন ভাবে আটকে আছে; তারা ঠিক তেমন আশাহীন যেমন আশাহীন সেই অবিশ্বাসীরা যারা ইতিমধ্যে কবরের মধ্যে আছে।"],
  "61:1": ["Glorifying Allah is everything in the heavens and everything on earth. He is the Almighty, Most Wise.","আকাশমণ্ডলী ও পৃথিবীর সবকিছু ঈশ্বরের মহিমা ঘোষণা করছে। তিনি সর্বশক্তিমান, সবচেয়ে প্রজ্ঞাবান।"],
  "61:2": ["O you who believe, why do you say what you do not do?","হে যারা বিশ্বাস কর, কেন তোমরা বল যা তোমরা কর না?"],
  "61:3": ["Most abominable in the sight of Allah is that you say what you do not do.","ঈশ্বরের কাছে সবচেয়ে ঘৃণিত বিষয় হলো তোমাদের বলা যা তোমরা কর না।"],
  "61:4": ["Allah loves those who fight in His cause united in one column, like the bricks in one wall.","ঈশ্বর তাদের ভালোবাসেন যারা তাঁর কারনে লড়াই করে সম্মিলিতভাবে এক স্তম্ভে, কোন দেয়ালের ইটগুলোর মতো।"],
  "61:5": ["Recall that Moses said to his people, \"O my people, why do you hurt me, even though you know that I am Allah's messenger to you?\" When they deviated, Allah diverted their hearts. For Allah does not guide the wicked people.","স্মরণ কর যে মুসা তার লোকদের বলেছিল, “হে আমার লোকেরা, কেন তোমরা আমাকে আঘাত কর, যদিও তোমরা জানো যে আমি তোমাদের কাছে ঈশ্বরের বার্তাবাহক?” যখন তারা পথচ্যুত হলো, ঈশ্বর তাদের হৃদয়কে বিমুখ করে দিলেন। কারন ঈশ্বর মন্দ লোকদের পথ দেখান না।"],
  "61:6": ["Recall that Jesus, son of Mary, said, \"O Children of Israel, I am Allah's messenger to you, confirming the Torah and bringing good news of a messenger to come after me whose name will be even more praised (Ahmad).\" Then, when he showed them the clear proofs, they said, \"This is profound magic.\"","স্মরণ কর, মরিয়মের পুত্র ঈসা বলেছিল, “হে ইসরাইলের সন্তানেরা, আমি তোমাদের প্রতি ঈশ্বরের বার্তাবাহক, তওরাতকে নিশ্চিত করছি এবং আমার পর একজন বার্তাবাহক আগমনের সুসংবাদ দিচ্ছি যারা নামকে করা হবে আরও বেশি প্রশংসিত (আহমদ)।” অতঃপর যখন সে তাদের স্পষ্ট প্রমাণদি দেখাল, তারা বলল, “এটা স্পষ্ট জাদু।”"],
  "61:7": ["Who is more evil than one who fabricates lies about Allah, and he is being invited to Submission? Allah does not guide the evil people.","সে ব্যক্তির চেয়ে কে অধিক মন্দ যে ঈশ্বর সম্পর্কে মিথ্যা উদ্ভাবন করে, এবং তাকে আত্মসমর্পণে দাওয়াত দেওয়া হচ্ছে? ঈশ্বর মন্দ লোকদের পথ দেখান না।"],
  "61:8": ["They wish to put out Allah's light with their mouths. But Allah insists upon perfecting His light, in spite of the disbelievers.","তারা তাদের মুখ দিয়ে ঈশ্বরের আলো নেভাতে চায়। কিন্তু ঈশ্বর তাঁর আলোকে নির্ভুলভাবে পূর্ণ করার উপর জোর দেন, অবিশ্বাসীদের সত্ত্বেও।"],
  "61:9": ["He has sent His messenger with the guidance and the true religion, and will make it dominate all religions, in spite of the idol worshipers.","তিনি তাঁর বার্তাবাহককে পাঠিয়েছেন পথনির্দেশনা এবং সত্য ধর্ম দিয়ে, আর একে সকল ধর্মের উপর কর্তৃত্বকারী করবেন, প্রতিমা উপাসকদের সত্ত্বেও।"],
  "61:10": ["O you who believe, let Me inform you of a trade that will save you from painful retribution.","হে তোমরা যারা বিশ্বাস কর, চল আমি তোমাদেরকে একটি বাণিজ্য সম্পর্কে জানাই যা তোমাদেরকে যন্ত্রণাদায়ক শাস্তি থেকে রক্ষা করবে।"],
  "61:11": ["Believe in Allah and His messenger and strive in the cause of Allah with your money and your lives. This is the best deal for you, if you only knew.","ঈশ্বর ও তাঁর বার্তাবাহককে বিশ্বাস কর এবং ঈশ্বরের পথে সংগ্রাম কর তোমাদের অর্থ ও তোমাদের জীবন দিয়ে। এটি তোমাদের জন্য সর্বোত্তম বাণিজ্য, যদি তোমরা কেবল জানতে।"],
  "61:12": ["In return, He forgives your sins, and admits you into gardens with flowing streams, with beautiful mansions in the gardens of Eden. This is the greatest triumph.","বিনিময়ে, তিনি তোমাদের পাপ ক্ষমা করেন এবং তোমাদের প্রবেশ করান প্রবাহিত ঝর্ণাসহ বাগানগুলোতে, সাথে রয়েছে ইডেনের সুন্দর অট্টালিকা বিশিষ্ট বাগানগুলো। এটিই সর্বোত্তম বিজয়।"],
  "61:13": ["Additionally, you get something you truly love: support from Allah and guaranteed victory. Give good news to the believers.","উপরন্তু, তোমরা পাও এমনকিছু যা তোমরা সত্যিকারভাবে ভালবাসোঃ  ঈশ্বরের পক্ষ থেকে সমর্থন ও প্রতিশ্রুত বিজয়। বিশ্বাসীদের সুসংবাদ দাও।"],
  "61:14": ["O you who believe, be Allah's supporters, like the disciples of Jesus, son of Mary. When he said to them, \"Who are my supporters towards Allah,\" they said, \"We are Allah's supporters.\" Thus, a group from the Children of Israel believed, and another group disbelieved. We helped those who believed against their enemy, until they won.","হে যারা বিশ্বাস কর, ঈশ্বরের সমর্থনকারী হও, মরিয়ম পুত্র ঈসার শিষ্যদের মত, যখন সে তাদের বলল, “ঈশ্বরের পথে কে আমরা সমর্থনকারী,” তারা বলল, “আমরা ঈশ্বরের সমর্থনকারী।” এরূপে, ইসরাইলের সন্তানদের একটি দল বিশ্বাস করলো এবং অন্য দলটি অবিশ্বাস করল। যারা বিশ্বাস করেছিল আমরা তাদেরকে তাদের শত্রুদের বিরুদ্ধে সাহায্য করলাম, যতক্ষণ না তারা জয়ী হল।"],
  "62:1": ["Glorifying Allah is everything in the heavens and everything on earth; the King, the Most Sacred, the Almighty, the Most Wise.","আকাশমণ্ডলীর সবকিছু এবং পৃথিবীর সবকিছু ঈশ্বরের মহিমা ঘোষণা করে; যিনি রাজা, সবচেয়ে পবিত্র, সর্বশক্তিমান, সবচেয়ে প্রজ্ঞাবান।"],
  "62:2": ["He is the One who sent to the gentiles a messenger from among them, to recite to them His revelations, purify them, and teach them the scripture and wisdom. Before this, they had gone far astray.","তিনিই সে সত্ত্বা যিনি (ঐশীগ্রন্থ সম্পর্কে) অজ্ঞ লোকদের কাছে একজন বার্তাবাহক পাঠিয়েছিলেন  তাদেরই মধ্য থেকে, তাদের কাছে তাঁর প্রকাশনাবলি আবৃতি করতে, তাদেরকে পবিত্র করতে, তাদেরকে শিক্ষা দিতে ঐশীগ্রন্থ ও প্রজ্ঞা। এর আগে, তারা অত্যধিক পথচ্যুত হয়ে গিয়েছিল।"],
  "62:3": ["And to many generations subsequent to them. He is the Almighty, Most Wise.","এবং তাদের পরবর্তী বহু প্রজন্মের কাছে। তিনি সর্বশক্তিমান, সবচেয়ে প্রজ্ঞাবান।"],
  "62:4": ["Such is Allah's grace that He bestows upon whomever He wills. Allah is Possessor of Infinite Grace.","এমনি ঈশ্বরের করুণা তা তিনি যার প্রতি ইচ্ছা অর্পণ করেন। ঈশ্বর অসীম করুণার অধিকারী।"],
  "62:5": ["The example of those who were given the Torah then failed to uphold it is like the donkey carrying great works of literature. Miserable indeed is the example of people who rejected Allah's revelations. Allah does not guide the wicked people.","যাদেরকে তওরাত দেয়া হয়েছিল এরপর তা মেনে চলতে ব্যর্থ হয়েছিল তাদের উদাহরণ সেই গাধার মত যে সাহিত্যের মহান কর্ম বহন করছে। নিশ্চয় শোচনীয় সেই লোকদের উদাহরণ যারা ঈশ্বরের প্রকাশনাবলি প্রত্যাখ্যান করেছিল। ঈশ্বর মন্দ লোকদের পথ দেখান না।"],
  "62:6": ["Say, \"O you who are Jewish, if you claim that you are Allah's chosen, to the exclusion of all other people, then you should long for death if you are truthful!\"","বল, ‘হে ইহুদিরা, যদি তোমরা দাবি কর যে তোমরা ঈশ্বরের বাছাইকৃত, অন্য সকল লোকদের বাদ দিয়ে, তবে তোমাদের উচিৎ মৃত্যু কামনা করা যদি তোমরা সত্যবাদী হও!”"],
  "62:7": ["They will never long for it, because of what they have committed. Allah is fully aware of the wicked.","তারা কখনই তা কামনা করবে না, তারা যা করেছে তার কারনে। ঈশ্বর মন্দদের সম্পর্কে পূর্ণ অবগত।"],
  "62:8": ["Say, \"The death that you are trying to evade will catch up with you sooner or later. Then you will be returned to the Knower of all secrets and declarations, then He will inform you of everything you had done.\"","বল, “যে মৃত্যুকে তোমরা এড়াতে চাও তা আগে বা পরে তোমাদের পাকড়াও করবে। এরপর তোমরা সকল গোপন ও প্রকাশ্য বিষয়ে জ্ঞানীর কাছে ফিরে যাবে, তখন তিনি তোমাদের জানাবেন যাকিছু তোমরা করেছিলে।"],
  "62:9": ["O you who believe, when the Congregational Prayer (Salat Al-Jumu'ah) is announced on Friday, you shall hasten to the commemoration of Allah, and drop all business. This is better for you, if you only knew.","হে যারা বিশ্বাস কর, যখন শুক্রবারের সম্মিলিত প্রার্থনার (সালাত আল-জুম্মাহর) ঘোষণা দেয়া হয়, তোমরা ঈশ্বরের স্মরণে দ্রুত মিলিত হও, এবং সকল ব্যবসা বন্ধ কর। এটি তোমাদের জন্য উত্তম, যদি কেবল তোমরা জানতে।"],
  "62:10": ["Once the prayer is completed, you may spread through the land to seek Allah's bounties, and continue to remember Allah frequently, that you may succeed.","প্রার্থনা সম্পন্ন হলে, তোমরা জমিনে ছড়িয়ে পড়তে পারো  ঈশ্বরের অনুগ্রহ সন্ধানে, এবং ঈশ্বরকে ঘন ঘন স্মরণ করতে থাক যাতে তোমরা সফলকাম হতে পার।"],
  "62:11": ["When some of them come across a business deal, or some entertainment, they rush to it and leave you standing! Say, \"What Allah possesses is far better than the entertainment or the business. Allah is the best Provider.\"","যখন তাদের কেউ কেউ কোন ব্যবসায়িক লেনদেন বা কিছু বিনোদনের সম্মুখীন হয়, তারা এর দিকে দ্রুত ছুটে যায় এবং তোমাকে দাড় করিয়ে রাখে! বল, “যা ঈশ্বরের কাছে আছে তা বিনোদন বা ব্যবসা থেকে অনেক অনেক উত্তম। ঈশ্বর সর্বোত্তম রিজিকদাতা।"],
  "63:1": ["When the hypocrites come to you they say, \"We bear witness that you are the messenger of Allah.\" Allah knows that you are His messenger, and Allah bears witness that the hypocrites are liars.","যখন ভণ্ডরা তোমার কাছে আসে তারা বলে, “আমরা সাক্ষ্য দেই যে আপনি ঈশ্বরের বার্তাবাহক।” ঈশ্বর জানেন যে তুমি ঈশ্বরের বার্তাবাহক, এবং ঈশ্বর সাক্ষ্য দেন যে ভণ্ডরা মিথ্যাবাদী।"],
  "63:2": ["Under the guise of their apparent faith, they repel the people from the path of Allah. Miserable indeed is what they do.","তাদের লোক-দেখানো বিশ্বাসের আড়ালে, তারা মানুষকে ঈশ্বরের পথে বাধা দেয়। নিশ্চয় শোচনীয় যা তারা করে।"],
  "63:3": ["This is because they believed, then disbelieved. Hence, their minds are blocked; they do not understand.","এটা এ কারনে যে তারা বিশ্বাস করেছিল, এরপর অবিশ্বাস করলো। সুতরাং, তাদের মনগুলো তালাবদ্ধ; তারা বোঝে না।"],
  "63:4": ["When you see them, you may be impressed by their looks. And when they speak, you may listen to their eloquence. They are like standing logs. They think that every call is intended against them. These are the real enemies; beware of them. Allah condemns them; they have deviated.","যখন তুমি তাদের দেখ, তুমি হয়তো তাদের বাহ্যরূপ দেখে অভিভূত হবে। আর যখন তারা কথা বলে, তুমি হয়তো তাদের বাকপটুতা শুনে থাকবে। তারা দাঁড়িয়ে থাকা কাঠের তক্তার মতো। প্রতিটি আহবানকে তারা নিজেদের বিরুদ্ধে মনে করে। এরাই আসল শত্রু; তাদের ব্যাপারে সাবধান হও। ঈশ্বর তাদের নিন্দা করেন; তারা পথচ্যুত হয়েছে।"],
  "63:5": ["When they are told, \"Come let the messenger of Allah pray for your forgiveness,\" they mockingly turn their heads, and you see them repel others and act arrogantly.","যখন তাদের বলা হয়, “আসো, ঈশ্বরের বার্তাবাহক তোমাদের জন্য ক্ষমা প্রার্থনা করবে,” তারা উপহাস করে তাদের মাথা ঘুরিয়ে নেয়, আর তুমি দেখ তারা অন্যদের বাধা দেয় এবং উদ্ধত আচরণ করে।"],
  "63:6": ["It is the same for them, whether you pray for their forgiveness, or not pray for their forgiveness; Allah will not forgive them. For Allah does not guide the wicked people.","এটি তাদের জন্য সমান, তুমি তাদের ক্ষমার জন্য প্রার্থনা কর অথবা তাদের ক্ষমার জন্য প্রার্থনা না কর; ঈশ্বর তাদের ক্ষমা করবেন না। কারন ঈশ্বর মন্দ লোকদের পথ প্রদর্শন করেন না।"],
  "63:7": ["They are the ones who say, \"Do not give any money to those who followed the messenger of Allah, perhaps they abandon him!\" However, Allah possesses the treasures of the heavens and the earth, but the hypocrites do not comprehend.","তারাই সেসব ব্যক্তি যারা বলে, “তাদেরকে কোন অর্থ দিও না যারা ঈশ্বরের বার্তাবাহকের অনুসরণ করে, হয়তো তারা তাকে পরিত্যাগ করবে!” কিন্তু, ঈশ্বরের কাছে রয়েছে আকাশমণ্ডলী ও পৃথিবীর সকল ধন-সম্পদ, কিন্তু ভণ্ডরা অনুধাবন করে না।"],
  "63:8": ["They say, \"If we go back to the city, the powerful therein will evict the weak (and we will be victimized).\" (They should know that) all dignity belongs to Allah and His messenger, and the believers. However, the hypocrites do not know.","তারা বলে, “যদি তোমরা সেই শহরে ফিরে যাও, সেখানকার ক্ষমতাধররা দুর্বললোকদের উচ্ছেদ করবে (এবং আমরা অত্যাচারের শিকার হবো)।” (তাদের জানা উচিৎ যে) সকল মর্যাদা ঈশ্বর ও তাঁর বার্তাবাহকের, এবং বিশ্বাসীদের। কিন্তু, ভণ্ডরা জানে না।"],
  "63:9": ["O you who believe, do not be distracted by your money and your children from remembering Allah. Those who do this are the losers.","হে যারা বিশ্বাস কর, তোমাদের অর্থ ও তোমাদের সন্তানদের কারনে ঈশ্বরের স্মরণ থেকে বিচ্যুত হইও না। যারা তা করে তারা ক্ষতিগ্রস্থ।"],
  "63:10": ["You shall give from our provisions to you before death comes to you, then you say, \"My Lord, if only You could delay this for a short while! I would then be charitable and join the righteous!\"","তোমাদেরকে আমাদের দেয়া জীবিকা থেকে তোমরা দাও তোমাদের কাছে মৃত্যু আসার পূর্বে, অন্যথায় তোমরা বল, “আমাদের প্রভু, শুধু যদি কিছু সময়ের জন্য আপনি একে বিলম্বিত করাতে পারতেন! আমি তবে দানশীল হতাম এবং সৎকর্মশীলদের সাথে যোগ দিতাম।"],
  "63:11": ["Allah never delays the appointed time of death for any soul. Allah is fully Cognizant of everything you do.","ঈশ্বর কখনই কোন আত্মার মৃত্যুর নির্ধারিত সময়কে বিলম্বিত করেন না। তোমরা যা কিছু কর ঈশ্বর সে সম্পর্কে সম্পূর্ণ অবগত।"],
  "64:1": ["Glorifying Allah is everything in the heavens and everything on earth. To Him belongs all kingship, and to Him belongs all praise, and He is Omnipotent.","আকাশমণ্ডলীর সবকিছু এবং পৃথিবীর সবকিছু ঈশ্বরের মহিমা ঘোষণা করে। সকল রাজত্ব তাঁর, এবং সকল প্রশংসা তাঁর, এবং তিনি সর্বশক্তিমান।"],
  "64:2": ["He is the One who created you, then among you there is the disbeliever, and the believer. Allah is fully Seer of everything you do.","তিনিই সে সত্ত্বা যিনি তোমাদের সৃষ্টি করেছেন, এরপর তোমাদের মধ্যে আছে অবিশ্বাসী ও বিশ্বাসী। ঈশ্বর তোমাদের করা সবকিছুর পূর্ণ দ্রষ্টা।"],
  "64:3": ["He created the heavens and the earth for a specific purpose, designed you and perfected your design, then to Him is the final destiny.","তিনি একটি নির্দিষ্ট উদ্দেশ্যে আকাশমণ্ডলী ও পৃথিবী সৃষ্টি করেছেন, তোমাদের নকশা করেছেন এবং তোমাদের নকশাকে নিখুঁত করেছেন, এরপর তাঁর দিকেই চূড়ান্ত নিয়তি।"],
  "64:4": ["He knows everything in the heavens and the earth, and He knows everything you conceal and everything you declare. Allah is fully aware of the innermost thoughts.","তিনি আকাশমণ্ডলী ও পৃথিবীর সবকিছু জানেন, এবং তিনি জানেন যা কিছু তোমরা গোপন কর আর যা কিছু তোমরা প্রকাশ কর। ঈশ্বর গভীরতম চিন্তাগুলো সম্পর্কে পূর্ণ অবগত।"],
  "64:5": ["Have you noted those who disbelieved in the past, then suffered the consequences of their decision? They incurred a painful retribution.","তোমরা কি তাদের লক্ষ্য করেছো যারা অতীতে অবিশ্বাস করেছিল, এরপর তাদের সিদ্ধান্তের ফল ভোগ করেছিল? তারা যন্ত্রণাদায়ক শাস্তির ভোগ করেছিল।"],
  "64:6": ["This is because their messengers went to them with clear proofs, but they said, \"Shall we follow humans like us?\" They disbelieved and turned away. Allah does not need them; Allah is in no need, Praiseworthy.","এটা এই কারনে যে তাদের বার্তাবাহকরা স্পষ্ট প্রমানাদি নিয়ে তাদের কাছে গিয়েছিল, কিন্তু তারা বলেছিল, “আমরা কি  আমাদের মত মানুষের অনুসরণ করব?” তারা অবিশ্বাস করলো এবং মুখ ফিরিয়ে নিয়েছিল। তাদেরকে ঈশ্বরের প্রয়োজন নেই; ঈশ্বর অভাব মুক্ত, প্রশংসনীয়।"],
  "64:7": ["Those who disbelieved claim that they will not be resurrected! Yes indeed, by my Lord, you will be resurrected, and you will be held accountable for everything you have done. This is easy for Allah to do.","যারা অবিশ্বাস করেছিল তারা দাবি করে যে তারা পুনরুত্থিত হবে না! হ্যাঁ নিশ্চয়, আমার প্রভুর শপথ, তোমরা পুনরুত্থিত হবে, এবং তোমাদেরকে হিসাব দিতে হবে সবকিছুর জন্য যা তোমরা করেছো। এটি ঈশ্বরের জন্য করা সহজ।"],
  "64:8": ["Therefore, you shall believe in Allah and His messenger, and the light that we have revealed herein. Allah is fully Cognizant of everything you do.","অতএব, তোমরা বিশ্বাস কর ঈশ্বর ও তাঁর বার্তাবাহককে, এবং সে আলো যা আমরা এখানে প্রকাশ করেছি। তোমরা যা কিছু কর সে সম্পর্কে ঈশ্বর পূর্ণ অবগত।"],
  "64:9": ["The day will come when He summons you to the Day of Summoning. That is the Day of Mutual Blaming. Anyone who believes in Allah and leads a righteous life, He will remit his sins, and will admit him into gardens with flowing streams. They abide therein forever. This is the greatest triumph.","সে দিন আসবে যখন তিনি তোমাদেরকে  আহবানের দিন তলব করবেন। এটাই পারস্পরিক দোষারোপের দিন। যে কেউ আল্লাহকে বিশ্বাস করে এবং সৎ জীবন যাপন করে, তিনি তার পাপ মোচন করবেন, এবং তাকে প্রবেশ করাবেন প্রবাহিত ঝর্ণা সহ বাগানে। তারা সেখানে চিরকাল বসবাস করে। এটাই সর্বশ্রেষ্ঠ বিজয়।"],
  "64:10": ["As for those who disbelieve and reject our revelations, they are the dwellers of the Hellfire; they abide therein forever. What a miserable destiny!","আর যারা অবিশ্বাস করে ও আমাদের প্রকাশনাবলি প্রত্যাখ্যান করে, তারা নরকাগ্নির বাসিন্দা; তারা সেখানে চিরকাল বাস করে। কি এক শোচনীয় নিয়তি!"],
  "64:11": ["Nothing happens to you except in accordance with Allah's will. Anyone who believes in Allah, He will guide his heart. Allah is fully aware of all things.","তোমাদের কোনকিছুই ঘটে না ঈশ্বরের ইচ্ছা অনুসারে ব্যতিত । যে কেউ ঈশ্বরে বিশ্বাস করে, তিনি তার হৃদয়কে পথ দেখাবেন। ঈশ্বর সকল বস্তু সম্পর্কে পূর্ণ অবগত।"],
  "64:12": ["You shall obey Allah and you shall obey the messenger. If you turn away, then the sole mission of our messenger is to deliver the message.","তোমরা ঈশ্বরকে মান্য কর এবং বার্তাবাহককে মান্য কর। যদি তোমরা মুখ ফিরিয়ে নাও, তবে আমাদের বার্তাবাহকের একমাত্র উদ্দেশ্য হল বার্তা পৌঁছে দেওয়া।"],
  "64:13": ["Allah: there is no other god besides Him. In Allah the believers shall trust.","ঈশ্বর : তাঁর পাশে অন্য কোন উপাস্য নেই। বিশ্বাসীরা ঈশ্বরে আস্থা রাখুক।"],
  "64:14": ["O you who believe, your spouses and your children can be your enemies; beware. If you pardon, forget, and forgive, then Allah is Forgiver, Most Merciful.","হে যারা বিশ্বাস কর, তোমাদের জীবনসঙ্গী এবং তোমাদের সন্তানরা তোমাদের শত্রু হতে পারে; সতর্ক হও। যদি তোমরা মার্জনা কর, ভুলে যাও এবং ক্ষমা করো, তবে ঈশ্বর ক্ষমাশীল, সবচেয়ে করুণাময়।"],
  "64:15": ["Your money and children are a test, and Allah possesses a great recompense.","তোমাদের অর্থ ও তোমাদের সন্তানাদি একটি পরীক্ষা, এবং ঈশ্বরের কাছে আছে এক মহা প্রতিদান।"],
  "64:16": ["Therefore, you shall reverence Allah as much as you can, and listen, and obey, and give (to charity) for your own good. Anyone who is protected from his own stinginess, these are the successful ones.","অতএব, তোমরা ঈশ্বরের ভক্তি কর যত বেশি তোমরা পারো, এবং শোন, এবং মেনে চলো, এবং দাও (দান হিসেবে) তোমাদের নিজেদের ভালোর জন্য। যেকেউ তার নিজের কৃপণতা থেকে সুরক্ষিত, এরাই সফলকাম ব্যক্তি।"],
  "64:17": ["If you lend Allah a loan of righteousness, He will multiply the reward for you manifold, and forgive you. Allah is Appreciative, Clement.","যদি তোমরা ঈশ্বরকে সততার ঋণ দাও, তিনি তোমাদের জন্য পুরস্কার বহুগুনে বৃদ্ধি করবেন, এবং তোমাদের ক্ষমা করবেন। ঈশ্বর যথার্থ মূল্যায়নকারী, সহনশীল।"],
  "64:18": ["The Knower of all secrets and declarations; the Almighty, Most Wise.","সকল গোপন ও প্রকাশ্য বিষয়ের জ্ঞানী; সর্বশক্তিমান। সবচেয়ে প্রজ্ঞাবান।"],
  "65:1": ["O you prophet, when you people divorce the women, you shall ensure that a divorce interim is fulfilled. You shall measure such an interim precisely. You shall reverence Allah your Lord. Do not evict them from their homes, nor shall you make life miserable for them, to force them to leave on their own, unless they commit a proven adultery. These are Allah's laws. Anyone who transgresses Allah's laws commits an injustice against himself. You never know; maybe Allah wills something good to come out of this.","হে নবি, যখন তোমরা পুরুষরা কোন নারীকে তালাক দাও, তোমরা নিশ্চিত হবে যে তালাকের অন্তবর্তীকাল পূর্ণ করা হয়েছে। তোমরা এই অন্তবর্তীকাল নির্ভুলভাবে গণনা করবে। তোমরা তোমাদের প্রভু ঈশ্বরকে ভক্তি করবে। তাদেরকে তাদের বাড়ি থেকে বের করে দিও না, না তোমরা তাদের জন্য জীবনকে অতিষ্ঠ করে তুলবে, নিজ থেকে তাদেরকে বের হয়ে যেতে বাধ্য করতে, যদি না তারা কোন প্রমাণিত ব্যভিচার করে। এগুলো ঈশ্বরের আইন। যেকেউ ঈশ্বরের আইন লঙ্ঘন করে সে তার নিজের বিরুদ্ধে অবিচার করে। তুমি কখনো জানো না; হয়তো ঈশ্বর চান এর থেকে ভালো কিছু হোক।"],
  "65:2": ["Once the interim is fulfilled, you may reconcile with them equitably, or go through with the separation equitably. You shall have two equitable witnesses witness the divorce before Allah. This is to enlighten those who believe in Allah and the Last Day. Anyone who reverences Allah, He will create an exit for him.","অন্তবর্তীকাল পূর্ণ হওয়া মাত্র, তোমরা তাদের সাথে ন্যায়সঙ্গতভাবে পুনর্মিলিত হতে পারো অথবা ন্যায়সঙ্গতভাবে আলাদা হয়ে যেতে পারো। তালাকের সাক্ষী হওয়ার জন্য ঈশ্বরের সামনে তোমরা দুজন ন্যায়পরায়ণ সাক্ষী রাখবে। এর কারণ, জ্ঞান দান করা তাদেরকে যারা ঈশ্বর ও শেষ দিবসে বিশ্বাস করে। যেকেউ ঈশ্বরকে ভক্তি-শ্রদ্ধা করে, তিনি তার জন্য প্রস্থানের পথ সৃষ্টি করবেন।"],
  "65:3": ["And will provide for him whence he never expected. Anyone who trusts in Allah, He suffices him. Allah's commands are done. Allah has decreed for everything its fate.","এবং তার জন্য জীবনোপকরণ সরবরাহ করবেন যেখান থেকে সে কখনো আশা করেনি। যে কেউ ঈশ্বরের প্রতি আস্থা রাখে, তিনি তার জন্য যথেষ্ট। ঈশ্বরের হুকুম সম্পাদিত হয়েছে। ঈশ্বর সবকিছুর জন্য এর নিয়তি নির্ধারণ করেছেন।"],
  "65:4": ["As for the women who have reached menopause, if you have any doubts, their interim shall be three months. As for those who do not menstruate, and discover that they are pregnant, their interim ends upon giving birth. Anyone who reverences Allah, He makes everything easy for him.","আর যে নারী রজোবন্ধে পৌঁছেছে, যদি তোমাদের কোন সন্দেহ থাকে, তাদের অন্তবর্তীকাল হবে তিন মাস। আর যাদের ঋতুস্রাব হয়নি, এবং আবিষ্কার করে যে তারা অন্তঃসত্ত্বা, তাদের অন্তবর্তীকাল শেষ হবে সন্তান প্রসব করার পর। যে কেউ ঈশ্বরকে ভক্তি করে, তিনি সব কিছু তার জন্য সহজ করে দেন।"],
  "65:5": ["This is Allah's command that He sends down to you. Anyone who reverences Allah, He remits his sins, and rewards him generously.","এটি ঈশ্বরের হুকুম যা তিনি তোমাদের কাছে অবতীর্ণ করেন। যে কেউ ঈশ্বরকে ভক্তি করে, তিনি তার পাপ ক্ষমা করেন এবং তাকে উদারভাবে পুরস্কৃত করেন।"],
  "65:6": ["You shall allow them to live in the same home in which they lived with you, and do not make life so miserable for them that they leave on their own. If they are pregnant, you shall spend on them until they give birth. If they nurse the infant, you shall pay them for this service. You shall maintain the amicable relations among you. If you disagree, you may hire another woman to nurse the child.","তোমরা একই ঘরে তাদের বাস করতে দেবে যেখানে তারা তোমাদের সাথে বাস করতো এবং তাদের জীবনকে এতো দুঃসহ করে তুলো না যে তারা নিজ থেকে বের হয়ে যায়। যদি তারা অন্তঃসত্ত্বা হয়, তোমরা তাদের জন্য খরচ করবে যতক্ষণ না তারা সন্তান প্রসব করে। যদি তারা নবজাতককে স্তন্য দান করে, এই সেবার জন্য তোমরা তাদের প্রাপ্য পারিশ্রমিক দাও। তোমরা তোমাদের মধ্যে শান্তিপূর্ণ সম্পর্ক বজায় রাখবে। যদি তোমরা অমত করো, তবে শিশুটিকে স্তন্য দান করতে অন্য নারীকে তোমরা ভাড়া করতে পার।"],
  "65:7": ["The rich husband shall provide support in accordance with his means, and the poor shall provide according to the means that Allah bestowed upon him. Allah does not impose on any soul more than He has given it. Allah will provide ease after difficulty.","ধনী স্বামী তার সামর্থ্য অনুসারে ভরণপোষণ দিবে, এবং গরীব সে অনুসারে দিবে যা ঈশ্বর তার উপর অর্পণ করেছেন। আল্লাহ কোন আত্মাকে তাঁকে দেয়া সামর্থ্যের অতিরিক্ত বোঝা চাপিয়ে দেন না। ঈশ্বর কষ্টের পর আরাম দিবেন।"],
  "65:8": ["Many a community rebelled against the commands of its Lord and against His messengers. Consequently, we held them strictly accountable, and requited them a terrible requital.","অনেক সম্প্রদায় তাদের প্রভুর প্রত্যাদেশাবলি ও তাঁর বার্তাবাহকদের বিরুদ্ধে বিদ্রোহ করেছিল। পরিণামে, আমরা তাদের কাছ থেকে কঠোর হিসাব নিয়েছিলাম, এবং তাদেরকে প্রতিদান দিয়েছিলাম এক যন্ত্রণাদায়ক প্রতিদান।"],
  "65:9": ["They suffered the consequences of their decisions; a profound loss.","তারা তাদের সিদ্ধান্তের পরিণাম ভোগ করেছিল, এক অসামান্য ক্ষতি।"],
  "65:10": ["Allah has prepared for them severe retribution. Therefore, you shall reverence Allah, O you who possess intelligence and believed. Allah has sent down to you a message—","ঈশ্বর তাদের জন্য কঠিন শাস্তি প্রস্তুত করেছেন। অতএব, তোমরা ঈশ্বরকে ভক্তি কর, হে যারা বুদ্ধিমত্তার অধিকারী এবং বিশ্বাস করেছো। ঈশ্বর তোমাদের কাছে একটি বার্তা অবতীর্ণ করেছেন-"],
  "65:11": ["a messenger who recites to you Allah's revelations, clearly, to lead those who believe and work righteousness out of the darkness into the light. Anyone who believes in Allah and leads a righteous life, He will admit him into gardens with flowing streams; they abide therein forever. Allah will generously reward him.","একজন বার্তাবাহক যে তোমাদের কাছে ঈশ্বরের প্রকাশনাবলি আবৃতি করে, স্পষ্টভাবে, তাদেরকে অন্ধকার থেকে আলোতে পরিচালিত করতে যারা বিশ্বাস করে ও সৎ জীবন যাপন করে। যেকেউ ঈশ্বরে বিশ্বাস করে ও সৎ জীবন যাপন করে, তিনি তাকে প্রবাহিত ঝর্ণা সহ বাগানে প্রবেশ করাবেন; তারা সেখানে চিরকাল বাস করবে। ঈশ্বর তাদেরকে উদারভাবে পুরস্কার দেবেন।"],
  "65:12": ["Allah created seven universes and the same number of earths. The commands flow among them. This is to let you know that Allah is Omnipotent, and that Allah is fully aware of all things.","ঈশ্বর সৃষ্টি করেছেন সাত মহাকাশ এবং একই সংখ্যক পৃথিবী। এগুলোর মধ্যে প্রত্যাদেশাবলি প্রবাহিত হয়। এটি কেবল তোমাদের জানানোর জন্য যে ঈশ্বর সর্বশক্তিমান এবং ঈশ্বর সকল বস্তু সম্পর্কে পূর্ণ অবগত।"],
  "66:1": ["O you prophet, why do you prohibit what Allah has made lawful for you, just to please your wives? Allah is Forgiver, Merciful.","হে নবী, কেন তুমি তা নিষিদ্ধ করো, যা ঈশ্বর তোমার জন্য আইনসিদ্ধ করেছেন, কেবল তোমার স্ত্রীদের সন্তুষ্ট করতে? ঈশ্বর ক্ষমাশীল, করুনাময়।"],
  "66:2": ["Allah has decreed for you the laws dealing with your oaths. Allah is your Lord, and He is the Omniscient, Most Wise.","ঈশ্বর তোমাদের কসমের ক্ষেত্রে করনীয় বিষয়ে তোমাদের জন্য আইন প্রকাশ করেছেন। ঈশ্বর তোমাদের প্রভু, এবং তিনি সর্বজ্ঞ, পরম জ্ঞানী।"],
  "66:3": ["The prophet had trusted some of his wives with a certain statement, then one of them spread it, and Allah let him know about it. He then informed his wife of part of the issue, and disregarded part. She asked him, \"Who informed you of this?\" He said, \"I was informed by the Omniscient, Most Cognizant.\"","নবী একটি বিশেষ কথার ক্ষেত্রে তার কিছু স্ত্রীদের বিশ্বাস করেছিল, এরপর তাদের একজন তা ছড়িয়ে দিল, এবং ঈশ্বর এ বিষয়ে তাকে জানিয়ে দিলেন। সে এরপর তার স্ত্রীকে এ বিষয়ে কিছু জানালো,আর কিছু এড়িয়ে গেলো। তার স্ত্রী তাকে জিজ্ঞেস করল, “এটা তোমাকে কে জানিয়েছে?” সে বলল, “আমি জেনেছি সর্বজ্ঞ, সব জানলেওয়ালার মাধ্যমে।”"],
  "66:4": ["If the two of you repent to Allah, then your hearts have listened. But if you band together against him, then Allah is his ally, and so is Gabriel and the righteous believers. Also, the angels are his helpers.","যদি তোমরা দু'জন ঈশ্বরের কাছে অনুশোচনা করো, তবে তোমাদের হৃদয় শুনেছে। কিন্তু সকলে তোমরা তার বিরুদ্ধে জোট বাধঁলেও, ঈশ্বর তার মিত্র, এবং জিব্রাইল ও সৎকর্মশীল বিশ্বাসীগণও। এছাড়া, ফেরেশতারা তার সাহায্যকারী।"],
  "66:5": ["If he divorces you, his Lord will substitute other wives in your place who are better than you; submitters (Muslims), believers (Mu'mins), obedient, repentant, worshipers, pious, either previously married, or virgins.","যদি সে তোমাদের তালাক দেয়, তার প্রভু তোমাদের স্থানে তাকে তোমাদের থেকে উত্তম স্ত্রী দেবেন; আত্মসমর্পণকারী (মুসলিম), বিশ্বাসী (মুমিন), মান্যকারী, অনুশোচনাকারী, উপাসনাকারী, সৎকর্মশীল, হয়তো পূর্বে বিবাহিত বা কুমারী।"],
  "66:6": ["O you who believe, protect yourselves and your families from the Hellfire whose fuel is people and rocks. Guarding it are stern and powerful angels who never disobey Allah; they do whatever they are commanded to do.","হে তোমরা যারা বিশ্বাস কর, নিজেকে ও তোমাদের পরিবারকে নরকাগ্নি থেকে রক্ষা কর, যার জ্বালানি মানুষ ও পাথর। একে পাহারা দিচ্ছে কঠোর এবং শক্তিশালী ফেরেশতারা যারা কখনো ঈশ্বরকে অমান্য করে না; তাদেরকে যা হুকুম করা হয় তারা তা সম্পাদন করে।"],
  "66:7": ["O you who disbelieved, do not apologize today. You are being requited only for what you did.","হে যারা অবিশ্বাস করেছ, আজ  দু:খ প্রকাশ করো না। তোমরা যা করেছ, শুধু এর জন্যই তোমরা প্রতিফল পাও।"],
  "66:8": ["O you who believe, you shall repent to Allah a firm repentance. Your Lord will then remit your sins and admit you into gardens with flowing streams. On that day, Allah will not disappoint the prophet and those who believed with him. Their light will radiate in front of them and to their right. They will say, \"Our Lord, perfect our light for us, and forgive us; You are Omnipotent.\"","হে যারা বিশ্বাস কর, তোমরা ঈশ্বরের কাছে অনুশোচনা করবে, যা হবে এক দৃঢ় অনুশোচনা। তাহলে, তোমাদের প্রভু তোমাদের পাপ ক্ষমা করবেন আর তোমাদের প্রবেশ করাবেন প্রবাহিত ঝর্ণাসহ বাগানে। ঐ দিন, ঈশ্বর নবীকে ও তার সাথে যারা ছিল তাদেরকে নিরাশ করবেন না। তাদের আলো তাদের সামনে এবং তাদের ডান দিকে বিচ্ছুরিত হবে। তারা বলবে, “আমাদের প্রভু, আমাদের জন্য আমাদের আলোকে পূর্ণাঙ্গ করুন, এবং আমাদের ক্ষমা করুন; আপনি সর্বশক্তিমান।”"],
  "66:9": ["O prophet, struggle against the disbelievers and the hypocrites and be stern with them. Their abode is Gehenna, and a miserable destiny.","হে নবী, অবিশ্বাসী ও ভণ্ডদের বিরুদ্ধে সংগ্রাম কর এবং তাদের প্রতি কঠোর হও। তাদের বাসস্থান জাহান্নাম, এবং এক শোচনীয় ভাগ্য।"],
  "66:10": ["Allah cites as examples of those who disbelieved the wife of Noah and the wife of Lot. They were married to two of our righteous servants, but they betrayed them and, consequently, they could not help them at all against Allah. The two of them were told, \"Enter the Hellfire with those who deserved it.\"","আল্লাহ উদাহরণ হিসেবে তাদের উল্লেখ করেন যারা অবিশ্বাস করেছিল, নূহের স্ত্রী এবং লুতের স্ত্রী। তারা আমাদের দু’জন সৎকর্মশীল বান্দার সাথে বিবাহ বন্ধনে আবদ্ধ ছিল, কিন্তু তারা তাদের সাথে বিশ্বাসঘাতকতা করেছিল এবং পরিণামে তারা তাদেরকে ঈশ্বরের বিরুদ্ধে একেবারেই সাহায্য করতে পারেনি। তাদের দুজনকে বলা হয়েছিল, “তাদের সাথে নরকাগ্নিতে প্রবেশ কর যারা এর যোগ্য।”"],
  "66:11": ["And Allah cites as an example of those who believed the wife of Pharaoh. She said, \"My Lord, build a home for me at You in Paradise, and save me from Pharaoh and his works; save me from the transgressing people.\"","এবং উদাহরণ হিসেবে ঈশ্বর তাদের উদ্ধৃতি দেন যারা বিশ্বাস করেছিল যেমন ফেরাউনের স্ত্রী। সে বলেছিল, “আমার প্রভু,স্বর্গে আপনার কাছে আমার জন্য একটি ঘর নির্মাণ করুন এবং আমাকে রক্ষা করুন ফেরাউন ও তার কাজকর্ম থেকে; আমাকে রক্ষা করুন সীমালঙ্ঘনকারী লোকদের থেকে।”"],
  "66:12": ["Also Mary, the Amramite. She maintained her chastity, then we blew into her from our spirit. She believed in the words of her Lord and His scriptures; she was obedient.","এছাড়া ছিল, ইমরানের কন্যা- মরিয়ম। সে তার সতীত্ব বজায় রেখেছিল, এরপর আমাদের আত্মা থেকে আমরা তার মধ্যে ফুঁকে দিলাম। সে তার প্রভুর বানীতে ও তাঁর ঐশীগ্রন্থে বিশ্বাস করেছিল; সে ছিল অনুগত।"],
  "67:1": ["Most exalted is the One in whose hands is all kingship, and He is Omnipotent.","সবচেয়ে মহিমান্বিত সে সত্ত্বা যাঁর হাতে রয়েছে সকল রাজত্ব, এবং তিনি সর্বশক্তিমান।"],
  "67:2": ["The One who created death and life for the purpose of distinguishing those among you who would do better. He is the Almighty, the Forgiving.","সে সত্ত্বা যিনি সৃষ্টি করেছেন মৃত্যু এবং জীবন, তোমাদের মধ্যে তাদেরকে আলাদা করার উদ্দেশ্যে যারা উত্তম কাজ করবে। তিনি সর্বশক্তিমান, ক্ষমাশীল।"],
  "67:3": ["He created seven universes in layers. You do not see any imperfection in the creation by the Most Gracious. Keep looking; do you see any flaw?","তিনি স্তরে স্তরে সৃষ্টি করেছেন, সাত মহাবিশ্ব। সবচেয়ে করুনাময়ের সৃষ্টিতে তুমি কোন অসম্পূর্ণতা দেখো না। দেখতে থাক; তুমি কি কোন ত্রুটি দেখো?"],
  "67:4": ["Look again and again; your eyes will come back stumped and conquered.","বার বার দেখো; তোমার চোখ হতবুদ্ধ ও পরাজিত হয়ে ফিরবে।"],
  "67:5": ["We adorned the lowest universe with lamps, and guarded its borders with projectiles against the devils; we prepared for them a retribution in Hell.","আমরা সর্বনিম্ন মহাবিশ্বকে প্রদীপ দিয়ে সজ্জিত করেছি এবং এর সীমান্তকে শয়তানদের বিরুদ্ধে ক্ষেপণাস্ত্র দিয়ে সুরক্ষিত করেছি; আমরা তাদের জন্য প্রস্তুত রেখেছি নরকের শাস্তি।"],
  "67:6": ["For those who disbelieved in their Lord, the retribution of Gehenna. What a miserable destiny.","যারা তাদের প্রভুকে অবিশ্বাস করে, তাদের জন্য জাহান্নামের শাস্তি। কি এক শোচনীয় নিয়তি।"],
  "67:7": ["When they get thrown therein, they hear its furor as it fumes.","যখন তারা সেখানে নিক্ষিপ্ত হয়, তারা এর হুংকার শুনতে পায় যখন তা ধোঁয়া ছড়ায়।"],
  "67:8": ["It almost explodes from rage. Whenever a group is thrown therein, its guards would ask them, \"Did you not receive a warner?\"","প্রচণ্ড ক্রোধে এটি প্রায় বিস্ফোরিত হয়। যখনই কোন দলকে সেখানে নিক্ষেপ করা হয়, এর প্রহরীরা তাদের জিজ্ঞাসা করবে, “তোমরা কি কোন সতর্ককারী পাওনি?”"],
  "67:9": ["They would answer, \"Yes indeed; a warner did come to us, but we disbelieved and said, 'Allah did not reveal anything. You are totally astray.'\"","তারা উত্তর দেবে, “হ্যাঁ নিশ্চয়, আমাদের কাছে একজন সতর্ককারী এসেছিল, কিন্তু আমরা অবিশ্বাস করেছিলাম আর বলেছিলাম, “ঈশ্বর কোন কিছু প্রকাশ করেননি। তোমরা পুরোপুরি পথভ্রষ্ট।”"],
  "67:10": ["They also say, \"If we heard or understood, we would not be among the dwellers of Hell!\"","তারা আরও বলে, “যদি আমরা শুনতাম বা বুঝতাম, তবে আমরা নরকের বাসিন্দা হতাম না!”"],
  "67:11": ["Thus, they confessed their sins. Woe to the dwellers of Hell.","এভাবে, তারা তাদের পাপ স্বীকার করেছিল। দু:খ তো নরকের বাসিন্দাদের।"],
  "67:12": ["As for those who reverence their Lord, when alone in their privacy, they have attained forgiveness and a great recompense.","আর যারা তাদের প্রভুকে ভক্তি-শ্রদ্ধা করে, তাদের একাকিত্বে, তারা অর্জন করেছে ক্ষমা এবং এক মহা প্রতিদান।"],
  "67:13": ["Whether you keep your utterances secret, or declare them, He is fully aware of the innermost thoughts.","তোমরা তোমাদের কথা গোপন করো অথবা প্রকাশ করো, তিনি গভীরতম চিন্তাগুলো সম্পর্কে সম্পূর্ণ অবগত।"],
  "67:14": ["Should He not know what He created? He is the Sublime, Most Cognizant.","তিনি কি জানবেন না যে তিনি কি সৃষ্টি করেছেন? তিনি মহীয়ান, সবচেয়ে অবগত।"],
  "67:15": ["He is the One who put the Earth at your service. Roam its corners, and eat from His provisions. To Him is the final summoning.","তিনিই সে সত্ত্বা যিনি পৃথিবীকে তোমাদের সেবায় নিয়োজিত করেছেন। এর আনাচে-কানাচে ঘুরে বেড়াও, এবং তাঁর জীবিকা থেকে খাও। তাঁর কাছেই, চুড়ান্ত তলব।"],
  "67:16": ["Have you guaranteed that the One in heaven will not strike the earth and cause it to tumble?","তোমরা কি নিশ্চয়তা দাও যে আকাশে যিনি আছেন তিনি পৃথিবীকে আঘাত করবেন না এবং একে ভেঙে ফেলবেন না?"],
  "67:17": ["Have you guaranteed that the One in heaven will not send upon you a violent storm? Will you then appreciate the value of My warning?","তোমাদের কি নিশ্চয়তা দেয়া হয়েছে যে, আকাশে যিনি আছেন তিনি তোমাদের উপর প্রবল ঝড় পাঠাবেন না? তখন কি তোমরা আমার সতর্কবানীর মূল্য উপলব্ধি করবে?"],
  "67:18": ["Others before them have disbelieved; how terrible was My requital!","তাদের পূর্বে অন্যরা অবিশ্বাস করেছিল; কি ভয়াবহ ছিল আমার প্রতিশোধ!"],
  "67:19": ["Have they not seen the birds above them lined up in columns and spreading their wings? The Most Gracious is the One who holds them in the air. He is Seer of all things.","তারা কি তাদের উপরস্থ পাখিগুলোকে দেখেনি স্তম্ভাকারে বিন্যস্ত হতে  এবং তাদের পাখা বিস্তৃত করতে? পরম করুণাময় হলেন সেই সত্ত্বা যিনি তাদেরকে বাতাসে ধরে রাখেন।  তিনি সবকিছু দেখেন।"],
  "67:20": ["Where are those soldiers who can help you against the Most Gracious? Indeed, the disbelievers are deceived.","কোথায় ঐসব সৈন্যরা যারা পরম করুণাময়ের বিরুদ্ধে তোমাদের সাহায্য করতে পারে? নিশ্চয়, অবিশ্বাসীরা প্রতারিত।"],
  "67:21": ["Who is there to provide for you, if He withholds His provisions? Indeed, they have plunged deep into transgression and aversion.","কে আছে যে তোমাদের জীবিকা দিবে, যদি তিনি তাঁর জীবিকা আটকে রাখেন? নিশ্চয়, তারা সীমালঙ্ঘন এবং বিমুখতার গভীরে নিমজ্জিত হয়েছে।"],
  "67:22": ["Is one who walks while slumped over on his face better guided, or one who walks straight on the right path?","সে ব্যক্তি যে হাঁটার সময় মুখ থুবড়ে পড়ে সে উত্তম, না সে ব্যক্তি যে সঠিক পথে সোজা হাঁটে?"],
  "67:23": ["Say, \"He is the One who initiated you, and granted you the hearing, the eyes, and the brains. Rarely are you appreciative.\"","বল, “তিনি সেই সত্ত্বা যিনি তোমাদের সূচনা করেছেন, এবং তোমাদের দান করেছেন শ্রবণ শক্তি, চোখ এবং মস্তিস্ক। তোমরা খুব কমই কৃতজ্ঞ।”"],
  "67:24": ["Say, \"He is the One who placed you on earth, and before Him you will be summoned.\"","বল, “তিনিই সে সত্ত্বা যিনি তোমাদেরকে পৃথিবীতে স্থান দিয়েছেন, এবং তাঁর সামনেই তোমাদের তলব করা হবে।”"],
  "67:25": ["They challenge: \"When will that prophecy come to pass, if you are truthful?\"","তারা চ্যালেঞ্জ করেঃ “কখন সেই ভবিষ্যৎবাণী সংঘটিত হবে, যদি তোমরা সত্যবাদী হও?”"],
  "67:26": ["Say, \"Such knowledge is with Allah; I am no more than a manifest warner.\"","বল, “ঈশ্বরের কাছেই রয়েছে এর জ্ঞান; আমি একজন স্পষ্ট সতর্ককারীর চেয়ে বেশি কিছু নই।”"],
  "67:27": ["When they see it happening, the faces of those who disbelieved will turn miserable, and it will be proclaimed: \"This is what you used to mock.\"","যখন তারা একে সংঘটিত হতে দেখে, যারা অবিশ্বাস করেছিল তাদের মুখ দুর্দশাগ্রস্থ হয়ে পড়বে, এবং ঘোষণা করা হবে যেঃ “এটি তা-ই যা নিয়ে তোমরা উপহাস করতে।”"],
  "67:28": ["Say, \"Whether Allah decides to annihilate me and those with me, or to shower us with His mercy, who is there to protect the disbelievers from a painful retribution?\"","বল, “ঈশ্বর আমাকে ও আমার সাথে যারা আছে, তাদেরকে যদি ধ্বংস করার সিদ্ধান্ত নেন অথবা আমাদের প্রতি তাঁর দয়া বর্ষণ করেন, কে আছে যে অবিশ্বাসীদের রক্ষা করবে এক যন্ত্রণাদায়ক শাস্তি থেকে?”"],
  "67:29": ["Say, \"He is the Most Gracious; we believe in Him, and we trust in Him. You will surely find out who is really far astray.\"","বল, “তিনি সবচেয়ে করুণাময়; আমরা তাকে বিশ্বাস করি, এবং আমরা তাঁর প্রতি আস্থা রাখি। তোমরা নিশ্চয় জানতে পারবে কে সত্যিকারর্থে বহুদূর পথভ্রষ্ট।”"],
  "67:30": ["Say, \"What if your water sinks away, who will provide you with pure water?\"","বল, “যদি তোমাদের পানি ভূগর্ভে ডুবে যায়, কে দেবে তোমাদের পরিষ্কার পানি?”"],
  "68:1": ["NuN, the pen, and what they (the people) write.","নুন, কলম, এবং যা তারা (লোকেরা) লিখে।"],
  "68:2": ["You have attained a great blessing from your Lord; you are not crazy.","তোমার প্রভুর পক্ষ থেকে তুমি একটি বিশাল অনুগ্রহ অর্জন করেছ; তুমি পাগল নও।"],
  "68:3": ["You have attained a recompense that is well deserved.","তুমি যথোপযুক্ত প্রতিদান অর্জন করেছ।"],
  "68:4": ["You are blessed with a great moral character.","তুমি মহান নৈতিক চরিত্র দ্বারা অনুগ্রহপ্রাপ্ত।"],
  "68:5": ["You will see, and they will see.","তুমি দেখবে, এবং তারাও দেখবে।"],
  "68:6": ["Which of you are condemned.","তোমাদের কে নিন্দিত।"],
  "68:7": ["Your Lord is fully aware of those who strayed off His path, and He is fully aware of those who are guided.","তোমার প্রভু তাদের বিষয়ে সম্পূর্ণ অবগত যারা তাঁর পথ থেকে সরে গেছে এবং তিনি তাদের বিষয়ে সম্পূর্ণ অবগত যারা সুপথ প্রাপ্ত।"],
  "68:8": ["Do not obey the rejectors.","প্রত্যাখ্যানকারীদের মান্য করো না।"],
  "68:9": ["They wish that you compromise, so they too can compromise.","তারা চায় যে, তুমি আপস করো, যাতে তারাও আপস করতে পারে।"],
  "68:10": ["Do not obey every lowly swearer.","মান্য করো না কোন হীন শপথকারীকে ।"],
  "68:11": ["A slanderer, a backbiter.","কোন পরনিন্দাকারীকে, কোন কুৎসা রটনাকারীকে।"],
  "68:12": ["Forbidder of charity, a transgressor, a sinner.","দান করতে নিষেধকারীকে, কোন সীমালঙ্ঘনকারীকে, কোন পাপীকে।"],
  "68:13": ["Unappreciative, and greedy.","অকৃতজ্ঞ, এবং লোভীকে।"],
  "68:14": ["Even though he possessed enough money and children.","এমনকি যদিও তার আছে যথেষ্ট অর্থ ও সন্তানাদি।"],
  "68:15": ["When our revelations are recited to him, he says, \"Tales from the past!\"","যখন আমাদের প্রকাশনাবলি তার কাছে পাঠ করা হয়, সে বলে, “অতীতের কল্প-কাহিনী!”"],
  "68:16": ["We will mark his face.","আমরা তার মুখমণ্ডল চিহ্নিত করে দিবো।"],
  "68:17": ["We have tested them like we tested the owners of the garden who swore that they will harvest it in the morning.","আমরা তাদের পরীক্ষা করেছি যেমন আমরা পরীক্ষা করেছিলাম বাগানের মালিকদের, যারা কসম খেয়েছিল যে সকালে তারা ফসল কাটবে।"],
  "68:18": ["They were so absolutely sure.","তারা এতোটাই শতভাগ নিশ্চিত ছিল।"],
  "68:19": ["A passing (storm) from your Lord passed by it while they were asleep.","যখন তারা ঘুমিয়ে ছিল, তখন তোমার প্রভুর কাছ থেকে একটি বয়ে যাওয়া (ঝড়) এর উপর দিয়ে গেল।"],
  "68:20": ["By morning, it was barren.","সকাল নাগাদ, এটি শস্যহীন হয়ে পড়লো।"],
  "68:21": ["They called on each other in the morning.","তারা সকালে একে অন্যের কাছে গেল।"],
  "68:22": ["\"Let us harvest the crop.\"","“চল আমরা ফসল কাটতে যাই।"],
  "68:23": ["On their way, they confided to each other.","যাবার পথে, তারা একে অন্যের উপর আস্থা রাখলো।"],
  "68:24": ["That from then on, none of them would be poor.","এ ব্যাপারে যে, এরপর থেকে, তাদের কেউ গরীব থাকবে না।"],
  "68:25": ["They were so absolutely sure of their harvest.","তারা তাদের ফসল কাটার বিষয়ে এতোটাই শতভাগ নিশ্চিত ছিল।"],
  "68:26": ["But when they saw it, they said, \"We were so wrong!","কিন্তু যখন তারা তা দেখল, তারা বলল, “আমরা কতটা ভুল ছিলাম!"],
  "68:27": ["\"Now, we have nothing!\"","“এখন, আমাদের কিছুই নেই!”"],
  "68:28": ["The righteous among them said, \"If only you had glorified (Allah)!\"","তাদের মধ্যে সৎকর্মশীলরা বলল, “যদি কেবল আমরা (ঈশ্বরের) মহিমা ঘোষণা করতাম!”"],
  "68:29": ["They said, \"Glory be to our Lord. We have transgressed.\"","তারা বলল, “আমাদের প্রভুর মহিমা। আমরা সীমালঙ্ঘন করেছি।”"],
  "68:30": ["They started to blame each other.","তারা একে অন্যের উপর দোষারোপ শুরু করলো।"],
  "68:31": ["They said, \"Woe to us. We sinned.","তারা বলল, “দুঃখ আমাদের। আমরা পাপ করেছি।"],
  "68:32": ["\"May our Lord grant us a better one. We repent to our Lord.\"","“আমাদের প্রভু যেন আমাদেরকে আরেকটি উত্তম বাগান দান করেন। আমরা আমাদের প্রভুর কাছে অনুশোচনা করি।”"],
  "68:33": ["Such was the requital. But the retribution of the Hereafter is far worse, if they only knew.","এমনই ছিল প্রতিদান। কিন্তু পরকালের শাস্তি অধিকতর মন্দ, যদি কেবল তারা জানত।"],
  "68:34": ["The righteous have deserved, at their Lord, gardens of bliss.","সৎকর্মশীলগণ অর্জন করেছে, তাদের প্রভুর কাছে, পরম সুখের বাগান।"],
  "68:35": ["Shall we treat the submitters like the criminals?","আমরা কি আত্মসমর্পণকারীদের গণ্য করবো অপরাধীদের মত?"],
  "68:36": ["What is wrong with your logic?","তোমাদের যুক্তিতে সমস্যা কোথায়?"],
  "68:37": ["Do you have another book to uphold?","তোমাদের কি মান্য করার অন্যকোন গ্রন্থ আছে?"],
  "68:38": ["In it, do you find anything you want?","এর মধ্যে, তোমরা কি যা চাও তা-ই পাও?"],
  "68:39": ["Or, have you received solemn assurances from us that grant you whatever you wish on the Day of Resurrection?","অথবা, তোমরা কি আমাদের কাছ থেকে দৃড় নিশ্চয়তা পেয়েছ যে পুনরুত্থান দিনে তোমরা যা চাও তা-ই পাবে?"],
  "68:40": ["Ask them, \"Who guarantees this for you?\"","তাদের জিজ্ঞেস করো, “কে তোমাদেরকে এমন অঙ্গীকার দেয়?”"],
  "68:41": ["Do they have idols? Let their idols help them, if they are truthful.","তাদের কি অন্যকোন উপাস্য আছে? তাদের উপাস্যরা তাদের সাহায্য করুক, যদি তারা সত্যবাদী হয়।"],
  "68:42": ["The day will come when they will be exposed, and they will be required to fall prostrate, but they will be unable to.","সেদিন আসবে যখন তারা প্রকাশিত হয়ে পড়বে, এবং তাদেরকে সেজদা করতে বলা হবে, কিন্তু তারা সক্ষম হবে না।"],
  "68:43": ["With their eyes subdued, humiliation will cover them. They were invited to fall prostrate when they were whole and able.","তাদের দৃষ্টি নতজানু হবে, অপমান তাদেরকে ঘিরে ফেলবে। তাদেরকে সেজদা করতে আমন্ত্রন জানানো হতো যখন তারা অক্ষত ও সক্ষম ছিল।"],
  "68:44": ["Therefore, let Me deal with those who reject this Hadith; we will lead them on whence they never perceive.","অতএব, আমাকে তাদের বিষয়ে ব্যবস্থা নিতে দাও যারা এই হাদিস প্রত্যাখ্যান করে, আমরা তাদেরকে সেখানে পরিচালিত করবো যেখানে তারা কখনই অনুধাবন করে না।"],
  "68:45": ["I will give them enough rope; My scheming is formidable.","আমি তাদেরকে যথেষ্ট ছাড় দেব; আমার পরিকল্পনা অভেদ্য।"],
  "68:46": ["Are you asking them for money, so they are burdened by the fine?","তুমি কি তাদের কাছে অর্থ চাইছো, তাই তারা জরিমানার কারণে ভারগ্রস্থ হয়ে পড়েছে?"],
  "68:47": ["Do they know the future? Do they have it recorded?","তারা কি ভবিষ্যৎ জানে? তাদের কাছে কি তা লিপিবদ্ধ আছে?"],
  "68:48": ["You shall steadfastly persevere in carrying out the commands of your Lord. Do not be like (Jonah) who called from inside the fish.","তুমি তোমার প্রভুর হুকুম পালনে দৃঢ়তার সাথে অবিচল থাকবে। (ইউনুস, ) যে মাছের ভিতর থেকে ডেকেছিল তার মতো হইও না।"],
  "68:49": ["If it were not for his Lord's grace, he would have been ejected into the desert as a sinner.","যদি তোমার প্রভুর পক্ষ থেকে করুণা না হতো, তবে সে পাপী হিসেবে মরুভূমিতে নিক্ষিপ্ত হতো।"],
  "68:50": ["But his Lord blessed him, and made him righteous.","কিন্তু তার প্রভু তাকে অনুগ্রহ করলেন, এবং তাকে সৎকর্মশীল বানালেন।"],
  "68:51": ["Those who disbelieved show their ridicule in their eyes when they hear the message and say, \"He is crazy!\"","যারা অবিশ্বাস করে, তারা যখন বার্তা শোনে তারা তাদের চাহনি দিয়ে উপহাস করে এবং বলে, “সে পাগল!”"],
  "68:52": ["It is in fact a message to the world.","এটি প্রকৃতপক্ষে বিশ্ববাসীর কাছে একটি বার্তা।"],
  "69:1": ["The incontestable (event).","সে তর্কাতীত (ঘটনা)।"],
  "69:2": ["What an incontestable (event)!","কি এক তর্কাতীত (ঘটনা)!"],
  "69:3": ["It is truly incontestable.","এটি সত্যিই তর্কাতীত।"],
  "69:4": ["Thamûd and 'Ãd disbelieved in the Shocker.","সামুদ ও আ'দ অবিশ্বাস করেছিল আঘাতকারীকে।"],
  "69:5": ["As for Thamûd, they were annihilated by the devastating (quake).","সামুদের ক্ষেত্রে, তারা বিলুপ্ত হয়েছিল বিধ্বংসী (কম্পন) দ্বারা।"],
  "69:6": ["As for 'Ãd, they were annihilated by a persistent, violent storm.","আ'দের ক্ষেত্রে, তারা বিলুপ্ত হয়েছিল এক অনবরত, তীব্র ঝড় দ্বারা।"],
  "69:7": ["He unleashed it upon them for seven nights and eight days, violently. You could see the people tossed around like decayed palm trunks.","একে তিনি তাদের উপর ছেড়ে দিয়েছিলেন সাত রাত ও আট দিনের জন্য, হিংস্রভাবে। তুমি লোকদের দেখতে পেতে চারদিকে ছুড়ে পড়ছিল, ক্ষয়প্রাপ্ত খেজুর গাছের কাণ্ডের মতো।"],
  "69:8": ["Can you find any trace of them?","তুমি কি তাদের কারো চিহ্ন পাও?"],
  "69:9": ["Pharaoh, others before him, and the sinners (of Sodom) were wicked.","ফেরাউন, তার পূর্বে অন্যরা এবং (সডমের) পাপিরা ছিল মন্দ।"],
  "69:10": ["They disobeyed the messenger of their Lord. Consequently, He requited them a devastating requital.","তারা তাদের প্রভুর বার্তাবাহককে অমান্য করেছিল। পরিণামে, তিনি তাদের প্রতিদান দিয়েছিলেন, বিধ্বংসী এক প্রতিদান।"],
  "69:11": ["The flood was devastating, so we carried you on the floating (ark).","বন্যাটি ছিল বিধ্বংসী, তাই আমরা তোমাদের ভাসমান (নৌযানে) আরোহণ করিয়েছিলাম।"],
  "69:12": ["We rendered it a lesson for you, that any listening ear may understand.","আমরা তোমাদের জন্য একে করেছি একটি শিক্ষা, যাতে কোন শ্রবনরত কান বুঝতে পারে।"],
  "69:13": ["When the horn is blown once.","একবার যখন শিঙ্গায় ফুঁ দেয়া হয়।"],
  "69:14": ["The earth and the mountains will be carried off and crushed; utterly crushed.","পৃথিবী ও পর্বতমালাকে বয়ে আনা হবে এবং চূর্ণ-বিচূর্ণ করা হবে; একেবারেই চূর্ণ-বিচূর্ণ।"],
  "69:15": ["That is the day when the inevitable event will come to pass.","ঐটা সেই দিন যখন সে অনিবার্য ঘটনা সংঘটিত হবে।"],
  "69:16": ["The heaven will crack, and fall apart.","আকাশ ফেটে পড়বে, এবং ছিন্ন হবে।"],
  "69:17": ["The angels will be all around, and Your Lord's dominion will then encompass eight (universes).","ফেরেশতারা চারদিকে থাকবে, এবং তোমার প্রভুর রাজ্য তখন পরিবেষ্টন করবে আট (মহাবিশ্বে)।"],
  "69:18": ["On that day, you will be exposed, nothing of you can be hidden.","ঐদিন, তোমাদের আসল চেহারা উন্মোচিত হবে, তোমাদের কোনকিছুই গোপন করা যাবে না।"],
  "69:19": ["As for the one who receives his record with his right hand, he will say, \"Come read my record.","আর যে ব্যক্তি তার রেকর্ড তার ডান হাতে পায়, সে বলবে, “এসো আমার নথিটি পড়।"],
  "69:20": ["\"I did believe that I was going to be held accountable.\"","“আমার বিশ্বাস ছিল যে আমাকে জবাবদিহি করতে হবে। ”"],
  "69:21": ["He has deserved a happy life.","সে সুখী জীবন অর্জন করেছে।"],
  "69:22": ["In an exalted Paradise.","একটি মহিমান্বিত স্বর্গে।"],
  "69:23": ["Its fruits are within reach.","এর ফলগুলো হাতের নাগালের মধ্যে।"],
  "69:24": ["Eat and drink happily in return for your works in days past.","অতীতের দিনগুলোয় তোমাদের কাজের বিনিময়ে সানন্দে খাও এবং পান করো।"],
  "69:25": ["As for him who is given his record in his left hand, he will say, \"Oh, I wish I never received my record.","আর যার নথি তার বাম হাতে দেয়া হবে, সে বলবে, “হায়, আমি যদি কখনই আমার নথি না পেতাম।"],
  "69:26": ["\"I wish I never knew my account.","“আমি যদি কখনই আমার হিসাব না জানতাম।"],
  "69:27": ["\"I wish my death was eternal.","“আমার মৃত্যুই যদি চিরস্থায়ী হত।"],
  "69:28": ["\"My money cannot help me.","“আমার টাকাপয়সা আমাকে সাহায্য করতে পারে না।"],
  "69:29": ["\"All my power is gone.\"","“আমার সকল ক্ষমতা চলে গেছে।”"],
  "69:30": ["Take him and shackle him.","তাকে নিয়ে চলো এবং তাকে শৃঙ্খলিত করো।"],
  "69:31": ["Burn him in Hell.","তাকে নরকে পুঁড়াও।"],
  "69:32": ["In a chain that is seventy arms long, tie him up.","সত্তুর হাত লম্বা শিকলে, তাকে বাঁধ।"],
  "69:33": ["For he did not believe in Allah, Most Great.","কারন সে সবচেয়ে মহান আল্লাহকে বিশ্বাস করতো না ।"],
  "69:34": ["Nor did he advocate the feeding of the poor.","না সে গরিবদের খাওয়ানোর পরামর্শ দিত ।"],
  "69:35": ["Consequently, he has no friend here.","পরিণামে, এখানে তার কোন বন্ধু নেই।"],
  "69:36": ["Nor any food, except the bitter variety.","না কোন খাদ্য, তেতো প্রকারের খাদ্য ব্যতীত।"],
  "69:37": ["Food for the sinners.","পাপীদের খাবার।"],
  "69:38": ["I swear by what you see.","আমি তার শপথ করি যা তোমরা দেখো।"],
  "69:39": ["And what you do not see.","এবং যা তোমরা দেখো না।"],
  "69:40": ["This is the utterance of an honorable messenger.","এটি একজন সন্মানিত বার্তাবাহকের কথা।"],
  "69:41": ["Not the utterance of a poet; rarely do you believe.","না কোন কবির কথা; তোমরা খুব কম ক্ষেত্রেই বিশ্বাস করো।"],
  "69:42": ["Nor the utterance of a soothsayer; rarely do you take heed.","না কোন ভবিষ্যৎ-বক্তার কথা; তোমরা খুব কম ক্ষেত্রেই উপদেশ গ্রহণ করো।"],
  "69:43": ["A revelation from the Lord of the universe.","মহাবিশ্বের প্রভুর পক্ষ থেকে একটি প্রকাশনা।"],
  "69:44": ["Had he uttered any other teachings.","যদি সে অন্য কোন শিক্ষা উচ্চারণ করতো।"],
  "69:45": ["We would have punished him.","আমরা তাকে শাস্তি দিতাম।"],
  "69:46": ["We would have stopped the revelations to him.","আমরা তার কাছে প্রত্যাদেশ পাঠানো বন্ধ করে দিতাম।"],
  "69:47": ["None of you could have helped him.","তোমাদের কেউ তাকে সাহায্য করতে পারতে না।"],
  "69:48": ["This is a reminder for the righteous.","এটি সৎকর্মশীলদের জন্য একটি সতর্কবানী।"],
  "69:49": ["We know; some of you are rejectors.","আমরা জানি; তোমাদের কেউ কেউ প্রত্যাখ্যানকারী।"],
  "69:50": ["It is but sorrow for the disbelievers.","এটি তো কেবল অবিশ্বাসীদের জন্য দুঃখ।"],
  "69:51": ["It is the absolute truth.","এটি পরম সত্য।"],
  "69:52": ["Therefore, you shall glorify the name of your Lord, Most Great.","অতএব, তুমি তোমার প্রভুর নামের মহিমা ঘোষণা করবে, যিনি সবচেয়ে মহান।"],
  "70:1": ["A questioner may question the inevitable retribution.","একজন প্রশ্নকারী অনিবার্য শাস্তির বিষয়ে প্রশ্ন করতে পারে।"],
  "70:2": ["For the disbelievers, none can stop it.","অবিশ্বাসীদের জন্য, কেউ তা থামাতে পারবে না।"],
  "70:3": ["From Allah; Possessor of the highest Height.","ঈশ্বর থেকে; উচ্চতম উচ্চতার অধিকারী।"],
  "70:4": ["The angels and the Spirit, with their reports, climb to Him in a day that equals fifty thousand years.","ফেরেশতারা, তাদের প্রতিবেদন নিয়ে, তাঁর দিকে এক দিনে আরোহণ করে, যা পঞ্চাশ হাজার বছরের সমান।"],
  "70:5": ["Therefore, you shall resort to a gracious patience.","অতএব, তুমি সদয় ধৈর্য ধারন করো।"],
  "70:6": ["For they see it far away.","কারন তারা তা দেখে অনেক দূরে।"],
  "70:7": ["While we see it very close.","আর আমরা একে দেখি খুব নিকটে।"],
  "70:8": ["The day will come when the sky will be like molten rocks.","সেদিন আসবে যখন আকাশ গলিত পাথরের মতো হবে।"],
  "70:9": ["The mountains will be like fluffy wool.","পর্বতমালা হবে তুলতুলে পশমের মতো।"],
  "70:10": ["No friend will care about his close friend.","কোন বন্ধু তার অন্তরঙ্গ বন্ধুর খবর নিবে না।"],
  "70:11": ["When they see them, the guilty will wish he could give his own children as ransom, to spare him the retribution of that day.","যখন এরা তাদের দেখবে, অপরাধীরা ইচ্ছা করবে যদি সে তার নিজের সন্তান-সন্ততিকে ক্ষতিপূরণ হিসেবে দিতে পারতো, ঐ দিনের শাস্তি থেকে তাকে রক্ষা করতে।"],
  "70:12": ["Also his spouse, and his brother.","তার স্ত্রী, এবং তার ভাইকেও।"],
  "70:13": ["Even his whole tribe that raised him.","এমনকি তার সমগ্র জাতিকে যারা তার লালন পালন করেছিল।"],
  "70:14": ["Even all the people on earth, if it would save him.","এমনকি পৃথিবীর সকল লোককে, যদি তা তাকে রক্ষা করতে পারে।"],
  "70:15": ["No; it is aflame.","না; এটি জ্বলছে।"],
  "70:16": ["Eager to burn.","জ্বালাতে উদগ্রীব।"],
  "70:17": ["It calls on those who turned away.","এটি আহবান করে তাদেরকে যারা মুখ ফিরিয়ে নিয়েছিল।"],
  "70:18": ["Those who hoarded and counted.","তাদেরকে যারা জমা করতো আর গুনতো।"],
  "70:19": ["Indeed, the human being is anxious.","নিশ্চয়, মানুষ উদ্বিগ্ন।"],
  "70:20": ["If touched by adversity, despondent.","দুর্দশা স্পর্শ করলে, হতাশ।"],
  "70:21": ["If blessed by wealth, stingy.","সম্পদ দ্বারা সৌভাগ্যবান হলে, কৃপণ।"],
  "70:22": ["Except for the worshipers.","উপাসনাকারীরা ব্যতিত।"],
  "70:23": ["Who always observe their contact prayers (Salat).","যারা সবসময় তাদের সংযোগ প্রার্থনা (সালাত) পালন করে।"],
  "70:24": ["Part of their money is set aside.","তাদের অর্থের একটি অংশ আলাদা করা থাকে।"],
  "70:25": ["For the poor and the needy.","গরীব ও অভাবগ্রস্থদের জন্য।"],
  "70:26": ["They believe in the Day of Judgment.","তারা বিশ্বাস করে বিচার দিনকে।"],
  "70:27": ["They reverence their Lord's requital.","তারা তাদের প্রভুর প্রতিদানকে ভক্তি-শ্রদ্ধা করে।"],
  "70:28": ["Their Lord's requital is not taken for granted.","তাদের প্রভুর প্রতিশোধকে হাল্কা ভাবে নেয় না।"],
  "70:29": ["They keep their chastity.","তারা তাদের সতীত্ব বজায় রাখে।"],
  "70:30": ["(They have relations) only with their spouses, or what is legally theirs—","(তাদের সম্পর্ক আছে) কেবল মাত্র তাদের স্বামী/স্ত্রীর সাথে, অথবা যা আইনত তাদের-"],
  "70:31": ["anyone who transgresses these limits is a sinner—","যেকেউ এই সীমা অতিক্রম করে সে একজন পাপী।"],
  "70:32": ["And the believers keep their word; they are trustworthy.","এবং বিশ্বাসীরা তাদের কথা রাখে; তারা বিশ্বস্ত।"],
  "70:33": ["Their testimony is truthful.","তাদের সাক্ষ্য সত্যনিষ্ঠ।"],
  "70:34": ["They consistently observe their contact prayers (Salat), on time.","তারা ধারাবাহিকভাবে তাদের সংযোগ প্রার্থনা (সালাত) পালন করে, যথাসময়ে।"],
  "70:35": ["They have deserved a position of honor, in Paradise.","স্বর্গে, তারা একটি সন্মানিত অবস্থানের যোগ্য হয়েছে।"],
  "70:36": ["What is keeping those who disbelieved from joining you?","যারা অবিশ্বাস করে, তাদেরকে কি বাধাঁ দিচ্ছে, তোমার সাথে যোগ দেয়ার ক্ষেত্রে?"],
  "70:37": ["To the right, and to the left, they flee.","ডানে ও বামে, তারা পালায়।"],
  "70:38": ["How can any of them expect to enter the blissful Paradise?","কেমন করে তাদের কেউ পরম সুখের স্বর্গে প্রবেশের আশা করতে পারে?"],
  "70:39": ["Never; we created them, and they know from what.","কখনো না; আমরা তাদের সৃষ্টি করেছি এবং তারা জানে কি থেকে।"],
  "70:40": ["I solemnly swear by the Lord of the easts and the wests; we are able—","আমি শপথ করি পূর্ব এবং পশ্চিমের প্রভুর; আমরা সক্ষম-"],
  "70:41": ["to substitute better people in their place; we can never be defeated.","তোমাদের স্থানে উত্তম লোকদের আনতে; আমরা কখনো পরাজিত হতে পারি না।"],
  "70:42": ["Therefore, let them blunder and play, until they meet the day that is awaiting them.","অতএব, তাদেরকে বিভ্রমে এবং ক্রিয়াকর্মে পড়ে থাকতে দাও, যতক্ষণ না তারা সে দিনের সাক্ষাৎ পায়, যা তাদের জন্য অপেক্ষা করছে।"],
  "70:43": ["That is the day they come out of the graves in a hurry, as if herded to the (sacrificial) altars.","ঐদিন তারা তাড়াহুড়া করে কবর থেকে বের হয়ে আসবে, যেন একত্রে চালিত হচ্ছে (বলিদানের) বেদির দিকে।"],
  "70:44": ["With their eyes subdued, shame will cover them. That is the day that is awaiting them.","তাদের দৃষ্টি অবনমিত থাকবে, লজ্জা তাদের ঢেকে ফেলবে। এটাই সে দিন যা তাদের জন্য অপেক্ষা করছে।"],
  "71:1": ["We sent Noah to his people: \"You shall warn your people before a painful retribution afflicts them.\"","আমরা নূহকে তার লোকদের কাছে পাঠিয়েছিলামঃ “তুমি তোমার লোকদের সতর্ক করো একটি যন্ত্রণাদায়ক শাস্তি তাদের কাছে আসার আগে।”"],
  "71:2": ["He said, \"O my people, I am a manifest warner to you.","সে বলল, “হে আমার লোকেরা, আমি তোমাদের কাছে একজন স্পষ্ট সতর্ককারী।"],
  "71:3": ["\"To alert you that you shall worship Allah, reverence Him, and obey me.","“তোমাদের সতর্ক করতে যে তোমরা ঈশ্বরের উপাসনা করো, তাঁকে সম্মান করো, এবং আমাকে মান্য করো।"],
  "71:4": ["\"He will then forgive you your sins and respite you for a predetermined period. Most assuredly, Allah's appointment can never be delayed, once it is due, if you only knew.\"","“তিনি তবে তোমাদের পাপ ক্ষমা করবেন এবং একটি পূর্বনির্ধারিত সময় পর্যন্ত তোমাদের অবকাশ দেবেন। অবশ্যই, ঈশ্বরের সাথে সাক্ষাতের নির্ধারিত সময় কখনো বিলম্বিত হতে পারে না, একবার এর সময় হলে, যদি শুধু তোমরা জানতে।”"],
  "71:5": ["He said, \"My Lord, I have invited my people night and day.","সে বলল, “আমার প্রভু, আমি আমার লোকদের দাওয়াত দিয়েছি রাতে ও দিনে।"],
  "71:6": ["\"But my invitation only increased their aversion.","“কিন্তু আমার দাওয়াত কেবল তাদের বিমুখতা বাড়িয়ে দিয়েছিল।"],
  "71:7": ["\"Whenever I invited them to be forgiven by You, they placed their fingers in their ears, covered themselves with their clothes, insisted, and turned arrogant.","“যখনি আমি তাদের দাওয়াত দিয়েছিলাম যে আপনি তাদের ক্ষমা করবেন, তারা তাদের কানে আঙ্গুল দিয়েছে, নিজেদের ঢেকে ফেলেছে তাদের কাপড় দিয়ে, জিদ করেছে, এবং উদ্ধত হয়েছে।"],
  "71:8": ["\"Then I invited them publicly.","“এরপর আমি তদের দাওয়াত দিয়েছিলাম জনসমক্ষে।"],
  "71:9": ["\"Then I proclaimed to them loudly, and I spoke to them privately.","“এরপর আমি তাদের কাছে ঘোষণা করেছিলাম উচ্চস্বরে, এবং আমি তাদের সাথে কথা বলেছিলাম ব্যক্তিগতভাবে।"],
  "71:10": ["\"I said, 'Implore your Lord for forgiveness; He is Forgiving.","“আমি বলেছিলাম, “তোমাদের প্রভুর কাছে ক্ষমা প্রার্থনা করো; তিনি ক্ষমাশীল।"],
  "71:11": ["\"'He will then shower you generously with rain.","“তিনি তবে তোমাদের জন্য উদারভাবে বৃষ্টি বর্ষণ করবেন।"],
  "71:12": ["\" 'And provide you with money and children, and orchards, and streams.' \"","“আর তোমাদের দেবেন অর্থ ও সন্তানাদি, এবং ফলের বাগান ও ঝর্ণা।"],
  "71:13": ["Why should you not strive to reverence Allah?","কেন তোমরা ঈশ্বরের সম্মান করতে সংগ্রাম করো না?"],
  "71:14": ["He is the One who created you in stages.","তিনিই সে সত্ত্বা যিনি তোমাদের সৃষ্টি করেছেন পর্যায়ক্রমে।"],
  "71:15": ["Do you not realize that Allah created seven universes in layers?","তোমরা কি অনুধাবন করো না যে ঈশ্বর সাত মহাবিশ্ব সৃষ্টি করেছেন স্তরে স্তরে।"],
  "71:16": ["He designed the moon therein to be a light, and placed the sun to be a lamp.","সেখানে তিনি চাঁদের নকশা করেছেন একটি আলো হিসেবে, আর সূর্যকে স্থাপন করেছেন একটি প্রদীপ হিসেবে।"],
  "71:17": ["And Allah germinated you from the earth like plants.","এবং ঈশ্বর পৃথিবী থেকে তোমাদের অঙ্কুরিত করেছেন উদ্ভিদের মতো।"],
  "71:18": ["Then He returns you into it, and He will surely bring you out.","এরপর তিনি এর মধ্যে তোমাদের ফিরে যেতে দেন, এবং তিনি অবশ্যই তোমাদের বের করে আনবেন।"],
  "71:19": ["Allah made the earth habitable for you.","পৃথিবীকে ঈশ্বর তোমাদের জন্য বাসযোগ্য করেছেন।"],
  "71:20": ["That you may build roads therein.","যাতে তোমরা সেখানে রাস্তা নির্মাণ করতে পারো।"],
  "71:21": ["Noah said, \"My Lord, they disobeyed me, and followed those who were even more corrupted when blessed with money and children.","নুহ বলেছিল, “আমার প্রভু, তারা আমাকে অমান্য করেছিল আর তাদের অনুসরণ করেছিল যারা আরও বেশি কলুষিত ছিল যখন অর্থ ও সন্তানাদি পেয়ে সৌভাগ্যশালী ছিল।"],
  "71:22": ["\"They schemed terrible schemes.","‘তারা চক্রান্ত করেছিল ভয়াবহ চক্রান্ত।"],
  "71:23": ["\"They said, 'Do not abandon your gods. Do not abandon Wadd, Suwaa', Yaghouth, Ya'ooq, and Nasr.'","“তারা বলেছিল, “তোমাদের উপাস্যদের ত্যাগ করো না। ত্যাগ করো না ওয়াদ্দ, সুয়আ, ইয়াঘউথ, ইয়াউক ও নাসরকে।\""],
  "71:24": ["\"They misled many. Therefore, let the wicked plunge deeper into loss.\"","“তারা অনেককে পথভ্রষ্ট করেছে। অতএব, মন্দদের ক্ষতির গভীরে নিমজ্জিত হতে দাও।”"],
  "71:25": ["Because of their sins they were drowned and assigned to the hellfire. They found no helpers to protect them from Allah.","পাপের কারনে তাদের ডুবিয়ে দেয়া হয়েছিল এবং নরকাগ্নির জন্য নির্ধারিত হলো। ঈশ্বর থেকে রক্ষা পেতে তারা কোন সাহায্যকারী পাইনি।"],
  "71:26": ["Noah also said, \"My Lord, do not leave a single disbeliever on earth.","নুহ আরও বলেছিল, “আমার প্রভু, পৃথিবীতে একজন অবিশ্বাসীকেও ছেড়ে দেবেন না।"],
  "71:27": ["\"For if you let them, they will only mislead your servants and give birth to nothing but wicked disbelievers.","“কারন যদি আপনি তাদের ছেড়ে দেন, তারা কেবল আপনার বান্দাদের পথভ্রষ্ট করবে এবং মন্দ অবিশ্বাসী ছাড়া কোনকিছু জন্ম দেবে না।"],
  "71:28": ["\"My Lord, forgive me and my parents, and anyone who enters my home as a believer, and all the believing men and women. But do not give the disbelievers anything but annihilation.\"","“আমার প্রভু, আমাকে ক্ষমা করুন ও আমার পিতামাতাকে এবং যেকেউ আমার গৃহে বিশ্বাসী হিসেবে প্রবেশ করে তাদেরকে, এবং সকল বিশ্বাসী পুরুষ ও নারীকে। কিন্তু অবিশ্বাসীদের ধ্বংস ছাড়া কিছু দেবেন না।”"],
  "72:1": ["Say, \"I was inspired that a group of jinns listened, then said, 'We have heard a wonderful Quran.","বল, “আমাকে প্রত্যাদিষ্ট হয়েছি যে জিনদের একটি দল শুনেছিল, তারপর বলল, “আমরা এক বিস্ময়কর কুরআন শুনেছি।"],
  "72:2": ["\"'It guides to righteousness, and we have believed in it; we will never set up any idols besides our Lord.","“এটি সৎকর্মশীলতার দিকে পথনির্দেশ করে, এবং একে আমরা বিশ্বাস করেছি; আমরা কখনো আমাদের প্রভুর পাশে কোন উপাস্য স্থাপন করবো না।"],
  "72:3": ["\"'The Most High is our only Lord. He never had a mate, nor a son.","“আমাদের একমাত্র প্রভু হলেন সর্বোচ্চ। কখনো তাঁর কোন সঙ্গি ছিল না, না ছিল পুত্র।"],
  "72:4": ["\"'It is the foolish among us who used to utter such nonsense about Allah.","আমাদের মধ্যে বোকারাই ঈশ্বর সম্পর্কে এমন নির্বোধের মতো কথা বলতো।"],
  "72:5": ["\"'We thought that neither the humans, nor the jinns, could possibly utter lies about Allah.","“আমরা মনে করতাম যে ঈশ্বর সম্পর্কে না মানুষ, না জীনরা, মিথ্যা বলতে পারে।"],
  "72:6": ["\"'Human beings used to seek power through jinn beings, but they only afflicted them with a lot of adversity.","“মানুষরা জীনদের মাধ্যমে শক্তি খুজঁতো, কিন্তু তারা কেবল নিজেদের অনেক অনেক দুর্দশায় জর্জরিত করেছে।"],
  "72:7": ["\"'They thought, just like you thought, that Allah would not send another (messenger).","“তারা মনে করতো, ঠিক যেমন তোমরা মনে করতে, যে ঈশ্বর অন্যকোন (বার্তাবাহক) পাঠাবেন না।"],
  "72:8": ["\"'We touched the heaven and found it filled with formidable guards and projectiles.","“আমরা আকাশ স্পর্শ করেছিলাম, আর একে পেলাম শক্তিশালী প্রহরী ও ক্ষেপণাস্ত্র দ্বারা পূর্ণ।"],
  "72:9": ["\"'We used to sit there in order to spy. Anyone who listens is pursued by a powerful projectile.","“আমরা গুপ্তচরবৃত্তির জন্য সেখানে বসে থাকতাম। যেকেউ শুনে, তাকে এক শক্তিশালী ক্ষেপণাস্ত্র ধাওয়া করে।"],
  "72:10": ["\"'We have no idea if something bad is intended for the inhabitants of Earth, or if their Lord wills to redeem them.","“আমাদের কোন ধারণা নেই পৃথিবীর বাসিন্দাদের জন্য খারাপ কিছু করার ইচ্ছা আছে, না তাদের প্রভু তাদের পুনরুদ্ধার করতে চান।"],
  "72:11": ["\"'Some of us are righteous, and some are less than righteous; we follow various paths.","“আমাদের কেউ কেউ সৎ-কর্মপরায়ণ এবং কেউ কেউ কম সৎ-কর্মপরায়ণ; আমরা বিভিন্ন পথ অনুসরণ করি।"],
  "72:12": ["\"'We knew full well that we can never run away from Allah on earth; we can never run away and escape.","“আমরা খুব ভালভাবে জানতাম যে পৃথিবীতে আমরা ঈশ্বর থেকে কখনো পালাতে পারবো না; আমরা কখনো পালিয়ে যেতে এবং মুক্তি পেতে পারবো না।"],
  "72:13": ["\"'When we heard the guidance, we believed therein. Anyone who believes in his Lord will never fear any injustice, nor any affliction.","যখন আমরা পথনির্দেশনা শুনেছিলাম, আমরা তাতে বিশ্বাস স্থাপন করেছি। যেকেউ তার প্রভুকে বিশ্বাস করে সে কখনো কোন অবিচার, না কোন কষ্টের আশংকা করবে।"],
  "72:14": ["\"'Among us are the submitters, and among us are the compromisers.'\" As for those who submitted, they are on the right path.","“আমাদের মধ্যে আছে আত্মসমর্পণকারীরা, এবং আমাদের মধ্যে আছে আপোষকারীরা।” যারা আত্মসমর্পণ করেছে, তারা সঠিক পথে আছে।"],
  "72:15": ["As for the compromisers, they will be fuel for Gehenna.","আপোষকারীদের ক্ষেত্রে, তারা হবে জাহান্নামের জ্বালানী।"],
  "72:16": ["If they remain on the right path, we will bless them with abundant water.","যদি তারা সঠিক পথে থাকে, আমরা প্রচুর পরিমান পানি দিয়ে তাদের সৌভাগ্যবান করবো।"],
  "72:17": ["We will surely test them all. As for him who disregards the message of his Lord, He will direct him to ever increasing retribution.","আমরা অবশ্যই তাদের সকলকে পরীক্ষা করব। যে ব্যক্তি তার প্রভুর বার্তাকে উপেক্ষা করে, তিনি তাকে ক্রমবর্ধমান শাস্তির দিকে পরিচালিত করবেন।"],
  "72:18": ["The places of worship belong to Allah; do not call on anyone else beside Allah.","উপাসনার স্থানগুলো ঈশ্বরের; ঈশ্বরের পাশে অন্য কাউকে ডেকো না।"],
  "72:19": ["When Allah's servant advocated Him alone, almost all of them banded together to oppose him.","যখন ঈশ্বরের বান্দা একমাত্র তাঁর ওকালতি করেছিল, তাদের প্রায় সকলেই তার বিরোধিতা করার জন্য একত্রিত হয়ে গেল।"],
  "72:20": ["Say, \"I worship only my Lord; I never set up any idols besides Him.\"","বল, “আমি একমাত্র আমার প্রভুর উপাসনা করি; আমি কখনই তাঁর পাশে কোন উপাস্য স্থাপন করি না।”"],
  "72:21": ["Say, \"I possess no power to harm you, nor to guide you.\"","বল, “আমার কোন ক্ষমতা নেই তোমাদের ক্ষতি করার, না তোমাদের পথ দেখাবার।”"],
  "72:22": ["Say, \"No one can protect me from Allah, nor can I find any other refuge besides Him.","বল, “কেউ আমাকে ঈশ্বরের হাত থেকে রক্ষা করতে পারে না, না আমি তার পাশে অন্য কোন আশ্রয় পেতে পারি।"],
  "72:23": ["\"I deliver Allah's proclamations and messages.\" Those who disobey Allah and His messenger incur the fire of Hell, wherein they abide forever.","“আমি ঈশ্বরের ঘোষণা ও বার্তা পৌঁছে দেই।” যারা ঈশ্বর ও তার বার্তাবাহককে অমান্য করে তারা টেনে আনে নরকের আগুন, যেখানে তারা চিরকাল বাস করে।"],
  "72:24": ["Once they see what is awaiting them, they will find out who is really weaker in power, and fewer in number.","একবার যখন তারা দেখে তাদের জন্য কি অপেক্ষা করছে, তারা দেখতে পাবে কারা সত্যিকার অর্থে শক্তিতে দুর্বল ও সংখ্যায় কম।"],
  "72:25": ["Say, \"I do not know if what is promised to you will happen soon, or if my Lord will delay it for awhile.\"","বল, “আমি জানি না তোমাদের কাছে যার অঙ্গীকার করা হয় তা কি শীঘ্রই ঘটবে, নাকি আমার প্রভু কিছু সময়ের জন্য একে বিলম্বিত করাবেন।”"],
  "72:26": ["He is the Knower of the future; He does not reveal the future to anyone.","তিনি ভবিষ্যত জান্তা; তিনি কারো কাছে ভবিষ্যতের কথা প্রকাশ করেন না।"],
  "72:27": ["Only to a messenger that He chooses, does He reveal from the past and the future, specific news.","শুধু তিনি পছন্দ করেন এমন একজন বার্তাবাহকের কাছে, তিনি অতীত ও ভবিষ্যৎ থেকে নির্দিষ্ট সংবাদ প্রকাশ করেন।"],
  "72:28": ["This is to ascertain that they have delivered their Lord's messages. He is fully aware of what they have. He has counted the numbers of all things.","এর কারণ নিশ্চিত করা যে তারা তাদের প্রভুর বানী পৌঁছে দিয়েছে। তাদের কাছে যা আছে সে সম্পর্কে তিনি পুরোপুরি অবহিত। তিনি সমস্ত বস্তুর সংখ্যা গণনা করে রেখেছেন।"],
  "73:1": ["O you cloaked one.","ও হে চাদর আবৃত।"],
  "73:2": ["Meditate during the night, except rarely.","রাতে ধ্যান করো, কদাচিৎ ছাড়া।"],
  "73:3": ["Half of it, or a little less.","এর অর্ধেক, বা কিছু কম।"],
  "73:4": ["Or a little more. And read the Quran from cover to cover.","বা কিছু বেশি। এবং কুরআন পড় প্রথম থেকে শেষ পর্যন্ত।"],
  "73:5": ["We will give you a heavy message.","তোমাকে আমরা একটি ভারি বার্তা দিব।"],
  "73:6": ["The meditation at night is more effective, and more righteous.","রাতের ধ্যান বেশি কার্যকর, এবং বেশি ন্যায়নিষ্ঠ।"],
  "73:7": ["You have a lot of time during the day for other matters.","দিনের বেলায় তোমার অনেকটা সময় অন্যান্য বিষয়ের জন্য রয়েছে ।"],
  "73:8": ["You shall commemorate the name of your Lord, to come ever closer and closer to Him.","তুমি তোমার প্রভুর নাম স্মরণ কর, তাঁর আরো নিকট থেকে নিকটে আসতে।"],
  "73:9": ["Lord of the east and the west; there is no other god besides Him. You should choose Him as your advocate.","পূর্ব ও পশ্চিমের প্রভু, তাঁর পাশে অন্য উপাস্য নেই। তোমার উকিল হিসাবে তাঁকে বেছে নেয়া উচিত।"],
  "73:10": ["And remain steadfast in the face of their utterances, and disregard them in a nice manner.","এবং তাদের কথার বিপরীতে দৃঢ় থাকো, এবং তাদের উপেক্ষা কর সুন্দরভাবে।"],
  "73:11": ["And let Me deal with the rejectors, who have been generously blessed; just give them a little time.","এবং প্রত্যাখ্যানকারীদের আমার হাতে ছেড়ে দাও, যাদের অনুগ্রহ করা হয়েছে উদারভাবে; তাদেরকে শুধু কিছু সময় দাও।"],
  "73:12": ["We have severe punishments, and Hell.","আমাদের কাছে আছে কঠোর শাস্তি, এবং নরক।"],
  "73:13": ["Food that can hardly be swallowed, and painful retribution.","খাবার যা কষ্ট করে গেলা যায় ও যন্ত্রণাদায়ক শাস্তি।"],
  "73:14": ["The day will come when the earth and the mountains will quake, and the mountains will turn into a weightless pile.","সেদিন আসবে যখন পৃথিবী ও পর্বতমালা কম্পিত হবে, এবং পর্বতমালা ভারহীন স্তূপে পরিণত হবে।"],
  "73:15": ["We have sent to you a messenger, just as we sent to Pharaoh a messenger.","আমরা তোমাদের কাছে একজন বার্তাবাহক পাঠিয়েছি, ঠিক যেমন আমরা ফেরাউনের কাছে একজন বার্তাবাহক পাঠিয়েছিলাম।"],
  "73:16": ["Pharaoh disobeyed the messenger and, consequently, we punished him severely.","ফেরাউন বার্তাবাহককে অমান্য করেছিল এবং পরিণামে, আমরা তাকে কঠিন শাস্তি দিয়েছিলাম।"],
  "73:17": ["If you disbelieve, how can you evade a day so terrible that it makes the infants gray-haired?","যদি তোমরা অবিশ্বাস করো, তবে কেমন করে এমন এক দিনকে তোমরা এড়াতে পারো যা এতো ভয়াবহ যে এটি শিশুদের বানিয়ে দেয় ধূসর কেশযুক্ত?"],
  "73:18": ["The heaven will shatter therefrom. His promise is true.","আকাশ সেখান থেকে বিদীর্ণ হবে। তাঁর প্রতিশ্রুতি সত্য।"],
  "73:19": ["This is a reminder; whoever wills, let him choose the path to his Lord.","এটি একটি সতর্কবাণী; যার ইচ্ছা, সে যেন তার প্রভুর দিকের পথ বেছে নেয়।"],
  "73:20": ["Your Lord knows that you meditate during two-thirds of the night, or half of it, or one-third of it, and so do some of those who believed with you. Allah has designed the night and the day, and He knows that you cannot always do this. He has pardoned you. Instead, you shall read what you can of the Quran. He knows that some of you may be ill, others may be traveling in pursuit of Allah's provisions, and others may be striving in the cause of Allah. You shall read what you can of it, and observe the contact prayers (Salat), give the obligatory charity (Zakat), and lend Allah a loan of righteousness. Whatever good you send ahead on behalf of your souls, you will find it at Allah far better and generously rewarded. And implore Allah for forgiveness. Allah is Forgiver, Most Merciful.","তোমার প্রভু জানেন যে তুমি রাতের দুই-তৃতীয়াংশ, অথবা এর অর্ধেক বা এর এক তৃতীয়াংশ সময় ধ্যান কর এবং তোমার সাথে যারা বিশ্বাস করেছে তাদের মধ্যেও কেউ কেউ তা করে। ঈশ্বর রাত ও দিনের নকশা করেছেন এবং তিনি জানেন যে তোমরা সর্বদা এটি করতে পারো না। তিনি তোমাদের ক্ষমা করেছেন। পরিবর্তে, তোমরা কুরআনের যতটুকু পার ততটুকু পাঠ কর। তিনি জানেন যে তোমাদের কেউ কেউ অসুস্থ থাকতে পার, অন্যরা হয়তো ঈশ্বরের জীবিকা লাভের চেষ্টায় ভ্রমন করতে পার, এবং অন্যান্যরা হয়তো ঈশ্বরের পথে সংগ্রাম করতে পারো। তোমরা এর থেকে যতটুকু পারো পাঠ করো, এবং সংযোগ প্রার্থনা (সালাত) পালন করো, বাধ্যতামূলক দান (যাকাত) দাও, এবং ঈশ্বরকে এক ন্যায়পরায়ণতার ঋণ দাও। তোমাদের আত্মার সমর্থনে যাকিছু ভালো তোমরা সামনে পাঠাবে, ঈশ্বরের কাছে তোমরা তা আরও উত্তমরুপে ও উদারভাবে পুরস্কৃত অবস্থায় পাবে। ঈশ্বরের কাছে ক্ষমার জন্য প্রার্থনা করো। ঈশ্বর ক্ষমাশীল, পরম দয়ালু।"],
  "74:1": ["O you hidden secret.","হে লুকায়িত রহস্য।"],
  "74:2": ["Come out and warn.","প্রকাশিত হও এবং সতর্ক করো।"],
  "74:3": ["Extol your Lord.","তোমার প্রভুর প্রশংসা করো।"],
  "74:4": ["Purify your garment.","তোমার পোশাক শুদ্ধ করো।"],
  "74:5": ["Forsake what is wrong.","যা ভুল তা ত্যাগ করো।"],
  "74:6": ["Be content with your lot.","তোমার ভাগ্য নিয়ে সন্তুষ্ট থাকো।"],
  "74:7": ["Steadfastly commemorate your Lord.","অবিচলভাবে তোমার প্রভুর স্মরণ করো।"],
  "74:8": ["Then, when the horn is blown.","অতঃপর, যখন শিংগায় ফুঁ দেয়া হয়।"],
  "74:9": ["That will be a difficult day.","এটা হবে এক কঠিন দিন।"],
  "74:10": ["For the disbelievers, not easy.","অবিশ্বাসীদের জন্য, সহজ নয়।"],
  "74:11": ["Let Me deal with one I created as an individual.","আমাকে সে ব্যক্তির বিষয়ে সিদ্ধান্ত নিতে দাও যাকে আমি একজন ব্যক্তি হিসাবে সৃষ্টি করেছিলাম।"],
  "74:12": ["I provided him with lots of money.","তাকে আমি দিয়েছিলাম- প্রচুর অর্থ।"],
  "74:13": ["And children to behold.","এবং দেখার জন্য সন্তানদের।"],
  "74:14": ["I made everything easy for him.","আমি তার জন্য সবকিছু সহজ করে দিয়েছিলাম।"],
  "74:15": ["Yet, he is greedy for more.","এরপরও, সে আরো পাওয়ার জন্য লোভী।"],
  "74:16": ["He stubbornly refused to accept these proofs.","সে একগুঁয়েভাবে এই প্রমানাদি মানতে অস্বীকার করলো।"],
  "74:17": ["I will increasingly punish him.","আমি তাকে ক্রমবর্ধমান শাস্তি দেব।"],
  "74:18": ["For he reflected, then decided.","কারণ, সে চিন্তাভাবনা করেছিল, এরপর সিদ্ধান্ত নিল।"],
  "74:19": ["Miserable is what he decided.","দু:খজনক তার সিদ্ধান্ত ।"],
  "74:20": ["Miserable indeed is what he decided.","নিশ্চয়, দু:খজনক তার সিদ্ধান্ত।"],
  "74:21": ["He looked.","সে দেখলো।"],
  "74:22": ["He frowned and whined.","সে ভ্রূকুটি করলো আর ঘ্যানঘ্যান করলো।"],
  "74:23": ["Then he turned away arrogantly.","এরপর, সে অহংকারে মুখ ফিরিয়ে নিল।"],
  "74:24": ["He said, \"This is but clever magic!","সে বলল, “এ তো চতুর জাদু!"],
  "74:25": ["\"This is human made.\"","“এটি মানুষের তৈরি।”"],
  "74:26": ["I will commit him to retribution.","আমি তাকে শাস্তিতে প্রবেশ করাবো।"],
  "74:27": ["What retribution!","কি রকম শাস্তি!"],
  "74:28": ["Thorough and comprehensive.","সর্বোতভাবে সম্পূর্ণ এবং বোধগম্য।"],
  "74:29": ["Obvious to all the people.","সব লোকের কাছে স্পষ্ট।"],
  "74:30": ["Over it is nineteen.","এর উপর আছে উনিশ।"],
  "74:31": ["We appointed angels to be guardians of Hell, and we assigned their number (19) (1) to disturb the disbelievers, (2) to convince the Christians and Jews (that this is a divine scripture), (3) to strengthen the faith of the faithful, (4) to remove all traces of doubt from the hearts of Christians, Jews, as well as the believers, and (5) to expose those who harbor doubt in their hearts, and the disbelievers; they will say, \"What did Allah mean by this allegory?\" Allah thus sends astray whomever He wills, and guides whomever He wills. None knows the soldiers of your Lord except He. This is a reminder for the people.","আমরা নরকের তত্ত্বাবধায়ক হিসেবে ফেরেশতাদের নিযুক্ত করেছি, এবং আমরা তাদের সংখ্যা নির্ধারণ করেছি (১৯) (১) অবিশ্বাসীদের বিরক্ত করতে (২) খ্রিস্টান ও ইহুদীদের বুঝাতে (যে এটি একটি ঐশীগ্রন্থ) (৩) আস্থাবানদের আস্থা আরো শক্তিশালী করতে (৪) খ্রিস্টান, ইহুদী সেই সাথে বিশ্বাসীদের হৃদয় থেকে সন্দেহের সব ছিটেফোঁটা দূর করতে, এবং (৫) তাদেরকে প্রকাশ করার জন্য যারা হৃদয়ে সন্দেহ পোষণ করে , এবং অবিশ্বাসীদের; তারা বলবে, “ঈশ্বর এই রুপকের মাধ্যমে কি বুঝিয়েছেন?” ঈশ্বর এভাবে যাকে ইচ্ছা পথভ্রষ্ট করেন এবং যাকে ইচ্ছা পথ দেখান। তোমার প্রভুর সৈন্যদের বিষয়ে তিনি ব্যতিত কেউ জানে না। এটি লোকদের জন্য একটি সতর্কবার্তা।"],
  "74:32": ["Absolutely, (I swear) by the moon.","অবশ্যই, (আমি শপথ করি) চাঁদের।"],
  "74:33": ["And the night as it passes.","এবং রাতের যখন তা অতিবাহিত হয়।"],
  "74:34": ["And the morning as it shines.","এবং প্রভাতের যখন তা আলো ছড়ায়।"],
  "74:35": ["This is one of the great miracles.","এটি বড়ো অলৌকিকতাসমূহের একটি।"],
  "74:36": ["A warning to the human race.","মানব জাতির প্রতি একটি সতর্কবার্তা।"],
  "74:37": ["For those among you who wish to advance, or regress.","তোমাদের মধ্যে যে এগিয়ে যেতে চায় অথবা পেছনে পড়ে থাকতে চায়, তার জন্য।"],
  "74:38": ["Every soul is trapped by its sins.","প্রত্যেক আত্মা এর পাপের ফাঁদে আটকে যায়।"],
  "74:39": ["Except for those on the right.","ডান পার্শ্বস্থরা ছাড়া।"],
  "74:40": ["While in Paradise, they will ask.","স্বর্গে, তারা জিজ্ঞেস করবে।"],
  "74:41": ["About the guilty.","অপরাধীদের বিষয়ে।"],
  "74:42": ["\"What brought you to this retribution?\"","“কিসে তোমাদের এই শাস্তিতে নিয়ে এসেছে?”"],
  "74:43": ["They will say, \"We did not observe the contact prayers (Salat).","তারা বলবে, “আমরা সংযোগ প্রার্থনা (সালাত) পালন করিনি।"],
  "74:44": ["\"We did not feed the poor.","“আমরা গরীবদের খেতে দিতাম না।"],
  "74:45": ["\"We blundered with the blunderers.","“আমরা ভ্রান্তদের সাথে ভুল পথে চলতাম।"],
  "74:46": ["\"We disbelieved in the Day of Judgment.","“আমরা বিচার দিনকে অবিশ্বাস করতাম।"],
  "74:47": ["\"Until certainty came to us now.\"","“এখন আমাদের কাছে নিশ্চয়তা আসা পর্যন্ত।”"],
  "74:48": ["The intercession of the intercessors will never help them.","সুপারিশকারীদের সুপারিশ কখনো তাদের সাহায্য করবে না।"],
  "74:49": ["Why are they so averse to this reminder?","তারা এই সতর্কবার্তার প্রতি এতো বিমুখ কেন?"],
  "74:50": ["Running like zebras.","জেব্রার মতো দৌড়ানো।"],
  "74:51": ["Who are fleeing from the lion!","যেগুলো সিংহ থেকে পালাচ্ছে।"],
  "74:52": ["Does each one of them want to receive the scripture personally?","তাদের প্রত্যেকে কি ব্যক্তিগতভাবে ঐশীগ্রন্থ পেতে চায়।"],
  "74:53": ["Indeed, they do not fear the Hereafter.","নিশ্চয়, তারা পরকালকে ভয় করে না।"],
  "74:54": ["Indeed, this is a reminder.","নিশ্চয়, এটি একটি স্মারক।"],
  "74:55": ["For those who wish to take heed.","তাদের জন্য যারা মনোযোগ দিতে চায়।"],
  "74:56": ["They cannot take heed against Allah's will. He is the source of righteousness; He is the source of forgiveness.","তারা মনোযোগ দিতে পারে না ঈশ্বরের ইচ্ছার বিরুদ্ধে। তিনি সৎ-কর্মশীলতার উৎস; তিনি ক্ষমাশীলতার উৎস।"],
  "75:1": ["I swear by the Day of Resurrection.","আমি পুনরুত্থান দিবসের শপথ করছি।"],
  "75:2": ["And I swear by the blaming soul.","এবং আমি দোষারোপকারী আত্মার শপথ করছি।"],
  "75:3": ["Does the human being think that we will not reconstruct his bones?","মানুষ কি মনে করে যে আমরা তার হাড়গুলো পুননির্মান করবো না?"],
  "75:4": ["Yes indeed; we are able to reconstruct his finger tip.","হ্যা নিশ্চয়; আমরা তার আঙুলের ডগা পুননির্মান করতে সক্ষম।"],
  "75:5": ["But the human being tends to believe only what he sees in front of him.","কিন্তু মানুষ বিশ্বাসপ্রবন শুধু তাতে যা সে তার সামনে দেখে।"],
  "75:6": ["He doubts the Day of Resurrection!","সে পুনরুত্থান দিবসে সন্দেহ করে।"],
  "75:7": ["Once the vision is sharpened.","একবার যখন দৃষ্টি শানিত করা হয়।"],
  "75:8": ["And the moon is eclipsed.","এবং চাঁদকে অন্ধকারাচ্ছন্ন করা হয় ।"],
  "75:9": ["And the sun and the moon crash into one another.","এবং সূর্য ও চাঁদ একে অন্যের উপর আছড়ে পড়ে।"],
  "75:10": ["The human being will say on that day, \"Where is the escape?\"","মানুষ ওই দিন বলবে, \"পলায়নের উপায় কোথায়?\""],
  "75:11": ["Absolutely, there is no escape.","নি:সন্দেহে, পলায়নের কোন উপায় নেই।"],
  "75:12": ["To your Lord, on that day, is the final destiny.","তোমাদের প্রভুর কাছে,ঐদিন, চূড়ান্ত নিয়তি।"],
  "75:13": ["The human being will be informed, on that day, of everything he did to advance himself, and everything he did to regress himself.","মানুষকে জানানো হবে, ঐদিন, সবকিছু যা সে নিজেকে এগিয়ে নিতে করেছে, এবং সবকিছু যা সে নিজেকে পেছানোর জন্য করেছে।"],
  "75:14": ["The human being will be his own judge.","মানুষ তার নিজের বিচারক হবে।"],
  "75:15": ["No excuses will be accepted.","কোন অজুহাত গ্রহন করা হবে না।"],
  "75:16": ["Do not move your tongue to hasten it.","এটি দ্রুত করতে তোমার জিহবা নাড়বে না।"],
  "75:17": ["It is we who will collect it into Quran.","আমরাই এটি কুরআন আকারে সংগ্রহ করবো।"],
  "75:18": ["Once we recite it, you shall follow such a Quran.","একবার আমরা এটি আবৃতি করলে, তুমি  অনুসরণ করবে এমনি এক কুরআন।"],
  "75:19": ["Then it is we who will explain it.","তারপর আমরাই এটি ব্যাখ্যা করবো।"],
  "75:20": ["Indeed, you love this fleeting life.","প্রকৃতপক্ষে, তোমরা এই ক্ষনস্থায়ী জীবনকে ভালবাসো।"],
  "75:21": ["While disregarding the Hereafter.","যখন পরকালকে অবহেলা করছো।"],
  "75:22": ["Some faces, on that day, will be happy.","কিছু মুখ, ঐদিন, সুখী হবে।"],
  "75:23": ["Looking at their Lord.","তাদের প্রভুর দিকে তাকিয়ে।"],
  "75:24": ["Other faces will be, on that day, miserable.","অন্য মুখগুলো, ঐদিন, দুর্দশাগ্রস্থ হবে।"],
  "75:25": ["Expecting the worst.","আশা করতে থাকবে সবচেয়ে নিকৃষ্ট কিছু।"],
  "75:26": ["Indeed, when (the soul) reaches the throat.","প্রকৃতপক্ষে, যখন (আত্মা) গলা পর্যন্ত পৌঁছায়।"],
  "75:27": ["And it is ordered: \"Let go!\"","এবং একে আদেশ করা হয়: \"বেরিয়ে যাও!\""],
  "75:28": ["He knows it is the end.","সে জানে যে এটাই পরিসমাপ্তি।"],
  "75:29": ["Each leg will lay motionless next to the other leg.","এক পা অন্য পায়ের পাশে নিশ্চল পরে থাকবে।"],
  "75:30": ["To your Lord, on that day, is the summoning.","তোমার প্রভুর কাছে, ঐদিন, তলব করা হবে।"],
  "75:31": ["For he observed neither the charity, nor the contact prayers (Salat).","কারণ সে না দান করতো, না সংযোগ প্রার্থনা (সালাত) পালন করতো।"],
  "75:32": ["But he disbelieved and turned away.","কিন্তু সে অবিশ্বাস করেছিল এবং মুখ ফিরিয়ে নিয়েছিল।"],
  "75:33": ["With his family, he acted arrogantly.","তার পরিবারের সাথে, সে ঔদ্ধত্যপনা দেখিয়েছে।"],
  "75:34": ["You have deserved this.","তুমি এর উপযুক্ত হয়েছো।"],
  "75:35": ["Indeed, you have deserved this.","নিশ্চয়ই, তুমি এর উপযুক্ত হয়েছো।"],
  "75:36": ["Does the human being think that he will go to nothing?","মানুষ কি মনে করে যে সে কিছুই থাকবে না?"],
  "75:37": ["Was he not a drop of ejected semen?","সে কি নির্গত এক ফোঁটা বীর্য ছিল না?"],
  "75:38": ["Then He created an embryo out of it!","এরপর তিনি এর থেকে একটি ভ্রুন সৃষ্টি করেছিলেন।"],
  "75:39": ["He made it into male or female!","তিনি এরপর একে পুরুষ অথবা নারী বানিয়েছিলেন।"],
  "75:40": ["Is He then unable to revive the dead?","তিনি কি এরপর মৃতকে পুনর্জীবিত করতে অক্ষম?"],
  "76:1": ["Is it not a fact that there was a time when the human being was nothing to be mentioned?","এটা কি বাস্তব নয় যে একটা সময় ছিল যখন মানুষ বলে উল্লেখ করার মতো কিছু ছিল না?"],
  "76:2": ["We created the human from a liquid mixture, from two parents, in order to test him. Thus, we made him a hearer and a seer.","আমরা মানুষকে সৃষ্টি করেছিলাম একটি তরল মিশ্রণ থেকে, মাতাপিতা দু'জন থেকে, তাকে পরীক্ষা করার উদ্দেশ্যে। আর তাই, আমরা তাকে একজন শ্রোতা ও দ্রষ্টা করেছি।"],
  "76:3": ["We showed him the two paths, then, he is either appreciative, or unappreciative.","আমরা তাকে দেখালাম দুটি পথ, তারপর, হয়তো সে কৃতজ্ঞ হয় নয়তো অকৃতজ্ঞ হয়।"],
  "76:4": ["We prepared for the disbelievers chains, shackles, and a blazing Hell.","আমরা অবিশ্বাসীদের জন্য প্রস্তুত করলাম শিকল, বেড়ি, এবং এক জ্বলন্ত নরক।"],
  "76:5": ["As for the virtuous, they will drink from cups spiced with nectar.","আর পূণ্যবানদের ক্ষেত্রে, তারা সুস্বাদু পানীয়ের কাপ থেকে পান করবে।"],
  "76:6": ["A spring that is reserved for Allah's servants; it will gush out as they will.","একটি ঝর্ণা- যা সংরক্ষিত আল্লাহর প্রতি নিবেদিতদের জন্য; এটি বের হয়ে আসবে প্রবল বেগে যেমন তারা চায়।"],
  "76:7": ["They fulfill their pledges, and reverence a day that is extremely difficult.","তারা তাদের প্রতিশ্রুতি পূর্ণ করে এবং এমন এক দিনকে সমীহ করে যা অত্যন্ত কঠিন।"],
  "76:8": ["They donate their favorite food to the poor, the orphan, and the captive.","তারা তাদের প্রিয় খাবার দান করে দরিদ্র, এতিম এবং বন্দীদের।"],
  "76:9": ["\"We feed you for the sake of Allah; we expect no reward from you, nor thanks.","\"আমরা তোমাদের খাওয়াই আল্লাহর উদ্দেশ্যে; না আমরা তোমাদের কাছ থেকে আশা করি পুরস্কার, না ধন্যবাদ।"],
  "76:10": ["\"We fear from our Lord a day that is full of misery and trouble.\"","\"আমরা আমাদের প্রভুকে ভয় করি সে দিনের ব্যাপারে যা দূর্দশা এবং যন্ত্রণায় পূর্ণ।\""],
  "76:11": ["Consequently, Allah protects them from the evils of that day, and rewards them with joy and contentment.","পরিনামে, ঈশ্বর তাদের রক্ষা করেন সে দিনের অমঙ্গল থেকে, এবং তাদেরকে পুরস্কৃত করেন আনন্দ ও পরিতৃপ্তি দিয়ে।"],
  "76:12": ["He rewards them for their steadfastness with Paradise, and silk.","তাদের অবিচলতার জন্য তিনি তাদের পুরস্কৃত করেন স্বর্গ, এবং রেশম দিয়ে।"],
  "76:13": ["They relax therein on luxurious furnishings. They suffer neither the heat of the sun, nor any cold.","তারা সেখানে বিলাসবহুল আসবাবের উপর আরাম করে। না তারা ভোগ করে সূর্যের তাপ, না কোন শীতলতা।"],
  "76:14": ["The shade covers them therein, and the fruits are brought within reach.","ছায়া সেখানে তাদের আবৃত করে, এবং ফলফলাদি নাগালের মধ্যে আনা হয়।"],
  "76:15": ["They are served drinks in silver containers and cups that are translucent.","তাদেরকে পানীয় পরিবেশন করা হয় রুপার পাত্র ও কাপে যা আলোকপ্রবাহী।"],
  "76:16": ["Translucent cups, though made of silver; they rightly deserved all this.","আলোকপ্রবাহী কাপ, যদিও রুপার তৈরী; এই সবকিছুর যথার্থ যোগ্যই তারা ছিল।"],
  "76:17": ["They enjoy drinks of delicious flavors.","তারা উপভোগ করে সুস্বাদু পানীয়।"],
  "76:18": ["From a spring therein known as \"Salsabeel.\"","সেখানকার একটি ঝরনা থেকে যা ‘সালসাবিল’ নামে পরিচিত।"],
  "76:19": ["Serving them will be immortal servants. When you see them, they will look like scattered pearls.","তাদের সেবায় থাকবে চিরজীবী সেবকরা। তুমি যখন তাদের দেখবে, তাদেরকে বিক্ষিপ্ত মুক্তার মত দেখাবে।"],
  "76:20": ["Wherever you look, you will see bliss, and a wonderful dominion.","তুমি যেখানেই তাকাও, তুমি দেখবে সুখ ও এক চমৎকার রাজত্ব।"],
  "76:21": ["On them will be clothes of green velvet, satin, and silver ornaments. Their Lord will provide them with pure drinks.","তাদের উপর থাকবে সবুজ মখমল, সাটিন বস্ত্র ও রূপার অলঙ্কার। তাদের প্রভু তাদের  সরবরাহ করবেন বিশুদ্ধ পানীয়।"],
  "76:22": ["This is the reward that awaits you, for your efforts have been appreciated.","এটা সে পুরস্কার যা তোমাদের জন্য অপেক্ষা করে, কেননা তোমাদের প্রচেষ্টার মূল্যায়ন হয়েছে।"],
  "76:23": ["We have revealed to you this Quran; a special revelation from us.","আমরা তোমাদের নিকট এই কুরআন প্রকাশ করেছি; যা আমাদের পক্ষ থেকে একটি বিশেষ প্রকাশ।"],
  "76:24": ["You shall steadfastly carry out your Lord's commandments, and do not obey any sinful disbeliever among them.","তোমরা অবিচলতার সাথে তোমাদের প্রভুর প্রত্যাদেশ পালন করবে, আর তাদের মধ্যকার কোন পাপী অবিশ্বাসীকে মান্য করবে না।"],
  "76:25": ["And commemorate the name of your Lord day and night.","আর তোমাদের প্রভুর নাম স্মরণ করো দিনে ও রাতে।"],
  "76:26": ["During the night, fall prostrate before Him, and glorify Him many a long night.","রাতের বেলায়, তাঁর সামনে সেজদায় পড়ো, এবং বহু দীর্ঘ-রাতজুড়ে তাঁর মহিমা ঘোষণা করো।"],
  "76:27": ["These people are preoccupied with this fleeting life, while disregarding—just ahead of them—a heavy day.","এইসব লোকেরা এই ক্ষনস্থায়ী জীবন নিয়ে আচ্ছন্ন, যখন উপেক্ষা করছে- তাদের ঠিক সামনের- এক ভারী দিনকে।"],
  "76:28": ["We created them, and established them, and, whenever we will, we can substitute others in their place.","আমরা তাদের সৃষ্টি করলাম, এবং তাদের প্রতিষ্ঠিত করলাম, আর, যখনই আমরা চাই, আমরা তাদের জায়গায় অন্যদের প্রতিস্থাপন করতে পারি।"],
  "76:29": ["This is a reminder: whoever wills shall choose the path to his Lord.","এটি একটি স্মারক: যেকেউ চায় তার প্রভুর পথ বেছে নিবে।"],
  "76:30": ["Whatever you will is in accordance with Allah's will. Allah is Omniscient, Wise.","যা কিছু তোমরা ইচ্ছা করো, তা ঈশ্বরের ইচ্ছানুযায়ী হয়। ঈশ্বর সর্বজ্ঞ, জ্ঞানী।"],
  "76:31": ["He admits whomever He wills into His mercy. As for the transgressors, He has prepared for them a painful retribution.","তিনি যাকে ইচ্ছা তাঁর দয়ায় প্রবেশ করান। আর সীমালঙ্ঘনকারীদের ক্ষেত্রে , তিনি তাদের জন্য একটি যন্ত্রণাদায়ক শাস্তি প্রস্তুত করেছেন।"],
  "77:1": ["(Angels) dispatched in succession.","(স্বর্গদূত) পর্যায়ক্রমে প্রেরিত।"],
  "77:2": ["To drive the wind.","বাতাস চালনা করতে।"],
  "77:3": ["Stir up clouds.","মেঘমালা সঞ্চালিত করতে।"],
  "77:4": ["Distribute the provisions.","খাদ্যদ্রব্য সরবরাহ করতে।"],
  "77:5": ["Deliver messages.","সংবাদ বিলি করতে।"],
  "77:6": ["Good news, as well as warnings.","শুভ সংবাদ, একই সাথে সতর্কবার্তা।"],
  "77:7": ["What is promised will come to pass.","যার প্রতিশ্রুতি দেয়া হয়, তা আসবে।"],
  "77:8": ["Thus, when the stars are put out.","সুতরাং, যখন তারাগুলোকে নিভিয়ে দেয়া হয়।"],
  "77:9": ["The sky is opened up.","আকাশ উন্মুক্ত করা হয়।"],
  "77:10": ["The mountains are blown up.","পর্বতমালা ধ্বংস করা হয়।"],
  "77:11": ["The messengers are summoned.","বার্তাবাহকদের তলব করা হয়।"],
  "77:12": ["That is the appointed day.","এটা সেই নির্ধারিত দিন।"],
  "77:13": ["The Day of Decision.","সিদ্ধান্তের দিন।"],
  "77:14": ["What a Day of Decision!","কী এক সিদ্ধান্তের দিন!"],
  "77:15": ["Woe on that day to the rejectors.","দিনটি হবে প্রত্যাখ্যানকারীদের জন্য দুঃখের।"],
  "77:16": ["Did we not annihilate the earlier generations?","আমরা কি পূর্বের প্রজন্মদের ধ্বংস করিনি?"],
  "77:17": ["Then we made others follow them?","তারপর, আমরা তাদের পর অন্যদের আসতে দেইনি?"],
  "77:18": ["This is what we do to the criminals.","অপরাধীদের সাথে আমরা এমনই করি।"],
  "77:19": ["Woe on that day to the rejectors.","দিনটি হবে প্রত্যাখ্যানকারীদের জন্য দুঃখের।"],
  "77:20": ["Did we not create you from a lowly liquid?","আমরা কি তোমাদের নিম্নমানের তরল থেকে সৃষ্টি করিনি?"],
  "77:21": ["Then we placed it in a well-protected repository.","এরপর, আমরা তা রেখেছি সুরক্ষিত আধারে।"],
  "77:22": ["For a specific period.","একটি নির্দিষ্ট সময়ের জন্য।"],
  "77:23": ["We measured it precisely. We are the best designers.","আমরা তা পরিমাপ করেছিলাম যথাযথভাবে। আমরা সর্বোত্তম নকশাকারী।"],
  "77:24": ["Woe on that day to the rejectors.","দিনটি হবে প্রত্যাখ্যানকারীদের জন্য দুঃখের।"],
  "77:25": ["Did we not make the earth an abode?","আমরা কি পৃথিবীকে একটি আবাস বানাইনি?"],
  "77:26": ["For the living and the dead?","জীবিত এবং মৃতদের জন্য?"],
  "77:27": ["We placed on it high mountains, and provided you with fresh water to drink.","আমরা এতে স্থাপন করেছি উচুঁ পর্বতমালা, এবং তোমাদের পান করার জন্য প্রদান করেছি বিশুদ্ধ পানি।"],
  "77:28": ["Woe on that day to the rejectors.","দিনটি হবে প্রত্যাখ্যানকারীদের জন্য দুঃখের।"],
  "77:29": ["Go to what you used to disbelieve in.","সেখানে যাও, যেখানে যাবার বিষয়ে অবিশ্বাস পোষনে তোমরা অভ্যস্ত ছিলে।"],
  "77:30": ["Go to a shade of three different densities.","যাও, তিনটি ভিন্ন ঘনত্বের ছায়ায়।"],
  "77:31": ["Yet, it provides neither coolness, nor protection from the heat.","অথচ, এটি না সরবরাহ করে শীতলতা, না রক্ষা করে তাপ থেকে।"],
  "77:32": ["It throws sparks as big as mansions.","এটি অট্টালিকাসমূহের মতো বড় স্ফুলিঙ্গ নিক্ষেপ করে।"],
  "77:33": ["As yellow as the color of camels.","উটের বর্ণের মতো হলুদ।"],
  "77:34": ["Woe on that day to the rejectors.","দিনটি হবে প্রত্যাখ্যানকারীদের জন্য দুঃখের।"],
  "77:35": ["That is the day they do not speak.","এটা সেই দিন, যখন তারা কথা বলে না।"],
  "77:36": ["Nor are they given permission to apologize.","না তাদের ক্ষমা চাওয়ার অনুমতি দেয়া হবে।"],
  "77:37": ["Woe on that day to the rejectors.","দিনটি হবে প্রত্যাখ্যানকারীদের জন্য দুঃখের।"],
  "77:38": ["This is the Day of Decision. We have summoned you and the previous generations.","এটি সিদ্ধান্তের দিন। আমরা তোমাদের এবং পূর্ববর্তী প্রজন্মদের তলব করেছি।"],
  "77:39": ["If you have any schemes, go ahead and scheme.","যদি তোমাদের কোন ষড়যন্ত্র থাকে, তবে এগিয়ে যাও এবং ষড়যন্ত্র করো।"],
  "77:40": ["Woe on that day to the rejectors.","দিনটি হবে প্রত্যাখ্যানকারীদের জন্য দুঃখের।"],
  "77:41": ["The righteous will enjoy shade and springs.","সৎকর্মশীলরা ছায়া এবং ঝর্ণা উপভোগ করবে।"],
  "77:42": ["And fruits that they desire.","এবং ফল যা তারা আকাঙ্খা করে।"],
  "77:43": ["Eat and drink happily in return for your works.","তোমাদের কাজের বিনিময়ে আনন্দের সাথে খাও এবং পান করো।"],
  "77:44": ["We thus reward the virtuous.","আমরা এভাবে পুরষ্কৃত করি পুণ্যকারীদের।"],
  "77:45": ["Woe on that day to the rejectors.","দিনটি হবে প্রত্যাখ্যানকারীদের জন্য দুঃখের।"],
  "77:46": ["Eat and enjoy temporarily; you are guilty.","খাও এবং উপভোগ কর সাময়িকভাবে; তোমরা অপরাধী।"],
  "77:47": ["Woe on that day to the rejectors.","দিনটি হবে প্রত্যাখ্যানকারীদের জন্য দুঃখের।"],
  "77:48": ["When they are told, \"Bow down,\" they do not bow down.","যখন তাদের বলা হয়, \"নত হও, \" তারা নত হয় না।"],
  "77:49": ["Woe on that day to the rejectors.","দিনটি হবে প্রত্যাখ্যানকারীদের জন্য দুঃখের।"],
  "77:50": ["Which Hadith, other than this, do they uphold?","এটি ছাড়া, কোন হাদিসে, তারা সমর্থন করে?"],
  "78:1": ["What are they questioning?","তারা কি নিয়ে প্রশ্ন করছে?"],
  "78:2": ["The great event.","সে মহা ঘটনা।"],
  "78:3": ["That is disputed by them.","তারা যাতে বিবাদ করে।"],
  "78:4": ["Indeed, they will find out.","নিশ্চয়, তারা দেখতে পাবে।"],
  "78:5": ["Most assuredly, they will find out.","নিঃসন্দেহে, তারা দেখতে পাবে।"],
  "78:6": ["Did we not make the earth habitable?","আমরা কি পৃথিবীকে বাসযোগ্য করিনি?"],
  "78:7": ["And the mountains stabilizers?","এবং পর্বতমালাকে ভারসাম্য রক্ষাকারী?"],
  "78:8": ["We created you as mates (for one another).","আমরা তোমাদের সৃষ্টি করেছিলাম (একে অপরের) সাথী হিসেবে ।"],
  "78:9": ["We created sleeping so you can rest.","আমরা সৃষ্টি করেছি ঘুম, যাতে তোমরা বিশ্রাম করতে পারো।"],
  "78:10": ["We made the night a cover.","আমরা রাতকে একটি আবরণ হিসেবে বানালাম।"],
  "78:11": ["And the day to seek provisions.","এবং জীবিকা খোঁজার জন্য দিন।"],
  "78:12": ["We built above you seven universes.","আমরা তোমাদের উপর সাত মহাবিশ্ব সৃষ্টি করেছি।"],
  "78:13": ["We created a bright lamp.","আমরা সৃষ্টি করেছি এক উজ্জ্বল বাতি।"],
  "78:14": ["We send down from the clouds pouring water.","মেঘ থেকে আমরা অবতীর্ন করি অবিরাম প্রবাহিত পানি।"],
  "78:15": ["To produce with it grains and plants.","এর দ্বারা খাদ্যশস্য এবং উদ্ভিদ উৎপন্ন করতে।"],
  "78:16": ["And various orchards.","এবং নানারকম ফলের বাগান।"],
  "78:17": ["The Day of Decision is appointed.","সিদ্ধান্তের দিনটি নির্ধারিত।"],
  "78:18": ["The day the horn is blown, and you come in throngs.","দিনটিতে শিঙ্গায় ফুঁ দেয়া হয়, আর তোমরা দলেবলে আসো।"],
  "78:19": ["The heaven will be opened like gates.","দরজার মত খোলা হবে স্বর্গ।"],
  "78:20": ["The mountains will be removed, as if they were a mirage.","পর্বতমালা সরিয়ে ফেলা হবে, যেন এরা ছিল একটি মরীচিকা।"],
  "78:21": ["Gehenna is inevitable.","জাহান্নাম অনিবার্য।"],
  "78:22": ["For the transgressors; it will be their abode.","সীমালঙ্ঘনকারীদের জন্য, এটি হবে তাদের আবাস।"],
  "78:23": ["They stay in it for ages.","তারা তাতে অবস্থান করে দীর্ঘকাল।"],
  "78:24": ["They never taste in it coolness, nor a drink.","তারা এর মাঝে না কখনো স্বাদ পায় শীতলতার, না কোন পানীয়ের।"],
  "78:25": ["Only an inferno, and bitter food.","শুধু একটি অগ্নিকুন্ডলী, এবং তিক্ত খাদ্য।"],
  "78:26": ["A just requital.","একটি ন্যায্য প্রতিফল।"],
  "78:27": ["They never expected to be held accountable.","তারা কখনো আশা করেনি যে হিসাব দিতে হবে।"],
  "78:28": ["And utterly rejected our signs.","এবং আমাদের নিদর্শনগুলো সম্পূর্ণরূপে প্রত্যাখ্যান করেছিল।"],
  "78:29": ["We counted everything in a record.","আমরা সবকিছুর হিসাব রাখলাম একটি নথিতে।"],
  "78:30": ["Suffer the consequences; we will only increase your retribution.","ভোগ করো পরিনতিসমূহ; আমরা শুধু তোমাদের শাস্তি বাড়িয়ে দিবো।"],
  "78:31": ["The righteous have deserved a reward.","সৎকর্মশীলরা অর্জন করেছে এক পুরস্কারের।"],
  "78:32": ["Orchards and grapes.","ফলের বাগান এবং আঙ্গুর।"],
  "78:33": ["Magnificent spouses.","চমকপ্রদ স্বামী-স্ত্রী"],
  "78:34": ["Delicious drinks.","সুস্বাদু পানীয়।"],
  "78:35": ["They will never hear in it any nonsense or lies.","এর মাঝে তারা কখনো কোন অর্থহীন বা মিথ্যা কিছু শুনবে না।"],
  "78:36": ["A reward from your Lord; a generous recompense.","তোমাদের প্রভুর পক্ষ থেকে একটি পুরস্কার; এক উদার প্রতিদান।"],
  "78:37": ["Lord of the heavens and the earth, and everything between them. The Most Gracious. No one can abrogate His decisions.","আকাশমন্ডলী ও পৃথিবী, এবং এদের মধ্যকার সবকিছুর প্রভু। সবচেয়ে করুনাময়। কেউ তার সিদ্ধান্ত বাতিল করতে পারে না।"],
  "78:38": ["The day will come when the Spirit and the angels will stand in a row. None will speak except those permitted by the Most Gracious, and they will utter only what is right.","সেদিন আসবে যখন সে আত্মা এবং স্বর্গদূতেরা এক সারিতে দাঁড়াবে। যারা সবচেয়ে করুনাময়ের দ্বারা অনুমোদিত তারা ব্যতীত আর কেউ কথা বলবে না এবং তারা শুধু বলবে, যা সত্য।"],
  "78:39": ["Such is the inevitable day. Whoever wills let him take refuge in his Lord.","এমনই হলো সে অনিবার্য দিন। যেকেউ চায় তাকে তার প্রভুর কাছে আশ্রয় নিতে দাও।"],
  "78:40": ["We have sufficiently warned you about an imminent retribution. That is the day when everyone will examine what his hands have sent forth, and the disbeliever will say, \"Oh, I wish I were dust.\"","একটি আসন্ন শাস্তি সম্পর্কে আমরা তোমাদের যথেষ্ট সতর্ক করেছি। এটা সেই দিন যখন প্রত্যেকে পরীক্ষা করবে যা তার হাত সামনে পাঠিয়েছে এবং অবিশ্বাসী বলবে, \"হায়, আমি যদি ধুলা হতাম।\""],
  "79:1": ["The (angels who) snatch (the souls of the disbelievers) forcibly.","বলপূর্বক (অবিশ্বাসীদের আত্না) ছিনিয়ে নেয়া (ফেরেশতারা)।"],
  "79:2": ["And those who gently take (the souls of the believers) joyfully.","আর আনন্দ সহকারে যারা আলতোভাবে (বিশ্বাসীদের আত্মা) নেয় তারা।"],
  "79:3": ["And those floating everywhere.","আর যারা ভেসে বেড়ায় সব জায়গায়।"],
  "79:4": ["Eagerly racing with one another—","আগ্রহভরে একে অন্যের সাথে পাল্লা দিয়ে-"],
  "79:5": ["to carry out various commands.","বিভিন্ন আদেশ সম্পন্ন করতে।"],
  "79:6": ["The day the quake quakes.","সে দিন যখন কম্পন নাড়া দেয়।"],
  "79:7": ["Followed by the second blow.","দ্বিতীয় বিকট শব্দের পর।"],
  "79:8": ["Certain minds will be terrified.","নির্দিষ্ট কিছু মন আতংকিত হবে।"],
  "79:9": ["Their eyes will be subdued.","তাদের চোখগুলো বশীভূত হবে।"],
  "79:10": ["They will say, \"We have been recreated from the grave!","তারা বলবে, \"আমরা কবর থেকে পুনরায় সৃষ্টি হয়েছি।\""],
  "79:11": ["\"How did this happen after we had turned into rotten bones?\"","\"আমরা পঁচা হাড়ে পরিণত হবার পর কিভাবে এটা ঘটলো?\""],
  "79:12": ["They had said, \"This is an impossible recurrence.\"","তারা বলেছিল, \"এটা এক অসম্ভব পুনরাবৃত্তি।\""],
  "79:13": ["All it takes is one nudge.","কেবল একটি ডাকই যথেষ্ট।"],
  "79:14": ["Whereupon they get up.","যার ফলে তারা জেগে উঠে।"],
  "79:15": ["Have you known about the history of Moses?","তুমি কি মুসার কাহিনী জেনেছো?"],
  "79:16": ["His Lord called him at the holy valley of Tuwaa.","তার প্রভু তাকে তুয়ার পবিত্র উপত্যকায় ডেকেছিলেন।"],
  "79:17": ["\"Go to Pharaoh; he has transgressed.\"","“ফেরাউনের কাছে যাও; সে সীমালঙ্ঘন করেছে।\""],
  "79:18": ["Tell him, \"Would you not reform?","তাকে বল, \"তুমি কি সংশোধিত হবে না? \""],
  "79:19": ["\"Let me guide you to your Lord, that you may turn reverent.\"","“চল আমি তোমাকে তোমার প্রভুর পথ দেখাই, যাতে তুমি ভক্তিপূর্ন হতে পারো।"],
  "79:20": ["He then showed him the great miracle.","তারপর সে তাকে মহা অলৌকিকতাটি দেখালো।"],
  "79:21": ["But he disbelieved and rebelled.","কিন্তু সে অবিশ্বাস করলো এবং বিদ্রোহ করলো।"],
  "79:22": ["Then he turned away in a hurry.","তারপর সে দ্রুত মুখ ফিরিয়ে নিল।"],
  "79:23": ["He summoned and proclaimed.","সে তলব করলো এবং ঘোষণা করলো।"],
  "79:24": ["He said, \"I am your Lord; most high.\"","সে বলল, \"আমি তোমাদের প্রভু; সবচেয়ে উর্ধ্বে।\""],
  "79:25": ["Consequently, Allah committed him to the retribution in the Hereafter, as well as in the first life.","পরিনামে,আল্লাহ তাকে শাস্তি দিলেন পরকালে, সেই সাথে প্রথম জীবনেও।"],
  "79:26": ["This is a lesson for the reverent.","এটি ভক্তদের জন্য একটি শিক্ষা।"],
  "79:27": ["Are you more difficult to create than the heaven? He constructed it.","আকাশমন্ডলীর চেয়ে তোমাদের সৃষ্টি কি বেশি কঠিন? তিনি এটি নির্মাণ করেছেন।"],
  "79:28": ["He raised its masses, and perfected it.","তিনি এর বস্তুগুলো উঠালেন এবং একে নিঁখুত করলেন।"],
  "79:29": ["He made its night dark, and brightened its morn.","তিনি এর রাতকে বানালেন অন্ধকার এবং এর সকালকে করেছেন আলোকিত।"],
  "79:30": ["He made the earth egg-shaped.","তিনি পৃথিবীকে বানিয়েছে ডিম্বাকৃতির।"],
  "79:31": ["From it, He produced its own water and pasture.","এর থেকে, তিনি উৎপন্ন করলেন এর নিজস্ব পানি এবং চারনভূমি।"],
  "79:32": ["He established the mountains.","তিনি পর্বতসমূহ প্রতিষ্ঠিত করলেন।"],
  "79:33": ["All this to provide life support for you and your animals.","এই সবকিছু তোমাদের এবং তোমাদের প্রাণীগুলোকে জীবনোপকরন প্রদান করতে।"],
  "79:34": ["Then, when the great blow comes.","তারপর, যখন বিকট শব্দ আসে।"],
  "79:35": ["That is the day when the human will remember everything he did.","এটি সেই দিন যখন মানুষের মনে পড়বে সবকিছু যা সে করেছিল।"],
  "79:36": ["Hell will be brought into existence.","অস্তিত্বে আনা হবে স্বর্গ ।"],
  "79:37": ["As for the one who transgressed.","আর তার ক্ষেত্রে যে সীমালঙ্ঘন করেছিল।"],
  "79:38": ["Who was preoccupied with this life.","যে আচ্ছন্ন ছিল এই জীবনে নিয়ে।"],
  "79:39": ["Hell will be the abode.","নরকই হবে আবাস।"],
  "79:40": ["As for the one who reverenced the majesty of his Lord, and enjoined the self from sinful lusts.","আর তার ক্ষেত্রে  যে তার প্রভুর মহিমাকে ভক্তি করেছিল, এবং পাপপূর্ণ লালসা থেকে নিজেকে বিরত রেখেছিল।"],
  "79:41": ["Paradise will be the abode.","স্বর্গই হবে আবাস।"],
  "79:42": ["They ask you about the Hour, and when it will take place!","তারা তোমাকে জিজ্ঞেস করে সে ঘন্টা  সম্পর্কে, আর কখন তা সংঘটিত হবে!"],
  "79:43": ["It is not you (Muhammad) who is destined to announce its time.","এর সময় ঘোষণা করার জন্য পূর্বনির্ধারিত ব্যক্তি তুমি নও (মুহাম্মাদ)।"],
  "79:44": ["Your Lord decides its fate.","এর নিয়তি ঠিক করেন তোমার প্রভু। যাও এর প্রত্যাশা করো।"],
  "79:45": ["Your mission is to warn those who expect it.","তোমার দায়িত্ব তাদেরকে সতর্ক করা যারা এর আশা করে।"],
  "79:46": ["The day they see it, they will feel as if they lasted one evening or half a day.","যেদিন তারা তা দেখবে, তারা অনুভব করবে যেন তারা টিকে ছিল এক সন্ধ্যা বা অর্ধেক দিন।"],
  "80:1": ["He (Muhammad) frowned and turned away.","সে (মুহাম্মদ) ভ্রু কুঁচকে মুখ ফিরিয়ে নিয়েছিল।"],
  "80:2": ["When the blind man came to him.","যখন অন্ধ লোকটি তার কাছে এসেছিল।"],
  "80:3": ["How do you know? He may purify himself.","কেমন করে তুমি জানো? হয়তো সে নিজেকে পরিশুদ্ধ করবে।"],
  "80:4": ["Or he may take heed, and benefit from the message.","অথবা হয়তো সে সতর্ক হবে, আর বার্তাটি থেকে উপকৃত হবে।"],
  "80:5": ["As for the rich man.","এবং ধনী লোকটির ক্ষেত্রে ।"],
  "80:6": ["You gave him your attention.","তুমি তোমার মনোযোগ তার প্রতি দিয়েছিলে।"],
  "80:7": ["Even though you could not guarantee his salvation.","যদিও তুমি তার মুক্তির নিশ্চয়তা দিতে পারতে না।"],
  "80:8": ["The one who came to you eagerly.","সে ব্যক্তি যে তোমার কাছে এসেছিল আগ্রহ নিয়ে।"],
  "80:9": ["And is really reverent.","এবং আসলেই ভক্তিপূর্ণ।"],
  "80:10": ["You ignored him.","তুমি তাকে উপেক্ষা করেছিলে।"],
  "80:11": ["Indeed, this is a reminder.","নিশ্চয়, এটি একটি স্মারক।"],
  "80:12": ["Whoever wills shall take heed.","যেকেউ চায় মনোযোগ দিবে।"],
  "80:13": ["In honorable scriptures.","সম্মানিত ঐশীগ্রন্থগুলোতে৷"],
  "80:14": ["Exalted and pure.","প্রশংসিত এবং নিখাদ৷"],
  "80:15": ["(Written) by the hands of messengers.","বার্তাবাহকদের হাতে (লিখিত)।"],
  "80:16": ["Who are honorable and righteous.","যারা সম্মানিত এবং সৎকর্মশীল।"],
  "80:17": ["Woe to the human being; he is so unappreciative!","দুর্ভোগ মানুষ জাতির প্রতি ; সে খুব অকৃতজ্ঞ৷"],
  "80:18": ["What did He create him from?","কি থেকে তাকে তিনি সৃষ্টি করেছিলেন ?"],
  "80:19": ["From a tiny drop, He creates him and designs him.","অতিক্ষুদ্র ফোঁটা থেকে, তিনি তাকে সৃষ্টি করেন আর তার নকশা করেন।"],
  "80:20": ["Then He points out the path for him.","এরপর তিনি তার জন্য সে পথটির দিকে অঙ্গুলিনির্দেশ করেন।"],
  "80:21": ["Then He puts him to death, and into the grave.","এরপর তিনি তাকে দেন মৃত্যু, এবং রাখেন কবরে।"],
  "80:22": ["When He wills, He resurrects him.","যখন তিনি চান, তিনি তাকে পুনরুজ্জীবিত করেন।"],
  "80:23": ["He shall uphold His commandments.","সে তাঁর প্রত্যাদেশাবলি বহাল রাখবে।"],
  "80:24": ["Let the human consider his food!","মানুষ তার খাদ্য নিয়ে ভেবে দেখুক।"],
  "80:25": ["We pour the water generously.","আমরা পানি বর্ষণ করি উদারভাবে।"],
  "80:26": ["Then we split the soil open.","এরপর আমরা মাটি চিরে পথ করে দেই।"],
  "80:27": ["We grow in it grains.","তাতে আমরা উৎপন্ন করি খাদ্যশস্য।"],
  "80:28": ["Grapes and pasture.","আঙ্গুর এবং চারণভূমি।"],
  "80:29": ["Olives and palms.","জলপাই এবং তাল।"],
  "80:30": ["A variety of orchards.","নানারকম ফলের বাগান।"],
  "80:31": ["Fruits and vegetables.","ফল-ফলাদি এবং শাকসবজি।"],
  "80:32": ["To provide life support for you and your animals.","তোমাদের আর তোমাদের প্রাণীদের জন্য জীবনোপকরণ প্রদান করতে।"],
  "80:33": ["Then, when the blow comes to pass.","তারপর, যখন আঘাতটি আসবে।"],
  "80:34": ["That is the day when one flees from his brother.","এটাই সে দিন যখন কোন ব্যক্তি পালিয়ে যায় তার ভাইকে ছেড়ে।"],
  "80:35": ["From his mother and father.","তার মা ও বাবাকে ছেড়ে।"],
  "80:36": ["From his spouse and children.","তার সহধর্মী-সহর্মিনী ও সন্তানাদিকে ছেড়ে।"],
  "80:37": ["Each one of them, on that day, worries about his own destiny.","তাদের প্রত্যেকে, ঐদিন, তার নিজের নিয়তি নিয়ে দুশ্চিন্তা করবে।"],
  "80:38": ["Some faces on that day will be happy.","ঐদিন কিছু চেহারা হবে সুখী।"],
  "80:39": ["Laughing and joyful.","হাস্যজ্জল এবং আনন্দিত।"],
  "80:40": ["Other faces, on that day, will be covered with misery.","অন্য চেহারাগুলো, ঐদিন, দু:খে ছেয়ে যাবে।"],
  "80:41": ["Overwhelmed by remorse.","অনুশোচনায় কাতর।"],
  "80:42": ["These are the wicked disbelievers.","এরাই অন্যায়কারী অবিশ্বাসী।"],
  "81:1": ["When the sun is rolled.","যখন সূর্যকে আবর্তন করা হয়।"],
  "81:2": ["The stars are crashed into each other.","তারাগুলো একে অন্যের উপর আছড়ে পড়ে।"],
  "81:3": ["The mountains are wiped out.","পর্বতসমূহ নিশ্চিহ্ন হয়।"],
  "81:4": ["The reproduction is halted.","প্রজনন বন্ধ করা হয়।"],
  "81:5": ["The beasts are summoned.","জানোয়ারদের তলব করা হয়।"],
  "81:6": ["The oceans are set aflame.","মহাসমুদ্রগুলোতে প্রজ্বলিত হয়।"],
  "81:7": ["The souls are restored to their bodies.","আত্মাগুলোকে তাদের দেহে ফিরিয়ে আনা হয়।"],
  "81:8": ["The girl who was buried alive is asked:","যে মেয়েটিকে জীবন্ত কবর দেয়া হয়েছিল তাকে জিজ্ঞেস করা হয়:"],
  "81:9": ["For what crime was she killed?","কোন অপরাধের জন্য তাকে হত্যা করা হয়েছিল?"],
  "81:10": ["The records are made known.","নথিগুলো জানিয়ে দেয়া হবে।"],
  "81:11": ["The heaven is removed.","আকাশমন্ডলী সরিয়ে ফেলা হবে।"],
  "81:12": ["Hell is ignited.","নরক প্রজ্বলিত হবে।"],
  "81:13": ["Paradise is presented.","স্বর্গ উপস্থাপিত হবে।"],
  "81:14": ["Every soul will know everything it brought.","প্রত্যেক আত্মা সবকিছু জানবে যা এটি নিয়ে এসেছে।"],
  "81:15": ["I solemnly swear by the galaxies.","আমি দৃঢ় শপথ করি ছায়াপথগুলোর নামে।"],
  "81:16": ["Precisely running in their orbits.","তাদের কক্ষপথে চলছে নির্ভুলভাবে।"],
  "81:17": ["By the night as it falls.","রাতের নামে যখন তা ঘনিয়ে আসে।"],
  "81:18": ["And the morn as it breathes.","আর সকাল যখন তা দম নেয়।"],
  "81:19": ["This is the utterance of an honorable messenger.","এটি একজন সম্মানিত বার্তাবাহকের উক্তি।"],
  "81:20": ["Authorized by the Possessor of the Throne, fully supported.","সিংহাসনের অধিকারী  দ্বারা অনুমোদিত, পূর্ণ সমর্থিত।"],
  "81:21": ["He shall be obeyed and trusted.","তাকে মান্য করতে হবে এবং আস্থা রাখতে হবে।"],
  "81:22": ["Your friend (Rashad) is not crazy.","তোমাদের বন্ধু (রাশাদ) পাগল নয়।"],
  "81:23": ["He saw him at the high horizon.","তিনি তাকে উঁচু দিগন্তে দেখেছিলেন।"],
  "81:24": ["He is not holding back any news.","সে কোন খবর গোপন রাখছে না ।"],
  "81:25": ["It is not the talk of a rejected devil.","এটি কোন বিতাড়িত শয়তানের কথা নয়।"],
  "81:26": ["Now then, where will you go?","তা এখন, তোমরা যাবে কোথায়?"],
  "81:27": ["This is a message to all the people.","এটি সব মানুষের জন্য একটি বার্তা।"],
  "81:28": ["For those who wish to go straight.","তাদের জন্য যারা সোজা চলতে চায়।"],
  "81:29": ["Whatever you will is in accordance with the will of Allah, Lord of the universe.","যা কিছুই তোমরা ইচ্ছা করো তা আল্লাহর ইচ্ছার অধীনে হয়, মহাবিশ্বের প্রভু ।"],
  "82:1": ["When the heaven is shattered.","যখন আকাশমন্ডলী চূর্ণ-বিচূর্ণ করা হয়।"],
  "82:2": ["The planets are scattered.","গ্রহগুলোকে ইতস্তত ছড়িয়ে দেয়া হয়।"],
  "82:3": ["The oceans are exploded.","মহাসাগরগুলো বিস্ফোরিত  হয় ।"],
  "82:4": ["The graves are opened.","কবর খুলে দেয়া হয় ।"],
  "82:5": ["Every soul will find out what caused it to advance, and what caused it to regress.","প্রত্যেকটি আত্মা দেখতে পাবে কি তাকে অগ্রগামী করেছে,আর কি তাকে পশ্চাৎপদ করেছে।"],
  "82:6": ["O you human being, what diverted you from your Lord, Most Honorable?","হে মানব জাতি,কি তোমাদেরকে সরিয়ে দিয়েছিল তোমাদের প্রভু থেকে, যিনি সবচেয়ে সম্মানিত?"],
  "82:7": ["The One who created you, designed you, and perfected you.","সে সত্ত্বা যিনি তোমাদের সৃষ্টি করেছেন, তোমাদের নকশা করেছেন, এবং তোমাদের নিঁখুত করেছেন৷"],
  "82:8": ["In whatever design He chose, He constructed it.","যে নকশাই তিনি পছন্দ করেছিলেন, তা তিনি নির্মাণ করেছেন।"],
  "82:9": ["Indeed, you disbelieve in the religion.","নিশ্চয়, তোমরা ধর্মে অবিশ্বাস করো।"],
  "82:10": ["Oblivious to the fact that there are (invisible) keepers around you.","এই বাস্তবতায় বেখবর যে তোমাদের চারপাশে (অদৃশ্য) রক্ষক আছে ।"],
  "82:11": ["They are honest recorders.","তারা সত্যনিষ্ঠ নথিভুক্তকারি।"],
  "82:12": ["They record everything you do.","তারা তোমাদের করা সবকিছু নথিভুক্ত করে।"],
  "82:13": ["Surely, the pious have deserved bliss.","নিশ্চয়, সৎকর্মশীলরা পরম সুখ অর্জন করেছে।"],
  "82:14": ["While the wicked have deserved Hell.","যেখানে অন্যায়কারীরা উপযুক্ত হয়েছে নরকের৷"],
  "82:15": ["Will incur it on the Day of Judgment.","তাতে পতিত হবে বিচার দিবসে৷"],
  "82:16": ["They never leave it.","তারা কখনো তা ছেড়ে যায় না।"],
  "82:17": ["Awesome is the Day of Judgment.","বিচারের দিন হলো অন্যরকম।"],
  "82:18": ["What a day; the Day of Judgment!","কি এক অসাধারণ দিন ; বিচারের দিন৷"],
  "82:19": ["That is the day when no soul can help another soul, and all decisions, on that day, will belong to Allah.","এটা সেই দিন যখন কোন আত্মা অন্য আত্মাকে সাহায্য করতে পারে না, এবং সকল সিদ্ধান্ত, ঐদিন, আল্লাহর অধীনে হবে।"],
  "83:1": ["Woe to the cheaters.","দূর্ভোগ প্রতারকদের প্রতি।"],
  "83:2": ["Who demand full measure when receiving from the people.","যারা লোকদের থেকে নেবার বেলায় পূর্ণমাত্রায় চায়।"],
  "83:3": ["But when giving them the measures or weights, they cheat.","কিন্তু সে পরিমান বা ওজন তাদেরকে দেবার বেলায়, তারা প্রতারণা করে।"],
  "83:4": ["Do they not know that they will be resurrected?","তারা কি জানে না যে তাদের পুনর্জীবিত করা হবে?"],
  "83:5": ["On a tremendous day?","এক মহাতাৎপর্যপূর্ণ দিনে?"],
  "83:6": ["That is the day when all people will stand before the Lord of the universe.","এটা সেই দিন যখন সব মানুষ মহাবিশ্বের প্রভুর সামনে দাঁড়াবে।"],
  "83:7": ["Indeed, the book of the wicked is in Sijjeen.","নিশ্চয়, অন্যায়কারী লোকের বইটি রয়েছে সীজ্জিনে।"],
  "83:8": ["Do you know what Sijjeen is?","তুমি কি জানো সীজ্জিন কী?"],
  "83:9": ["A numerically structured book.","সংখ্যা দ্বারা কাঠামোবদ্ধ একটি বই।"],
  "83:10": ["Woe on that day to the rejectors.","ঐদিন দূর্ভোগ প্রত্যাখ্যানকারীদের প্রতি।"],
  "83:11": ["They do not believe in the Day of Judgment.","তারা বিচারের দিনে বিশ্বাস করে না।"],
  "83:12": ["None disbelieves therein except the transgressor, the sinful.","তাতে কেউ অবিশ্বাস করে না সীমালঙ্ঘনকারী, পাপী ব্যতীত।"],
  "83:13": ["When our revelations are recited to him, he says, \"Tales from the past!\"","যখন আমাদের প্রকাশনাবলী তার কাছে আবৃত্তি করা হয়, সে বলে, \"অতীতের কল্প-কাহিনী!\""],
  "83:14": ["Indeed, their hearts have become shielded by their sins.","নিশ্চয়, তাদের পাপের দ্বারা তাদের হৃদয়ে আবরণ পড়েছে।"],
  "83:15": ["Indeed, they will be isolated, on that day, from their Lord.","নিশ্চয়, তারা আলাদা হবে, ঐদিন, তাদের প্রভুর কাছ থেকে।"],
  "83:16": ["Then they will be thrown into Hell.","তারপর তাদের নিক্ষেপ করা হবে নরকে।"],
  "83:17": ["They will be told, \"This is what you used to deny.\"","তাদের বলা হবে, \"এটা তা-ই, যা তোমরা অস্বীকার করতে।\""],
  "83:18": ["Indeed, the book of the righteous will be in 'Elleyyeen.","নিশ্চয়, সৎকর্মশীলদের বইটি থাকবে 'ইল্লীয়িন-এ।"],
  "83:19": ["Do you know what 'Elleyyeen is?","তুমি কি জানো 'ইল্লীয়িন কি?"],
  "83:20": ["A numerically structured book.","সংখ্যা দ্বারা কাঠামোবদ্ধ একটি বই।"],
  "83:21": ["To be witnessed by those close to Me.","তাদের দ্বারা প্রত্যক্ষযোগ্য যারা আমার নিকটবর্তী।"],
  "83:22": ["The righteous have deserved bliss.","সৎকর্মশীলরা পরমসুখ অর্জন করেছে।"],
  "83:23": ["On luxurious furnishings they watch.","বিলাসবহুল আসবাবপত্রের উপরে তারা পর্যবেক্ষণ করে।"],
  "83:24": ["You recognize in their faces the joy of bliss.","তুমি তাদের চেহারায় পরমসুখের আবেশ চিনতে পারবে।"],
  "83:25": ["Their drinks will be spiced with nectar.","তাদের পানীয়গুলো সুস্বাদু করা হবে প্রবিত্র মিশ্রণে।"],
  "83:26": ["Its spice is like musk. This is what the competitors should compete for.","এর শেষ অংশ কস্ত্তরির মত। এটা তা-ই যার জন্য প্রতিযোগীদের প্রতিযোগিতা করা উচিত।"],
  "83:27": ["Mixed into it will be special flavors.","এতে বিশেষ স্বাদসমূহ মিশ্রিত থাকবে ।"],
  "83:28": ["From a spring that is reserved for those close to Me.","একটি ঝর্ণা থেকে যা সংরক্ষিত তাদের জন্য যারা আমার নিকটে।"],
  "83:29": ["The wicked used to laugh at those who believed.","অন্যায়কারীরা তাদের নিয়ে হাসতো যারা বিশ্বাস করেছিল ।"],
  "83:30": ["When they passed by them, they used to poke fun.","যখন তারা তাদের পাশ দিয়ে যেতো, তারা ব্যঙ্গ-বিদ্রূপ করতো।"],
  "83:31": ["When they got together with their people, they used to joke.","যখন তারা তাদের লোকদের সাথে একত্রিত হতো,তারা ঠাট্টা করতো।"],
  "83:32": ["Whenever they saw them, they said, \"These people are far astray!","যখনই তারা তাদের দেখতো, তারা বলতো, \"এই লোকেরা বহুদূর পথভ্রষ্ট!\""],
  "83:33": ["\"They have no such thing as (invisible) guards.\"","\"(অদৃশ্য) প্রহরীর মত এমন কিছু তাদের নেই।\""],
  "83:34": ["Today, those who believed are laughing at the disbelievers.","আজ, যারা বিশ্বাস করেছিল তারা অবিশ্বাসীদের প্রতি হাসছে।"],
  "83:35": ["On luxurious furnishings they watch.","বিলাসবহুল আসবাবপত্রের উপর থেকে তারা পর্যবেক্ষণ করে।"],
  "83:36": ["Most assuredly, the disbelievers are requited for what they did.","সন্দেহাতীতভাবে, অবিশ্বাসীরা যা করেছিল তার জন্য তাদের থেকে প্রতিশোধ গ্রহন করা হবে।"],
  "84:1": ["The time will come when the sky is ruptured.","সময় আসবে যখন আকাশে ফাটল ধরবে।"],
  "84:2": ["It will submit to its Lord and expire.","এটি এর প্রভুর নিকট আত্মসমর্পণ করবে এবং বিলপ্ত হবে।"],
  "84:3": ["The earth will be leveled.","পৃথিবীকে সমতল করা হবে।"],
  "84:4": ["It will eject its contents, as it erupts.","এটি এর অভ্যন্তরস্থ-বস্তু নির্গত করবে,  যখন তা বিস্ফোরিত হবে।"],
  "84:5": ["It will submit to its Lord and expire.","এটি এর প্রভুর নিকট আত্মসমর্পণ করবে এবং বিলপ্ত হবে।"],
  "84:6": ["O humans, you are irreversibly heading for a meeting with your Lord.","হে মানুষ, তোমরা অপ্রত্যাবর্তনীয়ভাবে এগিয়ে যাচ্ছো তোমাদের প্রভুর সাথে সাক্ষাতের জন্য।"],
  "84:7": ["As for the one who receives his record in his right hand,","সে ব্যক্তির ক্ষেত্রে যে তার ডান হাতে নিজের কর্মফল গ্রহণ করে,"],
  "84:8": ["His reckoning will be easy.","তার হিসাব-নিকাশ হবে সহজ।"],
  "84:9": ["He will return to his people joyfully.","সে তার লোকদের কাছে আনন্দ নিয়ে ফিরে যাবে।"],
  "84:10": ["As for the one who receives his record behind his back,","সে ব্যক্তির ক্ষেত্রে যে তার বাম হাতে নিজের কর্মফল গ্রহণ করে,"],
  "84:11": ["He will be ridden with remorse.","সে হবে অনুশোচনায় কাতর।"],
  "84:12": ["And will burn in Hell.","এবং নরকে পুড়বে।"],
  "84:13": ["He used to act arrogantly among his people.","সে তার লোকদের সাথে ঔদ্ধত্যপূর্ণ আচরণ করতো।"],
  "84:14": ["He thought that he will never be called to account.","সে ভেবেছিল, তাকে কখনো হিসাব দিতে ডাকা হবে না।"],
  "84:15": ["Yes indeed, his Lord was Seer of him.","হ্যাঁ নিশ্চয়, তার প্রভু তার দ্রষ্টা ছিলেন।"],
  "84:16": ["I solemnly swear by the rosy dusk.","আমি শপথ করি গোলাপিবর্ণ গোধূলির নামে।"],
  "84:17": ["And the night as it spreads.","এবং রাত যখন তা ছড়িয়ে পড়ে।"],
  "84:18": ["And the moon and its phases.","এবং চাঁদ ও এর বিভিন্ন দশার নামে।"],
  "84:19": ["You will move from stage to stage.","তোমাদের নেয়া হবে এক ধাপ থেকে আরেক ধাপে।"],
  "84:20": ["Why do they not believe?","কেন তারা বিশ্বাস করে না?"],
  "84:21": ["And when the Quran is recited to them, they do not fall prostrate.","এবং যখন তাদের কাছে কোর'আন আবৃত্তি করা হয়, তারা সেজদায় পড়ে না।"],
  "84:22": ["This is because those who disbelieved are rejecting (the Quran).","এর কারণ যারা অবিশ্বাস করেছিল তারা প্রত্যাখ্যান করছে (কোর'আন)।"],
  "84:23": ["Allah is fully aware of their innermost thoughts.","আল্লাহ তাদের গভীরতম চিন্তাগুলো সম্পর্কে পুরোপুরি অবগত।"],
  "84:24": ["Promise them painful retribution.","তাদেরকে যন্ত্রণাদায়ক শাস্তির প্রতিশ্রুতি দাও।"],
  "84:25": ["As for those who believed and led a righteous life, they receive a recompense that is well deserved.","আর যারা বিশ্বাস করেছিল এবং সৎ জীবন-যাপন করেছিল, তারা এমন এক প্রতিদান পায় যা যথা উপযুক্ত।"],
  "85:1": ["The sky and its galaxies.","আকাশ এবং এর ছায়াপথগুলো।"],
  "85:2": ["The promised day.","সেই প্রতিশ্রুত দিন।"],
  "85:3": ["The witness and the witnessed.","সেই প্রত্যক্ষদর্শী এবং প্রত্যক্ষ বিষয়।"],
  "85:4": ["Woe to the people of the canyon.","দূর্ভোগ গিরিখাতের সে লোকদের প্রতি।"],
  "85:5": ["They ignited a blazing fire.","তারা একটি অগ্নীকুন্ডলী জ্বালিয়েছিল।"],
  "85:6": ["Then sat around it.","তারপর এর পাশে বসলো৷"],
  "85:7": ["To watch the burning of the believers.","যাতে বিশ্বাসীদের অগ্নিদগ্ধ হতে দেখা যায়।"],
  "85:8": ["They hated them for no other reason than believing in Allah, the Almighty, the Praiseworthy.","তারা তাদের ঘৃণা করেছিল শুধুমাত্র সর্বশক্তিমান, প্রশংসনীয় ঈশ্বরকে বিশ্বাস করার কারনেই।"],
  "85:9": ["To Him belongs the kingship of the heavens and the earth. And Allah witnesses all things.","আসমান ও পৃথিবীর রাজত্ব তাঁরই। এবং ঈশ্বর সকল কিছুর সাক্ষী।"],
  "85:10": ["Surely, those who persecute the believing men and women, then fail to repent, have incurred the retribution of Gehenna; they have incurred the retribution of burning.","নিশ্চয়, যারা বিশ্বাসী পুরুষ ও নারীদের কষ্ট দেয়, এরপর অনুশোচনা করতে ব্যর্থ হয়, তারা টেনে এনেছে জাহান্নামের শাস্তি; তারা টেনে এনেছে দগ্ধ হবার শাস্তি।"],
  "85:11": ["Surely, those who believed and led a righteous life, have deserved gardens with flowing streams. This is the greatest triumph.","নিশ্চয়, যারা বিশ্বাস করেছিল এবং সৎ জীবন-যাপন করেছিল, তারা প্রবাহিত ঝর্নাসহ বাগানের উপযুক্ত হয়েছে। এটাই শ্রেষ্ঠ বিজয়।"],
  "85:12": ["Indeed, your Lord's blow is severe.","নিশ্চয়, তোমাদের প্রভুর আঘাত কঠোর।"],
  "85:13": ["He is the One who initiates and repeats.","তিনিই সে সত্ত্বা যিনি সূচনা করেন এবং পুনরাবৃত্তি করেন।"],
  "85:14": ["And He is the Forgiving, Most Kind.","আর তিনিই ক্ষমাকারী, সবচেয়ে দয়ালু।"],
  "85:15": ["Possessor of the glorious throne.","মহিমান্বিত সিংহাসনের মালিক।"],
  "85:16": ["Doer of whatever He wills.","তিনি করেন, যাকিছু তিনি চান।"],
  "85:17": ["Did you note the history of the troops?","তুমি কি সেনাদলগুলোর ইতিহাস লক্ষ্য করেছো?"],
  "85:18": ["Pharaoh and Thamûd?","ফেরাউন এবং সামুদের?"],
  "85:19": ["Those who disbelieve are plagued with denial.","যারা অবিশ্বাস করে তারা প্রত্যাখ্যানের মহামারী রোগে আক্রান্ত ।"],
  "85:20": ["Allah is fully aware of them.","আল্লাহ তাদের বিষয়ে পুরোপুরি সচেতন।"],
  "85:21": ["Indeed, it is a glorious Quran.","নিশ্চয়, এটি গৌরবময় কোর'আন।"],
  "85:22": ["In a preserved master tablet.","আছে একটি সংরক্ষিত মূল ফলকে।"],
  "86:1": ["By the sky and Al-Taareq.","আকাশ এবং আল-তারেকের নামে শপথ।"],
  "86:2": ["Do you know what Al-Taareq is?","তুমি কি জানো আল-তারেক কি?"],
  "86:3": ["The bright star.","এক উজ্জ্বল তারা।"],
  "86:4": ["Absolutely, everyone is well guarded.","নি:সন্দেহে, সবাই সুরক্ষিত।"],
  "86:5": ["Let the human reflect on his creation.","মানুষ তার সৃষ্টি নিয়ে ভেবে দেখুক।"],
  "86:6": ["He was created from ejected liquid.","তাকে সৃষ্টি করা হয়েছে নির্গত তরল থেকে।"],
  "86:7": ["From between the spine and the viscera.","মেরুদণ্ড এবং ভেতরের অঙ্গের মধ্য থেকে।"],
  "86:8": ["He is certainly able to resurrect him.","তিনি নি:সন্দেহে তাকে পুনরুজ্জীবিত করতে সক্ষম।"],
  "86:9": ["The day all secrets become known.","সে দিন যখন সকল গোপনীয়তা জানাজানি হয়ে যাবে।"],
  "86:10": ["He will have no power, nor a helper.","তার কোন ক্ষমতা থাকবে না, না কোন সাহায্যকারী।"],
  "86:11": ["By the sky that returns (the water).","আকাশের নামে যা বর্ষণ করে (পানি)।"],
  "86:12": ["By the earth that cracks (to grow plants).","পৃথিবীর নামে যা বিদীর্ণ হয় (উদ্ভিদ উৎপন্ন করতে)।"],
  "86:13": ["This is a serious narration.","এটি একটি গুরুত্বপূর্ণ বিবরণ।"],
  "86:14": ["Not to be taken lightly.","হালকাভাবে নেয়ার মত নয়।"],
  "86:15": ["They plot and scheme.","তারা গোপন পরিকল্পনা করে।"],
  "86:16": ["But so do I.","তবে, আমি তা-ই করি।"],
  "86:17": ["Just respite the disbelievers a short respite.","অবিশ্বাসীদের কেবল অবকাশ দাও এক সংক্ষিপ্ত অবকাশ।"],
  "87:1": ["Glorify the name of your Lord, the Most High.","তোমার প্রভুর নামের মহিমা প্রকাশ করো, যিনি সুউচ্চ।"],
  "87:2": ["He creates and shapes.","তিনি সৃষ্টি করেন এবং আকার দেন।"],
  "87:3": ["He designs and guides.","তিনি নকশা করেন এবং পথ দেখান৷"],
  "87:4": ["He produces the pasture.","তিনি উৎপন্ন করেন চারণভূমির ঘাস।"],
  "87:5": ["Then turns it into light hay.","এরপর একে পরিনত করেন হালকা খড়ে।"],
  "87:6": ["We will recite to you; do not forget.","আমরা তোমার কাছে আবৃতি করবো ; ভূলে যেও না।"],
  "87:7": ["Everything is in accordance with Allah's will; He knows what is declared, and what is hidden.","আল্লাহর ইচ্ছানুসারে সবকিছু হয় ; তিনি জানেন যা ঘোষণা করা হয় এবং যা গোপন করা হয়।"],
  "87:8": ["We will direct you to the easiest path.","আমরা তোমাকে সহজতম পথের দিকে পরিচালনা করবো।"],
  "87:9": ["Therefore, you shall remind; perhaps the reminder will benefit.","অতঃএব, তুমি স্মরণ করিয়ে দেবে; সম্ভবত স্মরণ করিয়ে দিলে উপকার হবে৷"],
  "87:10": ["The reverent will take heed.","ভক্তিকারী মনোযোগ দিবে।"],
  "87:11": ["The wicked will avoid it.","দুর্বৃত্ত তা এড়িয়ে যাবে।"],
  "87:12": ["Consequently, he will suffer the great Hellfire.","পরিনামে সে বিশাল নরকাগ্নি ভোগ করবে।"],
  "87:13": ["Wherein he never dies, nor stays alive.","যেখানে সে কখনো মারা যায় না, না জীবিত থাকে।"],
  "87:14": ["Successful indeed is the one who redeems his soul.","নিশ্চয় সে ব্যক্তি সফল যে তার আত্মাকে উদ্ধার করে।"],
  "87:15": ["By remembering the name of his Lord, and observing the contact prayers (Salat).","তার প্রভুর নাম স্মরণের মাধ্যমে, এবং সংযোগ প্রার্থনা (সালাত) পালনের মাধ্যমে।"],
  "87:16": ["Indeed, you are preoccupied with this first life.","নিশ্চয়, তোমরা এই প্রথম জীবন নিয়ে মোহে আছো।"],
  "87:17": ["Even though the Hereafter is far better and everlasting.","যদিও পরকাল অনেক উত্তম এবং চিরস্থায়ী।"],
  "87:18": ["This is recorded in the earlier teachings.","এটা পূর্বেকার শিক্ষাগুলোতে নথিভুক্ত আছে৷"],
  "87:19": ["The teachings of Abraham and Moses.","ইব্রাহিম এবং মূসার শিক্ষাগুলো ।"],
  "88:1": ["Are you aware of the Overwhelming?","তুমি কি সে অভিভূতকারীর বিষয়ে সচেতন।"],
  "88:2": ["Faces on that day will be shamed.","ঐদিন চেহারাগুলো হবে লজ্জিত।"],
  "88:3": ["Laboring and exhausted.","পরিশ্রমরত এবং ক্লান্ত৷"],
  "88:4": ["Suffering in a blazing Hellfire.","জ্বলন্ত নরকাগ্নিতে দূর্দশাগ্রস্থ।"],
  "88:5": ["Drinking from a flaming spring.","অগ্নিকুন্ডলি পাকানো ঝর্না থেকে পানরত।"],
  "88:6": ["They will have no food except the useless variety.","তাদের কোন খাদ্য থাকবে না, অব্যবহার্য ধরণ ব্যতীত।"],
  "88:7": ["It never nourishes, nor satisfies hunger.","এটি কখনো পরিপুষ্ট করে না, না ক্ষুধা নিবারণ করে৷"],
  "88:8": ["Other faces on that day will be full of joy.","ঐদিন অন্য চেহারাসমূহ আনন্দে পূর্ণ থাকবে।"],
  "88:9": ["Satisfied with their work.","তাদের কাজে সন্তুষ্ট।"],
  "88:10": ["In an exalted Paradise.","প্রশংসিত স্বর্গোদ্যানে।"],
  "88:11": ["In it, no nonsense is heard.","তাতে, কোন অশোভন কথা শুনা যায় না৷"],
  "88:12": ["In it, a spring flows.","তাতে, একটি ঝর্ণা প্রবাহিত হয়৷"],
  "88:13": ["In it, there are luxurious furnishings.","তাতে, বিলাসবহুল আসবাবপত্র আছে।"],
  "88:14": ["And drinks made available.","এবং পানীয়কে সহজলভ্য করা আছে।"],
  "88:15": ["And pitchers in rows.","এবং সারি সারি কলস।"],
  "88:16": ["And carpets throughout.","এবং আদ্যোপান্ত কার্পেট।"],
  "88:17": ["Why do they not reflect on the camels and how they are created?","কেন তারা ভেবে দেখে না উটগুলো এবং তাদের সৃষ্টি নিয়ে?"],
  "88:18": ["And the sky and how it is raised.","এবং আকাশ ও এর উত্থান নিয়ে।"],
  "88:19": ["And the mountains and how they are constructed.","এবং পর্বতসমূহ ও এদের গঠন নিয়ে।"],
  "88:20": ["And the earth and how it is built.","এবং পৃথিবী ও এর নির্মাণ নিয়ে।"],
  "88:21": ["You shall remind, for your mission is to deliver this reminder.","তুমি স্মরণ করিয়ে দিবে, কারণ এই স্মারক পৌঁছে দেয়াই তোমার উদ্দেশ্য।"],
  "88:22": ["You have no power over them.","তাদের উপর তোমার কোন ক্ষমতা নেই৷"],
  "88:23": ["As for those who turn away and disbelieve.","আর যারা মুখ ফিরিয়ে নেয় এবং অবিশ্বাস করে।"],
  "88:24": ["Allah will commit them to the great retribution.","আল্লাহ তাদেরকে পতিত করবেন মহা শাস্তিতে৷"],
  "88:25": ["To us is their ultimate destiny.","আমাদের কাছে তাদের চূড়ান্ত নিয়তি৷"],
  "88:26": ["Then we will call them to account.","এরপর আমরা তাদেরকে হিসাবের জন্য ডাকবো।"],
  "89:1": ["By the dawn.","শপথ ভোরের।"],
  "89:2": ["And the ten nights.","এবং সে দশটি রাত।"],
  "89:3": ["By the even and the odd.","শপথ জোড় এবং বিজোড়ের।"],
  "89:4": ["By the night as it passes.","শপথ রাতের যখন তা অতিবাহিত হয়।"],
  "89:5": ["A profound oath, for one who possesses intelligence.","এক জ্ঞানগর্ভ শপথ, সে ব্যক্তির জন্য যে বুদ্ধিমত্তার অধিকারী।"],
  "89:6": ["Have you noted what your Lord did to 'Ãd?","তুমি কি লক্ষ্য করেছ তোমার প্রভু আদের প্রতি কি করেছিলেন?"],
  "89:7": ["Erum; the town with tall buildings.","ইরাম, উঁচু দালানের শহর।"],
  "89:8": ["There was nothing like it anywhere.","এর মতো কোথাও কিছু ছিল না।"],
  "89:9": ["Also Thamûd, who carved the rocks in their valley.","এছাড়া সামূদ, যারা তাদের উপত্যকায় পাথর খোদাই করতো।"],
  "89:10": ["And Pharaoh who possessed might.","এবং ফেরাউন যার প্রবল ক্ষমতা ছিল।"],
  "89:11": ["They all transgressed in the land.","তারা সবাই জমিনে সীমালঙ্ঘন করেছিল।"],
  "89:12": ["They spread evil throughout.","তারা সবখানে মন্দ ছড়ায়৷"],
  "89:13": ["Consequently, your Lord poured upon them a whipping retribution.","পরিনামে, তোমাদের প্রভু তাদের উপর চাবুকের শাস্তি ঢেলে দিলেন৷"],
  "89:14": ["Your Lord is ever watchful.","তোমার প্রভু সবসময় সজাগ।"],
  "89:15": ["When the human being is tested by his Lord, through blessings and joy, he says, \"My Lord is generous towards me.\"","যখন মানব জাতিকে তার প্রভুর দ্বারা পরীক্ষা করা হয়, অনুগ্রহসমূহ এবং আনন্দ দিয়ে, সে বলে, \"আমার প্রভু আমার প্রতি উদার।"],
  "89:16": ["But if He tests him through reduction in provisions, he says, \"My Lord is humiliating me!\"","কিন্তু যদি তিনি তাকে পরীক্ষা করেন জীবিকা কম দিয়ে, সে বলে, \" আমার প্রভু আমাকে অপদস্ত করছেন! \""],
  "89:17": ["Wrong! It is you who brought it on yourselves by not regarding the orphan.","ভুল! তুমিই তা নিজের উপর এনেছিলে এতিমের প্রতি খেয়াল না রেখে।"],
  "89:18": ["And not advocating charity towards the poor.","এবং গরিবের প্রতি দান করার উকালতি না করে।"],
  "89:19": ["And consuming the inheritance of helpless orphans.","এবং অসহায় এতিমের উত্তরাধিকার ভোগ করে।"],
  "89:20": ["And loving the money too much.","এবং টাকা-পয়সাকে খুব বেশি ভালোবেসে৷"],
  "89:21": ["Indeed, when the earth is crushed, utterly crushed.","নিশ্চয়, যখন পৃথিবী চূর্ণ-বিচূর্ণ হয়, সম্পূর্ণ চূর্ণ-বিচূর্ণ।"],
  "89:22": ["And your Lord comes, together with the angels in row after row.","এবং তোমাদের প্রভু আসেন, সারিতে সারিতে ফেরেশতাদের নিয়ে৷"],
  "89:23": ["On that day, Gehenna will be brought forth. On that day, the human being will remember—but what a remembrance—it will be too late.","ঐদিন, জাহান্নামকে অস্তিত্বে আনা হবে । মানব জাতি স্মরণ করবে - কিন্তু কতই না বিস্ময়কর স্মারক - তখন খুব দেরি হয়ে যাবে৷"],
  "89:24": ["He will say, \"Oh, I wish I prepared for my (eternal) life.\"","সে বলবে , \"ইস, আমি যদি আমার (চিরস্থায়ী) জীবনের জন্য প্রস্তুতি নিতাম।"],
  "89:25": ["On that day, no retribution could be worse than His retribution.","ঐদিন, তাঁর শাস্তির চেয়ে নিকৃষ্টতর শাস্তি হতে পারে না।"],
  "89:26": ["And no confinement is as effective as His confinement.","কোন বন্দিত্ব তাঁর বন্দিত্বের মতো কার্যকর নয়৷"],
  "89:27": ["As for you, O content soul.","আর তোমার ক্ষেত্রে, হে পরিতৃপ্ত আত্মা।"],
  "89:28": ["Return to your Lord, pleased and pleasing.","তোমার প্রভুর কাছে ফিরে যাও, আনন্দিত এবং আনন্দ প্রদানরত৷"],
  "89:29": ["Welcome into My servants.","আমার বান্দাদের মধ্যে স্বাগতম।"],
  "89:30": ["Welcome into My Paradise.","আমার স্বর্গে স্বাগতম।"],
  "90:1": ["I solemnly swear by this town.","আমি এই শহরের নামে দৃড় শপথ করি।"],
  "90:2": ["The town where you live.","যে শহরটিতে তুমি বাস করো।"],
  "90:3": ["The begetting and the begotten.","জন্ম দেয়া এবং জন্ম হওয়া।"],
  "90:4": ["We created the human being to work hard (to redeem himself).","আমরা মানুষ জাতিকে (তার নিজের মুক্তির জন্য) কঠিন শ্রম দিতে সৃষ্টি করেছি।"],
  "90:5": ["Does he think that no one will ever call him to account?","সে কি মনে করে যে কেউ তাকে কখনো হিসাব দেয়ার জন্য ডাকবে না?"],
  "90:6": ["He boasts, \"I spent so much money!\"","সে অহংকার করে, \"আমি অনেক বেশি টাকা ব্যয় করেছি!\""],
  "90:7": ["Does he think that no one sees him?","সে কি মনে করে যে কেউ তাকে দেখে না?"],
  "90:8": ["Did we not give him two eyes?","আমরা কি তাকে দু'টি চোখ দেইনি?"],
  "90:9": ["A tongue and two lips?","একটি জিহবা এবং দুটি ঠোঁট?"],
  "90:10": ["Did we not show him the two paths?","আমরা কি তাকে দু'টি পথ দেখাইনি?"],
  "90:11": ["He should choose the difficult path.","তার উচিত কঠিন পথ বেছে নেয়া।"],
  "90:12": ["Which one is the difficult path?","কোনটি কঠিন পথ?"],
  "90:13": ["The freeing of slaves.","দাস মুক্তি করা।"],
  "90:14": ["Feeding, during the time of hardship.","কষ্টের সময়, খাওয়ানো।"],
  "90:15": ["Orphans who are related.","এতিমদের যারা সম্পর্কিত।"],
  "90:16": ["Or the poor who is in need.","অথবা সে গরীবকে যার প্রয়োজন।"],
  "90:17": ["And being one of those who believe, and exhorting one another to be steadfast, and exhorting one another to be kind.","এবং তাদের একজন হওয়া যারা বিশ্বাস করে, এবং একে অন্যকে অবিচল হতে উদ্বুদ্ধ করে, এবং একে অন্যকে দয়ালু হতে উদ্বুদ্ধ করে।"],
  "90:18": ["These have deserved happiness.","এরা সুখ অর্জন করেছে।"],
  "90:19": ["As for those who disbelieved in our revelations, they have incurred misery.","আর তাদের ক্ষেত্রে যারা আমাদের প্রকাশনাবলি অবিশ্বাস করেছে, তারা দুর্দশা টেনে এনেছে।"],
  "90:20": ["They will be confined in the Hellfire.","তারা নরকাগ্নিতে আবদ্ধ থাকবে।"],
  "91:1": ["By the sun and its brightness.","শপথ সূর্য এবং এর উজ্জ্বলতার।"],
  "91:2": ["The moon that follows it.","এর অনুসরণকারী চাঁদের।"],
  "91:3": ["The day that reveals.","দিনের যা প্রকাশ করে।"],
  "91:4": ["The night that covers.","রাতের যা ঢেকে দেয়।"],
  "91:5": ["The sky and Him who built it.","সূর্যের এবং তাঁর, যিনি একে তৈরি করেছিলেন।"],
  "91:6": ["The earth and Him who sustains it.","পৃথিবীর এবং তাঁর, যিনি একে ধরে রেখেছেন।"],
  "91:7": ["The soul and Him who created it.","আত্মার এবং তাঁর, যিনি একে সৃষ্টি করেছিলেন।"],
  "91:8": ["Then showed it what is evil and what is good.","এরপর একে দেখালেন কি মন্দ আর কি খারাপ।"],
  "91:9": ["Successful is one who redeems it.","সে ব্যক্তি সফল যে একে পাপমুক্ত করে।"],
  "91:10": ["Failing is one who neglects it.","সে ব্যক্তি ব্যর্থ যে একে অবহেলা করে।"],
  "91:11": ["Thamûd's disbelief caused them to transgress.","সামূদের অবিশ্বাস তাদের সীমালঙ্ঘনের কারণ হয়েছিল।"],
  "91:12": ["They followed the worst among them.","তারা তাদের মধ্যকার নিকৃষ্টকে অনুসরণ করেছিল।"],
  "91:13": ["Allah's messenger said to them, \"This is Allah's camel; let her drink.\"","আল্লাহর বার্তাবাহক তাদের বলেছিলেন, \"এটি আল্লাহর উট ; একে পান করতে দাও।"],
  "91:14": ["They disbelieved him and slaughtered her. Their Lord then requited them for their sin and annihilated them.","তারা তাকে অবিশ্বাস করেছিল এবং একে জবাই করলো। তাদের প্রভু এরপর তাদের পাপের জন্য প্রতিশোধ নিয়েছিলেন এবং তাদের নির্মূল করলেন।"],
  "91:15": ["Yet, those who came after them remain heedless.","এরপরও, যারা তাদের পরে এসেছিল তারা অসতর্ক থেকে যায়।"],
  "92:1": ["By the night as it covers.","রাতের শপথ যখন তা আবৃত করে।"],
  "92:2": ["The day as it reveals.","দিন যখন তা প্রকাশ করে।"],
  "92:3": ["And Him who created the male and the female.","এবং তাঁর, যিনি সৃষ্টি করেছেন নারী ও পুরুষ।"],
  "92:4": ["Your works are of various kinds.","তোমাদের কাজগুলো বিভিন্ন রকমের।"],
  "92:5": ["As for him who gives to charity and maintains righteousness.","তাদের ক্ষেত্রে যারা দান করে এবং সৎকর্মশীলতা বজায় রাখে।"],
  "92:6": ["And upholds the scripture.","এবং ঐশীগ্রন্থ মেনে চলে।"],
  "92:7": ["We will direct him towards happiness.","আমরা তাকে সুখের দিকে পরিচালিত করবো।"],
  "92:8": ["But he who is stingy, though he is rich.","কিন্তু যে ব্যক্তি কৃপন, যদিও সে ধনী।"],
  "92:9": ["And disbelieves in the scripture.","এবং ঐশীগ্রন্থে অবিশ্বাস করে।"],
  "92:10": ["We will direct him towards misery.","আমরা তাকে দুর্দশার দিকে পরিচালিত করবো।"],
  "92:11": ["His money cannot help him when he falls.","তার বিপদে তার টাকা তাকে সাহায্য করতে পারবে না।"],
  "92:12": ["We provide the guidance.","আমরা পথনির্দেশনা প্রদান করি।"],
  "92:13": ["We control the Hereafter, as well as this life.","আমরা নিয়ন্ত্রণ করি পরকাল , সে সাথে এই জীবন।"],
  "92:14": ["I have warned you about the blazing Hellfire.","তোমাকে আমি জ্বলন্ত নরকাগ্নি সম্পর্কে সতর্ক করেছি।"],
  "92:15": ["None burns therein except the wicked.","মন্দরা ছাড়া কেউ তাতে পুড়বে না।"],
  "92:16": ["Who disbelieves and turns away.","যারা অবিশ্বাস করে এবং মুখ ফিরিয়ে নেয়।"],
  "92:17": ["Avoiding it will be the righteous.","একে এড়াবে সৎকর্মশীলরা।"],
  "92:18": ["Who gives from his money to charity.","যারা তাদের অর্থ থেকে দান করে।"],
  "92:19": ["Seeking nothing in return.","বিনিময়ে কোন কিছু না চেয়ে।"],
  "92:20": ["Seeking only his Lord, the Most High.","শুধু তার প্রভুকে চেয়ে, যিনি সুউচ্চ ।"],
  "92:21": ["He will certainly attain salvation.","সে নিশ্চয় মুক্তি অর্জন করবে।"],
  "93:1": ["By the forenoon.","পূর্বাহ্নের শপথ।"],
  "93:2": ["By the night as it falls.","রাতের শপথ যখন তা নেমে আসে।"],
  "93:3": ["Your Lord never abandoned you, nor did He forget.","তোমার প্রভু কখনো তোমাকে পরিত্যাগ করেননি, না তিনি ভুলে গিয়েছিলেন।"],
  "93:4": ["The Hereafter is far better for you than this first (life).","পরকাল তোমার জন্য অনেক উত্তম এই প্রথম (জীবন)-এর চেয়ে।"],
  "93:5": ["And your Lord will give you enough; you will be pleased.","আর তোমার প্রভু তোমাকে যথেষ্ট দিবেন; তুমি খুশি হবে।"],
  "93:6": ["Did He not find you orphaned and He gave you a home?","তিনি কি তোমাকে এতিম পাননি এবং তোমাকে একটি বাড়ি দেননি?"],
  "93:7": ["He found you astray, and guided you.","তিনি তোমাকে পথভ্রষ্ট পেয়েছিলেন, এবং তোমাকে পথ দেখিয়েছেন।"],
  "93:8": ["He found you poor, and made you rich.","তিনি তোমাকে গরীব পেয়েছিলেন , এবং তোমাকে ধনী করেছেন।"],
  "93:9": ["Therefore, you shall not forsake the orphan.","সুতরাং, তুমি এতিমকে পরিত্যাগ করো না।"],
  "93:10": ["Nor shall you reprimand the beggar.","না তুমি ভিক্ষুককে তিরস্কার করবে।"],
  "93:11": ["You shall proclaim the blessing your Lord has bestowed upon you.","তুমি তোমার প্রতি তোমার প্রভুর অর্পিত অনুগ্রহ ঘোষণা করবে।"],
  "94:1": ["Did we not cool your temper?","আমরা কি তোমার মেজাজ ঠান্ডা করিনি?"],
  "94:2": ["And we unloaded your load (of sins).","এবং আমরা তোমার (পাপের) বোঝা হালকা করেছিলাম।"],
  "94:3": ["One that burdened your back.","যে বিষয়টা তোমার পিছনে বোঝা হয়েছিল।"],
  "94:4": ["We exalted you to an honorable position.","আমরা তোমাকে একটি সম্মানিত অবস্থানে উন্নিত করেছিলাম।"],
  "94:5": ["With pain there is gain.","কষ্টের সাথে রয়েছে অর্জন।"],
  "94:6": ["Indeed, with pain there is gain.","নিশ্চয়, কষ্টের সাথে রয়েছে অর্জন।"],
  "94:7": ["Whenever possible you shall strive.","যখনই সম্ভব হয় তুমি সংগ্রাম করবে।"],
  "94:8": ["Seeking only your Lord.","কেবল তোমার প্রভুর অন্বেষনে।"],
  "95:1": ["By the fig and the olive.","শপথ ডুমুর ও জলপাই-এর।"],
  "95:2": ["Mount Sinai.","সিনাই পর্বত।"],
  "95:3": ["And this honored town (Mecca).","এবং এই সম্মানিত শহর (মক্কা)।"],
  "95:4": ["We created man in the best design.","আমরা মানুষকে সর্বোত্তম নকশায় সৃষ্টি করেছি।"],
  "95:5": ["Then turned him into the lowliest of the lowly.","এরপর তাকে ফিরিয়ে দিলাম সর্বনিম্ন হীনতায়।"],
  "95:6": ["Except those who believe and lead a righteous life; they receive a reward that is well deserved.","তাদের ব্যতীত যারা বিশ্বাস করে এবং সৎকর্মশীল জীবন-যাপন করে; তারা যথাযোগ্য পুরষ্কার পায়।"],
  "95:7": ["Why do you still reject the faith?","এরপরও কেন তোমরা বিশ্বাসী হতে প্রত্যাখ্যান করো?"],
  "95:8": ["Is Allah not the Most Wise, of all the wise ones?","সকল প্রজ্ঞাবানদের থেকে, আল্লাহ কি সবচেয়ে প্রজ্ঞাবান নন?"],
  "96:1": ["Read, in the name of your Lord, who created.","পড়, তোমার প্রভুর নামে, যিনি সৃষ্টি করেছেন।"],
  "96:2": ["He created man from an embryo.","তিনি মানুষকে সৃষ্টি করেছেন ভ্রূণ থেকে।"],
  "96:3": ["Read, and your Lord, Most Exalted.","পড়, এবং তোমার প্রভু, সবচেয়ে প্রশংসিত।"],
  "96:4": ["Teaches by means of the pen.","শিক্ষা দেন কলমের দ্বারা।"],
  "96:5": ["He teaches man what he never knew.","তিনি মানুষকে শেখান যা সে কখনো জানতো না।"],
  "96:6": ["Indeed, the human transgresses.","নিশ্চয়, মানুষ সীমালঙ্ঘন করে।"],
  "96:7": ["When he becomes rich.","যখন সে ধনী হয়।"],
  "96:8": ["To your Lord is the ultimate destiny.","তোমার প্রভুর কাছে চূড়ান্ত নিয়তি।"],
  "96:9": ["Have you seen the one who enjoins.","তুমি কি সে ব্যক্তিকে দেখেছ যে বাধাঁ দেয়।"],
  "96:10": ["Others from praying?","অন্যদেরকে প্রার্থনা করা থেকে?"],
  "96:11": ["Is it not better for him to follow the guidance?","পথনির্দেশনা অনুসরণ করা কি তার জন্য উত্তম নয়?"],
  "96:12": ["Or advocate righteousness?","অথবা সৎকর্মশীলতার সমর্থন করা?"],
  "96:13": ["If he disbelieves and turns away.","যদি সে অবিশ্বাস করে এবং মুখ ফিরিয়ে নেয়।"],
  "96:14": ["Does he not realize that Allah sees?","সে কি বুঝে না যে আল্লাহ দেখেন?"],
  "96:15": ["Indeed, unless he refrains, we will take him by the forelock.","নিশ্চয়, যদি সে বিরত না থাকে, আমরা তার মাথার চুলগুচ্ছ ধরে নিয়ে যাবো।"],
  "96:16": ["A forelock that is disbelieving and sinful.","একটি চুলগুচ্ছ যা অবিশ্বাসী এবং পাপী।"],
  "96:17": ["Let him then call on his helpers.","সে তখন তার সাহায্যকারীদের ডাকুক।"],
  "96:18": ["We will call the guardians of Hell.","আমরা ডাকবো দোযখের তত্ত্বাবধায়কদের।"],
  "96:19": ["You shall not obey him; you shall fall prostrate and draw nearer.","তাকে তুমি মান্য করবে না; তুমি সেজদা করবে এবং নিকটতর হও।"],
  "97:1": ["We revealed it in the Night of Destiny.","আমরা একে নিয়তির রজনীতে প্রকাশ করেছি।"],
  "97:2": ["How awesome is the Night of Destiny!","নিয়তির রজনীটি কতই না অসাধারণ!"],
  "97:3": ["The Night of Destiny is better than a thousand months.","নিয়তির রজনীটি হাজার মাসের চেয়ে উত্তম।"],
  "97:4": ["The angels and the Spirit descend therein, by their Lord's leave, to carry out every command.","ফেরেশতারা এবং আত্মা সেখানে নামে, তাদের প্রভুর অনুমতিক্রমে, সম্পাদন করতে প্রতিটি আদেশ।"],
  "97:5": ["Peaceful it is until the advent of the dawn.","ভোরের আগমন পর্যন্ত এটি শান্তিপূর্ণ।"],
  "98:1": ["Those who disbelieved among the people of the scripture, as well as the idol worshipers, insist on their ways, despite the proof given to them.","ঐশীগ্রন্থের লোকদের যারা অবিশ্বাস করেছিল, আর যারা শরিক উপাসনাকারী, তারা তাদের পথেই অনড় থাকে, যদিও তাদেরকে প্রমাণ দেয়া হয়েছে।"],
  "98:2": ["A messenger from Allah is reciting to them sacred instructions.","আল্লাহর পক্ষ থেকে একজন বার্তাবাহক তাদের কাছে ঐশ্বরিক নির্দেশনাবলি আবৃত্তি করছে।"],
  "98:3": ["In them there are valuable teachings.","যাতে আছে মূল্যবান শিক্ষাসমূহ।"],
  "98:4": ["In fact, those who received the scripture did not dispute until the proof was given to them.","প্রকৃতপক্ষে, যারা ঐশীগ্রন্থ পেয়েছে তারা বিবাদ করে না যতক্ষণ না তাদেরকে প্রমাণ দেয়া হয়।"],
  "98:5": ["All that was asked of them was to worship Allah, devoting the religion absolutely to Him alone, observe the contact prayers (Salat), and give the obligatory charity (Zakat). Such is the perfect religion.","তাদেরকে কেবল বলা হয়েছিল ঈশ্বরের উপাসনা করতে, ধর্মকে পুরোপুরি শুধু তাঁর প্রতি উৎসর্গ করে, সংযোগ প্রার্থনা (সালাত) পালন করো, এবং বাধ্যতামূলক দান (যাকাত) দাও। এমনি হলো যথার্থ ধর্ম।"],
  "98:6": ["Those who disbelieved among the people of the scripture, and the idol worshipers have incurred the fire of Gehenna forever. They are the worst creatures.","ঐশীগ্রন্থের লোকদের মধ্যে যারা অবিশ্বাস করেছিল, এবং প্রতিমা উপাসকরা চিরকালের জন্য টেনে এনেছে জাহান্নামের আগুন। তারা হলো নিকৃষ্ট সৃষ্টি।"],
  "98:7": ["Those who believed and led a righteous life are the best creatures.","যারা বিশ্বাস করেছে এবং সৎ জীবন-যাপন করেছে তারা হলো সর্বোত্তম সৃষ্টি।"],
  "98:8": ["Their reward at their Lord is the gardens of Eden with flowing streams, wherein they abide forever. Allah is pleased with them, and they are pleased with Him. Such is the reward for those who reverence their Lord.","তাদের প্রভুর কাছে তাদের পুরষ্কার হলো প্রবাহিত ঝর্ণাসহ ইডেনের বাগানগুলো, যেখানে তারা চিরকাল বাস করে। আল্লাহ তাদের প্রতি সন্তুষ্ট, এবং তারা তাঁর প্রতি সন্তুষ্ট।"],
  "99:1": ["When the earth is severely quaked.","যখন পৃথিবীকে ভীষণভাবে নাড়ানো হয়।"],
  "99:2": ["And the earth ejects its loads.","এবং পৃথিবী এর বোঝাগুলো উদ্গিরন করে।"],
  "99:3": ["The human will wonder: \"What is happening?\"","মানুষ বিস্মিত হবে : “কি ঘটছে?”"],
  "99:4": ["On that day, it will tell its news.","ঐদিন, এটি এর সংবাদ বলবে।"],
  "99:5": ["That your Lord has commanded it.","যা তোমার প্রভু একে আদেশ করেছেন।"],
  "99:6": ["On that day, the people will issue from every direction, to be shown their works.","ঐদিন, প্রত্যেক দিক থেকে লোকেরা আসবে, তাদের কাজগুলো তাদেরকে দেখাতে।"],
  "99:7": ["Whoever does an atom's weight of good will see it.","যে কেউ একটি পরমানুর ভরের সমান ভাল কাজ করেছে, সে তা দেখবে।"],
  "99:8": ["And whoever does an atom's weight of evil will see it.","এবং যেকেউ একটি পরমানুর ভরের সমান মন্দ কাজ করেছে, সে তা দেখবে।"],
  "100:1": ["By the fast gallopers.","দ্রুত ছুটে চলা ধাবনকারীর শপথ।"],
  "100:2": ["Igniting sparks.","যে প্রজ্জ্বলিত করে অগ্নিস্ফুলিঙ্গ।"],
  "100:3": ["Invading (the enemy) by morning.","(শত্রুর উপর) হামলা করে সকালের মধ্যে।"],
  "100:4": ["Striking terror therein.","সেখানে আতংক সৃষ্টি করে।"],
  "100:5": ["Penetrating to the heart of their territory.","ভেদ করে তাদের এলাকার প্রানকেন্দ্র।"],
  "100:6": ["The human being is unappreciative of his Lord.","মানব জাতি তার প্রভুর প্রতি অকৃতজ্ঞ।"],
  "100:7": ["He bears witness to this fact.","সে এই বাস্তবতার সাক্ষ্য বহন করে।"],
  "100:8": ["He loves material things excessively.","সে পার্থিব জিনিস অতিরিক্ত ভালবাসে।"],
  "100:9": ["Does he not realize that the day will come when the graves are opened?","সে কি অনুধাবন করে না যে সেদিন আসবে যখন কবর উন্মুক্ত করা হবে?"],
  "100:10": ["And all secrets are brought out.","এবং সকল গোপনীয়তা সামনে আনা হবে।"],
  "100:11": ["They will find out, on that day, that their Lord has been fully Cognizant of them.","তারা, ঐদিন দেখবে, যে তাদের প্রভু তাদের সম্পর্কে জ্ঞাত।"],
  "101:1": ["The Shocker.","এক চরম বিপর্যয়।"],
  "101:2": ["What a shocker!","কি এক চরম বিপর্যয়?"],
  "101:3": ["Do you have any idea what the Shocker is?","তোমার কি কোন ধারণা আছে ঐ চরম বিপর্যয়ের বিষয়ে?"],
  "101:4": ["That is the day when the people come out like swarms of butterflies.","এটা সেদিন যখন লোকেরা বেরিয়ে আসে প্রজাপতির ঝাঁকের মতো।"],
  "101:5": ["The mountains will be like fluffy wool.","পর্বতগুলো হবে তুলতুলে পশমের মতো।"],
  "101:6": ["As for him whose weights are heavy.","তার ক্ষেত্রে যার পাল্লা ভারী।"],
  "101:7": ["He will lead a happy (eternal) life.","সে সুখী (অনন্ত) জীবন অতিবাহিত করবে।"],
  "101:8": ["As for him whose weights are light.","তার ক্ষেত্রে যার পাল্লা হালকা।"],
  "101:9": ["His destiny is lowly.","তার ভাগ্য নিম্নমানের।"],
  "101:10": ["Do you know what it is?","তুমি কি জানো এটি কি?"],
  "101:11": ["The blazing Hellfire.","জ্বলন্ত অগ্নিকুণ্ড।"],
  "102:1": ["You remain preoccupied with hoarding.","তোমরা জমা করা নিয়ে মোহাচ্ছন্ন থাকো।"],
  "102:2": ["Until you go to the graves.","যতক্ষণ না তোমরা কবরে যাও।"],
  "102:3": ["Indeed, you will find out.","নিশ্চয়, তোমরা বুঝতে পাবে।"],
  "102:4": ["Most assuredly, you will find out.","নি:সন্দেহে, তোমরা বুঝতে পাবে।"],
  "102:5": ["If only you could find out for certain.","যদি শুধু তোমরা নিশ্চিত বুঝতে।"],
  "102:6": ["You would envision Hell.","তোমরা নরকের কল্পনা করবে।"],
  "102:7": ["Then you would see it with the eye of certainty.","এরপর তোমরা এটি দেখবে নিশ্চয়তার চোখ দিয়ে।"],
  "102:8": ["Then you will be questioned, on that day, about the blessings you had enjoyed.","এরপর, ঐদিন, তোমাদের প্রশ্ন করা হবে, তোমাদের ভোগ করা অনুগ্রহসমূহ সম্পর্কে।"],
  "103:1": ["By the afternoon.","অপরাহ্নের শপথ।"],
  "103:2": ["The human being is utterly lost.","মানবজাতি ভীষণভাবে ক্ষতিগ্রস্ত।"],
  "103:3": ["Except those who believe and lead a righteous life, and exhort one another to uphold the truth, and exhort one another to be steadfast.","তারা ছাড়া যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে, এবং একে অন্যকে সত্যে আঁকড়ে থাকতে উদ্ধুদ্ধ করে, এবং একে অন্যকে অবিচল থাকতে উদ্ধুদ্ধ করে।"],
  "104:1": ["Woe to every backbiter, slanderer.","দূর্ভোগ প্রত্যেক পরনিন্দাকারী, অপবাদকারীর।"],
  "104:2": ["He hoards money and counts it.","সে টাকা জমায় আর তা হিসাব করে।"],
  "104:3": ["As if his money will make him immortal.","যেন তার টাকা তাকে অমর করবে।"],
  "104:4": ["Never; he will be thrown into the Devastator.","কখনো নয়; তাকে নিক্ষেপ করা হবে সে ধ্বংসকারীর মধ্যে।"],
  "104:5": ["Do you know what the Devastator is?","তুমি কি জানো ধ্বংসকারীটি কি?"],
  "104:6": ["Allah's blazing Hellfire.","আল্লাহর জ্বলন্ত নরকাগ্নি।"],
  "104:7": ["It burns them inside out.","এটি তাদের আপাদমস্তক পোড়ায়।"],
  "104:8": ["They will be confined therein.","তারা সেখানে আবদ্ধ থাকবে।"],
  "104:9": ["In extended columns.","বর্ধিত স্তম্ভে।"],
  "105:1": ["Have you noted what your Lord did to the people of the elephant?","তুমি কি লক্ষ্য করেছ তোমার প্রভু হাতিওয়ালাদের সাথে কি করেছিলেন?"],
  "105:2": ["Did He not cause their schemes to backfire?","তিনি কি তাদের ষড়যন্ত্রকে উল্টো তাদের বিরুদ্ধে যেতে দেননি?"],
  "105:3": ["He sent upon them swarms of birds.","তিনি তাদের উপর পাঠালেন পাখিদের ঝাঁক।"],
  "105:4": ["That showered them with hard stones.","যা তাদের উপর শক্ত পাথর বর্ষণ করলো।"],
  "105:5": ["He made them like chewed up hay.","তিনি তাদেরকে চিবানো খড়ের মতো করে দিলেন।"],
  "106:1": ["This should be cherished by Quraish.","এটি কোরাইশদের দ্বারা লালিত হওয়া উচিত।"],
  "106:2": ["The way they cherish the caravans of the winter and the summer.","যেভাবে তারা শীত ও গ্রীষ্মের কাফেলাদের লালন করে।"],
  "106:3": ["They shall worship the Lord of this shrine.","তারা এই তীর্থস্থানের প্রভুর উপাসনা করবে।"],
  "106:4": ["For He is the One who fed them after hunger, and provided them with security after fear.","কারণ তিনিই সে সত্ত্বা যিনি তাদের ক্ষুধার পর খাবার দিয়েছেন, আর ভয়ের পর তাদের নিরাপত্তা দিয়েছেন।"],
  "107:1": ["Do you know who really rejects the faith?","তুমি কি জানো কে সত্যিকার অর্থে বিশ্বাস প্রত্যাখান করে?"],
  "107:2": ["That is the one who mistreats the orphans.","ঐ ব্যক্তি যে এতিমের সাথে দুর্ব্যবহার করে।"],
  "107:3": ["And does not advocate the feeding of the poor.","এবং গরীবদের খাওয়ানো সমর্থন করে না।"],
  "107:4": ["And woe to those who observe the contact prayers (Salat)—","এবং তাদের প্রতি দূর্ভোগ যারা সংযোগ প্রার্থনা (সালাত) পালন করে-"],
  "107:5": ["who are totally heedless of their prayers.","যারা তাদের প্রার্থনায় পুরোপুরি অমনোযোগী।"],
  "107:6": ["They only show off.","তারা কেবল লোক দেখানো কাজ করে।"],
  "107:7": ["And they forbid charity.","আর তারা দান করতে নিষেধ করে।"],
  "108:1": ["We have blessed you with many a bounty.","আমরা তোমাকে অনেক কিছু উদারভাবে দিয়ে সৌভাগ্যবান করেছি।"],
  "108:2": ["Therefore, you shall pray to your Lord (Salat), and give to charity.","সুতরাং, তুমি তোমার প্রভুর কাছে প্রার্থনা করো (সালাত), এবং দান করো।"],
  "108:3": ["Your opponent will be the loser.","তোমার প্রতিদ্বন্দ্বী পরাজিত হবে।"],
  "109:1": ["Say, \"O you disbelievers.","বল, “হে তোমরা অবিশ্বাসীরা।"],
  "109:2": ["\"I do not worship what you worship.","আমি উপাসনা করি না তোমরা যার উপাসনা করো।"],
  "109:3": ["\"Nor do you worship what I worship.","না তোমরা উপাসনা করো আমি যার উপাসনা করি।"],
  "109:4": ["\"Nor will I ever worship what you worship.","না আমি কখনো উপাসনা করবো তোমরা যার উপাসনা করো।"],
  "109:5": ["\"Nor will you ever worship what I worship.","না তোমরা কখনো উপাসনা করবে আমি যার উপাসনা করি।"],
  "109:6": ["\"To you is your religion, and to me is my religion.\"","“তোমাদের ধর্ম তোমাদের কাছে, এবং আমার ধর্ম আমার কাছে।”"],
  "110:1": ["When triumph comes from Allah, and victory.","যখন আল্লাহ থেকে আসে সাফল্য, এবং বিজয়।"],
  "110:2": ["You will see the people embracing Allah's religion in throngs.","তুমি লোকদের দলে দলে আল্লাহর ধর্ম গ্রহণ করতে দেখবে।"],
  "110:3": ["You shall glorify and praise your Lord, and implore Him for forgiveness. He is the Redeemer.","তুমি তোমার প্রভুর মহিমা ও প্রশংসা করো, এবং ক্ষমার জন্য তাঁর কাছে মিনতি করো। তিনিই পরিত্রাণকারী।"],
  "111:1": ["Condemned are the works of Abee Lahab, and he is condemned.","আবি লাহাবের কাজগুলো নিন্দিত এবং সে নিন্দিত।"],
  "111:2": ["His money and whatever he has accomplished will never help him.","তার অর্থ-বিত্ত এবং যাকিছুই সে অর্জন করেছে কখনো তাকে সাহায্য করবে না।"],
  "111:3": ["He has incurred the blazing Hell.","সে টেনে এনেছে জ্বলন্ত নরক।"],
  "111:4": ["Also his wife, who led the persecution.","তার স্ত্রীও, যে নির্যাতনের নেতৃত্ব দিয়েছিল।"],
  "111:5": ["She will be (resurrected) with a rope of thorns around her neck.","সে তার গলায় কাঁটার রশি নিয়ে (পুনরুজ্জীবিত) হবে।"],
  "112:1": ["Proclaim, \"He is the One and only Allah.","ঘোষণা করো, “তিনি এক এবং একমাত্র ঈশ্বর।"],
  "112:2": ["\"The Absolute Allah.","“পরম ঈশ্বর।"],
  "112:3": ["\"Never did He beget. Nor was He begotten.","“তিনি কখনো জন্ম দেননি। না তাঁকে জন্ম দেয়া হয়েছিল।"],
  "112:4": ["\"None equals Him.\"","“কেউ তাঁর সমান নয়।”"],
  "113:1": ["Say, \"I seek refuge in the Lord of daybreak.","বল, “আমি আশ্রয় প্রার্থনা করি প্রভাতের প্রভুর কাছে।"],
  "113:2": ["\"From the evils among His creations.","“তাঁর সৃষ্টির অনিষ্ট থেকে”"],
  "113:3": ["\"From the evils of darkness as it falls.","অন্ধকারের অনিষ্ট থেকে যখন তা গভীর হয়।"],
  "113:4": ["\"From the evils of the troublemakers.","গোলযোগ সৃষ্টিকারীর অনিষ্ট থেকে।"],
  "113:5": ["\"From the evils of the envious when they envy.\"","“হিংসুকের অনিষ্ট থেকে, যখন তারা হিংসা করে।”"],
  "114:1": ["Say, \"I seek refuge in the Lord of the people.","বল, \" আমি মানুষের প্রভুর নিকট ক্ষমা প্রার্থনা করি।"],
  "114:2": ["\"The King of the people.","\"মানুষের রাজা।"],
  "114:3": ["\"The god of the people.","\"মানুষের উপাস্য।"],
  "114:4": ["\"From the evils of sneaky whisperers.","\"গোপনে কুমন্ত্রনাদাতার অনিষ্ট থেকে।"],
  "114:5": ["\"Who whisper into the chests of the people.","“যে কুমন্ত্রনা দেয় মানুষের বুকে।"],
  "114:6": ["\"Be they of the jinns, or the people.\"","“হোক সে জ্বীনদের কেউ, বা মানুষদের কেউ।”"],
};
